/* ============================================================
   Procedure: [dbo].[Usp_SaveUpdateSearchCriteria]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveUpdateSearchCriteria (    
 @CriteriaIDToOperate BIGINT    
 ,@CriteriaName NVARCHAR(500)    
 ,@CriteriaType NVARCHAR(50)    
 ,@ProductIDs NVARCHAR(max)    
 ,@AllProductDefault BIT    
 ,@SearchApplyTo NVARCHAR(50)    
 ,@SortByColumnName NVARCHAR(500)    
 ,@OrderBy NVARCHAR(50)    
 ,@IsActive BIT    
 ,@UserID BIGINT    
 ,@tblTypeSearchCondition tblTypeSearchCriteria readonly    
 )    
AS    
BEGIN    
 DECLARE @CriteriaID BIGINT = 0    
 DECLARE @ParentID BIGINT = 0    
    
 SELECT TOP 1 @ParentID = isnull(ParentID, user_id)    
 FROM User_Detail(NOLOCK)    
 WHERE User_ID = @UserID    
    
 IF (@CriteriaIDToOperate = 0)    
 BEGIN    
  IF (    
    NOT EXISTS (    
     SELECT 1    
     FROM ProductSearchCriteria(NOLOCK)    
     WHERE CriteriaName = @CriteriaName    
      AND CreatedBy = @UserID    
     )    
    )    
  BEGIN    
   INSERT INTO ProductSearchCriteria (    
    [CriteriaName]    
    ,[CriteriaType]    
    ,[ProductIDs]    
    ,[AllProductDefault]    
    ,[SearchApplyTo]    
    ,[SortByColumnName]    
    ,[OrderBy]    
    ,[ParentID]    
    ,[CreatedOn]    
    ,[ModifiedOn]    
    ,[IsActive]    
    ,[CreatedBy]    
    )    
   VALUES (    
    @CriteriaName    
    ,@CriteriaType    
    ,@ProductIDs    
    ,@AllProductDefault    
    ,@SearchApplyTo    
    ,@SortByColumnName    
    ,@OrderBy    
    ,@ParentID    
    ,getdate()    
    ,getdate()    
    ,@IsActive    
    ,@UserID    
    )    
    
   SELECT @CriteriaID = SCOPE_IDENTITY();    
    
   INSERT INTO ProductSearchCondition (    
    CriteriaID    
    ,ColumnName    
    ,Operator    
    ,Value    
    ,CreatedOn    
    ,CreatedBy    
    )    
   SELECT @CriteriaID    
    ,ColumnName    
    ,Operator    
    ,Value    
    ,getdate()    
    ,@UserID    
   FROM @tblTypeSearchCondition    
    
   SELECT 'Data Saved' AS MSG    
    
   DECLARE @rowJson NVARCHAR(MAX) = (    
    -- SELECT *    
   
SELECT [ID]  
      ,[CriteriaName]  
      ,[CriteriaType]  
      ,[ProductIDs]  
      ,[AllProductDefault]  
      ,[SearchApplyTo]  
      ,[SortByColumnName]  
      ,[OrderBy]  
      ,[ParentID]  
      ,[CreatedOn]  
      ,[ModifiedOn]  
      ,[IsActive]  
      ,(dbo.udf_mk_GetTaskCreatorName(CreatedBy)) AS [CreatedBy]  
     FROM ProductSearchCriteria WITH(NOLOCK)    
     WHERE ID = @CriteriaID    
     FOR JSON AUTO    
      ,INCLUDE_NULL_VALUES    
     )    
    
   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID    
    ,@Activity_type = 'Inst_Segmnt'    
    ,@ActionType = 'I'    
    ,@RowJson = @rowJson    
    ,@Table_name = 'ProductSearchCriteria'    
  END    
  ELSE    
  BEGIN    
   SELECT 'Criteria Name Already Exists' AS MSG    
  END    
 END    
 ELSE    
 BEGIN    
  IF (    
    NOT EXISTS (    
     SELECT 1    
     FROM ProductSearchCriteria(NOLOCK)    
     WHERE ID <> @CriteriaIDToOperate    
      AND CriteriaName = @CriteriaName    
      AND CreatedBy = @UserID    
     )    
    )    
  BEGIN    
   UPDATE ProductSearchCriteria    
   SET CriteriaName = @CriteriaName    
    ,CriteriaType = @CriteriaType    
    ,ProductIDs = @ProductIDs    
    ,AllProductDefault = @AllProductDefault    
    ,SearchApplyTo = @SearchApplyTo    
    ,SortByColumnName = @SortByColumnName    
    ,OrderBy = @OrderBy    
    ,ModifiedOn = getdate()    
    ,IsActive = @IsActive    
   WHERE ID = @CriteriaIDToOperate    
    
   DELETE    
   FROM ProductSearchCondition    
   WHERE CriteriaID = @CriteriaIDToOperate    
    
   INSERT INTO ProductSearchCondition (    
    CriteriaID    
    ,ColumnName    
    ,Operator    
    ,Value    
    ,CreatedOn    
    ,CreatedBy    
    )    
   SELECT @CriteriaIDToOperate    
    ,ColumnName    
    ,Operator    
    ,Value    
    ,getdate()    
    ,@UserID    
   FROM @tblTypeSearchCondition    
    
   SELECT 'Data Saved' AS MSG    
    
   SET @rowJson = (    
     SELECT *     
     FROM ProductSearchCriteria WITH(NOLOCK)    
     WHERE ID = @CriteriaIDToOperate    
     FOR JSON AUTO    
      ,INCLUDE_NULL_VALUES    
     )    
    
   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID    
    ,@Activity_type = 'Updt_Segmnt'    
    ,@ActionType = 'U'    
    ,@RowJson = @rowJson    
    ,@Table_name = 'ProductSearchCriteria'    
  END    
  ELSE    
  BEGIN    
   SELECT 'Criteria Name Already Exists' AS MSG    
  END    
 END    
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveUpdateSearchCriteriaConditions]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveUpdateSearchCriteriaConditions (    
 @CriteriaName NVARCHAR(500)    
 ,@CriteriaType NVARCHAR(200)    
 ,@ApplyTo NVARCHAR(50)    
 ,@IsActive BIT    
 ,@UserID BIGINT    
 ,@tbl_SearchConditions tbltype_SearchCriteriaCondition readonly    
 ,@SearchCriteriaID BIGINT    
 )    
AS    
BEGIN    
 DECLARE @ParentID BIGINT = 0    
    
 SELECT TOP 1 @ParentID = ISNULL(ParentID, User_ID)    
 FROM User_Detail(NOLOCK)    
 WHERE User_ID = @UserID    
    
 DECLARE @InsertedCriteriaID BIGINT = 0    
    
 IF (@SearchCriteriaID = 0)    
 BEGIN    
  IF (    
    NOT EXISTS (    
     SELECT 1    
     FROM tbl_SearchCriteria(NOLOCK)    
     WHERE CriteriaName = @CriteriaName    
      AND ParentID = @ParentID    
     )    
    )    
  BEGIN    
   INSERT INTO tbl_SearchCriteria (    
    [CriteriaName]    
    ,[CriteriaType]    
    ,[ApplyTo]    
    ,[ParentID]    
    ,[IsActive]    
    ,[CreatedOn]    
    ,[ModifiedOn]    
    ,[CreatedBy]    
    ,[ModifiedBy]    
    )    
   VALUES (    
    @CriteriaName    
    ,@CriteriaType    
    ,@ApplyTo    
    ,@ParentID    
    ,@IsActive    
    ,getdate()    
    ,getdate()    
    ,@UserID    
    ,@UserID    
    )    
    
   SET @InsertedCriteriaID = SCOPE_IDENTITY();    
    
   INSERT INTO tbl_SearchCriteriaConditions (    
    CriteriaID    
    ,FieldName    
    ,FieldType    
    ,Operator    
    ,Value    
    )    
   SELECT @InsertedCriteriaID    
    ,FieldName    
    ,FieldType    
    ,Operator    
    ,Value    
   FROM @tbl_SearchConditions    
    
   SELECT 'Record Saved'    
    
   DECLARE @rowJson NVARCHAR(MAX) = (    
     SELECT *    
     FROM tbl_SearchCriteria    
     WHERE ID = @InsertedCriteriaID    
     FOR JSON AUTO    
      ,INCLUDE_NULL_VALUES    
     )    
    
   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID    
    ,@Activity_type = 'Inst_Segmnt'    
    ,@ActionType = 'I'    
    ,@RowJson = @rowJson    
    ,@Table_name = 'tbl_SearchCriteria'    
  END    
  ELSE    
  BEGIN    
   SELECT 'Search Criteria Name Already Exists'    
  END    
 END    
 ELSE IF (@SearchCriteriaID > 0)    
 BEGIN    
  IF (    
    NOT EXISTS (    
     SELECT 1    
     FROM tbl_SearchCriteria(NOLOCK)    
     WHERE CriteriaName = @CriteriaName    
      AND ParentID = @ParentID    
      AND ID <> @SearchCriteriaID    
     )    
    )    
  BEGIN    
   UPDATE tbl_SearchCriteria    
   SET CriteriaName = @CriteriaName    
    ,CriteriaType = @CriteriaType    
    ,ApplyTo = @ApplyTo    
    ,IsActive = @IsActive    
    ,ModifiedOn = getdate()    
    ,ModifiedBy = @UserID    
   WHERE ID = @SearchCriteriaID    
    
   DELETE    
   FROM tbl_SearchCriteriaConditions    
   WHERE CriteriaID = @SearchCriteriaID    
    
   INSERT INTO tbl_SearchCriteriaConditions (    
    CriteriaID    
    ,FieldName    
    ,FieldType    
    ,Operator    
    ,Value    
    )    
   SELECT @SearchCriteriaID    
    ,FieldName    
    ,FieldType    
    ,Operator    
    ,Value    
   FROM @tbl_SearchConditions    
    
   SELECT 'Record Saved'    
    
   SET @rowJson = (    
     SELECT *    
     FROM tbl_SearchCriteria    
     WHERE ID = @SearchCriteriaID    
     FOR JSON AUTO    
      ,INCLUDE_NULL_VALUES    
     )    
    
   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID    
    ,@Activity_type = 'Updt_Segmnt'    
    ,@ActionType = 'U'    
    ,@RowJson = @rowJson    
    ,@Table_name = 'tbl_SearchCriteria'    
  END    
  ELSE    
  BEGIN    
   SELECT 'Search Criteria Name Already Exists'    
  END    
 END    
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveUpdateUserTokenGuid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SaveUpdateUserTokenGuid
(
   @UserName nvarchar(500)
  ,@Mode nvarchar(500)
)
as
begin
      Declare  @Parentid  bigint = 0
	  Declare @NewUid nvarchar(500) = ''    
		  if( exists (select 1 from user_detail(nolock) where User_Login = @UserName))
	         begin 
			    select top 1 @Parentid = ParentID from User_Detail with(nolock) where User_Login = @UserName 

			     if(@Mode = 'set')
				   begin
				       if(not exists(select 1 from tbl_UserTokenGuid with(nolock) where ParentID = @Parentid)) 
					      begin
						     set @NewUid =  NEWID()          

						     insert into tbl_UserTokenGuid
							  (TokenGuid, ParentID,CreatedDate,ModifiedDate)
							  select @NewUid,@Parentid, getdate(),getdate()
							  select 1 as status, @NewUid as MSG 
						  end
                        else
						  begin
						       set @NewUid =  NEWID()
							   update tbl_UserTokenGuid 
							       set TokenGuid = @NewUid, ModifiedDate = getdate() where ParentID = @Parentid
                               select 1 as status, @NewUid as MSG  
						  end

				   end
                 else
				   begin
                       if(not exists(select 1 from tbl_UserTokenGuid with(nolock) where ParentID = @Parentid)) 
					      begin
						     set @NewUid =  NEWID()          

						     insert into tbl_UserTokenGuid
							  (TokenGuid, ParentID,CreatedDate,ModifiedDate)
							  select @NewUid,@Parentid, getdate(),getdate()
							  select 1 as status, @NewUid as MSG 
						  end
                        else
						  begin
						       select @NewUid = TokenGuid from tbl_UserTokenGuid with(nolock) where ParentID = @Parentid
                               select 1 as status, @NewUid as MSG  
						  end
                                
				   end
			end
           else
		    Begin
			    select 0 as status, 'Invalid UserName' as MSG 
			end 
	   

End



GO

/* ============================================================
   Procedure: [dbo].[usp_SaveUrlKeywordHint]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- Exec usp_SaveUrlKeywordHint @Url=Null,@Keywords=null
CREATE   PROC usp_SaveUrlKeywordHint
(
	@Url varchar(500),
	@Keywords varchar(max)
)
As
Begin

	If exists(Select * From [tbl_UrlKeywords] Where IsArchived=0 and Url=@Url)
	Begin
		Update [tbl_UrlKeywords] Set IsArchived=1 Where Url=@Url and IsArchived=0
	End

	Insert into [tbl_UrlKeywords]([Url], Keywords, IsArchived)
	Values (@Url, @Keywords, 0)

	Select isnull(SCOPE_IDENTITY(),0) as Row_ID
End



GO

