   Procedure: [dbo].[usp_SaveUrlKeywordHintException]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- Exec usp_SaveUrlKeywordHintException @Url='rediff.com',@UserId=335,@TimeToWait=30,@ExceptionMsg=''
CREATE   PROC usp_SaveUrlKeywordHintException
(
	@Url varchar(500),
	@UserId varchar(50),
	@TimeToWait int,
	@ExceptionMsg varchar(500)
)
As
Begin

	Insert into [tbl_UrlKeywordsException]([Url],UserId,TimeToWait,ExceptionMsg)
	Values (@Url, @UserId, @TimeToWait, @ExceptionMsg)

	Select isnull(SCOPE_IDENTITY(),0) as Row_ID
End



