/* ============================================================
   Procedure: [dbo].[Usp_SaveUserCampaignMaster_ForSMS_WithLinkURLDT_and_VoiceBroadcast]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROCEDURE [dbo].[Usp_SaveUserCampaignMaster_ForSMS_WithLinkURLDT_and_VoiceBroadcast]            
(            
 @UserID bigint,             
 @TRGCampaignID bigint,                                              
 @AccountUsed BIGINT,                                              
 @SenderID VARCHAR(500),                                              
 @DLTTemplateID nvarchar(200),            
 @Message NVARCHAR(2000),                                              
 @IsUnicode BIT,                                              
 @IsActive BIT,                                              
 @tbl SMSUrl_Link_new READONLY,        
 @TimeBeforeUnit int,        
 @TimeUnit nvarchar(20),
 @tblVoicebroadcast  tblType_VoiceBroadCast readonly                        
)            
As            
 Begin            
            
    Declare @ParentID bigint = 0             
 Declare @CampaignName nvarchar(200) = ''              
 Declare @EventID int = 0             
 Declare @TemplateID bigint = 0            
 Declare @Applicability nvarchar(max) = ''             
            
            
  select  top 1 @ParentID = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @UserID                  
  
      if(isnull(@ParentID,0) = 0 or isnull(@UserID,0) = 0 )
	    begin
		     select 'May be Session expired: unexpected userid & Parentid value' as Status , '0' as ID        
		     goto Label1    
		end   
  
  
  
  
  select top 1  @CampaignName = ( CAST(isnull(cname,'') as nvarchar)+ '_SMS')            
   , @EventID = isnull(eventid,0) , @Applicability = isnull(Audience,'')  from triggeredcampaigns(nolock) where id = @TRGCampaignID              
              
   select @TemplateID = isnull(ID,0) from UserMailTemplate(nolock) where DLT_TemplateID = @DLTTemplateID            
            
   -- if(@EventID not in (152,153,154,155))        
   --Begin        
   --   set @TimeBeforeUnit = null        
   --set @TimeUnit = null        
   --End        
     
       if(rtrim(ltrim(@TimeUnit)) = '')  
       Begin  
        set @TimeBeforeUnit = null        
              set @TimeUnit = null  
    End  
  
           
   IF NOT EXISTS (                                              
        SELECT 'x'                                              
        FROM   UserCampaignMaster AS ucm                                              
        WHERE  ucm.ParentID = @ParentID                                              
               AND ucm.CampaignName = @CampaignName                                              
    )                                              
 BEGIN                
               
     Declare @ExpiryDate nvarchar(50) = ''              
  Declare @StartDate nvarchar(50) = ''             
  Declare @NextExecuteDateTime nvarchar(50) = dateadd(ss,5,getdate())             
                                               
     IF (@ExpiryDate = '')                                              
     BEGIN                                              
         SET @ExpiryDate = NULL                                              
     END                                                
                                                   
                                                   
                                                   
     IF (isnull(@StartDate,'') = '')                                              
     BEGIN                                              
         SET @StartDate = CAST(GETDATE() AS nvarchar)                                              
     END
	 else
	  begin
	     SET @StartDate = dbo.[fn_getISTtimefromusertime](@ParentID,@StartDate);
	  end
                                                   
                                                  
   --if dbo.[fn_getISTtimefromusertime](@ParentID,@NextExecuteDateTime) < getdate()                                    
   --   begin                                    
   --   set @nextexecutedatetime=dateadd(ss,15,getdate())                                    
   --   end                                    
                         
                                          
                                                   
     INSERT INTO UserCampaignMaster                                              
       (                                
         ParentID,                                              
         CampaignName,                   
         IsEventBased,                                              
         IsScheduled,                                              
         Applicabilty,                                              
         ExclusionsNumber,                                              
     Exclusions,                                   
         InclusionsNumber,                                              
         AccountUsed,                
         SenderID,                                              
         [Message],                                              
         TemplateID,                                 
         TemplateGroupID,                                              
         IsUnicode,                                              
         MailReplyTo,                                              
         MailSubject,                                              
         MailContent,                                               TrackResponse,                                              
         TrackShortURL,                                              
         UnsubscribePage,                               
         UnsubscribeShortURL,                                 
         Tags,                                              
         IsRunAfter,                                              
         IsSchedule,                                              
         ScheduleID,                                              
         NextExecuteDateTime,                                              
         IsActive,                                              
         CreatedOn,                                              
         Createdby,                                              
         ExpiryDate,                                              
         EventsName,                                              
         ApplicabiltyGroupList,                                              
         ExclusionsGroupList,                                              
  NotificationMail,                                              
         SuccessNotificationEmail,                                              
         FailureNotificationEmail,                                              
         IsRecurring,                                              
         IsEnding,                                              
         TemplateGroupSequence,                                              
         IsNeverExpire,                                     
         RunAtHours,                                              
         RunAtMin,                                              
         StartDate,                                              
         IsSurplusExclusions,                                          
         Medium,                                    
         FromMailID,                
         DLTTemplateID,            
         eventid,        
   TimeBeforeEvent,        
   TimeUnit                                       
       )                                              
     VALUES                                              
       (                                              
         @ParentID,                                              
         @CampaignName,                                              
         1,                                              
         0,                                              
         @Applicability,                         
         '',  --@ExclusionsNumber,                                            
         '', --@Exclusions,                                              
         '', --@InclusionsNumber,                                              
         @AccountUsed,                                              
         @SenderID,                                              
         @Message,                                              
         @TemplateID,                                              
         0,--@TemplateGroupID,                                              
         @IsUnicode,                                              
         '',--@MailReplyTo,                                              
         '',--@MailSubject,                                      
         '',--@MailContent,                                              
         '',--@TrackResponse,                                              
         '',--@TrackShortURL,                                              
         '',--@UnsubscribePage,                                              
         '',--@UnsubscribeShortURL,                                              
         '',--@Tags,                                              
     1,--@IsRunAfter,                                              
         0,--@IsSchedule,                                              
         0,--@ScheduleID,                                              
                                           
         --@NextExecuteDateTime,               
         dbo.[fn_getISTtimefromusertime](@ParentID,@NextExecuteDateTime),                                  
         @IsActive,                                              
         GETDATE(),                                              
         @UserID,                                              
                                           
         --@ExpiryDate,                                
         dbo.[fn_getISTtimefromusertime](@ParentID,@ExpiryDate),                                  
                
         '', --@EventsName,                                              
         '', -- @ApplicabilityGroup,                                              
         '',--@ExclusionsGroup,                                              
         '',--@NotificationEmail,                                      
         '',--@SuccessNotificationEmail,                                              
         '',--@FailureNotificationEmail,                                              
         0,--@IsRecurring,                                              
         1,--@IsEnding,                                              
         1,--@TemplateGroupSequence,                                              
         1,--@IsNeverExpire,                          
         '',--@RunAfterHr,                                              
         '',--@RunAfterMin,                                              
         @StartDate,                                              
         --dbo.[fn_getISTtimefromusertime](@ParentID,@StartDate),                                  
         0,--@IsSurplusExclusions ,                                          
         'SMS',                                    
         '',--isnull(nullif(@FromMailID,''),'contactus@email19.in'),                
         @DLTTemplateID,            
         @EventID ,        
         @TimeBeforeUnit,        
   @TimeUnit        
                   
    )                                  
                                                   
     DECLARE @CID BIGINT = scope_identity()                               
                   
    update triggeredcampaigns set  smscampaignid =  @CID where id = @TRGCampaignID            
            
            
-- if (@MediumSMSORMail='Voice')                  
-- begin                                
--exec usp_updatevoicecampaignroute  @CID                                    
-- end                  
                                    
  if (select isschedule from UserCampaignMaster where id=@cid)=1                                  
  begin                                  
  create table #temp(campaignid bigint,nextexecution datetime)                                  
  insert into #temp(campaignid,nextexecution)                                  
  exec usp_getNextScheduleDate @cid                                  
  update u set NextExecuteDateTime=dbo.fn_getISTtimefromusertime(@UserID,isnull(nextexecution,getdate())) from UserCampaignMaster u join #temp t on u.id=t.campaignid                             
  where u.id=@CID                                  
  drop table #temp                                  
  end                                           
                                                   
  declare @lnkct int  = 0                                  
  declare @CountVoiceBroadcast int = 0                        
  select @lnkct= COUNT(*) from @tbl                         
                          
    select @CountVoiceBroadcast= COUNT(*) from @tblVoiceBroadcast                         
           
                               
 --if @lnkct >0                                    
 --   insert into dbo.Link_smsurl_Campaign (CampaignId, longurl, short_url, parentid, page_nm,                              
 --     lAction, CMobile, Email, subject, Body, wmobile, wtext, P_url                              
 --    )                                
 --    select @CID, long_url, short_url,@ParentID, 'Campaign  SMS',                              
 --    lAction, CMobile, Email, subject, Body , wmobile, wtext,P_url                               
 --     from @tbl                           
                             
                        
   declare @IsVoice_V bit = 0                        
      Declare @AppID_V bigint = 0                        
      Declare @Duration_V int = 0                        
      Declare @DNID_V nvarchar(20) = ''                  
      Declare @Frequency_V int = 0                        
      Declare @Latency_V int = 0                        
      Declare @Route_V nvarchar(20) = ''                        
                        
  if(@CountVoiceBroadcast > 0)                        
  Begin                        
          select top 1                       
           @IsVoice_V = isVoice                         
          ,@AppID_V =  AppID                         
         ,@Duration_V =  Duration                         
         ,@DNID_V   = DNID                         
         ,@Frequency_V = Frequency                         
         ,@Latency_V = Latency                  
          ,@Route_V = Route                         
          from @tblVoiceBroadcast                        
                        
  End                        
                        
                        
                        
   if @lnkct >0                         
   Begin                        
                                      
    insert into dbo.Link_smsUrl_dtl(BatchId,ccid, longurl, short_url, parentid, page_nm,                              
  lAction, CMobile, Email, subject, Body, wmobile, wtext, P_url                           
     )                                
     select 0,@CID, long_url, short_url,@ParentID, 'Campaign  SMS',                              
     lAction, CMobile, Email, subject, Body , wmobile, wtext,P_url                               
                             
  from @tbl                           
                           
    if(@CountVoiceBroadcast > 0)                        
  Begin                        
		 if(@IsVoice_V = 1)                      
		 Begin                      
			update Link_smsUrl_dtl set isVoice = @IsVoice_V ,AppID = @AppID_V ,Duration = @Duration_V ,DNID = @DNID_V,                        
			Frequency = @Frequency_V ,Latency = @Latency_V ,Route = @Route_V                        
			where ccid = @CID                        
			end                      
		 else                      
		 Begin                      
		  update Link_smsUrl_dtl set isVoice = 0                       
			where ccid = @CID                        
                          
	 	 End                      
     End                        
                             
   end                        
                                                              
                               
     --INSERT INTO UserCampaignSettings                                              
     --  (                                              
     --    NAME,                                              
     --    UserID,                                              
     -- IsEditable,                                     
     --    IsActive,                                              
     --    CreatedDate,                                              
     --    ModifiedDate,                                              
     --    ModifiedBy,                                              
     --    UserCampaignMasterID                                              
     --  )                                              
     --VALUES                                              
     --  (                                              
     --    @CampaignName,                                              
     --    @ParentID,                                              
     --    0,                                              
     --    1,                                              
     --    GETDATE(),                                              
     --    GETDATE(),                                              
     --    @UserID,                                              
     --  @CID                                            
     --  )                                                
                                                   
                                                   
                                                   
     --DECLARE @CampaignID BIGINT = (                                              
     --            SELECT TOP 1 ucs.CampaignID                                      
     --         FROM   UserCampaignSettings ucs                                              
     --            WHERE  ucs.Name = @CampaignName                                              
     --            AND ucs.UserID = @ParentID                                              
     --        )                                                
                                                   
                                                   
                                                   
   --  INSERT INTO UserSearchList                                              
   --    (                                              
   --      ParentID,                                              
   --      SearchName,                                              
   --      SearchType,                                              
   --      Medium,                                              
   --      Source,                                              
   --      Campaign,                                              
   --      CurrentlyAssignedTo,                       
   --      FollowUpStatus,                                              
   --IsPredefined,                                              
   --      IsResponse,                                              
   --      IsUnsubscribe,                                              
   --      IsSearch,                                              
   --      IsCustom,                                              
   --      CreatedOn,                                              
   --      CreatedBy                                              
   --    )                                              
   --  VALUES                                              
   --    (                                              
   --      @ParentID,                                              
   --      'Response - ' + @CampaignName,                                              
   --      'AL',                                       
   --      0,                                              
   --      0,                                              
   --      @CID,                                              
   --      0,                                              
   --      0,          
   --      0,                                              
   --      1,                                              
   --      0,                               
   --      0,                                              
   --      0,                                              
   --      GETDATE(),                                              
   --      @UserID                                              
   --    )                                                
                                              
        SELECT 'Success' as  Status ,  @CID as ID                                            
   END            
   else            
       Begin            
       select 'Campaign Name Already Exists' as Status , '0' as ID            
    End            
         
	  Label1:	 
 End 


GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveUserCampaignMaster_ForSMS_WithLinkURLDT_and_VoiceBroadcast_1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-------------------------------

CREATE   PROCEDURE [dbo].[Usp_SaveUserCampaignMaster_ForSMS_WithLinkURLDT_and_VoiceBroadcast_1]                  
(  
 @UserID BIGINT,                   
 @TRGCampaignID BIGINT,                                                    
 @AccountUsed BIGINT,                                                    
 @SenderID VARCHAR(500),                                                    
 @DLTTemplateID NVARCHAR(200),                  
 @Message NVARCHAR(2000),                                                    
 @IsUnicode BIT,                                                    
 @IsActive BIT,                                                    
 @tbl SMSUrl_Link_new READONLY,              
 @TimeBeforeUnit INT,              
 @TimeUnit NVARCHAR(20),   
 @MaxLimit INT,  
 @tblVoicebroadcast tblType_VoiceBroadCast READONLY                               
)                  
AS                  
BEGIN                  
  
    BEGIN TRY  
        -- Declare variables  
        DECLARE @ParentID BIGINT = 0;  
        DECLARE @CampaignName NVARCHAR(200) = '';                    
        DECLARE @EventID INT = 0;                   
        DECLARE @TemplateID BIGINT = 0;                  
        DECLARE @Applicability NVARCHAR(MAX) = '';                   
        DECLARE @NextExecuteDateTime NVARCHAR(50) = DATEADD(SS, 5, GETDATE());    
        DECLARE @ExpiryDate NVARCHAR(50) = '';  
        DECLARE @StartDate NVARCHAR(50) = '';   
		Declare @ScheduleIdID int = 0 ;
   Declare @IsScheduled BIT ;
   Declare @IsEventBased BIT ;
  
        -- Select data from User_Detail and triggeredcampaigns  
        SELECT TOP 1 @ParentID = ISNULL(ParentID, User_ID)   
        FROM User_Detail (NOLOCK)   
        WHERE User_ID = @UserID;  
  
        SELECT TOP 1 @CampaignName = (CAST(ISNULL(cname, '') AS NVARCHAR) + '_SMS'),  
                      @EventID = ISNULL(eventid, 0), 
					  @ScheduleIdID = isnull(Schedule,0) ,
                      @Applicability = ISNULL(Audience, '')  
        FROM triggeredcampaigns (NOLOCK)   
        WHERE id = @TRGCampaignID;  
  
		IF @ScheduleIdID > 0
BEGIN
    SET @IsScheduled = 1; 
    SET @IsEventBased = 1; 
END
ELSE
BEGIN
    SET @IsScheduled = 0; 
    SET @IsEventBased = 0; 
END


        -- Select Template ID  
        SELECT @TemplateID = ISNULL(ID, 0)   
        FROM UserMailTemplate (NOLOCK)   
        WHERE DLT_TemplateID = @DLTTemplateID;  
  
        -- Set TimeBeforeUnit and TimeUnit to null if TimeUnit is empty  
        IF (RTRIM(LTRIM(@TimeUnit)) = '')        
        BEGIN        
            SET @TimeBeforeUnit = NULL;  
            SET @TimeUnit = NULL;        
        END;        
  
        -- Insert into UserCampaignMaster if CampaignName does not exist  
        IF NOT EXISTS (SELECT 'x'   
                       FROM UserCampaignMaster AS ucm   
                       WHERE ucm.ParentID = @ParentID   
                         AND ucm.CampaignName = @CampaignName)                                                    
        BEGIN                      
            -- Set default ExpiryDate and StartDate  
            IF (@ExpiryDate = '') SET @ExpiryDate = NULL;  
            IF (@StartDate = '') SET @StartDate = CAST(GETDATE() AS NVARCHAR);  
  
            -- Insert data into UserCampaignMaster  
            INSERT INTO UserCampaignMaster                                                    
       (                                      
         ParentID,                                                    
         CampaignName,                         
         IsEventBased,                                                    
         IsScheduled,                                                    
         Applicabilty,                                                    
         ExclusionsNumber,                                                    
         Exclusions,                                         
         InclusionsNumber,                                                    
         AccountUsed,                      
         SenderID,                                                    
         [Message],                                                    
         TemplateID,                                       
         TemplateGroupID,                                                    
         IsUnicode,             
         MailReplyTo,                                                    
         MailSubject,                                                    
         MailContent,            
   TrackResponse,                                                    
         TrackShortURL,                                                    
         UnsubscribePage,                                     
         UnsubscribeShortURL,                                       
         Tags,                                                    
         IsRunAfter,                                                    
         IsSchedule,                                                    
         ScheduleID,                                                    
         NextExecuteDateTime,                                                    
         IsActive,                                                    
         CreatedOn,                                                    
         Createdby,                                                    
         ExpiryDate,                                                    
         EventsName,                                                    
         ApplicabiltyGroupList,                                                    
         ExclusionsGroupList,                                                    
  NotificationMail,                                                    
         SuccessNotificationEmail,                                                    
         FailureNotificationEmail,                                                    
         IsRecurring,                                                    
         IsEnding,                                                    
         TemplateGroupSequence,                                                    
         IsNeverExpire,                                           
         RunAtHours,                                                    
         RunAtMin,                                                    
         StartDate,                                                    
         IsSurplusExclusions,                                                
         Medium,                                          
         FromMailID,                      
         DLTTemplateID,                  
         eventid,              
   TimeBeforeEvent,              
   TimeUnit ,  
   maxlimit  
       )                                                    
     VALUES                                                    
       (                                                    
         @ParentID,                                                    
         @CampaignName,                                                    
         @IsEventBased,                                                    
        @IsScheduled,                
         @Applicability,                               
         '',  --@ExclusionsNumber,                                                  
         '', --@Exclusions,                                                    
         '', --@InclusionsNumber,                                   
         @AccountUsed,                                                    
         @SenderID,                                                    
         @Message,                                                    
         @TemplateID,                                                    
         0,--@TemplateGroupID,                                                    
         @IsUnicode,                                                    
         '',--@MailReplyTo,                                                    
         '',--@MailSubject,                                            
         '',--@MailContent,                                                    
         '',--@TrackResponse,                                                    
         '',--@TrackShortURL,                                                    
         '',--@UnsubscribePage,                            
         '',--@UnsubscribeShortURL,                                                    
         '',--@Tags,                                                    
     1,--@IsRunAfter,                                                    
        @IsScheduled,--@IsSchedule,                                                    
         @ScheduleIdID,--@ScheduleID,                                                    
                                                 
         --@NextExecuteDateTime,                     
         dbo.[fn_getISTtimefromusertime](@ParentID,@NextExecuteDateTime),                                        
         @IsActive,                                                    
         GETDATE(),                                                    
         @UserID,                                                    
                                                 
         --@ExpiryDate,                                      
         dbo.[fn_getISTtimefromusertime](@ParentID,@ExpiryDate),                                        
                      
         '', --@EventsName,                                                    
         '', -- @ApplicabilityGroup,                                                    
         '',--@ExclusionsGroup,                                                    
         '',--@NotificationEmail,                                            
         '',--@SuccessNotificationEmail,                                                    
         '',--@FailureNotificationEmail,                                                    
         0,--@IsRecurring,                                                    
         1,--@IsEnding,                                                    
         1,--@TemplateGroupSequence,                                                    
         1,--@IsNeverExpire,                                
         '',--@RunAfterHr,                                                    
         '',--@RunAfterMin,                                                    
         --@StartDate,                                                    
         dbo.[fn_getISTtimefromusertime](@ParentID,@StartDate),                                        
         0,--@IsSurplusExclusions ,                                                
         'SMS',                                          
         '',--isnull(nullif(@FromMailID,''),'contactus@email19.in'),                      
         @DLTTemplateID,                  
         @EventID ,              
         @TimeBeforeUnit,              
   @TimeUnit ,  
   @MaxLimit  
                         
    )       
  
            DECLARE @CID BIGINT = SCOPE_IDENTITY();  
  
            -- Update triggeredcampaigns with SMSCampaignID  
            UPDATE triggeredcampaigns   
            SET smscampaignid = @CID   
            WHERE id = @TRGCampaignID;  
  
            -- Handle scheduling logic  
            IF (SELECT isschedule FROM UserCampaignMaster WHERE id = @CID) = 1  
            BEGIN  
                CREATE TABLE #temp (campaignid BIGINT, nextexecution DATETIME);  
                INSERT INTO #temp (campaignid, nextexecution)   
                EXEC usp_getNextScheduleDate @CID;  
                  
                UPDATE u   
                SET NextExecuteDateTime = dbo.fn_getISTtimefromusertime(@UserID, ISNULL(nextexecution, GETDATE()))   
                FROM UserCampaignMaster u   
                JOIN #temp t ON u.id = t.campaignid  
                WHERE u.id = @CID;  
  
                DROP TABLE #temp;  
            END;  
  
            -- Handle link URL and voice broadcast logic  
            DECLARE @lnkct INT = (SELECT COUNT(*) FROM @tbl);  
            DECLARE @CountVoiceBroadcast INT = (SELECT COUNT(*) FROM @tblVoiceBroadcast);  
  
            -- Insert into Link_smsUrl_dtl if link count is greater than 0  
            IF @lnkct > 0   
            BEGIN  
                INSERT INTO dbo.Link_smsUrl_dtl  
                (BatchId, ccid, longurl, short_url, parentid, page_nm, lAction, CMobile, Email, subject, Body, wmobile, wtext, P_url)  
                SELECT 0, @CID, long_url, short_url, @ParentID, 'Campaign  SMS', lAction, CMobile, Email, subject, Body, wmobile, wtext, P_url  
                FROM @tbl;  
  
                -- Update Link_smsUrl_dtl if voice broadcast exists  
                IF @CountVoiceBroadcast > 0  
                BEGIN  
                    DECLARE @IsVoice_V BIT = 0;  
                    DECLARE @AppID_V BIGINT = 0;  
                    DECLARE @Duration_V INT = 0;  
                    DECLARE @DNID_V NVARCHAR(20) = '';  
                    DECLARE @Frequency_V INT = 0;  
                    DECLARE @Latency_V INT = 0;  
                    DECLARE @Route_V NVARCHAR(20) = '';  
  
                    SELECT TOP 1  
                        @IsVoice_V = isVoice,  
                        @AppID_V = AppID,  
                        @Duration_V = Duration,  
                        @DNID_V = DNID,  
                        @Frequency_V = Frequency,  
                        @Latency_V = Latency,  
                        @Route_V = Route  
                    FROM @tblVoiceBroadcast;  
  
                    IF (@IsVoice_V = 1)  
                    BEGIN  
                        UPDATE Link_smsUrl_dtl   
                        SET isVoice = @IsVoice_V, AppID = @AppID_V, Duration = @Duration_V, DNID = @DNID_V,   
                            Frequency = @Frequency_V, Latency = @Latency_V, Route = @Route_V  
                        WHERE ccid = @CID;  
                    END  
                    ELSE  
                    BEGIN  
                        UPDATE Link_smsUrl_dtl   
                        SET isVoice = 0  
                        WHERE ccid = @CID;  
                    END;  
                END;  
            END;  
  
            -- Generate JSON for audit  
            DECLARE @rowJson NVARCHAR(MAX);  
            SET @rowJson = (SELECT * FROM UserCampaignMaster WHERE id = @CID FOR JSON AUTO);  
  
            -- Call audit procedure  
            EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId   
                @User_id = @UserID,  
                @Activity_type = 'Campaign Creation',  
                @ActionType = 'C',  
                @RowJson = @rowJson,  
                @Table_name = 'UserCampaignMaster';  
  
            -- Return success  
            SELECT 'Success' AS Status, @CID AS ID;  
        END  
        ELSE  
        BEGIN  
            -- Return failure for duplicate Campaign Name  
            SELECT 'Campaign Name Already Exists' AS Status, '0' AS ID;  
        END;  
    END TRY  
  
    -- Catch block to handle errors  
    BEGIN CATCH  
        -- Log error information  
        EXEC usp_InsertErrorInfo;  
    END CATCH  
  
END;  




GO

/* ============================================================
   Procedure: [dbo].[Usp_SaveUserCampaignMaster_ForSMS_Without_LinkURLDT]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
       
      
CREATE   PROCEDURE [dbo].[Usp_SaveUserCampaignMaster_ForSMS_Without_LinkURLDT]            
(            
 @UserID bigint,             
 @TRGCampaignID bigint,                                              
 @AccountUsed BIGINT,                                              
 @SenderID VARCHAR(500),                                              
 @DLTTemplateID nvarchar(200),            
 @Message NVARCHAR(2000),                                              
 @IsUnicode BIT,                                              
 @IsActive BIT,                                              
 --@tbl SMSUrl_Link_new READONLY      
 @TimeBeforeUnit int,      
 @TimeUnit nvarchar(20)                         
)            
As            
 Begin            
            
    Declare @ParentID bigint = 0             
 Declare @CampaignName nvarchar(200) = ''              
 Declare @EventID int = 0             
 Declare @TemplateID bigint = 0            
 Declare @Applicability nvarchar(max) = ''             
            
            
  select  top 1 @ParentID = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @UserID                  
  
        if(isnull(@ParentID,0) = 0 or isnull(@UserID,0) = 0 )
	    begin
		     select 'May be Session expired: unexpected userid & Parentid value' as Status , '0' as ID        
		     goto Label1  
		end   
  
  select top 1  @CampaignName = ( CAST(isnull(cname,'') as nvarchar)+ '_SMS')            
   , @EventID = isnull(eventid,0) , @Applicability = isnull(Audience,'')  from triggeredcampaigns(nolock) where id = @TRGCampaignID              
              
   select @TemplateID = isnull(ID,0) from UserMailTemplate(nolock) where DLT_TemplateID = @DLTTemplateID            
            
   -- if(@EventID not in (152,153,154,155))      
   --Begin      
   --   set @TimeBeforeUnit = null      
   --set @TimeUnit = null      
   --End      
      
    if(rtrim(ltrim(@TimeUnit)) = '')  
       Begin  
        set @TimeBeforeUnit = null        
              set @TimeUnit = null  
    End  
  
              
   IF NOT EXISTS (                                              
