  @TimeUnit nvarchar(20)        
)          
as          
Begin          
          
    Declare @ParentID bigint = 0               
    Declare @CampaignName nvarchar(200) = ''                
    Declare @EventID int = 0               
    Declare @Applicability nvarchar(max) = ''               
              
              
      select  top 1 @ParentID = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @UserID                    
      
	    if(isnull(@ParentID,0) = 0 or isnull(@UserID,0) = 0 )
	    begin
		     select 'May be Session expired: unexpected userid & Parentid value' as Status , '0' as ID        
		     goto Label1  
		end   

	  
	  select top 1  @CampaignName = ( CAST(isnull(cname,'') as nvarchar)+ '_Mail')              
          , @EventID = isnull(eventid,0) , @Applicability = isnull(Audience,'')  from triggeredcampaigns(nolock) where id = @TRGCampaignID              
          
    --  if(@EventID not in (152,153,154,155))        
    --Begin        
    --set @TimeBeforeEvent = null        
    --   set @TimeUnit = null        
    --End          
        
   if(rtrim(ltrim(@TimeUnit)) = '')  
       Begin  
        set @TimeBeforeEvent = null        
              set @TimeUnit = null  
    End  
      
        
          
      IF NOT EXISTS (                                                
        SELECT 'x'                                                
        FROM   UserCampaignMaster AS ucm                                                
        WHERE  ucm.ParentID = @ParentID                                                
               AND ucm.CampaignName = @CampaignName                                                
       )                                                
     BEGIN            
              
        Declare @ExpiryDate nvarchar(50) = ''                
  Declare @StartDate nvarchar(50) = ''               
  Declare @NextExecuteDateTime nvarchar(50) = dateadd(ss,5,getdate())               
                                                 
     IF (@ExpiryDate = '')                                                
     BEGIN                                                
         SET @ExpiryDate = NULL                                                
     END                                                  
                                                     
                                                     
                                                     
     --IF (@StartDate = '')                                                
     --BEGIN                                                
     --    SET @StartDate = CAST(GETDATE() AS nvarchar)                                                
     --END                                                  
      
	   IF (isnull(@StartDate,'') = '')                                              
     BEGIN                                              
         SET @StartDate = CAST(GETDATE() AS nvarchar)                                              
     END
	 else
	  begin
	     SET @StartDate = dbo.[fn_getISTtimefromusertime](@ParentID,@StartDate);
	  end

	  

                                                    
   --if dbo.[fn_getISTtimefromusertime](@ParentID,@NextExecuteDateTime) < getdate()                                      
   --   begin                                      
   --   set @nextexecutedatetime=dateadd(ss,15,getdate())                                      
   --   end                                      
                           
                                            
                                                     
     INSERT INTO UserCampaignMaster                                                
       (                                  
         ParentID,                                                
         CampaignName,                                                
         IsEventBased,                                                
         IsScheduled,                                                
         Applicabilty,                          
         ExclusionsNumber,                                                
         Exclusions,                                     
         InclusionsNumber,                                                
         AccountUsed,                                                
      SenderID,                                                
         [Message],                                                
         TemplateID,                       
         TemplateGroupID,                                                
         IsUnicode,                                                
         MailReplyTo,                                                
         MailSubject,                                                
         MailContent,                 
         TrackResponse,                                 
         TrackShortURL,                                                
         UnsubscribePage,                                 
         UnsubscribeShortURL,                                   
         Tags,                                                
         IsRunAfter,                                                
         IsSchedule,                                                
         ScheduleID,                                                
         NextExecuteDateTime,                                                
         IsActive,                                                
         CreatedOn,                                                
         Createdby,                                                
         ExpiryDate,                                                
         EventsName,                                                
         ApplicabiltyGroupList,                                                
         ExclusionsGroupList,                                                
  NotificationMail,                                                
         SuccessNotificationEmail,                                                
         FailureNotificationEmail,                                                
         IsRecurring,                                                
         IsEnding,                                                
         TemplateGroupSequence,                                                
         IsNeverExpire,                                       
         RunAtHours,                                                
         RunAtMin,                                                
         StartDate,                                                
         IsSurplusExclusions,                                            
         Medium,                                      
         FromMailID,                  
         DLTTemplateID,              
         eventid,      
   TimeBeforeEvent,      
   TimeUnit                                         
       )                                                
     VALUES                                                
       (                                                
         @ParentID,                                                
         @CampaignName,                                                
         1,                                                
         0,                                                
         @Applicability,                           
         '',  --@ExclusionsNumber,                                              
         '', --@Exclusions,                                                
         '', --@InclusionsNumber,                                                
         @AccountUsed,                                                
         '',--@SenderID,                                                
         '',--@Message,                                                
         @TemplateID,                                                
         0,--@TemplateGroupID,                                                
         0,--@IsUnicode,                             
         @MailReplyTo,                                                
         @MailSubject,                                        
         @MailContent,                                                
         '',--@TrackResponse,                                                
         '',--@TrackShortURL,                                                
         '',--@UnsubscribePage,                                       
         '',--@UnsubscribeShortURL,                                                
         '',--@Tags,                                                
         1,--@IsRunAfter,                                                
         0,--@IsSchedule,                                                
         0,--@ScheduleID,                                                
                                             
         --@NextExecuteDateTime,                                   
         dbo.[fn_getISTtimefromusertime](@ParentID,@NextExecuteDateTime),                                    
         @IsActive,                                                
         GETDATE(),                                                
         @UserID,               
                                             
         --@ExpiryDate,                                  
         dbo.[fn_getISTtimefromusertime](@ParentID,@ExpiryDate),                                    
                       
         '', --@EventsName,                                                
         '', -- @ApplicabilityGroup,                                                
         '',--@ExclusionsGroup,                                                
         '',--@NotificationEmail,                                        
         '',--@SuccessNotificationEmail,                                                
         '',--@FailureNotificationEmail,                                                
         0,--@IsRecurring,                                                
         1,--@IsEnding,                                                
         1,--@TemplateGroupSequence,                                                
         1,--@IsNeverExpire,                            
         '',--@RunAfterHr,                                                
         '',--@RunAfterMin,                                                
         @StartDate,                                                
         --dbo.[fn_getISTtimefromusertime](@ParentID,@StartDate),                                    
         0,--@IsSurplusExclusions ,                                            
         'Mail',                                      
         isnull(nullif(@FromMailID,''),'contactus@email19.in'),                  
         '',--@dltemplateid              
         @EventID,                                               
         @TimeBeforeEvent,      
   @TimeUnit            
    )                                    
                                                     
     DECLARE @CID BIGINT = scope_identity()                                 
                     
     update triggeredcampaigns set  mailcampaignid =  @CID where id = @TRGCampaignID          
          
          
--   INSERT INTO UserCampaignSettings                                                
--       (                                                
--         NAME,                                                
--         UserID,                                                
--      IsEditable,                                       
--         IsActive,                                                
--         CreatedDate,                                                
--         ModifiedDate,                                                
--         ModifiedBy,                                                
--         UserCampaignMasterID                                                
--       )                                                
--     VALUES                                                
