----------------------------------------------------
CREATE   PROCEDURE [dbo].[Usp_SaveUserCampaignMasterForMail_FromTRG_1]        
(        
  @UserID bigint,             
  @TRGCampaignID bigint,                                              
  @AccountUsed BIGINT,         
  @FromMailID nvarchar(500),        
  @MailReplyTo NVARCHAR(500),        
  @TemplateID BIGINT,        
  @MailSubject NVARCHAR(500),                                          
  @MailContent NVARCHAR(MAX),         
  @IsActive BIT,          
  @TimeBeforeEvent int,      
  @TimeUnit nvarchar(20),
  @MaxLimit int
)        
as        
Begin        
      Begin Try 
    Declare @ParentID bigint = 0             
    Declare @CampaignName nvarchar(200) = ''              
    Declare @EventID int = 0             
    Declare @Applicability nvarchar(max) = ''
	Declare @ScheduleIdID int = 0 
   Declare @IsScheduled BIT 
    Declare @IsEventBased BIT 
            
            
      select  top 1 @ParentID = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @UserID                  
      select top 1  @CampaignName = ( CAST(isnull(cname,'') as nvarchar)+ '_Mail')            
          , @EventID = isnull(eventid,0) ,@ScheduleIdID = isnull(Schedule,0) , @Applicability = isnull(Audience,'')  from triggeredcampaigns(nolock) where id = @TRGCampaignID            
        
    --  if(@EventID not in (152,153,154,155))      
    --Begin      
    --set @TimeBeforeEvent = null      
    --   set @TimeUnit = null      
    --End        
     IF @ScheduleIdID > 0
BEGIN
    SET @IsScheduled = 1; 
    SET @IsEventBased = 0; 
END
ELSE
BEGIN
    SET @IsScheduled = 0; 
    SET @IsEventBased = 1; 
END
      
        
      IF NOT EXISTS (                                              
        SELECT 'x'                                              
        FROM   UserCampaignMaster AS ucm                                              
        WHERE  ucm.ParentID = @ParentID                                              
               AND ucm.CampaignName = @CampaignName                                              
       )                                              
