         SET @ExpiryDate = NULL                                              
     END                                                
                                                   
                                                   
                                                   
     IF (@StartDate = '')                                              
     BEGIN                                              
         SET @StartDate = CAST(GETDATE() AS nvarchar)                                              
     END                                                
                                                   
                                                  
