         IsScheduled,                                              
         Applicabilty,                                              
         ExclusionsNumber,                                              
         Exclusions,                                   
         InclusionsNumber,                                              
         AccountUsed,                                              
      SenderID,                                              
         [Message],                                              
         TemplateID,                     
         TemplateGroupID,                                              
         IsUnicode,                                              
         MailReplyTo,                                              
         MailSubject,                                              
         MailContent,               
         TrackResponse,                               
         TrackShortURL,                                              
         UnsubscribePage,                               
         UnsubscribeShortURL,                                 
         Tags,                                              
         IsRunAfter,                                              
         IsSchedule,                                              
         ScheduleID,                                              
         NextExecuteDateTime,                                              
         IsActive,                                              
         CreatedOn,                                              
         Createdby,                                              
         ExpiryDate,                                              
         EventsName,                                              
         ApplicabiltyGroupList,                                              
         ExclusionsGroupList,                                              
  NotificationMail,                                              
         SuccessNotificationEmail,                                              
         FailureNotificationEmail,                                              
         IsRecurring,                                              
         IsEnding,                                              
         TemplateGroupSequence,                                              
         IsNeverExpire,                                     
         RunAtHours,                                              
         RunAtMin,                                              
         StartDate,                                              
         IsSurplusExclusions,                                          
         Medium,                                    
         FromMailID,                
         DLTTemplateID,            
         eventid,    
   TimeBeforeEvent,    
   TimeUnit,
   maxlimit
       )                                              
     VALUES                                              
       (                                              
         @ParentID,                                              
         @CampaignName,                                              
         1,                                              
         @IsScheduled,                                              
         @Applicability,                         
         '',  --@ExclusionsNumber,                                            
         '', --@Exclusions,                                              
         '', --@InclusionsNumber,                                              
         @AccountUsed,                                              
         '',--@SenderID,                                              
         '',--@Message,                                              
         @TemplateID,                                              
         0,--@TemplateGroupID,                                              
         0,--@IsUnicode,                                              
         @MailReplyTo,                                              
         @MailSubject,                                      
         @MailContent,                                              
         '',--@TrackResponse,                                              
         '',--@TrackShortURL,                                              
         '',--@UnsubscribePage,                                     
         '',--@UnsubscribeShortURL,                                              
         '',--@Tags,                                              
         1,--@IsRunAfter,                                              
         @IsScheduled,--@IsSchedule,                                              
         @ScheduleIdID,--@ScheduleID,                                              
                                           
         --@NextExecuteDateTime,                                 
         dbo.[fn_getISTtimefromusertime](@ParentID,@NextExecuteDateTime),                                  
         @IsActive,                                              
         GETDATE(),                                              
         @UserID,             
                                           
         --@ExpiryDate,                                
         dbo.[fn_getISTtimefromusertime](@ParentID,@ExpiryDate),                                  
                     
         '', --@EventsName,                                              
         '', -- @ApplicabilityGroup,                                              
         '',--@ExclusionsGroup,                                              
         '',--@NotificationEmail,                                      
         '',--@SuccessNotificationEmail,                                              
         '',--@FailureNotificationEmail,                                              
         0,--@IsRecurring,                                              
         1,--@IsEnding,                                              
         1,--@TemplateGroupSequence,                                              
         1,--@IsNeverExpire,                          
         '',--@RunAfterHr,                                              
         '',--@RunAfterMin,                                              
         --@StartDate,                                              
         dbo.[fn_getISTtimefromusertime](@ParentID,@StartDate),                                  
         0,--@IsSurplusExclusions ,                                          
         'Mail',                                    
         isnull(nullif(@FromMailID,''),'contactus@email19.in'),                
         '',--@dltemplateid            
         @EventID,                                             
         @TimeBeforeEvent,    
   @TimeUnit ,
   @MaxLimit
    )                                  
                                                   
     DECLARE @CID BIGINT = scope_identity()                               
                   
     update triggeredcampaigns set  mailcampaignid =  @CID where id = @TRGCampaignID        
        
        
   INSERT INTO UserCampaignSettings                                              
       (                                              
         NAME,                                              
         UserID,                                              
      IsEditable,                                     
         IsActive,                                              
         CreatedDate,                                              
         ModifiedDate,                                              
         ModifiedBy,                                              
         UserCampaignMasterID                                              
       )                                              
     VALUES                                              
       (                                              
         @CampaignName,                                              
         @ParentID,                                              
         0,                                              
         1,                                              
         GETDATE(),                                              
         GETDATE(),                                              
         @UserID,                                              
         @CID                  
       )                                                
                                                   
                                                   
                                                   
     DECLARE @CampaignID BIGINT = (                                              
                 SELECT TOP 1 ucs.CampaignID                                      
              FROM   UserCampaignSettings ucs                                              
                 WHERE  ucs.Name = @CampaignName                                              
                        AND ucs.UserID = @ParentID                                              
             )                                                
                                                   
                                                   
                                                   
   --  INSERT INTO UserSearchList                                              
   --    (                                              
   --      ParentID,                
   --      SearchName,                                              
   --      SearchType,                                              
   --      Medium,                                              
   --      Source,                                              
   --      Campaign,                                              
   --      CurrentlyAssignedTo,                                              
   --      FollowUpStatus,                   
   --IsPredefined,                                              
   --      IsResponse,                                              
   --      IsUnsubscribe,                                              
   --      IsSearch,                                              
   --      IsCustom,                                              
   --      CreatedOn,                                              
   --      CreatedBy                                              
   --    )                                              
   --  VALUES                                              
   --    (                                              
   --      @ParentID,                                              
   --      'Response - ' + @CampaignName,                                        
   --      'AL',                                       
   --      0,                                              
   --      0,                                              
   --      @CID,                                              
   --      0,                                              
   --      0,                                              
   --      0,                                              
   --      1,                                              
   --      0,                               
   --      0,                                              
   --      0,                                              
   --      GETDATE(),                                              
   --      @UserID                                              
   --    )                                                
                                              
        -- Generate JSON for audit
            DECLARE @rowJson NVARCHAR(MAX);
            SET @rowJson = (SELECT * FROM UserCampaignMaster WHERE id = @CID FOR JSON AUTO);

            -- Call audit procedure
            EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId 
                @User_id = @UserID,
                @Activity_type = 'Campaign Creation',
                @ActionType = 'C',
                @RowJson = @rowJson,
                @Table_name = 'UserCampaignMaster';

            -- Return success
            SELECT 'Success' AS Status, @CID AS ID;
        END
        ELSE
        BEGIN
            -- Return failure for duplicate Campaign Name
            SELECT 'Campaign Name Already Exists' AS Status, '0' AS ID;
        END;
    END TRY

    -- Catch block to handle errors
    BEGIN CATCH
        -- Log error information
        EXEC usp_InsertErrorInfo;
    END CATCH

END;



