         @UserID,                                              
         @CID                  
       )                                                
                                                   
                                                   
                                                   
     DECLARE @CampaignID BIGINT = (                                              
                 SELECT TOP 1 ucs.CampaignID                                      
              FROM   UserCampaignSettings ucs                                              
                 WHERE  ucs.Name = @CampaignName                                              
                        AND ucs.UserID = @ParentID                                              
             )                                                
                                                   
                                                   
                                                   
   --  INSERT INTO UserSearchList                                              
   --    (                                              
   --      ParentID,                
   --      SearchName,                                              
   --      SearchType,                                              
   --      Medium,                                              
   --      Source,                                              
   --      Campaign,                                              
   --      CurrentlyAssignedTo,                                              
   --      FollowUpStatus,                   
   --IsPredefined,                                              
   --      IsResponse,                                              
   --      IsUnsubscribe,                                              
   --      IsSearch,                                              
   --      IsCustom,                                              
   --      CreatedOn,                                              
   --      CreatedBy                                              
   --    )                                              
   --  VALUES                                              
   --    (                                              
   --      @ParentID,                                              
   --      'Response - ' + @CampaignName,                                        
   --      'AL',                                       
   --      0,                                              
   --      0,                                              
   --      @CID,                                              
   --      0,                                              
   --      0,                                              
   --      0,                                              
   --      1,                                              
   --      0,                               
   --      0,                                              
   --      0,                                              
   --      GETDATE(),                                              
   --      @UserID                                              
   --    )                                                
                                              
        -- Generate JSON for audit
            DECLARE @rowJson NVARCHAR(MAX);
            SET @rowJson = (SELECT * FROM UserCampaignMaster WHERE id = @CID FOR JSON AUTO);

            -- Call audit procedure
            EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId 
                @User_id = @UserID,
                @Activity_type = 'Campaign Creation',
                @ActionType = 'C',
                @RowJson = @rowJson,
                @Table_name = 'UserCampaignMaster';

            -- Return success
            SELECT 'Success' AS Status, @CID AS ID;
        END
        ELSE
        BEGIN
            -- Return failure for duplicate Campaign Name
            SELECT 'Campaign Name Already Exists' AS Status, '0' AS ID;
        END;
    END TRY

    -- Catch block to handle errors
    BEGIN CATCH
        -- Log error information
        EXEC usp_InsertErrorInfo;
    END CATCH

END;



GO

