/* ============================================================
   Procedure: [dbo].[usp_SaveUserEngagementTrack]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_SaveUserEngagementTrack]  
    @UserID bigint,  
 @PageURL NVARCHAR(255),  @SpendTime FLOAT,  @InactiveTime FLOAT,  
 @Mode NVARCHAR(50)  
  
AS  
BEGIN  
     declare @UserEngMasterId bigint    
  declare @CountRow int   
  
 SET @CountRow = (SELECT COUNT(*)                   FROM tbl_user_engagement_track_master WITH (NOLOCK)                  WHERE UserID = @UserID                     AND PageURL = @PageURL);     
 SET @UserEngMasterId = (SELECT TOP 1 EngagementID             
             FROM tbl_user_engagement_track_master WITH (NOLOCK)                         WHERE UserID = @UserID                            AND PageURL = @PageURL);  
    
	if(@CountRow = 0)  
 begin  
  INSERT INTO tbl_user_engagement_track_master (UserID,PageURL,CreatedDate)   
  VALUES (@UserID, @PageURL, GETDATE())  
  SET @UserEngMasterId = SCOPE_IDENTITY()  
   
 end  
 INSERT INTO tbl_user_engagement_track_details (UserEngMasterId,SpendTime,InactiveTime,CreatedDate,Mode)   
 VALUES (@UserEngMasterId, @SpendTime,@InactiveTime, GETDATE(),@Mode)  
END  


GO

