/* ============================================================
   Procedure: [dbo].[Usp_SaveUserInputDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_SaveUserInputDetails]
    @Name NVARCHAR(400),
    @Mobile NVARCHAR(400),
    @Email NVARCHAR(400),
    @Accesskey NVARCHAR(400)
AS
BEGIN
    DECLARE @ID BIGINT;
    DECLARE @ParentID BIGINT;
    DECLARE @EntityID BIGINT;
    DECLARE @EntityName VARCHAR(20);

    -- Get the ParentID based on the Accesskey
    SELECT @ParentID = ParentID 
    FROM WebLeadWidgetSetting 
    WHERE Accesskey = @Accesskey;

    -- Check for existing leads or enquiries
    IF EXISTS (
        SELECT 1 
        FROM UserLeads 
        WHERE ParentID = @ParentID 
        AND (@Mobile <> '' AND MobileNo = @Mobile) OR (@Email <> '' AND EmailID = @Email)
    )
    BEGIN
        -- If a lead exists, set EntityID for Lead
        SELECT @EntityID = (SELECT TOP 1 LeadNo 
                            FROM UserLeads 
                            WHERE ParentID = @ParentID 
                            AND (@Mobile <> '' AND MobileNo = @Mobile) OR (@Email <> '' AND EmailID = @Email));
        SET @EntityName = 'Lead';
    END
    ELSE
    BEGIN
        -- Check for existing enquiries
        IF EXISTS (
            SELECT 1 
            FROM UserEnquiry 
            WHERE ParentID = @ParentID 
            AND (@Mobile <> '' AND MobileNo = @Mobile) OR (@Email <> '' AND EmailID = @Email)
        )
        BEGIN
            -- If enquiries exist, set EntityID to the most recent enquiry
            SELECT @EntityID = (SELECT TOP 1 EnquiryID 
                                FROM UserEnquiry 
                                WHERE ParentID = @ParentID 
                                AND (@Mobile <> '' AND MobileNo = @Mobile) OR (@Email <> '' AND EmailID = @Email) 
                                ORDER BY EnquiryID DESC);
            SET @EntityName = 'Enquiry';
        END
        ELSE
        BEGIN
            -- Insert a new enquiry if none exist
            INSERT INTO UserEnquiry ([PersonName], [MobileNo], [EmailId], [ParentID], [CreatedDate],
			 [SourceName],[MediumName],[CampaignName],[IsOpen],[IsduplicateEmail],[IsduplicateMobile])
            VALUES (@Name, @Mobile, @Email, @ParentID, GETDATE(),0,0,0,0,0,0);

        -- Get the new EnquiryID
            SET @EntityID = SCOPE_IDENTITY();
            SET @EntityName = 'Enquiry';
       END
    END
	   
  set @ID = (select count(*) from WebLead where (@Mobile <> '' AND MobileNumber = @Mobile) OR (@Email <> '' AND EmailID = @Email));     

  if(@ID = 0) 
  BEGIN
    -- Insert into WebLead regardless of whether it's a Lead or Enquiry
    INSERT INTO WebLead ([Name], [MobileNumber], [EmailId], [ParentID], [EntityID], [EntityType], [CreatedDate], [IsActive])
    VALUES (@Name, @Mobile, @Email, @ParentID, @EntityID, @EntityName, GETDATE(), 1);

    -- Get the inserted WebLead ID
    SET @ID = SCOPE_IDENTITY();
	END
	
END




GO

