   Procedure: [dbo].[USP_SCHEDULE_DETAILS_ALL_SCHEDULE]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


 
 
 CREATE   PROC [dbo].[USP_SCHEDULE_DETAILS_ALL_SCHEDULE]  --10001,'07/16/2011','07/16/2011'    
@USERID BIGINT,    
@FROM_DATE VARCHAR(200),    
@TO_DATE VARCHAR(200)    
AS 
   
Declare @where varchar(max), @query varchar(max)
   
   set @where=''
   
 IF(@USERID!='')
 BEGIN
    SET @where=@where+' AND convert(varchar(10),BI.USERID)='+ convert(varchar(10),@USERID)+'  ' 
  END
  ELSE
  BEGIN
      SET @where=@where+' AND 1=1 '
  END
 IF(@FROM_DATE!='' and @TO_DATE!='')
 BEGIN
     SET @where=@where+' AND convert(nvarchar,convert(datetime,BI.scheduleddate,111),112)  between convert(nvarchar,convert(datetime,'''+@FROM_DATE+''',111),112)  and convert(nvarchar,convert(datetime,'''+@TO_DATE+''',111),112)  '
 END
 ELSE
 BEGIN
   SET @where=@where+' AND 1=1 '
 END
  
set @query='select distinct bi.batchid,bi.scheduledDate,bi.ScheduledTime,cds.message,bi.TotalRecords,bi.IsPrority,bi.userID
 from CloneMessageDeliveryStatus cds join batchinfo bi on cds.batchid=bi.batchid 
 where bi.dbtype=1 and bi.ScheduledTime!='''' and bi.isProcess is null  '    
 + @where


print(@query)
exec(@query)






