/* ============================================================
   Procedure: [dbo].[usp_ScrapBook]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
  
  
CREATE   PROCEDURE [dbo].[usp_ScrapBook]  
     @ScrapBookId int=null,  
  @Title nvarchar(max)=null,  
     @ItemType nvarchar(max)=null,  
     @Note nvarchar(max)=null,  
     @Theme nvarchar(max)=null,  
     @Action nvarchar(max)=null,  
     @Userid bigint=null,  
     @Active bit=null,  
  @PageNo INT,  
  @RecordsPerPage INT  
  
AS  
  
DECLARE @RecordCount INT  
  
BEGIN  
   if(@Action='InsertScrapBook')  
  BEGIN  
   --Change Set : Multiple upload is not working on ScrpBook Upload functionality.  
   --Only for Attachment / Upload section  
   IF(@ItemType='Attachment') --Split the attachment @Note  variable with # , and insert records as per found count.  
    BEGIN   
      CREATE TABLE #TemporaryAttachment -- Local #TemporaryAttachment table - starts with single # For Notes / Attachment Entry  
       (  
        Notes VARCHAR(2000)  
       )  
        
      INSERT INTO #TemporaryAttachment  
      (Notes)  
      SELECT value  
      FROM STRING_SPLIT(@Note, '#');  
  
        
      INSERT INTO tbl_scrapbook(Title,ItemType,Note,Theme,Active,UserId,CreatedBy,CreatedDate,[ModifiedBy],[ModifiedDate])  
      OUTPUT INSERTED.ScrapBookId  
      SELECT @Title,@ItemType,Notes,@Theme,@Active,@Userid,@Userid,GETDATE(),@Userid,GETDATE() FROM #TemporaryAttachment             
  
      DROP TABLE #TemporaryAttachment             
    END  
   ELSE  
    BEGIN   
  
    IF NOT EXISTS(SELECT ScrapBookId from tbl_scrapbook where Title=@Title ANd Note=@Note And UserId=@Userid And Active = 1 AND ItemType = 'Notes'  
      And convert(nvarchar,CreatedDate,101) = convert(nvarchar,getdate(),101))  
       begin  
        INSERT INTO tbl_scrapbook(Title,ItemType,Note,Theme,Active,UserId,CreatedBy,CreatedDate,[ModifiedBy],[ModifiedDate])  
        OUTPUT INSERTED.ScrapBookId  
        VALUES(@Title,@ItemType,@Note,@Theme,@Active,@Userid,@Userid,GETDATE(),@Userid,GETDATE());  
       End  
     Else  
       begin  
        INSERT INTO tbl_scrapbook(Title,ItemType,Note,Theme,Active,UserId,CreatedBy,CreatedDate,[ModifiedBy],[ModifiedDate])  
        OUTPUT INSERTED.ScrapBookId  
        VALUES(@Title,@ItemType,@Note,@Theme,@Active,@Userid,@Userid,GETDATE(),@Userid,GETDATE());  
       End  
    END  
  END  
   if(@Action='EditScrapBook')  
  begin  
   if(@ItemType='CheckList')  
   begin  
     update tbl_scrapbook set Title=@Title,Note=@Note,Theme=@Theme,[ModifiedBy]=@Userid,[ModifiedDate]=GETDATE()  
     where ScrapBookId=@ScrapBookId;  
     delete from tbl_scrapbook_checklistdetail where ScrapBooklId=@ScrapBookId;   
     end  
   else  
   begin  
     update tbl_scrapbook set Title=@Title,Note=@Note,Theme=@Theme,[ModifiedBy]=@Userid,[ModifiedDate]=GETDATE()  
     where ScrapBookId=@ScrapBookId;  
     return @ScrapBookId    
   end  
  end  
   if(@Action='DeleteScrapBook')  
  begin  
   delete from tbl_scrapbook where ScrapBookId=@ScrapBookId;  
   delete from tbl_scrapbook_checklistdetail where ScrapBooklId=@ScrapBookId;  
     end  
 IF(@Action='GetByUserId')  
  BEGIN   
   --Ticket :  : Apply paging functionality on Scrapbook  
   --Change Set :      
   SELECT  @RecordCount = count(*) FROM tbl_scrapbook  WHERE UserId=@Userid   
       
   IF (@PageNo < 1)    
    SET @PageNo = 1    
        
   SELECT  *,@RecordCount as RecordCount FROM tbl_scrapbook  WHERE UserId=@Userid   
   ORDER BY CreatedDate   DESC  
   OFFSET ( @PageNo - 1 ) * @RecordsPerPage ROWS    
   FETCH NEXT @RecordsPerPage ROWS ONLY    
      
  END  
 if(@Action='SearchText')  
  begin   
   --Ticket :  : Apply paging functionality on Scrapbook   
   --Change Set :    
   SELECT  @RecordCount = count(*) FROM tbl_scrapbook  WHERE UserId=@Userid   
    IF (@PageNo < 1)    
      SET @PageNo = 1    
     
   IF(@Note='' or @Note is null)  
     BEGIN  
      SELECT  *,@RecordCount as RecordCount FROM tbl_scrapbook  WHERE UserId=@Userid   
      ORDER BY CreatedDate   DESC  
      OFFSET ( @PageNo - 1 ) * @RecordsPerPage ROWS    
      FETCH NEXT @RecordsPerPage ROWS ONLY    
     END   
   ELSE  
     BEGIN  
      SELECT  *,@RecordCount as RecordCount FROM tbl_scrapbook  WHERE UserId=@Userid  and (Note like '%'+@Note+'%' or Title like '%'+@Note+'%')  
      ORDER BY CreatedDate   DESC  
      OFFSET ( @PageNo - 1 ) * @RecordsPerPage ROWS    
      FETCH NEXT @RecordsPerPage ROWS ONLY   
     END  
 END    
END



GO

