/* ============================================================
   Procedure: [dbo].[USP_seach_user_name1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.USP_seach_user_name1 --10000,2,'','','0'      
	@m_id BIGINT
	,@user_id INT
	,-- from bigint,      
	@grpname VARCHAR(20)
	,@contact_mobile NVARCHAR(20)
	,@contact_name VARCHAR(200)
AS
BEGIN
	DECLARE @wherecluse VARCHAR(500)
		,@query VARCHAR(500)

	SET @wherecluse = ''
	SET @query = ''

	IF (@contact_mobile = '')
	BEGIN
		SET @wherecluse = @wherecluse + ' and 1=1'
	END
	ELSE
	BEGIN
		SET @wherecluse = @wherecluse + ' and c.contact_mobile like ''%' + @contact_mobile + '%'''
	END

	IF (@contact_name = '')
	BEGIN
		SET @wherecluse = @wherecluse + ' and  1=1'
	END
	ELSE
	BEGIN
		SET @wherecluse = @wherecluse + ' and c.contact_name like ''%' + @contact_name + '%'''
	END

	IF (@grpname = 'Select Group')
	BEGIN
		SET @wherecluse = @wherecluse + ' and 1=1'
	END
	ELSE
	BEGIN
		SET @wherecluse = @wherecluse + ' and g.group_name =''' + @grpname + ''''
	END

	SET @query = 'select g.group_name,c.contact_mobile,cdg.group_id,c.m_id,c.user_id,c.contact_name from Contact_Detail c ,group_detail g,contact_group_detail cdg   
where g.group_id=cdg.group_id  and c.contact_id=cdg.contact_id and c.m_id=' + convert(VARCHAR, @m_id, 12) + ' and c.user_id=' + convert(VARCHAR, @user_id, 12) + ' ' + @wherecluse

	PRINT @query

	EXECUTE (@query)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @user_id
		,@Activity_type = 'View_usrgrp'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'group_detail'
END



