CREATE   PROC [dbo].[usp_Search_Requester]      
(      
 @ParentID BIGINT,      
 @SearchText AS VARCHAR(200)      
)      
AS      
BEGIN      
SET NOCOUNT on       
 SELECT  DISTINCT  Name,EmailID,leadimage FROM VW_UserLeads1       
  WHERE ParentID=@ParentID      
  AND       
   (      
    (EmailID = @SearchText AND EmailID<>'')      
    OR (MobileNo = @SearchText)      
    OR (MobileNo1 = @SearchText)      
    OR (MobileNo2 = @SearchText)      
    --OR (NAME like @SearchText+'%')      
   )      
 UNION       
 SELECT  DISTINCT Name ,EmailID,leadimage FROM VW_UserLeads2       
  WHERE ParentID=@ParentID      
  AND       
   (      
    (EmailID = @SearchText AND EmailID<>'')      
    OR (MobileNo = @SearchText AND MobileNo<>'')      
    OR (MobileNo1 = @SearchText AND MobileNo1<>'')      
    OR (MobileNo2 = @SearchText AND MobileNo2<>'')      
    --OR (NAME like @SearchText+'%' AND NAME<>'')      
   )      
UNION       
 SELECT  DISTINCT Name,EmailID,leadimage FROM VW_UserLeads3       
  WHERE ParentID=@ParentID      
  AND       
   (      
    (EmailID = @SearchText AND EmailID<>'')      
    OR (MobileNo = @SearchText AND MobileNo<>'')      
    OR (MobileNo1 = @SearchText AND MobileNo1<>'')      
    OR (MobileNo2 = @SearchText AND MobileNo2<>'')      
    --OR (NAME like @SearchText+'%' AND NAME<>'')      
   )      
  
   UNION       
 SELECT  DISTINCT Name,EmailID,leadimage FROM VW_Serv_User_Detail_Support       
  WHERE ParentID=@ParentID      
  AND       
   (      
    (EmailID = @SearchText AND EmailID<>'')      
    OR (MobileNo = @SearchText AND MobileNo<>'')      
    --OR (NAME like @SearchText+'%' AND NAME<>'')      
   )      
END 


