/* ============================================================
   Procedure: [dbo].[Usp_Search_Transaction_ByDate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- =============================================        
-- Author:  <vinay kumar upadhyay,chandra prakash singh>        
-- Create date: <Create Date,,>        
-- Description: <Description,,>        
-- =============================================       
CREATE   PROCEDURE [dbo].[Usp_Search_Transaction_ByDate] --'9910930090','11/11/2014','11/11/2014','1'      
@Mobile varchar(12),        
@Fromdate varchar(20),        
@Todate varchar(20) ,    
@User_ID varchar(20)    
      
        
as          
BEGIN   

   Select top 1 @User_ID = Cast(isnull(ParentID,0) as nvarchar) from User_Detail with(nolock) where User_ID = @User_ID     
     
 declare @query varchar(max)        
 declare @where varchar(max)        
 set @query=''        
 set @where=''        
 if(@Fromdate='' or @Todate='')        
begin        
set @where =@where+'1=1 and  '        
end        
else        
begin        
set @where =@where+' convert(nvarchar,convert(datetime, cd.[datecreated],104),112)          
between convert(nvarchar,convert(datetime, '''+@Fromdate+''', 104),112) and convert(nvarchar,convert(datetime, '''+@Todate+''', 104),112) and '        
end        
     if(@Mobile='' )        
   begin        
set @where =@where+'1=1 and  '        
   end        
   else         
   begin         
   set @where =@where+ 'us.Mobile  =''' +@Mobile+''' and ';        
   end      
   if(@User_ID='')    
   begin    
   set    
   @where=@where+'1=1 '    
   end    
   begin    
   set @where=@where+ 'cd.User_ID =''' +@User_ID+''' ';    
   end      
      
   SET NOCOUNT ON;         
  set @QUERY= ' select  cd.user_id,cd.credits,CAST(CAST(us.Mobile AS DECIMAL(20))AS VARCHAR(20)) as Mobile, cd.m_id,cd.credit_id,cd.balance,cd.debits,cd.datecreated from User_Detail us (nolock) inner join   Credit_details cd (nolock) on us.user_id=cd.user_id and us.m_id=cd.m_id where '+  @WHERE+'  '         
          
          
 print(@QUERY);        
exec(@QUERY)        
SET NOCOUNT OFF;        
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_SearchAccorMob]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_SearchAccorMob]      
@UserId int,                                                     
@SenderId nchar(20),   
@BatchId bigint, -- from int 
@mobile varchar(20)=null  
  
As  
Begin  
-- change the logic what does this condition do   
if ((@mobile is null) or @mobile='')  
Begin  
  
select Mobile as Mobile,  
CASE  
    WHEN priority=1   
     THEN 'H'  
    WHEN priority=2  
    THEN 'N'       
   ELSE 'L'  
     END as priority  
  
from dbo.MessageStorage  WITH (NOLOCK) where U_ID=@UserId and senderid=@SenderId  and MessageBatchID=@BatchId   
End  
else  
select Mobile as Mobile,priority from MessageStorage ms WITH (NOLOCK)  where U_ID=@UserId and senderid=@SenderId  and MessageBatchID=@BatchId   
and Mobile=@mobile  
End  
  
  


GO

