/* ============================================================
   Procedure: [dbo].[usp_SearchBatch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/****************************************************************************  
  
SP_Name        : [usp_SearchBatch]                     
Author         : vinay  
Created ON     : 24/12/2009 04:30 PM        
Version        : 1  
Alter BY       :          
Alter Date     :   
Location       :    
SP Description : Proc is used to select records from MessageStorage
              
****************************************************************************/
   
CREATE   PROC [dbo].[usp_SearchBatch]      
@UserId int,  
@SenderID nchar(20)=''   
As  
Begin  
select distinct MessageBatchID as BatchId,  
CASE  
 WHEN priority=1   
 THEN 'H'  
 WHEN priority=2  
 THEN 'N'       
 ELSE 'L'  
END as priority from MessageStorage With(NOLOCK) where u_id= @UserId AND senderId=@SenderID  
End  
  



GO

