       set @smpp_id='2'                            
       end              
     else              
        begin              
  set @smpp_id='Select'               
       end              
Set Nocount on              
Declare @Query varchar(8000),@whereClause varchar(2000)                                              
--Declare @username nvarchar(30)                          
                                                
set @whereClause=''                     
                                
  If  @user_id=''                   
 Begin                                              
  Set @whereClause = @whereClause+' 1=1 and '                                              
               
 End                                         
Else                                        
    Begin                                              
  Set @whereClause =@whereClause+'U_ID ='''+@user_id+''' and '                                              
     End                                                          
                 
 If  @sender_id=''                   
 Begin                                              
  Set @whereClause = @whereClause+' 1=1 and '                                              
 End                                         
Else                                        
    Begin                                              
  Set @whereClause =@whereClause+'Sender_ID ='''+@sender_id+''' and '                                              
 End                 
                 
If @dnd_config='Select'                   
 Begin                                              
  Set @whereClause = @whereClause+' 1=1 and '                                              
 End                                         
Else                                        
    Begin                                              
  Set @whereClause =@whereClause+'DNDConfig ='''+@dnd_config+''' and '                                              
               
 End                 
              
If @sms_priority='Select'                   
 Begin                                              
  Set @whereClause = @whereClause+' 1=1 and '                                              
 End                                         
Else                                        
    Begin                                              
  Set @whereClause =@whereClause+'SMSPriority ='''+@sms_priority+''' and '                                              
 End                             
               If @smpp_id='Select'                   
 Begin                                              
