 End                                         
Else                                        
    Begin                                              
       Set @whereClause =@whereClause+'SMPPID ='''+@smpp_id+''''                
     End               
          
        
set @Query= 'select distinct U_ID,Sender_ID,case DNDConfig when 1 then ''Yes'' else ''No'' end as DNDConfig ,case SMSPriority when 1 then ''High'' when 2 then ''Normal'' when 3 then ''Low'' end as SMSPriority,dbo.fn_GetSMPPName(smppid) as SMPPID from User

Configurations with (NOLOCK) where '+@whereClause+' order         
by U_ID asc'               
--PRINT 'CASE2'          
--END          
exec(@Query)          
End        


