CREATE   PROCEDURE [dbo].[usp_SearchCriteriaConditions_UserId_CriteriaType]     
(     
 @CriteriaName varchar(30) = null,    
 @UserId [bigint] = NULL,     
 @CriteriaType varchar(30) = NULL     
)    
AS     
  SET NOCOUNT ON     
  BEGIN TRY     
  begin     
  Declare @ParentId bigint = (Select top 1 ParentId from User_Detail(nolock) where User_ID = @UserId)     
    
