/* ============================================================
   Procedure: [dbo].[usp_searchKeyword]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_searchKeyword] --10000,1,ACCOUNT         
 @m_id bigint,-- from nvarchar(50),            
@user_id int ,-- from nvarchar(50),    
@keyword nvarchar(50)    
as        
Declare @whereClause varchar(500),@Query varchar(2000),@ErrNo Int    
     
Set Nocount off      
Begin Transaction                                                                        
set @whereClause=''      
If @keyword = ''                                                                        
 Begin                                                                        
  Set @whereClause = @whereClause+' 1=1'     
Set @ErrNo = @@error                                                                                                                                       
 End                                                                        
Else                                                                        
 Begin                                                                        
  Set @whereClause =@whereClause+'Keyword Like ''%'+@keyword+'%'''    
Set @ErrNo = @@error                                                                         
                                                                  
 End        
                        
set @Query = 'select * from Shortcode_keyword where M_ID=' +convert(varchar,@m_id,12)+ ' AND User_ID= ' +convert(varchar,@user_id,12)+ '  and ' +@whereClause+''     
                                                                     
                                                                       
exec (@Query)                                                                                  
If @ErrNo = 0                                                                        
 Begin                                                                        
  Commit Transaction                                                                        
  Set Nocount on                                                                        
  Return 0                                                                        
 End                                                          
Else                                                                        
 Begin                                  
  Rollback Transaction                                                                        
  Set Nocount on                                                           
  Return @ErrNo                               
 End  


GO

