begin          
select  @resellerid = Reseller_ID from Reseller_Detail where User_id=@user_id and M_ID=@m_id          
end          
DECLARE @whereClause VARCHAR(500),@sQuery Varchar(5000),@che varchar(5000)             
set @whereClause=''                
                                                                                                       
If (@user_name=null)                                          
Begin                    
 Set @whereClause =@whereClause +  ' 1=1 AND '                                          
 -- Set @ErrNo = @@error                                           
End                                          
Else                                          
Begin                        
Set @whereClause = @whereClause+ 'k.keyword like ''%'+ @Keyword +'%'' AND '               
  --Set @ErrNo = @@error                                          
End               
              
If (@user_name=null)                                          
Begin                    
 Set @whereClause =@whereClause +  ' 1=1'                                           
  --Set @ErrNo = @@error                                           
End                                          
Else                                          
Begin                        
Set @whereClause = @whereClause+ 'u.user_Login like ''%'+ @user_name +'%'''              
  --Set @ErrNo = @@error                                          
End               
              
              
            
              
 if (@FlagSearch='All')              
   Begin              
            
 SET   @sQuery= 'select k.Keyword_Id,k.ShortCode,k.Keyword,u.user_login,k.Message,k.Type,u.m_id,u.user_id               
     from Shortcode_keyword k join User_detail u on k.user_id=u.User_id and k.m_id=u.M_id               
     where u.m_id= '+@resellerid+' and u.status=1  AND ' + @whereClause              
   End              
