     Begin              
             
  SET @sQuery= 'select k.Keyword_Id,k.ShortCode,k.Keyword,u.user_login,k.Message,k.Type,u.m_id,u.user_id               
     from Shortcode_keyword k join User_detail u on k.user_id=u.User_id and k.m_id=u.M_id               
     where u.m_id= '+@resellerid+'and u.status=1 AND k.TYPE='''+@FlagSearch + '''AND ' + @whereClause              
              
   End              
 print @sQuery              
EXEC(@sQuery)


GO

