/* ============================================================
   Procedure: [dbo].[Usp_SearchTemplateByContent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SearchTemplateByContent --335,'hello #name#'  
(  
  @UserID bigint,  
  @ContentToBeSearched nvarchar(max),  
  @SenderID bigint  
)   
as  
Begin  
  
   declare @ParentID bigint = 0 ,@DLT_TemplateID nvarchar(200) = ''   
   select @ParentID = isnull(ParentID,0)  from User_Detail(nolock) where User_ID = @UserID         
     
   select top 1 @DLT_TemplateID = isnull(TSM.DLT_TemplateID,'') 
       from DLT_TemplateSenderMapping(nolock) as TSM
	     join [UserMailTemplate](nolock) as UMT
	     On TSM.DLT_TemplateID = UMT.DLT_TemplateID
		where TSM.SenderID = @SenderID   
       and TSM.CreatedBy = @UserID  and UMT.MailContent = @ContentToBeSearched 
	   
  
  if(RTRIM(ltrim(@DLT_TemplateID)) <> '')  
    Begin  
   SELECT top 1  
       [ID]  
      ,[ParentID]  
      ,[Name]  
      ,[MailSubject]  
      ,[MailContent]  
      ,[CreatedOn]  
      ,[CreatedBy]  
      ,[IsSMS]  
      ,[IsMail]  
      ,[IsLeads]  
      ,[IsEnquiry]  
      ,[IsConversion]  
      ,[IsList]  
      ,[ListID]  
      ,[isGroup]  
      ,[IsPersonalized]  
      ,[MailContentEditable]  
      ,[IsUnicode]  
      ,[isrte]  
      ,[body_disp]  
      ,[DLT_TemplateID]  
      ,[MessageType]  
      ,[ActiveStatus]  
    FROM [UserMailTemplate](nolock)  
  where ParentID = @ParentID  
        and MailContent = @ContentToBeSearched  
     and DLT_TemplateID = @DLT_TemplateID      
 end  
End


GO

