/* ============================================================
   Procedure: [dbo].[usp_select_active_user]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
        
CREATE   PROC [dbo].[usp_select_active_user] --10001,335                    
@m_id BIGINT , -- frm nvarchar 19-08-2010        
@user_id INT  -- frm nvarchar         
AS                      
DECLARE @rid NVARCHAR(50)              
SET NOCOUNT ON                                                                                                                                        
SET @rid = (  
        SELECT TOP 1 reseller_id  
        FROM   reseller_detail with(nolock)  
        WHERE  m_id            = @m_id  
               AND USER_ID     = @user_id  
    )  
                      
SELECT *  
FROM   user_detail as ud with(nolock) 
WHERE  ud.M_ID                        = @rid  
       AND ud.Status                  = '1'  
       AND (ud.Type = '0' OR ud.Type     = '2')  
       and ud.User_ID = ud.ParentID        

ORDER BY  
       User_Login  
           
SET NOCOUNT OFF        
    


GO

