CREATE   PROCEDURE [dbo].[usp_select_balance_Mail] --10000,1
	@M_ID BIGINT,
	@User_ID INT -- frm big int 19-08-2010
AS
BEGIN
	SELECT TOP 1 99999        AS validity,
	       mcd.Balance
	FROM   MailCreditDetails  AS mcd
	WHERE  mcd.M_ID = @M_ID
	       AND mcd.[User_ID] = @User_ID
	ORDER BY
	       mcd.Credit_ID DESC
END



GO

/* ============================================================
   Procedure: [dbo].[usp_select_balance_MailCredit]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_select_balance_MailCredit] --10001,335                     
@M_ID BIGINT,                              
@User_ID BIGINT -- frm big int 19-08-2010                            
AS                            
BEGIN   
      Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @User_ID)
      Declare @MIDP bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID)
	     
if exists(select 1 from user_detail(nolock) where HasVirtualCredits=1 and IsSuperReseller=1 and USER_ID=@ParentID)          
begin          
declare @actualbalance bigint= isnull((select top 1 balance from  SuperResellerMailCreditDetails (nolock)    
where m_id=@MIDP and user_id=@ParentID order by credit_id desc),0)          
SELECT TOP 1 99999  AS validity,cast(balance as nvarchar) + ' ( ' +cast(@actualbalance as nvarchar) + ' ) ' as Balance FROM   MailCreditDetails(nolock) WHERE  m_id = @MIDP  AND USER_ID = @ParentID ORDER BY credit_id       DESC          
end          
else          
begin          
SELECT TOP 1 99999  AS validity,balance FROM   MailCreditDetails(nolock) WHERE  m_id = @MIDP  AND USER_ID = @ParentID ORDER BY credit_id DESC           
end                 
END 


GO

