CREATE   PROC [dbo].[usp_select_banner_ddl]        
@M_ID bigint,        
@User_ID int -- frm big int 19-08-2010
as                    
select banner_id,case when( len(banner) > 15)
 then
 substring(banner,1,15)+'......' 
else
substring(banner,1,15) 
end
as banner 
from M_Banner 
Where M_ID=@M_ID and User_ID=@User_ID order by Banner_ID desc 

