/* ============================================================
   Procedure: [dbo].[usp_select_BroadcastcontactList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--exec usp_select_BroadcastcontactList 10001,335,'',1,50   
CREATE   PROC [dbo].[usp_select_BroadcastcontactList]                    
@M_ID bigint,                       
@UserID int,                    
@name nvarchar(50) ,  
@pageIndex int,              
@PageSize int=2                  
                                                                                             
as                                                                                                          
Declare @ErrNo Int,@Query varchar(2000),@whereClause varchar(500),@operator varchar(10)                                                                                      
Set Nocount off                                                                                                                                                      
set @whereClause=''                                 
If @name = ''                                                                                      
 Begin                                                                                      
  Set @whereClause = @whereClause+' 1=1  '                                                                                      
  Set @ErrNo = @@error                                                                                      
 End                                                                                      
Else                                                                                      
 Begin                                                                                      
  set @whereClause=' (cd.Contact_Name Like ''%'+@name+'%'' or cd.Contact_Mobile Like ''%'+@name+'%'')';                                                                                       
  Set @ErrNo = @@error                                                                                      
 End                                  
   
                    
  set @Query='select distinct cd.m_id,cd.user_id, Contact_ID,(case when cd.Contact_Name=''0'' then '''' else cd.Contact_Name end) as Contact_Name,  
   Contact_Mobile , case when ud.ProfilePictureName is null then ''~/userImage/defaultprofilepic.jpg'' else ud.ProfilePictureName  end as ContactImage  
   from contact_detail cd   
   inner join user_detail ud on ud.User_ID=cd.User_ID  
   where  cd.User_ID='''+convert(varchar,@UserID,10) +''' and  cd.M_ID='''+convert(varchar,@M_ID,10) +''' and  '+@whereClause+''             
          
declare @TempTable1 table                    
(                    
Id int  identity(1,1),                    
m_id bigint,                    
user_id  int,   
Contact_ID  varchar(50),                    
Contact_Name varchar(150),                    
Contact_Mobile varchar(50),                    
ContactImage varchar(50)  
)                    
insert into @TempTable1(m_id,user_id,Contact_ID,Contact_Name,Contact_Mobile,ContactImage) exec(@Query)                   
--select count(Id)from @TempTable1                  
declare @TempTable table                    
(                    
Id int  identity(1,1),                    
m_id bigint,                    
user_id  int,     
Contact_ID  varchar(50),                         
Contact_Name varchar(150),                    
Contact_Mobile varchar(50),                    
ContactImage varchar(50)                  
)                   
insert into @TempTable(m_id,user_id,Contact_ID,Contact_Name,Contact_Mobile,ContactImage) exec(@Query)                    
select * from (SELECT  *, ROW_NUMBER()   OVER(ORDER BY Id ASC) AS rownum from @TempTable) as TempTable                  
where rownum between (@pageIndex-1)*@PageSize+1 AND @pageIndex*@PageSize                                                                                              
--end 



GO

