/* ============================================================
   Procedure: [dbo].[usp_select_contactList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


                  
--exec usp_select_contactList 10001,335,'jy',''                  
                  
CREATE   PROC [dbo].[usp_select_contactList]                   
(                  
@M_ID bigint,                     
@UserID int,                  
@name nvarchar(50) ,  
@orderby varchar(50)                 
)                  
as                  
begin                  
Declare @ErrNo Int,@Query varchar(2000),@whereClause varchar(500)                  
Set Nocount off                     
 if @name<>''                  
    begin                  
    set @whereClause=' and (cd.Contact_Name Like ''%'+@name+'%'' or cd.Contact_Mobile Like ''%'+@name+'%'')';                    
    --set @whereClause=' and cd.Contact_Name Like ''%'+@name+'%''';                    
    end                                                                                                                                                                        
   set @Query='select Top 50 Contact_ID,(case when cd.Contact_Name=''0'' then '''' else cd.Contact_Name end) as Contact_Name,Contact_Mobile,
   case when ud.ProfilePictureName is null then ''~/userImage/defaultprofilepic.jpg'' else ud.ProfilePictureName  end as ProfilePictureName
   from contact_detail cd 
   inner join user_detail ud on ud.User_ID=cd.User_ID
   where cd.User_ID='''+convert(varchar,@UserID,10) +''' and cd.M_ID='''+convert(varchar,@M_ID,10)+''''              
                
   if @whereClause<>''                  
    begin                  
   set @Query=@Query+@whereClause;                  
    end    
    if @orderby<>''    
  begin  
      set @Query=@Query+@orderby  
  end  
    else  
  begin              
     set @Query=@Query+' order by cd.Contact_Name,Contact_Mobile'                  
  end  
  exec(@Query)                  
                    
End 



GO

