   Procedure: [dbo].[usp_Select_Country]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_Select_Country    
@CountryName varchar(100)    
as            
begin         
  
if exists( select * from M_Country where Country_Name=@CountryName and Symbol is not null )  
begin  
 select [Code ISO 4217] + ' ( '+Symbol+' )' as CurrencyCode,Country_ID   
 from M_Country where Country_Name=@CountryName  
end  
else  
begin  
 select [Code ISO 4217] + ' ( '+Symbol+' )' as CurrencyCode,Country_ID  
 from M_Country  
 where [Code ISO 4217]='USD'  
end  
end    
    


