SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_select_credit_balance]  --10043,27828      
@m_id bigint, -- from nvarchar(50),        
@user_id int -- from nvarchar(50)        
as     
    
	Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @user_id )    
    Declare @MIDP bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID )     
   
if exists(select 1 from user_detail with(nolock) where HasVirtualCredits=1 and IsSuperReseller=1 and USER_ID=@ParentID)  
begin  
declare @actualbalance bigint= isnull((select top 1 balance from  superresellercredit_details with(nolock) where m_id=@MIDP and user_id=@ParentID order by credit_id desc),0)  
select top 1 ID,Credit_ID,M_ID,FromUser_ID,User_ID,Debits,Credits,cast(balance as nvarchar) + ' ( ' +cast(@actualbalance as nvarchar) + ' ) ' as Balance,Validity,Default_Credit,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,MachineName,LastModified,typecredit from  credit_details with(nolock) where m_id=@MIDP and user_id=@ParentID order by credit_id desc    
end  
else  
begin  
select top 1 * from  credit_details with(nolock)  where m_id=@MIDP and user_id=@ParentID order by credit_id desc    
end    
  


