   Procedure: [dbo].[usp_select_defaultRateList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[usp_select_defaultRateList]    
as               
  
select c.Country_ID,   
CASE WHEN (c.CountryCode) <>'' then '(' +c.CountryCode+') '+c.Country_Name   else c.Country_Name end as CountryName,  
ISNULL(c.Symbol,'') + ' ' + CONVERT(nvarchar(22), r.Rate)  as rate
from M_Country c inner join RateListDefault r  
on c.Country_ID=r.CountryId  
order by CountryName  
  



GO

