CREATE   PROC dbo.usp_select_group1 @M_ID BIGINT
	,@User_ID INT
	,-- frm big int 19-08-2010  
	@Group_name VARCHAR(100)
AS
IF (@Group_name = 'Select Group')
BEGIN
	SELECT *
	FROM group_detail
	WHERE m_id = @M_ID
		AND user_id = @User_ID
	ORDER BY Group_ID
END
ELSE
BEGIN
	SELECT *
	FROM group_detail
	WHERE m_id = @M_ID
		AND user_id = @User_ID
		AND Group_Name = @Group_name
	ORDER BY Group_ID

