/* ============================================================
   Procedure: [dbo].[usp_select_message_details_user_of_reseller]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROC [dbo].[usp_select_message_details_user_of_reseller]
@m_id bigint,    
@user_id int,  
@aUser_id nvarchar(50),      
@fdate nvarchar(50),              
@tdate nvarchar(50)                                                                                
as                                                                                            
Declare @ErrNo Int,@Query varchar(2000),@whereClause varchar(500),@operator varchar(10)                                                                        
Set Nocount off                                                                        
Begin Transaction                                                                        
set @whereClause=''       
      
declare @mid nvarchar(50),@rid nvarchar(50)      
set @rid=(select reseller_id from reseller_detail where m_id=@m_id and user_id=@user_id)  

 If @aUser_id = 'Select'                                                                        
 Begin                                                                        
  Set @whereClause = @whereClause+' 1=1 and '                                                                        
  Set @ErrNo = @@error                                                                        
 End                                                                        
Else                                                                        
 Begin                    
  Set @whereClause = @whereClause+ ' user_id ='''+@aUser_id+''' and '                                                                 
  Set @ErrNo = @@error                                                                        
 End  
     
If (@fdate !='' and @tdate !='')      
 Begin       
  Set @whereClause = @whereClause+ '(convert(nvarchar,convert(datetime,datecreated,104),112) between convert(nvarchar,convert(datetime,'''+@fdate+''',104),112) and convert(nvarchar,convert(datetime ,'''+@tdate +''',104),112))'      
  Set @ErrNo = @@error       
 End      
Else      
 Begin      
  Set @whereClause =@whereClause +  ' 1=1'      
  Set @ErrNo = @@error      
 End      
      
set @Query='select * from message_detail      
where m_id='''+@rid +'''  and  '+@whereClause+''       
print @Query      
exec (@Query)      
      
If @ErrNo = 0      
 Begin      
  Commit Transaction      
  Set Nocount on      
  Return 0      
 End      
Else      
 Begin      
  Rollback Transaction      
  Set Nocount on       
  Return @ErrNo      
 End





GO

/* ============================================================
   Procedure: [dbo].[USP_SELECT_MONITORMESSAGE]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_SELECT_MONITORMESSAGE]           
AS                      
SET NOCOUNT ON                                      
BEGIN                      
SELECT MESSAGEID,CAST(U_ID AS NVARCHAR)+' '+USER_LOGIN U_ID, MESSAGE, SENDERID,
case when isnull(B.ScheduledDate,'')<>'' then try_cast(scheduleddate as datetime)
else MESSAGEINSERTDATE end MESSAGEINSERTDATE,mm.BATCHID FROM MESSAGEMONITOR MM(NOLOCK)  
join BatchInfo B (nolock) on b.batchid=MM.BatchID
LEFT JOIN USER_DETAIL UD(NOLOCK)  
ON MM.U_ID=UD.USER_ID   
left join messagemonitor_tbp t(nolock)  
on t.batchid=mm.BatchID  

where t.batchid is null and  
messageid in(select max(messageid) from MESSAGEMONITOR(NOLOCK) group by batchid) order by convert(nvarchar,convert(datetime,MESSAGEINSERTDATE,104),112)   
END    
    
--delete messagemonitor


GO

/* ============================================================
   Procedure: [dbo].[USP_SELECT_MONITORMESSAGE_MAIL]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
CREATE   PROCEDURE  [dbo].[USP_SELECT_MONITORMESSAGE_MAIL]                  
AS                              
BEGIN            
SET NOCOUNT ON                                              
 --SELECT MailMonitorID, CAST(MM.U_ID AS NVARCHAR)+' '+USER_LOGIN AS U_ID, MESSAGE, SENDERNAME,MessageInsertDate,BATCHID,ReplyTo ,Email_Subject,Message  AS Mail_Content    
 --FROM MAILMONITOR MM(NOLOCK)        
 --LEFT JOIN USER_DETAIL UD(NOLOCK)  ON MM.U_ID=UD.USER_ID         
 --WHERE MailMonitorID in(SELECT MAX(MailMonitorID) FROM MAILMONITOR(NOLOCK) GROUP BY BATCHID)         
 --ORDER BY CONVERT(NVARCHAR,CONVERT(DATETIME,MESSAGEINSERTDATE,104),112)       
 /*  
 SELECT Mail_ID, CAST(UD.USER_ID  AS NVARCHAR)+' '+USER_LOGIN AS U_ID, Mail_BatchID,ReplyTo ,Mail_Subject,    
   ''  AS Mail_TempleteBody, (select count(1) from CloneEmailsFilter(nolock) where Mail_BatchID=EF.Mail_BatchID) TotalMails,   
   Mail_FromEmail AS SENDERNAME,Mail_InsertedDate   
 FROM CloneEmailsFilter EF(NOLOCK)      
  LEFT JOIN USER_DETAIL UD(NOLOCK)  ON EF.Mail_UserID=UD.USER_ID      
  WHERE Mail_ID =(SELECT MAX(Mail_ID) FROM cloneEmailsFilter(NOLOCK) where Mail_BatchID=EF.Mail_BatchID) --AND  ISNULL(EF.IsMonitor,0)=0     
   ORDER BY CONVERT(NVARCHAR,CONVERT(DATETIME,Mail_InsertedDate,104),112)       
   */   
 SELECT Mail_ID, CAST(UD.USER_ID  AS NVARCHAR)+' '+USER_LOGIN AS U_ID, Mail_BatchID,ef.ReplyTo ,Mail_Subject,    
   isnull(Messages,'')  AS Mail_TempleteBody, (select count(1) from EmailsFilter(nolock) where Mail_BatchID=EF.Mail_BatchID) TotalMails,     
   Mail_FromEmail AS SENDERNAME,Mail_InsertedDate  
 FROM EmailsFilter EF(NOLOCK)      
  LEFT JOIN USER_DETAIL UD(NOLOCK)  ON EF.Mail_UserID=UD.USER_ID  
  join BatchEmail_Infos b on b.BatchID=ef.Mail_BatchID    
  WHERE Mail_ID =(SELECT MAX(Mail_ID) FROM EmailsFilter(NOLOCK) where Mail_BatchID=EF.Mail_BatchID) AND isnull(bmonitor,0)=0-- ISNULL(EF.IsMonitor,0)=0     
   ORDER BY CONVERT(NVARCHAR,CONVERT(DATETIME,Mail_InsertedDate,104),112)       
     
END 


GO

