/* ============================================================
   Procedure: [dbo].[USP_SELECT_MONITORVoice]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_SELECT_MONITORVoice]  
(  
@didno varchar(20)  
)                 
AS                            
SET NOCOUNT ON                                            
BEGIN  
if @didno = ''                          
SELECT MonitorID,CAST(mm.user_id AS NVARCHAR)+' '+USER_LOGIN U_ID, am.Appid      
,VoiceInsertDate,BATCHID,[dbo].[Cloud_getvoicefl](MM.Appid,mm.user_id,0) url,    
ltrim(rtrim([dbo].[Cloud_getvoicefl](MM.Appid,mm.user_id,1))) Voice_text,    
(select count(*) from Voice_MONITOR(NOLOCK) ss where ss.batchid = MM.Batchid       
group by batchid) rcount, am.AppName, am.PhoneNo    
 FROM Voice_MONITOR MM(NOLOCK) LEFT JOIN USER_DETAIL UD(NOLOCK)        
ON MM.user_id=UD.USER_ID     
inner join dbo.Cloud_app_master am on am.User_id = mm.user_id and     
am.Appid = mm.Appid    
where MonitorID in(select max(MonitorID) from Voice_MONITOR(NOLOCK)       
group by batchid) order by VoiceInsertDate   
else  
SELECT MonitorID,CAST(mm.user_id AS NVARCHAR)+' '+USER_LOGIN U_ID, am.Appid      
,VoiceInsertDate,BATCHID,[dbo].[Cloud_getvoicefl](MM.Appid,mm.user_id,0) url,    
ltrim(rtrim([dbo].[Cloud_getvoicefl](MM.Appid,mm.user_id,1))) Voice_text,    
(select count(*) from Voice_MONITOR(NOLOCK) ss where ss.batchid = MM.Batchid       
group by batchid) rcount, am.AppName, am.PhoneNo    
 FROM Voice_MONITOR MM(NOLOCK) LEFT JOIN USER_DETAIL UD(NOLOCK)        
ON MM.user_id=UD.USER_ID     
inner join dbo.Cloud_app_master am on am.User_id = mm.user_id and     
am.Appid = mm.Appid    
where MonitorID in(select max(MonitorID) from Voice_MONITOR(NOLOCK)   
 group by batchid) and am.PhoneNo = @didno  
 order by VoiceInsertDate          
END 


GO

