SET QUOTED_IDENTIFIER ON

/****************************************************************************                                  
SP_NAME        : USP_TRUNCATETABLE                                                     
AUTHOR         : AJAY SINGH                                  
CREATED ON     : 05/07/2012 04:30 PM                                                      
LOCATION       :                                    
SP DESCRIPTION : THIS SP IS USED TO dndncmanagemant.aspx                                                
****************************************************************************/ 
CREATE   PROCEDURE usp_select_noofrow_tablename
as 
begin
select tb.name as tablename, max(ta.rowcnt) as noofrecord  from sysindexes ta join sysobjects tb 
on ta.id=tb.id where tb.name like 'azq%'
group by tb.name
end


