/* ============================================================
   Procedure: [dbo].[usp_select_open_dnd]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

                    
/****************************************************************************                                    
SP_Name        : [[usp_select_open_dnd]]                                                       
Author         : Kushagra Bansal                                    
Created ON     : 25/6/2012 01:30 PM                                                        
Location       : OpenDND.cs                                     
SP Description : This SP is Used to search the requier information for page openDND according to date inserted                                  
****************************************************************************/                                       
                          
                    
CREATE   PROC [dbo].[usp_select_open_dnd] --'10/5/2012','23/06/2012','','','1','1'                              
@Fdate nvarchar(10),                                
@Tdate nvarchar(10),                
@SendingIdentification nvarchar(25),                
@ID nvarchar(max),          
@EXELPera  nvarchar(1),      
@DeliveryBasis nvarchar(1),  
@SenderID nvarchar(50)                            
as     --I deleted This '0'+ from their so that to take it without 0 in order to integrate it with other tables                        
-----------------------------------------------------------------------------------                        
                                                                                                          
SELECT convert(nvarchar,messageinsertdate,104) as Date,m1.U_ID,m1.senderid,m1.message,(SELECT '0'+ltrim(rtrim(mobile)) + ',' FROM MessageQueueAirtelThree m2(nolock) WHERE m2.BatchID = m1.BatchID and m2.message = m1.message ORDER BY mobile FOR XML PATH('')
 ) AS mobile,m1.BatchID INTO #temp1 FROM          
MessageQueueAirtelThree m1(nolock) where senderid=@SenderID  
--where convert(nvarchar,convert(datetime,messageinsertdate,104),112) between convert(nvarchar,convert(datetime,@Fdate,104),112) and convert(nvarchar,convert(datetime,@Tdate,104),112)   
GROUP BY message,convert(nvarchar,messageinsertdate,104),m1.U_ID,Senderid,BatchID --order by BatchID DESC                          
                            
  Declare @Output Table( ID int IDENTITY(0,1),                            
  mobile text,                            
  U_ID Bigint,Senderid nvarchar(50),                            
  [message] nvarchar(2500),                            
  [Date] Varchar(10),                    
  BatchID  bigint                    
  )                            
  Declare @Final Table(ID int IDENTITY(0,1),                
  [Date] Varchar(12),                            
  U_ID Bigint,Senderid nvarchar(50),                            
  [message] nvarchar(max),                            
  mobile nvarchar(max),                    
  BatchID  bigint                            
  )                            
              
  --SELECT * FROm #temp1            
  insert into @Output([Date],U_ID,Senderid,[message],mobile,BatchID) select * from #temp1                            
  declare @count int;                            
  declare @total int;                            
  set @total=(select count(*) from @Output );                            
  set @count=(select count(*) from @Output )-1;                            
  while(@total>0)                            
  BEGIN                            
  DECLARE @text varchar(max),@U_ID Bigint,@Sender nvarchar(50),@message nvarchar(max),@date nvarchar(max),@BatchID  bigint                            
  set @text=(select mobile from @Output where id=@count )                            
  set @U_ID=(select U_ID from @Output where id=@count )   
  set @Sender=(select Senderid  from @Output where id=@count )                          
  set @message=(select [message] from @Output where id=@count )                            
  set @date=(select [Date] from @Output where id=@count )                      
  set @BatchID=(select BatchID from @Output where id=@count )                         
  insert into @Final([Date],U_ID,Senderid,[message],mobile,BatchID) select Date,U_ID,Senderid,message,value,BatchID                    
  from [fn_Split_SMS](@text,@U_ID,@Sender,@message,@date,@BatchID)                             
  set  @total=@total-1;                   
  set @count=@count-1;                            
  END                            
                           
                           
              -- SELECT * FROm @Final            
              --Below is a change           
              IF(@EXELPera!=1)          
              BEGIN          
                        
                  
   IF(@SendingIdentification=1)                
   BEGIN                
   select * from @Final WHERE ID IN (SELECT value as ID from fn_Split(@ID,','))              
   --(SELECT value as mobile from fn_Split(@mobile,','))              
   END                       
                          
  ELSE                
  BEGIN                
  select * from @Final order by BatchID DESC, ID  DESC                   
                          
  select ID from @Final order by ID                        
    END                      
              
    END          
    -----------------------------------------------------------------          
              
   --Here is a game begin of exel sheet delivery report           
    ELSE IF(@EXELPera=1)                
   BEGIN           
              
    Declare @EXEL Table(ID int,                
            MessageStatus nvarchar(30)          
  )                 
              
              
              
    declare @countE int;                            
  declare @totalE int;                            
  set @totalE=(select count(*) from @Final );                            
  set @countE=(select count(*) from @Final )-1;                            
  while(@totalE>0)                            
  BEGIN                            
     DECLARE @IDE varchar(max),@mobileE nvarchar(30),@U_IDE Bigint,@messageE nvarchar(max),@Message_Like nvarchar(max),@MessageStatus nvarchar(30)          
                               
                              
                               
                               
  set @IDE=(select ID from @Final where id=@countE )                            
  set @mobileE=(select mobile from @Final where id=@countE )           
   set @U_IDE=(select U_ID from @Final where id=@countE )                            
  set @messageE=(select [message] from @Final where id=@countE )                            
            
            
  SET @Message_Like='%'+(select Substring(@messageE,1,69))+'%'           
            
              
        --I make change here      
        --SET @MessageStatus= (SELECT DISTINCT MessageStatus FROM MessageDeliveryStatus WHERE '0'+mobile IN (SELECT value as mobileE from fn_Split(@mobileE,',')) AND U_ID=@U_IDE AND Message LIKE  @Message_Like AND MessageStatus='Deliverd'  )             
 
          SET @MessageStatus= (SELECT DISTINCT MessageStatus FROM MessageDeliveryStatusTemp WHERE '0'+mobile IN (SELECT value as mobileE from fn_Split(@mobileE,',')) AND U_ID=@U_IDE AND Message LIKE  @Message_Like AND MessageStatus='Deliverd'  )          
      
IF (@MessageStatus='Deliverd')              
              
BEGIN              
           
insert into @EXEL(ID,MessageStatus)VALUES(@IDE,'Deliverd')          
          
          
              
END              
              
ELSE              
BEGIN              
insert into @EXEL(ID,MessageStatus)VALUES(@IDE,'Not Deliverd')              
END              
              
          
          
          
set  @totalE=@totalE-1;                            
set @countE=@countE-1;          
          
              
              
              
END          
           
 --SELECT * from @EXEL          
 SELECT F.ID,E.MessageStatus,F.Date,F.U_ID,F.message,F.mobile,F.BatchID INTO #FinalExel from @Final F JOIN @EXEL E ON F.ID=E.ID ORDER BY BatchID DESC, ID  DESC          
       
 --SELECT * FROM #FinalExel      
       
 IF(@DeliveryBasis=1)      
 BEGIN      
 SELECT * FROM #FinalExel WHERE MessageStatus='Deliverd'      
 select ID from #FinalExel  WHERE MessageStatus='Deliverd' order by ID     
     
 END      
       
 ELSE IF(@DeliveryBasis=2)      
 BEGIN      
 SELECT * FROM #FinalExel  WHERE MessageStatus='Not Deliverd'     
 select ID from #FinalExel WHERE MessageStatus='Not Deliverd' order by ID     
 END      
       
 ELSE      
 BEGIN      
 SELECT * FROM #FinalExel     
 select ID from #FinalExel order by ID     
 END      
       
           
  END            
          


GO

/* ============================================================
   Procedure: [dbo].[usp_select_open_dnd_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_select_open_dnd_new] --'10/06/2012','23/06/2012'  
@Fdate nvarchar(10),    
@Tdate nvarchar(10)    
as 
SELECT m1.batchid,convert(nvarchar,messageinsertdate,104) as Date,m1.U_ID,m1.message,(SELECT '0'+ltrim(rtrim(mobile)) + ',' FROM MySMS.[dbo].[MessageQueueAirtelThree] m2 WHERE m2.message = m1.message ORDER BY mobile FOR XML PATH('') ) AS mobile INTO #temp1 FROM 
MySMS.[dbo].[MessageQueueAirtelThree] m1 where convert(nvarchar,convert(datetime,messageinsertdate,104),112) between convert(nvarchar,convert(datetime,@Fdate,104),112) and      
convert(nvarchar,convert(datetime,@Tdate,104),112) GROUP BY message,  
convert(nvarchar,messageinsertdate,104),m1.U_ID,batchid order by convert(nvarchar,messageinsertdate,104)

		Declare @Output Table(ID int IDENTITY(0,1),
		[Date] Varchar(10),
		U_ID Bigint,
		[message] text,
		mobile text,
		batchid Bigint
		)
		Declare @Final Table([Date] Varchar(12),
		U_ID Bigint,
		[message] nvarchar(max),
		mobile nvarchar(max),
		batchid Bigint
		)
		insert into @Output([Date],U_ID,[message],mobile,batchid) select * from #temp1
		declare @count int;
		declare @total int;
		set @total=(select count(*) from @Output );
		set @count=(select count(*) from @Output )-1;
		while(@total>0)
		BEGIN
		DECLARE @text varchar(max),@U_ID Bigint,@message nvarchar(max),@date nvarchar(max),@batchid Bigint
		set @text=(select mobile from @Output where id=@count )
		set @U_ID=(select U_ID from @Output where id=@count )
		set @message=(select [message] from @Output where id=@count )
		set @date=(select [Date] from @Output where id=@count )
		set @batchid=(select batchid from @Output where id=@count )
		insert into @Final([Date],U_ID,[message],mobile,batchid) 
		select Date,U_ID,message,value,batchid from [fn_Split_SMS_new](@text,@U_ID,@message,@date,@batchid)
		set  @total=@total-1;
		set @count=@count-1;
		END
		select * from @Final order by batchid desc


GO

/* ============================================================
   Procedure: [dbo].[usp_select_ratelist]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


            
              
CREATE   PROC [dbo].[usp_select_ratelist]             
@user_id int             
as                            
        
 select * from        
 (        
 select @user_id as userid,c.Country_ID as Country_ID,               
 CASE WHEN (c.CountryCode) <>'' then '(+' + LTRIM(RTRIM(c.CountryCode))+') '+c.Country_Name   else c.Country_Name end as   CountryName,LTRIM(RTRIM(c.CountryCode)) as CountryCode,   
  
  ISNULL(c.Symbol,'') as  curSymbol, r.Rate as Rate, c.Currency ,c.[Code ISO 4217] CurrencyCode              
 from M_Country c inner join RateListDefault r on c.Country_ID=r.CountryId  where c.Country_ID not in ( select CountryId from RatelistModify where UserId=@user_id)            
            
 union all            
         
 select @user_id as userid, c.Country_ID,               
 CASE WHEN (c.CountryCode) <>'' then '(+' + LTRIM(RTRIM(c.CountryCode))+') '+c.Country_Name   else c.Country_Name end as   CountryName,LTRIM(RTRIM(c.CountryCode)) as CountryCode,   
   
 ISNULL(c.Symbol,'') as  curSymbol,              
 r.Rate as Rate, c.Currency ,c.[Code ISO 4217] CurrencyCode        
 from M_Country c inner join RatelistModify r on c.Country_ID=r.CountryId            
 where UserId=@user_id ) result        
         
 order by Country_ID        
         
         



GO

