   Procedure: [dbo].[usp_select_report]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
 
CREATE   PROCEDURE [dbo].[usp_select_report] -- '4663','gauransh' 
 
 
@User_Id int, 
@SenderID nvarchar(50) 
as 
--if(@User_Id='335') 
if(@User_Id='364' or @User_Id='16300' or @User_Id='17626' or @User_Id='16301' or @User_Id='17809' or @User_Id='1889' or @User_Id='16343' or @User_Id='17492' ) 
begin 
with cte as( 
SELECT md.Mobile as Mobile, Message, md.SenderID as SenderID, 
isnull(rd.Statuswitherr,(CASE MessageStatus WHEN '3' THEN 'DND' when '6' 
then 'INVALID' when '9' then 'UNDELIV' when '5' then 'BLACKLISTED' ELSE 'Sent' END )) 
AS MessageStatus, MessageInsertDate AS MessageDeliveredDate,isnull(lasterror,substring(rd.Statuswitherr,18,4)) as LastError, 
ROW_NUMBER() over (partition by md.messagedeliverystatusid order by md.messagedeliverystatusid) as dlr 
FROM messagedeliverystatus md with (nolock) left join mysmstrans.dbo.ReceiveDeliveryData rd with (nolock) 
on '91'+md.mobile=rd.mobile --and md.senderid=replace(rd.senderid,'AM-','') 
WHERE (md.SenderID =@SenderID or @SenderID = '#All#' ) AND (U_ID = @User_Id)) 
select substring(Mobile,1,6)+'****' as mobile,'************' as message,SenderID,MessageStatus,MessageDeliveredDate,LastError from cte where dlr=1 
end 
 
--else if(@User_Id='364' or @User_Id='16300' or @User_Id='17626' or @User_Id='16301' or @User_Id='17809' ) 
--begin 
--with cte as( 
--SELECT md.Mobile as Mobile, Message, md.SenderID as SenderID, 
--isnull(rd.Statuswitherr,(CASE MessageStatus WHEN '3' THEN 'DND' when '6' 
--then 'INVALID' when '9' then 'UNDELIV' when '5' then 'BLACKLISTED' ELSE 'Sent' END )) 
--AS MessageStatus, MessageInsertDate AS MessageDeliveredDate,isnull(lasterror,substring(rd.Statuswitherr,18,4)) as LastError, 
--ROW_NUMBER() over (partition by md.messagedeliverystatusid order by md.messagedeliverystatusid) as dlr 
--FROM messagedeliverystatus md with (nolock) left join dbo.ReceiveDeliveryData rd with (nolock) 
--on '91'+md.mobile=rd.mobile --and md.senderid=replace(rd.senderid,'AM-','') 
--WHERE (md.SenderID =@SenderID or @SenderID = '#All#' ) AND (U_ID = @User_Id)) 
--select substring(Mobile,1,6)+'****' as mobile,Message,SenderID,MessageStatus,MessageDeliveredDate,LastError from cte where dlr=1 
--end 
 
else if(@User_Id='17131') 
begin 
with cte as( 
SELECT md.Mobile as Mobile, Message, md.SenderID as SenderID, 
(CASE MessageStatus WHEN 'Sent.' THEN 'DELIVRD err:0' ELSE MessageStatus END) 
AS MessageStatus, MessageInsertDate AS MessageDeliveredDate, 
ROW_NUMBER() over (partition by md.messagedeliverystatusid order by md.messagedeliverystatusid) as dlr 
FROM mysmstrans.dbo.messagedeliverystatustemp md with (nolock)WHERE (md.SenderID =@SenderID or @SenderID = '#All#' ) AND (U_ID = @User_Id)) 
select mobile,Message,SenderID,MessageStatus,MessageDeliveredDate from cte where dlr=1 
end 
else 
begin 
with cte as( 
SELECT md.Mobile as Mobile, Message, md.SenderID as SenderID, 
isnull(rd.Statuswitherr,(CASE MessageStatus WHEN '3' THEN 'DND' when '6' 
then 'INVALID' when '9' then 'UNDELIV' when '5' then 'BLACKLISTED' ELSE 'Sent' END )) 
AS MessageStatus, MessageInsertDate AS MessageDeliveredDate,isnull(lasterror,substring(rd.Statuswitherr,18,4)) as LastError, 
ROW_NUMBER() over (partition by md.messagedeliverystatusid order by md.messagedeliverystatusid) as dlr 
FROM messagedeliverystatus md with (nolock) left join mysmstrans.dbo.ReceiveDeliveryData rd with (nolock) 
on '91'+md.mobile=rd.mobile --and md.senderid=replace(rd.senderid,'AM-','') 
WHERE (md.SenderID =@SenderID or @SenderID = '#All#' ) AND (U_ID = @User_Id)) 
select mobile,Message,SenderID,MessageStatus,MessageDeliveredDate,LastError from cte where dlr=1 
end 



