   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_select_report_thirty_app] --335,'04/20/2016'                     
@User_Id int,          
@Date varchar(20)     
as       
begin      
SELECT MessageID, Mobile, Message, SenderID,isnull((CASE MessageStatus WHEN '3' THEN 'DND' when '6'           
then 'Invalid' when 'NULL' then 'Sent'  when '5' then 'Blacklisted'           
when '7' then 'Sent'  when '9' then 'UNDELIV' when '' then 'Sent' ELSE messagestatus END),'Sent')          
AS MessageStatus,MessageInsertDate AS MessageDeliveredDate,LastError          
FROM  MySMS.dbo.ThirtyDaysHistory(nolock)          
WHERE U_ID = @User_Id  
and CONVERT(nvarchar,convert(datetime,MessageInsertDate,104),112) between CONVERT(nvarchar,convert(datetime,''+ @Date+'',104),112)      
and CONVERT(nvarchar,convert(datetime,''+ @Date+'',104),112)  
union all     
SELECT MessageID, Mobile, Message, SenderID,isnull((CASE MessageStatus WHEN '3' THEN 'DND' when '6'           
then 'Invalid' when 'NULL' then 'Sent'  when '5' then 'Blacklisted'           
when '7' then 'Sent'  when '9' then 'UNDELIV' when '' then 'Sent' ELSE messagestatus END),'Sent')          
AS MessageStatus,MessageInsertDate AS MessageDeliveredDate,LastError          
FROM  MySMS.dbo.Messagedeliverystatus(nolock)           
WHERE U_ID = @User_Id  
and CONVERT(nvarchar,convert(datetime,MessageInsertDate,104),112) between CONVERT(nvarchar,convert(datetime,''+ @Date+'',104),112)      
and CONVERT(nvarchar,convert(datetime,''+ @Date+'',104),112)  
end   
  
        



GO

/* ============================================================
   Procedure: [dbo].[usp_select_report_thirty_WithMobile_Pagination]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_select_report_thirty_WithMobile_Pagination]
(
    @User_Id    bigint,
    @SenderID   NVARCHAR(50),
    @fromDate   VARCHAR(20),
    @todate     VARCHAR(20),
    @Mobile     NVARCHAR(50),
    @PageNumber INT = 1,
    @PageSize   INT = 50
)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @TimeZoneName NVARCHAR(255) =
    ISNULL(
        (SELECT TimeZone
         FROM mysms.dbo.User_Detail WITH (NOLOCK)
         WHERE User_ID = @User_Id),
        'india standard time'
    );

    DROP TABLE if exists #ReportTemp;   
    /* ================= TEMP TABLE ================= */
    CREATE TABLE #ReportTemp
    (
        MessageID BIGINT,
        Mobile NVARCHAR(50),
        Message NVARCHAR(MAX),
        SenderID NVARCHAR(50),
        MessageStatus NVARCHAR(50),
        MessageDeliveredDate DATETIME,
        LastError NVARCHAR(MAX)
    );

    /* ================= SPECIAL USERS ================= */
    IF (@User_Id IN (364,16300,17626,16301,17809,1889,17492,335,23513))
    BEGIN
        INSERT INTO #ReportTemp
        SELECT
            MessageID,
            SUBSTRING(Mobile,1,6) + '****',
            '********************',
            SenderID,
            ISNULL(
                CASE MessageStatus
                    WHEN '3' THEN 'DND'
                    WHEN '6' THEN 'Invalid'
                    WHEN '5' THEN 'Blacklisted'
                    WHEN '7' THEN 'Sent'
                    WHEN 'DND_check_failed' THEN 'Sent'
                    WHEN '9' THEN 'UNDELIV'
                    WHEN '' THEN 'Sent'
                    WHEN 'NULL' THEN 'Sent'
                    ELSE MessageStatus
                END,'Sent'),
            --dbo.fn_ConvertDateTime(MessageInsertDate,@TimeZoneName,0),
            MessageInsertDate,
            LastError
        FROM ThirtyDaysHistory WITH (NOLOCK)
        WHERE
            (SenderID = @SenderID OR @SenderID = '#All#')
            AND U_ID = @User_Id
            AND Mobile LIKE '%' + @Mobile + '%'
            AND dbtype = 0
            AND MessageInsertDate >= @fromDate
            AND MessageInsertDate < DATEADD(DAY,1,@todate)

        UNION ALL

        SELECT
            MessageID,
            SUBSTRING(Mobile,1,6) + '****',
            '********************',
            SenderID,
            ISNULL(
                CASE MessageStatus
                    WHEN '3' THEN 'DND'
                    WHEN '6' THEN 'Invalid'
                    WHEN '5' THEN 'Blacklisted'
                    WHEN '7' THEN 'Sent'
                    WHEN 'DND_check_failed' THEN 'Sent'
                    WHEN '9' THEN 'UNDELIV'
                    WHEN '' THEN 'Sent'
                    WHEN 'NULL' THEN 'Sent'
                    ELSE MessageStatus
                END,'Sent'),
            --dbo.fn_ConvertDateTime(MessageInsertDate,@TimeZoneName,0),
            MessageInsertDate,
            LastError
        FROM Messagedeliverystatus WITH (NOLOCK)
        WHERE
            (SenderID = @SenderID OR @SenderID = '#All#')
            AND U_ID = @User_Id
            AND Mobile LIKE '%' + @Mobile + '%'
            AND dbtype = 0
            AND MessageInsertDate >= @fromDate
            AND MessageInsertDate < DATEADD(DAY,1,@todate);
    END
    ELSE
    BEGIN
        INSERT INTO #ReportTemp
        SELECT
            MessageID,
            Mobile,
            Message,
            SenderID,
            ISNULL(
                CASE MessageStatus
                    WHEN '3' THEN 'DND'
                    WHEN '6' THEN 'Invalid'
                    WHEN '5' THEN 'Blacklisted'
                    WHEN '7' THEN 'Sent'
                    WHEN 'DND_check_failed' THEN 'Sent'
                    WHEN '9' THEN 'UNDELIV'
                    WHEN '' THEN 'Sent'
                    WHEN 'NULL' THEN 'Sent'
                    ELSE MessageStatus
                END,'Sent'),
             --dbo.fn_ConvertDateTime(MessageInsertDate,@TimeZoneName,0),
            MessageInsertDate,
            LastError
        FROM ThirtyDaysHistory WITH (NOLOCK)
        WHERE
            (SenderID = @SenderID OR @SenderID = '#All#')
            AND U_ID = @User_Id
            AND Mobile LIKE '%' + @Mobile + '%'
            AND dbtype = 0
            AND MessageInsertDate >= @fromDate
            AND MessageInsertDate < DATEADD(DAY,1,@todate)

        UNION ALL

        SELECT
            MessageID,
            Mobile,
            Message,
            SenderID,
            ISNULL(
                CASE MessageStatus
                    WHEN '3' THEN 'DND'
                    WHEN '6' THEN 'Invalid'
                    WHEN '5' THEN 'Blacklisted'
                    WHEN '7' THEN 'Sent'
                    WHEN 'DND_check_failed' THEN 'Sent'
                    WHEN '9' THEN 'UNDELIV'
                    WHEN '' THEN 'Sent'
                    WHEN 'NULL' THEN 'Sent'
                    ELSE MessageStatus
                END,'Sent'),
            --dbo.fn_ConvertDateTime(MessageInsertDate,@TimeZoneName,0),
            MessageInsertDate,
            LastError
        FROM Messagedeliverystatus WITH (NOLOCK)
        WHERE
            (SenderID = @SenderID OR @SenderID = '#All#')
            AND U_ID = @User_Id
            AND Mobile LIKE '%' + @Mobile + '%'
            AND dbtype = 0
            AND MessageInsertDate >= @fromDate
            AND MessageInsertDate < DATEADD(DAY,1,@todate);
    END

    /* ================= TOTAL COUNT ================= */
    SELECT COUNT(1) AS TotalCount FROM #ReportTemp;

    /* ================= PAGED DATA ================= */
  
  if(@pagesize < 101 )
  begin
  SELECT *
    FROM #ReportTemp
    ORDER BY MessageDeliveredDate DESC
    OFFSET (@PageNumber - 1) * @PageSize ROWS
    FETCH NEXT @PageSize ROWS ONLY;
  end
  else
  begin
        SELECT *
    FROM #ReportTemp
    ORDER BY MessageDeliveredDate DESC
   -- OFFSET (@PageNumber - 1) * @PageSize ROWS
   -- FETCH NEXT @PageSize ROWS ONLY;   
   end

   DROP TABLE if exists #ReportTemp;

END



GO

/* ============================================================
   Procedure: [dbo].[usp_select_report_thirty_WithMobile_Pagination1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.usp_select_report_thirty_WithMobile_Pagination1
(
    @User_Id     BIGINT,
    @SenderID    NVARCHAR(50),
    @FromDate    DATETIME,
    @ToDate      DATETIME,
    @Mobile      NVARCHAR(50) = NULL,
    @PageNumber  INT = 1,
    @PageSize    INT = 50
)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @Offset INT = (@PageNumber - 1) * @PageSize;

    DECLARE @TimeZoneName NVARCHAR(255);

    SELECT @TimeZoneName = ISNULL(TimeZone, 'india standard time')
    FROM mysms.dbo.User_Detail
    WHERE User_ID = @User_Id;

    ;WITH BaseData AS
    (
        SELECT
            m.MessageID,
            CASE 
                WHEN @User_Id IN (364,16300,17626,16301,17809,1889,17492,335,23513)
                THEN SUBSTRING(m.Mobile,1,6) + '****'
                ELSE m.Mobile
            END AS Mobile,

            CASE 
                WHEN @User_Id IN (364,16300,17626,16301,17809,1889,17492,335,23513)
                THEN '********************'
                ELSE m.Message
            END AS Message,

            m.SenderID,

            CASE m.MessageStatus
                WHEN '3' THEN 'DND'
                WHEN '6' THEN 'Invalid'
                WHEN '5' THEN 'Blacklisted'
                WHEN '7' THEN 'Sent'
                WHEN '9' THEN 'UNDELIV'
                ELSE 'Sent'
            END AS MessageStatus,

            dbo.fn_ConvertDateTime(m.MessageInsertDate, @TimeZoneName, 0) 
                AS MessageDeliveredDate,

            m.LastError,

            COUNT(*) OVER() AS TotalRecords
        FROM dbo.Basedata m
        WHERE
            m.User_ID = @User_Id
            AND (@SenderID = '#All#' OR m.SenderID = @SenderID)
            AND (@Mobile IS NULL OR m.Mobile = @Mobile)
            AND m.MessageInsertDate >= @FromDate
            AND m.MessageInsertDate < DATEADD(DAY,1,@ToDate)
    )

    SELECT *
    FROM BaseData
    ORDER BY MessageDeliveredDate DESC
    OFFSET @Offset ROWS
    FETCH NEXT @PageSize ROWS ONLY;
END



GO

