   Procedure: [dbo].[usp_select_user_detail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
CREATE   PROCEDURE [dbo].[usp_select_user_detail]   --335                      
@user_id bigint-- from nvarchar(50)                          
as              
      
