/* ============================================================
   Procedure: [dbo].[usp_select_user_type_check]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_select_user_type_check] --'47668-Hrithik','Iyda@123'--'32222-user5','16529'--'Abhi01','16847' --'47668-Hrithik',  'Iyda@123'             
	@user_id nvarchar(50),        
	@pwd varchar(50)    --change from nvarchar to varchar on 17-08-2010 gaurav              
as  
BEGIN  
  
	/*  
		select * from user_detail ud(nolock) left join User_Filter uf(nolock) on ud.userfilter = uf.Code   
		where user_login=@user_id and ( pwd = @pwd or 'z4@X!m2Q#9pL7^tR' = @pwd)  
	*/  

	 --declare    
		--@user_id nvarchar(50) = '47668-Hrithik',        
		--@pwd varchar(50) = 'Iyda@123'  

	 /*select ( case when (  --udp.UserType = 3 or udp.UserType =4  
			ud.Type = 3 or ud.Type =4  
		) then 'Partner' else 'User' end) As DefaultmasterPage,   
	  ud.*, uf.* , rd.Partner_Type, rd.IsPartner  
	  from user_detail ud(nolock)  
		left join reseller_detail(nolock) rd on ud.ParentID = rd.User_ID
		left join User_Filter uf(nolock) on ud.userfilter = uf.Code   
		--left join User_Detail udp (nolock) on udp.User_ID = ud.ParentID  
	 where ud.user_login=@user_id and ud.pwd = @pwd   */

	SELECT  
        -- Determine DefaultMasterPage with priority from tbl_pm_UserRoleMapping
        ISNULL(NULLIF(rm.DefaultMasterPage, ''), 
            CASE WHEN udp.Type IN (3, 4) and (ud.User_ID= ud.ParentID or rm.DefaultmasterPage='Partner') THEN 'Partner' ELSE 'User' END
        ) AS DefaultMasterPage,

        ud.*,
        uf.*
    FROM user_detail ud WITH (NOLOCK)
    LEFT JOIN User_Filter uf WITH (NOLOCK) 
        ON ud.userfilter = uf.Code
    LEFT JOIN User_Detail udp WITH (NOLOCK) 
        ON udp.User_ID = ud.ParentID
    LEFT JOIN tbl_pm_UserRoleMapping rm WITH (NOLOCK) 
        ON rm.UserId = ud.User_ID
    WHERE ud.user_login = @user_id 
      AND ud.pwd = @pwd
  
END  


GO

