/* ============================================================
   Procedure: [dbo].[Usp_selectAllAirtelSpamMessageinSMS19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_selectAllAirtelSpamMessageinSMS19]             
@pageindex int =2,                        
@pagesize int=100              
as       
Begin                
declare @temptable table      
(       
   ID int identity(1,1),      
   Msg_id int,      
   mobile char(20),      
   [message] varchar(2500),      
   source varchar(50),      
   User_Id bigint,      
   Priority int,      
   CreatedDate smalldatetime      
       
)      
insert into  @temptable(Msg_id,mobile,[message],source,User_Id,Priority,CreatedDate)      
 SELECT Msg_id,mobile,[message],source,User_Id,Priority,CreatedDate from AirtelSpam WITH(NOLOCK)      
  select count(ID) from @temptable          
  SELECT ID,Msg_id,mobile,[message],source,User_Id,Priority,CreatedDate from @temptable                       
  where ID between ((@pageIndex-1)*@PageSize+1) AND (@pageIndex*@PageSize)        
         
End  
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_selectAllAirtelSpamMessageSearchForSMS19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_selectAllAirtelSpamMessageSearchForSMS19] --'apply','','','','',1,100                    
@Message varchar(2500),                
@UserID int, -- from varchar(20),                
@SenderID varchar(20),                
@Mobile varchar(20),                
@FromDate varchar(20),              
@ToDate varchar(20),            
@pageindex int,                      
@pagesize int=2                
as          
Begin        
Begin Try                  
Set NoCount On                
Declare @Sql varchar(8000)                                                                                      
Declare @whereClause varchar(8000)                                       
set @whereClause=''                   
--added by vinay to search                   
 If @Message=''                                                                                        
    Begin                                        
    Set @whereClause =@Message +  '1=1 and '                                                                                        
    End                                                                                        
    Else                                                                                        
    Begin                                    
    Set @whereClause = @whereClause+ ' message like ''%'+@Message+'%''  and '                                                                                        
    End                              
                                                      
    If @UserID=''                                                                                        
    Begin                                        
    Set @whereClause =@whereClause+'1=1 and '                                                                                        
    End                                                                                        
    Else                                                                                        
    Begin                                          
    Set @whereClause = @whereClause+ ' User_Id = '''+@UserID+'''  and '                                                                                        
    End                                                   
                                   
    If @SenderID = ''                                                                                       
    Begin                                        
    Set @whereClause =@whereClause+'1=1 and '                                                                                        
    End                                                                                        
    Else                                                                                        
    Begin                        
    Set @whereClause = @whereClause+ ' source = '''+@SenderID+''' and '                      
    End                    
                  
    If @Mobile = ''                                                                                       
    Begin                                        
    Set @whereClause =@whereClause+'1=1 and '                                                                                        
    End                                                                                        
    Else                                                                                        
    Begin                        
    Set @whereClause = @whereClause+ ' mobile like ''%'+@Mobile+'%'' and '                      
    End                    
                  
                
    If (@FromDate !='' and @ToDate !='')                                                    
    Begin                                                     
    Set @whereClause = @whereClause+ '(convert(nvarchar,convert(datetime,CreatedDate,104),112) between convert(nvarchar,convert(datetime,'''+@FromDate+''',104),112) and convert(nvarchar,convert(datetime ,'''+@ToDate +''',104),112)) '                      
        
          
                 
   End                                 
     Else                                                    
     Begin                                                    
       Set @whereClause =@whereClause +  ' 1=1 '                        
     End              
              
 set @Sql= 'SELECT Msg_id,mobile,[message],source,User_Id,Priority,CreatedDate from AirtelSpam      
 with (NOLOCK) where '+@whereClause+''              
                     
-- create a temporary table to store Message Stored Data            
declare @temptable table            
(            
   ID int identity(1,1),        
   Msg_id int,        
   mobile char(20),        
   [message] varchar(2500),        
   source varchar(50),        
   User_Id int,        
   Priority int,        
   CreatedDate smalldatetime        
)            
 insert into  @temptable(Msg_id,mobile,[message],source,User_Id,Priority,CreatedDate) exec(@Sql)        
--count no of row in temptable            
  select count(Msg_id) from @temptable            
--for custom pagging            
 SELECT ID,Msg_id,mobile,[message],source,User_Id,Priority,CreatedDate from @temptable                         
  where ID between ((@pageIndex-1)*@PageSize+1) AND (@pageIndex*@PageSize)               
END Try        
Begin Catch        
if @@trancount>0        
Rollback        
End Catch          
END  
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_selectAllQueue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_selectAllQueue] --'messagequeue','Send SMS','1'                      
@tablename varchar(100),                                     
@senderid varchar(30),                      
@status varchar(10)                                   
as                                      
Begin                                    
Declare @Sql varchar(8000)                       
DECLARE @TEMPTABLE TABLE                    
(                    
  TBLNAME VARCHAR(100),                    
  BATCHID BIGINT,                    
  SENDERID VARCHAR(30),                    
  MESSAGE VARCHAR(2500),                    
  MSGCOUNT VARCHAR(20),                    
  DATE VARCHAR(30),                    
  PRIORITY CHAR(5)                    
)                    
    IF @tablename='ALL TABLE'                     
     BEGIN                    
       INSERT INTO @TEMPTABLE(TBLNAME,BATCHID,SENDERID,MESSAGE,MSGCOUNT,DATE,PRIORITY)                    
       select 'Q1',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MESSAGEQUEUE                      
         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority                    
      UNION ALL                     
      select 'Q2',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MessageQueueTwo                      
         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority                    
     UNION ALL                     
      select 'Q3',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MessageQueueThree                      
         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority                    
     UNION ALL                     
      select 'Q4',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MessageQueueFour                      
         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority                    
  UNION ALL                     
      select 'Airtel',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MessageQueueAirtel                      
         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority                    
UNION ALL                     
      select 'AirtelTwo',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MessageQueueAirtelTwo                      
         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority                    
UNION ALL                     
      select 'AirtelThree',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MessageQueueAirtelThree              
         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority           
UNION ALL                     
      select 'AirtelPri',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MessageQueueAirtelPri                      
         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority            
UNION ALL                     
      select 'Voda',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MessageQueueVoda                      
         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority                    
    
    
--UNION ALL      
--            select 'Pel1',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from PelTable1                        
--         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority       
--          
--UNION ALL      
--            select 'Pel2',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from PelTable2                       
--         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority       
--UNION ALL      
--            select 'Pel3',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from PelTable3                       
--         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority       
--UNION ALL      
--            select 'Pel4',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from PelTable4                        
--         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority       
--UNION ALL      
--            select 'Pel5',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from PelTable5                        
--         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority       
--UNION ALL      
--            select 'Pel6',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from PelTable6                        
--         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority       
--UNION ALL      
--            select 'Pel7',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from PelTable7                        
--         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority       
--UNION ALL      
--            select 'Pel8',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from PelTable8                        
--         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority       
--      
 END          
 ELSE IF @tablename='MessageQueueVoda'                     
   BEGIN                    
  INSERT INTO @TEMPTABLE(TBLNAME,BATCHID,SENDERID,MESSAGE,MSGCOUNT,DATE,PRIORITY)                    
  select 'Voda',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MessageQueueVoda                      
  group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority                    
   END                         
  ELSE IF @tablename='MessageQueue'                     
   BEGIN                    
  INSERT INTO @TEMPTABLE(TBLNAME,BATCHID,SENDERID,MESSAGE,MSGCOUNT,DATE,PRIORITY)                    
  select 'Q1',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MESSAGEQUEUE                      
  group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority                    
   END                     
ELSE IF @tablename='MessageQueueTwo'                     
   BEGIN                    
  INSERT INTO @TEMPTABLE(TBLNAME,BATCHID,SENDERID,MESSAGE,MSGCOUNT,DATE,PRIORITY)                    
   select 'Q2',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MessageQueueTwo                      
         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority                    
   END                     
ELSE IF @tablename='MessageQueueThree'                     
   BEGIN                    
  INSERT INTO @TEMPTABLE(TBLNAME,BATCHID,SENDERID,MESSAGE,MSGCOUNT,DATE,PRIORITY)                    
   select 'Q3',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MessageQueueThree                      
         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority                    
   END                     
ELSE IF @tablename='MessageQueueFour'                     
   BEGIN                    
  INSERT INTO @TEMPTABLE(TBLNAME,BATCHID,SENDERID,MESSAGE,MSGCOUNT,DATE,PRIORITY)                    
   select 'Q4',batchid,senderid,message,count(mobile) as count,convert(nvarchar,messageinsertdate,100) as date,priority from MessageQueueFour                      
         group by batchid,senderid,message,convert(nvarchar,messageinsertdate,100),priority                    
   END                     
ELSE IF @tablename='MessageQueueAirtel'                     
