/* ============================================================
   Procedure: [dbo].[Usp_selectAllSpamMessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/****************************************************************************        
        
SP_Name        : [Usp_selectAllSpamMessage]                           
Author         : Mukesh       
Created ON     : 25/12/2009 04:30 PM              
Version        : 1        
Alter BY       :                
Alter Date     :         
Location       :          
SP Description : Proc is used to select records from SMSConfigurations table      
               : Proc is also declaring a temp table       
               : Proc is also inserting records into temp table      
                    
****************************************************************************/      
      
CREATE   PROC [dbo].[Usp_selectAllSpamMessage] -- 1,10                   
@pageindex int,                      
@pagesize int=2                
as          
Begin        
Begin Try                  
Set NoCount On                
Declare @Sql varchar(8000)          
 set @Sql= 'select MessageSpamID,MessageID,          
 BatchID,Mobile,Message,SenderID,SmppID,MessageInsertDate,      
Priority,U_ID from  dbo.MessageSpam with (NOLOCK) '              
           
declare @temptable table            
(            
   Id int  identity(1,1),             
   MessageStorageID int,            
   MessageID bigint,            
   MessageBatchID nvarchar(20),            
   Mobile char(20),            
   [Message] varchar(2500),            
   SenderID  nchar(20),            
   SmppID tinyint,            
   MessageInsertDate datetime,            
   Priority tinyint,            
   U_ID int            
)            
print @sql        
 insert into @temptable(MessageStorageID,MessageID,MessageBatchID,Mobile,[Message],SenderID,            
 SmppID,MessageInsertDate,Priority,U_ID) exec(@Sql)        
--count no of row in temptable            
  select count(MessageStorageID) from @temptable            
--for custom pagging            
  select ID,MessageStorageID as MessageID,MessageID,MessageBatchID as BatchID,Mobile,[Message],SenderID,          
  SmppID,MessageInsertDate,Priority,U_ID,'UI' as operator from @temptable            
 where ID between ((@pageIndex-1)*@PageSize+1) AND (@pageIndex*@PageSize)              
END Try        
Begin Catch        
if @@trancount>0        
Rollback        
End Catch          
END 


GO

