    End                                                                       
                                                       
    If @SenderID = ''                                                                                                           
    Begin                                                            
    Set @whereClause =@whereClause+'1=1 and '                                                                                                            
    End                                                 
    Else                                           
    Begin                                            
    Set @whereClause = @whereClause+ ' rtrim(ltrim(SenderID)) = '''+@SenderID+''' and '                                          
    End                                        
                                      
    If @Mobile = ''                                                                                                           
    Begin                     
    Set @whereClause =@whereClause+'1=1 and '                                                                                                            
    End                                                              
    Else                                                                               
  Begin                                            
 Set @whereClause = @whereClause+ ' Mobile like ''%'+@Mobile+'%'' and '                                          
   End                                      
                                      
                                    
    If (@FromDate !='' and @ToDate !='')                                                                        
    Begin                                                                         
    Set @whereClause = @whereClause+ '(convert(nvarchar,convert(datetime,MessageInsertDate,104),112) between convert(nvarchar,convert(datetime,'''+@FromDate+''',104),112) and convert(nvarchar,convert(datetime ,'''+@ToDate +''',104),112)) and '            
 
    
       
        
                               
   End                                                                        
     Else                                                                        
     Begin                                                                        
       Set @whereClause =@whereClause +  ' 1=1 and '                                      
     End                       
                    
 If (@FromTime !='' and @ToTime !='')                                                                        
    Begin                                                                         
    Set @whereClause = @whereClause+ 'convert(datetime,MessageInsertDate,103) between convert(datetime,'''+@FromTime+''',103) and convert(datetime,'''+@ToTime+''',103) '                                   
                                     
   End                                                                        
     Else                                                                        
     Begin                                                                        
       Set @whereClause =@whereClause +  ' 1=1 '                                      
     End                                       
                                  
 set @Sql= 'select BatchID,MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,Operator,Isallowdnd,IsDND from  dbo.MessageSpam with (NOLOCK) where '+@whereClause+''                                  
    print (@Sql)                                     
-- ALTER a temporary table to store Message Stored Data                                
declare @temptable table                                
(                                
   Id int  identity(1,1),                                 
