IsDND     int                        
)                                
 insert into @temptable(BatchID,MessageID,Mobile,[Message],SenderID,                                
 SmppID,MessageInsertDate,Priority,U_ID,Operator,Isallowdnd,Isdnd) exec(@Sql)                            
