select  MessageID,Mobile,Message,SenderID,SmppID,Priority,U_ID,IsUniCode,IsDND,Operator,Isallowdnd,MessageBatchID,MessageInsertDate       
from @temptable   where Priority=0;        
      
      
                 
END Try                      
Begin Catch                      
if @@trancount>0                      
Rollback                      
End Catch                        
END       



