CREATE   PROC [dbo].[usp_selectCity1] -- 'Goa', '+91'       
@State_name varchar(50),      
@c_code varchar(10)          
AS          
BEGIN        
set nocount on      
declare @state_id bigint      
select @state_id=s.State_ID from m_state1 s inner join m_country1 c on s.Country_ID=c.Country_ID where c.CountryCode=@c_code and s.State_Name=@State_name;      
 SELECT City_ID, City_Name        
 FROM   m_city1        
 WHERE  State_ID = @state_id ;       
END 


GO

