select @state_id=s.State_ID from m_state1 s inner join m_country1 c on s.Country_ID=c.Country_ID where ltrim(rtrim(c.CountryCode))=@c_code and s.State_Name=@State_name;          
 SELECT City_ID, City_Name            
 FROM   m_city1(nolock)            
 WHERE  State_ID = @state_id ;           
END 



