/* ============================================================
   Procedure: [dbo].[Usp_SelectContactForAppbyuserid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_SelectContactForAppbyuserid] --25398                   
@User_ID int                  
 as                     
 begin     
  DECLARE @TEMPTABLE TABLE                                      
 (   
 contact_id BIGINT,                                     
 User_ID BIGINT,                                      
 Contact_Name nvarchar(200),                                      
 Contact_Mobile NVARCHAR(100),   
 contact_email VARCHAR(250),                                    
 Contact_DOB VARCHAR(250),                                    
 Contact_Anniversary varchar(20),                                    
 countryCode varchar(20),    
 ImageUrl varchar(200),                                  
 UserType varchar(50)  
 )               
  insert into @TEMPTABLE    
  select contact_id,cd.User_ID User_ID,ltrim(rtrim(Contact_Name)) as Contact_Name,Contact_Mobile,contact_email,Contact_DOB,       Contact_Anniversary,ltrim(rtrim(cd.countryCode)) countryCode,ProfilePicturePath ImageUrl,'A' as UserType from user_detail ud(
nolock) inner join     Contact_Detail cd(nolock)  
  on CAST(CAST(ud.Mobile AS DECIMAL(20)) AS VARCHAR(20)) = cd.Contact_Mobile where cd.user_id=@User_ID  
  union all  
  select contact_id,User_ID,ltrim(rtrim(Contact_Name)) as Contact_Name,Contact_Mobile,contact_email,Contact_DOB,          Contact_Anniversary,ltrim(rtrim(cd.countryCode)) countryCode,ImageUrl,'N' as UserType from Contact_Detail cd(nolock)where user_id=@User_ID and     Contact_Mobile not in(select Mobile from user_detail(nolock))  
  
  ;with cte as(Select *,ROW_NUMBER()OVER (PARTITION BY Contact_Mobile Order By Contact_Mobile)AS NUMBER from  @TEMPTABLE)  
  select contact_id,User_ID,Contact_Name,Contact_Mobile,contact_email,Contact_DOB,Contact_Anniversary,ltrim(rtrim(CountryCode)) as countryCode,ImageUrl,UserType from cte where number=1   
   
                 
 --SELECT contact_id,Contact_Name,Contact_Mobile,contact_email, Contact_DOB, Contact_Anniversary FROM Contact_Detail WHERE User_ID=@User_ID and group_id is null                 
 end   


GO

/* ============================================================
   Procedure: [dbo].[USP_SELECTDNDALLOWNUMBER]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_SELECTDNDALLOWNUMBER]          
@pageindex int,                                        
@pagesize int=2                    
AS                  
Set NoCount On                                  
Declare @Sql varchar(8000)                    
BEGIN                  
 set @Sql='SELECT     TempMessageSource.MessageID, TempMessageSource.Mobile, TempMessageSource.Message, TempMessageSource.SenderID,           
                      TempMessageSource.User_ID, TempMessageSource.SmppID, TempMessageSource.MessageInsertDate, TempMessageSource.Priority,           
                      TempMessageSource.Unicode, TempMessageSource.ScheduledDateTime, TempMessageSource.ScheduledTime, TempMessageSource.IsAirtel,           
                      TempMessageSource.BatchId, TempMessageSource.MobileSubSet, TempMessageSource.IsDND, TempMessageSource.IsAllowedDND,           
                      User_Detail.FName        
FROM         TempMessageSource INNER JOIN          
                      User_Detail ON TempMessageSource.User_ID = User_Detail.User_ID                         
 WHERE                         
TempMessageSource.IsAllowedDND=1 and TempMessageSource.fivehundredflag=1 and TempMessageSource.Priority != 2  and TempMessageSource.ScheduledTime = '''' and TempMessageSource.ScheduledDateTime = '''''                          
              
update TempMessageSource set BATCHID=10              
                  
declare @temptable table                              
(                              
   ID int identity(1,1),                          
   MessageID bigint, -- from int                         
   Mobile varchar(20),                          
   Message varchar(2500),                          
   SenderID varchar(50),                          
   User_ID int,-- from bigint              
   SmppID int,              
 MessageInsertDate datetime,              
 Priority int,              
 Unicode bit,               
ScheduledDateTime varchar(50),              
 ScheduledTime varchar(50),               
IsAirtel bit ,               
 BatchId varchar(50),              
 MobileSubSet int,              
 IsDND bit,              
 IsAllowedDND bit,        
FName varchar(50)                          
                           
)                         
insert into  @temptable(MessageID,Mobile,Message,SenderID,User_ID,SmppID, MessageInsertDate, Priority, Unicode,ScheduledDateTime,              
 ScheduledTime,IsAirtel, BatchId, MobileSubSet, IsDND, IsAllowedDND,FName) exec(@Sql)                          
--count no of row in temptable                              
  select count(MessageID) from @temptable                              
--for custom pagging                              
 SELECT ID, MessageID, Mobile, Message, SenderID, User_ID, SmppID, MessageInsertDate, Priority, Unicode, ScheduledDateTime, ScheduledTime, IsAirtel,               
                      BatchId, MobileSubSet, IsDND, IsAllowedDND,FName from @temptable                                           
  where ID between ((@pageIndex-1)*@PageSize+1) AND (@pageIndex*@PageSize)                  
END    


GO

