/* ============================================================
   Procedure: [dbo].[Usp_SelectError1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_SelectError1] -- '','','1','3'      
@fdate nvarchar(50),                      
@tdate nvarchar(50),      
@pageindex int,          
@pagesize int=2            
as      
Declare @Query varchar(2000),@whereClause varchar(500),@operator varchar(10)                                                                                              
set @whereClause=''                        
                         
If (@fdate !='' and @tdate !='')                          
 Begin                           
  Set @whereClause = @whereClause+ '(convert(nvarchar,convert(datetime,Created_Date,104),112) between convert(nvarchar,convert(datetime,'''+@fdate+''',104),112) and convert(nvarchar,convert(datetime ,'''+@tdate +''',104),112))'                          
        
 End                          
Else                          
 Begin                          
  Set @whereClause =@whereClause +  ' 1=1'                          
       
 End                          
      
set @Query='select ID,Page_Name,Error,UserLogin,Created_Date from sms_errortable where '+@whereClause+'  order by Created_Date desc'        
      
      
declare @TempTable1 table            
(            
R_ID int  identity(1,1),            
ID  varchar(50),            
Page_Name varchar(200),       
Error varchar(600),  
userlogin varchar (250),  
Created_Date varchar(50)  
)            
          
insert into @TempTable1(ID,Page_Name,Error,userlogin,Created_Date) exec(@Query)           
select count(*)from @TempTable1          
          
declare @TempTable table            
(            
R_ID int  identity(1,1),            
ID  varchar(50),            
Page_Name varchar(200),       
Error varchar(600),           
userlogin varchar (250),  
Created_Date varchar(50)         
)         
           
insert into @TempTable(ID,Page_Name,Error,userlogin,Created_Date) exec(@Query)            
select * from (SELECT  *, ROW_NUMBER()   OVER(ORDER BY R_ID ASC) AS rownum from @TempTable) as TempTable          
where rownum between (@pageIndex-1)*@PageSize+1 AND @pageIndex*@PageSize




GO

