/* ============================================================
   Procedure: [dbo].[Usp_SelectMailsParsing]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_SelectMailsParsing] --11  
 @FilterID BIGINT  
AS  
BEGIN  
 SELECT ID,SourceID,MediumID,CampaignID, CASE   
             WHEN Iswithintext  
                  =  
                  1 THEN 'Within Text'  
             WHEN IsRegex  
                  =  
                  1 THEN 'Regular Expressions'  
             ELSE 'Within text using Wildcard'  
        END  AS CaptureAlgorithm,  
        CASE   
             WHEN Iswithintext = 1 THEN 'Starting Text: "' + CAST(StartFrom AS NVARCHAR)   
                  + '" . Ends with: "' + CAST(Endwith AS NVARCHAR) + '" .'  
             WHEN IsRegex = 1 AND isemail = 1 THEN 'Capture Email'  
             WHEN IsRegex = 1 AND isnumbers = 1 THEN   
                  'Capture Numbers with minimum digits ' + CAST(mindigits AS NVARCHAR)  
             WHEN IsRegex = 1 AND isothers = 1 THEN   
                  'Capture text matching regex ' + CAST(regextext AS NVARCHAR)  
             WHEN iswildcard = 1 THEN 'Starting Text: ' + CAST(StartFrom AS NVARCHAR)   
                  + ' . Ends with: ' + CAST(Endwith AS NVARCHAR)  
        END  AS Criteria,  
        CASE   
             WHEN IsFullCapturedData = 1 THEN 'Map full text'  
             ELSE 'Manipulate text before mapping as: Prefix- "' + CAST(Prefix AS NVARCHAR)   
                  + '" , Suffix- "' + CAST(Suffix AS NVARCHAR) + '" ' + CASE   
                                                                             WHEN   
                                                                                  btwleft  
                                                                                  <  
                                                                                  >  
                                                                                  0 THEN   
                                                                                  ' , Left characters '   
                                                                                  +  
                                                                                  CAST(btwleft AS NVARCHAR)  
                                                                             WHEN   
                                                                                  btwright  
                                                                                  <  
                                                                                  >  
                                                                                  0 THEN   
                                                                                  ' , Right Characters '   
                                                                                  +  
                                                                                  CAST(btwright AS NVARCHAR)  
                                                                             WHEN   
                                                                                  btwmid  
                                                                                  <  
                                                                                  >  
                                                                                  0 THEN   
                                                                                  CAST(btwmidlength AS NVARCHAR)   
                                                                                  +  
                                                                                  ' , Chatacters from '   
                                                                                  +  
                                                                                  CAST(btwmid AS NVARCHAR)  
                                                                                  +  
                                                                                  'th character'  
                                                                             ELSE   
                                                                                  ''  
                                                                        END + CASE   
                                                                                   WHEN   
                                                                                        Replacetext   
                                                                                        <  
                                                                                        >  
                                                                                        '' THEN   
                                                                                        ' , Replace text '   
                                                                                        +  
                                                                                        CAST(Replacetext AS NVARCHAR)   
                                                                                        +  
                                                                                        ' with '   
                                                                                        +  
                                                                                        CAST(ReplaceTextWith AS NVARCHAR)  
                                                                                   ELSE   
                                                                                        ''  
                                                                              END  
        END  AS MappedData,  
        MappingColumn  
 FROM   usermailsparsing  
 WHERE  FilterID = @FilterID  
 ORDER BY  
        ID      DESC  
END



GO

