/* ============================================================
   Procedure: [dbo].[USP_SELECTMINIMUMINDEX]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*                      
Creation Date: 24-03-2010                      
Created by vinay:-                       
Objective:- This procedure is used to select minimum index from dnd directory table                      
*/                      
CREATE   PROC [dbo].[USP_SELECTMINIMUMINDEX]                    
@TABLENAME VARCHAR(10),                      
@DATE VARCHAR(30)                      
AS                 
Begin try               
IF @TABLENAME= '1'                      
BEGIN                      
SELECT MIN(DNDID) FROM dbo.DndDirectory                      
END                      
IF @TABLENAME= '2'                      
BEGIN                      
SELECT MIN(BlackID) FROM dbo.BlacklistedNo                    
END                 
IF @TABLENAME= '0'                      
BEGIN                 
  if @DATE=''                
   begin                    
      SELECT min(SixDaysHistory1ID) FROM MySMSReport.dbo.SixDaysHistory1                 
   end                
   else                
   begin                
      SELECT isnull(min(SixDaysHistory1ID),'0') FROM MySMSReport.dbo.SixDaysHistory1 WHERE convert(nvarchar,messageinsertdate,103)=convert(nvarchar,@DATE,103)                 
   end                
END               
IF @TABLENAME= '3'                      
BEGIN                 
  if @DATE=''                
   begin                    
      SELECT min(SixDaysHistory2ID) FROM MySMSReport.dbo.SixDaysHistory2                 
   end                
   else                
   begin                
      SELECT isnull(min(SixDaysHistory2ID),'0') FROM MySMSReport.dbo.SixDaysHistory2 WHERE convert(nvarchar,messageinsertdate,103)=convert(nvarchar,@DATE,103)                 
   end                
END               
IF @TABLENAME= '4'                      
BEGIN                 
  if @DATE=''                
   begin                    
      SELECT min(SixDaysHistory3ID) FROM MySMSReport.dbo.SixDaysHistory3                 
   end                
   else                
   begin                
      SELECT isnull(min(SixDaysHistory3ID),'0') FROM MySMSReport.dbo.SixDaysHistory3 WHERE convert(nvarchar,messageinsertdate,103)=convert(nvarchar,@DATE,103)                 
   end                
END               
IF @TABLENAME= '5'                      
BEGIN                 
  if @DATE=''                
   begin                    
      SELECT min(SixDaysHistory4ID) FROM MySMSReport.dbo.SixDaysHistory4                 
   end                
   else                
   begin                
      SELECT isnull(min(SixDaysHistory4ID),'0') FROM MySMSReport.dbo.SixDaysHistory4 WHERE convert(nvarchar,messageinsertdate,103)=convert(nvarchar,@DATE,103)                 
   end                
END               
IF @TABLENAME= '6'                      
BEGIN                 
  if @DATE=''                
   begin                    
      SELECT min(SixDaysHistory5ID) FROM MySMSReport.dbo.SixDaysHistory5                 
   end                
   else                
   begin                
      SELECT isnull(min(SixDaysHistory5ID),'0') FROM MySMSReport.dbo.SixDaysHistory5 WHERE convert(nvarchar,messageinsertdate,103)=convert(nvarchar,@DATE,103)                 
   end                
END               
IF @TABLENAME= '7'                      
BEGIN                 
  if @DATE=''                
   begin                    
      SELECT min(SixDaysHistory6ID) FROM MySMSReport.dbo.SixDaysHistory6                 
   end                
   else                
   begin                
      SELECT isnull(min(SixDaysHistory6ID),'0') FROM MySMSReport.dbo.SixDaysHistory6 WHERE convert(nvarchar,messageinsertdate,103)=convert(nvarchar,@DATE,103)                 
   end                
END               
IF @TABLENAME= '8'                      
BEGIN                 
  if @DATE=''                
   begin        
      SELECT min(SixDaysHistory1ID) as SixDaysID FROM MySMSReport.dbo.SixDaysHistory                 
   end                
   else                
   begin                
      SELECT isnull(min(SixDaysHistory1ID),'0') FROM MySMSReport.dbo.SixDaysHistory WHERE convert(nvarchar,messageinsertdate,103)=convert(nvarchar,@DATE,103)                 
   end                
END               
    END TRY          
BEGIN CATCH          
  EXECUTE usp_InsertErrorInfo;          
End CATCH 


