/* ============================================================
   Procedure: [dbo].[Usp_SelectnInsertRoleCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[Usp_SelectnInsertRoleCRM]    
AS     
BEGIN
	SELECT tt.RoleID,
	       tt.ROLE INTO #TempTable
	FROM   [CRM].CRMDB.[dbo].[M_Role] AS tt
	
	DELETE 
	FROM   M_Role
	WHERE  RoleID NOT IN (SELECT tt.RoleID
	                      FROM   #TempTable tt)
	
	INSERT INTO M_Role
	  (
	    -- ID -- this column value is auto-generated
	    RoleID,
	    RoleName,
	    CreatedOn
	  )
	SELECT tt.RoleID,
	       tt.ROLE,
	       GETDATE()
	FROM   #TempTable        AS tt
	       LEFT JOIN M_Role  AS mr
	            ON  mr.RoleID = tt.RoleID
	WHERE  mr.RoleID IS NULL
	
	DROP TABLE #TempTable
END 



GO

