/* ============================================================
   Procedure: [dbo].[usp_SelectRecentChatContact]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_SelectRecentChatContact] --581,''
(                  
@UserID bigint,        
               
@Searchname varchar(100)                  
)                  
as                  
begin          
	if(@Searchname<>'')                  
	begin 
		select [type],roomuserid,UserId,groupuser_name,name
		from
		(
			select distinct 'G' as [type],  mr.roomID as roomuserid,rp.UserId as userid,  SUBSTRING(rp.ToJid,1,CHARINDEX('+',rp.ToJid)-1) as groupuser_name,'' as name
			from   
			[chat_app].dbo.[tblRoomChatParsing] rp 
			inner join
			[chat_app].dbo.[ofMucRoom] mr  
			on SUBSTRING(rp.ToJid,1,CHARINDEX('@',rp.ToJid)-1)= mr.name
		    where rp.UserId=@UserID

			union all 

			select distinct 'C' as [type],rp.UserId as roomuserid,rp.UserId as userid,ud.user_login as groupuser_name, ud.FName as name
			from   
			[chat_app].dbo.[tblUserChatParsing] rp 
			left outer join user_detail ud 
			on rp.UserId=ud.User_ID 
			where rp.UserId=@UserID
		) result
		order by groupuser_name 
		End
		else
		begin 
			select [type],roomuserid,UserId,groupuser_name,name
			from
			(
				select distinct 'G' as [type],  mr.roomID as roomuserid,rp.UserId as userid,  SUBSTRING(rp.ToJid,1,CHARINDEX('+',rp.ToJid)-1) as groupuser_name,'' as name
				from   
				[chat_app].dbo.[tblRoomChatParsing] rp 
				inner join
				[chat_app].dbo.[ofMucRoom] mr  
				on SUBSTRING(rp.ToJid,1,CHARINDEX('@',rp.ToJid)-1)= mr.name
				where rp.UserId=@UserID

				union all 

				select distinct 'C' as [type],rp.UserId as roomuserid,rp.UserId as userid,ud.user_login as groupuser_name, ud.FName as name
				from   
				[chat_app].dbo.[tblUserChatParsing] rp 
				left outer join user_detail ud 
				on rp.UserId=ud.User_ID 
				where rp.UserId=@UserID
			) result
			order by groupuser_name			
		End					
							
							
End








GO

