/* ============================================================
   Procedure: [dbo].[USP_SELECTRECORDFRROMdMessageMonitor]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
    
/****************************************************************************      
SP_Name        : USP_SELECTRECORDFRROMdMessageMonitor                         
Author         : vinay      
Created ON     : 24/12/2009 04:30 PM            
Version        : 1      
Alter BY       :              
Alter Date    :       
Location       : PELSOFT      
SP Description : This SP is Used to SELECT RECORD FROM Message Monitor TABLE      
             
****************************************************************************/         
CREATE   PROC [dbo].[USP_SELECTRECORDFRROMdMessageMonitor]              
@pageindex INT,                                                
@pagesize INT=2                            
AS                          
SET NOCOUNT ON                                          
DECLARE @Sql VARCHAR(8000)                            
BEGIN                          
 SET @Sql='SELECT MessageID,Mobile,Message,SENDerID,U_ID,MessageInsertDate,Priority FROM MessageMonitor ORDER BY Priority desc'                                  
                      
                   
                          
DECLARE @temptable table                                      
(                                      
   ID INT identity(1,1),                                  
   MessageID BIGINT,                                  
   Mobile char(20),                                  
   Message VARCHAR(2500),                                  
   SENDerID VARCHAR(50),                                  
   U_ID INT,-- frm big int                      
   MessageInsertDate DATETIME,                      
   Priority INT                     
                                 
                                   
)                                 
insert into  @temptable(MessageID,Mobile,Message,SENDerID,U_ID,MessageInsertDate,Priority) EXEC(@Sql)                                  
--COUNT no of row in temptable                                      
  SELECT COUNT(Mobile) FROM @temptable                                      
--for custom pagging                                      
 SELECT  MessageID,Mobile,Message,SENDerID,U_ID,MessageInsertDate,Priority FROM @temptable                                                   
  WHERE ID between ((@pageIndex-1)*@PageSize+1) AND (@pageIndex*@PageSize)                          
END                    
    


GO

