/* ============================================================
   Procedure: [dbo].[Usp_Send_CallDetailReport_SetBased_ExecPerUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_Send_CallDetailReport_SetBased_ExecPerUser]
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @now DATETIME = GETDATE();

    -- Table variables must be declared BEFORE the CTE, otherwise a CTE cannot be followed
    -- by a DECLARE (that causes the "dangling CTE" syntax error).
    DECLARE @InsertedReports TABLE (
        ReportMailID BIGINT,
        ReportSettingID BIGINT,
        ParentID BIGINT,
        DsSetDeliverAt DATETIME
    );

    DECLARE @Claimed TABLE (ReportMailID BIGINT PRIMARY KEY);

    BEGIN TRY
        ---------------------------------------------------------------------   
        -- Identify candidate settings and compute schedule - CTE chain
        ---------------------------------------------------------------------
        ;WITH CandidateSettings AS (
            SELECT
                t.*,
                TRY_CONVERT(time, t.SendAtTime) AS SendAtTime_t,
                CASE WHEN t.LastDeliveredAt IS NULL THEN CAST(@now AS date)
                     ELSE CAST(t.LastDeliveredAt AS date) END AS BaseDate
            FROM dbo.tbl_dsboardMailSetting t WITH (NOLOCK)
            WHERE t.DashboardType = 'CallDetailReport'
              AND t.ParentID IN ( 34594,41475, 45205)
              AND ISNULL(t.IsActive, 0) = 1
              AND t.ID NOT IN (
                  SELECT ReportSettingid
                  FROM dbo.Reportsmailed WITH (NOLOCK)
                  WHERE (isprocessed = 0)
                     OR (isprocessed = 2
                         AND processedat < DATEADD(MI, -20, @now)
                         AND DATEDIFF(HH, createdon, @now) <= 4
                        )
              )
        ),
        SettingsWithSchedule AS (
            SELECT
                c.*,
                CASE WHEN c.SendAtTime_t IS NOT NULL
                     THEN CAST(CONCAT(CONVERT(varchar(10), c.BaseDate, 23),' ',CONVERT(varchar(8), c.SendAtTime_t)) AS datetime)
                     ELSE NULL
                END AS DsSetDeliverAt,
                UPPER(LTRIM(RTRIM(ISNULL(c.SendAtPeriod, '')))) AS SendAtPeriod_norm,
                TRY_CONVERT(int, c.SendAtWhichDay) AS SendAtWhichDay_int,
                LTRIM(RTRIM(ISNULL(c.EmailIDs, ''))) AS AlternateEmailIDs
            FROM CandidateSettings c
        ),
        SettingsDue AS (
            SELECT
                s.*,
                CASE
                  WHEN s.SendAtPeriod_norm = 'DAILY' THEN 1
                  WHEN s.SendAtPeriod_norm = 'WEEKLY' AND DATEPART(dw, s.DsSetDeliverAt) = s.SendAtWhichDay_int THEN 1
                  WHEN s.SendAtPeriod_norm = 'MONTHLY' AND (
                         DATEPART(DD, s.DsSetDeliverAt) = s.SendAtWhichDay_int
                         OR (s.SendAtWhichDay_int = 0 AND CONVERT(date, s.DsSetDeliverAt) = CONVERT(date, DATEADD(month, ((YEAR(@now) - 1900) * 12) + MONTH(@now), -1)))
                         OR ((SELECT DATEPART(dd, CONVERT(date, DATEADD(month, ((YEAR(@now) - 1900) * 12) + MONTH(@now), -1)))) < s.SendAtWhichDay_int)
                      ) THEN 1
                  ELSE 0
                END AS FlagToMove
            FROM SettingsWithSchedule s
            WHERE s.DsSetDeliverAt IS NOT NULL
        ),

        DueNow AS (
            SELECT *
            FROM SettingsDue s
            WHERE s.FlagToMove = 1
              AND DATEDIFF(SECOND, @now, s.DsSetDeliverAt) BETWEEN 1 AND 60
        )
        ---------------------------------------------------------------------
        -- Immediately follow the CTE with the statement that consumes it:
        -- Insert Reportsmailed rows for DueNow and capture inserted IDs into @InsertedReports
        ---------------------------------------------------------------------
        INSERT INTO dbo.Reportsmailed (parentid, reportsettingid, createdon, isprocessed, sentstatus)
        OUTPUT inserted.id, inserted.reportsettingid, inserted.parentid, inserted.createdon
        INTO @InsertedReports (ReportMailID, ReportSettingID, ParentID, DsSetDeliverAt)
        SELECT d.ParentID, d.ID, @now, 0, 0
        FROM DueNow d;
        ---------------------------------------------------------------------

        IF (SELECT COUNT(1) FROM @InsertedReports) = 0
        BEGIN
            -- Nothing to process right now
            RETURN;
        END

        ---------------------------------------------------------------------
        -- Atomically claim these Reportsmailed rows (isprocessed = 2)
        ---------------------------------------------------------------------
        UPDATE r
        SET r.isprocessed = 2
        OUTPUT inserted.id INTO @Claimed(ReportMailID)
        FROM dbo.Reportsmailed r
        INNER JOIN @InsertedReports ir ON ir.ReportMailID = r.id
        WHERE r.isprocessed = 0;

        IF (SELECT COUNT(1) FROM @Claimed) = 0
        BEGIN
            -- No rows could be claimed
            RETURN;
        END

        ---------------------------------------------------------------------
        -- Expand per-setting user collections into per-user rows (no nested loops)
        -- Create #final_result (includes UserID for calling usp_getEnquiryReport)
        ---------------------------------------------------------------------
        SELECT
            fr.EmailIDCollections,
            fr.ParentID,
            fr.FromDate,
            fr.ToDate,
            fr.ReportSettingID,
            fr.ReportMailID,
            fr.UserID,
			fr.FilterText
        INTO #final_result
        FROM (
            SELECT
                ir.ReportMailID,
                ir.ReportSettingID,
                TRY_CONVERT(BIGINT, LTRIM(RTRIM(s.value))) AS UserID,
                COALESCE(ud.ParentID, TRY_CONVERT(BIGINT, LTRIM(RTRIM(s.value)))) AS ParentID,
                CASE
                    WHEN LTRIM(RTRIM(ISNULL(ud.Email, ''))) = '' AND LTRIM(RTRIM(ISNULL(t.EmailIDs, ''))) = '' THEN ''
                    WHEN LTRIM(RTRIM(ISNULL(ud.Email, ''))) = '' THEN LTRIM(RTRIM(ISNULL(t.EmailIDs, '')))
                    WHEN LTRIM(RTRIM(ISNULL(t.EmailIDs, ''))) = '' THEN LTRIM(RTRIM(ISNULL(ud.Email, '')))
                    ELSE LTRIM(RTRIM(ISNULL(ud.Email, ''))) + ',' + LTRIM(RTRIM(ISNULL(t.EmailIDs, '')))
                END AS EmailIDCollections,
                CAST(
                    CASE UPPER(LTRIM(RTRIM(ISNULL(t.SendAtPeriod, ''))))
                        WHEN 'DAILY' THEN CONVERT(date, DATEADD(DAY, -1, ir.DsSetDeliverAt))
                        WHEN 'WEEKLY' THEN CONVERT(date, DATEADD(WEEK, -1, ir.DsSetDeliverAt))
                        WHEN 'MONTHLY' THEN CONVERT(date, DATEADD(MONTH, -1, ir.DsSetDeliverAt))
                        ELSE NULL
                    END AS date
                ) AS FromDate,
                CAST(CONVERT(date, ir.DsSetDeliverAt) AS date) AS ToDate
                ,t.FilterText  
			FROM @InsertedReports ir
            INNER JOIN dbo.tbl_dsboardMailSetting t WITH (NOLOCK) ON t.ID = ir.ReportSettingID
            CROSS APPLY STRING_SPLIT(ISNULL(t.UserCollections, ''), ',') s
            LEFT JOIN dbo.User_Detail ud WITH (NOLOCK) ON ud.User_ID = TRY_CONVERT(BIGINT, LTRIM(RTRIM(s.value)))
            WHERE ir.ReportMailID IN (SELECT ReportMailID FROM @Claimed)
              AND ISNULL(t.UserCollections, '') <> ''
        ) fr;

        ---------------------------------------------------------------------
        -- Aggregate mailid per ReportMailID and update Reportsmailed.mailid
        ---------------------------------------------------------------------
        ;WITH MailAgg AS (
            SELECT
                ReportMailID,
                STRING_AGG(EmailIDCollections, ',') WITHIN GROUP (ORDER BY EmailIDCollections) AS MailIDAggregated
            FROM (
                SELECT DISTINCT ReportMailID, EmailIDCollections
                FROM #final_result
            ) t
            GROUP BY ReportMailID
        )
        UPDATE r
        SET r.mailid = m.MailIDAggregated
        FROM dbo.Reportsmailed r
        INNER JOIN MailAgg m ON m.ReportMailID = r.id
        WHERE r.id IN (SELECT ReportMailID FROM @Claimed);

        ---------------------------------------------------------------------
        -- Controlled cursor to invoke usp_getEnquiryReport per user (capture failures)
        ---------------------------------------------------------------------
        DECLARE @Row_ReportMailID BIGINT,
                @Row_ReportSettingID BIGINT,
                @Row_UserID BIGINT,
                @Row_ParentID BIGINT,
                @Row_FromDate DATE,
                @Row_ToDate DATE,
                @Row_EmailIDCollections NVARCHAR(MAX),
				@FilterText nvarchar(max) = '';
        DECLARE @Failures TABLE (
            ReportMailID BIGINT,
            ReportSettingID BIGINT,
            UserID BIGINT,
            ErrorMessage NVARCHAR(2000),
            ErrorTime DATETIME DEFAULT SYSUTCDATETIME()
        );

        DECLARE cur CURSOR LOCAL FAST_FORWARD FOR
            SELECT ReportMailID, ReportSettingID, UserID, ParentID, FromDate, ToDate, EmailIDCollections
            FROM #final_result
            ORDER BY ReportMailID;

        OPEN cur;
        FETCH NEXT FROM cur INTO @Row_ReportMailID, @Row_ReportSettingID, @Row_UserID, @Row_ParentID, @Row_FromDate, @Row_ToDate, @Row_EmailIDCollections;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            BEGIN TRY
                
	   SELECT @Row_EmailIDCollections as EmailIDCollections, @Row_ParentID as ParentID, @Row_FromDate as FromDate, @Row_ToDate as ToDate, @Row_ReportSettingID as ReportSettingID, @Row_ReportMailID
				   as ReportMailID, @Row_UserID as UserID

		  exec usp_rtp_GetCallLogDetailList @Row_FromDate,@Row_ToDate,@Row_UserID,@FilterText,1,10000 


            END TRY
            BEGIN CATCH
                INSERT INTO @Failures (ReportMailID, ReportSettingID, UserID, ErrorMessage)
                VALUES (@Row_ReportMailID, @Row_ReportSettingID, @Row_UserID, ERROR_MESSAGE());
            END CATCH

            FETCH NEXT FROM cur INTO @Row_ReportMailID, @Row_ReportSettingID, @Row_UserID, @Row_ParentID, @Row_FromDate, @Row_ToDate,             @Row_EmailIDCollections;
        END

        CLOSE cur;
        DEALLOCATE cur;

        ---------------------------------------------------------------------
        -- Mark claimed Reportsmailed rows as processed
        ---------------------------------------------------------------------
        UPDATE r
        SET r.isprocessed = 1,
            r.processedat = @now
        FROM dbo.Reportsmailed r
        WHERE r.id IN (SELECT ReportMailID FROM @Claimed);

        ---------------------------------------------------------------------
        -- Update LastDeliveredAt in settings for processed settings
        ---------------------------------------------------------------------
        UPDATE s
        SET s.LastDeliveredAt = ir.DsSetDeliverAt
        FROM dbo.tbl_dsboardMailSetting s
        INNER JOIN @InsertedReports ir ON s.ID = ir.ReportSettingID
        WHERE ir.ReportMailID IN (SELECT ReportMailID FROM @Claimed);

        ---------------------------------------------------------------------
        -- Return final result and failures
        ---------------------------------------------------------------------
        SELECT EmailIDCollections, ParentID, FromDate, ToDate, ReportSettingID, ReportMailID, UserID
        FROM #final_result where 1=2
        ORDER BY ParentID;

        SELECT * FROM @Failures;

        DROP TABLE IF EXISTS #final_result;
    END TRY
    BEGIN CATCH
        -- Best-effort persistence of claimed rows as processed to avoid immediate reprocessing
        IF OBJECT_ID('tempdb..#final_result') IS NOT NULL
        BEGIN
            UPDATE r
            SET r.isprocessed = 1,
                r.processedat = @now
            FROM dbo.Reportsmailed r
            WHERE r.id IN (SELECT ReportMailID FROM @Claimed);
        END

        DECLARE @ErrMsg NVARCHAR(4000) = ERROR_MESSAGE();
        DECLARE @ErrSeverity INT = ERROR_SEVERITY();
        DECLARE @ErrState INT = ERROR_STATE();

        RAISERROR('Error in Usp_Send_CallDetailReport_SetBased_ExecPerUser: %s', @ErrSeverity, @ErrState, @ErrMsg);
        RETURN;
    END CATCH
END


GO

/* ============================================================
   Procedure: [dbo].[Usp_Send_CallReportDashboard_MailsAsPerSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_Send_CallReportDashboard_MailsAsPerSettings]                      
as                      
Begin                      
     drop table if exists  #tempSettingsData                      
     Select ROW_NUMBER() over(order by id asc) as RowNum,* into #tempSettingsData from tbl_dsboardMailSetting(nolock) where DashboardType = 'CallReportDashboard'  and  isnull(IsActive,0) = 1                         
  declare @DsCount int = 0, @DsRowIndex int = 0                      
  declare @DsSendAtPeriod nvarchar(200) = '',@DsSendAtTime nvarchar(50) = '',@DsUserCollection nvarchar(max) = '',@DsLastDeliveredAt datetime = null,@DsSetDeliverAt datetime = null                  
  declare @SendAtWhichDay nvarchar(50) = ''                       
  declare @SettingID bigint = 0                       
  --declare @DsSections nvarchar(500) = ''                      
  declare @Scope nvarchar(100) = ''                    
  declare @ParentID bigint = 0;                  
 -- Declare @DashboardID bigint = 0;                  
 -- Declare @ReportIDColections nvarchar(max) = '';                
  Declare @EmailIDCollections nvarchar(max) = '';                      
  Declare @AlternateEmailIDs nvarchar(max) = '';                
                    
  select @DsCount = count(1) from #tempSettingsData                       
  --select * from #tempSettingsData                     
                      
  --select @DsCount                    
                       
  while(@DsCount > 0)                       
       Begin                      
      set @DsRowIndex += 1;                    
   select @DsSendAtPeriod = isnull(SendAtPeriod,''),@DsSendAtTime = isnull(SendAtTime,'')                  
   ,@DsUserCollection = isnull(UserCollections,'') ,@DsLastDeliveredAt = LastDeliveredAt,@SettingID = ID                  
    --,@DsSections = ISNULL(Sections,'')       
 ,@SendAtWhichDay = isnull(SendAtWhichDay,'') , @Scope = Scope, @AlternateEmailIDs =  isnull(EmailIDs,'')      
  from #tempSettingsData where RowNum = @DsRowIndex                   
                
    --select @EmailIDCollections =  (select                    
    --stuff                    
    -- (                     
    --  (select ',' + isnull(ud.EMail,'') from                    
    --   (                    
    -- select  value from fn_split(@DsUserCollection,',') ) as tbl                    
    --     join User_Detail(nolock) as ud on tbl.value = ud.User_ID                    
    -- FOR XML PATH('')), 1, 1, ''))                   
                            
    --  if(rtrim(ltrim(isnull(@AlternateEmailIDs,''))) <> '')                  
    -- Begin                
    --  set  @EmailIDCollections = @EmailIDCollections + ',' + rtrim(ltrim(isnull(@AlternateEmailIDs,'')));                  
    -- End                       
                  
              
              
      if(@DsLastDeliveredAt is null)                        
       Begin                        
       set  @DsSetDeliverAt = Convert(datetime, CAST(convert(date,getdate()) as nvarchar) +' '+ @DsSendAtTime)                        
    end                        
          else                        
        begin                        
        set @DsSetDeliverAt = Convert(datetime, CAST(convert(date,@DsLastDeliveredAt ) as nvarchar) +' '+ @DsSendAtTime)                        
     end                
                               
         -- select  @DsSetDeliverAt,@DsSendAtTime                   
             
          
       Declare @FlagToMove bit = 0                  
                   
    if(ltrim(rtrim(@DsSendAtPeriod)) = 'Daily')                    
     Begin                    
       set  @FlagToMove = 1                      
     End                      
     else if(ltrim(rtrim(@DsSendAtPeriod)) = 'weekly')                    
      Begin                
      if(DATEPART(dw,@DsSetDeliverAt) = @SendAtWhichDay)                
     Begin                     
             set  @FlagToMove = 1                
     end                      
      End   
     else if(ltrim(rtrim(@DsSendAtPeriod)) = 'Monthly')                    
     Begin                 
     declare @LastDayOfMonth_int int = ( SELECT DATEPART(dd, Convert(date, DATEADD(month, ((YEAR(GETDATE()) - 1900) * 12) + MONTH(GETDATE()), -1))))                
                     
       if(DATEPART(DD,@DsSetDeliverAt) = @SendAtWhichDay)                
     Begin                     
             set  @FlagToMove = 1                
     end                
       else if(@SendAtWhichDay = 0)                
  Begin                
        declare @DateLastDay date = Convert(date,DATEADD(month, ((YEAR(GETDATE()) - 1900) * 12) + MONTH(GETDATE()), -1))                
      if(convert(date,@DsSetDeliverAt) = @DateLastDay)                
        Begin                
        set  @FlagToMove = 1                
     End                
                       
     End                 
        else if ( @LastDayOfMonth_int < @SendAtWhichDay)                
     Begin                
         set  @FlagToMove = 1                
     End                      
       End       
               
      if((DATEDIFF(SECOND,getdate(),@DsSetDeliverAt) between 1 and 60) and  (@FlagToMove = 1))                  
     Begin                    
    drop table if exists  #tempUsers                  
       select ROW_NUMBER() over(order by CAST(value as bigint) asc ) as RowNum ,CAST(value as bigint) as UserID  into #tempUsers from fn_Split(@DsUserCollection,',')                  
                  
    declare @userCount int = 0,@UserRowNum int = 0                     
    select @userCount = count(1) from #tempUsers                  
    while(@userCount > 0)                  
       Begin                  
      set @UserRowNum += 1                  
         declare @UserID bigint = 0                          
      select @UserID = userID from #tempUsers where RowNum = @UserRowNum               
   select @ParentID = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @UserID               
             
     
	 select @EmailIDCollections = ( select top 1  isnull(Email,'') from User_Detail with(nolock) where  User_ID = @UserID )                       
 
      if(rtrim(ltrim(isnull(@AlternateEmailIDs,''))) <> '')              
     Begin            
      set  @EmailIDCollections = @EmailIDCollections + ',' + rtrim(ltrim(isnull(@AlternateEmailIDs,'')));              
         --set @AltEmailIDFlag = 1
	 End   
			 
			       
  declare @FromDate datetime = null                
     declare @ToDate datetime = null                
                          
     if(@DsSendAtPeriod = 'daily' )                
       Begin                
        set @ToDate = @DsSetDeliverAt                
     set @FromDate = DATEADD(day,-1,@DsSetDeliverAt)                 
    End                 
     else if(@DsSendAtPeriod = 'weekly' )                
       Begin                
        set @ToDate = @DsSetDeliverAt                
     set @FromDate = DATEADD(WEEK,-1,@DsSetDeliverAt)                 
    End                 
     else if(@DsSendAtPeriod = 'monthly' )                
       Begin                
        set @ToDate = @DsSetDeliverAt                
        --set @FromDate = DATEADD(day,-30,@DsSetDeliverAt)      
     set @FromDate = DATEADD(MONTH,-1,@DsSetDeliverAt)              
    End                          
      
   declare @FromDateTemp date = Cast(@FromDate as date);      
   declare @ToDateTemp date = Cast(@ToDate as date);      
      
      if(@Scope = 'self')                
     Begin                
       --select 's'              
      select @EmailIDCollections as EmailIDCollections,@ParentID as ParentID ,@FromDateTemp as FromDate, @ToDateTemp as ToDate  ;                       
       --exec Dashboard_Prototype_New @UserID,@DsSections       
    exec usp_rtp_CallReportDashboardCount  @UserID,@FromDateTemp,@ToDateTemp                
     end                
else                
    Begin                
       --select 'g'                 
        --select @ParentID = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @UserID                    
        select @EmailIDCollections as EmailIDCollections,@ParentID as ParentID  ,@FromDateTemp as FromDate, @ToDateTemp as ToDate                   
        --exec Dashboard_Prototype_New @ParentID,@DsSections                   
        exec usp_rtp_CallReportDashboardCount  @ParentID,@FromDateTemp,@ToDateTemp   
  --exec usp_getleadreport 34594,34594,'20200101','20220707'                
    End                  
                  
  --select  @userCount                         
   set  @userCount = @userCount - 1                          
    end -- end of usercount while loop                     
                        
    if(ltrim(rtrim(@DsSendAtPeriod)) = 'Daily')                      
     Begin                      
       set @DsLastDeliveredAt = dateadd(day,1, @DsSetDeliverAt)                         
     End                        
     else if(ltrim(rtrim(@DsSendAtPeriod)) = 'weekly')                      
      Begin                      
        set @DsLastDeliveredAt = dateadd(WEEK,1, @DsSetDeliverAt)                         
      End                           
     else if(ltrim(rtrim(@DsSendAtPeriod)) = 'Monthly')                     
     Begin                      
       set @DsLastDeliveredAt = dateadd(MONTH,1, @DsSetDeliverAt)                         
     End                          
            
    update tbl_dsboardMailSetting set LastDeliveredAt = @DsLastDeliveredAt where ID = @SettingID                      
        end                      
                      
   set @DsCount += -1;                      
    End -- end of ds while                       
                      
  drop table if exists  #tempUsers                      
  drop table if exists  #tempSettingsData                  
  drop table if exists #tempReports                       
end 


