select CAST(CAST(Mobile AS DECIMAL(20))AS VARCHAR(20)),'Dear '+case when len(user_login)>11 then left(user_login,11) + '...' else User_Login end +',Your bal is '+cast([Balance] as nvarchar(20))+'.Claim free CRM App & 500Rs bal for SMS,5k Mail,2yr WebHosting,LeadTracking from Justdial,Indiamart etc.Call 8882258258','KITAPP',1,GETDATE(),2,17821,0,0,'UI',@BATCHID,0 FROM #TmpBalance LCD(nolock) inner join User_Detail LUD(NOLOCK)      
on lcd.User_ID=lud.User_ID where lud.M_ID=10043 and Status=1    
union all  
select CAST(CAST(Mobile AS DECIMAL(20))AS VARCHAR(20)),'Dear '+case when len(user_login)>11 then left(user_login,11) + '...' else User_Login end +',Your bal is '+cast([Balance] as nvarchar(20))+'.Claim free CRM App & 500Rs bal for SMS,5k Mail,2yr WebHosting,LeadTracking from Justdial,Indiamart etc.Call 8882258258','KITAPP',1,GETDATE(),2,17821,0,0,'UI',@BATCHID,0 FROM #TmpBalance LCD(nolock) inner join User_Detail LUD(NOLOCK)      
