/* ============================================================
   Procedure: [dbo].[Usp_Send_WhatsAppReport_SetBased_ExecPerUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_Send_WhatsAppReport_SetBased_ExecPerUser]
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @now DATETIME = GETDATE();

    -- Table variables must be declared BEFORE the CTE, otherwise a CTE cannot be followed
    -- by a DECLARE (that causes the "dangling CTE" syntax error).
    DECLARE @InsertedReports TABLE (
        ReportMailID BIGINT,
        ReportSettingID BIGINT,
        ParentID BIGINT,
        DsSetDeliverAt DATETIME
    );

    DECLARE @Claimed TABLE (ReportMailID BIGINT PRIMARY KEY);

    BEGIN TRY
        ---------------------------------------------------------------------   
        -- Identify candidate settings and compute schedule - CTE chain
        ---------------------------------------------------------------------
        ;WITH CandidateSettings AS (
            SELECT
                t.*,
                TRY_CONVERT(time, t.SendAtTime) AS SendAtTime_t,
                CASE WHEN t.LastDeliveredAt IS NULL THEN CAST(@now AS date)
                     ELSE CAST(t.LastDeliveredAt AS date) END AS BaseDate
            FROM dbo.tbl_dsboardMailSetting t WITH (NOLOCK)
            WHERE t.DashboardType = 'WhatsAppReport'
              AND t.ParentID IN ( 34594,41475, 45205)
              AND ISNULL(t.IsActive, 0) = 1
              AND t.ID NOT IN (
                  SELECT ReportSettingid
                  FROM dbo.Reportsmailed WITH (NOLOCK)
                  WHERE (isprocessed = 0)
                     OR (isprocessed = 2
                         AND processedat < DATEADD(MI, -20, @now)
                         AND DATEDIFF(HH, createdon, @now) <= 4
                        )
              )
        ),
        SettingsWithSchedule AS (
            SELECT
                c.*,
                CASE WHEN c.SendAtTime_t IS NOT NULL
                     THEN CAST(CONCAT(CONVERT(varchar(10), c.BaseDate, 23),' ',CONVERT(varchar(8), c.SendAtTime_t)) AS datetime)
                     ELSE NULL
                END AS DsSetDeliverAt,
                UPPER(LTRIM(RTRIM(ISNULL(c.SendAtPeriod, '')))) AS SendAtPeriod_norm,
                TRY_CONVERT(int, c.SendAtWhichDay) AS SendAtWhichDay_int,
                LTRIM(RTRIM(ISNULL(c.EmailIDs, ''))) AS AlternateEmailIDs
            FROM CandidateSettings c
        ),
        SettingsDue AS (
            SELECT
                s.*,
                CASE
                  WHEN s.SendAtPeriod_norm = 'DAILY' THEN 1
                  WHEN s.SendAtPeriod_norm = 'WEEKLY' AND DATEPART(dw, s.DsSetDeliverAt) = s.SendAtWhichDay_int THEN 1
                  WHEN s.SendAtPeriod_norm = 'MONTHLY' AND (
                         DATEPART(DD, s.DsSetDeliverAt) = s.SendAtWhichDay_int
                         OR (s.SendAtWhichDay_int = 0 AND CONVERT(date, s.DsSetDeliverAt) = CONVERT(date, DATEADD(month, ((YEAR(@now) - 1900) * 12) + MONTH(@now), -1)))
                         OR ((SELECT DATEPART(dd, CONVERT(date, DATEADD(month, ((YEAR(@now) - 1900) * 12) + MONTH(@now), -1)))) < s.SendAtWhichDay_int)
                      ) THEN 1
                  ELSE 0
                END AS FlagToMove
            FROM SettingsWithSchedule s
            WHERE s.DsSetDeliverAt IS NOT NULL
        ),

        DueNow AS (
            SELECT *
            FROM SettingsDue s
            WHERE s.FlagToMove = 1
              AND DATEDIFF(SECOND, @now, s.DsSetDeliverAt) BETWEEN 1 AND 60
        )
        ---------------------------------------------------------------------
        -- Immediately follow the CTE with the statement that consumes it:
        -- Insert Reportsmailed rows for DueNow and capture inserted IDs into @InsertedReports
        ---------------------------------------------------------------------
        INSERT INTO dbo.Reportsmailed (parentid, reportsettingid, createdon, isprocessed, sentstatus)
        OUTPUT inserted.id, inserted.reportsettingid, inserted.parentid, inserted.createdon
        INTO @InsertedReports (ReportMailID, ReportSettingID, ParentID, DsSetDeliverAt)
        SELECT d.ParentID, d.ID, @now, 0, 0
        FROM DueNow d;
        ---------------------------------------------------------------------

        IF (SELECT COUNT(1) FROM @InsertedReports) = 0
        BEGIN
            -- Nothing to process right now
            RETURN;
        END

        ---------------------------------------------------------------------
        -- Atomically claim these Reportsmailed rows (isprocessed = 2)
        ---------------------------------------------------------------------
        UPDATE r
        SET r.isprocessed = 2
        OUTPUT inserted.id INTO @Claimed(ReportMailID)
        FROM dbo.Reportsmailed r
        INNER JOIN @InsertedReports ir ON ir.ReportMailID = r.id
        WHERE r.isprocessed = 0;

        IF (SELECT COUNT(1) FROM @Claimed) = 0
        BEGIN
            -- No rows could be claimed
            RETURN;
        END

        ---------------------------------------------------------------------
        -- Expand per-setting user collections into per-user rows (no nested loops)
        -- Create #final_result (includes UserID for calling usp_getEnquiryReport)
        ---------------------------------------------------------------------
        SELECT
            fr.EmailIDCollections,
            fr.ParentID,
            fr.FromDate,
            fr.ToDate,
            fr.ReportSettingID,
            fr.ReportMailID,
            fr.UserID
        INTO #final_result
        FROM (
            SELECT
                ir.ReportMailID,
                ir.ReportSettingID,
                TRY_CONVERT(BIGINT, LTRIM(RTRIM(s.value))) AS UserID,
                COALESCE(ud.ParentID, TRY_CONVERT(BIGINT, LTRIM(RTRIM(s.value)))) AS ParentID,
                CASE
                    WHEN LTRIM(RTRIM(ISNULL(ud.Email, ''))) = '' AND LTRIM(RTRIM(ISNULL(t.EmailIDs, ''))) = '' THEN ''
                    WHEN LTRIM(RTRIM(ISNULL(ud.Email, ''))) = '' THEN LTRIM(RTRIM(ISNULL(t.EmailIDs, '')))
                    WHEN LTRIM(RTRIM(ISNULL(t.EmailIDs, ''))) = '' THEN LTRIM(RTRIM(ISNULL(ud.Email, '')))
                    ELSE LTRIM(RTRIM(ISNULL(ud.Email, ''))) + ',' + LTRIM(RTRIM(ISNULL(t.EmailIDs, '')))
                END AS EmailIDCollections,
                CAST(
                    CASE UPPER(LTRIM(RTRIM(ISNULL(t.SendAtPeriod, ''))))
                        WHEN 'DAILY' THEN CONVERT(date, DATEADD(DAY, -1, ir.DsSetDeliverAt))
                        WHEN 'WEEKLY' THEN CONVERT(date, DATEADD(WEEK, -1, ir.DsSetDeliverAt))
                        WHEN 'MONTHLY' THEN CONVERT(date, DATEADD(MONTH, -1, ir.DsSetDeliverAt))
                        ELSE NULL
                    END AS date
                ) AS FromDate,
                CAST(CONVERT(date, ir.DsSetDeliverAt) AS date) AS ToDate
            FROM @InsertedReports ir
            INNER JOIN dbo.tbl_dsboardMailSetting t WITH (NOLOCK) ON t.ID = ir.ReportSettingID
            CROSS APPLY STRING_SPLIT(ISNULL(t.UserCollections, ''), ',') s
            LEFT JOIN dbo.User_Detail ud WITH (NOLOCK) ON ud.User_ID = TRY_CONVERT(BIGINT, LTRIM(RTRIM(s.value)))
            WHERE ir.ReportMailID IN (SELECT ReportMailID FROM @Claimed)
              AND ISNULL(t.UserCollections, '') <> ''
        ) fr;

        ---------------------------------------------------------------------
        -- Aggregate mailid per ReportMailID and update Reportsmailed.mailid
        ---------------------------------------------------------------------
        ;WITH MailAgg AS (
            SELECT
                ReportMailID,
                STRING_AGG(EmailIDCollections, ',') WITHIN GROUP (ORDER BY EmailIDCollections) AS MailIDAggregated
            FROM (
                SELECT DISTINCT ReportMailID, EmailIDCollections
                FROM #final_result
            ) t
            GROUP BY ReportMailID
        )
        UPDATE r
        SET r.mailid = m.MailIDAggregated
        FROM dbo.Reportsmailed r
        INNER JOIN MailAgg m ON m.ReportMailID = r.id
        WHERE r.id IN (SELECT ReportMailID FROM @Claimed);

        ---------------------------------------------------------------------
        -- Controlled cursor to invoke usp_getEnquiryReport per user (capture failures)
        ---------------------------------------------------------------------
        DECLARE @Row_ReportMailID BIGINT,
                @Row_ReportSettingID BIGINT,
                @Row_UserID BIGINT,
                @Row_ParentID BIGINT,
                @Row_FromDate DATE,
                @Row_ToDate DATE,
                @Row_EmailIDCollections NVARCHAR(MAX);

        DECLARE @Failures TABLE (
            ReportMailID BIGINT,
            ReportSettingID BIGINT,
            UserID BIGINT,
            ErrorMessage NVARCHAR(2000),
            ErrorTime DATETIME DEFAULT SYSUTCDATETIME()
        );

        DECLARE cur CURSOR LOCAL FAST_FORWARD FOR
            SELECT ReportMailID, ReportSettingID, UserID, ParentID, FromDate, ToDate, EmailIDCollections
            FROM #final_result
            ORDER BY ReportMailID;

        OPEN cur;
        FETCH NEXT FROM cur INTO @Row_ReportMailID, @Row_ReportSettingID, @Row_UserID, @Row_ParentID, @Row_FromDate, @Row_ToDate, @Row_EmailIDCollections;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            BEGIN TRY
                

            
			     SELECT @Row_EmailIDCollections as EmailIDCollections, @Row_ParentID as ParentID, @Row_FromDate as FromDate, @Row_ToDate as ToDate, @Row_ReportSettingID as ReportSettingID, @Row_ReportMailID
				   as ReportMailID, @Row_UserID as UserID


		declare @SqlQuery nvarchar(max) = ''		
		 SET @sqlquery = '
         EXEC [usp_GetWhatsappSummeryByUserIdAndDuration] 
             2, ' + CAST(@Row_UserID AS NVARCHAR) + ', ''' + CONVERT(NVARCHAR, @Row_FromDate, 120) + ''', ''' + CONVERT(NVARCHAR, @Row_ToDate, 120) + '''';
         
         -- Execute and fetch data using CLR
         EXEC usp_clr_GetRemoteData @sqlquery;


            END TRY
            BEGIN CATCH
                INSERT INTO @Failures (ReportMailID, ReportSettingID, UserID, ErrorMessage)
                VALUES (@Row_ReportMailID, @Row_ReportSettingID, @Row_UserID, ERROR_MESSAGE());
            END CATCH

            FETCH NEXT FROM cur INTO @Row_ReportMailID, @Row_ReportSettingID, @Row_UserID, @Row_ParentID, @Row_FromDate, @Row_ToDate,             @Row_EmailIDCollections;
        END

        CLOSE cur;
        DEALLOCATE cur;

        ---------------------------------------------------------------------
        -- Mark claimed Reportsmailed rows as processed
        ---------------------------------------------------------------------
        UPDATE r
        SET r.isprocessed = 1,
            r.processedat = @now
        FROM dbo.Reportsmailed r
        WHERE r.id IN (SELECT ReportMailID FROM @Claimed);

        ---------------------------------------------------------------------
        -- Update LastDeliveredAt in settings for processed settings
        ---------------------------------------------------------------------
        UPDATE s
        SET s.LastDeliveredAt = ir.DsSetDeliverAt
        FROM dbo.tbl_dsboardMailSetting s
        INNER JOIN @InsertedReports ir ON s.ID = ir.ReportSettingID
        WHERE ir.ReportMailID IN (SELECT ReportMailID FROM @Claimed);

        ---------------------------------------------------------------------
        -- Return final result and failures
        ---------------------------------------------------------------------
        SELECT EmailIDCollections, ParentID, FromDate, ToDate, ReportSettingID, ReportMailID, UserID
        FROM #final_result where 1 = 2
        ORDER BY ParentID;

        SELECT * FROM @Failures;

        DROP TABLE IF EXISTS #final_result;
    END TRY
    BEGIN CATCH
        -- Best-effort persistence of claimed rows as processed to avoid immediate reprocessing
        IF OBJECT_ID('tempdb..#final_result') IS NOT NULL
        BEGIN
            UPDATE r
            SET r.isprocessed = 1,
                r.processedat = @now
            FROM dbo.Reportsmailed r
            WHERE r.id IN (SELECT ReportMailID FROM @Claimed);
        END

        DECLARE @ErrMsg NVARCHAR(4000) = ERROR_MESSAGE();
        DECLARE @ErrSeverity INT = ERROR_SEVERITY();
        DECLARE @ErrState INT = ERROR_STATE();

        RAISERROR('Error in Usp_Send_WhatsAppReport_SetBased_ExecPerUser: %s', @ErrSeverity, @ErrState, @ErrMsg);
        RETURN;
    END CATCH
END


GO

/* ============================================================
   Procedure: [dbo].[usp_sendcallcentrereport]
   ============================================================ */

SET ANSI_NULLS ON
