    CREATE   PROCEDURE [dbo].[usp_sendcallcentrereport] --17626,
	(@users nvarchar(max)=0,@fromdate nvarchar(12)=null,@todate nvarchar(12)=null)
	as
	begin
	select @users=coalesce(@users,'0'),@fromdate=coalesce(@fromdate,convert(varchar,dateadd(d,-1,cast(getdate() as date)),104)),@todate=coalesce(@todate,convert(varchar,cast(getdate() as date),104))
	create table #users(user_id bigint)
	if @users<>'0'
	begin
	insert into #users(user_id)
	select value as user_id from dbo.fn_split(@users,',')
	end
	else
	begin
	insert into #users(user_id)
	select u.user_id from User_Detail(nolock) u join Price_UserSubscriptionDetails p(nolock) on u.user_id=p.UserID and p.IsNewPlan=1 and p.PlanEndDate>=cast(getdate() as date)
	where user_id=parentid and
	exists (select 1 from user_detail(nolock) where user_id<>user_id and parentid=u.parentid and status=1 and isnull(Cloudrole,0)<>0)
	end
	--create table #userreport(User_ID bigint, [User] nvarchar(100), [CallDate] nvarchar(20), TotalCalls int, CONNECTED int, MISSED int, CallPeriod nvarchar(100) , CallType nvarchar(50))
	create table ##userreport(user_login nvarchar(100),user_id bigint,TotalOutBoundCallsToday int,TotalOutBoundCallsThisMonth int,TotalInboundToday int,TotalInboundThisMonth int,[CallPeriodToday(InMins)] int,
[CallPeriodThisMonth(InMins)] int,TotalLeads int,FollowUpsOverDue int,FollowupsDoneToday int,ClosuresToday int,AmountClosedToday numeric(18,2),FollowupsDoneThisMonth int,
 ClosuresThisMonth int,AmountClosedThisMonth numeric(18,2),TaskOverDue int,TasksCompletedToday int, TasksCompletedthismonth int)
 create table #dailyalerts(emailid nvarchar(200),mailbody nvarchar(max))

 declare @user bigint=0,@email nvarchar(200)
	while @user is not null
	begin
select @user=(select min(user_id) from #users where user_id>@user)
insert into ##userreport(user_login,user_id,TotalOutBoundCallsToday,TotalOutBoundCallsThisMonth,TotalInboundToday,TotalInboundThisMonth,[CallPeriodToday(InMins)],[CallPeriodThisMonth(InMins)],
TotalLeads,FollowUpsOverDue,FollowupsDoneToday, ClosuresToday,AmountClosedToday,FollowupsDoneThisMonth,ClosuresThisMonth,AmountClosedThisMonth,TaskOverDue,TasksCompletedToday,TasksCompletedthismonth)
exec usp_dailyagentreport @user,@fromdate

select @email=EMail from user_detail(nolock) where user_id=@user
--declare @query nvarchar(200)
--set @query= ' SET NOCOUNT ON; select * from ##final '  
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX)        
SET @xml =CAST(( SELECT user_login AS 'td','',TotalOutBoundCallsToday AS 'td','',TotalOutBoundCallsThisMonth AS 'td','',TotalInboundToday AS 'td','',TotalInboundThisMonth AS 'td','',[CallPeriodToday(InMins)]
 AS 'td','',[CallPeriodThisMonth(InMins)] AS 'td','',TotalLeads AS 'td','',FollowUpsOverDue AS 'td','',FollowupsDoneToday AS 'td','', ClosuresToday AS 'td','',AmountClosedToday AS 'td','',
FollowupsDoneThisMonth AS 'td','',ClosuresThisMonth AS 'td','',AmountClosedThisMonth AS 'td','',TaskOverDue AS 'td','',TasksCompletedToday AS 'td','',TasksCompletedthismonth
from ##userreport FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))
SET @body ='<html><H1>User Activity and Follow Up summary as on '+cast (getdate() as nvarchar)+     
'</H1><body><table border = 2><tr><th>User_name</th><th>TotalOutBoundCallsToday</th><th>TotalOutBoundCallsThisMonth</th><th>TotalInboundToday</th><th>TotalInboundThisMonth</th><th>CallPeriodToday(InMins)</th><th>CallPeriodThisMonth(InMins)</th><th>
TotalLeads</th><th>FollowUpsOverDue</th><th>FollowupsDoneToday</th><th> ClosuresToday</th><th>AmountClosedToday</th><th>FollowupsDoneThisMonth</th><th>ClosuresThisMonth</th><th>AmountClosedThisMonth</th><th>TaskOverDue</th><th>TasksCompletedToday</th><th>TasksCompletedthismonth</th></tr>'         
SET @body = @body + @xml +'</table></body></html>'        

insert into #dailyalerts(emailid,mailbody)
select @email,@body

/*
EXEC msdb.dbo.sp_send_dbmail        
@profile_name='Job_Alerts',         
@recipients='csshukla@pelsoftlabs.in;karuna@pelsoftlabs.in',        
