	select @mobile=str(mobile),@pname=isnull(fname,'')+isnull(' '+lname,'') from user_detail(nolock) where user_id=@user
	insert into #userreport(User_ID, [User],CallDate,TotalCalls,CONNECTED,MISSED,CallPeriod ,CallType)
	exec usp_Rep_GetCallSummaryAgentwise @user,@fromdate,@todate
	select * from #userreport
