/* ============================================================
   Procedure: [dbo].[usp_sendcampaignerrormail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_sendcampaignerrormail]-- 17626        
@errorid bigint        
as        
begin       
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX) declare @isevent int =(select IsEvent from Campaignerror where id=@errorid)        
declare @lasteventmailexecution datetime,@lasteventsmsexecution datetime,@lastschedulemailexecution datetime,@lastschedulesmsexecution datetime      
select @lasteventmailexecution= campaignexecuteddatetime from usercampaignexecution where isSMS=0 and isevent=1      
select @lasteventsmsexecution= campaignexecuteddatetime from usercampaignexecution where isSMS=1 and isevent=1      
select @lastschedulemailexecution= campaignexecuteddatetime from usercampaignexecution where isSMS=0 and isevent=0      
select @lastschedulesmsexecution= campaignexecuteddatetime from usercampaignexecution where isSMS=1 and isevent=0      
      
select cast(cast(ErrorDate as DATE) as nvarchar) as ErrorDate,AffectedService,IsEvent,ErrorMessage into #temp from Campaignerror where id=@errorid        
declare @service nvarchar(20)= (select affectedservice from campaignerror where ID=@errorid)      
SET @xml =CAST(( SELECT [ErrorDate] AS 'td','',[AffectedService] AS 'td','',[IsEvent] AS 'td','', ErrorMessage from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))        
SET @body ='<html><H1>Error in ' + @service +' at ' +cast (getdate() as nvarchar)+'</H1><body><table border = 2><tr><th>ErrorDate</th><th>AffectedService</th><th>IsEvent</th><th>ErrorMessage</th></tr>'         

if(@service = 'Telephony')
 Begin

 SET @body = @body + @xml +'</table></body></html>'        
     
 End
 else
 Begin

SET @body = @body + @xml +'</table><p>'+ case when @service in ('SMS','Mails') then 'Last Event mail execution at ' + cast(@lasteventmailexecution as nvarchar(20))  + '. '+      
'Last Event sms execution at ' + cast(@lasteventsmsexecution as nvarchar(20))  +  '. '+      
'Last Scheduled mail execution at ' + cast(@lastschedulemailexecution as nvarchar(20))  + '. '+      
'Last Scheduled SMS execution at ' + cast(@lastschedulesmsexecution as nvarchar(20))  + '. ' else ' ' end + '</p></body></html>'        

 end

 declare @subject nvarchar(100) ='Urgent: Error in ' + @service + case when @isevent=1 then ' Event based' else 'Scheduled' end + case when @service in ('SMS','Mails') then ' Campaign at ' else ' Service at ' end +cast (getdate() as nvarchar)      


if not exists (select 1 from emailqueue(nolock) where  subject=@subject and  createdtime>dateadd(hh,-1,getdate()))
 begin
EXEC usp_enqueueemail        
@profile_name='Alerts',         
@recipients='karuna@pelsoftlabs.in;mayank.nigam@pelsoftlabs.in',        
--@blind_copy_recipients='karuna@pelsoftlabs.in',        
@subject=@subject,        
@body = @body,        
@body_format ='HTML'        
end
drop table #temp        
end   
      



