/* ============================================================
   Procedure: [dbo].[usp_sendcontactusmail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_sendcontactusmail] --164--38145     
@rowid bigint      
as      
begin      
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX)      
select coalesce(t.Name,isnull(u.fname,'')+' '+isnull(lname,''),'') Name,coalesce(t.EmailID,u.EMail,'') Email,coalesce(t.MobileNo,str(u.mobile,10),'') Mobile,isnull(t.Concern,'') Concern,
isnull(t.Source,'') Source,isnull(t.Subject,'') Subject,isnull(u.user_login,'') UserLogin  
 into #temp
from tbl_mk_contact_us(nolock) t 
left join user_detail(nolock) u on u.user_id=t.UserId
where rowid=@rowid

--Added following code to insert lead in lead list    
/*
declare @Source  nvarchar(200)          
  ,@LeadDetails nvarchar(max)          
  ,@Name nvarchar(200)          
  ,@Mobile nvarchar(50)          
  ,@EmailID nvarchar(500)          
  ,@Company nvarchar(500)          
  ,@Address nvarchar(max)          
  ,@Remarks nvarchar(max)          
  ,@ParentID bigint     
select @Source = 'SignUp' ,@LeadDetails='SignUp from '+ isnull(nullif(source,''),'Web'),@Name=isnull(FName,'')+' ' +isnull(LName,''),@Mobile=str(Mobile,10,0),@EmailID=email,@Company=isnull(CompnayName,'')           
,@Address='',@Remarks= 'Signup Medium: '+ISNULL(Medium,'') + ' .Campaign: '+ ISNULL(Campaign,'') +' .',@ParentID=335 from user_detail where user_id=@usercreated  
  
  
  set  @LeadDetails = ''     
  if(@Name <> '')    
     Begin    
        if(@LeadDetails = '')    
       Begin    
          set @LeadDetails = 'Name'    
    End    
           else     
       Begin    
         set @LeadDetails = @LeadDetails + '|Name'     
    End    
  End    
    
  if(@Mobile <> '')    
     Begin    
        if(@LeadDetails = '')    
       Begin    
          set @LeadDetails = 'Mobile'    
    End    
           else     
       Begin    
         set @LeadDetails = @LeadDetails + '|Mobile'     
    End    
  End    
    
   if(@EmailID <> '')    
      Begin    
         if(@LeadDetails = '')    
        Begin    
           set @LeadDetails = 'EmailID'    
    End    
           else     
       Begin    
         set @LeadDetails = @LeadDetails + '|EmailID'     
    End    
   End    
    
    
    if(@Company <> '')    
      Begin    
         if(@LeadDetails = '')    
        Begin    
           set @LeadDetails = 'Company'    
    End    
           else     
       Begin    
         set @LeadDetails = @LeadDetails + '|Company'     
    End    
   End    
    
    
   if(@Remarks <> '')    
      Begin    
         if(@LeadDetails = '')    
        Begin    
           set @LeadDetails = 'Remarks'    
    End    
           else     
       Begin    
         set @LeadDetails = @LeadDetails + '|Remarks'     
    End    
   End  
     
  
   if(charindex('Mobile',@LeadDetails) <> 0)    
    Begin    
      exec usp_insertintoleadlist @Source,@LeadDetails,@Name,@Mobile,@EmailID,@Company,@Address,@Remarks,@ParentID           
     end  
*/  
--Code end for lead list      
    
SET @xml =CAST(( SELECT [UserLogin] AS 'td','',[Name] AS 'td','',       
[EMail]  AS 'td','',Mobile as 'td','',Concern as 'td','',Subject as 'td','',Source from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))      
SET @body ='<html><H1>New contact us form filled for Kit19 at ' +cast (getdate() as nvarchar)
+'</H1><body><table border = 2><tr><th>User Login</th><th>Name</th><th>Email</th><th>Mobile</th><th>Concern</th><th>Subject</th><th>Source</th></tr>'       
SET @body = @body + @xml +'</table></body></html>'      
EXEC usp_enqueueemail      
@profile_name='AlertsNew',       
@recipients='csshukla@pelsoftlabs.in',      
@blind_copy_recipients='karuna@pelsoftlabs.in',      
@subject='New contact us form filled',      
@body = @body,      
@body_format ='HTML'      
drop table #temp      
end 



GO

/* ============================================================
   Procedure: [dbo].[usp_SendDailyEmailsFromQueue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- ===========================================================================
-- PART 3: Update usp_SendDailyEmailsFromQueue
-- Adds: {{ProgressStatement}}, {{PendingModulesSection}} substitution
--       + Management Report email at the end
-- ===========================================================================

CREATE   PROCEDURE [dbo].[usp_SendDailyEmailsFromQueue]
    @DryRun BIT = 0
AS
BEGIN
    SET NOCOUNT ON;

    ---------------------------------------------------------------------------
    -- 1. Collect pending communications (with extra fields for new merge tags)
    ---------------------------------------------------------------------------
    ;WITH LatestExtension AS (
        SELECT
            WorkflowId,
            MAX(GrantedOn)   AS LatestGrantedOn,
            MAX(NewEndDate)  AS ExtendedEndDate
        FROM WorkflowExtensions
        GROUP BY WorkflowId
    ),
    CompletedModules AS (
        SELECT wsp.WorkflowId,
            ISNULL(
                STRING_AGG(N'&#10003; ' + sm.ModuleName, N'<br/>')
                    WITHIN GROUP (ORDER BY sm.ModuleName),
                N'(No modules completed yet)'
            ) AS ModulesText,
            COUNT(*)          AS CompletedCount
        FROM WorkflowSetupProgress wsp
        JOIN SetupModules sm ON wsp.ModuleId = sm.Id
        WHERE wsp.Status = N'Completed'
        GROUP BY wsp.WorkflowId
    ),
    TotalModules AS (
        SELECT WorkflowId, COUNT(*) AS TotalCount
        FROM WorkflowSetupProgress
        WHERE Status <> N'NotNeeded'
        GROUP BY WorkflowId
    ),
    PendingModules AS (
        SELECT
            wsp.WorkflowId,
            -- Section 1: items that need client action
            STRING_AGG(
                CASE WHEN wsp.Status IN (N'PendingAtClient', N'Blocked')
                THEN N'<tr><td style=''padding:5px 12px;border-bottom:1px solid #f0f0f0;''><strong>' + sm.ModuleName + N'</strong></td>'
                     + N'<td style=''padding:5px 12px;border-bottom:1px solid #f0f0f0;''>'
                     + CASE wsp.Status
                         WHEN N'PendingAtClient' THEN N'<span style=''background:#fff3cd;color:#856404;padding:2px 7px;border-radius:4px;font-size:11px;''>Info Required</span>'
                         ELSE N'<span style=''background:#f8d7da;color:#842029;padding:2px 7px;border-radius:4px;font-size:11px;''>Blocked</span>'
                       END
                     + ISNULL(N'<br/><small style=''color:#6c757d;''>' + NULLIF(wsp.BlockerNotes, N'') + N'</small>', N'')
                     + N'</td></tr>'
                ELSE NULL END,
                N''
            ) AS ClientHtml,
            SUM(CASE WHEN wsp.Status IN (N'PendingAtClient', N'Blocked') THEN 1 ELSE 0 END) AS ClientCount,
            -- Section 2: modules not yet started by our team
            STRING_AGG(
                CASE WHEN wsp.Status = N'NotStarted'
                THEN N'<tr><td style=''padding:5px 12px;border-bottom:1px solid #f0f0f0;''>' + sm.ModuleName + N'</td>'
                     + N'<td style=''padding:5px 12px;border-bottom:1px solid #f0f0f0;color:#6c757d;font-size:12px;''>'
                     + ISNULL(sm.Category, N'General') + N'</td></tr>'
                ELSE NULL END,
                N''
            ) AS QueueHtml,
            SUM(CASE WHEN wsp.Status = N'NotStarted' THEN 1 ELSE 0 END) AS QueueCount
        FROM WorkflowSetupProgress wsp
        JOIN SetupModules sm ON wsp.ModuleId = sm.Id
        WHERE wsp.Status IN (N'PendingAtClient', N'Blocked', N'NotStarted')
        GROUP BY wsp.WorkflowId
    )
    SELECT
        ROW_NUMBER() OVER (ORDER BY w.Id, ct.TriggerType) AS RowNum,
        w.Id                                               AS WorkflowId,
        ct.Id                                              AS TemplateId,
        ISNULL(NULLIF(LTRIM(RTRIM(w.ClientContactName)), N''), pe.name) AS RecipientName,
        ISNULL(NULLIF(LTRIM(RTRIM(w.ClientContactEmail)),N''), pe.email) AS RecipientEmail,
        ISNULL(NULLIF(LTRIM(RTRIM(w.ClientContactName)), N''), pe.name) AS CustomerName,
        ISNULL(pe.company_name, N'Your Company')                         AS CompanyName,
        ISNULL(ul.User_Name, N'KIT19 Team')                              AS OwnerName,
        CONVERT(NVARCHAR(20), w.TrialStartDate, 106)                     AS TrialStartDate,
        CONVERT(NVARCHAR(20), w.TrialEndDate, 106)                       AS TrialEndDate,
        CAST(w.TrialDurationDays AS NVARCHAR(10))                        AS TrialDurationDays,
        CAST(DATEDIFF(DAY, GETDATE(), w.TrialEndDate) AS NVARCHAR(10))   AS DaysRemaining,
        ISNULL(cm.ModulesText, N'Setup in progress')                     AS ModulesCompleted,
        ISNULL(pm.ClientHtml,  N'')  AS ClientHtml,
        ISNULL(pm.ClientCount, 0)    AS ClientCount,
        ISNULL(pm.QueueHtml,   N'')  AS QueueHtml,
        ISNULL(pm.QueueCount,  0)    AS QueueCount,
        -- Progress statement based on % completion
        CASE
            WHEN ISNULL(tm.TotalCount, 0) = 0 THEN N'Your setup is just getting started. Our team will guide you through each step.'
            WHEN (ISNULL(cm.CompletedCount,0) * 100 / tm.TotalCount) >= 80 THEN N'Excellent progress! You are almost at the finish line.'
            WHEN (ISNULL(cm.CompletedCount,0) * 100 / tm.TotalCount) >= 50 THEN N'Good progress &mdash; you are past the halfway mark. Keep going!'
            WHEN (ISNULL(cm.CompletedCount,0) * 100 / tm.TotalCount) >= 25 THEN N'You have made a great start. Let us keep the momentum going.'
            ELSE N'Your setup is in its early stages. Our team is here to accelerate your onboarding.'
        END AS ProgressStatement,
        -- e.g. "8/52 modules"
        CONCAT(ISNULL(cm.CompletedCount, 0), N'/', ISNULL(tm.TotalCount, 0), N' modules') AS SetupProgress,
        -- Deal Amount from workflow additional fields
        ISNULL(CAST((
            SELECT TOP 1 wafv.NumericValue FROM WorkflowAdditionalFieldValues wafv
            JOIN AdditionalFieldDefinitions afd ON wafv.FieldId = afd.Id
            WHERE wafv.WorkflowId = w.Id AND afd.FieldName = N'Amount'
        ) AS NVARCHAR(50)), N'') AS DealAmount,
        ct.Subject,
        ct.MessageBody,
        ct.Channel,
        ct.TriggerType
    INTO #PendingEmails
    FROM TrialSetupWorkflow w (NOLOCK)
    JOIN pre_enquiry pe         ON w.LeadId = pe.enqno AND w.OfficeId = pe.office_id
    LEFT JOIN User_Login ul     ON w.CurrentOwnerId = ul.user_id
    LEFT JOIN LatestExtension le ON le.WorkflowId = w.Id
    LEFT JOIN CompletedModules cm ON cm.WorkflowId = w.Id
    LEFT JOIN TotalModules tm    ON tm.WorkflowId = w.Id
    LEFT JOIN PendingModules pm  ON pm.WorkflowId = w.Id
    CROSS JOIN CommunicationTemplates ct
    WHERE w.IsActive   = 1
      AND w.IsDeleted  = 0
      AND w.IsLocked   = 0
      AND w.IsCompleted = 0
      AND ct.IsActive  = 1
      AND ct.Channel   = N'Email'
      AND (ct.ProductId IS NULL OR ct.ProductId = w.ProductId)
      AND (
            NULLIF(LTRIM(RTRIM(w.ClientContactEmail)), N'') IS NOT NULL
         OR NULLIF(LTRIM(RTRIM(pe.email)), N'') IS NOT NULL
          )
      AND (
            (ct.TriggerType = N'ScheduledDays'
             AND w.TrialStartDate IS NOT NULL
             AND DATEDIFF(DAY, w.TrialStartDate, GETDATE()) = ct.TriggerDayOffset)
         OR (ct.TriggerType = N'OnExtensionDay1'
             AND w.TrialStartDate IS NOT NULL
             AND le.LatestGrantedOn IS NOT NULL
             AND DATEDIFF(DAY, le.LatestGrantedOn, GETDATE()) = 1)
         OR (ct.TriggerType = N'OnExtensionDay3'
             AND w.TrialStartDate IS NOT NULL
             AND le.LatestGrantedOn IS NOT NULL
             AND DATEDIFF(DAY, le.LatestGrantedOn, GETDATE()) = 3)
         OR (ct.TriggerType = N'OnExtensionExpiring'
             AND w.TrialStartDate IS NOT NULL
             AND le.ExtendedEndDate IS NOT NULL
             AND DATEDIFF(DAY, GETDATE(), le.ExtendedEndDate) = 2)
         OR (ct.TriggerType = N'OnWorkflowStart'
             AND DATEDIFF(DAY, w.WorkflowStartDate, GETDATE()) = 0)
          )
      AND NOT EXISTS (
          SELECT 1 FROM WorkflowCommunicationLog
          WHERE WorkflowId = w.Id
            AND TemplateId = ct.Id
            AND CAST(SentOn AS DATE) = CAST(GETDATE() AS DATE)
      );

    ---------------------------------------------------------------------------
    -- 2. Loop and send each email
    ---------------------------------------------------------------------------
    DECLARE
        @RowNum           INT,
        @MaxRow           INT,
        @WorkflowId       BIGINT,
        @TemplateId       INT,
        @RecipientName    NVARCHAR(255),
        @RecipientEmail   NVARCHAR(255),
        @CustomerName     NVARCHAR(255),
        @CompanyName      NVARCHAR(255),
        @OwnerName        NVARCHAR(255),
        @TrialStartDate   NVARCHAR(20),
        @TrialEndDate     NVARCHAR(20),
        @TrialDurationDays NVARCHAR(10),
        @DaysRemaining    NVARCHAR(10),
        @ModulesText      NVARCHAR(MAX),
        @ClientHtml       NVARCHAR(MAX),
        @ClientCount      INT,
        @QueueHtml        NVARCHAR(MAX),
        @QueueCount       INT,
        @ProgressStmt     NVARCHAR(500),
        @SetupProgress    NVARCHAR(50),
        @DealAmount       NVARCHAR(50),
        @Subject          NVARCHAR(500),
        @Body             NVARCHAR(MAX),
        @TriggerType      NVARCHAR(100),
        @PendingSection   NVARCHAR(MAX),
        @ErrorMsg         NVARCHAR(1000);

    SELECT @RowNum = 1, @MaxRow = MAX(RowNum) FROM #PendingEmails;

    PRINT CONCAT('Pending emails to send today: ', ISNULL(@MaxRow, 0));

    WHILE @RowNum <= ISNULL(@MaxRow, 0)
    BEGIN
        SELECT
            @WorkflowId        = WorkflowId,
            @TemplateId        = TemplateId,
            @RecipientName     = RecipientName,
            @RecipientEmail    = RecipientEmail,
            @CustomerName      = CustomerName,
            @CompanyName       = CompanyName,
            @OwnerName         = OwnerName,
            @TrialStartDate    = TrialStartDate,
            @TrialEndDate      = TrialEndDate,
            @TrialDurationDays = TrialDurationDays,
            @DaysRemaining     = DaysRemaining,
            @ModulesText       = ModulesCompleted,
            @ClientHtml        = ClientHtml,
            @ClientCount       = ClientCount,
            @QueueHtml         = QueueHtml,
            @QueueCount        = QueueCount,
            @ProgressStmt      = ProgressStatement,
            @SetupProgress     = SetupProgress,
            @DealAmount        = DealAmount,
            @Subject           = Subject,
            @Body              = MessageBody,
            @TriggerType       = TriggerType
        FROM #PendingEmails
        WHERE RowNum = @RowNum;

        -- Build two-section pending block
        SET @PendingSection = N'';

        IF @ClientCount > 0
            SET @PendingSection = @PendingSection
                + N'<div style="background:#fff8f0;border:1px solid #ffd699;border-radius:8px;padding:16px;margin-bottom:10px;">'
                + N'<h4 style="color:#e65100;margin:0 0 8px;font-size:14px;">&#9888; Action Required From Your Side ('
                + CAST(@ClientCount AS NVARCHAR) + N' item' + CASE WHEN @ClientCount > 1 THEN N's' ELSE N'' END + N')</h4>'
                + N'<p style="font-size:13px;color:#555;margin:0 0 10px;">These modules need your input or approval before we can proceed:</p>'
                + N'<table style="width:100%;border-collapse:collapse;font-size:13px;">'
                + N'<thead><tr style="background:#ffecd6;"><th style="padding:6px 12px;text-align:left;">Module</th><th style="padding:6px 12px;text-align:left;">What We Need</th></tr></thead>'
                + N'<tbody>' + @ClientHtml + N'</tbody></table>'
                + N'<p style="font-size:13px;color:#e65100;font-weight:bold;margin:10px 0 0;">Please respond to your setup manager to keep your trial on track.</p>'
                + N'</div>';

        IF @QueueCount > 0
            SET @PendingSection = @PendingSection
                + N'<div style="background:#f0f7ff;border:1px solid #b8daff;border-radius:8px;padding:16px;">'
                + N'<h4 style="color:#0056b3;margin:0 0 8px;font-size:14px;">&#9881; In Our Setup Queue ('
                + CAST(@QueueCount AS NVARCHAR) + N' item' + CASE WHEN @QueueCount > 1 THEN N's' ELSE N'' END + N')</h4>'
                + N'<p style="font-size:13px;color:#555;margin:0 0 10px;">The following modules are scheduled to be completed by our team:</p>'
                + N'<table style="width:100%;border-collapse:collapse;font-size:13px;">'
                + N'<thead><tr style="background:#cfe2ff;"><th style="padding:6px 12px;text-align:left;">Module</th><th style="padding:6px 12px;text-align:left;">Category</th></tr></thead>'
                + N'<tbody>' + @QueueHtml + N'</tbody></table>'
                + N'</div>';

        -- Apply all merge tags
        SET @Body = REPLACE(@Body, N'{{CustomerName}}',          @CustomerName);
        SET @Body = REPLACE(@Body, N'{{ClientContactName}}',     @CustomerName);
        SET @Body = REPLACE(@Body, N'{{CompanyName}}',           @CompanyName);
        SET @Body = REPLACE(@Body, N'{{OwnerName}}',             @OwnerName);
        SET @Body = REPLACE(@Body, N'{{TrialStartDate}}',        @TrialStartDate);
        SET @Body = REPLACE(@Body, N'{{TrialEndDate}}',          @TrialEndDate);
        SET @Body = REPLACE(@Body, N'{{TrialDurationDays}}',     @TrialDurationDays);
        SET @Body = REPLACE(@Body, N'{{DaysRemaining}}',         @DaysRemaining);
        SET @Body = REPLACE(@Body, N'{{ModulesCompleted}}',      @ModulesText);
        SET @Body = REPLACE(@Body, N'{{ProgressStatement}}',     @ProgressStmt);
        SET @Body = REPLACE(@Body, N'{{SetupProgress}}',         @SetupProgress);
        SET @Body = REPLACE(@Body, N'{{DealAmount}}',            @DealAmount);
        SET @Body = REPLACE(@Body, N'{{PendingModulesSection}}', @PendingSection);
        SET @Body = REPLACE(@Body, N'{{UsageSummary}}',          N'');
        SET @Body = REPLACE(@Body, N'{{SalesOwner}}',            @OwnerName);
        SET @Body = REPLACE(@Body, N'{{ChurnReason}}',           N'');
        SET @Body = REPLACE(@Body, N'{{LeadEmail}}',             @RecipientEmail);

        SET @ErrorMsg = NULL;

        IF @DryRun = 0
        BEGIN
            BEGIN TRY
                EXEC msdb.dbo.sp_send_dbmail
                    @profile_name = N'KIT19_SES_Profile',
                    @recipients   = @RecipientEmail,
                    @subject      = @Subject,
                    @body         = @Body,
                    @body_format  = N'HTML';

                INSERT INTO WorkflowCommunicationLog
                    (WorkflowId, TemplateId, Channel, Recipient, Subject, MessageBody, SentOn, SentBy, Status, IsAutomated)
                VALUES
                    (@WorkflowId, @TemplateId, N'Email', @RecipientEmail, @Subject, @Body, GETDATE(), NULL, N'Sent', 1);

                PRINT CONCAT('  OK  [WF:', @WorkflowId, '] -> ', @RecipientEmail, ' | ', @Subject);
            END TRY
            BEGIN CATCH
                SET @ErrorMsg = LEFT(ERROR_MESSAGE(), 1000);
                INSERT INTO WorkflowCommunicationLog
                    (WorkflowId, TemplateId, Channel, Recipient, Subject, MessageBody, SentOn, SentBy, Status, ErrorMessage, IsAutomated)
                VALUES
                    (@WorkflowId, @TemplateId, N'Email', @RecipientEmail, @Subject, @Body, GETDATE(), NULL, N'Failed', @ErrorMsg, 1);
                PRINT CONCAT('  FAIL [WF:', @WorkflowId, '] -> ', @RecipientEmail, ' | ', @ErrorMsg);
            END CATCH;
        END
        ELSE
        BEGIN
            PRINT CONCAT('  [DRY-RUN] Would send [WF:', @WorkflowId, '] -> ', @RecipientEmail, ' | ', @Subject);
        END

        SET @RowNum = @RowNum + 1;
    END

    DROP TABLE #PendingEmails;

    ---------------------------------------------------------------------------
    -- 3. Build and send Daily Management Report
    ---------------------------------------------------------------------------

    DECLARE @ManagementEmail NVARCHAR(255) = N'shuti.m1989@gmail.com';  -- << Change to management email

    DECLARE @ReportRows NVARCHAR(MAX) = N'';
    DECLARE @ReportBody NVARCHAR(MAX);

    SELECT @ReportRows = @ReportRows +
        N'<tr style="background:' + CASE WHEN ROW_NUMBER() OVER (ORDER BY w.Id) % 2 = 0 THEN N'#f8f9fa' ELSE N'#fff' END + N';">'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;">' + CAST(pe.EnqNo AS NVARCHAR) + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;">' + ISNULL(NULLIF(LTRIM(RTRIM(w.ClientContactName)),N''), pe.Name) + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;">' + ISNULL(pe.company_name, N'-') + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;">' + ISNULL(CAST(pe.Executive AS NVARCHAR(200)), N'-') + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;">' + ISNULL(ul.User_Name, N'-') + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;text-align:center;">' + ISNULL(CAST((
            SELECT TOP 1 CAST(NumericValue AS INT) FROM WorkflowAdditionalFieldValues wafv
            JOIN AdditionalFieldDefinitions afd ON wafv.FieldId = afd.Id
            WHERE wafv.WorkflowId = w.Id AND afd.FieldName = N'NumberOfUsers') AS NVARCHAR), N'-') + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;text-align:right;">'
            + ISNULL(N'&#8377;' + CAST((
                SELECT TOP 1 CAST(NumericValue AS BIGINT) FROM WorkflowAdditionalFieldValues wafv
                JOIN AdditionalFieldDefinitions afd ON wafv.FieldId = afd.Id
                WHERE wafv.WorkflowId = w.Id AND afd.FieldName = N'Amount') AS NVARCHAR), N'-') + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;">' + CONVERT(NVARCHAR(20), w.WorkflowStartDate, 106) + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;">' + ISNULL(ul.User_Name, N'Unassigned') + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;">' + ISNULL(wp.ProductName, N'-') + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;">' + ISNULL(CONVERT(NVARCHAR(20), w.TrialEndDate, 106), N'-') + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;text-align:center;'
            + CASE WHEN DATEDIFF(DAY, GETDATE(), w.TrialEndDate) <= 2 THEN N'color:#dc3545;font-weight:bold;' ELSE N'' END + N'">'
            + ISNULL(CAST(DATEDIFF(DAY, GETDATE(), w.TrialEndDate) AS NVARCHAR), N'-') + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;text-align:center;">'
            + CASE WHEN EXISTS(SELECT 1 FROM WorkflowExtensions WHERE WorkflowId = w.Id) THEN N'<span style="color:green;font-weight:bold;">Yes</span>' ELSE N'No' END + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;">'
            + ISNULL(CONVERT(NVARCHAR(20), (SELECT MAX(NewEndDate) FROM WorkflowExtensions WHERE WorkflowId = w.Id), 106), N'-') + N'</td>'
        + N'<td style="padding:7px 10px;border:1px solid #dee2e6;text-align:center;">'
            + CONCAT(
                ISNULL((SELECT COUNT(*) FROM WorkflowSetupProgress WHERE WorkflowId = w.Id AND Status = N'Completed'), 0),
                N' / ',
                ISNULL((SELECT COUNT(*) FROM WorkflowSetupProgress WHERE WorkflowId = w.Id AND Status <> N'NotNeeded'), 0)
              ) + N' modules</td>'
        + N'</tr>'
    FROM TrialSetupWorkflow w (NOLOCK)
    JOIN pre_enquiry pe          ON w.LeadId = pe.EnqNo AND w.OfficeId = pe.Office_ID
    LEFT JOIN User_Login ul      ON w.CurrentOwnerId = ul.user_id
    LEFT JOIN WorkflowProducts wp ON w.ProductId = wp.Id
    WHERE w.IsActive = 1
      AND w.IsDeleted = 0
    ORDER BY w.WorkflowStartDate;

    DECLARE @ActiveCount INT = (
        SELECT COUNT(*) FROM TrialSetupWorkflow WHERE IsActive = 1 AND IsDeleted = 0
    );
    DECLARE @ExpiringCount INT = (
        SELECT COUNT(*) FROM TrialSetupWorkflow
        WHERE IsActive = 1 AND IsDeleted = 0
          AND TrialEndDate IS NOT NULL
          AND DATEDIFF(DAY, GETDATE(), TrialEndDate) BETWEEN 0 AND 3
    );

    SET @ReportBody = N'<div style="font-family:Arial,sans-serif;max-width:1100px;margin:auto;padding:20px;">'
        + N'<div style="background:linear-gradient(135deg,#0d6efd,#0a58ca);padding:20px 24px;border-radius:8px 8px 0 0;">'
        + N'<h1 style="color:#fff;margin:0;font-size:20px;">KIT19 Daily Trial Setup Report</h1>'
        + N'<p style="color:rgba(255,255,255,0.85);margin:6px 0 0;font-size:13px;">Generated: ' + CONVERT(NVARCHAR(30), GETDATE(), 113) + N'</p></div>'
        + N'<div style="background:#fff;padding:20px 24px;border:1px solid #dee2e6;border-radius:0 0 8px 8px;">'
        + N'<div style="display:flex;gap:16px;margin-bottom:20px;">'
        + N'<div style="background:#e8f4fd;padding:14px 20px;border-radius:8px;flex:1;text-align:center;">'
        + N'<div style="font-size:28px;font-weight:bold;color:#0d6efd;">' + CAST(@ActiveCount AS NVARCHAR) + N'</div>'
        + N'<div style="font-size:12px;color:#555;">Active Setups</div></div>'
        + N'<div style="background:#fff3cd;padding:14px 20px;border-radius:8px;flex:1;text-align:center;">'
        + N'<div style="font-size:28px;font-weight:bold;color:#856404;">' + CAST(@ExpiringCount AS NVARCHAR) + N'</div>'
        + N'<div style="font-size:12px;color:#555;">Expiring in 3 Days</div></div></div>'
        + N'<div style="overflow-x:auto;">'
        + N'<table style="width:100%;border-collapse:collapse;font-size:12px;min-width:1000px;">'
        + N'<thead><tr style="background:#0d6efd;color:#fff;">'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;text-align:left;">Enq No</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Contact Name</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Company</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Lead Owner</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Setup Owner</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">No. of Users</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Deal Amt (Rs.)</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Registered On</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Currently Assigned</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Product</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Trial End Date</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Days Left</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Extended?</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Extended Till</th>'
        + N'<th style="padding:8px 10px;border:1px solid #0a58ca;">Setup Progress</th>'
        + N'</tr></thead><tbody>'
        + ISNULL(@ReportRows, N'<tr><td colspan="14" style="text-align:center;padding:20px;color:#6c757d;">No active setups today.</td></tr>')
        + N'</tbody></table></div>'
        + N'<hr style="border:none;border-top:1px solid #dee2e6;margin:20px 0;"/>'
        + N'<p style="font-size:11px;color:#adb5bd;">KIT19 CRM | Automated Daily Report | Do not reply to this email.</p>'
        + N'</div></div>';

    IF @DryRun = 0
    BEGIN
        BEGIN TRY
            DECLARE @ReportQuery NVARCHAR(MAX) = N'
SELECT
    pe.EnqNo                                                                AS [Enq No],
    ISNULL(CASE WHEN LEN(LTRIM(RTRIM(w.ClientContactName)))>0 THEN w.ClientContactName ELSE NULL END, pe.name)
                                                                            AS [Contact Name],
    ISNULL(pe.company_name, ''-'')                                          AS Company,
    ISNULL(CAST(pe.Executive AS VARCHAR(200)), ''-'')                       AS [Lead Owner],
    ISNULL(ul.User_Name, ''-'')                                             AS [Setup Owner],
    ISNULL(CAST((SELECT TOP 1 v.NumericValue FROM WorkflowAdditionalFieldValues v JOIN AdditionalFieldDefinitions d ON v.FieldId=d.Id WHERE v.WorkflowId=w.Id AND d.FieldName=''NumberOfUsers'') AS VARCHAR(20)), ''-'')
                                                                            AS [Users],
    ISNULL(CAST((SELECT TOP 1 v.NumericValue FROM WorkflowAdditionalFieldValues v JOIN AdditionalFieldDefinitions d ON v.FieldId=d.Id WHERE v.WorkflowId=w.Id AND d.FieldName=''Amount'') AS VARCHAR(20)), ''-'')
                                                                            AS [Deal Amt (Rs.)],
    CONVERT(VARCHAR(20), w.WorkflowStartDate, 106)                          AS [Registered On],
    ISNULL(wp.ProductName, ''-'')                                           AS Product,
    ISNULL(CONVERT(VARCHAR(20), w.TrialEndDate, 106), ''-'')                AS [Trial End Date],
    ISNULL(CAST(DATEDIFF(DAY, GETDATE(), w.TrialEndDate) AS VARCHAR(10)), ''-'')
                                                                            AS [Days Left],
    CASE WHEN EXISTS(SELECT 1 FROM WorkflowExtensions WHERE WorkflowId=w.Id) THEN ''Yes'' ELSE ''No'' END
                                                                            AS Extended,
    ISNULL(CONVERT(VARCHAR(20),(SELECT MAX(NewEndDate) FROM WorkflowExtensions WHERE WorkflowId=w.Id),106),''-'')
                                                                            AS [Extended Till],
    CAST(ISNULL((SELECT COUNT(*) FROM WorkflowSetupProgress WHERE WorkflowId=w.Id AND Status=''Completed''),0) AS VARCHAR)
        + '' / ''
        + CAST(ISNULL((SELECT COUNT(*) FROM WorkflowSetupProgress WHERE WorkflowId=w.Id AND Status<>''NotNeeded''),0) AS VARCHAR)
        + '' modules''                                                      AS [Setup Progress]
FROM TrialSetupWorkflow w
JOIN pre_enquiry pe   ON w.LeadId=pe.EnqNo AND w.OfficeId=pe.Office_ID
LEFT JOIN User_Login ul       ON w.CurrentOwnerId=ul.user_id
LEFT JOIN WorkflowProducts wp ON w.ProductId=wp.Id
WHERE w.IsActive=1 AND w.IsDeleted=0
ORDER BY w.WorkflowStartDate';


        declare @mailsubject nvarchar(500)=N'KIT19 Daily Trial Setup Report - ' + CONVERT(NVARCHAR(12), GETDATE(), 106)


            EXEC msdb.dbo.sp_send_dbmail
                @profile_name = N'KIT19_SES_Profile',
                @recipients   = @ManagementEmail,
                @subject      = @mailsubject,
                @body         = @ReportBody,
                @body_format  = N'HTML',
                @query        = @ReportQuery,
                @execute_query_database  = N'CRMDB',
                @attach_query_result_as_file = 1,
                @query_attachment_filename   = N'KIT19_DailyReport.csv',
                @query_result_separator      = N',',
                @query_result_no_padding     = 1;
            PRINT CONCAT('Management report sent to ', @ManagementEmail);
        END TRY
        BEGIN CATCH
            PRINT CONCAT('Management report FAILED: ', ERROR_MESSAGE());
        END CATCH;
    END
    ELSE
    BEGIN
        PRINT CONCAT('[DRY-RUN] Management report would be sent to ', @ManagementEmail, ' for ', @ActiveCount, ' active setups');
    END

    PRINT 'usp_SendDailyEmailsFromQueue complete.';
END



GO

/* ============================================================
