   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROC [dbo].[usp_sendfacebookleadmail]-- 1-- 17626        
@id bigint        
as        
begin       
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX) 
      
select id,full_name as FullName,Email,phone_number into #temp from facebookleads where id=@id   
