declare @subject nvarchar(100) ='New Facebook lead recieved at '+cast (getdate() as nvarchar)      
      
EXEC usp_enqueueemail        
@profile_name='Alerts',         
@recipients='animesh.shukla@pelsoftlabs.in;csshukla@pelsoftlabs.in;shailendra.singh@pelsoftlabs.in',        
@blind_copy_recipients='karuna@pelsoftlabs.in',        
@subject=@subject,        
@body = @body,        
@body_format ='HTML'        
drop table #temp        
end   
      



