/* ============================================================
   Procedure: [dbo].[usp_SendIntlSmsManyToMany]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_SendIntlSmsManyToMany]
(
	@UserId BIGINT,
	@MobileNo NVARCHAR(MAX),
	@SenderId nvarchar(30),
	@SmsMsg NVARCHAR(4000),
	@MassOpBatchId BIGINT= 0,
	@UrlTrack bit=0,
	@UrlText nvarchar(max),
	@Placeholder nvarchar(max)
)
AS
BEGIN  
  
    
 --declare @MobileNo nvarchar(max) = '+919913943059,+619913943057,+619913943058',    
	--@UserId BIGINT=34594,
	--@SmsMsg nvarchar(4000)=N'ghhhhhhhhhhhh   #lead.AssignedTo# #lead.City#  jhjh\nkjkj m  #lead.EmailID2# https://kit19.com',
	--@MassOpBatchId bigint=1342,
	--@SenderId nvarchar(30)='INTL_MSMSM',
	--@UrlTrack bit=0,
	--@UrlText nvarchar(max)='https://kit19.com',
	--@Placeholder nvarchar(max)='#lead.AssignedTo#,#lead.City#,#lead.EmailID2#'
   
  
    -- Declare variables      
    DECLARE @Result AS VARCHAR(100);  
    DECLARE @IsValid AS BIT;  
    DECLARE @SmsApiURI AS VARCHAR(200);  
    DECLARE @IntlSMSProviderId AS INT, @PageName varchar(20), @TotalRecords int=0;  
    DECLARE @Balance AS DECIMAL, @IsPriority bit=0;  
    DECLARE @Country AS VARCHAR(200), @Batchid BIGINT=0;  
    DECLARE @Key AS VARCHAR(200), @ispersonalised BIT=0;  
    DECLARE @Send AS VARCHAR(200), @Placeholders NVARCHAR(MAX) = '', @TrackedUrl nvarchar(max);  
    DECLARE @CountryCode AS VARCHAR(200), @ParentId bigint,@EntityName  varchar(10);  
    DECLARE @TotalCost numeric(18,4)= 0, @Cost numeric(18,4)= 0, @IsUnicode BIT= 0, @NoOfUnit INT= 1;  

	BEGIN TRY
      
	SELECT @ParentId=ParentId FROM user_detail WITH(NOLOCK) WHERE User_ID = @UserId  
   
	DROP TABLE IF EXISTS #MobileNumbers;  
  
    -- Create a temporary table to store individual mobile numbers      
    CREATE TABLE #MobileNumbers  
    (  
		CountryCode NVARCHAR(20),   
        MobileNo    NVARCHAR(30),   
        Cost        numeric(18,4),  
		EntityId bigint,  
		EntityName  varchar(10)  
    );  

    SELECT @IsUnicode = dbo.fn_isunicode(@SmsMsg);  
    SELECT @NoOfUnit = (CASE  
                            WHEN @IsUnicode = 0  
                                    AND LEN(@SmsMsg) <= 160  
                            THEN 1  
                            WHEN @IsUnicode = 0  
                                    AND LEN(@SmsMsg) > 160  
                            THEN CEILING(LEN(@SmsMsg) / CAST(153 AS FLOAT))  
                            WHEN @IsUnicode = 1  
                                    AND LEN(@SmsMsg) <= 70  
                            THEN 1  
                            ELSE CEILING(LEN(@SmsMsg) / CAST(67 AS FLOAT))  
                        END);  
  
    -- Split the mobile numbers and insert into the temporary table      
    INSERT INTO #MobileNumbers  
    (CountryCode,MobileNo)  
    SELECT countrycode,MobileWithoutContryCode  
    FROM  
    (  
        SELECT ROW_NUMBER() OVER(PARTITION BY countrycode,MobileNo ORDER BY countrycode,MobileNo) AS sno,   
                countrycode,   
                STUFF(replace(MobileNo, '+', ''), CHARINDEX(replace(TRIM(countrycode), '+', ''), replace(MobileNo, '+', '')), LEN(replace(TRIM(countrycode), '+', '')), '') MobileWithoutContryCode  
        FROM m_country1(NOLOCK) INNER JOIN  
        (  
            SELECT value AS MobileNo  
            FROM STRING_SPLIT(@MobileNo, ',')  
        ) M   
		ON replace(LTRIM(RTRIM(countrycode)), '+', '') = LEFT(dbo.fn_trim0prefix(replace(replace(replace(MobileNo, '+', ''), '-', ''), ' ', '')), LEN(replace(LTRIM(RTRIM(countrycode)), '+', '')))  
    ) T  
    WHERE T.sno = 1;  
  
    -- Check if the user exists      
    IF EXISTS (SELECT 1 FROM user_detail WITH(NOLOCK) WHERE User_ID = @UserId)  
    BEGIN      
        -- Get the user's balance      
        SELECT @Balance = dbo.fn_GetMoneyBalance(@UserId);  
  
        IF EXISTS (SELECT * FROM Price_Base_SMS_Rate_Exception(NOLOCK) WHERE ParentID = @ParentId)  
        BEGIN  
            UPDATE MN  
            SET MN.Cost = CAST(ISNULL(BR.PTrns, 0.00) * @NoOfUnit AS NUMERIC(18, 4))  
            FROM Price_Base_SMS_Rate_Exception(NOLOCK) BR RIGHT JOIN #MobileNumbers MN   
			ON BR.DestinationCountryCode = MN.CountryCode AND BR.ParentID = @UserId;  
        END;  
        ELSE  
        BEGIN  
            UPDATE MN  
            SET MN.Cost = CAST(ISNULL(BR.PTrns, 0.00) * @NoOfUnit AS NUMERIC(18, 4))  
            FROM Price_base_sms_rate(NOLOCK) BR RIGHT JOIN #MobileNumbers MN   
			ON BR.DestinationCountryCode = MN.CountryCode AND BR.IsEligible = 1;  
        END;  
  
        SELECT @TotalCost = SUM(Cost)  
        FROM #MobileNumbers;  
  
        PRINT concat('@Balance: ', @Balance);  
        PRINT concat('@TotalCost: ', @TotalCost);  
        PRINT concat('@TotalCost*1.5: ', @TotalCost * 1.5);  
        PRINT concat('Balance After this batch: ', @Balance - (@TotalCost * 1.5));  
  
        -- Check if the user has sufficient balance      
        IF((@Balance - (@TotalCost * 1.5)) > 0)  
        BEGIN  
            -- Check if the country is eligible for SMS service      
            IF @TotalCost > 0  
            BEGIN      
                -- Get SMS provider details      
                SELECT @SmsApiURI = API,   
                        @IntlSMSProviderId = id,   
                        @Key = [Key],   
                        @CountryCode = CountryCode  
                FROM tbl_intlSMSProvider WITH(NOLOCK)  
                WHERE IsActive = 1;  
  
				Select @EntityName=EntityType, @TrackedUrl=TrackedUrl
				from Tbl_MassOperationSummary(nolock)
				Where	BatchID=@MassOpBatchId

				Select @TotalRecords=count(*)
				From  Tbl_MassOperationDetails(nolock) 
				Where SummaryId=@MassOpBatchId

				If(@TotalRecords<20)
				Begin
					Set @IsPriority=1
				End
				Else
				Begin
					Set @IsPriority=0
				End

				If @EntityName='Lead'
				Begin
					UPDATE MN SET MN.EntityId = UL.ID, MN.EntityName = 'Lead'     
					FROM Tbl_MassOperationDetails(nolock) MODT inner join UserLeads(NOLOCK) UL
					ON	MODT.EntityID=UL.ID inner join #MobileNumbers MN  
					ON  MN.MobileNo in (UL.MobileNo, UL.MobileNo1, UL.MobileNo2) and MN.CountryCode in (UL.CountryCode, UL.CountryCode1, UL.CountryCode2)  
					Where	MODT.SummaryId=@MassOpBatchId

					Set @PageName='MassLeadIntlSms'
				End
				Else If @EntityName='Enquiry'
				Begin
					UPDATE MN SET MN.EntityId = UL.EnquiryID, MN.EntityName = 'Enquiry'     
					FROM Tbl_MassOperationDetails(nolock) MODT inner join UserEnquiry(NOLOCK) UL
					ON	MODT.EntityID=UL.EnquiryID inner join #MobileNumbers MN  
					ON  MN.MobileNo in (UL.MobileNo, UL.MobileNo1, UL.MobileNo2) and MN.CountryCode in (UL.CountryCode, UL.CountryCode1, UL.CountryCode2)  
					Where	MODT.SummaryId=@MassOpBatchId

					Set @PageName='MassEnquiryIntlSms'
				End

				--If(CHARINDEX('#Lead.', @SmsMsg) > 0)  
				--Begin  
				-- SET @Placeholder = (SELECT dbo.ExtractPlaceholders('lead', @SmsMsg));  
				--End  
				--Else  
				--Begin  
				--	SET @Placeholder = (SELECT dbo.ExtractPlaceholders('Enquiry', @SmsMsg));  
				--End  
  
				IF (isnull(@Placeholder,'') = '')
				BEGIN    
				 SET @ispersonalised = 0;    
				END    
				ELSE    
				BEGIN    
				 SET @ispersonalised = 1;    
				END    
  
				select top 1 @Batchid=Batchid from Int_MessageDeliveryStatus(nolock) Where MassOpBatchId=@MassOpBatchId

				If(isnull(@Batchid,0)=0)
				Begin
				-- Begin transaction for batch ID  
					BEGIN TRAN  
					 INSERT INTO Getbatchrecord (user_id, randnum)  
					 VALUES (@UserId, @UserId);  
					 SET @Batchid = SCOPE_IDENTITY();  
					 DELETE FROM Getbatchrecord WHERE Batchid = @Batchid;  

					 insert into BatchInfo(UserID,BatchID,Operator,TotalRecords,ProcessTable,IsProcess,IsPrority,IsAllowDND,BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,IsUniCode,PageName,userfilter,TableName,InvalidCount,DbType,filterMode,bmessage,Totalprocessed,BatchProcessComplete,batchmonitordate,IsFlash,CreatedBy,sms_source,bsender_id,isbatchdeleted,BI_CreatedBy)
					 values
					 (@UserId,@Batchid,null,@TotalRecords,'0',1,@IsPriority,0,GETDATE(),GETDATE(),'','',@IsUnicode,@PageName,'PTrns','Int_MessageDeliveryStatus',0,0,null,@SmsMsg,@TotalRecords,null,null,0,@UserId,@PageName,@SenderId,0,@UserId)
					 
					 COMMIT;  
				End
  
				declare @shorturl nvarchar(10)=null ,          
				@longurl nvarchar(300)=@UrlText,  --original destination url        
				@page_nm nvarchar(50)=null,          
				@IAction nvarchar(50)=null,          
				@isvoice bit=null,          
				@appid int,          
				@duration int=null,          
				@dnid nvarchar(20)=null,          
				@frequency int=null,          
				@latency int=null,          
				@route nvarchar(20) =null    


				--set @isunicode=coalesce(@isunicode,0)              
				--set @priority=coalesce(@priority,0)            
				set @shorturl=coalesce(@shorturl,'pel.im')          
				set @page_nm=coalesce(@page_nm,'Send IntSMS Proc')          
				set @IAction=coalesce(@IAction,'Original Url')          
     
				insert into Link_smsUrl_dtl(BatchId,short_url,longurl,insertdate,status,Parentid,Page_nm,lAction,P_url,IsVoice,AppID,Duration,DNID,Frequency,Latency,Route)          
				select @Batchid,@shorturl,@longurl,GETDATE(),1,@ParentId,@page_nm,@IAction,@longurl,isnull(@isvoice,0),isnull(@appid,0),isnull(@duration,0),@dnid,@frequency,@latency,@route

				INSERT INTO Int_MessageDeliveryStatus (CountryCode, BatchID, Mobile, Message, SenderID, MessageStatus, MessageInsertDate, U_ID, IsUniCode, processed, SmsMode, MassOpBatchId, EntityId, EntityName, UrlTrack, Price, IsPersonalised, TrackedUrl)
				  Select CountryCode, BatchID=ISNULL(@Batchid, 0), MobileNo, Message=@SmsMsg, SenderID=@SenderId, MessageStatus=(CASE WHEN not(LEN(MobileNo) BETWEEN 5 AND 15 AND MobileNo NOT LIKE '%[^0-9+]%') THEN 'Invalid MobileNo' WHEN isnull(cost,0)=0 THEN 'NonDeliverable CountryCode' ELSE ''  END), MessageInsertDate=getdate(), U_ID=@UserId, IsUnicode=@IsUnicode, processed=0, SmsMode='multiTomulti', MassOpBatchId=@MassOpBatchId, EntityID, EntityName, UrlTrack=@UrlTrack, Cost, IsPersonalised=@ispersonalised, TrackedUrl=@TrackedUrl  
				From #MobileNumbers  
  
                -- Set success result      
                SET @Result = 'Success';  
                SET @IsValid = 1;  
                SET @Send = 'Alert';  
            END;  
            ELSE  
            BEGIN      
                -- Set failure result for ineligible country      
                SET @Result = 'We do not serve SMS to this country.';  
                SET @IsValid = 0;  
                SET @SmsApiURI = '';  
                SET @IntlSMSProviderId = '';  
                SET @Key = '';  
                SET @Send = '';  
                SET @CountryCode = '';  
            END;  
        END;  
        ELSE  
        BEGIN  
            -- Set failure result for insufficient balance      
            SET @Result = 'You have insufficient balance';  
            SET @IsValid = 0;  
            SET @SmsApiURI = '';  
            SET @IntlSMSProviderId = '';  
            SET @Key = '';  
            SET @Send = '';  
            SET @CountryCode = '';  
        END;  
	END;  
    ELSE  
    BEGIN      
        -- Set failure result for user not found      
        SET @Result = 'User not found';  
        SET @IsValid = 0;  
        SET @SmsApiURI = '';  
        SET @IntlSMSProviderId = '';  
        SET @Key = '';  
        SET @Send = '';  
        SET @CountryCode = '';  
    END;  
  
    -- Select the result      
    SELECT CAST(@Result AS NVARCHAR(200)) AS Result,   
            CAST(@IsValid AS BIT) AS IsValid,   
            CAST(@SmsApiURI AS NVARCHAR(200)) AS SmsApiURI,   
            CAST(@IntlSMSProviderId AS INT) AS IntlSMSProviderId,   
            CAST(@Key AS NVARCHAR(200)) AS Keys,   
            CAST(@Send AS NVARCHAR(200)) AS Sends,   
            CAST(@CountryCode AS NVARCHAR(200)) AS CountryCode;  
  
    -- Clean up temporary table      
    --DROP TABLE if exists #MobileNumbers;        
	END TRY
	BEGIN CATCH              
		insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)
		SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()              
	END CATCH
END;  



GO

/* ============================================================
   Procedure: [dbo].[usp_SendIntlSmsManyToMany_new1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--------------------------------------


CREATE   PROC [dbo].[usp_SendIntlSmsManyToMany_new1]  
(  
 @UserId BIGINT,  
 @MobileNo NVARCHAR(MAX),  
 @SenderId nvarchar(30),  
 @SmsMsg NVARCHAR(4000),  
 @MassOpBatchId BIGINT= 0, 
 @EntityId BIGINT,
 @EntityType nvarchar(30),
 @UrlTrack bit=0,  
 @UrlText nvarchar(max),  
 @Placeholder nvarchar(max)  
)  
AS  
BEGIN    
    
    DECLARE @Result AS VARCHAR(100);    
    DECLARE @IsValid AS BIT;    
    DECLARE @SmsApiURI AS VARCHAR(200);    
    DECLARE @IntlSMSProviderId AS INT, @PageName varchar(20), @TotalRecords int=0;    
    DECLARE @Balance AS DECIMAL, @IsPriority bit=0;    
    DECLARE @Country AS VARCHAR(200), @Batchid BIGINT=0;    
    DECLARE @Key AS VARCHAR(200), @ispersonalised BIT=0;    
    DECLARE @Send AS VARCHAR(200), @Placeholders NVARCHAR(MAX) = '';    
    DECLARE @CountryCode AS VARCHAR(200), @ParentId bigint,@EntityName  varchar(10);    
    DECLARE @TotalCost numeric(18,4)= 0, @Cost numeric(18,4)= 0, @IsUnicode BIT= 0, @NoOfUnit INT= 1;    
  
 BEGIN TRY  
        
		
 SELECT @ParentId=ParentId FROM user_detail WITH(NOLOCK) WHERE User_ID = @UserId    
 
     
 DROP TABLE IF EXISTS #MobileNumbers;    
    
    -- Create a temporary table to store individual mobile numbers        
    CREATE TABLE #MobileNumbers    
    (    
  CountryCode NVARCHAR(20),     
        MobileNo    NVARCHAR(30),     
        Cost        numeric(18,4),    
  EntityId bigint,    
  EntityName  varchar(10)    
    );    
  
    SELECT @IsUnicode = dbo.fn_isunicode(@SmsMsg);    
    SELECT @NoOfUnit = (CASE    
                            WHEN @IsUnicode = 0    
                                    AND LEN(@SmsMsg) <= 160    
                            THEN 1    
                            WHEN @IsUnicode = 0    
                                    AND LEN(@SmsMsg) > 160    
                            THEN CEILING(LEN(@SmsMsg) / CAST(153 AS FLOAT))    
                            WHEN @IsUnicode = 1    
                                    AND LEN(@SmsMsg) <= 70    
                            THEN 1    
                            ELSE CEILING(LEN(@SmsMsg) / CAST(67 AS FLOAT))    
                        END);    
    
	--select * from userleads (nolock) where id=1702338
   -- Insert data into #MobileNumbers based on EntityType
        IF @EntityType = 'lead'  
        BEGIN  
            INSERT INTO #MobileNumbers (CountryCode, MobileNo, EntityId, EntityName)
            SELECT ul.CountryCode, ul.MobileNo, ul.ID, 'Lead' AS EntityName
            FROM userleads ul
            WHERE ul.ID = @EntityId;  
        END  
        ELSE IF @EntityType = 'enquiry'  
        BEGIN  
            INSERT INTO #MobileNumbers (CountryCode, MobileNo, EntityId, EntityName)
            SELECT ue.CountryCode, ue.MobileNo, ue.EnquiryID, 'Enquiry' AS EntityName
            FROM userenquiry ue
            WHERE ue.EnquiryID = @EntityId;  
        END  
    
    -- Check if the user exists        
    IF EXISTS (SELECT 1 FROM user_detail WITH(NOLOCK) WHERE User_ID = @UserId)    
    BEGIN    
	-- Check if any CountryCode in #MobileNumbers is not equal to '+61'
    IF EXISTS (SELECT 1 FROM #MobileNumbers WHERE CountryCode <> '+61')
    BEGIN
        -- Print and set failure result for ineligible country
        PRINT 'Country Code: ' + + @CountryCode;;
        SET @Result = 'We do not serve SMS to this country.';
        SET @IsValid = 0;
        SET @SmsApiURI = '';
        SET @IntlSMSProviderId = '';
        SET @Key = '';
        SET @Send = '';
        SET @CountryCode = '';

    END;
       ELSE
	BEGIN
     -- Get the user's balance        
        SELECT @Balance = dbo.fn_GetMoneyBalance(@UserId);    
    
        IF EXISTS (SELECT * FROM Price_Base_SMS_Rate_Exception(NOLOCK) WHERE ParentID = @ParentId)    
        BEGIN    
            UPDATE MN    
            SET MN.Cost = CAST(ISNULL(BR.PTrns, 0.00) * @NoOfUnit AS NUMERIC(18, 4))    
            FROM Price_Base_SMS_Rate_Exception(NOLOCK) BR RIGHT JOIN #MobileNumbers MN     
   ON BR.DestinationCountryCode = MN.CountryCode AND BR.ParentID = @UserId;    
        END;    
        ELSE    
        BEGIN    
            UPDATE MN    
            SET MN.Cost = CAST(ISNULL(BR.PTrns, 0.00) * @NoOfUnit AS NUMERIC(18, 4))    
            FROM Price_base_sms_rate(NOLOCK) BR RIGHT JOIN #MobileNumbers MN     
   ON BR.DestinationCountryCode = MN.CountryCode AND BR.IsEligible = 1;    
        END;    
    
        SELECT @TotalCost = SUM(Cost)    
        FROM #MobileNumbers;    
    
        PRINT concat('@Balance: ', @Balance);    
        PRINT concat('@TotalCost: ', @TotalCost);    
        PRINT concat('@TotalCost*1.5: ', @TotalCost * 1.5);    
        PRINT concat('Balance After this batch: ', @Balance - (@TotalCost * 1.5));    
    
        -- Check if the user has sufficient balance        
        IF((@Balance - (@TotalCost * 1.5)) > 0)    
        BEGIN    
		print '1'
            -- Check if the country is eligible for SMS service        
            IF @TotalCost > 0

            BEGIN  
			print '2'
			--select * from tbl_intlSMSProvider  WHERE IsActive = 1;
                -- Get SMS provider details        
                SELECT @SmsApiURI = API,     
                        @IntlSMSProviderId = id,     
                        @Key = [Key],     
                        @CountryCode = CountryCode    
                FROM tbl_intlSMSProvider WITH(NOLOCK)    
                WHERE IsActive = 1 and RequestType='GET';    
    print '3'
	--select * from #MobileNumbers
    --Select @EntityName=EntityType  
    --from Tbl_MassOperationSummary(nolock)  
    --Where BatchID=@MassOpBatchId  
  
    --Select @TotalRecords=count(*)  
    --From  Tbl_MassOperationDetails(nolock)   
    --Where SummaryId=@MassOpBatchId  
  
    --If(@TotalRecords<20)  
    --Begin  
    -- Set @IsPriority=1  
    --End  
    --Else  
    --Begin  
    -- Set @IsPriority=0  
    --End  
  Set @IsPriority=1 
  print '4'
    If @EntityName='Lead'  

    Begin
	
    UPDATE MN 
SET MN.EntityId = UL.ID, 
    MN.EntityName = 'Lead'       
FROM #MobileNumbers MN  
INNER JOIN UserLeads UL WITH (NOLOCK) 
    ON MN.EntityID = UL.ID 
   AND MN.MobileNo IN (UL.MobileNo, UL.MobileNo1, UL.MobileNo2) 
   AND MN.CountryCode IN (UL.CountryCode, UL.CountryCode1, UL.CountryCode2) 
WHERE MN.EntityID = @EntityId; 
  
     Set @PageName='MassLeadIntlSms'  
    End  
    Else If @EntityName='Enquiry'  
    Begin 
	
     UPDATE MN SET MN.EntityId = UL.EnquiryID, MN.EntityName = 'Enquiry'       
     FROM Tbl_MassOperationDetails(nolock) MODT inner join UserEnquiry(NOLOCK) UL  
     ON MODT.EntityID=UL.EnquiryID inner join #MobileNumbers MN    
     ON  MN.MobileNo in (UL.MobileNo, UL.MobileNo1, UL.MobileNo2) and MN.CountryCode in (UL.CountryCode, UL.CountryCode1, UL.CountryCode2)    
     Where MODT.SummaryId=@MassOpBatchId  
  
  UPDATE MN 
SET MN.EntityId = UL.EnquiryID, 
    MN.EntityName = 'Enquiry'       
FROM #MobileNumbers MN  
INNER JOIN UserEnquiry(NOLOCK) UL 
    ON MN.EntityID = UL.EnquiryID 
   AND MN.MobileNo IN (UL.MobileNo, UL.MobileNo1, UL.MobileNo2) 
   AND MN.CountryCode IN (UL.CountryCode, UL.CountryCode1, UL.CountryCode2) 
WHERE MN.EntityID = @EntityId;

     Set @PageName='MassEnquiryIntlSms'  
    End  
  
    IF (isnull(@Placeholder,'') = '')  
    BEGIN 
	print '5'
     SET @ispersonalised = 0;      
    END      
    ELSE      
    BEGIN 
	print '6'
     SET @ispersonalised = 1;  
	 
    END      
    
    select top 1 @Batchid=Batchid from Int_MessageDeliveryStatus(nolock) Where MassOpBatchId=@MassOpBatchId  
  
    If(isnull(@Batchid,0)=0)  
    Begin  
	print '7'
    -- Begin transaction for batch ID    
     BEGIN TRAN    
      INSERT INTO Getbatchrecord (user_id, randnum)    
      VALUES (@UserId, @UserId);    
      SET @Batchid = SCOPE_IDENTITY();    
      DELETE FROM Getbatchrecord WHERE Batchid = @Batchid;    
  
      insert into BatchInfo(UserID,BatchID,Operator,TotalRecords,ProcessTable,IsProcess,IsPrority,IsAllowDND,BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,IsUniCode,PageName,userfilter,TableName,InvalidCount,DbType,filterMode,bmessage,Totalprocessed,BatchProcessComplete,batchmonitordate,IsFlash,CreatedBy,sms_source,bsender_id,isbatchdeleted,BI_CreatedBy)  
      values  
      (@UserId,@Batchid,null,@TotalRecords,'0',1,@IsPriority,0,GETDATE(),GETDATE(),'','',@IsUnicode,@PageName,'PTrns','Int_MessageDeliveryStatus',0,0,null,@SmsMsg,@TotalRecords,null,null,0,@UserId,@PageName,@SenderId,0,@UserId)  
        print '8'
      COMMIT;    
    End  
    
    declare @shorturl nvarchar(10)=null ,            
    @longurl nvarchar(300)=@UrlText,  --original destination url          
    @page_nm nvarchar(50)=null,            
    @IAction nvarchar(50)=null,            
    @isvoice bit=null,            
    @appid int,            
    @duration int=null,            
    @dnid nvarchar(20)=null,            
    @frequency int=null,            
    @latency int=null,            
    @route nvarchar(20) =null      
  
  
    --set @isunicode=coalesce(@isunicode,0)                
    --set @priority=coalesce(@priority,0)              
    set @shorturl=coalesce(@shorturl,'pel.im')            
    set @page_nm=coalesce(@page_nm,'Send IntSMS Proc')            
    set @IAction=coalesce(@IAction,'Original Url')            
      print '9' 
    insert into Link_smsUrl_dtl(BatchId,short_url,longurl,insertdate,status,Parentid,Page_nm,lAction,P_url,IsVoice,AppID,Duration,DNID,Frequency,Latency,Route)            
    select @Batchid,@shorturl,@longurl,GETDATE(),1,@ParentId,@page_nm,@IAction,@longurl,isnull(@isvoice,0),isnull(@appid,0),isnull(@duration,0),@dnid,@frequency,@latency,@route  
  print '10'
  begin try
    INSERT INTO Int_MessageDeliveryStatus (CountryCode, BatchID, Mobile, Message, SenderID, MessageStatus, MessageInsertDate, U_ID, IsUniCode, processed, SmsMode, MassOpBatchId, EntityId, EntityName, UrlTrack, Price, IsPersonalised)  
      Select CountryCode, BatchID=ISNULL(@Batchid, 0), MobileNo, Message=@SmsMsg, SenderID=@SenderId, MessageStatus=(CASE WHEN not(LEN(MobileNo) BETWEEN 5 AND 15 AND MobileNo NOT LIKE '%[^0-9+]%') THEN 'Invalid MobileNo' WHEN isnull(cost,0)=0 THEN 'NonDeliverable CountryCode' ELSE ''  END), MessageInsertDate=getdate(), U_ID=@UserId, IsUnicode=@IsUnicode, processed=0, SmsMode='multiTomulti', MassOpBatchId=@MassOpBatchId, EntityID, EntityName, UrlTrack=@UrlTrack, Cost, IsPersonalised=@ispersonalised    
    From #MobileNumbers  
	end try
	begin catch
	print error_message()
	end catch
	print '11'
    
                -- Set success result        
                SET @Result = 'Success';    
                SET @IsValid = 1;    
                SET @Send = 'Alert';    
            END;    
            ELSE    
            BEGIN      
			 PRINT 'Country Code: ' + @CountryCode;
                -- Set failure result for ineligible country        
                SET @Result = 'We do not serve SMS to this country.';    
                SET @IsValid = 0;    
                SET @SmsApiURI = '';    
                SET @IntlSMSProviderId = '';    
                SET @Key = '';    
                SET @Send = '';    
                SET @CountryCode = '';    
            END;    
        END;    
        ELSE    
        BEGIN    
		 
            -- Set failure result for insufficient balance        
            SET @Result = 'You have insufficient balance';    
            SET @IsValid = 0;    
            SET @SmsApiURI = '';    
            SET @IntlSMSProviderId = '';    
            SET @Key = '';    
            SET @Send = '';    
            SET @CountryCode = '';    
        END;   
	end
	end
    ELSE    
    BEGIN        
        -- Set failure result for user not found        
        SET @Result = 'User not found';    
        SET @IsValid = 0;    
        SET @SmsApiURI = '';    
        SET @IntlSMSProviderId = '';    
        SET @Key = '';    
        SET @Send = '';    
        SET @CountryCode = '';    
    END;    
    
    -- Select the result        
    SELECT CAST(@Result AS NVARCHAR(200)) AS Result,     
            CAST(@IsValid AS BIT) AS IsValid,     
            CAST(@SmsApiURI AS NVARCHAR(200)) AS SmsApiURI,     
            CAST(@IntlSMSProviderId AS INT) AS IntlSMSProviderId,     
            CAST(@Key AS NVARCHAR(200)) AS Keys,     
            CAST(@Send AS NVARCHAR(200)) AS Sends,     
            CAST(@CountryCode AS NVARCHAR(200)) AS CountryCode;    
    
    -- Clean up temporary table        
    --DROP TABLE if exists #MobileNumbers;          
 END TRY  
 BEGIN CATCH                
  insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)  
  SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()                
 END CATCH  
END;   



GO

/* ============================================================
   Procedure: [dbo].[usp_SendIntlSmsOneToMany]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[usp_SendIntlSmsOneToMany]  
(  
 @UserId        BIGINT,   
 @MobileNo      NVARCHAR(MAX),  
 @SenderId		nvarchar(30),  
 @SmsMsg        NVARCHAR(4000),   
 @MassOpBatchId BIGINT= 0,
 @UrlTrack		bit=0
)  
AS  
BEGIN  
  
/*    
    declare @MobileNo nvarchar(max) = '+919913943059,+619913943057,+619913943058',    
  @UserId BIGINT=34594,      
 @SmsMsg nvarchar(4000)=N'This is Sample TextThis is Sample TextThis is Sample TextThis is Sample Text आयोग',    
 @MassOpBatchId bigint=0    
 */  
  
    -- Declare variables      
    DECLARE @Result AS VARCHAR(100);  
    DECLARE @IsValid AS BIT;  
    DECLARE @SmsApiURI AS VARCHAR(200);  
    DECLARE @IntlSMSProviderId AS INT, @IsPriority bit=0;  
    DECLARE @Balance AS DECIMAL, @PageName varchar(20), @TotalRecords int=0;  
    DECLARE @Country AS VARCHAR(200), @Batchid BIGINT=0;  
    DECLARE @Key AS VARCHAR(200), @ispersonalised BIT=0,@EntityName  varchar(10);  
    DECLARE @Send AS VARCHAR(200), @Placeholders NVARCHAR(MAX) = '', @TrackedUrl nvarchar(max);  
    DECLARE @CountryCode AS VARCHAR(200), @ParentId bigint;  
    DECLARE @TotalCost numeric(18,4)= 0, @Cost numeric(18,4)= 0, @IsUnicode BIT= 0, @NoOfUnit INT= 1;  
      
	BEGIN TRY

	SELECT @ParentId=ParentId FROM user_detail WITH(NOLOCK) WHERE User_ID = @UserId  
   
	DROP TABLE IF EXISTS #MobileNumbers;  
  
    -- Create a temporary table to store individual mobile numbers      
    CREATE TABLE #MobileNumbers  
    (  
		CountryCode NVARCHAR(20),   
        MobileNo    NVARCHAR(30),   
        Cost        numeric(18,4),  
		EntityId bigint,  
		EntityName  varchar(10)  
    );  

    SELECT @IsUnicode = dbo.fn_isunicode(@SmsMsg);  
    SELECT @NoOfUnit = (CASE  
                            WHEN @IsUnicode = 0  
                                    AND LEN(@SmsMsg) <= 160  
                            THEN 1  
                            WHEN @IsUnicode = 0  
                                    AND LEN(@SmsMsg) > 160  
                            THEN CEILING(LEN(@SmsMsg) / CAST(153 AS FLOAT))  
                            WHEN @IsUnicode = 1  
                                    AND LEN(@SmsMsg) <= 70  
                            THEN 1  
                            ELSE CEILING(LEN(@SmsMsg) / CAST(67 AS FLOAT))  
                        END);  
  
    -- Split the mobile numbers and insert into the temporary table      
    INSERT INTO #MobileNumbers  
    (CountryCode,MobileNo)  
    SELECT countrycode,MobileWithoutContryCode  
    FROM  
    (  
        SELECT ROW_NUMBER() OVER(PARTITION BY countrycode,MobileNo ORDER BY countrycode,MobileNo) AS sno,   
                countrycode,   
                STUFF(replace(MobileNo, '+', ''), CHARINDEX(replace(TRIM(countrycode), '+', ''), replace(MobileNo, '+', '')), LEN(replace(TRIM(countrycode), '+', '')), '') MobileWithoutContryCode  
        FROM m_country1(NOLOCK) INNER JOIN  
        (  
            SELECT value AS MobileNo  
            FROM STRING_SPLIT(@MobileNo, ',')  
        ) M   
		ON replace(LTRIM(RTRIM(countrycode)), '+', '') = LEFT(dbo.fn_trim0prefix(replace(replace(replace(MobileNo, '+', ''), '-', ''), ' ', '')), LEN(replace(LTRIM(RTRIM(countrycode)), '+', '')))  
    ) T  
    WHERE T.sno = 1;  
  
    -- Check if the user exists      
    IF EXISTS (SELECT 1 FROM user_detail WITH(NOLOCK) WHERE User_ID = @UserId)  
    BEGIN      
        -- Get the user's balance      
        SELECT @Balance = dbo.fn_GetMoneyBalance(@UserId);  
  
        IF EXISTS (SELECT * FROM Price_Base_SMS_Rate_Exception(NOLOCK) WHERE ParentID = @UserId)  
        BEGIN  
            UPDATE MN  
            SET MN.Cost = CAST(ISNULL(BR.PTrns, 0.00) * @NoOfUnit AS NUMERIC(18, 4))  
            FROM Price_Base_SMS_Rate_Exception(NOLOCK) BR RIGHT JOIN #MobileNumbers MN   
			ON BR.DestinationCountryCode = MN.CountryCode AND BR.ParentID = @UserId;  
        END;  
        ELSE  
        BEGIN  
            UPDATE MN  
            SET MN.Cost = CAST(ISNULL(BR.PTrns, 0.00) * @NoOfUnit AS NUMERIC(18, 4))  
            FROM Price_base_sms_rate(NOLOCK) BR RIGHT JOIN #MobileNumbers MN   
			ON BR.DestinationCountryCode = MN.CountryCode AND BR.IsEligible = 1;  
        END;  
  
        SELECT @TotalCost = SUM(Cost)  
        FROM #MobileNumbers;  
  
        PRINT concat('@Balance: ', @Balance);  
        PRINT concat('@TotalCost: ', @TotalCost);  
        PRINT concat('@TotalCost*1.5: ', @TotalCost * 1.5);  
        PRINT concat('Balance After this batch: ', @Balance - (@TotalCost * 1.5));  
  
        -- Check if the user has sufficient balance      
        IF((@Balance - (@TotalCost * 1.5)) > 0)  
        BEGIN  
            -- Check if the country is eligible for SMS service      
            IF @TotalCost > 0  
            BEGIN      
                -- Get SMS provider details      
                SELECT @SmsApiURI = API,   
                        @IntlSMSProviderId = id,   
                        @Key = [Key],   
                        @CountryCode = CountryCode  
                FROM tbl_intlSMSProvider WITH(NOLOCK)  
                WHERE IsActive = 1;  
  
  				Select @EntityName=EntityType, @TrackedUrl=TrackedUrl
				from Tbl_MassOperationSummary(nolock)
				Where	BatchID=@MassOpBatchId

				Select @TotalRecords=count(*)
				From  Tbl_MassOperationDetails(nolock) 
				Where SummaryId=@MassOpBatchId

				If(@TotalRecords<20)
				Begin
					Set @IsPriority=1
				End
				Else
				Begin
					Set @IsPriority=0
				End

  				If @EntityName='Lead'
				Begin
					UPDATE MN SET MN.EntityId = UL.ID, MN.EntityName = 'Lead'     
					FROM Tbl_MassOperationDetails(nolock) MODT inner join UserLeads(NOLOCK) UL
					ON	MODT.EntityID=UL.ID inner join #MobileNumbers MN  
					ON  MN.MobileNo in (UL.MobileNo, UL.MobileNo1, UL.MobileNo2) and MN.CountryCode in (UL.CountryCode, UL.CountryCode1, UL.CountryCode2)  
					Where	MODT.SummaryId=@MassOpBatchId

					Set @PageName='MassLeadIntlSms'
				End
				Else If @EntityName='Enquiry'
				Begin
					UPDATE MN SET MN.EntityId = UL.EnquiryID, MN.EntityName = 'Enquiry'     
					FROM Tbl_MassOperationDetails(nolock) MODT inner join UserEnquiry(NOLOCK) UL
					ON	MODT.EntityID=UL.EnquiryID inner join #MobileNumbers MN  
					ON  MN.MobileNo in (UL.MobileNo, UL.MobileNo1, UL.MobileNo2) and MN.CountryCode in (UL.CountryCode, UL.CountryCode1, UL.CountryCode2)  
					Where	MODT.SummaryId=@MassOpBatchId

					Set @PageName='MassEnquiryIntlSms'
				End

  
				If(CHARINDEX('#Lead.', @SmsMsg) > 0)  
				Begin  
				 SET @Placeholders = (SELECT dbo.ExtractPlaceholders('lead', @SmsMsg));  
				End  
				Else  
				Begin  
					SET @Placeholders = (SELECT dbo.ExtractPlaceholders('Enquiry', @SmsMsg));  
				End  
  
				IF (@Placeholders = '')    
				BEGIN    
				 SET @ispersonalised = 0;    
				END    
				ELSE    
				BEGIN    
				 SET @ispersonalised = 1;    
				END    
  
				select top 1 @Batchid=Batchid from Int_MessageDeliveryStatus(nolock) Where MassOpBatchId=@MassOpBatchId

				If(isnull(@Batchid,0)=0)
				Begin
					-- Begin transaction for batch ID  
					BEGIN TRAN  
					 INSERT INTO Getbatchrecord (user_id, randnum)  
					 VALUES (@UserId, @UserId);  
					 SET @Batchid = SCOPE_IDENTITY();  
					 DELETE FROM Getbatchrecord WHERE Batchid = @Batchid;  

					 insert into BatchInfo(UserID,BatchID,Operator,TotalRecords,ProcessTable,IsProcess,IsPrority,IsAllowDND,BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,IsUniCode,PageName,userfilter,TableName,InvalidCount,DbType,filterMode,bmessage,Totalprocessed,BatchProcessComplete,batchmonitordate,IsFlash,CreatedBy,sms_source,bsender_id,isbatchdeleted,BI_CreatedBy)
					 values
					 (@UserId,@Batchid,null,@TotalRecords,'0',1,@IsPriority,0,GETDATE(),GETDATE(),'','',@IsUnicode,@PageName,'PTrns','Int_MessageDeliveryStatus',0,0,null,@SmsMsg,@TotalRecords,null,null,0,@UserId,@PageName,@SenderId,0,@UserId)
					COMMIT;  
				End

                If(@UrlTrack=1 and isnull(@TrackedUrl,'') !='')
                Begin
                       declare @shorturl nvarchar(10)=null ,            
                        @longurl nvarchar(300)=@TrackedUrl,  --original destination url          
                        @page_nm nvarchar(50)=null,            
                        @IAction nvarchar(50)=null,            
                        @isvoice bit=null,            
                        @appid int,            
                        @duration int=null,            
                        @dnid nvarchar(20)=null,            
                        @frequency int=null,            
                        @latency int=null,            
                        @route nvarchar(20) =null      
  
  
                    set @shorturl=coalesce(@shorturl,'pel.im')            
                    set @page_nm=coalesce(@page_nm,'Send IntSMS Proc')            
                    set @IAction=coalesce(@IAction,'Original Url')            
       
                    insert into Link_smsUrl_dtl(BatchId,short_url,longurl,insertdate,status,Parentid,Page_nm,lAction,P_url,IsVoice,AppID,Duration,DNID,Frequency,Latency,Route)
                    select @Batchid,@shorturl,@longurl,GETDATE(),1,@ParentId,@page_nm,@IAction,@longurl,isnull(@isvoice,0),isnull(@appid,0),isnull(@duration,0),@dnid,@frequency,@latency,@route  
                End

  
				INSERT INTO Int_MessageDeliveryStatus (CountryCode, BatchID, Mobile, Message, SenderID, MessageStatus, MessageInsertDate, U_ID, IsUniCode, processed, SmsMode, MassOpBatchId, EntityId, EntityName, UrlTrack, Price, IsPersonalised, TrackedUrl)
				  Select CountryCode, BatchID=ISNULL(@Batchid, 0), MobileNo, Message=@SmsMsg, SenderID=@SenderId,MessageStatus=(CASE WHEN not(LEN(MobileNo) BETWEEN 5 AND 15 AND MobileNo NOT LIKE '%[^0-9+]%') THEN 'Invalid MobileNo' WHEN isnull(cost,0)=0 THEN 'NonDeliverable CountryCode' ELSE ''  END), MessageInsertDate=getdate(), U_ID=@UserId, IsUnicode=@IsUnicode, processed=0, SmsMode='singleTomulti', MassOpBatchId=@MassOpBatchId, EntityID, EntityName, UrlTrack=@UrlTrack, Cost, IsPersonalised=@ispersonalised, TrackedUrl=@TrackedUrl  
				From #MobileNumbers  
  
                -- Set success result      
                SET @Result = 'Success';  
                SET @IsValid = 1;  
                SET @Send = 'Alert';  
            END;  
            ELSE  
            BEGIN      
                -- Set failure result for ineligible country      
                SET @Result = 'We do not serve SMS to this country.';  
                SET @IsValid = 0;  
                SET @SmsApiURI = '';  
                SET @IntlSMSProviderId = '';  
                SET @Key = '';  
                SET @Send = '';  
                SET @CountryCode = '';  
            END;  
        END;  
        ELSE  
        BEGIN  
            -- Set failure result for insufficient balance      
            SET @Result = 'You have insufficient balance';  
            SET @IsValid = 0;  
            SET @SmsApiURI = '';  
            SET @IntlSMSProviderId = '';  
            SET @Key = '';  
            SET @Send = '';  
            SET @CountryCode = '';  
        END;  
	END;  
    ELSE  
    BEGIN      
        -- Set failure result for user not found      
        SET @Result = 'User not found';  
        SET @IsValid = 0;  
        SET @SmsApiURI = '';  
        SET @IntlSMSProviderId = '';  
        SET @Key = '';  
        SET @Send = '';  
        SET @CountryCode = '';  
    END;  
  
    -- Select the result      
    SELECT CAST(@Result AS NVARCHAR(200)) AS Result,   
            CAST(@IsValid AS BIT) AS IsValid,   
            CAST(@SmsApiURI AS NVARCHAR(200)) AS SmsApiURI,   
            CAST(@IntlSMSProviderId AS INT) AS IntlSMSProviderId,   
            CAST(@Key AS NVARCHAR(200)) AS Keys,   
            CAST(@Send AS NVARCHAR(200)) AS Sends,   
            CAST(@CountryCode AS NVARCHAR(200)) AS CountryCode;  
  
    -- Clean up temporary table      
    --DROP TABLE if exists #MobileNumbers;        
	END TRY                                  
	BEGIN CATCH              
		insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)
		SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()              
	END CATCH
END;  



GO

/* ============================================================
   Procedure: [dbo].[usp_SendLeadCustomFieldDuplicationMsg]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROC usp_SendLeadCustomFieldDuplicationMsg
As
Begin
	If (select  count(*)
		From (
		select ROW_NUMBER() over(partition by CFL.leadid, cfl.fieldID order by CFL.recordid desc) sno, CFL.*
		from customfieldLeadvalue(nolock) CFL 
		Where CFL.CreatedDate >= DATEADD(hour,-1, getdate())
		) A
		Where A.Sno > 1
		) > 0
	Begin
		declare @Msg varchar(1000) = ''
		set @Msg= ' A lead Custom field record insertion resulted in duplication. @RunTime: ' + cast (getdate() as nvarchar)

		Exec usp_SendMsgDbMail @MsgSubject='Lead Custom Field Insertion resulted in Duplication', @MsgBody=@Msg, @ToAddr='mayank.nigam@pelsoftlabs.in', @CcAddr='karuna@pelsoftlabs.in', @BccAddr='mukesh-kumar@pelsoftlabs.in'
	End
End



GO

/* ============================================================
   Procedure: [dbo].[usp_sendLowBalanceAlerts]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sendLowBalanceAlerts]
as
begin
select getdate() Date, [User_id],[UserLogin],AvgConsumption,Balance,Lowbalance into #smslowbalance 
from
(select d.User_id,d.UserLogin,avg(totalconsumption) AvgConsumption,dbo.fn_getsmsbalance(d.user_id) Balance,case when dbo.fn_getsmsbalance(d.user_id)<avg(totalconsumption)*7 then 1 else 0 end as LowBalance
 from dailyconsumption d join user_detail u (nolock) on u.user_id=d.user_id where u.m_id=10043--where dbo.fn_getsmsbalance(user_id)<avg(totalconsumption)*7
 group by d.User_id,d.UserLogin) A
 where LowBalance=1

 select getdate() date, [User_id],[UserLogin],AvgConsumption,Balance,Lowbalance into #maillowbalance from
(select d.User_id,d.UserLogin,avg(totalmailconsumption) AvgConsumption,dbo.fn_getmailbalance(d.user_id) Balance,case when dbo.fn_getmailbalance(d.user_id)<avg(totalmailconsumption)*7 then 1 else 0 end as LowBalance
 from dailymailconsumption d join user_detail (nolock) u on u.user_id=d.user_id where u.m_id=10043--where dbo.fn_getsmsbalance(user_id)<avg(totalconsumption)*7
 group by d.User_id,d.UserLogin) A
 where LowBalance=1

 select getdate() date, [User_id],[UserLogin],AvgConsumption,Balance,Lowbalance into #moneylowbalance from
(select d.User_id,d.UserLogin,avg(TotalMoneyConsumption) AvgConsumption,dbo.fn_GetMoneyBalance(d.user_id) Balance,case when dbo.fn_getmailbalance(d.user_id)<avg(TotalMoneyConsumption)*7 then 1 else 0 end as LowBalance
 from DailyMoneyConsumption d join user_detail (nolock) u on u.user_id=d.user_id where u.m_id=10043--where dbo.fn_getsmsbalance(user_id)<avg(totalconsumption)*7
 group by d.User_id,d.UserLogin) A
 where LowBalance=1



 select * from  #smslowbalance
 select * from  #maillowbalance
  --select * from  #moneylowbalance


 
end  


