/* ============================================================
   Procedure: [dbo].[usp_sendmailerrormail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROC [dbo].[usp_sendmailerrormail]-- 1-- 17626        
@errorid bigint        
as        
begin       
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX) declare @isevent nvarchar(20) =(select TableName from Mailerror where id=@errorid)        
--declare @lasteventmailexecution datetime,@lasteventsmsexecution datetime,@lastschedulemailexecution datetime,@lastschedulesmsexecution datetime      
--select @lasteventmailexecution= campaignexecuteddatetime from usercampaignexecution where isSMS=0 and isevent=1      
--select @lasteventsmsexecution= campaignexecuteddatetime from usercampaignexecution where isSMS=1 and isevent=1      
--select @lastschedulemailexecution= campaignexecuteddatetime from usercampaignexecution where isSMS=0 and isevent=0      
--select @lastschedulesmsexecution= campaignexecuteddatetime from usercampaignexecution where isSMS=1 and isevent=0      
      
select id,cast(cast(ErrorDate as DATE) as nvarchar) as ErrorDate,AffectedService,TableName,ErrorMessage into #temp from Mailerror where id=@errorid   
declare @lasteventmailexecution datetime= (select cast(cast(ErrorDate as DATE) as nvarchar) from #temp where ID=@errorid)     
declare @service nvarchar(20)= (select affectedservice from mailerror where ID=@errorid)      
SET @xml =CAST(( SELECT [ErrorDate] AS 'td','',[AffectedService] AS 'td','',[TableName] AS 'td','', ErrorMessage from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))        
SET @body ='<html><H1>Error in ' + @service +' at ' +cast (getdate() as nvarchar)+'</H1><body><table border = 2><tr><th>ErrorDate</th><th>AffectedService</th><th>TableName</th><th>ErrorMessage</th></tr>'         
SET @body = @body + @xml +'</table><p>'+ 'Mail sending failed at ' + cast(@lasteventmailexecution as nvarchar(20))  + '. '+      
--'Last Event sms execution at ' + cast(@lasteventsmsexecution as nvarchar(20))  +  '. '+      
--'Last Scheduled mail execution at ' + cast(@lastschedulemailexecution as nvarchar(20))  + '. '+      
--'Last Scheduled SMS execution at ' + cast(@lastschedulesmsexecution as nvarchar(20))  + '. ' else ' ' end 
 '</p></body></html>'        
declare @subject nvarchar(100) ='Mail sending failed from table ' + @isevent +' at '+cast (getdate() as nvarchar)      
      
EXEC usp_enqueueemail        
@profile_name='Alerts',         
@recipients='animesh@pelsoftlabs.in',        
@blind_copy_recipients='karuna@pelsoftlabs.in',        
@subject=@subject,        
@body = @body,        
@body_format ='HTML'        
drop table #temp        
end   
      



GO

/* ============================================================
   Procedure: [dbo].[usp_SendMailFromEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


  CREATE   PROCEDURE [dbo].[usp_SendMailFromEnquiry]                           
 @IDS VARCHAR(MAX),                          
 @Account BIGINT,                          
 @Email_Subject VARCHAR(1000),                          
 @Message VARCHAR(MAX),                          
 @SenderName VARCHAR(100),                          
 @ReplyTo VARCHAR(1000),                          
 @EmailId BIT ,                          
 @EmailId1 BIT ,                          
 @EmailId2 BIT   ,   
 @UserId bigint = 0                         
AS                          
BEGIN         
 --select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))          
DECLARE @MailCount BIGINT,@IsMonitor Bit = 1           
DECLARE @m_id BIGINT,@parentid bigint    
 SELECT @m_id= ud.M_ID,@parentid=parentid                            
                 FROM   User_Detail AS ud (nolock)                           
                 WHERE  ud.[User_ID] = @Account                      
 SELECT @MailCount = (select count(1) from dbo.fn_split(@IDS,'#'))                       
  DECLARE @CurrentBalance BIGINT = (                          
             SELECT TOP 1 mcd.Balance                          
             FROM   MailCreditDetails AS mcd   (nolock)                       
             WHERE  mcd.[User_ID] = @parentid                          
             ORDER BY mcd.Credit_ID DESC                          
         )                          
                           
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount                          
 IF @Balance > 0                          
 BEGIN                          
 SELECT A.EmailID,                          
        A.AccountID,                          
        A.SenderName,                          
        A.MailContent,                          
        A.MailSubject,                          
        A.ReplyTo,  
  A.EnquiryID INTO #tempTable                          
 FROM   (                          
            SELECT ISNULL(A.EmailID, '') AS EmailID,                          
                   @Account        AS AccountID,                          
                   @SenderName     AS SenderName,                          
                   A.MailContent,                          
                   @Email_Subject  AS MailSubject,                          
                   @ReplyTo        AS ReplyTo  ,   
       EnquiryID  
            FROM   (                          
                       SELECT CASE                           
                                   WHEN @EmailId = 1 THEN ul.EmailID                          
                                   ELSE ''                          
                              END AS EmailID,                          
                              --dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID)                
                               dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID)  AS                           
                              MailContent,   
        ul.EnquiryID  
                       FROM   UserEnquiry AS ul  (nolock)                        
                       WHERE  ul.EnquiryID IN (SELECT [value]                          
                       FROM   dbo.fn_Split(@IDS, '#') AS fs)            
                         ----Added By Siddharth ----            
                                     
                        AND ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') <> ''             
                      AND ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') not in             
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID             
                      from UserEnquiry UETemp (nolock) inner join Client_UnSubscribeDetails C_UDTemp  (nolock)          
                      on (UETemp.EmailID =C_UDTemp.Email)            
                                
                      where ul.EnquiryID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs))            
                                                                
                       UNION ALL                           
                            
                       SELECT CASE                           
                                   WHEN @EmailId1 = 1 THEN ul.EmailID1                          
                                   ELSE ''                          
                              END AS EmailID,                          
                             -- dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)                 
                             dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID1)                 
                              AS                           
                              MailContent ,    
         ul.EnquiryID  
                       FROM   UserEnquiry AS ul(nolock)                          
                       WHERE  ul.EnquiryID IN (SELECT [value]                          
                                        FROM   dbo.fn_Split(@IDS, '#') AS fs)            
                                          ----Added By Siddharth ----            
                                                    
                      AND ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') <> ''             
                      AND ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') not in             
                ( select ISNULL(C_UDTemp.Email,'') as EmailID             
                      from UserEnquiry UETemp (nolock) inner join Client_UnSubscribeDetails C_UDTemp  (nolock)          
                      on (UETemp.EmailID1 =C_UDTemp.Email)            
              
                      where ul.EnquiryID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))             
                                
                           
                                                                  
                       UNION ALL                          
                                                 
                       SELECT CASE                           
                                   WHEN @EmailId2 = 1 THEN ul.EmailID2                          
                                   ELSE ''                          
                              END AS EmailID,                          
                              --dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)                
                              dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID2)                
                              AS                           
                              MailContent  ,    
         ul.EnquiryID  
                       FROM   UserEnquiry AS ul  (nolock)                        
                       WHERE  ul.EnquiryID IN (SELECT [value]                          
                       FROM   dbo.fn_Split(@IDS, '#') AS fs)             
                         ----Added By Siddharth ----            
                                   
                       AND ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') <> ''             
                      AND ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') not in             
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID             
                      from UserEnquiry UETemp (nolock) inner join Client_UnSubscribeDetails C_UDTemp  (nolock)          
                      on (UETemp.EmailID2 =C_UDTemp.Email)            
                                
                      where ul.EnquiryID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))            
                                                    
                                                                 
                   )                  A                          
            WHERE  ISNULL(A.EmailID, '') <> ''                          
        ) A                          
                           
                           
                           
Declare @Status Bigint=0,@CountLimit bigint = 0                    
select @Status = status,@CountLimit = Plimit from ProcessMailLimit                  
                          
  if(@Status=1)                    
  Begin                    
Begin                   
  if(@MailCount > @CountLimit )                    
  Begin                    
   set @IsMonitor = 0                     
  End                    
 End                    
   End                    
                      
      
 DECLARE @BatchID BIGINT    
 begin tran                              
 INSERT INTO GetBatchRecord                          
       (                          
         [User_id],                          
         RandNum                          
       )             
     VALUES                          
       (                          
         @Account,                          
         @Account                          
       )                                
select @BatchID=SCOPE_IDENTITY()                               
DELETE                        
     FROM GetBatchRecord                          
     WHERE batchid=@BatchID    
 commit                              
                               
     DECLARE @Mail_FromEmail VARCHAR(500) = ''                            
    
select @Mail_FromEmail=coalesce((select top 1 mail_id from defaultmailid(nolock) where user_id=@account order by datecreated desc),    
(SELECT ud.EMail FROM   User_Detail AS ud  (nolock) WHERE  ud.[User_ID] = @Account),'contactus@email19.in')     
    
insert into CloneEmailsFilter(Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,    
Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source)    
select @Mail_FromEmail,A.EmailID,A.MailSubject,'',A.MailContent,GETDATE(),A.AccountID,@parentid,A.ReplyTo,@BatchID,1,'','','',A.MailContent,@ismonitor,0,@mailcount,'Enquiry-MassSend'    
from #tempTable A    
    
/*                           
     INSERT INTO BatchEmail_Infos                          
       (                          
         -- ID -- this column value is auto-generated                          
         BatchID,                          
         UserID,                          
         SenderName,                          
         [Message],                          
         TotalRecords,                          
         TotalProcessed,                          
         ProcessTable,                          
         IsProcess,                          
         Priority_Level,                          
         BatchInsertTime,                          
         BatchProcessTime,                          
         ScheduledDate,                          
         ScheduledTime,                          
         TemplateID,                          
         [Route],                          
         PageName,                          
         IsScheduled,                          
         Email_Subject,                          
         ReplyTo,                          
         Amount,                          
         Currency                          
       )                          
     SELECT @BatchID,                          
            A.AccountID,                          
            A.SenderName,                          
            @Message,                          
            COUNT(*),                          
            0,                          
            0,                          
            0,                          
            0,                          
            GETDATE(),                          
            NULL,                          
            NULL,                          
            NULL,                          
            NULL,                          
            NULL,                          
            NULL,                          
            0,                          
            A.MailSubject,                   
            A.ReplyTo,                          
            COUNT(*),                          
            'INR'                          
     FROM   #tempTable A                          
     GROUP BY                          
            A.AccountID,                          
            A.SenderName,                          
            A.MailSubject,                          
            A.ReplyTo                           
                         
     INSERT INTO ClientEmails                          
       (                          
         -- Id -- this column value is auto-generated                          
         GUID,                          
         Email_Id,                          
         SentDateTime,                          
         UserId,                          
         ReplyTo,                          
         [Status],                          
         BatchID,                          
         [Message]                          
       )                          
     SELECT NEWID(),                          
            A.EmailID,                          
            GETDATE(),                          
            A.AccountID,                          
            A.ReplyTo,                          
            '',                          
            @BatchID,                          
            A.MailContent                          
     FROM   #tempTable A                          
                               
     INSERT INTO EmailsFilter                          
       (                          
         Mail_GUID,                          
         -- Mail_ID -- this column value is auto-generated                          
         Mail_FromEmail,                          
         Mail_ToEmail,                          
         Mail_Subject,                          
         Mail_TempleteName,                          
         Messages,                          
         Mail_InsertedDate,                          
         Mail_UserID,                          
         ReplyTo,                          
         Mail_BatchID,                          
         Mail_Priority,                          
         Mail_ScheduleDate,                          
         Mail_Attechement,                          
         Mail_TempleteBody,                    
         IsMonitor                          
       )                          
     SELECT NEWID(),                          
            @Mail_FromEmail,                          
            A.EmailID,                          
            A.MailSubject,                          
            '',                          
            A.MailContent,                          
            GETDATE(),                          
            A.AccountID,                          
            A.ReplyTo,                          
            @BatchID,                          
            0,                          
            NULL,                          
            0,                          
            A.MailContent,                    
            @IsMonitor                          
     FROM   #tempTable A               
                   
                   
       update EmailsFilter set EmailsFilter.Mail_Priority=2              
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email              
                              
                               
     INSERT INTO MailCreditDetails                          
       (                          
         FromUser_ID,                          
         M_ID,                          
         USER_ID,                          
         Debits,                          
         Credits,                          
         Balance ,                      
         Validity                         
       )                          
     VALUES                          
       (                          
         @Account,                          
         @m_id,                      
         @Account,                          
         @MailCount,                          
         0,                          
         @Balance  ,                      
         99999                        
       )            
    */              
   
 if(@UserId  > 0 )    
  begin    
   declare  @Username nvarchar(255)  
   declare @leadActivityHistory AS LeadActivitywithid_Tbltype    
  
   select @Username = User_Login from User_Detail(nolock) where User_Id = @UserId  
    
   insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )    
    select     
  EnquiryId,    
  @UserId,     
  @parentid,    
  concat(@Username , '  sent mail with subject ', MailSubject , ' to emailid ', EmailID),    
  'Mail sent to Enquiry',    
  'Batchemail_infos',        
  @BatchID    
    from #tempTable    
   
  exec UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory    
 end  
  
     SELECT 'Success'                          
 END                          
 ELSE                          
 BEGIN                          
     SELECT 'Insufficient Balance'                          
 END                          
                           
 DROP TABLE #tempTable                          
END 





