			,Mail_ToEmail
			,Mail_Subject
			,Mail_TempleteName
			,Messages
			,Mail_InsertedDate
			,Mail_UserID
			,Mail_ParentID
			,ReplyTo
			,Mail_BatchID
			,Mail_Priority
			,Mail_ScheduleDate
			,Mail_ScheduledTime
			,Mail_Attechement
			,Mail_TempleteBody
			,IsMonitor
			,TemplateID
			,Count
			,Source
			)
		SELECT @Mail_FromEmail
			,A.EmailID
			,A.MailSubject
			,''
			,A.MailContent
			,GETDATE()
			,@UserId
			,@parentid
			,A.ReplyTo
			,@BatchID
			,1
			,''
			,''
			,''
			,A.MailContent
			,@ismonitor
			,0
			,@mailcount
			,'Enquiry-MassSend'
		FROM #tempTable A
		print concat('ailbatchid in sp :',@BatchID)
		--exec usp_ProcessMailBatch @BatchID
		/*                               
     INSERT INTO BatchEmail_Infos                              
       (                              
         -- ID -- this column value is auto-generated                              
         BatchID,                              
         UserID,                              
         SenderName,                              
         [Message],                              
         TotalRecords,                              
         TotalProcessed,                              
         ProcessTable,                              
         IsProcess,                              
         Priority_Level,                              
         BatchInsertTime,                              
         BatchProcessTime,                              
         ScheduledDate,                              
         ScheduledTime,                              
         TemplateID,                              
         [Route],                              
         PageName,                              
         IsScheduled,                              
         Email_Subject,                              
         ReplyTo,                              
        Amount,                              
         Currency                              
       )                              
     SELECT @BatchID,                              
            A.AccountID,                              
            A.SenderName,                              
            @Message,                              
            COUNT(*),                              
            0,                              
            0,                              
            0,                              
            0,                             
            GETDATE(),                              
            NULL,                              
            NULL,                              
            NULL,                              
            NULL,                              
            NULL,                              
            NULL,                              
            0,                              
            A.MailSubject,                       
            A.ReplyTo,                              
            COUNT(*),                              
            'INR'                              
     FROM   #tempTable A                              
     GROUP BY                              
            A.AccountID,                              
            A.SenderName,                              
            A.MailSubject,                              
            A.ReplyTo                               
                             
     INSERT INTO ClientEmails                              
       (                              
         -- Id -- this column value is auto-generated                              
         GUID,                              
         Email_Id,                              
         SentDateTime,                              
         UserId,                              
         ReplyTo,                              
         [Status],                              
         BatchID,                              
         [Message]                              
       )                              
     SELECT NEWID(),                              
            A.EmailID,                              
            GETDATE(),                              
            A.AccountID,                              
            A.ReplyTo,                              
            '',                              
            @BatchID,                              
            A.MailContent                              
     FROM   #tempTable A                              
                                   
     INSERT INTO EmailsFilter                              
       (                              
         Mail_GUID,                              
         -- Mail_ID -- this column value is auto-generated                              
         Mail_FromEmail,                              
         Mail_ToEmail,                              
         Mail_Subject,                              
         Mail_TempleteName,                              
         Messages,                              
         Mail_InsertedDate,                              
         Mail_UserID,                              
         ReplyTo,                              
         Mail_BatchID,                              
         Mail_Priority,                              
         Mail_ScheduleDate,                              
         Mail_Attechement,                              
         Mail_TempleteBody,                        
         IsMonitor                              
       )                              
     SELECT NEWID(),                              
            @Mail_FromEmail,                              
            A.EmailID,                              
            A.MailSubject,                              
            '',                              
            A.MailContent,                              
            GETDATE(),                              
            A.AccountID,                
            A.ReplyTo,                              
            @BatchID,                              
            0,                              
            NULL,                              
            0,                              
            A.MailContent,                        
            @IsMonitor                              
     FROM   #tempTable A                   
                       
                       
       update EmailsFilter set EmailsFilter.Mail_Priority=2                  
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                  
                                  
     
     INSERT INTO MailCreditDetails                              
       (                              
         FromUser_ID,                              
         M_ID,                              
         USER_ID,                              
         Debits,                              
         Credits,                              
         Balance ,                          
         Validity                             
       )                              
     VALUES                              
       (                              
         @Account,                              
         @m_id,                          
         @Account,                              
         @MailCount,                              
         0,                              
         @Balance  ,                          
         99999                            
       )                
    */
		print '2'
		IF (@UserId > 0)
		BEGIN
		print '3'
			DECLARE @Username NVARCHAR(255)
			DECLARE @leadActivityHistory AS LeadActivitywithid_Tbltype

			SELECT @Username = User_Login
			FROM User_Detail(NOLOCK)
			WHERE User_Id = @UserId

			INSERT INTO @leadActivityHistory (
