   ,Count    
   ,Source    
   ,EntityName
   ,EntityID
   ,IsMatched
   )    
  SELECT @Mail_FromEmail    
   ,A.EmailID    
   ,A.MailSubject    
   ,''    
   ,A.MailContent    
   ,GETDATE()    
   ,@UserId    
   ,@parentid    
   ,A.ReplyTo    
   ,@BatchID    
   ,1    
   ,''    
   ,''    
   ,''    
   ,A.MailContent    
   ,@ismonitor    
   ,0    
   ,@mailcount    
   ,'Enquiry-MassSend'    
   ,'Enquiry'
   ,EnquiryID
   ,0
  FROM #tempTable A    
    
  /*                                   
     INSERT INTO BatchEmail_Infos                                  
       (                                  
         -- ID -- this column value is auto-generated                                  
         BatchID,                                  
         UserID,                                  
         SenderName,                                  
         [Message],                                  
         TotalRecords,                                  
         TotalProcessed,                                  
