--,A.ReplyTo,'+cast(@BatchID as nvarchar)+',1,'''','''','''',A.MailContent,'+cast(@ismonitor as nvarchar)+',0,'+cast(@mailcount as nvarchar)+',''Enquiry-MassSend''              
--from #tempTable A '             

--exec sp_executesql @sql_st

-- end
 
 drop table if exists #clonetbl
 drop table if exists #TableData2  
/*                                     
     INSERT INTO BatchEmail_Infos                                    
       (                                    
         -- ID -- this column value is auto-generated                                    
         BatchID,                                    
