/* ============================================================
   Procedure: [dbo].[usp_SendMailFromEnquiry_WithTemplateID_FromMailID_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
    
CREATE   PROCEDURE [dbo].[usp_SendMailFromEnquiry_WithTemplateID_FromMailID_new] @IDS VARCHAR(MAX)      
 ,@Account BIGINT      
 ,@Email_Subject VARCHAR(1000)      
 ,@Message_TemplateID BIGINT      
 ,@SenderName VARCHAR(100)      
 ,@ReplyTo VARCHAR(1000)      
 ,@EmailId BIT      
 ,@EmailId1 BIT      
 ,@EmailId2 BIT      
 ,@UserId BIGINT = 0      
 ,@FromMailID VARCHAR(500)      
AS      
BEGIN      

     drop table if exists #CloneEmailsFilter  

 SELECT @Email_Subject = isnull(nullif(@Email_Subject, ''), (      
    SELECT mailsubject      
    FROM UserMailTemplate(NOLOCK)      
    WHERE id = @message_templateID      
    ))      
      
 DECLARE @MailCount BIGINT      
  ,@IsMonitor BIT = 1      
 DECLARE @m_id BIGINT      
  ,@parentid BIGINT      
      
 SELECT @m_id = ud.M_ID      
  ,@parentid = parentid      
 FROM User_Detail AS ud(NOLOCK)      
 WHERE ud.[User_ID] = @Account      
      
 SELECT @MailCount = (      
   SELECT count(1)      
   FROM dbo.fn_split(@IDS, '#')      
   )      
      
 DECLARE @CurrentBalance BIGINT = (      
   SELECT TOP 1 mcd.Balance      
   FROM MailCreditDetails AS mcd(NOLOCK)      
   WHERE mcd.[User_ID] = @parentid      
   ORDER BY mcd.Credit_ID DESC      
   )      
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount      
      
 IF @Balance > 0      
 BEGIN      
  DECLARE @Message VARCHAR(MAX)      
      
  SELECT @Message = MailContent      
  FROM UserMailTemplate(NOLOCK)      
  WHERE ID = @Message_TemplateID      
      
  SELECT A.EmailID      
   ,A.AccountID      
   ,A.SenderName      
   ,A.MailContent      
   ,A.MailSubject      
   ,A.ReplyTo      
   ,A.EnquiryId      
  INTO #tempTable      
  FROM (      
   SELECT ISNULL(A.EmailID, '') AS EmailID      
    ,@Account AS AccountID      
    ,@SenderName AS SenderName      
    ,A.MailContent      
    ,A.MailSubject      
    ,@ReplyTo AS ReplyTo      
    ,A.EnquiryId      
   FROM (      
    SELECT CASE       
      WHEN @EmailId = 1      
       THEN ul.EmailID      
      ELSE ''      
      END AS EmailID      
     ,      
     --dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID)                            
     dbo.[fn_getEnquiryMessageMail_new](ul.ParentID, @Message, ul.EmailID, ul.EnquiryID ) AS MailContent    
 ,dbo.[fn_getEnquiryMessageMail_new](ul.ParentID, @Email_Subject, ul.EmailID, ul.EnquiryID ) AS MailSubject    
     ,ul.EnquiryID      
    FROM UserEnquiry AS ul(NOLOCK)      
    WHERE ul.EnquiryID IN (      
      SELECT [value]      
      FROM dbo.fn_Split(@IDS, '#') AS fs      
      )      
     ----Added By Siddharth ----                      
     AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') <> ''      
     AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') NOT IN (      
      SELECT ISNULL(C_UDTemp.Email, '') AS EmailID      
      FROM UserEnquiry UETemp(NOLOCK)      
      INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID = C_UDTemp.Email)      
      WHERE ul.EnquiryID IN (      
        SELECT fs.value      
        FROM dbo.fn_Split(@IDS, '#') AS fs      
        )      
      )      
          
    UNION ALL      
          
    SELECT CASE       
      WHEN @EmailId1 = 1      
       THEN ul.EmailID1      
      ELSE ''      
      END AS EmailID      
     ,      
     -- dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)                             
     dbo.[fn_getEnquiryMessageMail_new](ul.ParentID, @Message, ul.EmailID1,ul.EnquiryID ) AS MailContent   
  ,dbo.[fn_getEnquiryMessageMail_new](ul.ParentID, @Email_Subject, ul.EmailID1, ul.EnquiryID ) AS MailSubject    
     ,ul.EnquiryID      
    FROM UserEnquiry AS ul(NOLOCK)      
    WHERE ul.EnquiryID IN (      
      SELECT [value]      
      FROM dbo.fn_Split(@IDS, '#') AS fs      
      )      
     ----Added By Siddharth ----                   
     AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') <> ''      
     AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') NOT IN (      
      SELECT ISNULL(C_UDTemp.Email, '') AS EmailID      
      FROM UserEnquiry UETemp(NOLOCK)      
     INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID1 = C_UDTemp.Email)      
      WHERE ul.EnquiryID IN (      
        SELECT fs.value      
        FROM dbo.fn_Split(@IDS, '#') AS fs      
        )      
      )      
          
    UNION ALL      
          
    SELECT CASE       
      WHEN @EmailId2 = 1      
       THEN ul.EmailID2      
      ELSE ''      
      END AS EmailID      
     ,      
     --dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)                            
      dbo.[fn_getEnquiryMessageMail_new](ul.ParentID, @Message, ul.EmailID2,ul.EnquiryID) AS MailContent   
  ,dbo.[fn_getEnquiryMessageMail_new](ul.ParentID, @Email_Subject, ul.EmailID2, ul.EnquiryID ) AS MailSubject   
     ,ul.EnquiryID      
    FROM UserEnquiry AS ul(NOLOCK)      
    WHERE ul.EnquiryID IN (      
      SELECT [value]      
      FROM dbo.fn_Split(@IDS, '#') AS fs      
      )      
     ----Added By Siddharth ----                      
     AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') <> ''      
     AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') NOT IN (      
      SELECT ISNULL(C_UDTemp.Email, '') AS EmailID      
      FROM UserEnquiry UETemp(NOLOCK)      
      INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID2 = C_UDTemp.Email)      
      WHERE ul.EnquiryID IN (      
        SELECT fs.value      
        FROM dbo.fn_Split(@IDS, '#') AS fs      
        )      
      )      
    ) A      
   WHERE ISNULL(A.EmailID, '') <> ''      
   ) A      
      
  DECLARE @Status BIGINT = 0      
   ,@CountLimit BIGINT = 0      
      
  SELECT @Status = STATUS      
   ,@CountLimit = Plimit      
  FROM ProcessMailLimit      
      
  IF (@Status = 1)      
  BEGIN      
   BEGIN      
    IF (@MailCount > @CountLimit)      
    BEGIN      
     SET @IsMonitor = 0      
    END      
   END      
  END      
      
  DECLARE @BatchID BIGINT      
      
  BEGIN TRAN      
      
  INSERT INTO GetBatchRecord (      
   [User_id]      
   ,RandNum      
   )      
  VALUES (      
   @Account      
   ,@Account      
   )      
      
  SELECT @BatchID = SCOPE_IDENTITY()      
      
  DELETE      
  FROM GetBatchRecord      
  WHERE batchid = @BatchID      
      
  COMMIT      
      
  DECLARE @Mail_FromEmail VARCHAR(500) = ''      
      
  SELECT @Mail_FromEmail = coalesce((      
     SELECT TOP 1 mail_id      
     FROM defaultmailid(NOLOCK)      
     WHERE user_id = @account      
     ORDER BY datecreated DESC      
     ), (      
     SELECT ud.EMail      
     FROM User_Detail AS ud(NOLOCK)      
     WHERE ud.[User_ID] = @Account      
     ), 'contactus@email19.in')      
      
  IF (rtrim(ltrim(@FromMailID)) <> '')      
  BEGIN      
   SET @Mail_FromEmail = @FromMailID      
  END      
      
  INSERT INTO CloneEmailsFilter (      
   Mail_FromEmail      
   ,Mail_ToEmail      
   ,Mail_Subject      
   ,Mail_TempleteName      
   ,Messages      
   ,Mail_InsertedDate      
   ,Mail_UserID      
   ,Mail_ParentID      
   ,ReplyTo      
   ,Mail_BatchID      
   ,Mail_Priority      
   ,Mail_ScheduleDate      
   ,Mail_ScheduledTime      
   ,Mail_Attechement      
   ,Mail_TempleteBody      
   ,IsMonitor      
   ,TemplateID      
   ,Count      
   ,Source      
   )      
  SELECT @Mail_FromEmail      
   ,A.EmailID      
   ,A.MailSubject      
   ,''      
   ,A.MailContent      
   ,GETDATE()      
   ,@UserId      
   ,@parentid      
   ,A.ReplyTo      
   ,@BatchID      
   ,1      
   ,''      
   ,''      
   ,''      
   ,A.MailContent      
   ,@ismonitor      
   ,0      
   ,@mailcount      
   ,'Enquiry-SingleSend'      
  FROM #tempTable A      
      
  /*                                          
     INSERT INTO BatchEmail_Infos                                      
       (                                      
         -- ID -- this column value is auto-generated                                      
         BatchID,                                      
         UserID,                                      
         SenderName,                          
         [Message],                                      
         TotalRecords,                                      
         TotalProcessed,                                      
         ProcessTable,                                      
         IsProcess,                                      
         Priority_Level,                                      
         BatchInsertTime,                            
         BatchProcessTime,                                      
         ScheduledDate,                                      
         ScheduledTime,                                      
         TemplateID,                                      
         [Route],                                      
         PageName,                                      
         IsScheduled,                                      
         Email_Subject,                                      
         ReplyTo,                                      
         Amount,                              
         Currency                                      
       )                                      
     SELECT @BatchID,                                      
            A.AccountID,                                      
            A.SenderName,                                      
            @Message,                                      
            COUNT(*),                                      
            0,                
            0,                                      
            0,                              
            0,                                      
            GETDATE(),                                      
            NULL,                                      
            NULL,                                      
            NULL,                                      
            NULL,                                      
            NULL,                                      
            NULL,                                      
            0,                                 
            A.MailSubject,                                      
            A.ReplyTo,                                      
       COUNT(*),                                      
            'INR'                                      
     FROM   #tempTable A                                      
     GROUP BY                                      
            A.AccountID,                                      
            A.SenderName,                                      
            A.MailSubject,                                      
            A.ReplyTo                                       
                                           
     INSERT INTO ClientEmails                                      
       (                                      
        -- Id -- this column value is auto-generated                                      
         GUID,                                      
         Email_Id,                                      
         SentDateTime,                                      
         UserId,                                      
         ReplyTo,                                      
         [Status],                                      
         BatchID,                                      
         [Message]                                      
       )                                      
     SELECT NEWID(),                             
            A.EmailID,                                      
            GETDATE(),                                      
            A.AccountID,                                      
            A.ReplyTo,                                      
            '',                                      
            @BatchID,                                      
            A.MailContent                                      
     FROM   #tempTable A                                      
                                           
     INSERT INTO EmailsFilter                                      
      (                          
         Mail_GUID,                                      
         -- Mail_ID -- this column value is auto-generated                                      
         Mail_FromEmail,                                      
         Mail_ToEmail,                                      
         Mail_Subject,                                      
         Mail_TempleteName,                                      
         Messages,                                      
         Mail_InsertedDate,                            
         Mail_UserID,                                      
         ReplyTo,                                      
         Mail_BatchID,                                      
         Mail_Priority,                                      
         Mail_ScheduleDate,                                      
         Mail_Attechement,                                      
         Mail_TempleteBody,                                
         IsMonitor                    
       )                                      
     SELECT NEWID(),                                      
            @Mail_FromEmail,                                      
            A.EmailID,                                      
            A.MailSubject,                                      
            '',                                      
            A.MailContent,                                      
            GETDATE(),                                      
            A.AccountID,                                      
            A.ReplyTo,                                      
     @BatchID,                                      
            0,                                      
            NULL,                                      
            0,                    
            A.MailContent,                                
            @IsMonitor                                      
     FROM   #tempTable A                        
                             
       update EmailsFilter set EmailsFilter.Mail_Priority=2                        
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                                      
                                         
     INSERT INTO MailCreditDetails                                      
       (                                      
         FromUser_ID,                                      
         M_ID,                                      
         USER_ID,                                      
         Debits,                                      
         Credits,                                      
         Balance ,                                  
         Validity                                     
       )                                      
     VALUES                                      
       (                                      
         @Account,                                      
         @m_id,                                      
         @Account,                                      
         @MailCount,                                      
         0,                                      
         @Balance  ,                                  
         99999                                    
       )                      
    */      
  IF (@UserId > 0)      
  BEGIN      
   DECLARE @Username NVARCHAR(255)      
   DECLARE @leadActivityHistory AS LeadActivitywithid_Tbltype      
      
   SELECT @Username = User_Login      
   FROM User_Detail(NOLOCK)      
   WHERE User_Id = @UserId      
      
   INSERT INTO @leadActivityHistory (      
    LeadID      
    ,UserID      
    ,ParentID      
    ,EventDescription      
    ,EventName      
    ,RefTable      
    ,refid      
    )      
   SELECT EnquiryId      
    ,@UserId      
    ,@parentid      
    ,CONCAT (      
     @Username      
     ,'  sent mail with subject '      
     ,MailSubject      
     ,' to emailid '      
     ,EmailID      
     )      
    ,'Mail sent to Enquiry'      
    ,'Batchemail_infos'      
    ,@BatchID      
   FROM #tempTable      
      
   EXEC UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory      
  END      
      
  SELECT 'Success'      
 END      
 ELSE      
 BEGIN      
  SELECT 'Insufficient Balance'      
 END      
      
 DROP TABLE #tempTable      
      
 DECLARE @rowJson NVARCHAR(MAX) = (    
   SELECT *    
   FROM CloneEmailsFilter WITH(NOLOCK)    
   WHERE Mail_BatchID = @BatchID    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
IF @rowJson is not null    
 begin    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
  ,@Activity_type = 'Inst_Mail_enqry'    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'CloneEmailsFilter'    
 END    
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_SendMailFromEnquiry_WithTemplateID_FromMailID_ViaOtherDB]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SendMailFromEnquiry_WithTemplateID_FromMailID_ViaOtherDB]
     @IDS VARCHAR(MAX)
	,@Account BIGINT
	,@Email_Subject VARCHAR(1000)
	,@Message_TemplateID BIGINT
	,@SenderName VARCHAR(100)
	,@ReplyTo VARCHAR(1000)
	,@EmailId BIT
	,@EmailId1 BIT
	,@EmailId2 BIT
	,@UserId BIGINT = 0
	,@FromMailID VARCHAR(500)
AS
BEGIN
	SELECT @Email_Subject = isnull(nullif(@Email_Subject, ''), (
				SELECT mailsubject
				FROM UserMailTemplate(NOLOCK)
				WHERE id = @message_templateID
				))

	DECLARE @MailCount BIGINT
		,@IsMonitor BIT = 1
	DECLARE @m_id BIGINT
		,@parentid BIGINT

	SELECT @m_id = ud.M_ID
		,@parentid = parentid
	FROM User_Detail AS ud(NOLOCK)
	WHERE ud.[User_ID] = @Account

	SELECT @MailCount = (
			SELECT count(1)
			FROM dbo.fn_split(@IDS, '#')
			)

	DECLARE @CurrentBalance BIGINT = (
			SELECT TOP 1 mcd.Balance
			FROM MailCreditDetails AS mcd(NOLOCK)
			WHERE mcd.[User_ID] = @parentid
			ORDER BY mcd.Credit_ID DESC
			)
	DECLARE @Balance BIGINT = @CurrentBalance - @MailCount

	IF @Balance > 0
	BEGIN
		DECLARE @Message VARCHAR(MAX)

		SELECT @Message = MailContent
		FROM UserMailTemplate(NOLOCK)
		WHERE ID = @Message_TemplateID

		SELECT A.EmailID
			,A.AccountID
			,A.SenderName
			,A.MailContent
			,A.MailSubject
			,A.ReplyTo
			,A.EnquiryId
		INTO #tempTable
		FROM (
			SELECT ISNULL(A.EmailID, '') AS EmailID
				,@Account AS AccountID
				,@SenderName AS SenderName
				,A.MailContent
				,@Email_Subject AS MailSubject
				,@ReplyTo AS ReplyTo
				,A.EnquiryId
			FROM (
				SELECT CASE 
						WHEN @EmailId = 1
							THEN ul.EmailID
						ELSE ''
						END AS EmailID
					,
					--dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID)                      
					dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID) AS MailContent
					,ul.EnquiryID
				FROM UserEnquiry AS ul(NOLOCK)
				WHERE ul.EnquiryID IN (
						SELECT [value]
						FROM dbo.fn_Split(@IDS, '#') AS fs
						)
					----Added By Siddharth ----                
					AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') <> ''
					AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') NOT IN (
						SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
						FROM UserEnquiry UETemp(NOLOCK)
						INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID = C_UDTemp.Email)
						WHERE ul.EnquiryID IN (
								SELECT fs.value
								FROM dbo.fn_Split(@IDS, '#') AS fs
								)
						)
				
				UNION ALL
				
				SELECT CASE 
						WHEN @EmailId1 = 1
							THEN ul.EmailID1
						ELSE ''
						END AS EmailID
					,
					-- dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)                       
					dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID1) AS MailContent
					,ul.EnquiryID
				FROM UserEnquiry AS ul(NOLOCK)
				WHERE ul.EnquiryID IN (
						SELECT [value]
						FROM dbo.fn_Split(@IDS, '#') AS fs
						)
					----Added By Siddharth ----             
					AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') <> ''
					AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') NOT IN (
						SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
						FROM UserEnquiry UETemp(NOLOCK)
						INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID1 = C_UDTemp.Email)
						WHERE ul.EnquiryID IN (
								SELECT fs.value
								FROM dbo.fn_Split(@IDS, '#') AS fs
								)
						)
				
				UNION ALL
				
				SELECT CASE 
						WHEN @EmailId2 = 1
							THEN ul.EmailID2
						ELSE ''
						END AS EmailID
					,
					--dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)                      
					dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID2) AS MailContent
					,ul.EnquiryID
				FROM UserEnquiry AS ul(NOLOCK)
				WHERE ul.EnquiryID IN (
						SELECT [value]
						FROM dbo.fn_Split(@IDS, '#') AS fs
						)
					----Added By Siddharth ----                
					AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') <> ''
					AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') NOT IN (
						SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
						FROM UserEnquiry UETemp(NOLOCK)
						INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID2 = C_UDTemp.Email)
						WHERE ul.EnquiryID IN (
								SELECT fs.value
								FROM dbo.fn_Split(@IDS, '#') AS fs
								)
						)
				) A
			WHERE ISNULL(A.EmailID, '') <> ''
			) A

		DECLARE @Status BIGINT = 0
			,@CountLimit BIGINT = 0

		SELECT @Status = STATUS
			,@CountLimit = Plimit
		FROM ProcessMailLimit

		IF (@Status = 1)
		BEGIN
			BEGIN
				IF (@MailCount > @CountLimit)
				BEGIN
					SET @IsMonitor = 0
				END
			END
		END

		DECLARE @BatchID BIGINT

		BEGIN TRAN

		INSERT INTO GetBatchRecord (
			[User_id]
			,RandNum
			)
		VALUES (
			@Account
			,@Account
			)

		SELECT @BatchID = SCOPE_IDENTITY()

		DELETE
		FROM GetBatchRecord
		WHERE batchid = @BatchID

		COMMIT

		DECLARE @Mail_FromEmail VARCHAR(500) = ''

		SELECT @Mail_FromEmail = coalesce((
					SELECT TOP 1 mail_id
					FROM defaultmailid(NOLOCK)
					WHERE user_id = @account
					ORDER BY datecreated DESC
					), (
					SELECT ud.EMail
					FROM User_Detail AS ud(NOLOCK)
					WHERE ud.[User_ID] = @Account
					), 'contactus@email19.in')

		IF (rtrim(ltrim(@FromMailID)) <> '')
		BEGIN
			SET @Mail_FromEmail = @FromMailID
		END

  	  INSERT INTO BatchEmail_Infos                                  
        (                                  
         -- ID -- this column value is auto-generated                                  
         BatchID,                                  
         UserID,                                  
         SenderName,                                  
         [Message],                                  
         TotalRecords,                                  
         TotalProcessed,                                  
         ProcessTable,                                  
         IsProcess,                                  
         Priority_Level,                                  
         BatchInsertTime,                                  
         BatchProcessTime,                                  
         ScheduledDate,                                  
         ScheduledTime,                                  
         TemplateID,                                  
         [Route],                                  
         PageName,                                  
         IsScheduled,                                  
         Email_Subject,                                  
         ReplyTo,                                  
        Amount,                                  
         Currency                                  
       )                                  
     SELECT @BatchID,                                  
            A.AccountID,                                  
            --A.SenderName,                                  
            @Mail_FromEmail,
			@Message,                                  
            COUNT(*),                                  
            0,                                  
            0,                                  
            0,                                  
            0,                                 
            GETDATE(),                                  
            NULL,                                  
            NULL,             
            NULL,                                  
            NULL,                                  
            NULL,                                  
            NULL,                                  
            0,                                  
            A.MailSubject,                           
            A.ReplyTo,                                  
            COUNT(*),                                  
            'INR'                                  
     FROM   #tempTable A                                  
     GROUP BY                                  
            A.AccountID,                                  
            --A.SenderName,                                  
            A.MailSubject,                                  
            A.ReplyTo

    INSERT INTO MailCreditDetails                                  
       (                                  
         FromUser_ID,                                  
         M_ID,                                  
         USER_ID,                                  
         Debits,                                  
         Credits,                                  
         Balance ,                              
         Validity                                 
       )                                  
     VALUES                                  
       (                                  
         @Account,                                  
         @m_id,                              
         @Account,                                  
         @MailCount,                                  
         0,                                  
         @Balance  ,                              
         99999                                
       )

	  INSERT INTO [10.0.0.135].[MysmsTrans].[dbo].CloneEmailsFilter (
			Mail_FromEmail
			,Mail_ToEmail
			,Mail_Subject
			,Mail_TempleteName
			,Messages
			,Mail_InsertedDate
			,Mail_UserID
			,Mail_ParentID
			,ReplyTo
			,Mail_BatchID
			,Mail_Priority
			,Mail_ScheduleDate
			,Mail_ScheduledTime
			,Mail_Attechement
			,Mail_TempleteBody
			,IsMonitor
			,TemplateID
			,Count
			,Source
			,EntityName
            ,EntityID
            ,IsMatched
			)
		SELECT @Mail_FromEmail
			,A.EmailID
			,A.MailSubject
			,''
			,A.MailContent
			,GETDATE()
			,@UserId
			,@parentid
			,A.ReplyTo
			,@BatchID
			,1
			,''
			,''
			,''
			,A.MailContent
			,@ismonitor
			,0
			,@mailcount
			,'Enquiry-MassSend'
			,'Enquiry'
		    ,EnquiryID
		    ,0
		FROM #tempTable A

		/*                                    
     INSERT INTO BatchEmail_Infos                                
       (                                
         -- ID -- this column value is auto-generated                                
         BatchID,                                
         UserID,                                
         SenderName,                                
         [Message],                                
         TotalRecords,                                
         TotalProcessed,                                
         ProcessTable,                                
         IsProcess,                                
         Priority_Level,                                
         BatchInsertTime,                      
         BatchProcessTime,                                
         ScheduledDate,                                
         ScheduledTime,                                
         TemplateID,                                
         [Route],                                
         PageName,                                
         IsScheduled,                                
         Email_Subject,                                
         ReplyTo,                                
         Amount,                        
         Currency                                
       )                                
     SELECT @BatchID,                                
            A.AccountID,                                
            A.SenderName,                                
            @Message,                                
            COUNT(*),                                
            0,          
            0,                                
            0,                                
            0,                                
            GETDATE(),                                
            NULL,                                
            NULL,                                
            NULL,                                
            NULL,                                
            NULL,                                
            NULL,                                
            0,                           
            A.MailSubject,                                
            A.ReplyTo,                                
       COUNT(*),                                
            'INR'                                
     FROM   #tempTable A                                
     GROUP BY                                
            A.AccountID,                                
            A.SenderName,                                
            A.MailSubject,                                
            A.ReplyTo                                 
                                     
     INSERT INTO ClientEmails                                
       (                                
        -- Id -- this column value is auto-generated                                
         GUID,                                
         Email_Id,                                
         SentDateTime,                                
         UserId,                                
         ReplyTo,                                
         [Status],                                
         BatchID,                                
         [Message]                                
       )                                
     SELECT NEWID(),                       
            A.EmailID,                                
            GETDATE(),                                
            A.AccountID,                                
            A.ReplyTo,                                
            '',                                
            @BatchID,                                
            A.MailContent                                
     FROM   #tempTable A                                
                                     
     INSERT INTO EmailsFilter                                
       (                    
         Mail_GUID,                                
         -- Mail_ID -- this column value is auto-generated                                
         Mail_FromEmail,                                
         Mail_ToEmail,                                
         Mail_Subject,                                
         Mail_TempleteName,                                
         Messages,                                
         Mail_InsertedDate,                      
         Mail_UserID,                                
         ReplyTo,                                
         Mail_BatchID,                                
         Mail_Priority,                                
         Mail_ScheduleDate,                                
         Mail_Attechement,                                
         Mail_TempleteBody,                          
         IsMonitor                                
       )                                
     SELECT NEWID(),                                
            @Mail_FromEmail,                                
            A.EmailID,                                
            A.MailSubject,                                
            '',                                
            A.MailContent,                                
            GETDATE(),                                
            A.AccountID,                                
            A.ReplyTo,                                
     @BatchID,                                
            0,                                
            NULL,                                
            0,                                
            A.MailContent,                          
            @IsMonitor                                
     FROM   #tempTable A                  
                       
       update EmailsFilter set EmailsFilter.Mail_Priority=2                  
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                                
                                   
     INSERT INTO MailCreditDetails                                
       (                                
         FromUser_ID,                                
         M_ID,                                
         USER_ID,                                
         Debits,                                
         Credits,                                
         Balance ,                            
         Validity                               
       )                                
     VALUES                                
       (                                
         @Account,                                
         @m_id,                                
         @Account,                                
         @MailCount,                                
         0,                                
         @Balance  ,                            
         99999                              
       )                
    */
		IF (@UserId > 0)
		BEGIN
			DECLARE @Username NVARCHAR(255)
			DECLARE @leadActivityHistory AS LeadActivitywithid_Tbltype

			SELECT @Username = User_Login
			FROM User_Detail(NOLOCK)
			WHERE User_Id = @UserId

			INSERT INTO @leadActivityHistory (
				LeadID
				,UserID
				,ParentID
				,EventDescription
				,EventName
				,RefTable
				,refid
				)
			SELECT EnquiryId
				,@UserId
				,@parentid
				,CONCAT (
					@Username
					,'  sent mail with subject '
					,MailSubject
					,' to emailid '
					,EmailID
					)
				,'Mail sent to Enquiry'
				,'Batchemail_infos'
				,@BatchID
			FROM #tempTable

			EXEC UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory
		END

		SELECT 'Success'
	END
	ELSE
	BEGIN
		SELECT 'Insufficient Balance'
	END

	DROP TABLE #tempTable

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM [10.0.0.135].[MysmsTrans].[dbo].CloneEmailsFilter WITH(NOLOCK)
			WHERE Mail_BatchID = @BatchID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'Inst_Mail_enqry'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'CloneEmailsFilter'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_SendMailFromEnquiry_WithTemplateID_Shaired]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_SendMailFromEnquiry_WithTemplateID_Shaired                     
 @IDS VARCHAR(MAX),                    
 @Account BIGINT,                    
 @Email_Subject VARCHAR(1000),                    
 @Message_TemplateID Bigint,                    
 @SenderName VARCHAR(100),                    
 @ReplyTo VARCHAR(1000),                    
 @EmailId BIT ,                    
 @EmailId1 BIT ,                    
 @EmailId2 BIT                    
AS                    
BEGIN         
           
 Declare @Message VARCHAR(MAX)         
        
  select @Message = MailContent  From UserMailTemplate where ID= @Message_TemplateID        
                    
                   
 SELECT A.EmailID,                    
        A.AccountID,                    
        A.SenderName,                    
        A.MailContent,                    
        A.MailSubject,                    
        A.ReplyTo INTO #tempTable                    
 FROM   (                    
            SELECT ISNULL(A.EmailID, '') AS EmailID,                    
                   @Account        AS AccountID,                    
                   @SenderName     AS SenderName,                    
                   A.MailContent,                    
                   @Email_Subject  AS MailSubject,                    
                   @ReplyTo        AS ReplyTo                    
            FROM   (                    
                       SELECT CASE                     
                                   WHEN @EmailId = 1 THEN ul.EmailID                    
                                   ELSE ''                    
                              END AS EmailID,                    
                              --dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID)          
                               dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID)  AS                     
                              MailContent                    
                       FROM   UserEnquiry AS ul                    
                       WHERE  ul.EnquiryID IN (SELECT [value]                    
                                        FROM   dbo.fn_Split(@IDS, '#') AS fs)     
                                            
                                          ----Added By Siddharth ----    
                                             
                       AND ISNULL(NULLIF(CAST(ul.EmailID as bigint), ''), '') <> ''     
                      AND ISNULL(NULLIF(CAST(ul.EmailID as bigint), ''), '') not in     
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID     
                      from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp    
                      on (UETemp.EmailID =C_UDTemp.Email)    
                        
                      where ul.EnquiryID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))                  
                       UNION ALL                     
                                           
                       SELECT CASE                     
                                   WHEN @EmailId1 = 1 THEN ul.EmailID1                    
                                   ELSE ''                    
                              END AS EmailID,                    
                             -- dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)           
                             dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID1)           
                              AS                     
                              MailContent                   
                       FROM   UserEnquiry AS ul                    
                       WHERE  ul.EnquiryID IN (SELECT [value]                    
                       FROM   dbo.fn_Split(@IDS, '#') AS fs)    
                           
                       ----Added By Siddharth ----    
                           
                     AND ISNULL(NULLIF(CAST(ul.EmailID1 as bigint), ''), '') <> ''     
       AND ISNULL(NULLIF(CAST(ul.EmailID1 as bigint), ''), '') not in     
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID     
                      from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp    
                      on (UETemp.EmailID1 =C_UDTemp.Email)    
                        
                      where ul.EnquiryID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))                     
                       UNION ALL                    
                                           
                       SELECT CASE                     
                                   WHEN @EmailId2 = 1 THEN ul.EmailID2                    
                                   ELSE ''                    
                              END AS EmailID,                    
                              --dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)          
                              dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID2)          
                              AS                     
                              MailContent                    
                       FROM   UserEnquiry AS ul                    
                       WHERE  ul.EnquiryID IN (SELECT [value]                    
                       FROM   dbo.fn_Split(@IDS, '#') AS fs)    
                           
                         ----Added By Siddharth ----    
                           
                       AND ISNULL(NULLIF(CAST(ul.EmailID2 as bigint), ''), '') <> ''     
                      AND ISNULL(NULLIF(CAST(ul.EmailID2 as bigint), ''), '') not in     
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID     
                      from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp    
                      on (UETemp.EmailID2 =C_UDTemp.Email)    
                        
                      where ul.EnquiryID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))     
                          
                                         
                   )                  A                    
            WHERE  ISNULL(A.EmailID, '') <> ''                    
        ) A                    
                     
 DECLARE @MailCount BIGINT,@IsMonitor Bit = 1                    
 SELECT @MailCount = COUNT(*)                    
 FROM   #tempTable                    
                     
                     
Declare @Status Bigint=0,@CountLimit bigint = 0              
select @Status = status,@CountLimit = Plimit from ProcessMailLimit            
                    
  if(@Status=1)              
  Begin              
Begin              
  if(@MailCount > @CountLimit )              
  Begin              
   set @IsMonitor = 0               
  End              
 End              
   End              
                
 DECLARE @CurrentBalance BIGINT = (                    
             SELECT TOP 1 mcd.Balance                    
             FROM   MailCreditDetails AS mcd                    
             WHERE  mcd.[User_ID] = @Account                    
             ORDER BY                    
                    mcd.Credit_ID DESC                    
         )                    
                     
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount                    
 IF @Balance > 0                    
 BEGIN                    
     DECLARE @m_id BIGINT = (                    
                 SELECT TOP 1 ud.M_ID                    
                 FROM   User_Detail AS ud                    
                 WHERE  ud.[User_ID] = @Account                    
             )                    
                         
 INSERT INTO GetBatchRecord                    
       (                    
         [User_id],                    
         RandNum                    
       )                  
     VALUES                    
       (                    
         @Account,                    
         @Account                    
       )                          
             
     DECLARE @BatchID BIGINT = (                    
                 SELECT MAX(gbr.BatchID)                    
                 FROM   GetBatchRecord AS gbr               
                 WHERE  gbr.[User_id] = @Account                    
             )                        
                         
     DELETE                     
     FROM   GetBatchRecord                    
     WHERE  [User_id] = @Account                       
                         
                         
                         
     DECLARE @Mail_FromEmail VARCHAR(500) = ''                      
                     
     SELECT @Mail_FromEmail = ud.EMail                    
     FROM   User_Detail          AS ud                    
            LEFT JOIN User_Type  AS ut(NOLOCK)                    
                 ON  ud.UserType = ut.ID                    
     WHERE  ud.[User_ID] = @Account                     
                         
     INSERT INTO BatchEmail_Infos                    
       (                    
         -- ID -- this column value is auto-generated                    
         BatchID,                    
         UserID,                    
         SenderName,                    
         [Message],                    
         TotalRecords,                    
         TotalProcessed,                    
         ProcessTable,                    
         IsProcess,                    
         Priority_Level,                    
         BatchInsertTime,                    
         BatchProcessTime,                    
         ScheduledDate,                    
         ScheduledTime,                    
         TemplateID,                    
         [Route],                    
         PageName,                    
         IsScheduled,                    
         Email_Subject,                    
         ReplyTo,                    
         Amount,                    
         Currency                    
       )                    
     SELECT @BatchID,                    
            A.AccountID,                    
            A.SenderName,                    
            @Message,                    
            COUNT(*),                    
            0,                    
            0,                    
            0,                    
            0,                    
            GETDATE(),                    
            NULL,                    
            NULL,                    
            NULL,                    
            NULL,                    
            NULL,                    
            NULL,                    
            0,                    
            A.MailSubject,                    
            A.ReplyTo,                    
       COUNT(*),                    
            'INR'                    
     FROM   #tempTable A                    
     GROUP BY                    
            A.AccountID,                    
            A.SenderName,                    
            A.MailSubject,                    
            A.ReplyTo                     
                         
     INSERT INTO ClientEmails                    
       (                    
        -- Id -- this column value is auto-generated                    
         GUID,                    
         Email_Id,                    
         SentDateTime,                    
         UserId,                    
         ReplyTo,                    
         [Status],                    
         BatchID,                    
         [Message]                    
       )                    
     SELECT NEWID(),                    
            A.EmailID,                    
            GETDATE(),                    
            A.AccountID,                    
            A.ReplyTo,                    
            '',                    
            @BatchID,                    
            A.MailContent                    
     FROM   #tempTable A                    
                         
     INSERT INTO EmailsFilter                    
       (        
         Mail_GUID,                    
         -- Mail_ID -- this column value is auto-generated                    
         Mail_FromEmail,                    
         Mail_ToEmail,                    
         Mail_Subject,                    
         Mail_TempleteName,                    
         Messages,                    
         Mail_InsertedDate,          
         Mail_UserID,                    
         ReplyTo,                    
         Mail_BatchID,                    
         Mail_Priority,                    
         Mail_ScheduleDate,                    
         Mail_Attechement,                    
         Mail_TempleteBody,              
         IsMonitor                    
       )                    
     SELECT NEWID(),                    
            @Mail_FromEmail,                    
            A.EmailID,                    
            A.MailSubject,                    
            '',                    
            A.MailContent,                    
            GETDATE(),                    
            A.AccountID,                    
            A.ReplyTo,                    
            @BatchID,                    
            0,                    
            NULL,                    
            0,                    
            A.MailContent,              
            @IsMonitor                    
     FROM   #tempTable A      
           
       update EmailsFilter set EmailsFilter.Mail_Priority=2      
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                    
                         
     INSERT INTO MailCreditDetails                    
       (                    
         FromUser_ID,                    
         M_ID,                    
         USER_ID,                    
         Debits,                    
         Credits,                    
         Balance ,                
         Validity                   
       )                    
     VALUES                    
       (                    
         @Account,                    
         @m_id,                    
         @Account,                    
         @MailCount,                    
         0,                    
         @Balance  ,                
         99999                  
       )                    
     SELECT 'Success'                    
 END                    
 ELSE                    
 BEGIN                    
     SELECT 'Insufficient Balance'                    
 END                    
                     
 DROP TABLE #tempTable                    
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_SendMailFromEnquiry_WithTemplateID_WithFromMailID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_SendMailFromEnquiry_WithTemplateID_WithFromMailID]                                 
 @IDS VARCHAR(MAX),                                
 @Account BIGINT,                                
 @Email_Subject VARCHAR(1000),                                
 @Message_TemplateID Bigint,                                
 @SenderName VARCHAR(100),                                
 @ReplyTo VARCHAR(1000),                                
 @EmailId BIT ,                                
 @EmailId1 BIT ,                                
 @EmailId2 BIT,      
 @FromMailID nvarchar(500)  = '',     
 @UserId bigint = 0      
AS                                
BEGIN               
select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))              

 CREATE TABLE #TableData2 (ID BIGINT)
		  
 INSERT INTO #TableData2 (ID)           
 select Item from fu_SplitString(@IDS,'#')

DECLARE @MailCount BIGINT,@IsMonitor Bit = 1               
DECLARE @m_id BIGINT,@parentid bigint        
 SELECT @m_id= ud.M_ID,@parentid=parentid                                
                 FROM   User_Detail AS ud (nolock)                               
                 WHERE  ud.[User_ID] = @Account       
 --dbo.fn_split(@IDS,'#')
 SELECT @MailCount = (select count(1) from #TableData2)                           
  DECLARE @CurrentBalance BIGINT = (                              
             SELECT TOP 1 mcd.Balance                              
             FROM   MailCreditDetails AS mcd   (nolock)                           
             WHERE  mcd.[User_ID] = @parentid                              
             ORDER BY mcd.Credit_ID DESC                              
         )                              
                               
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount                              
  IF @Balance > 0                                
 BEGIN                                
                     
 Declare @Message VARCHAR(MAX)                     
                    
  select @Message = MailContent  From UserMailTemplate(nolock) where ID= @Message_TemplateID                    
                                
                               
 SELECT A.EmailID,                                
        A.AccountID,                                
        A.SenderName,                                
        A.MailContent,                                
        A.MailSubject,                                
        A.ReplyTo,    
  A.EnquiryID  INTO #tempTable                                
 FROM   (                                
            SELECT ISNULL(A.EmailID, '') AS EmailID,                                
                   @Account        AS AccountID,                                
                   @SenderName     AS SenderName,                                
                   A.MailContent,                                
                   @Email_Subject  AS MailSubject,                                
                   @ReplyTo        AS ReplyTo  ,    
        A.EnquiryID    
            FROM   (                                
                       SELECT CASE                                 
                                   WHEN @EmailId = 1 THEN ul.EmailID                                
                                   ELSE ''                                
                              END AS EmailID,                                
                              --dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID)                      
                               dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID)  AS                                 
                              MailContent ,    
         ul.EnquiryID    
                       FROM   UserEnquiry AS ul  (nolock)                              
					   inner join #TableData2 t2 on ul.EnquiryID = t2.ID 
                       WHERE 
					   --ul.EnquiryID IN (SELECT [value]                                
        --                                FROM   dbo.fn_Split(@IDS, '#') AS fs) AND             
                                                        
                                        ----Added By Siddharth ----                
      
                       ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') <> ''                 
                      AND ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') not in                 
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID                 
                      from UserEnquiry UETemp (nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)               
                      on (UETemp.EmailID =C_UDTemp.Email)                
					   inner join #TableData2 t2 on ul.EnquiryID = t2.ID 
                                    
                      --where ul.EnquiryID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs )
					  )                              
                       UNION ALL                                 
                                                       
                       SELECT CASE                                 
                                   WHEN @EmailId1 = 1 THEN ul.EmailID1                                
                                   ELSE ''                                
                              END AS EmailID,                                
                             -- dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)                       
                             dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID1)                       
                              AS                                 
                              MailContent  ,    
         ul.EnquiryID                              
                       FROM   UserEnquiry AS ul  (nolock)                              
					   inner join #TableData2 t2 on ul.EnquiryID = t2.ID 
                       WHERE  
					   --ul.EnquiryID IN (SELECT [value] FROM  dbo.fn_Split(@IDS, '#') AS fs) AND               
                                       
                       ----Added By Siddharth ----             
                                       
                      ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') <> ''                 
       AND ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') not in                 
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID                 
                      from UserEnquiry UETemp (nolock) inner join Client_UnSubscribeDetails C_UDTemp  (nolock)              
                      on (UETemp.EmailID1 =C_UDTemp.Email)                
					   inner join #TableData2 t2 on ul.EnquiryID = t2.ID 
                                    
                      --where ul.EnquiryID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs )
					  )                                 
                       UNION ALL                                
                                                       
                       SELECT CASE                                 
                                   WHEN @EmailId2 = 1 THEN ul.EmailID2                                
                                   ELSE ''                                
                              END AS EmailID,                                
                              --dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)                      
                              dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID2)                      
                              AS                                 
                              MailContent   ,    
         ul.EnquiryID                              
                       FROM   UserEnquiry AS ul  (nolock)                              
					   inner join #TableData2 t2 on ul.EnquiryID = t2.ID 
                      WHERE 
					  --ul.EnquiryID IN (SELECT [value] FROM   dbo.fn_Split(@IDS, '#') AS fs)  AND              
                                       
                         ----Added By Siddharth ----                
                                       
                       ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') <> ''                 
                      AND ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') not in                 
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID                 
                      from UserEnquiry UETemp (nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)               
                      on (UETemp.EmailID2 =C_UDTemp.Email)                
					   inner join #TableData2 t2 on ul.EnquiryID = t2.ID 
                                    
                      --where ul.EnquiryID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs )
					  )                 
                     
                                                     
                   )                  A                                
            WHERE  ISNULL(A.EmailID, '') <> ''                                
        ) A                                
                                 
