            NULL,                                  
            NULL,                                  
            0,                             
            A.MailSubject,                                  
            A.ReplyTo,                                  
       COUNT(*),                                  
            'INR'                                  
     FROM   #tempTable A                                  
     GROUP BY                                  
            A.AccountID,                                  
            A.SenderName,                                  
            A.MailSubject,                                  
            A.ReplyTo                                   
                                       
     INSERT INTO ClientEmails                                  
       (                                  
        -- Id -- this column value is auto-generated                                  
         GUID,                                  
         Email_Id,                                  
         SentDateTime,                                  
         UserId,                                  
         ReplyTo,                                  
         [Status],                                  
