         [Message]                                  
       )                                  
     SELECT NEWID(),                         
            A.EmailID,                                  
            GETDATE(),                                  
            A.AccountID,                                  
            A.ReplyTo,                                  
            '',                                  
            @BatchID,                                  
            A.MailContent                                  
     FROM   #tempTable A                                  
                                       
     INSERT INTO EmailsFilter                                  
       (                      
         Mail_GUID,                                  
