/* ============================================================
   Procedure: [dbo].[usp_SendMailFromEnquiryPage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC usp_SendMailFromEnquiryPage 
@IDS               VARCHAR(MAX), 
@Account           BIGINT, 
@EmailSubject      VARCHAR(1000), 
@Message           VARCHAR(MAX), 
@SenderName        VARCHAR(100), 
@ReplyTo           VARCHAR(1000), 
@EmailId           BIT, 
@EmailId1          BIT, 
@EmailId2          BIT, 
@MessageTemplateId BIGINT        = 0
AS
    BEGIN
        IF @MessageTemplateId <> 0
            BEGIN
                SELECT @Message = MailContent
                FROM UserMailTemplate
                WHERE ID = @MessageTemplateId;
        END;
        SELECT A.EmailID, 
               A.AccountID, 
               A.SenderName, 
               A.MailContent, 
               A.MailSubject, 
               A.ReplyTo
        INTO #tempTable
        FROM
        (
            SELECT ISNULL(A.EmailID, '') AS EmailID, 
                   @Account AS AccountID, 
                   @SenderName AS SenderName, 
                   A.MailContent, 
                   @EmailSubject AS MailSubject, 
                   @ReplyTo AS ReplyTo
            FROM
            (
                SELECT CASE
                           WHEN @EmailId = 1
                           THEN ul.EmailID
                           ELSE ''
                       END AS EmailID, 
                       dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID) AS MailContent
                FROM UserLeads AS ul
                WHERE ul.ID IN
                (
                    SELECT [value]
                    FROM dbo.fn_Split(@IDS, '#') AS fs
                )
                AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') <> ''
                AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') NOT IN
                (
                    SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
                    FROM UserLeads AS UETemp
                         INNER JOIN Client_UnSubscribeDetails AS C_UDTemp ON UETemp.EmailID = C_UDTemp.Email
                    WHERE ul.ID IN
                    (
                        SELECT fs.value
                        FROM dbo.fn_Split(@IDS, '#') AS fs
                    )
                )
                UNION ALL
                SELECT CASE
                           WHEN @EmailId1 = 1
                           THEN ul.EmailID1
                           ELSE ''
                       END AS EmailID, 
                       dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)
                FROM UserLeads AS ul
                WHERE ul.ID IN
                (
                    SELECT [value]
                    FROM dbo.fn_Split(@IDS, '#') AS fs
                )
                AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') <> ''
                AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') NOT IN
                (
                    SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
                    FROM UserLeads AS UETemp
                         INNER JOIN Client_UnSubscribeDetails AS C_UDTemp ON UETemp.EmailID1 = C_UDTemp.Email
                    WHERE ul.ID IN
                    (
                        SELECT fs.value
                        FROM dbo.fn_Split(@IDS, '#') AS fs
                    )
                )
                UNION ALL
                SELECT CASE
                           WHEN @EmailId2 = 1
                           THEN ul.EmailID2
                           ELSE ''
                       END AS EmailID, 
                       dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)
                FROM UserLeads AS ul
                WHERE ul.ID IN
                (
                    SELECT [value]
                    FROM dbo.fn_Split(@IDS, '#') AS fs
                )
                AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') <> ''
                AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') NOT IN
                (
                    SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
                    FROM UserLeads AS UETemp
                         INNER JOIN Client_UnSubscribeDetails AS C_UDTemp ON UETemp.EmailID2 = C_UDTemp.Email
                    WHERE ul.ID IN
                    (
                        SELECT fs.value
                        FROM dbo.fn_Split(@IDS, '#') AS fs
                    )
                )
            ) AS A
            WHERE ISNULL(A.EmailID, '') <> ''
        ) AS A;
        DECLARE @MailCount BIGINT, @IsMonitor BIT= 1;
        SELECT @MailCount = COUNT(*)
        FROM #tempTable;
        DECLARE @Status BIGINT= 0, @CountLimit BIGINT= 0;
        SELECT @Status = STATUS, 
               @CountLimit = Plimit
        FROM ProcessMailLimit;
        IF @Status = 1
            BEGIN
                BEGIN
                    IF @MailCount > @CountLimit
                        BEGIN
                            SET @IsMonitor = 0;
                    END;
        END;
        END;
        DECLARE @CurrentBalance BIGINT=
        (
            SELECT TOP 1 mcd.Balance
            FROM MailCreditDetails AS mcd
            WHERE mcd.User_ID = @Account
            ORDER BY mcd.Credit_ID DESC
        );
        DECLARE @Balance BIGINT= @CurrentBalance - @MailCount;
        IF @Balance > 0
            BEGIN
                DECLARE @m_id BIGINT=
                (
                    SELECT TOP 1 ud.M_ID
                    FROM User_Detail AS ud
                    WHERE ud.User_ID = @Account
                );
                INSERT INTO GetBatchRecord
                (User_id, 
                 RandNum
                )
                VALUES
                (@Account, 
                 @Account
                );
                DECLARE @BatchID BIGINT=
                (
                    SELECT MAX(gbr.BatchID)
                    FROM GetBatchRecord AS gbr
                    WHERE gbr.User_id = @Account
                );
                DELETE FROM GetBatchRecord
                WHERE User_id = @Account;
                DECLARE @Mail_FromEmail VARCHAR(500)= '';
                SELECT @Mail_FromEmail = ud.EMail
                FROM User_Detail AS ud
                     LEFT JOIN User_Type AS ut(NOLOCK) ON ud.UserType = ut.ID
                WHERE ud.User_ID = @Account;
                INSERT INTO BatchEmail_Infos
                (                
                -- ID -- this column value is auto-generated                
                BatchID, 
                UserID, 
                SenderName, 
                Message, 
                TotalRecords, 
                TotalProcessed, 
                ProcessTable, 
                IsProcess, 
                Priority_Level, 
                BatchInsertTime, 
                BatchProcessTime, 
                ScheduledDate, 
                ScheduledTime, 
                TemplateID, 
                Route, 
                PageName, 
                IsScheduled, 
                Email_Subject, 
                ReplyTo, 
                Amount, 
                Currency
                )
                       SELECT @BatchID, 
                              A.AccountID, 
                              A.SenderName, 
                              @Message, 
                              COUNT(*), 
                              0, 
                              0, 
                              0, 
                              0, 
                              GETDATE(), 
                              NULL, 
                              NULL, 
                              NULL, 
                              NULL, 
                              NULL, 
                              NULL, 
                              0, 
                              A.MailSubject, 
                              A.ReplyTo, 
                              COUNT(*), 
                              'INR'
                       FROM #tempTable AS A
                       GROUP BY A.AccountID, 
                                A.SenderName, 
                                A.MailSubject, 
                                A.ReplyTo;
                INSERT INTO ClientEmails
                (                
                -- Id -- this column value is auto-generated                
                GUID, 
                Email_Id, 
                SentDateTime, 
                UserId, 
                ReplyTo, 
                STATUS, 
                BatchID, 
                Message
                )
                       SELECT NEWID(), 
                              A.EmailID, 
                              GETDATE(), 
                              A.AccountID, 
                              A.ReplyTo, 
                              '', 
                              @BatchID, 
                              A.MailContent
                       FROM #tempTable AS A;
                INSERT INTO EmailsFilter
                (Mail_GUID,                
                 -- Mail_ID -- this column value is auto-generated                
                 Mail_FromEmail, 
                 Mail_ToEmail, 
                 Mail_Subject, 
                 Mail_TempleteName, 
                 Messages, 
                 Mail_InsertedDate, 
                 Mail_UserID, 
                 ReplyTo, 
                 Mail_BatchID, 
                 Mail_Priority, 
                 Mail_ScheduleDate, 
                 Mail_Attechement, 
                 Mail_TempleteBody, 
                 IsMonitor
                )
                       SELECT NEWID(), 
                              @Mail_FromEmail, 
                              A.EmailID, 
                              A.MailSubject, 
                              '', 
                              A.MailContent, 
                              GETDATE(), 
                              A.AccountID, 
                              A.ReplyTo, 
                              @BatchID, 
                              0, 
                              NULL, 
                              0, 
                              A.MailContent, 
                              @IsMonitor
                       FROM #tempTable AS A;
                UPDATE EmailsFilter
                  SET 
                      EmailsFilter.Mail_Priority = 2
                FROM EmailsFilter
                     INNER JOIN CustomerEmail ON EmailsFilter.Mail_ToEmail = CustomerEmail.Email;
                INSERT INTO MailCreditDetails
                (FromUser_ID, 
                 M_ID, 
                 USER_ID, 
                 Debits, 
                 Credits, 
                 Balance, 
                 Validity
                )
                VALUES
                (@Account, 
                 @m_id, 
                 @Account, 
                 @MailCount, 
                 0, 
                 @Balance, 
                 99999
                );
                SELECT 'Success';
        END;
            ELSE
            BEGIN
                SELECT 'Insufficient Balance';
        END;
        DROP TABLE #tempTable;
    END;


GO

