/* ============================================================
   Procedure: [dbo].[usp_SendMailFromLeads_FromMailID_ViaOtherDB]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SendMailFromLeads_FromMailID_ViaOtherDB] 
     @IDS VARCHAR(MAX)
	,@Account BIGINT
	,@Email_Subject VARCHAR(1000)
	,@Message VARCHAR(MAX)
	,@SenderName VARCHAR(100)
	,@ReplyTo VARCHAR(1000)
	,@EmailId BIT
	,@EmailId1 BIT
	,@EmailId2 BIT
	,@UserId BIGINT = 0
	,@FromMailID VARCHAR(500)
AS
BEGIN
	--select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))                
	DECLARE @MailCount BIGINT
		,@IsMonitor BIT = 1
	DECLARE @m_id BIGINT
		,@parentid BIGINT

	SELECT @m_id = ud.M_ID
		,@parentid = parentid
	FROM User_Detail AS ud(NOLOCK)
	WHERE ud.[User_ID] = @Account

	SELECT @MailCount = (
			SELECT count(1)
			FROM dbo.fn_split(@IDS, '#')
			)

	DECLARE @CurrentBalance BIGINT = (
			SELECT TOP 1 mcd.Balance
			FROM MailCreditDetails AS mcd(NOLOCK)
			WHERE mcd.[User_ID] = @parentid
			ORDER BY mcd.Credit_ID DESC
			)
	DECLARE @Balance BIGINT = @CurrentBalance - @MailCount

	IF @Balance > 0
	BEGIN
		SELECT A.EmailID
			,A.AccountID
			,A.SenderName
			,A.MailContent
			,A.MailSubject
			,A.ReplyTo
			,A.leadid
		INTO #tempTable
		FROM (
			SELECT ISNULL(A.EmailID, '') AS EmailID
				,@Account AS AccountID
				,@SenderName AS SenderName
				,A.MailContent
				,@Email_Subject AS MailSubject
				,@ReplyTo AS ReplyTo
				,Leadid
			FROM (
				SELECT CASE 
						WHEN @EmailId = 1
							THEN ul.EmailID
						ELSE ''
						END AS EmailID
					,dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID) AS MailContent
					,ul.ID AS leadid
				FROM UserLeads AS ul(NOLOCK)
				WHERE ul.ID IN (
						SELECT [value]
						FROM dbo.fn_Split(@IDS, '#') AS fs
						)
					AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') <> ''
					AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') NOT IN (
						SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
						FROM UserLeads UETemp(NOLOCK)
						INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID = C_UDTemp.Email)
						WHERE ul.ID IN (
								SELECT fs.value
								FROM dbo.fn_Split(@IDS, '#') AS fs
								)
						)
				
				UNION ALL
				
				SELECT CASE 
						WHEN @EmailId1 = 1
							THEN ul.EmailID1
						ELSE ''
						END AS EmailID
					,dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)
					,ul.ID AS leadid
				FROM UserLeads AS ul(NOLOCK)
				WHERE ul.ID IN (
						SELECT [value]
						FROM dbo.fn_Split(@IDS, '#') AS fs
						)
					AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') <> ''
					AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') NOT IN (
						SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
						FROM UserLeads UETemp(NOLOCK)
						INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID1 = C_UDTemp.Email)
						WHERE ul.ID IN (
								SELECT fs.value
								FROM dbo.fn_Split(@IDS, '#') AS fs
								)
						)
					AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') <> ''
					AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') NOT IN (
						SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
						FROM UserLeads UETemp(NOLOCK)
						INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID2 = C_UDTemp.Email)
						WHERE ul.ID IN (
								SELECT fs.value
								FROM dbo.fn_Split(@IDS, '#') AS fs
								)
						)
				
				UNION ALL
				
				SELECT CASE 
						WHEN @EmailId2 = 1
							THEN ul.EmailID2
						ELSE ''
						END AS EmailID
					,dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)
					,ul.ID AS leadid
				FROM UserLeads AS ul(NOLOCK)
				WHERE ul.ID IN (
						SELECT [value]
						FROM dbo.fn_Split(@IDS, '#') AS fs
						)
				) A
			WHERE ISNULL(A.EmailID, '') <> ''
			) A

		DECLARE @Status BIGINT = 0
			,@CountLimit BIGINT = 0

		SELECT @Status = STATUS
			,@CountLimit = Plimit
		FROM ProcessMailLimit

		IF (@Status = 1)
		BEGIN
			BEGIN
				IF (@MailCount > @CountLimit)
				BEGIN
					SET @IsMonitor = 0
				END
			END
		END

		DECLARE @BatchID BIGINT

		BEGIN TRAN

		INSERT INTO GetBatchRecord (
			[User_id]
			,RandNum
			)
		VALUES (
			@Account
			,@Account
			)

		SELECT @BatchID = SCOPE_IDENTITY()

		DELETE
		FROM GetBatchRecord
		WHERE batchid = @BatchID

		COMMIT

		DECLARE @Mail_FromEmail VARCHAR(500) = ''

		SELECT @Mail_FromEmail = coalesce((
					SELECT TOP 1 mail_id
					FROM defaultmailid(NOLOCK)
					WHERE user_id = @account
					ORDER BY datecreated DESC
					), (
					SELECT ud.EMail
					FROM User_Detail AS ud(NOLOCK)
					WHERE ud.[User_ID] = @Account
					), 'contactus@email19.in')

		IF (rtrim(ltrim(@FromMailID)) <> '')
		BEGIN
			SET @Mail_FromEmail = @FromMailID
		END
		
	  INSERT INTO BatchEmail_Infos                                  
        (                                  
         -- ID -- this column value is auto-generated                                  
         BatchID,                                  
         UserID,                                  
         SenderName,                                  
         [Message],                                  
         TotalRecords,                                  
         TotalProcessed,                                  
         ProcessTable,                                  
         IsProcess,                                  
         Priority_Level,                                  
         BatchInsertTime,                                  
         BatchProcessTime,                                  
         ScheduledDate,                                  
         ScheduledTime,                                  
         TemplateID,                                  
         [Route],                                  
         PageName,                                  
         IsScheduled,                                  
         Email_Subject,                                  
         ReplyTo,                                  
        Amount,                                  
         Currency                                  
       )                                  
     SELECT @BatchID,                                  
            A.AccountID,                                  
            --A.SenderName,
			@Mail_FromEmail,
            @Message,                                  
            COUNT(*),                                  
            0,                                  
            0,                                  
            0,                                  
            0,                                 
            GETDATE(),                                  
            NULL,                                  
            NULL,             
            NULL,                                  
            NULL,                                  
            NULL,                                  
            NULL,                                  
            0,                                  
            A.MailSubject,                           
            A.ReplyTo,                                  
            COUNT(*),                                  
            'INR'                                  
     FROM   #tempTable A                                  
     GROUP BY                                  
            A.AccountID,                                  
            --A.SenderName,                                  
            A.MailSubject,                                  
            A.ReplyTo

    INSERT INTO MailCreditDetails                                  
       (                                  
         FromUser_ID,                                  
         M_ID,                                  
         USER_ID,                                  
         Debits,                                  
         Credits,                                  
         Balance ,                              
         Validity                                 
       )                                  
     VALUES                                  
       (                                  
         @Account,                                  
         @m_id,                              
         @Account,                                  
         @MailCount,                                  
         0,                                  
         @Balance  ,                              
         99999                                
       )
	   
	 INSERT INTO [10.0.0.135].[MysmsTrans].[dbo].CloneEmailsFilter (
			Mail_FromEmail
			,Mail_ToEmail
			,Mail_Subject
			,Mail_TempleteName
			,Messages
			,Mail_InsertedDate
			,Mail_UserID
			,Mail_ParentID
			,ReplyTo
			,Mail_BatchID
			,Mail_Priority
			,Mail_ScheduleDate
			,Mail_ScheduledTime
			,Mail_Attechement
			,Mail_TempleteBody
			,IsMonitor
			,TemplateID
			,Count
			,Source
			,EntityName
            ,EntityID
            ,IsMatched
			)
		SELECT @Mail_FromEmail
			,A.EmailID
			,A.MailSubject
			,''
			,A.MailContent
			,GETDATE()
			,@UserId
			,@parentid
			,A.ReplyTo
			,@BatchID
			,1
			,''
			,''
			,''
			,A.MailContent
			,@ismonitor
			,0
			,@mailcount
			,'Leads-MassSend'
			,'Lead'
		    ,leadid
		    ,0
		FROM #tempTable A

		/*                             
     INSERT INTO BatchEmail_Infos                        
       (                        
         -- ID -- this column value is auto-generated                        
         BatchID,                        
         UserID,                        
         SenderName,                        
         [Message],                        
         TotalRecords,                        
         TotalProcessed,                        
         ProcessTable,                        
         IsProcess,                        
         Priority_Level,                        
         BatchInsertTime,                        
         BatchProcessTime,                        
         ScheduledDate,                        
         ScheduledTime,                        
         TemplateID,                        
         [Route],                        
         PageName,                        
         IsScheduled,                        
         Email_Subject,                        
         ReplyTo,                        
         Amount,                        
         Currency                        
       )                        
     SELECT @BatchID,                        A.AccountID,                        
            A.SenderName,                        
            @Message,                        
            COUNT(*),                        
            0,                        
            0,                        
            0,                        
            0,                        
            GETDATE(),                        
            NULL,                        
            NULL,                        
            NULL,                        
            NULL,                        
            NULL,                        
            NULL,                        
            0,                        
            A.MailSubject,                        
            A.ReplyTo,                        
            COUNT(*),                        
            'INR'                        
     FROM   #tempTable A                        
     GROUP BY                        
            A.AccountID,                        
            A.SenderName,                        
            A.MailSubject,                        
            A.ReplyTo                         
                             
     INSERT INTO ClientEmails                        
       (                        
         -- Id -- this column value is auto-generated                        
         GUID,                        
         Email_Id,                        
         SentDateTime,                        
         UserId,                        
         ReplyTo,                        
         [Status],                        
         BatchID,                        
         [Message]                        
       )                        
     SELECT NEWID(),                        
            A.EmailID,                        
            GETDATE(),                        
            A.AccountID,                        
            A.ReplyTo,                        
            '',                        
            @BatchID,                        
            A.MailContent                        
     FROM   #tempTable A                        
                             
     INSERT INTO EmailsFilter                        
       (                        
         Mail_GUID,                        
         -- Mail_ID -- this column value is auto-generated                        
         Mail_FromEmail,                        
         Mail_ToEmail,                        
         Mail_Subject,                        
         Mail_TempleteName,                        
         Messages,                        
         Mail_InsertedDate,                        
         Mail_UserID,                        
         ReplyTo,                        
         Mail_BatchID,          
         Mail_Priority,                        
         Mail_ScheduleDate,                        
         Mail_Attechement,                        
         Mail_TempleteBody,                    
         IsMonitor                        
       )                        
     SELECT NEWID(),                        
            @Mail_FromEmail,                        
 A.EmailID,                        
            A.MailSubject,                        
            '',                        
            A.MailContent,                            GETDATE(),                        
            A.AccountID,                        
            A.ReplyTo,                        
            @BatchID,                        
            0,                        
            NULL,                        
            0,                        
            A.MailContent,                    
            @IsMonitor                        
     FROM   #tempTable A                  
                     
      update EmailsFilter set EmailsFilter.Mail_Priority=2                
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                       
                             
     INSERT INTO MailCreditDetails                        
       (                        
         FromUser_ID,                        
         M_ID,                        
         USER_ID,                        
         Debits,                        
         Credits,                        
         Balance ,                      
         Validity                       
       )                        
     VALUES                        
       (                        
         @Account,                        
         @m_id,                        
         @Account,                        
         @MailCount,                        
         0,                        
         @Balance,                      
         99999                        
   )          
   */
		IF (@UserId > 0)
		BEGIN
			DECLARE @leadActivityHistory AS LeadActivitywithid_Tbltype
			DECLARE @Username NVARCHAR(255) = (
					SELECT User_Login
					FROM User_Detail(NOLOCK)
					WHERE User_Id = @UserId
					)

			INSERT INTO @leadActivityHistory (
				LeadID
				,UserID
				,ParentID
				,EventDescription
				,EventName
				,RefTable
				,refid
				)
			SELECT leadid
				,@UserId
				,@parentid
				,CONCAT (
					@Username
					,' sent a mail with subject '
					,MailSubject
					,' to emailid '
					,EmailID
					)
				,'Mail sent to lead'
				,'Batchemail_infos'
				,@BatchID
			FROM #tempTable

			EXEC UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory
		END

		SELECT 'Success'
	END
	ELSE
	BEGIN
		SELECT 'Insufficient Balance'
	END

	DROP TABLE #tempTable

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM [10.0.0.135].[MysmsTrans].[dbo].CloneEmailsFilter
			WHERE Mail_BatchID = @BatchID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'Inst_Mail_Lead'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'CloneEmailsFilter'
END



