/* ============================================================
   Procedure: [dbo].[usp_SendMailFromLeads_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_SendMailFromLeads_new] 
(
    @IDS               VARCHAR(MAX),
    @Account           BIGINT,
    @Email_Subject     VARCHAR(1000),
    @Message           VARCHAR(2000),
    @SenderName        VARCHAR(100),
    @ReplyTo           VARCHAR(1000),
    @EmailId           VARCHAR(10),
    @EmailId1          VARCHAR(10),
    @EmailId2          VARCHAR(10)
)
AS
	-- =============================================
	-- Author:      Name Vishal Kumar Srivastava
	-- Create date: 01-09-2017
	-- Description: MassOperation of Send Mail From Leads
	--[usp_SendMailFromLeads] 270,335,'df','<p>dfsgdgds#CompanyName##MobileNo##SourceName#</p>','PelsoftlabsReseller','ab.yahoo.com','s','',''
	--[usp_SendMailFromLeads] 272,335,'df','<p>dfsgdgds#CompanyName##MobileNo##SourceName#</p>','PelsoftlabsReseller','','1','',''
	-- =============================================   
BEGIN
	BEGIN TRY
		BEGIN TRANSACTION 
		--DECLARE @IDS VARCHAR(MAX)=''  
		DECLARE @TotalCreditCount INT = 0;  
		DECLARE @Balance INT = 0 
		--SET @IDS='245';  
		
		SELECT @Balance = ISNULL(Balance, 0)
		FROM   MailCreditDetails AS mcd
		WHERE  mcd.[User_ID] IN (@Account)
		       AND Credit_ID = (
		               SELECT MAX(Credit_ID)
		               FROM   MailCreditDetails
		           )
		ORDER BY
		       Credit_ID DESC  
		
		SELECT @TotalCreditCount = COUNT(1)
		FROM   UserLeads ue
		WHERE  ID IN (SELECT fs.[value]
		              FROM   dbo.fn_Split(@IDS, ',') fs)
		       AND (
		               ISNULL(NULLIF(CAST(ue.EmailId AS VARCHAR(100)), ''), '') 
		               <> ''
		               OR ISNULL(NULLIF(CAST(ue.EmailId1 AS VARCHAR(100)), ''), '') 
		                  <> ''
		               OR ISNULL(NULLIF(CAST(ue.EmailId2 AS VARCHAR(100)), ''), '') 
		                  <> ''
		           )
		
		SET @Balance = @Balance -@TotalCreditCount 
		-- SELECT @Balance   
		
		IF (@Balance > 0)
		BEGIN
		    -------------For Mail information--------------------------   
		    INSERT INTO GetBatchRecord
		      (
		        [User_id],
		        RandNum
		      )
		    VALUES
		      (
		        @Account,
		        @Account
		      )      
		    DECLARE @BatchID BIGINT = (
		                SELECT MAX(gbr.BatchID)
		                FROM   GetBatchRecord AS gbr
		                WHERE  gbr.[User_id] = @Account
		            )
		    
		    DELETE 
		    FROM   GetBatchRecord
		    WHERE  [User_id] = @Account   
		    
		    DECLARE @Mail_FromEmail VARCHAR(100) = ''; 
		    SELECT @Mail_FromEmail = ud.EMail
		    FROM   User_Detail          AS ud
		           LEFT JOIN User_Type  AS ut(NOLOCK)
		                ON  ud.UserType = ut.ID
		    WHERE  ud.[User_ID] = @Account 
		    
		    -- PRINT @Mail_FromEmail
		    ----------------------Debit -------------------
		    DECLARE @rmid BIGINT,
		            @ruid BIGINT,
		            @rbal BIGINT,
		            @rcid BIGINT,
		            @MIDUser BIGINT
		    
		    DECLARE @rvalidity           NVARCHAR(300),
		            @rdefault_credit     NVARCHAR(300),
		            @finalbalance        BIGINT,
		            @rCredit             BIGINT,
		            @uCredits            BIGINT            
		    
		    SELECT TOP(1) @MIDUser = m_id
		    FROM   User_Detail
		    WHERE  USER_ID = @Account
		    
		    SELECT TOP(1) @rmid = m_id,
		           @ruid           = USER_ID
		    FROM   reseller_detail
		    WHERE  reseller_id     = @MIDUser
		    
		    SELECT TOP(1) @rbal = balance,
		           @rvalidity           = validity,
		           @rdefault_credit     = default_credit,
		           @rCredit             = credits,
		           @rcid                = credit_id
		    FROM   MailCreditDetails
		    WHERE  m_id                 = @rmid
		           AND USER_ID          = @ruid
		    ORDER BY
		           credit_id DESC 
		    
		    --@balanceValue
		    --Debit      
		    INSERT INTO MailCreditDetails
		      (
		        FromUser_ID,
		        M_ID,
		        USER_ID,
		        Debits,
		        Credits,
		        Balance,
		        Validity,
		        Default_Credit
		      )
		    VALUES
		      (
		        @Account,
		        @rmid,
		        @ruid,
		        0,
		        @TotalCreditCount,
		        @finalbalance,
		        @rvalidity,
		        @rdefault_credit
		      ) 
		    ------------------------------------------
		    
		    INSERT INTO BatchEmail_Infos
		      (
		        BatchID,
		        UserID,
		        SenderName,
		        MESSAGE,
		        TotalRecords,
		        TotalProcessed,
		        ProcessTable,
		        IsProcess,
		        Priority_Level,
		        BatchInsertTime,
		        TemplateID,
		        PageName,
		        IsScheduled,
		        Email_Subject,
		        ReplyTo,
		        Amount,
		        Currency
		      )
		    SELECT @BatchID   AS BatchID,
		           @Account   AS USERID,
		           @SenderName,
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID) AS 
		           Messagetext,
		           1,
		           0,
		           0,
		           0,
		           0,
		           GETDATE(),
		           0,
		           '',
		           0,
		           @Email_Subject,
		           @ReplyTo,
		           0,
		           '+91'
		    FROM   UserLeads  AS ue
		    WHERE  ue.ID IN (SELECT fs.[value]
		                     FROM   dbo.fn_Split(@IDS, ',') AS fs)
		           AND (
		                   ISNULL(NULLIF(CAST(ue.EmailId AS VARCHAR(100)), ''), '') 
		                   <> ''
		                   OR ISNULL(NULLIF(CAST(ue.EmailId1 AS VARCHAR(100)), ''), '') 
		                      <> ''
		                   OR ISNULL(NULLIF(CAST(ue.EmailId2 AS VARCHAR(100)), ''), '') 
		                      <> ''
		               )      
		    
		    INSERT INTO EmailsFilter
		      (
		        Mail_FromEmail,
		        Mail_ToEmail,
		        Mail_Subject,
		        Mail_TempleteName,
		        Messages,
		        Mail_InsertedDate,
		        Mail_UserID,
		        ReplyTo,
		        Mail_BatchID,
		        Mail_Priority,
		        Mail_ScheduleDate,
		        Mail_Attechement,
		        Mail_TempleteBody
		      )
		    SELECT @Mail_FromEmail,
		           CASE 
		                WHEN @EmailId = '1' THEN ISNULL(CAST(ue.EmailId AS VARCHAR(100)), '')
		                ELSE ''
		           END        AS EmailId,
		           @Email_Subject,
		           '',
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID) AS 
		           Messages,
		           GETDATE(),
		           @Account,
		           '',
		           @BatchID,
		           0,
		           GETDATE(),
		           '',
		           ''
		    FROM   UserLeads     ue
		    WHERE  ID IN (SELECT fs.[value]
		                  FROM   dbo.fn_Split(@IDS, ',') fs)
		           AND ISNULL(NULLIF(CAST(@EmailId AS VARCHAR(100)), ''), '') <>
		               '' 
		    UNION
		    SELECT @Mail_FromEmail,
		           CASE 
		                WHEN @EmailId1 = '1' THEN ISNULL(CAST(ue.EmailId1 AS VARCHAR(100)), '')
		                ELSE ''
		           END        AS EmailId1,
		           @Email_Subject,
		           '',
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID1) AS 
		           Messages,
		           GETDATE(),
		           @Account,
		           '',
		           @BatchID,
		           0,
		           GETDATE(),
		           '',
		           ''
		    FROM   UserLeads     ue
		    WHERE  ID IN (SELECT fs.[value]
		                  FROM   dbo.fn_Split(@IDS, ',') fs)
		           AND ISNULL(NULLIF(CAST(@EmailId1 AS VARCHAR(100)), ''), '') <
		               >
		               '' 
		    UNION
		    SELECT @Mail_FromEmail,
		           CASE 
		                WHEN @EmailId2 = '1' THEN ISNULL(CAST(ue.EmailId2 AS VARCHAR(100)), '')
		                ELSE ''
		           END        AS EmailId2,
		           @Email_Subject,
		           '',
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID2) AS 
		           Messages,
		           GETDATE(),
		           @Account,
		           '',
		           @BatchID,
		           0,
		           GETDATE(),
		           '',
		           ''
		    FROM   UserLeads     ue
		    WHERE  ID IN (SELECT fs.[value]
		                  FROM   dbo.fn_Split(@IDS, ',') fs)
		           AND ISNULL(NULLIF(CAST(@EmailId2 AS VARCHAR(100)), ''), '') <
		               >
		               ''   
		    
		    
		    
		    INSERT INTO ClientEmails
		      (
		        Email_Id,
		        SentDateTime,
		        UserId,
		        ReplyTo,
		        STATUS,
		        BatchID,
		        MESSAGE
		      )
		    SELECT CASE 
		                WHEN @EmailId = '1' THEN ISNULL(NULLIF(CAST(ue.EmailId AS VARCHAR(100)), ''), '')
		                ELSE ''
		           END        AS EmailId,
		           GETDATE(),
		           @Account,
		           '',
		           '',
		           @BatchID,
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID) AS 
		           Messages
		    FROM   UserLeads     ue
		    WHERE  ID IN (SELECT fs.[value]
		                  FROM   dbo.fn_Split(@IDS, ',') fs)
		           AND ISNULL(NULLIF(CAST(@EmailId AS VARCHAR(100)), ''), '') <>
		               '' 
		    UNION
		    SELECT CASE 
		                WHEN @EmailId1 = '1' THEN ISNULL(NULLIF(CAST(ue.EmailId2 AS VARCHAR(100)), ''), '')
		                ELSE ''
		           END        AS EmailId1,
		           GETDATE(),
		           @Account,
		           '',
		           '',
		           @BatchID,
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID1) AS 
		           Messages
		    FROM   UserLeads     ue
		    WHERE  ID IN (SELECT fs.[value]
		                  FROM   dbo.fn_Split(@IDS, ',') fs)
		           AND ISNULL(NULLIF(CAST(@EmailId1 AS VARCHAR(100)), ''), '') <
		               >
		               '' 
		    UNION
		    SELECT CASE 
		                WHEN @EmailId2 = '1' THEN ISNULL(NULLIF(CAST(ue.EmailId2 AS VARCHAR(100)), ''), '')
		                ELSE ''
		           END        AS EmailId2,
		           GETDATE(),
		           @Account,
		           '',
		           '',
		           @BatchID,
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID2) AS 
		           Messages
		    FROM   UserLeads     ue
		    WHERE  ID IN (SELECT fs.[value]
		                  FROM   dbo.fn_Split(@IDS, ',') fs)
		           AND ISNULL(NULLIF(CAST(@EmailId2 AS VARCHAR(100)), ''), '') <
		               >
		               ''   
		    
		    SELECT 'Record Saved' 
		    COMMIT TRANSACTION
		END
		ELSE
		BEGIN
		    SELECT 'InSuffient Balance'
		END
	END TRY  
	BEGIN CATCH
		ROLLBACK TRANSACTION  
		
		SELECT ERROR_NUMBER()     AS ErrorNumber,
		       ERROR_SEVERITY()   AS ErrorSeverity,
		       ERROR_STATE()      AS ErrorState,
		       ERROR_PROCEDURE()  AS ErrorProcedure,
		       ERROR_LINE()       AS ErrorLine,
		       ERROR_MESSAGE()    AS ErrorMessage
	END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_SendMailFromLeads_Shaired]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_SendMailFromLeads_Shaired            
 @IDS VARCHAR(MAX),            
 @Account BIGINT,            
 @Email_Subject VARCHAR(1000),            
 @Message VARCHAR(MAX),            
 @SenderName VARCHAR(100),            
 @ReplyTo VARCHAR(1000),            
 @EmailId BIT ,            
 @EmailId1 BIT ,            
 @EmailId2 BIT            
AS            
BEGIN            
 SELECT A.EmailID,            
        A.AccountID,            
        A.SenderName,            
        A.MailContent,            
        A.MailSubject,            
        A.ReplyTo INTO #tempTable            
 FROM   (            
            SELECT ISNULL(A.EmailID, '') AS EmailID,            
                   @Account        AS AccountID,            
                   @SenderName     AS SenderName,            
                   A.MailContent,            
                   @Email_Subject  AS MailSubject,            
                   @ReplyTo        AS ReplyTo            
            FROM   (            
                       SELECT CASE             
                                   WHEN @EmailId = 1 THEN ul.EmailID            
                                   ELSE ''            
                              END AS EmailID,            
                              dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID) AS             
                              MailContent            
                       FROM   UserLeads AS ul            
                       WHERE  ul.ID IN (SELECT [value]            
                                        FROM   dbo.fn_Split(@IDS, '#') AS fs)   
                                          AND ISNULL(NULLIF(CAST(ul.EmailID as bigint), ''), '') <> ''     
                      AND ISNULL(NULLIF(CAST(ul.EmailID as bigint), ''), '') not in     
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID     
                      from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp    
                      on (UETemp.EmailID =C_UDTemp.Email)    
                        
                      where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs))     
                                          
                                          
                                                  
                       UNION ALL             
                                   
                       SELECT CASE             
                                   WHEN @EmailId1 = 1 THEN ul.EmailID1            
                                   ELSE ''            
                              END AS EmailID,            
                              dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)            
                       FROM   UserLeads AS ul            
                       WHERE  ul.ID IN (SELECT [value]            
                                        FROM   dbo.fn_Split(@IDS, '#') AS fs)   
                                         AND ISNULL(NULLIF(CAST(ul.EmailID1 as bigint), ''), '') <> ''     
                      AND ISNULL(NULLIF(CAST(ul.EmailID1 as bigint), ''), '') not in     
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID     
                      from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp    
                      on (UETemp.EmailID1 =C_UDTemp.Email)    
                        
                      where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))  
                                 
                                AND ISNULL(NULLIF(CAST(ul.EmailID2 as bigint), ''), '') <> ''     
                      AND ISNULL(NULLIF(CAST(ul.EmailID2 as bigint), ''), '') not in     
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID     
                      from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp    
                      on (UETemp.EmailID2 =C_UDTemp.Email)    
                        
                      where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))    
                                 
                                                   
                       UNION ALL            
                                   
                       SELECT CASE             
                                   WHEN @EmailId2 = 1 THEN ul.EmailID2            
                                   ELSE ''            
                              END AS EmailID,            
                              dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)            
                       FROM   UserLeads AS ul            
                       WHERE  ul.ID IN (SELECT [value]            
                                        FROM   dbo.fn_Split(@IDS, '#') AS fs)            
                   )                  A            
            WHERE  ISNULL(A.EmailID, '') <> ''            
        ) A            
             
 DECLARE @MailCount BIGINT ,@IsMonitor Bit = 1            
 SELECT @MailCount = COUNT(*)            
 FROM   #tempTable            
             
             
  Declare @Status Bigint=0,@CountLimit bigint = 0        
   select @Status = status,@CountLimit = Plimit from ProcessMailLimit               
      if(@Status = 1)        
      Begin        
    Begin        
      if(@MailCount >  @CountLimit )        
      Begin        
       set @IsMonitor = 0         
      End        
     End        
       End        
             
             
 DECLARE @CurrentBalance BIGINT = (            
             SELECT TOP 1 mcd.Balance            
             FROM   MailCreditDetails AS mcd            
             WHERE  mcd.[User_ID] = @Account            
             ORDER BY            
                    mcd.Credit_ID DESC            
         )            
             
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount            
 IF @Balance > 0            
 BEGIN            
     DECLARE @m_id BIGINT = (            
                 SELECT TOP 1 ud.M_ID            
                 FROM   User_Detail AS ud            
                 WHERE  ud.[User_ID] = @Account            
             )            
                 
     INSERT INTO GetBatchRecord            
       (            
         [User_id],            
         RandNum            
       )            
     VALUES               (            
         @Account,            
         @Account            
       )                  
                 
     DECLARE @BatchID BIGINT = (            
                 SELECT MAX(gbr.BatchID)            
                 FROM  GetBatchRecord AS gbr            
                 WHERE  gbr.[User_id] = @Account            
             )                
                 
     DELETE             
     FROM   GetBatchRecord            
     WHERE  [User_id] = @Account               
                 
                 
                 
     DECLARE @Mail_FromEmail VARCHAR(500) = ''              
                 
     SELECT @Mail_FromEmail = ud.EMail            
     FROM   User_Detail          AS ud            
            LEFT JOIN User_Type  AS ut(NOLOCK)            
                 ON  ud.UserType = ut.ID            
     WHERE  ud.[User_ID] = @Account             
                 
     INSERT INTO BatchEmail_Infos            
       (            
         -- ID -- this column value is auto-generated            
         BatchID,            
         UserID,            
         SenderName,            
         [Message],            
         TotalRecords,            
         TotalProcessed,            
         ProcessTable,            
         IsProcess,            
         Priority_Level,            
         BatchInsertTime,            
         BatchProcessTime,            
         ScheduledDate,            
         ScheduledTime,            
         TemplateID,            
         [Route],            
         PageName,            
         IsScheduled,            
         Email_Subject,            
         ReplyTo,            
         Amount,            
         Currency            
       )            
     SELECT @BatchID,                        A.AccountID,            
            A.SenderName,            
            @Message,            
            COUNT(*),            
            0,            
            0,            
            0,            
            0,            
            GETDATE(),            
            NULL,            
            NULL,            
            NULL,            
            NULL,            
            NULL,            
            NULL,            
            0,            
            A.MailSubject,            
            A.ReplyTo,            
            COUNT(*),            
            'INR'            
     FROM   #tempTable A            
     GROUP BY            
            A.AccountID,            
            A.SenderName,            
            A.MailSubject,            
            A.ReplyTo             
                 
     INSERT INTO ClientEmails            
       (            
         -- Id -- this column value is auto-generated            
         GUID,            
         Email_Id,            
         SentDateTime,            
         UserId,            
         ReplyTo,            
         [Status],            
         BatchID,            
         [Message]            
       )            
     SELECT NEWID(),            
            A.EmailID,            
            GETDATE(),            
            A.AccountID,            
            A.ReplyTo,            
            '',            
            @BatchID,            
            A.MailContent            
     FROM   #tempTable A            
                 
     INSERT INTO EmailsFilter            
       (            
         Mail_GUID,            
         -- Mail_ID -- this column value is auto-generated            
         Mail_FromEmail,            
         Mail_ToEmail,            
         Mail_Subject,            
         Mail_TempleteName,            
         Messages,            
         Mail_InsertedDate,            
         Mail_UserID,            
         ReplyTo,            
         Mail_BatchID,            
         Mail_Priority,            
         Mail_ScheduleDate,            
         Mail_Attechement,            
         Mail_TempleteBody,        
         IsMonitor            
       )            
     SELECT NEWID(),            
            @Mail_FromEmail,            
 A.EmailID,            
            A.MailSubject,            
            '',            
            A.MailContent,            
            GETDATE(),            
            A.AccountID,            
            A.ReplyTo,            
            @BatchID,            
            0,            
            NULL,            
            0,            
            A.MailContent,        
            @IsMonitor            
     FROM   #tempTable A      
         
      update EmailsFilter set EmailsFilter.Mail_Priority=2    
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email           
                 
     INSERT INTO MailCreditDetails            
       (            
         FromUser_ID,            
         M_ID,            
         USER_ID,            
         Debits,            
         Credits,            
         Balance ,          
         Validity           
       )            
     VALUES            
       (            
         @Account,            
         @m_id,            
         @Account,            
         @MailCount,            
         0,            
         @Balance,          
         99999            
       )            
     SELECT 'Success'            
 END            
 ELSE            
 BEGIN            
     SELECT 'Insufficient Balance'            
 END            
             
 DROP TABLE #tempTable            
END 


GO

