         ScheduledTime,                
         TemplateID,                
         [Route],                
         PageName,                
         IsScheduled,                
         Email_Subject,                
         ReplyTo,                
         Amount,                
         Currency                
       )                
     SELECT @BatchID,                        A.AccountID,                
            A.SenderName,                
            @Message,                
            COUNT(*),                
            0,                
            0,                
            0,                
            0,                
            GETDATE(),                
            NULL,                
            NULL,                
            NULL,                
            NULL,                
            NULL,                
            NULL,                
            0,                
            A.MailSubject,                
            A.ReplyTo,                
            COUNT(*),                
            'INR'                
     FROM   #tempTable A                
     GROUP BY                
            A.AccountID,                
            A.SenderName,                
            A.MailSubject,                
            A.ReplyTo                 
                     
     INSERT INTO ClientEmails                
       (                
         -- Id -- this column value is auto-generated                
         GUID,                
         Email_Id,                
         SentDateTime,                
         UserId,                
         ReplyTo,                
         [Status],                
         BatchID,                
         [Message]                
       )                
     SELECT NEWID(),                
            A.EmailID,                
            GETDATE(),                
            A.AccountID,                
            A.ReplyTo,                
            '',                
            @BatchID,                
            A.MailContent                
     FROM   #tempTable A                
                     
     INSERT INTO EmailsFilter                
       (                
         Mail_GUID,                
         -- Mail_ID -- this column value is auto-generated                
         Mail_FromEmail,                
         Mail_ToEmail,                
         Mail_Subject,                
         Mail_TempleteName,                
         Messages,                
         Mail_InsertedDate,                
         Mail_UserID,                
         ReplyTo,                
         Mail_BatchID,                
         Mail_Priority,                
         Mail_ScheduleDate,                
         Mail_Attechement,                
         Mail_TempleteBody,            
         IsMonitor                
       )                
     SELECT NEWID(),                
            @Mail_FromEmail,                
 A.EmailID,                
            A.MailSubject,                
            '',                
            A.MailContent,                            GETDATE(),                
            A.AccountID,                
            A.ReplyTo,                
            @BatchID,                
            0,                
            NULL,                
            0,                
            A.MailContent,            
            @IsMonitor                
     FROM   #tempTable A          
             
      update EmailsFilter set EmailsFilter.Mail_Priority=2        
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email               
                     
     INSERT INTO MailCreditDetails                
       (                
         FromUser_ID,                
