       )                  
     SELECT @BatchID,                        A.AccountID,                  
            A.SenderName,                  
            @Message,                  
            COUNT(*),                  
            0,                  
            0,                  
            0,                  
            0,                  
            GETDATE(),                  
            NULL,                  
            NULL,                  
            NULL,                  
            NULL,                  
            NULL,                  
            NULL,                  
            0,                  
            A.MailSubject,                  
            A.ReplyTo,                  
            COUNT(*),                  
            'INR'                  
     FROM   #tempTable A                  
     GROUP BY                  
            A.AccountID,                  
            A.SenderName,                  
            A.MailSubject,                  
            A.ReplyTo                   
                       
     INSERT INTO ClientEmails                  
       (                  
         -- Id -- this column value is auto-generated                  
         GUID,                  
         Email_Id,                  
         SentDateTime,                  
         UserId,                  
         ReplyTo,                  
         [Status],                  
         BatchID,                  
         [Message]                  
       )                  
     SELECT NEWID(),                  
            A.EmailID,                  
            GETDATE(),                  
            A.AccountID,                  
            A.ReplyTo,                  
            '',                  
            @BatchID,                  
            A.MailContent                  
     FROM   #tempTable A                  
                       
     INSERT INTO EmailsFilter                  
       (                  
         Mail_GUID,                  
         -- Mail_ID -- this column value is auto-generated                  
         Mail_FromEmail,                  
         Mail_ToEmail,                  
         Mail_Subject,                  
         Mail_TempleteName,                  
         Messages,                  
         Mail_InsertedDate,                  
         Mail_UserID,                  
         ReplyTo,                  
         Mail_BatchID,                  
         Mail_Priority,                  
         Mail_ScheduleDate,                  
         Mail_Attechement,                  
         Mail_TempleteBody,              
         IsMonitor                  
       )                  
     SELECT NEWID(),                  
            @Mail_FromEmail,                  
 A.EmailID,                  
            A.MailSubject,                  
            '',                  
            A.MailContent,                            GETDATE(),                  
            A.AccountID,                  
            A.ReplyTo,                  
            @BatchID,                  
            0,                  
            NULL,                  
            0,                  
            A.MailContent,              
            @IsMonitor                  
     FROM   #tempTable A            
               
      update EmailsFilter set EmailsFilter.Mail_Priority=2          
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                 
                       
     INSERT INTO MailCreditDetails                  
       (                  
         FromUser_ID,                  
         M_ID,                  
         USER_ID,                  
         Debits,                  
         Credits,                  
         Balance ,                
         Validity                 
       )                  
     VALUES                  
       (                  
         @Account,                  
         @m_id,                  
         @Account,                  
         @MailCount,                  
         0,                  
         @Balance,                
         99999                  
   )    
   */
   
  if(@UserId  > 0 )        
 begin        
  declare @leadActivityHistory AS LeadActivitywithid_Tbltype        
  declare  @Username nvarchar(255) = ( select User_Login from User_Detail(nolock) where User_Id = @UserId)         
  insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )        
   select         
    leadid,        
    @UserId,         
    @parentid,        
    concat(@Username , ' sent a mail with subject ',  MailSubject, ' to emailid ', EmailID),        
    'Mail sent to lead',        
    'Batchemail_infos',            
    @BatchID        
   from #tempTable        
        
  exec UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory        
 end  
   
   
   
                     
     SELECT 'Success'                  
 END                  
 ELSE                  
 BEGIN                  
     SELECT 'Insufficient Balance'                  
 END                  
                   
 DROP TABLE #tempTable                  
END 




