/* ============================================================
   Procedure: [dbo].[usp_SendMailFromLeads_WithTemplateID_FromMailID_ViaOtherDB]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SendMailFromLeads_WithTemplateID_FromMailID_ViaOtherDB]
     @IDS VARCHAR(MAX)
	,@Account BIGINT
	,@Email_Subject VARCHAR(1000)
	,@Message_TemplateID BIGINT
	,@SenderName VARCHAR(100)
	,@ReplyTo VARCHAR(1000)
	,@EmailId BIT
	,@EmailId1 BIT
	,@EmailId2 BIT
	,@UserId BIGINT = 0
	,@FromMailID VARCHAR(500)
AS
BEGIN
	DECLARE @tname NVARCHAR(200)

	SELECT @Email_Subject = isnull(nullif(@Email_Subject, ''), (
				SELECT mailsubject
				FROM UserMailTemplate(NOLOCK)
				WHERE id = @message_templateID
				))

	DECLARE @MailCount BIGINT
		,@IsMonitor BIT = 1
	DECLARE @m_id BIGINT
		,@parentid BIGINT

	SELECT @m_id = ud.M_ID
		,@parentid = parentid
	FROM User_Detail AS ud(NOLOCK)
	WHERE ud.[User_ID] = @Account

	SELECT @MailCount = (
			SELECT count(1)
			FROM dbo.fn_split(@IDS, '#')
			)

	DECLARE @CurrentBalance BIGINT = (
			SELECT TOP 1 mcd.Balance
			FROM MailCreditDetails AS mcd(NOLOCK)
			WHERE mcd.[User_ID] = @parentid
			ORDER BY mcd.Credit_ID DESC
			)
	DECLARE @Balance BIGINT = @CurrentBalance - @MailCount

	IF @Balance > 0
	BEGIN
		DECLARE @Message VARCHAR(MAX)

		SELECT @Message = MailContent
			,@tname = Name
		FROM UserMailTemplate(NOLOCK)
		WHERE ID = @Message_TemplateID

		SELECT A.EmailID
			,A.AccountID
			,A.SenderName
			,A.MailContent
			,A.MailSubject
			,A.ReplyTo
			,A.leadid
		INTO #tempTable
		FROM (
			SELECT ISNULL(A.EmailID, '') AS EmailID
				,@Account AS AccountID
				,@SenderName AS SenderName
				,A.MailContent
				,@Email_Subject AS MailSubject
				,@ReplyTo AS ReplyTo
				,Leadid
			FROM (
				SELECT CASE 
						WHEN @EmailId = 1
							THEN ul.EmailID
						ELSE ''
						END AS EmailID
					,dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID) AS MailContent
					,ul.ID AS leadid
				FROM UserLeads AS ul(NOLOCK)
				WHERE ul.ID IN (
						SELECT [value]
						FROM dbo.fn_Split(@IDS, '#') AS fs
						)
					AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') <> ''
					AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') NOT IN (
						SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
						FROM UserLeads UETemp(NOLOCK)
						INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID = C_UDTemp.Email)
						WHERE ul.ID IN (
								SELECT fs.value
								FROM dbo.fn_Split(@IDS, '#') AS fs
								)
						)
				
				UNION ALL
				
				SELECT CASE 
						WHEN @EmailId1 = 1
							THEN ul.EmailID1
						ELSE ''
						END AS EmailID
					,dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)
					,ul.ID AS leadid
				FROM UserLeads AS ul(NOLOCK)
				WHERE ul.ID IN (
						SELECT [value]
						FROM dbo.fn_Split(@IDS, '#') AS fs
						)
					AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') <> ''
					AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') NOT IN (
						SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
						FROM UserLeads UETemp(NOLOCK)
						INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID1 = C_UDTemp.Email)
						WHERE ul.ID IN (
								SELECT fs.value
								FROM dbo.fn_Split(@IDS, '#') AS fs
								)
						)
				
				UNION ALL
				
				SELECT CASE 
						WHEN @EmailId2 = 1
							THEN ul.EmailID2
						ELSE ''
						END AS EmailID
					,dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)
					,ul.ID AS leadid
				FROM UserLeads AS ul(NOLOCK)
				WHERE ul.ID IN (
						SELECT [value]
						FROM dbo.fn_Split(@IDS, '#') AS fs
						)
					AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') <> ''
					AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') NOT IN (
						SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
						FROM UserLeads UETemp(NOLOCK)
						INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID2 = C_UDTemp.Email)
						WHERE ul.ID IN (
								SELECT fs.value
								FROM dbo.fn_Split(@IDS, '#') AS fs
								)
						)
				) A
			WHERE ISNULL(A.EmailID, '') <> ''
			) A

		DECLARE @Status BIGINT = 0
			,@CountLimit BIGINT = 0

		SELECT @Status = STATUS
			,@CountLimit = Plimit
		FROM ProcessMailLimit

		IF (@Status = 1)
		BEGIN
			BEGIN
				IF (@MailCount > @CountLimit)
				BEGIN
					SET @IsMonitor = 0
				END
			END
		END

		DECLARE @BatchID BIGINT

		BEGIN TRAN

		INSERT INTO GetBatchRecord (
			[User_id]
			,RandNum
			)
		VALUES (
			@Account
			,@Account
			)

		SELECT @BatchID = SCOPE_IDENTITY()

		DELETE
		FROM GetBatchRecord
		WHERE batchid = @BatchID

		COMMIT

		DECLARE @Mail_FromEmail VARCHAR(500) = ''

		SELECT @Mail_FromEmail = coalesce((
					SELECT TOP 1 mail_id
					FROM defaultmailid(NOLOCK)
					WHERE user_id = @account
					ORDER BY datecreated DESC
					), (
					SELECT ud.EMail
					FROM User_Detail AS ud(NOLOCK)
					WHERE ud.[User_ID] = @Account
					), 'contactus@email19.in')

		IF (rtrim(ltrim(@FromMailID)) <> '')
		BEGIN
			SET @Mail_FromEmail = @FromMailID
		END
		
	   INSERT INTO BatchEmail_Infos                                  
        (                                  
         -- ID -- this column value is auto-generated                                  
         BatchID,                                  
         UserID,                                  
         SenderName,                                  
         [Message],                                  
         TotalRecords,                                  
         TotalProcessed,                                  
         ProcessTable,                                  
         IsProcess,                                  
         Priority_Level,                                  
         BatchInsertTime,                                  
         BatchProcessTime,                                  
         ScheduledDate,                                  
         ScheduledTime,                                  
         TemplateID,                                  
         [Route],                                  
         PageName,                                  
         IsScheduled,                                  
         Email_Subject,                                  
         ReplyTo,                                  
        Amount,                                  
         Currency                                  
       )                                  
     SELECT @BatchID,                                  
            A.AccountID,                                  
            --A.SenderName,
			@Mail_FromEmail,
            @Message,                                  
            COUNT(*),                                  
            0,                                  
            0,                                  
            0,                                  
            0,                                 
            GETDATE(),                                  
            NULL,                                  
            NULL,             
            NULL,                                  
            NULL,                                  
            NULL,                                  
            NULL,                                  
            0,                                  
            A.MailSubject,                           
            A.ReplyTo,                                  
            COUNT(*),                                  
            'INR'                                  
     FROM   #tempTable A                                  
     GROUP BY                                  
            A.AccountID,                                  
            --A.SenderName,                                  
            A.MailSubject,                                  
            A.ReplyTo

    INSERT INTO MailCreditDetails                                  
       (                                  
         FromUser_ID,                                  
         M_ID,                                  
         USER_ID,                                  
         Debits,                                  
         Credits,                                  
         Balance ,                              
         Validity                                 
       )                                  
     VALUES                                  
       (                                  
         @Account,                                  
         @m_id,                              
         @Account,                                  
         @MailCount,                                  
         0,                                  
         @Balance  ,                              
         99999                                
       )


		INSERT INTO [10.0.0.135].[MysmsTrans].[dbo].CloneEmailsFilter (
			Mail_FromEmail
			,Mail_ToEmail
			,Mail_Subject
			,Mail_TempleteName
			,Messages
			,Mail_InsertedDate
			,Mail_UserID
			,Mail_ParentID
			,ReplyTo
			,Mail_BatchID
			,Mail_Priority
			,Mail_ScheduleDate
			,Mail_ScheduledTime
			,Mail_Attechement
			,Mail_TempleteBody
			,IsMonitor
			,TemplateID
			,Count
			,Source
			,EntityName
            ,EntityID
            ,IsMatched
			)
		SELECT @Mail_FromEmail
			,A.EmailID
			,A.MailSubject
			,isnull(@tname, '')
			,A.MailContent
			,GETDATE()
			,@UserId
			,@parentid
			,A.ReplyTo
			,@BatchID
			,1
			,''
			,''
			,''
			,A.MailContent
			,@ismonitor
			,0
			,@mailcount
			,'Lead-MassSend'
			,'Lead'
		    ,leadid
		    ,0
		FROM #tempTable A

		/*                                
     INSERT INTO BatchEmail_Infos                            
       (                            
         -- ID -- this column value is auto-generated                          
         BatchID,                            
         UserID,                            
         SenderName,                            
         [Message],                            
         TotalRecords,                            
         TotalProcessed,                            
         ProcessTable,                            
         IsProcess,                            
         Priority_Level,                        
         BatchInsertTime,                            
         BatchProcessTime,                            
         ScheduledDate,                            
         ScheduledTime,                            
         TemplateID,                            
         [Route],                            
         PageName,                            
         IsScheduled,                            
         Email_Subject,                            
         ReplyTo,                            
         Amount,                            
         Currency                            
       )                            
     SELECT @BatchID,                            
            A.AccountID,                            
            A.SenderName,                            
            @Message,                            
            COUNT(*),           
            0,                            
            0,                            
            0,                            
            0,                            
            GETDATE(),                            
            NULL,                            
            NULL,                            
            NULL,                            
            NULL,                        
            NULL,                            
            NULL,                            
            0,                            
            A.MailSubject,                            
            A.ReplyTo,                            
            COUNT(*),                            
            'INR'                            
     FROM   #tempTable A                            
     GROUP BY                            
            A.AccountID,                            
            A.SenderName,                            
            A.MailSubject,              
            A.ReplyTo                             
                                 
     INSERT INTO ClientEmails                            
       (                            
         -- Id -- this column value is auto-generated                            
         GUID,                            
         Email_Id,                            
         SentDateTime,                            
         UserId,                            
         ReplyTo,                            
         [Status],             
         BatchID,                            
         [Message]                            
       )                            
     SELECT NEWID(),                            
            A.EmailID,                            
            GETDATE(),                            
            A.AccountID,                            
            A.ReplyTo,                            
            '',                            
            @BatchID,                            
            A.MailContent                            
     FROM   #tempTable A                            
                                 
     INSERT INTO EmailsFilter                            
       (                            
         Mail_GUID,                            
         -- Mail_ID -- this column value is auto-generated                        
         Mail_FromEmail,                            
         Mail_ToEmail,                            
         Mail_Subject,                            
         Mail_TempleteName,                            
         Messages,                            
         Mail_InsertedDate,                            
         Mail_UserID,                            
         ReplyTo,                            
         Mail_BatchID,                            
         Mail_Priority,                            
         Mail_ScheduleDate,                            
         Mail_Attechement,                            
         Mail_TempleteBody,                        
         IsMonitor                            
       )                            
     SELECT NEWID(),                            
            @Mail_FromEmail,                            
            A.EmailID,                            
            A.MailSubject,                            
            '',                            
            A.MailContent,                            
            GETDATE(),                            
            A.AccountID,                            
            A.ReplyTo,                            
            @BatchID,                            
            0,                            
            NULL,                            
            0,                            
            A.MailContent,                        
            @IsMonitor                            
     FROM   #tempTable A                   
                       
     update EmailsFilter set EmailsFilter.Mail_Priority=2                  
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                                  
                                 
     INSERT INTO MailCreditDetails                            
       (                            
         FromUser_ID,                            
         M_ID,                            
         USER_ID,                            
         Debits,                            
         Credits,                            
         Balance ,                          
         Validity                           
       )                            
   VALUES                            
       (                            
         @Account,                            
         @m_id,                            
  @Account,                            
         @MailCount,                            
         0,                            
         @Balance,                          
         99999                            
       )                            
    */
		IF (@UserId > 0)
		BEGIN
			DECLARE @leadActivityHistory AS LeadActivitywithid_Tbltype
			DECLARE @Username NVARCHAR(255) = (
					SELECT User_Login
					FROM User_Detail(NOLOCK)
					WHERE User_Id = @UserId
					)

			INSERT INTO @leadActivityHistory (
				LeadID
				,UserID
				,ParentID
				,EventDescription
				,EventName
				,RefTable
				,refid
				)
			SELECT leadid
				,@UserId
				,@parentid
				,CONCAT (
					@Username
					,' sent a mail with subject '
					,MailSubject
					,' to emailid '
					,EmailID
					)
				,'Mail sent to lead'
				,'Batchemail_infos'
				,@BatchID
			FROM #tempTable

			EXEC UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory
		END

		SELECT 'Success'
	END
	ELSE
	BEGIN
		SELECT 'Insufficient Balance'
	END

	DROP TABLE

	IF EXISTS #tempTable
		DECLARE @rowJson NVARCHAR(MAX) = (
				SELECT *
				FROM [10.0.0.135].[MysmsTrans].[dbo].CloneEmailsFilter
				WHERE Mail_BatchID = @BatchID
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'Inst_Mail_Lead'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'CloneEmailsFilter'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_SendMailFromLeads_WithTemplateID_Shaired]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_SendMailFromLeads_WithTemplateID_Shaired               
 @IDS VARCHAR(MAX),                
 @Account BIGINT,                
 @Email_Subject VARCHAR(1000),                
 @Message_TemplateID Bigint,                
 @SenderName VARCHAR(100),                
 @ReplyTo VARCHAR(1000),                
 @EmailId BIT ,                
 @EmailId1 BIT ,                
 @EmailId2 BIT                
AS                
BEGIN                
        
   Declare @Message VARCHAR(MAX)         
        
  select @Message = MailContent  From UserMailTemplate where ID= @Message_TemplateID        
        
 SELECT A.EmailID,                
        A.AccountID,                
        A.SenderName,                
        A.MailContent,                
        A.MailSubject,                
        A.ReplyTo INTO #tempTable                
 FROM   (                
            SELECT ISNULL(A.EmailID, '') AS EmailID,                
                   @Account        AS AccountID,                
                   @SenderName     AS SenderName,                
                   A.MailContent,                
                   @Email_Subject  AS MailSubject,                
                   @ReplyTo        AS ReplyTo                
            FROM   (                
                       SELECT CASE                 
                                   WHEN @EmailId = 1 THEN ul.EmailID                
                                   ELSE ''                
                              END AS EmailID,                
                              dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID) AS                 
                              MailContent                
                       FROM   UserLeads AS ul                
                       WHERE  ul.ID IN (SELECT [value]                
                                        FROM   dbo.fn_Split(@IDS, '#') AS fs)      
                                         AND ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') <> ''       
                      AND ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') not in       
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID       
                      from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp      
                      on (UETemp.EmailID =C_UDTemp.Email)      
                          
                      where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))     
                                            
                                                      
                       UNION ALL                 
                                       
                       SELECT CASE                 
                                   WHEN @EmailId1 = 1 THEN ul.EmailID1                
                                   ELSE ''                
                              END AS EmailID,                
                              dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)                
                       FROM   UserLeads AS ul                
                       WHERE  ul.ID IN (SELECT [value]                
                                        FROM   dbo.fn_Split(@IDS, '#') AS fs)    
                                            
                                          AND ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') <> ''       
                      AND ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') not in       
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID       
                      from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp      
                      on (UETemp.EmailID1 =C_UDTemp.Email)      
                          
                      where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))                
                       UNION ALL                
                                       
                       SELECT CASE                 
                                   WHEN @EmailId2 = 1 THEN ul.EmailID2                
                                   ELSE ''                
                              END AS EmailID,                
                              dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)                
                       FROM   UserLeads AS ul                
                       WHERE  ul.ID IN (SELECT [value]                
                                        FROM   dbo.fn_Split(@IDS, '#') AS fs)    
                                          AND ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') <> ''       
                      AND ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') not in       
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID       
                      from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp      
                      on (UETemp.EmailID2 =C_UDTemp.Email)      
                          
                      where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))     
                                            
                                            
                                                        
                   )                  A                
            WHERE  ISNULL(A.EmailID, '') <> ''                
        ) A                
                 
 DECLARE @MailCount BIGINT ,@IsMonitor Bit = 1                
 SELECT @MailCount = COUNT(*)                
 FROM   #tempTable                
                 
                 
  Declare @Status Bigint=0,@CountLimit bigint = 0            
   select @Status = status,@CountLimit = Plimit from ProcessMailLimit                   
      if(@Status = 1)            
      Begin            
    Begin            
      if(@MailCount >  @CountLimit )            
      Begin            
       set @IsMonitor = 0             
      End            
     End            
       End            
                 
                 
 DECLARE @CurrentBalance BIGINT = (                
             SELECT TOP 1 mcd.Balance                
             FROM   MailCreditDetails AS mcd                
             WHERE  mcd.[User_ID] = @Account                
             ORDER BY                
                    mcd.Credit_ID DESC                
         )                
                 
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount                
 IF @Balance > 0                
 BEGIN                
     DECLARE @m_id BIGINT = (                           SELECT TOP 1 ud.M_ID                
                 FROM   User_Detail AS ud                
                 WHERE  ud.[User_ID] = @Account                
             )                
                     
     INSERT INTO GetBatchRecord                
       (                
         [User_id],                
         RandNum                
       )                
     VALUES               (                
         @Account,                
         @Account                
       )                      
                     
     DECLARE @BatchID BIGINT = (                
                 SELECT MAX(gbr.BatchID)                
                 FROM  GetBatchRecord AS gbr                
                 WHERE  gbr.[User_id] = @Account                
             )                    
                     
     DELETE                 
     FROM   GetBatchRecord                
     WHERE  [User_id] = @Account                   
                     
                     
                     
     DECLARE @Mail_FromEmail VARCHAR(500) = ''                  
                     
     SELECT @Mail_FromEmail = ud.EMail                
     FROM   User_Detail          AS ud                
            LEFT JOIN User_Type  AS ut(NOLOCK)                
                 ON  ud.UserType = ut.ID                
     WHERE  ud.[User_ID] = @Account                 
                     
     INSERT INTO BatchEmail_Infos                
       (                
         -- ID -- this column value is auto-generated              
         BatchID,                
         UserID,                
         SenderName,                
         [Message],                
         TotalRecords,                
         TotalProcessed,                
         ProcessTable,                
         IsProcess,                
         Priority_Level,            
         BatchInsertTime,                
         BatchProcessTime,                
         ScheduledDate,                
         ScheduledTime,                
         TemplateID,                
         [Route],                
         PageName,                
         IsScheduled,                
         Email_Subject,                
         ReplyTo,                
         Amount,                
         Currency                
       )                
     SELECT @BatchID,                
            A.AccountID,                
            A.SenderName,                
            @Message,                
            COUNT(*),                
            0,                
            0,                
            0,                
            0,                
            GETDATE(),                
            NULL,                
            NULL,                
            NULL,                
            NULL,                
            NULL,                
            NULL,                
            0,                
            A.MailSubject,                
            A.ReplyTo,                
            COUNT(*),                
            'INR'                
     FROM   #tempTable A                
     GROUP BY                
            A.AccountID,                
            A.SenderName,                
            A.MailSubject,                
            A.ReplyTo                 
                     
     INSERT INTO ClientEmails                
       (                
         -- Id -- this column value is auto-generated                
         GUID,                
         Email_Id,                
         SentDateTime,                
         UserId,                
         ReplyTo,                
         [Status],                
         BatchID,                
         [Message]                
       )                
     SELECT NEWID(),                
            A.EmailID,                
            GETDATE(),                
            A.AccountID,                
            A.ReplyTo,                
            '',                
            @BatchID,                
            A.MailContent                
     FROM   #tempTable A                
                     
     INSERT INTO EmailsFilter                
       (                
         Mail_GUID,                
         -- Mail_ID -- this column value is auto-generated            
         Mail_FromEmail,                
         Mail_ToEmail,                
         Mail_Subject,                
         Mail_TempleteName,                
         Messages,                
         Mail_InsertedDate,                
         Mail_UserID,                
         ReplyTo,                
         Mail_BatchID,                
         Mail_Priority,                
         Mail_ScheduleDate,                
         Mail_Attechement,                
         Mail_TempleteBody,            
         IsMonitor                
       )                
     SELECT NEWID(),                
            @Mail_FromEmail,                
            A.EmailID,                
            A.MailSubject,                
            '',                
            A.MailContent,                
            GETDATE(),                
            A.AccountID,                
            A.ReplyTo,                
            @BatchID,                
            0,                
            NULL,                
            0,                
            A.MailContent,            
            @IsMonitor                
     FROM   #tempTable A       
           
     update EmailsFilter set EmailsFilter.Mail_Priority=2      
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                      
                     
     INSERT INTO MailCreditDetails                
       (                
         FromUser_ID,                
         M_ID,                
         USER_ID,                
         Debits,                
         Credits,                
         Balance ,              
         Validity               
       )                
     VALUES                
       (                
         @Account,                
         @m_id,                
  @Account,                
         @MailCount,                
         0,                
         @Balance,              
         99999                
       )                
     SELECT 'Success'                
 END                
 ELSE                
 BEGIN                
     SELECT 'Insufficient Balance'                
 END                
                 
 DROP TABLE #tempTable                
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_SendMailFromLeads_WithTemplateID_WithFromMailID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SendMailFromLeads_WithTemplateID_WithFromMailID]                   
 @IDS VARCHAR(MAX),                      
 @Account BIGINT,                      
 @Email_Subject VARCHAR(1000),                      
 @Message_TemplateID Bigint,                      
 @SenderName VARCHAR(100),                      
 @ReplyTo VARCHAR(1000),                      
 @EmailId BIT ,                      
 @EmailId1 BIT ,                      
 @EmailId2 BIT,    
 @FromMailID nvarchar(max) = '',  
 @UserId bigint  
AS                      
BEGIN          

CREATE TABLE #TableData2 ( ID BIGINT )
		  
INSERT INTO #TableData2 (ID)           
SELECT fs.[value] FROM   dbo.fn_Split(@IDS, '#') fs

select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))            
DECLARE @MailCount BIGINT,@IsMonitor Bit = 1             
DECLARE @m_id BIGINT,@parentid bigint      
 SELECT @m_id= ud.M_ID,@parentid=parentid                              
                 FROM   User_Detail AS ud (nolock)                             
                 WHERE  ud.[User_ID] = @Account                        
 SELECT @MailCount = (select count(1) from #TableData2 --dbo.fn_split(@IDS,'#')
 )                         
  DECLARE @CurrentBalance BIGINT = (                            
             SELECT TOP 1 mcd.Balance                            
             FROM   MailCreditDetails AS mcd   (nolock)                         
             WHERE  mcd.[User_ID] = @parentid                            
             ORDER BY mcd.Credit_ID DESC                            
         )                                        
                         
                             
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount                            
  IF @Balance > 0                              
 BEGIN                              
             
   Declare @Message VARCHAR(MAX)               
              
  select @Message = MailContent  From UserMailTemplate(nolock) where ID= @Message_TemplateID              
              
 SELECT A.EmailID,                      
        A.AccountID,                      
        A.SenderName,                      
        A.MailContent,                      
        A.MailSubject,     
        A.ReplyTo,  
  A.LeadId INTO #tempTable                      
 FROM   (                      
            SELECT ISNULL(A.EmailID, '') AS EmailID,                      
                   @Account        AS AccountID,                      
                   @SenderName     AS SenderName,                      
                   A.MailContent,                      
                   @Email_Subject  AS MailSubject,                      
                   @ReplyTo        AS ReplyTo,  
       LeadId  
            FROM   (                      
                       SELECT CASE                       
                                   WHEN @EmailId = 1 THEN ul.EmailID                      
                                   ELSE ''                      
                              END AS EmailID,                      
                              dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID) AS                       
                              MailContent,  
         ul.ID as LeadId  
                       FROM   UserLeads AS ul  (nolock)                    
						inner join #TableData2 tb2 on ul.ID = tb2.ID 
                       WHERE  --ul.ID IN (SELECT [value] FROM   dbo.fn_Split(@IDS, '#') AS fs) AND 
										ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') <> ''             
                      AND ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') not in             
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID             
                      from UserLeads UETemp(nolock) inner join Client_UnSubscribeDetails C_UDTemp  (nolock)          
                      on (UETemp.EmailID =C_UDTemp.Email)            
						inner join #TableData2 tb2 on UETemp.ID = tb2.ID 
                                
                      --where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs )
					  )           
                                 
                                                            
                       UNION ALL                
                                             
                       SELECT CASE                       
                                   WHEN @EmailId1 = 1 THEN ul.EmailID1               
                                   ELSE ''                      
                              END AS EmailID,                      
                              dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1),  
         ul.ID as LeadId  
                       FROM   UserLeads AS ul (nolock)                     
						inner join #TableData2 tb2 on ul.ID = tb2.ID 
                       WHERE  --ul.ID IN (SELECT [value] FROM   dbo.fn_Split(@IDS, '#') AS fs) AND 
					   ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') <> ''             
                      AND ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') not in             
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID             
                      from UserLeads UETemp(nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)           
                      on (UETemp.EmailID1 =C_UDTemp.Email)            
 						inner join #TableData2 tb2 on UETemp.ID = tb2.ID 
          
                      --where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs )
					  )                      
                       UNION ALL                      
                                             
                       SELECT CASE                       
                                   WHEN @EmailId2 = 1 THEN ul.EmailID2                      
                                   ELSE ''                      
                              END AS EmailID,                      
                              dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2) ,  
         ul.ID as LeadId                     
                       FROM   UserLeads AS ul (nolock)                     
						inner join #TableData2 tb2 on ul.ID = tb2.ID 

                       WHERE  --ul.ID IN (SELECT [value] FROM   dbo.fn_Split(@IDS, '#') AS fs) AND         
						ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') <> ''             
                      AND ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') not in             
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID             
                      from UserLeads UETemp(nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)           
                      on (UETemp.EmailID2 =C_UDTemp.Email)            
						inner join #TableData2 tb2 on UETemp.ID = tb2.ID 
                                
                      --where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs )
					  )           
                                                  
                                                  
                                                              
                   )                  A                      
            WHERE  ISNULL(A.EmailID, '') <> ''                      
        ) A                      
                       
                       
                       
  Declare @Status Bigint=0,@CountLimit bigint = 0                  
   select @Status = status,@CountLimit = Plimit from ProcessMailLimit                         
      if(@Status = 1)                  
      Begin                  
    Begin                  
      if(@MailCount >  @CountLimit )                  
      Begin                  
       set @IsMonitor = 0                   
      End                  
     End                  
       End                  
                       
       
                                   
 DECLARE @BatchID BIGINT      
 begin tran                                
 INSERT INTO GetBatchRecord                            
       (                            
         [User_id],                            
   RandNum                            
       )               
     VALUES                            
       (                            
         @Account,                            
         @Account                            
       )                                  
select @BatchID=SCOPE_IDENTITY()                                 
DELETE                          
     FROM GetBatchRecord                            
     WHERE batchid=@BatchID      
 commit                                
                                   
   DECLARE @Mail_FromEmail NVARCHAR(500) = ''                              
     
  if(@FromMailID = '')    
    Begin       
   select @Mail_FromEmail=coalesce((select top 1 mail_id from defaultmailid(nolock) where user_id=@account order by datecreated desc),      
    (SELECT ud.EMail FROM   User_Detail AS ud  (nolock) WHERE  ud.[User_ID] = @Account),'contactus@email19.in')       
    end    
  else    
   Begin    
     set @Mail_FromEmail = @FromMailID       
   End       
    
insert into CloneEmailsFilter(Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,      
Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source)      
select @Mail_FromEmail,A.EmailID,A.MailSubject,'',A.MailContent,GETDATE(),A.AccountID,@parentid,A.ReplyTo,@BatchID,1,'','','',A.MailContent,@ismonitor,0,@mailcount,'Lead-MassSend'      
from #tempTable A      
/*                          
     INSERT INTO BatchEmail_Infos                      
       (                      
         -- ID -- this column value is auto-generated                    
         BatchID,                      
         UserID,                      
         SenderName,                      
         [Message],                      
         TotalRecords,                      
         TotalProcessed,                      
         ProcessTable,                      
         IsProcess,                      
         Priority_Level,                  
         BatchInsertTime,                      
         BatchProcessTime,                      
         ScheduledDate,                      
         ScheduledTime,                      
         TemplateID,                      
         [Route],                      
         PageName,                      
         IsScheduled,                      
         Email_Subject,                      
         ReplyTo,                      
         Amount,                      
         Currency                      
       )                      
     SELECT @BatchID,                      
            A.AccountID,                      
            A.SenderName,                      
            @Message,                      
            COUNT(*),                      
            0,                      
            0,                      
            0,                      
            0,                      
            GETDATE(),                      
            NULL,                      
            NULL,                      
            NULL,                      
            NULL,                      
            NULL,                      
            NULL,                      
            0,                      
            A.MailSubject,                      
            A.ReplyTo,                      
            COUNT(*),                      
            'INR'                      
     FROM   #tempTable A                      
     GROUP BY                      
            A.AccountID,                      
            A.SenderName,                      
            A.MailSubject,                      
            A.ReplyTo                       
                           
     INSERT INTO ClientEmails                      
       (                      
         -- Id -- this column value is auto-generated                      
         GUID,                      
         Email_Id,                      
         SentDateTime,                      
         UserId,                      
         ReplyTo,                      
         [Status],                      
         BatchID,                      
         [Message]                      
       )                      
     SELECT NEWID(),                      
            A.EmailID,                      
            GETDATE(),                      
            A.AccountID,                      
            A.ReplyTo,                      
 '',                      
            @BatchID,                      
            A.MailContent                      
     FROM   #tempTable A                      
                           
     INSERT INTO EmailsFilter                      
       (                      
         Mail_GUID,                      
         -- Mail_ID -- this column value is auto-generated                  
         Mail_FromEmail,                      
         Mail_ToEmail,                      
         Mail_Subject,                      
         Mail_TempleteName,                      
         Messages,                      
         Mail_InsertedDate,                      
         Mail_UserID,                      
         ReplyTo,                      
         Mail_BatchID,                      
         Mail_Priority,                      
         Mail_ScheduleDate,                      
         Mail_Attechement,                      
         Mail_TempleteBody,                  
         IsMonitor                      
       )                      
     SELECT NEWID(),                      
            @Mail_FromEmail,                      
            A.EmailID,                      
            A.MailSubject,                      
            '',                      
            A.MailContent,                      
            GETDATE(),                      
            A.AccountID,                      
            A.ReplyTo,                      
            @BatchID,                      
            0,                      
            NULL,                      
            0,                      
            A.MailContent,                  
            @IsMonitor                      
     FROM   #tempTable A             
                 
     update EmailsFilter set EmailsFilter.Mail_Priority=2            
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                            
                           
     INSERT INTO MailCreditDetails                      
       (                      
         FromUser_ID,                      
         M_ID,                      
         USER_ID,                      
         Debits,                      
         Credits,                      
         Balance ,                    
         Validity                     
       )                      
     VALUES                      
       (                      
         @Account,                      
         @m_id,                      
  @Account,                      
         @MailCount,                      
         0,                      
         @Balance,                    
         99999                      
       )                      
    */   
   
 if(@UserId  > 0 )  
 begin  
  declare @leadActivityHistory AS LeadActivitywithid_Tbltype  
  declare  @Username nvarchar(255) = ( select User_Login from User_Detail(nolock) where User_Id = @UserId)   
  insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )  
   select   
    leadid,  
    @UserId,   
    @parentid,  
    concat(@Username , ' sent a mail with subject ',  MailSubject, ' to emailid ', EmailID),  
    'Mail sent to lead',  
    'Batchemail_infos',      
    @BatchID  
   from #tempTable  
  
  exec UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory  
 end  
  
     SELECT 'Success'                      
 END                      
 ELSE                      
 BEGIN                      
     SELECT 'Insufficient Balance'     
 END                      
                       
 DROP TABLE #tempTable                      
END 






GO

/* ============================================================
   Procedure: [dbo].[usp_SendMailFromLeadsOld]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_SendMailFromLeadsOld] 

(
    @IDS               VARCHAR(MAX),
    @Account           BIGINT,
    @Email_Subject     VARCHAR(1000),
    @Message           VARCHAR(2000),
    @SenderName        VARCHAR(100),
    @ReplyTo           VARCHAR(1000),
    @EmailId           VARCHAR(10),
    @EmailId1          VARCHAR(10),
    @EmailId2          VARCHAR(10)
)
AS
BEGIN
	BEGIN TRY
		BEGIN TRANSACTION 
		
		--DECLARE @IDS VARCHAR(MAX)=''  
		
		DECLARE @TotalCreditCount INT = 0;  
		
		DECLARE @Balance INT = 0 
		
		--SET @IDS='245';  
		
		
		
		DECLARE @Balance_TableData TABLE
		        
		        ([User_ID] BIGINT, Balance BIGINT, Credit_ID INT)
		
		INSERT INTO @Balance_TableData
		  (
		    [User_ID],
		    Balance,
		    Credit_Id
		  )
		SELECT [User_ID],
		       ISNULL(Balance, 0),
		       Credit_ID
		FROM   MailCreditDetails AS mcd
		WHERE  mcd.[User_ID] IN (@Account)
		ORDER BY
		       DateCreated DESC
		
		
		
		SELECT @Balance = ISNULL(Balance, 0)
		FROM   @Balance_TableData
		WHERE  Credit_ID = (
		           SELECT MAX(Credit_ID)
		           FROM   @Balance_TableData
		       )
		ORDER BY
		       Credit_ID DESC
		
		
		
		--SELECT  @Balance =Isnull(Balance,0)   FROM MailCreditDetails AS mcd     
		
		--WHERE  mcd.[User_ID] IN(@Account)  AND Credit_ID=(SELECT MAX(Credit_ID) From MailCreditDetails)  ORDER BY Credit_ID DESC  
		
		
		
		SELECT @TotalCreditCount = COUNT(1)
		FROM   UserLeads ue
		WHERE  ID IN (SELECT fs.[value]
		              FROM   dbo.fn_Split(275, ',') fs)
		       AND (
		               ISNULL(NULLIF(CAST(ue.EmailId AS VARCHAR(100)), ''), '') 
		               <> ''
		               OR ISNULL(NULLIF(CAST(ue.EmailId1 AS VARCHAR(100)), ''), '') 
		                  <> ''
		               OR ISNULL(NULLIF(CAST(ue.EmailId2 AS VARCHAR(100)), ''), '') 
		                  <> ''
		           )
		
		
		
		SET @Balance = @Balance -@TotalCreditCount 
		
		-- SELECT @Balance   
		
		IF (@Balance > 0)
		BEGIN
		    -------------------
		    
		    ----------------------Debit -------------------  
		    
		    DECLARE @rmid BIGINT,
		            @ruid BIGINT,
		            @rbal BIGINT,
		            @rcid BIGINT,
		            @MIDUser BIGINT        
		    
		    DECLARE @rvalidity           NVARCHAR(300),
		            @rdefault_credit     NVARCHAR(300),
		            @finalbalance        BIGINT,
		            @rCredit             BIGINT,
		            @uCredits            BIGINT              
		    
		    
		    
		    SELECT TOP(1) @MIDUser = m_id
		    FROM   User_Detail
		    WHERE  USER_ID = @Account            
		    
		    SELECT TOP(1) @rmid = m_id,
		           @ruid           = USER_ID
		    FROM   reseller_detail
		    WHERE  reseller_id     = @MIDUser        
		    
		    SELECT TOP(1) @rbal = balance,
		           @rvalidity           = validity,
		           @rdefault_credit     = default_credit,
		           @rCredit             = credits,
		           @rcid                = credit_id
		    FROM   MailCreditDetails
		    WHERE  m_id                 = @rmid
		           AND USER_ID          = @ruid
		    ORDER BY
		           credit_id DESC 
		    
		    
		    
		    --@balanceValue   
		    
		    --Debit        
		    
		    INSERT INTO MailCreditDetails
		      (
		        FromUser_ID,
		        M_ID,
		        USER_ID,
		        Debits,
		        Credits,
		        Balance,
		        Validity,
		        Default_Credit
		      )
		    VALUES
		      (
		        @Account,
		        @rmid,
		        @ruid,
		        0,
		        @TotalCreditCount,
		        @finalbalance,
		        @rvalidity,
		        @rdefault_credit
		      ) 
		    
		    ------------------------------------------  
		    
		    
		    
		    -------------For Mail information--------------------------   
		    
		    INSERT INTO GetBatchRecord
		      (
		        [User_id],
		        RandNum
		      )
		    VALUES
		      (
		        @Account,
		        @Account
		      )      
		    
		    DECLARE @BatchID BIGINT = (
		                SELECT MAX(gbr.BatchID)
		                FROM   GetBatchRecord AS gbr
		                WHERE  gbr.[User_id] = @Account
		            )    
		    
		    DELETE 
		    FROM   GetBatchRecord
		    WHERE  [User_id] = @Account   
		    
		    
		    
		    DECLARE @Mail_FromEmail VARCHAR(100) = ''  
		    
		    SELECT @Mail_FromEmail = ud.EMail
		    FROM   User_Detail          AS ud
		           LEFT JOIN User_Type  AS ut(NOLOCK)
		                ON  ud.UserType = ut.ID
		    WHERE  ud.[User_ID] = @Account 
		    
		    
		    
		    -- PRINT @Mail_FromEmail  
		    
		    
		    
		    
		    
		    INSERT INTO BatchEmail_Infos
		      (
		        BatchID,
		        UserID,
		        SenderName,
		        MESSAGE,
		        TotalRecords,
		        TotalProcessed,
		        ProcessTable,
		        IsProcess,
		        Priority_Level,
		        BatchInsertTime,
		        TemplateID,
		        PageName,
		        IsScheduled,
		        Email_Subject,
		        ReplyTo,
		        Amount,
		        Currency
		      )
		    SELECT @BatchID   AS BatchID,
		           @Account   AS USERID,
		           @SenderName,
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID) AS 
		           Messagetext,
		           1,
		           0,
		           0,
		           0,
		           0,
		           GETDATE(),
		           0,
		           '',
		           0,
		           @Email_Subject,
		           @ReplyTo,
		           0,
		           '+91'
		    FROM   UserLeads  AS ue
		    WHERE  ue.ID IN (SELECT fs.[value]
		                     FROM   dbo.fn_Split(@IDS, ',') AS fs)
		           AND (
		                   ISNULL(NULLIF(CAST(ue.EmailId AS VARCHAR(100)), ''), '') 
		                   <> ''
		                   OR ISNULL(NULLIF(CAST(ue.EmailId1 AS VARCHAR(100)), ''), '') 
		                      <> ''
		                   OR ISNULL(NULLIF(CAST(ue.EmailId2 AS VARCHAR(100)), ''), '') 
		                      <> ''
		               )      
		    
		    
		    
		    INSERT INTO EmailsFilter
		      (
		        Mail_FromEmail,
		        Mail_ToEmail,
		        Mail_Subject,
		        Mail_TempleteName,
		        Messages,
		        Mail_InsertedDate,
		        Mail_UserID,
		        ReplyTo,
		        Mail_BatchID,
		        Mail_Priority,
		        Mail_ScheduleDate,
		        Mail_Attechement,
		        Mail_TempleteBody
		      )
		    SELECT @Mail_FromEmail,
		           CASE 
		                WHEN @EmailId = '1' THEN ISNULL(CAST(ue.EmailId AS VARCHAR(100)), '')
		                ELSE ''
		           END        AS EmailId,
		           @Email_Subject,
		           '',
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID) AS 
		           Messages,
		           GETDATE(),
		           @Account,
		           '',
		           @BatchID,
		           0,
		           GETDATE(),
		           '',
		           ''
		    FROM   UserLeads     ue
		    WHERE  ID IN (SELECT fs.[value]
		                  FROM   dbo.fn_Split(@IDS, ',') fs)
		           AND ISNULL(NULLIF(CAST(ue.EmailId AS VARCHAR(100)), ''), '') 
		               <>
		               
		               '' 
		    
		    UNION
		    SELECT @Mail_FromEmail,
		           CASE 
		                WHEN @EmailId1 = '1' THEN ISNULL(CAST(ue.EmailId1 AS VARCHAR(100)), '')
		                ELSE ''
		           END        AS EmailId1,
		           @Email_Subject,
		           '',
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID1) AS 
		           Messages,
		           GETDATE(),
		           @Account,
		           '',
		           @BatchID,
		           0,
		           GETDATE(),
		           '',
		           ''
		    FROM   UserLeads     ue
		    WHERE  ID IN (SELECT fs.[value]
		                  FROM   dbo.fn_Split(@IDS, ',') fs)
		           AND ISNULL(NULLIF(CAST(ue.EmailId1 AS VARCHAR(100)), ''), '') 
		               <>
		               
		               '' 
		    
		    UNION
		    SELECT @Mail_FromEmail,
		           CASE 
		                WHEN @EmailId2 = '1' THEN ISNULL(CAST(ue.EmailId2 AS VARCHAR(100)), '')
		                ELSE ''
		           END        AS EmailId2,
		           @Email_Subject,
		           '',
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID2) AS 
		           Messages,
		           GETDATE(),
		           @Account,
		           '',
		           @BatchID,
		           0,
		           GETDATE(),
		           '',
		           ''
		    FROM   UserLeads     ue
		    WHERE  ID IN (SELECT fs.[value]
		                  FROM   dbo.fn_Split(@IDS, ',') fs)
		           AND ISNULL(NULLIF(CAST(ue.EmailId2 AS VARCHAR(100)), ''), '') 
		               <>
		               
		               ''   
		    
		    
		    
		    
		    
		    
		    
		    INSERT INTO ClientEmails
		      (
		        Email_Id,
		        SentDateTime,
		        UserId,
		        ReplyTo,
		        STATUS,
		        BatchID,
		        MESSAGE
		      )
		    SELECT CASE 
		                WHEN @EmailId = '1' THEN ISNULL(NULLIF(CAST(ue.EmailId AS VARCHAR(100)), ''), '')
		                ELSE ''
		           END        AS EmailId,
		           GETDATE(),
		           @Account,
		           '',
		           '',
		           @BatchID,
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID) AS 
		           Messages
		    FROM   UserLeads     ue
		    WHERE  ID IN (SELECT fs.[value]
		                  FROM   dbo.fn_Split(@IDS, ',') fs)
		           AND ISNULL(NULLIF(CAST(ue.EmailId AS VARCHAR(100)), ''), '') 
		               <>
		               
		               '' 
		    
		    UNION
		    SELECT CASE 
		                WHEN @EmailId1 = '1' THEN ISNULL(NULLIF(CAST(ue.EmailId2 AS VARCHAR(100)), ''), '')
		                ELSE ''
		           END        AS EmailId1,
		           GETDATE(),
		           @Account,
		           '',
		           '',
		           @BatchID,
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID1) AS 
		           Messages
		    FROM   UserLeads     ue
		    WHERE  ID IN (SELECT fs.[value]
		                  FROM   dbo.fn_Split(@IDS, ',') fs)
		           AND ISNULL(NULLIF(CAST(ue.EmailId1 AS VARCHAR(100)), ''), '') 
		               <>
		               
		               '' 
		    
		    UNION
		    SELECT CASE 
		                WHEN @EmailId2 = '1' THEN ISNULL(NULLIF(CAST(ue.EmailId2 AS VARCHAR(100)), ''), '')
		                ELSE ''
		           END        AS EmailId2,
		           GETDATE(),
		           @Account,
		           '',
		           '',
		           @BatchID,
		           dbo.fn_getLeadsMailMessage(ue.ParentID, @Message, ue.EmailID2) AS 
		           Messages
		    FROM   UserLeads     ue
		    WHERE  ID IN (SELECT fs.[value]
		                  FROM   dbo.fn_Split(@IDS, ',') fs)
		           AND ISNULL(NULLIF(CAST(ue.EmailId2 AS VARCHAR(100)), ''), '') 
		               <>
		               
		               ''   
		    
		    
		    
		    SELECT 'Record Saved' 
		    
		    COMMIT TRANSACTION
		END
		ELSE
		BEGIN
		    SELECT 'InSuffient Balance'
		END
	END TRY  
	
	BEGIN CATCH
		ROLLBACK TRANSACTION  
		
		
		
		SELECT ERROR_NUMBER()     AS ErrorNumber,
		       ERROR_SEVERITY()   AS ErrorSeverity,
		       ERROR_STATE()      AS ErrorState,
		       ERROR_PROCEDURE()  AS ErrorProcedure,
		       ERROR_LINE()       AS ErrorLine,
		       ERROR_MESSAGE()    AS ErrorMessage
	END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_SendMailFromUser_FromMailID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.usp_SendMailFromUser_FromMailID 
 --@IDS VARCHAR(MAX)    
  @Account BIGINT    
 ,@Email_Subject VARCHAR(1000)    
 ,@Message VARCHAR(MAX)    
 ,@SenderName VARCHAR(100)    
 ,@ReplyTo VARCHAR(1000)    
 ,@EmailId BIT    
 --,@EmailId1 BIT    
 --,@EmailId2 BIT    
 ,@UserId BIGINT = 0    
 ,@FromMailID VARCHAR(500)    
AS    
BEGIN    
 --select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))                    
 DECLARE @MailCount BIGINT    
  ,@IsMonitor BIT = 1    
 DECLARE @m_id BIGINT    
  ,@parentid BIGINT    
    
 SELECT @m_id = ud.M_ID    
  ,@parentid = parentid    
 FROM User_Detail AS ud(NOLOCK)    
 WHERE ud.[User_ID] = @Account    
    
 SELECT @MailCount = (    
   SELECT count(1)    
   FROM dbo.fn_split(@UserId, '#')    
   )    
    
 DECLARE @CurrentBalance BIGINT = (    
   SELECT TOP 1 mcd.Balance    
   FROM MailCreditDetails AS mcd(NOLOCK)    
   WHERE mcd.[User_ID] = @parentid    
   ORDER BY mcd.Credit_ID DESC    
   )    
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount    
    
 IF @Balance > 0    
 BEGIN    
  SELECT   
    A.EmailID,    
    A.AccountID,    
    A.SenderName,    
    A.MailContent,    
    A.MailSubject,    
    A.ReplyTo,    
    A.userid    
INTO #tempTable    
FROM (    
    SELECT   
        ISNULL(A.EmailID, '') AS EmailID,    
        @Account AS AccountID,    
        @SenderName AS SenderName,    
        A.MailContent,    
        @Email_Subject AS MailSubject,    
        @ReplyTo AS ReplyTo,    
        userid    
    FROM (    
        SELECT   
            CASE     
                WHEN @EmailId = 1 THEN ul.Email    
                ELSE ''    
            END AS EmailID,    
            dbo.fn_getUserMailMessage(ul.ParentID, @Message, ul.Email) AS MailContent,    
            ul.User_Id AS userid    
        FROM User_Detail AS ul (NOLOCK)    
        WHERE ul.User_ID IN (    
                SELECT [value]    
                FROM dbo.fn_Split(@UserId, '#') AS fs    
            )    
            AND ISNULL(NULLIF(CAST(ul.Email AS VARCHAR), ''), '') <> ''    
            AND ISNULL(NULLIF(CAST(ul.Email AS VARCHAR), ''), '') NOT IN (    
                SELECT ISNULL(C_UDTemp.Email, '') AS EmailID    
                FROM User_Detail UETemp (NOLOCK)    
                INNER JOIN Client_UnSubscribeDetails C_UDTemp (NOLOCK) ON (UETemp.Email = C_UDTemp.Email)    
                WHERE ul.ID IN (    
                    SELECT fs.value    
                    FROM dbo.fn_Split(@UserId, '#') AS fs    
                )    
            )    
    ) A    
    WHERE ISNULL(A.EmailID, '') <> ''    
) A;  
  
    
  DECLARE @Status BIGINT = 0    
   ,@CountLimit BIGINT = 0    
    
  SELECT @Status = STATUS    
   ,@CountLimit = Plimit    
  FROM ProcessMailLimit    
    
  IF (@Status = 1)    
  BEGIN    
   BEGIN    
    IF (@MailCount > @CountLimit)    
    BEGIN    
     SET @IsMonitor = 0    
    END    
   END    
  END    
    
  DECLARE @BatchID BIGINT    
    
  BEGIN TRAN    
    
  INSERT INTO GetBatchRecord (    
   [User_id]    
   ,RandNum    
   )    
  VALUES (    
   @Account    
   ,@Account    
   )    
    
  SELECT @BatchID = SCOPE_IDENTITY()    
    
  DELETE    
  FROM GetBatchRecord    
  WHERE batchid = @BatchID    
    
  COMMIT    
    
  DECLARE @Mail_FromEmail VARCHAR(500) = ''    
    
  SELECT @Mail_FromEmail = coalesce((    
     SELECT TOP 1 mail_id    
     FROM defaultmailid(NOLOCK)    
     WHERE user_id = @account    
     ORDER BY datecreated DESC    
     ), (    
     SELECT ud.EMail    
     FROM User_Detail AS ud(NOLOCK)    
     WHERE ud.[User_ID] = @Account    
     ), 'contactus@email19.in')    
    
  IF (rtrim(ltrim(@FromMailID)) <> '')    
  BEGIN    
   SET @Mail_FromEmail = @FromMailID    
  END    
    
  INSERT INTO CloneEmailsFilter (    
   Mail_FromEmail    
   ,Mail_ToEmail    
   ,Mail_Subject    
   ,Mail_TempleteName    
   ,Messages    
   ,Mail_InsertedDate    
   ,Mail_UserID    
   ,Mail_ParentID    
   ,ReplyTo    
   ,Mail_BatchID    
   ,Mail_Priority    
   ,Mail_ScheduleDate    
   ,Mail_ScheduledTime    
   ,Mail_Attechement    
   ,Mail_TempleteBody    
   ,IsMonitor    
   ,TemplateID    
   ,Count    
   ,Source    
   )    
  SELECT @Mail_FromEmail    
   ,A.EmailID    
   ,A.MailSubject    
   ,''    
   ,A.MailContent    
   ,GETDATE()    
   ,@UserId    
   ,@parentid    
   ,A.ReplyTo    
   ,@BatchID    
   ,1    
   ,''    
   ,''    
   ,''    
   ,A.MailContent    
   ,@ismonitor    
   ,0    
   ,@mailcount    
   ,'Users-MassSend'    
  FROM #tempTable A    
    
  /*                                 
     INSERT INTO BatchEmail_Infos                            
       (                            
         -- ID -- this column value is auto-generated                            
         BatchID,                            
         UserID,                            
         SenderName,                            
         [Message],                            
         TotalRecords,                            
         TotalProcessed,                            
         ProcessTable,                            
         IsProcess,                            
         Priority_Level,                            
         BatchInsertTime,                            
         BatchProcessTime,                            
         ScheduledDate,                            
         ScheduledTime,                            
         TemplateID,                            
         [Route],                            
         PageName,                            
         IsScheduled,                            
         Email_Subject,                            
         ReplyTo,                            
         Amount,                            
         Currency                            
       )                            
     SELECT @BatchID,                        A.AccountID,                            
            A.SenderName,                            
            @Message,                            
            COUNT(*),                            
            0,                            
            0,                            
            0,                            
            0,                            
            GETDATE(),                            
            NULL,                            
            NULL,                            
            NULL,                            
            NULL,                            
            NULL,                            
            NULL,                            
            0,                            
            A.MailSubject,                            
            A.ReplyTo,                            
            COUNT(*),                            
            'INR'                            
     FROM   #tempTable A                            
     GROUP BY                            
            A.AccountID,                            
            A.SenderName,                            
            A.MailSubject,                            
            A.ReplyTo                             
                                 
     INSERT INTO ClientEmails                     
       (                            
         -- Id -- this column value is auto-generated                            
         GUID,                            
         Email_Id,                            
         SentDateTime,                            
         UserId,                            
         ReplyTo,                            
         [Status],                            
         BatchID,                            
         [Message]                            
       )                            
     SELECT NEWID(),                            
            A.EmailID,                            
