CREATE   PROCEDURE [dbo].[usp_SendMailFromUser_WithTemplateID_FromMailID]                         
 --@IDS VARCHAR(MAX),                            
 @Account BIGINT,                            
 @Email_Subject VARCHAR(1000),                            
 @Message_TemplateID Bigint,                            
 @SenderName VARCHAR(100)='',                            
 @ReplyTo VARCHAR(1000),                            
 @EmailId BIT,                            
 --@EmailId1 BIT,                            
 --@EmailId2 BIT,          
 @UserId bigint = 0,    
 @FromMailID varchar(500)           
AS                            
BEGIN         
declare @tname nvarchar(200)             
select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))                  
 SELECT 
            @SenderName = ISNULL(FName, '') + ' ' + ISNULL(LName, '') 
        FROM 
            User_Detail (NOLOCK)
        WHERE 
            User_ID = @Account;DECLARE @MailCount BIGINT,@IsMonitor Bit = 1                   
DECLARE @m_id BIGINT,@parentid bigint            
 SELECT @m_id= ud.M_ID,@parentid=parentid                                    
                 FROM   User_Detail AS ud (nolock)                                   
                 WHERE  ud.[User_ID] = @Account                              
 SELECT @MailCount = (select count(1) from dbo.fn_split(@UserId,'#'))                               
  DECLARE @CurrentBalance BIGINT = (                                  
             SELECT TOP 1 mcd.Balance                                  
             FROM   MailCreditDetails AS mcd   (nolock)                               
             WHERE  mcd.[User_ID] = @parentid                                  
             ORDER BY mcd.Credit_ID DESC                                  
         )                                              
                               
                                   
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount                                  
  IF @Balance > 0                                    
 BEGIN                                    
                   
   Declare @Message VARCHAR(MAX)                     
                    
  select @Message = MailContent,@tname=Name  From UserMailTemplate(nolock) where ID= @Message_TemplateID                    
                    
 SELECT A.EmailID,                            
        A.AccountID,                            
        A.SenderName,                            
        A.MailContent,                            
        A.MailSubject,                            
        A.ReplyTo,          
  A.leadid          
  INTO #tempTable                            
 FROM   (                            
            SELECT ISNULL(A.EmailID, '') AS EmailID,                            
                   @Account        AS AccountID,                            
                   @SenderName     AS SenderName,                            
                   A.MailContent,                            
                   @Email_Subject  AS MailSubject,                            
                   @ReplyTo        AS ReplyTo ,          
       Leadid          
            FROM   (                            
                       SELECT CASE                             
                                   WHEN @EmailId = 1 THEN ul.Email                            
                                   ELSE ''                            
                              END AS EmailID,                            
                              dbo.fn_getUserMailMessage(ul.ParentID, @Message, ul.Email) AS                             
                              MailContent,ul.ID as leadid                            
                       FROM   User_Detail AS ul  (nolock)                          
                       WHERE  ul.User_ID IN (SELECT [value]                            
                                        FROM   dbo.fn_Split(@UserId, '#') AS fs)                  
                                         AND ISNULL(NULLIF(CAST(ul.Email as varchar), ''), '') <> ''                   
                      AND ISNULL(NULLIF(CAST(ul.Email as varchar), ''), '') not in                   
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID                   
                      from User_Detail UETemp(nolock) inner join Client_UnSubscribeDetails C_UDTemp  (nolock)                
                      on (UETemp.Email =C_UDTemp.Email)                  
                                      
                      where ul.User_ID in(Select fs.value from dbo.fn_Split(@UserId, '#') AS fs ))                 
                                                           
                   )A                            
            WHERE  ISNULL(A.EmailID, '') <> ''                            
        ) A                            
                             
                             
                       
  Declare @Status Bigint=0,@CountLimit bigint = 0                        
   select @Status = status,@CountLimit = Plimit from ProcessMailLimit                               
      if(@Status = 1)      
      Begin                        
    Begin                        
      if(@MailCount >  @CountLimit )                        
      Begin                        
       set @IsMonitor = 0                         
      End                        
     End                        
       End                        
                        
             
                                         
 DECLARE @BatchID BIGINT            
 begin tran                                      
 INSERT INTO GetBatchRecord                                  
       (                                  
         [User_id],                                  
         RandNum                                  
       )                     
     VALUES                                  
       (                                  
         @Account,                                  
         @Account                                  
       )                                        
select @BatchID=SCOPE_IDENTITY()                                       
DELETE                                
     FROM GetBatchRecord                                  
     WHERE batchid=@BatchID            
 commit                                      
                                       
             
     DECLARE @Mail_FromEmail VARCHAR(500) = ''                                    
            
select @Mail_FromEmail=coalesce((select top 1 mail_id from defaultmailid(nolock) where user_id=@account order by datecreated desc),            
(SELECT ud.EMail FROM   User_Detail AS ud  (nolock) WHERE  ud.[User_ID] = @Account),'contactus@email19.in')             
    
if(rtrim(ltrim(@FromMailID)) <> '')    
   Begin    
       set @Mail_FromEmail = @FromMailID    
   End    
            
insert into Mysms.dbo.CloneEmailsFilter(Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,            
    
    
    
Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source)            
select @Mail_FromEmail,A.EmailID,A.MailSubject,isnull(@tname,''),A.MailContent,GETDATE(),A.AccountID,@parentid,A.ReplyTo,@BatchID,1,'','','',A.MailContent,@ismonitor,0,@mailcount,'Lead-MassSend'            
from #tempTable A            
/*                                
     INSERT INTO BatchEmail_Infos                            
       (                            
         -- ID -- this column value is auto-generated                          
         BatchID,                            
         UserID,                            
         SenderName,                            
         [Message],                            
         TotalRecords,                            
         TotalProcessed,                            
         ProcessTable,                            
         IsProcess,                            
         Priority_Level,                        
         BatchInsertTime,                            
         BatchProcessTime,                            
         ScheduledDate,                            
         ScheduledTime,                            
         TemplateID,                            
         [Route],                            
         PageName,                            
         IsScheduled,                            
         Email_Subject,                            
         ReplyTo,                            
         Amount,                            
         Currency                            
       )                            
     SELECT @BatchID,                            
            A.AccountID,                            
            A.SenderName,                            
            @Message,                            
            COUNT(*),                            
            0,                            
            0,                            
            0,                            
            0,                            
            GETDATE(),                            
            NULL,                            
            NULL,                            
            NULL,                            
NULL,                            
            NULL,                            
            NULL,                            
            0,                            
            A.MailSubject,                            
            A.ReplyTo,                            
            COUNT(*),                            
            'INR'                            
     FROM   #tempTable A                            
     GROUP BY                            
            A.AccountID,                            
            A.SenderName,                            
            A.MailSubject,              
            A.ReplyTo                             
                                 
     INSERT INTO ClientEmails                            
       (                            
         -- Id -- this column value is auto-generated                            
         GUID,                            
         Email_Id,                            
         SentDateTime,                            
         UserId,                            
         ReplyTo,                            
         [Status],             
         BatchID,                            
         [Message]                            
       )                            
     SELECT NEWID(),                            
            A.EmailID,                            
            GETDATE(),                            
            A.AccountID,                            
            A.ReplyTo,                            
            '',                            
            @BatchID,                            
            A.MailContent                            
     FROM   #tempTable A                            
                                 
     INSERT INTO EmailsFilter                            
       (                            
         Mail_GUID,                            
         -- Mail_ID -- this column value is auto-generated                        
         Mail_FromEmail,                            
         Mail_ToEmail,                            
         Mail_Subject,                            
         Mail_TempleteName,                            
         Messages,                            
         Mail_InsertedDate,                            
         Mail_UserID,                            
         ReplyTo,                            
         Mail_BatchID,                            
         Mail_Priority,                            
         Mail_ScheduleDate,                            
         Mail_Attechement,                            
         Mail_TempleteBody,                        
         IsMonitor                            
       )                            
     SELECT NEWID(),                            
            @Mail_FromEmail,                            
            A.EmailID,                            
            A.MailSubject,                            
            '',                            
            A.MailContent,                            
            GETDATE(),                            
            A.AccountID,                            
            A.ReplyTo,                            
            @BatchID,                            
            0,                            
            NULL,                            
            0,                            
            A.MailContent,                        
            @IsMonitor                            
     FROM   #tempTable A                   
                       
     update EmailsFilter set EmailsFilter.Mail_Priority=2                  
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                                  
                                 
     INSERT INTO MailCreditDetails                            
       (                            
         FromUser_ID,                            
         M_ID,                            
         USER_ID,                            
         Debits,                            
         Credits,                            
         Balance ,                          
         Validity                           
       )           
     VALUES                            
       (                            
         @Account,                            
         @m_id,                            
  @Account,                            
         @MailCount,                            
         0,                            
         @Balance,                          
         99999                            
       )                            
    */            
          
           
 /*if(@UserId  > 0 )          
 begin          
  declare @leadActivityHistory AS LeadActivitywithid_Tbltype          
  declare  @Username nvarchar(255) = ( select User_Login from User_Detail(nolock) where User_Id = @UserId)           
  insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )          
   select           
    leadid,          
    @UserId,           
    @parentid,          
    concat(@Username , ' sent a mail with subject ',  MailSubject, ' to emailid ', EmailID),          
    'Mail sent to lead',          
    'Batchemail_infos',              
    @BatchID          
   from #tempTable          
          
  exec UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory          
 end    */      
          
    SELECT 'Success'                            
 END                            
 ELSE                            
 BEGIN                            
     SELECT 'Insufficient Balance'                            
