CREATE   PROCEDURE [dbo].[usp_SendMails]                           
 @emails nvarchar(max),                              
 @Account BIGINT,                              
 @Email_Subject nVARCHAR(1000),                              
 @Message_TemplateID Bigint,      
 @messagecontent nvarchar(max),                              
 @SenderName VARCHAR(100),                              
 @ReplyTo VARCHAR(1000),    
 @route nvarchar(10),     
 @priority int,    
 @mailsource nvarchar(50),    
 @batchid bigint output    
 AS                              
BEGIN         
--set @account=335    
--declare
-- @emails nvarchar(max) ='gm.corporate@jmvhyundai.com',                              
-- @Account BIGINT =12141,                              
-- @Email_Subject nVARCHAR(1000) = 'Email verification',                              
-- @Message_TemplateID Bigint = 0,      
-- @messagecontent nvarchar(max)='Hello! <br/> <br/>Thank you for being a  https://premium.ezcrm.in member.You need to verify your email to be able to login to  https://premium.ezcrm.in <br/> <br/> Please    <a href="https://premium.ezcrm.in/EmailVerification.aspx?ID=7788DFA2-90B7-43C2-984C-1986DCB35CCE" > Click Here </a> to verify your mail ID.Please ignore this email if you are not registered with https://premium.ezcrm.in <br/><br/><br/> if you are not able to click above link please copy below link & Paste it in browser <br/>https://premium.ezcrm.in/EmailVerification.aspx?ID=7788DFA2-90B7-43C2-984C-1986DCB35CCE ',                              
-- @SenderName VARCHAR(100)='support@ezcrm.in',                              
-- @ReplyTo VARCHAR(1000)='support@ezcrm.in',    
-- @route nvarchar(10) = 'T',     
-- @priority int = 1,    
-- @mailsource nvarchar(50) = 'Verify email',    
-- @batchid bigint


declare @sentmail_logid bigint    
insert into sentmails_log(emails,account,email_subject,message_templateid,messagecontent,sendername,replyto,route,priority,mailsource)    
select @emails,@account,@email_subject,@message_templateid,@messagecontent,@sendername,@replyto,@route,@priority,@mailsource    
select @sentmail_logid=scope_identity()    
    
    
declare @tname nvarchar(200)               
select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))                    
DECLARE @MailCount BIGINT,@IsMonitor Bit = 1                     
DECLARE @m_id BIGINT,@parentid bigint              
 SELECT @m_id= ud.M_ID,@parentid=parentid                                      
                 FROM   User_Detail AS ud (nolock)                                     
                 WHERE  ud.[User_ID] = @Account                                
 SELECT @MailCount = (select count(1) from dbo.fn_split(@emails,','))                                 
  DECLARE @CurrentBalance BIGINT = (                                    
             SELECT TOP 1 mcd.Balance                                    
             FROM   MailCreditDetails AS mcd   (nolock)                                 
             WHERE  mcd.[User_ID] = @parentid                                    
             ORDER BY mcd.Credit_ID DESC                                    
         )                                                
                                
                                     
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount                                    
 if @balance<0 and @account=335      
 begin      
 insert into MailCreditDetails(M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,FromDate,ToDate,DateCreated,      
DateUpdated,EmpUpdated,MachineName,LastModified,typecredit,CreatedBy)       
select top 1 M_ID,FromUser_ID,User_ID,Debits,@MailCount,Balance+@MailCount,Validity,Default_Credit,FromDate,ToDate,getdate(),      
getdate(),EmpUpdated,MachineName,getdate(),typecredit,CreatedBy from mailcreditdetails(nolock) where       
FromUser_ID=335 and user_id=335 order by credit_id desc      
end    


 IF @Balance > 0                                     
 BEGIN                                      
    print 'balance ok';
   --Declare @Message VARCHAR(MAX)                       
if @messagecontent=''      
begin                      
  select @messagecontent = MailContent,@tname=Name  From UserMailTemplate(nolock) where ID= @Message_TemplateID                      
end                      
 SELECT f.value as EmailID,                              
         @Account AS AccountID,                              
                   @SenderName     AS SenderName,                              
                   @messagecontent Mailcontent,                              
                   @Email_Subject  AS MailSubject,                              
                   @ReplyTo        AS ReplyTo,    
       @route as mailroute       
  INTO #tempTable                              
 FROM   dbo.fn_split(@emails,',') f      
 where value not in (select Email  from Client_UnSubscribeDetails C_UDTemp (nolock) where parentid=@parentid)      
    
if @route='T'    
begin      
Declare @Status Bigint=0,@CountLimit bigint = 0                          
select @Status = status,@CountLimit = Plimit from ProcessMailLimit(nolock)         
      if(@Status = 1)                          
      Begin                          
    Begin                          
      if(@MailCount >  @CountLimit )                          
      Begin                          
       set @IsMonitor = 0                           
      End                          
     End                          
       End                         
end                          
               
                                           
 --DECLARE @BatchID BIGINT              
 begin tran                                        
 INSERT INTO GetBatchRecord                                    
       (                                    
         [User_id],                                    
         RandNum                                    
       )             
     VALUES                                    
       (                                    
         @Account,                                    
         @Account                                    
       )                                          
select @BatchID=SCOPE_IDENTITY()                                         
DELETE                                  
     FROM GetBatchRecord                                    
     WHERE batchid=@BatchID              
 commit                                        
                                         
               
DECLARE @Mail_FromEmail VARCHAR(500) = ''                                      
              
select @Mail_FromEmail=coalesce(@SenderName,(select top 1 mail_id from defaultmailid(nolock) where user_id=@account order by datecreated desc),              
(SELECT ud.EMail FROM   User_Detail AS ud  (nolock) WHERE  ud.[User_ID] = @Account),'contactus@email19.in')               
     
 begin try    
insert into CloneEmailsFilter(Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,              
Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source,mailroute)              
select @Mail_FromEmail,A.EmailID,A.MailSubject,isnull(@tname,''),A.MailContent,GETDATE(),A.AccountID,@parentid,A.ReplyTo,@BatchID,@priority,'','','',A.MailContent,@ismonitor,0,@mailcount,@mailsource,mailroute              
from #tempTable A     
if @@rowcount>0    
begin    
update sentmails_log set isprocessed=1,processed_at=getdate(),batchid=@batchid where id=    @sentmail_logid    
end    
  end try    
  begin catch    
  update sentmails_log set batchid=@batchid,error_description=error_message() where id=    @sentmail_logid    
    
  exec usp_inserterrorinfo    
  end catch    
--SELECT @BatchID      
END     
else begin 
	print 'balance insufficient';
end

DROP TABLE if exists #tempTable                     
END


GO

