 --                  ( select ISNULL(C_UDTemp.Email,'') as EmailID           
 --   from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp          
 --                     on (UETemp.EmailID2 =C_UDTemp.Email)          
                              
 --                     where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))          
                                       
                                                         
 --                      UNION ALL                  
                                         
 --                      SELECT CASE                   
 --                                  WHEN @EmailId2 = 1 THEN ul.EmailID2                  
 --                                  ELSE ''                  
 --                             END AS EmailID,                  
 --                             dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)                  
 --                      FROM   UserLeads AS ul                  
 --                      WHERE  ul.ID IN (SELECT [value]                  
 --                                       FROM   dbo.fn_Split(@IDS, '#') AS fs)                  
 --                  )                  A                  
 --           WHERE  ISNULL(A.EmailID, '') <> ''                  
 --       ) A                  
declare @EmailId varchar(200)   
declare @SenderName VARCHAR(100)               
DECLARE @IsMonitor Bit = 1                  
 --SELECT @MailCount = COUNT(*)                  
 --FROM   #tempTable                  
                   
                   
  Declare @Status Bigint=0,@CountLimit bigint = 0              
   select @Status = status,@CountLimit = Plimit from ProcessMailLimit                     
      if(@Status = 1)              
      Begin              
    Begin              
      if(@CountLimit < 1 )              
      Begin              
       set @IsMonitor = 0               
      End              
     End              
       End              
                   
                   
 DECLARE @CurrentBalance BIGINT = (                  
             SELECT TOP 1 mcd.Balance                  
             FROM   MailCreditDetails AS mcd(nolock)                  
             WHERE  mcd.[User_ID] = @Account                  
             ORDER BY                  
                    mcd.Credit_ID DESC                  
         )                  
                   
 DECLARE @Balance BIGINT = @CurrentBalance - 1                 
 IF @Balance > 0                  
 BEGIN                  
     DECLARE @m_id BIGINT = (                  
                 SELECT TOP 1 ud.M_ID                  
                 FROM   User_Detail(nolock) AS ud                  
                 WHERE  ud.[User_ID] = @Account                  
             )                  
     DECLARE @BatchID BIGINT
	 
	 
	 INSERT INTO GetBatchRecord                  
       (                  
         [User_id],                  
         RandNum                  
       )                  
     VALUES               (                  
         @Account,                  
         @Account                  
       )                        
                       
      SELECT @batchid=scope_identity()
	                         
     DELETE                   
     FROM   GetBatchRecord                  
     WHERE  batchid = @BatchID
	 
	                      
                     
                       
                       
     DECLARE @Mail_FromEmail VARCHAR(500) = ''                    

declare @pid bigint=(select parentid from user_detail(nolock) where user_id=@Account)                       
SELECT top 1 @Mail_FromEmail =mail_id from DefaultMailID (nolock) where User_ID=@pid

if @Mail_FromEmail is null     
begin
SELECT @Mail_FromEmail = ud.EMail                  
     FROM   User_Detail          AS ud (nolock)
            LEFT JOIN User_Type  AS ut(NOLOCK)                  
                 ON  ud.UserType = ut.ID                  
     WHERE  ud.[User_ID] = @Account                   
end 
                  
     select @EmailId=EMail from user_detail(nolock) where USER_ID=@toAccount   

     select @SenderName=User_Login from user_detail(nolock) where USER_ID=@Account    
     INSERT INTO BatchEmail_Infos                  
       (                  
         -- ID -- this column value is auto-generated                  
         BatchID,                  
         UserID,                  
         SenderName,                  
         [Message],             
         TotalRecords,                  
         TotalProcessed,                  
         ProcessTable,                  
         IsProcess,                  
         Priority_Level,                  
         BatchInsertTime,                  
         BatchProcessTime,                  
         ScheduledDate,                  
         ScheduledTime,                  
         TemplateID,                  
         [Route],                  
         PageName,                  
         IsScheduled,                  
         Email_Subject,                  
         ReplyTo,                  
         Amount,                  
         Currency                  
       )                  
     values( @BatchID,                        @Account,                  
            @SenderName,                  
            @Message,                  
            1,                  
            0,                  
            0,                  
            0,                  
            0,                  
            GETDATE(),                  
            NULL,                  
            NULL,                  
            NULL,                  
            NULL,                  
            NULL,                  
            NULL,                  
            0,                  
            @Email_Subject,                  
            '',                  
            1,                  
            'INR'                  
     )              
               
                       
     INSERT INTO ClientEmails                  
       (                  
         -- Id -- this column value is auto-generated                  
         GUID,                  
         Email_Id,                  
         SentDateTime,                  
         UserId,                  
         ReplyTo,                  
         [Status],                  
         BatchID,                  
         [Message]                  
       )                  
     values( NEWID(),                  
            @EmailId,                  
            GETDATE(),                  
            @Account,                  
            '',                  
            '',                  
            @BatchID,                  
            @Message                  
     )                 
                       
     INSERT INTO EmailsFilter                  
       (                  
         Mail_GUID,                  
         -- Mail_ID -- this column value is auto-generated                  
         Mail_FromEmail,                  
         Mail_ToEmail,                  
         Mail_Subject,                  
         Mail_TempleteName,                  
         Messages,                  
         Mail_InsertedDate,                  
         Mail_UserID,                  
         ReplyTo,                  
         Mail_BatchID,                  
         Mail_Priority,                  
         Mail_ScheduleDate,                  
         Mail_Attechement,                  
         Mail_TempleteBody,              
         IsMonitor                  
       )                  
     values( NEWID(),                  
            @Mail_FromEmail,                  
 @EmailId,                  
            @Email_Subject,                  
            '',                  
            @Message,                  
            GETDATE(),                  
            @Account,                  
            '',                  
            @BatchID,                  
            0,                  
            NULL,                  
            0,                  
            @Message,              
           @IsMonitor                  
     )         
               
      update EmailsFilter set EmailsFilter.Mail_Priority=2          
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                 
                       
     INSERT INTO MailCreditDetails                 
       (                  
         FromUser_ID,                  
         M_ID,                  
         USER_ID,                  
         Debits,                  
         Credits,                  
         Balance ,                
         Validity                 
       )                  
     VALUES                  
       (                  
         @Account,                  
         @m_id,                  
         @Account,                  
         1,                  
         0,                  
         @Balance,                
         99999                  
   )                  
     SELECT 'Success'                  
 END                  
 ELSE                  
 BEGIN                  
     SELECT 'Insufficient Balance'                  
 END                  
                   
                
END 


GO

