    --  WHERE ul.EnquiryID IN (  
    --    SELECT fs.value  
    --    FROM dbo.fn_Split(@IDS, '#') AS fs  
    --    )  
    --  )  
      
    UNION  
      
    SELECT CASE   
      WHEN @EmailId1 = 1  
       THEN ul.EmailID1  
      ELSE ''  
      END AS EmailID  
       
     -- ,dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)  
     ,isnull(content,@message) as MailContent  
     ,isnull(msubject,@email_subject) as Mailsubject  
     --dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID1) AS MailContent  
     ,ul.EnquiryID  
    FROM UserEnquiry AS ul(NOLOCK)  
    inner join #TableData2 t2 on ul.EnquiryID = t2.ID      
     inner join #entitypcvalues ep on ep.entityid=ul.enquiryid  
     inner join #entitypcvalues_subject es on es.entityid=ul.EnquiryID  
  
    WHERE   
    ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') <> ''   
  
    --ul.EnquiryID IN (  
    --  SELECT [value]  
    --  FROM dbo.fn_Split(@IDS, '#') AS fs  
    --  )  
    -- ----Added By Siddharth ----                  
    -- AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') <> ''  
    -- AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') NOT IN (  
    --  SELECT ISNULL(C_UDTemp.Email, '') AS EmailID  
    --  FROM UserEnquiry UETemp(NOLOCK)  
    --  INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID1 = C_UDTemp.Email)  
    --  WHERE ul.EnquiryID IN (  
    --    SELECT fs.value  
    --    FROM dbo.fn_Split(@IDS, '#') AS fs  
    --    )  
    --  )  
      
    UNION   
      
    SELECT CASE   
      WHEN @EmailId2 = 1  
       THEN ul.EmailID2  
      ELSE ''  
      END AS EmailID  
       
     --,dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)  
     ,isnull(content,@message) as MailContent  
     ,isnull(msubject,@email_subject) as Mailsubject  
     --dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID2) AS MailContent  
     ,ul.EnquiryID  
    FROM UserEnquiry AS ul(NOLOCK)  
     inner join #TableData2 t2 on ul.EnquiryID = t2.ID    
     inner join #entitypcvalues ep on ep.entityid=ul.enquiryid  
     inner join #entitypcvalues_subject es on es.entityid=ul.EnquiryID  
    WHERE   
    ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') <> ''  
  
    --ul.EnquiryID IN (  
    --  SELECT [value]  
    --  FROM dbo.fn_Split(@IDS, '#') AS fs  
    --  )  
    -- ----Added By Siddharth ----                  
    -- AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') <> ''  
    -- AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') NOT IN (  
    --  SELECT ISNULL(C_UDTemp.Email, '') AS EmailID  
    --  FROM UserEnquiry UETemp(NOLOCK)  
    --  INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID2 = C_UDTemp.Email)  
    --  WHERE ul.EnquiryID IN (  
    --    SELECT fs.value  
    --    FROM dbo.fn_Split(@IDS, '#') AS fs  
    --    )  
    --  )  
    ) A  
   WHERE ISNULL(A.EmailID, '') <> ''  
   ) A  
  
  DECLARE @Status BIGINT = 0  
   ,@CountLimit BIGINT = 0  
  
  SELECT @Status = STATUS  
   ,@CountLimit = Plimit  
  FROM ProcessMailLimit  
  
  IF (@Status = 1)  
  BEGIN  
   BEGIN  
    IF (@MailCount > @CountLimit)  
    BEGIN  
     SET @IsMonitor = 0  
    END  
   END  
  END  
  
  DECLARE @BatchID BIGINT  
  
  BEGIN TRAN  
  
  INSERT INTO GetBatchRecord (  
   [User_id]  
   ,RandNum  
   )  
  VALUES (  
   @Account  
   ,@Account  
   )  
  
  SELECT @BatchID = SCOPE_IDENTITY()  
  
  DELETE  
  FROM GetBatchRecord  
  WHERE batchid = @BatchID  
  
  COMMIT  
  
  DECLARE @Mail_FromEmail VARCHAR(500) = ''  
  IF (rtrim(ltrim(@FromMailID)) <> '')  
  BEGIN  
   SET @Mail_FromEmail = @FromMailID  
  END  
  else  
  begin  
  SELECT @Mail_FromEmail = coalesce((  
     SELECT TOP 1 mail_id  
     FROM defaultmailid(NOLOCK)  
     WHERE user_id = @account  
     ORDER BY datecreated DESC  
     ), (  
     SELECT ud.EMail  
     FROM User_Detail AS ud(NOLOCK)  
     WHERE ud.[User_ID] = @Account  
     ), 'contactus@email19.in')  
       end  
  
    
  print '1'  
  INSERT INTO CloneEmailsFilter (  
   Mail_FromEmail  
   ,Mail_ToEmail  
   ,Mail_Subject  
   ,Mail_TempleteName  
   ,Messages  
   ,Mail_InsertedDate  
   ,Mail_UserID  
   ,Mail_ParentID  
   ,ReplyTo  
   ,Mail_BatchID  
   ,Mail_Priority  
   ,Mail_ScheduleDate  
   ,Mail_ScheduledTime  
   ,Mail_Attechement  
   ,Mail_TempleteBody  
   ,IsMonitor  
   ,TemplateID  
   ,Count  
   ,Source  
   )  
  SELECT @Mail_FromEmail  
   ,A.EmailID  
   ,A.MailSubject  
   ,''  
   ,A.MailContent  
   ,GETDATE()  
   ,@UserId  
   ,@parentid  
   ,A.ReplyTo  
   ,@BatchID  
   ,1  
   ,''  
   ,''  
   ,''  
   ,A.MailContent  
   ,@ismonitor  
   ,0  
   ,@mailcount  
   ,'Enquiry-MassSend'  
  FROM #tempTable A  
  --print concat('ailbatchid in sp :',@BatchID)  
  --exec usp_ProcessMailBatch @BatchID  
  /*                                 
     INSERT INTO BatchEmail_Infos                                
       (                                
         -- ID -- this column value is auto-generated                                
         BatchID,                                
         UserID,                                
         SenderName,                                
         [Message],                                
         TotalRecords,                                
         TotalProcessed,                                
         ProcessTable,                                
         IsProcess,                                
         Priority_Level,                                
         BatchInsertTime,                                
         BatchProcessTime,                           
         ScheduledDate,                                
         ScheduledTime,                                
         TemplateID,                                
         [Route],                                
         PageName,                                
         IsScheduled,                                
         Email_Subject,                                
         ReplyTo,                                
        Amount,                                
         Currency                                
       )                                
     SELECT @BatchID,                                
            A.AccountID,                                
            A.SenderName,                                
            @Message,                                
            COUNT(*),                                
            0,                                
            0,                                
            0,                                
            0,                               
            GETDATE(),                                
            NULL,                                
            NULL,                                
            NULL,                                
            NULL,                                
            NULL,                                
            NULL,                                
            0,                                
            A.MailSubject,                         
            A.ReplyTo,                                
            COUNT(*),                                
            'INR'                                
     FROM   #tempTable A                                
     GROUP BY                                
            A.AccountID,                                
            A.SenderName,                                
            A.MailSubject,                                
            A.ReplyTo                                 
                               
     INSERT INTO ClientEmails                                
       (                                
         -- Id -- this column value is auto-generated                                
         GUID,                                
         Email_Id,                                
         SentDateTime,                                
         UserId,                                
         ReplyTo,                                
         [Status],                                
         BatchID,                                
         [Message]                                
       )                                
     SELECT NEWID(),                                
            A.EmailID,                                
            GETDATE(),                                
            A.AccountID,                                
            A.ReplyTo,                                
            '',                                
            @BatchID,                                
            A.MailContent                                
     FROM   #tempTable A                                
                                     
     INSERT INTO EmailsFilter                                
       (                                
         Mail_GUID,                                
         -- Mail_ID -- this column value is auto-generated                                
         Mail_FromEmail,                                
         Mail_ToEmail,                                
         Mail_Subject,                                
         Mail_TempleteName,                                
         Messages,                                
         Mail_InsertedDate,                                
         Mail_UserID,                                
         ReplyTo,                                
         Mail_BatchID,                                
         Mail_Priority,                                
         Mail_ScheduleDate,                                
         Mail_Attechement,                                
         Mail_TempleteBody,                          
         IsMonitor                                
       )                                
     SELECT NEWID(),                                
            @Mail_FromEmail,                                
            A.EmailID,                                
            A.MailSubject,                                
            '',                                
            A.MailContent,                                
            GETDATE(),                                
            A.AccountID,                  
            A.ReplyTo,                                
            @BatchID,                                
            0,                                
            NULL,                                
            0,                                
            A.MailContent,                          
            @IsMonitor                                
     FROM   #tempTable A                     
                         
                         
       update EmailsFilter set EmailsFilter.Mail_Priority=2                    
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                    
                                    
       
     INSERT INTO MailCreditDetails                                
       (                                
         FromUser_ID,                                
         M_ID,                                
         USER_ID,                                
         Debits,                                
         Credits,                                
         Balance ,                            
         Validity                               
       )                                
     VALUES                                
       (                                
         @Account,                                
         @m_id,                            
         @Account,                                
         @MailCount,                                
         0,                                
         @Balance  ,                            
         99999                              
       )                  
    */  
  print '2'  
  IF (@UserId > 0)  
  BEGIN  
  print '3'  
   DECLARE @Username NVARCHAR(255)  
   DECLARE @leadActivityHistory AS LeadActivitywithid_Tbltype  
  
   SELECT @Username = User_Login  
   FROM User_Detail(NOLOCK)  
   WHERE User_Id = @UserId 
   
   drop table if exists #userenquiry
   select u.* into #userenquiry from userenquiry(nolock) u join #tempTable t on u.EnquiryID=t.EnquiryID

  
   INSERT INTO @leadActivityHistory (  
    LeadID  
    ,UserID  
    ,ParentID  
    ,EventDescription  
    ,EventName  
    ,RefTable  
    ,refid  
    )  
   SELECT t.EnquiryId  
    ,@UserId  
    ,@parentid  
    ,CONCAT (  
     isnull(@agentname,@username)
     ,'  sent a mail to enquiryid: '
	 ,t.enquiryid
	 ,', Name: '
	 ,u.PersonName
	 ,' with subject '  
     ,MailSubject  
     ,' to emailid '  
     ,t.EmailID
	 , case when @executionid>0 then ' under execution id : '+cast(@executionid as nvarchar) else '' end
	      )  
    ,'Mail sent to Enquiry'  
    ,'Batchemail_infos'  
    ,@BatchID  
   FROM #tempTable t join #userenquiry u on t.EnquiryID=u.EnquiryID
  
   EXEC UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory  
   print '4'  
  END  
  
  SELECT 'Success'  
  END  
 ELSE  
 BEGIN  
  SELECT 'Insufficient Balance'  
  END  
  
 DROP TABLE #tempTable  
  
 
END  
  
  


