CREATE   PROCEDURE [dbo].[usp_SendMassMailFromEnquiry_WithFromMailID_new1]                                       
 --@IDS VARCHAR(MAX),                                      
 --@Account BIGINT,                                      
 --@Email_Subject VARCHAR(1000),                                      
 --@Message VARCHAR(MAX),                                      
 --@SenderName VARCHAR(100),                                      
 --@ReplyTo VARCHAR(1000),                                      
 --@EmailId BIT ,                                      
 --@EmailId1 BIT ,                                      
 --@EmailId2 BIT,              
 --@FromMailID nvarchar(500)  = '',             
 --@UserId bigint = 0,    
 --@massbatchid bigint=0    
 @metatdata nvarchar(max),  
