CREATE   PROCEDURE [dbo].[usp_SendMassMailFromEnquiry_WithTemplateID_WithFromMailID_new] @IDS VARCHAR(MAX)   ----Working fine for enquiry template  with deduct fn
	,@Account BIGINT
	,@Email_Subject VARCHAR(1000)
	,@Message_TemplateID BIGINT
	,@SenderName VARCHAR(100)
	,@ReplyTo VARCHAR(1000)
	,@EmailId BIT
	,@EmailId1 BIT
	,@EmailId2 BIT
	,@UserId BIGINT = 0
	,@FromMailID VARCHAR(500),
	@massbatchid bigint=0 ,    
 @Mail_ScheduleDate VARCHAR(50)=''  
AS
BEGIN
/*declare   @IDS VARCHAR(MAX)='4660112',                          
 @Account BIGINT=34594,                          
 @Email_Subject VARCHAR(1000)='asdedsd',                        
 @Message_TemplateID BIGINT=6849,                         
 @SenderName VARCHAR(100)='kmukesh343 ( Transactional Balance: 9994)(Mukesh Kumar)',                       
 @ReplyTo VARCHAR(1000)='partnership@kit19.com',                       
 @EmailId BIT=1,                          
 @EmailId1 BIT=0,                      
 @EmailId2 BIT=0,      
 @UserId bigint = 34594,  
 @FromMailID varchar(500)='partnership@kit19.com'*/



	SELECT @Email_Subject = isnull(nullif(@Email_Subject, ''), (
				SELECT mailsubject
				FROM UserMailTemplate(NOLOCK)
				WHERE id = @message_templateID
				))

	DECLARE @MailCount BIGINT,@IsMonitor BIT = 1
	DECLARE @m_id BIGINT,@parentid BIGINT 
	declare @NoOfUnit INT, @TotalCostForBatch DECIMAL(18, 4), @TotalCostMultiplied DECIMAL(18, 4), @TotalCostForCreditDetails DECIMAL(18, 4),@default_credit DECIMAL(18, 4)
	DECLARE @CurrentBalance DECIMAL(18, 4), @servicetype varchar(100),@credittypeid int;

	if @massbatchid IS NOT NULL AND @massbatchid <> 0    
    BEGIN    
        select @IDS= STRING_AGG(cast(Entityid as nvarchar(max)),'#') from Tbl_MassOperationDetails(nolock) where SummaryId=@massbatchid    
        Update  Tbl_MassOperationSummary set BatchStartTime= GetDate()  where BatchID=@massbatchid    
    END  


	SELECT @m_id = ud.M_ID ,@parentid = parentid FROM User_Detail AS ud(NOLOCK)WHERE ud.[User_ID] = @Account

	SELECT @MailCount = (SELECT count(1)FROM dbo.fn_split(@IDS, '#'))
    set @servicetype='Mail';
	select @credittypeid=credittypeid from Price_Master_TypeCredit(nolock) where creditname=@servicetype
    SET @CurrentBalance = dbo.GetAvailableBalanceForService(@parentid,@credittypeid);  
    SELECT @TotalCostForCreditDetails = ISNULL(BR.Price, 0.00) * @MailCount
    FROM Price_Base_Mail_Rate BR(nolock) where BR.OriginCountryId = 101;
	drop table if exists #TableData2
	 CREATE TABLE #TableData2 (Sno int identity, ID BIGINT) 
	 INSERT INTO #TableData2 (ID)    
    select Item from fu_SplitString(@IDS,'#')  
	--DECLARE @CurrentBalance BIGINT = (
	--		SELECT TOP 1 mcd.Balance
	--		FROM MailCreditDetails AS mcd(NOLOCK)
	--		WHERE mcd.[User_ID] = @parentid
	--		ORDER BY mcd.Credit_ID DESC
	--		)
	--DECLARE @Balance BIGINT = @CurrentBalance - @MailCount
	DECLARE @Balance decimal(18,4) = @CurrentBalance - @TotalCostForCreditDetails       
	IF @Balance >= 0
	BEGIN


		DECLARE @Message VARCHAR(MAX)

		SELECT @Message = MailContent
		FROM UserMailTemplate(NOLOCK)
		WHERE ID = @Message_TemplateID
		--code to get replaced values
declare @entity nvarchar(20)='Enquiry',@entityplaceholders nvarchar(2000)                                         
  drop table if exists #entitypcvalues
  drop table if exists #entitypcvalues_subject
  
  declare @entities as entities
  create table #entitypcvalues(entityid bigint,content nvarchar(max))
  create table #entitypcvalues_subject(entityid bigint,msubject nvarchar(500))

   insert into @entities(entity,entityid)
   select @entity,ID from #TableData2


  select @entityplaceholders=dbo.ExtractPlaceholders(@entity,@message)

 
   if @entityplaceholders<>''
   begin
   insert into #entitypcvalues(entityid,content)
   exec [usp_replaceentityplaceholders_bulk_singlecontent] @entities,@message,@entityplaceholders
   end
   else
   begin
     insert into #entitypcvalues(entityid,content)
     select entityid,@message from @entities
   end

     select @entityplaceholders=dbo.ExtractPlaceholders(@entity,@Email_Subject)

 if @entityplaceholders<>''
   begin
   insert into #entitypcvalues_subject(entityid,msubject)
   exec [usp_replaceentityplaceholders_bulk_singlecontent] @entities,@Email_Subject,@entityplaceholders
   end
   else
   begin
   insert into #entitypcvalues_subject(entityid,msubject)
     select entityid,@Email_Subject from @entities
   end



		SELECT A.EmailID
			,A.AccountID
			,A.SenderName
			,A.MailContent
			,A.MailSubject
			,A.ReplyTo
			,A.EnquiryId
		INTO #tempTable
		FROM (
			SELECT ISNULL(A.EmailID, '') AS EmailID
				,@Account AS AccountID
				,@SenderName AS SenderName
				,A.MailContent
				,A.mailsubject AS MailSubject
				,@ReplyTo AS ReplyTo
				,A.EnquiryId
			FROM (
				SELECT CASE 
						WHEN @EmailId = 1
							THEN ul.EmailID
						ELSE ''
						END AS EmailID
					
					--,dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID)  
					,isnull(content,@message) as MailContent
					,isnull(msubject,@email_subject) as mailsubject

					--dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID) AS MailContent
					,ul.EnquiryID
				FROM UserEnquiry AS ul(NOLOCK)
				inner join #TableData2 t2 on ul.EnquiryID = t2.ID   
					inner join #entitypcvalues ep on ep.entityid=ul.enquiryid
				    inner join #entitypcvalues_subject es on es.entityid=ul.enquiryid
				WHERE 
				ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') <> ''

				--ul.EnquiryID IN (
				--		SELECT [value]
				--		FROM dbo.fn_Split(@IDS, '#') AS fs
				--		)
				--	----Added By Siddharth ----                
				--	AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') <> ''
				--	AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') NOT IN (
				--		SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
				--		FROM UserEnquiry UETemp(NOLOCK)
				--		INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID = C_UDTemp.Email)
				--		WHERE ul.EnquiryID IN (
				--				SELECT fs.value
				--				FROM dbo.fn_Split(@IDS, '#') AS fs
				--				)
				--		)
				
				UNION
				
				SELECT CASE 
						WHEN @EmailId1 = 1
							THEN ul.EmailID1
						ELSE ''
						END AS EmailID
					
					-- ,dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)
			,isnull(content,@message) as MailContent
					,isnull(msubject,@email_subject) as mailsubject

					--dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID1) AS MailContent
					,ul.EnquiryID
				FROM UserEnquiry AS ul(NOLOCK)
				inner join #TableData2 t2 on ul.EnquiryID = t2.ID   
					inner join #entitypcvalues ep on ep.entityid=ul.enquiryid
				    inner join #entitypcvalues_subject es on es.entityid=ul.enquiryid
				WHERE 
				ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') <> ''

				--ul.EnquiryID IN (
				--		SELECT [value]
				--		FROM dbo.fn_Split(@IDS, '#') AS fs
				--		)
				--	----Added By Siddharth ----             
				--	AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') <> ''
				--	AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') NOT IN (
				--		SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
				--		FROM UserEnquiry UETemp(NOLOCK)
				--		INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID1 = C_UDTemp.Email)
				--		WHERE ul.EnquiryID IN (
				--				SELECT fs.value
				--				FROM dbo.fn_Split(@IDS, '#') AS fs
				--				)
				--		)
				
				UNION
				
				SELECT CASE 
						WHEN @EmailId2 = 1
							THEN ul.EmailID2
						ELSE ''
						END AS EmailID
					
					--,dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2) 
					,isnull(content,@message) as MailContent
					,isnull(msubject,@email_subject) as mailsubject

					--dbo.fn_getEnquiryMessageMail(ul.ParentID, @Message, ul.EmailID2) AS MailContent
					,ul.EnquiryID
				FROM UserEnquiry AS ul(NOLOCK)
				inner join #TableData2 t2 on ul.EnquiryID = t2.ID   
					inner join #entitypcvalues ep on ep.entityid=ul.enquiryid
				    inner join #entitypcvalues_subject es on es.entityid=ul.enquiryid
				WHERE 
				ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') <> ''
				--ul.EnquiryID IN (
				--		SELECT [value]
				--		FROM dbo.fn_Split(@IDS, '#') AS fs
				--		)
				--	----Added By Siddharth ----                
				--	AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') <> ''
				--	AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') NOT IN (
				--		SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
				--		FROM UserEnquiry UETemp(NOLOCK)
				--		INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID2 = C_UDTemp.Email)
				--		WHERE ul.EnquiryID IN (
				--				SELECT fs.value
				--				FROM dbo.fn_Split(@IDS, '#') AS fs
				--				)
				--		)
				) A
			WHERE ISNULL(A.EmailID, '') <> ''
			) A

		DECLARE @Status BIGINT = 0
			,@CountLimit BIGINT = 0

		SELECT @Status = STATUS
			,@CountLimit = Plimit
		FROM ProcessMailLimit

		IF (@Status = 1)
		BEGIN
			BEGIN
				IF (@MailCount > @CountLimit)
				BEGIN
					SET @IsMonitor = 0
				END
			END
		END

		DECLARE @BatchID BIGINT

		BEGIN TRAN

		INSERT INTO GetBatchRecord (
			[User_id]
			,RandNum
			)
		VALUES (
			@Account
			,@Account
			)

		SELECT @BatchID = SCOPE_IDENTITY()

		DELETE
		FROM GetBatchRecord
		WHERE batchid = @BatchID

		COMMIT

		DECLARE @Mail_FromEmail VARCHAR(500) = ''

				IF (rtrim(ltrim(@FromMailID)) <> '')
		BEGIN
			SET @Mail_FromEmail = @FromMailID
		END
else
begin
		SELECT @Mail_FromEmail = coalesce((
					SELECT TOP 1 mail_id
					FROM defaultmailid(NOLOCK)
					WHERE user_id = @account
					ORDER BY datecreated DESC
					), (
					SELECT ud.EMail
					FROM User_Detail AS ud(NOLOCK)
					WHERE ud.[User_ID] = @Account
					), 'contactus@email19.in')
end

		INSERT INTO CloneEmailsFilter (
			Mail_FromEmail
			,Mail_ToEmail
			,Mail_Subject
			,Mail_TempleteName
			,Messages
			,Mail_InsertedDate
			,Mail_UserID
			,Mail_ParentID
			,ReplyTo
			,Mail_BatchID
			,Mail_Priority
			,Mail_ScheduleDate
			,Mail_ScheduledTime
			,Mail_Attechement
			,Mail_TempleteBody
			,IsMonitor
			,TemplateID
			,Count
			,Source
			)
		SELECT @Mail_FromEmail
			,A.EmailID
			,A.MailSubject
			,''
			,A.MailContent
			,GETDATE()
			,@UserId
			,@parentid
			,A.ReplyTo
			,@BatchID
			,1
			,''
			,''
			,''
			,A.MailContent
			,@ismonitor
			,0
			,@mailcount
			,'Enquiry-MassSend'
		FROM #tempTable A

		print concat('mailbatchid in sp :',@BatchID)
		--exec usp_ProcessMailBatch @BatchID

		/*                                    
     INSERT INTO BatchEmail_Infos                                
       (                                
         -- ID -- this column value is auto-generated                                
         BatchID,                                
         UserID,                                
         SenderName,                                
         [Message],                                
         TotalRecords,                                
         TotalProcessed,                                
         ProcessTable,                                
         IsProcess,                                
         Priority_Level,                                
         BatchInsertTime,                      
         BatchProcessTime,                                
         ScheduledDate,                                
         ScheduledTime,                                
         TemplateID,                                
         [Route],                                
         PageName,                                
         IsScheduled,                                
         Email_Subject,                                
         ReplyTo,                                
         Amount,                        
         Currency                                
       )                                
     SELECT @BatchID,                                
            A.AccountID,                                
            A.SenderName,                                
            @Message,                                
            COUNT(*),                                
            0,          
            0,                                
            0,                                
            0,                                
            GETDATE(),                                
            NULL,                                
            NULL,                                
            NULL,                                
            NULL,                                
            NULL,                                
            NULL,                                
            0,                           
            A.MailSubject,                                
            A.ReplyTo,                                
       COUNT(*),                                
            'INR'                                
     FROM   #tempTable A                                
     GROUP BY                                
            A.AccountID,                                
            A.SenderName,                                
            A.MailSubject,                                
            A.ReplyTo                                 
                                     
     INSERT INTO ClientEmails                                
       (                                
        -- Id -- this column value is auto-generated                                
         GUID,                                
         Email_Id,                                
         SentDateTime,                                
         UserId,                                
         ReplyTo,                                
         [Status],                                
         BatchID,                                
         [Message]                                
       )                                
     SELECT NEWID(),                       
            A.EmailID,                                
            GETDATE(),                                
            A.AccountID,                                
            A.ReplyTo,                                
            '',                                
            @BatchID,                                
            A.MailContent                                
     FROM   #tempTable A                                
                                     
     INSERT INTO EmailsFilter                                
       (                    
         Mail_GUID,                                
         -- Mail_ID -- this column value is auto-generated                                
         Mail_FromEmail,                                
         Mail_ToEmail,                                
         Mail_Subject,                                
         Mail_TempleteName,                                
         Messages,                                
         Mail_InsertedDate,                      
         Mail_UserID,                                
         ReplyTo,                                
         Mail_BatchID,                                
         Mail_Priority,                                
         Mail_ScheduleDate,                                
         Mail_Attechement,                                
         Mail_TempleteBody,                          
         IsMonitor                                
       )                                
     SELECT NEWID(),                                
            @Mail_FromEmail,                                
            A.EmailID,                                
            A.MailSubject,                                
            '',                                
            A.MailContent,                                
            GETDATE(),                                
            A.AccountID,                                
            A.ReplyTo,                                
     @BatchID,                                
            0,                                
            NULL,                                
            0,                                
            A.MailContent,                          
            @IsMonitor                                
     FROM   #tempTable A                  
                       
       update EmailsFilter set EmailsFilter.Mail_Priority=2                  
      from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                                
                                   
     INSERT INTO MailCreditDetails                                
       (                                
         FromUser_ID,                                
         M_ID,                                
         USER_ID,                                
         Debits,                                
         Credits,                                
         Balance ,                            
         Validity                               
       )                                
     VALUES                                
       (                                
         @Account,                                
         @m_id,                                
         @Account,                                
         @MailCount,                                
         0,                                
         @Balance  ,                            
         99999                              
       )                
    */
		IF (@UserId > 0)
		BEGIN
			DECLARE @Username NVARCHAR(255)
			DECLARE @leadActivityHistory AS LeadActivitywithid_Tbltype

			SELECT @Username = User_Login
			FROM User_Detail(NOLOCK)
			WHERE User_Id = @UserId

			INSERT INTO @leadActivityHistory (
				LeadID
				,UserID
				,ParentID
				,EventDescription
				,EventName
				,RefTable
				,refid
				)
			SELECT EnquiryId
				,@UserId
				,@parentid
				,CONCAT (
					@Username
					,'  sent mail with subject '
					,MailSubject
					,' to emailid '
					,EmailID
					)
				,'Mail sent to Enquiry'
				,'Batchemail_infos'
				,@BatchID
			FROM #tempTable

			EXEC UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory
		END

		SELECT 'Success'
		IF @massBatchID IS NOT NULL AND @massBatchID <> 0    
        BEGIN    
            Update  Tbl_MassOperationSummary set BatchEndTime= GetDate(), ScheduleDateTime=@Mail_ScheduleDate, Remarks = 'Record Saved', IsProcessed=1 where BatchID=@massbatchid    
        END    
	END
	ELSE
	BEGIN
		SELECT 'Insufficient Balance'
		IF @massBatchID IS NOT NULL AND @massBatchID <> 0    
        BEGIN    
            Update  Tbl_MassOperationSummary set BatchEndTime= GetDate(), ScheduleDateTime=@Mail_ScheduleDate, Remarks = 'Insufficient Balance', IsProcessed=1 where BatchID=@massbatchid    
        END    
	END

	DROP TABLE #tempTable

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM batchemail_infos(nolock)
			WHERE BatchID = @BatchID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'Insert User Enquiry mail'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'batchemail_infos'
END






GO

/* ============================================================
   Procedure: [dbo].[usp_SendMassMailFromEnquiry_WithTemplateID_WithFromMailID_new__ViaOtherDB]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
 CREATE   PROCEDURE [dbo].[usp_SendMassMailFromEnquiry_WithTemplateID_WithFromMailID_new__ViaOtherDB]                                   
 @IDS VARCHAR(MAX),                                  
 @Account BIGINT,                                  
 @Email_Subject VARCHAR(1000),                                  
 @Message_TemplateID Bigint,                                  
 @SenderName VARCHAR(100),                                  
 @ReplyTo VARCHAR(1000),                                  
 @EmailId BIT ,                                  
 @EmailId1 BIT ,                                  
 @EmailId2 BIT,        
 @FromMailID nvarchar(500)  = '',       
 @UserId bigint = 0,
 @massbatchid bigint=0,
 @Mail_ScheduleDate VARCHAR(50)='' 
AS                                  
BEGIN                 
select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))                
  
 CREATE TABLE #TableData2 (ID BIGINT)  
      if @massbatchid IS NOT NULL AND @massbatchid <> 0
	BEGIN
		select @IDS= STRING_AGG(cast(Entityid as nvarchar(max)),'#') from Tbl_MassOperationDetails where SummaryId=@massbatchid 
		--Update  Tbl_MassOperationSummary set BatchStartTime= GetDate()  where BatchID=@massbatchid 

		UPDATE Tbl_MassOperationSummary
        SET BatchStartTime = GETDATE(),
            ScheduleDateTime = CASE 
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'
                                 THEN @Mail_ScheduleDate
                                 ELSE ScheduleDateTime
                               END
        WHERE BatchID = @massbatchid;


	END
 INSERT INTO #TableData2 (ID)             
 select Item from fu_SplitString(@IDS,'#')  
  
DECLARE @MailCount BIGINT,@IsMonitor Bit = 1  , @getmessagestart datetime  , @getmessageend datetime  , @insertmessagestart datetime  , @insertmessageend datetime  
			,@count int=0, @TemptableName nvarchar(50)='', @sqls nvarchar(max)=''
DECLARE @m_id BIGINT,@parentid bigint          
 SELECT @m_id= ud.M_ID,@parentid=parentid                                  
                 FROM   User_Detail AS ud (nolock)                                 
                 WHERE  ud.[User_ID] = @Account         
 --dbo.fn_split(@IDS,'#')  
 SELECT @MailCount = (select count(1) from #TableData2)                             
  DECLARE @CurrentBalance BIGINT = (                                
             SELECT TOP 1 mcd.Balance                                
             FROM   MailCreditDetails AS mcd   (nolock)                             
             WHERE  mcd.[User_ID] = @parentid                                
             ORDER BY mcd.Credit_ID DESC                                
         )                                
                                 
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount                                
  IF @Balance > 0                                  
 BEGIN                                  
                       
 Declare @Message VARCHAR(MAX)                       
                      
  select @Message = MailContent  From UserMailTemplate(nolock) where ID= @Message_TemplateID                      
                                  
       set @getmessagestart=GETDATE();                 
 SELECT A.EmailID,                                  
        A.AccountID,                                  
        A.SenderName,                                  
        A.MailContent,                                  
        A.MailSubject,                                  
        A.ReplyTo,      
  A.EnquiryID  INTO #tempTable                                  
 FROM   (                                  
            SELECT ISNULL(A.EmailID, '') AS EmailID,                                  
                   @Account        AS AccountID,                                  
                   @SenderName     AS SenderName,                                  
                   A.MailContent,                                  
                   --@Email_Subject  AS MailSubject,                                  
                   A.MailSubject,
				   @ReplyTo        AS ReplyTo  ,      
        A.EnquiryID      
            FROM   (                                  
                       SELECT CASE                                   
                                   WHEN @EmailId = 1 THEN ul.EmailID                                  
                                   ELSE ''                                  
                              END AS EmailID,                                  
                              --dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID)                        
                               dbo.fn_getEnquiryMessageMail_new(ul.ParentID, @Message, ul.EmailID,ul.EnquiryID)  AS                                   
                              MailContent , 
							  dbo.fn_getEnquiryMessageMail_new(ul.ParentID, @Email_Subject, ul.EmailID,ul.EnquiryID)  AS                                   
                              MailSubject  ,    
         ul.EnquiryID      
                       FROM   UserEnquiry AS ul  (nolock)                
        inner join #TableData2 t2 on ul.EnquiryID = t2.ID   
                       WHERE   
        --ul.EnquiryID IN (SELECT [value]                                  
        --                                FROM   dbo.fn_Split(@IDS, '#') AS fs) AND               
                                                          
                                        ----Added By Siddharth ----                  
        
                       ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') <> ''                   
                      AND ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') not in                   
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID                   
                      from UserEnquiry UETemp (nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)                 
                      on (UETemp.EmailID =C_UDTemp.Email)                  
        inner join #TableData2 t2 on ul.EnquiryID = t2.ID   
                                      
                      --where ul.EnquiryID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs )  
       )                                
                       UNION ALL                                   
                                                         
                       SELECT CASE                                   
                                   WHEN @EmailId1 = 1 THEN ul.EmailID1                                  
                                   ELSE ''                                  
                              END AS EmailID,                                  
                             -- dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID1)                         
                             dbo.fn_getEnquiryMessageMail_new(ul.ParentID, @Message, ul.EmailID1,ul.EnquiryID)                         
                              AS                                   
                              MailContent  ,
							   dbo.fn_getEnquiryMessageMail_new(ul.ParentID, @Email_Subject, ul.EmailID1,ul.EnquiryID)  AS                                   
                              MailSubject  ,
         ul.EnquiryID                                
                       FROM   UserEnquiry AS ul  (nolock)                                
        inner join #TableData2 t2 on ul.EnquiryID = t2.ID   
                       WHERE    
        --ul.EnquiryID IN (SELECT [value] FROM  dbo.fn_Split(@IDS, '#') AS fs) AND                 
                                         
                       ----Added By Siddharth ----               
                                         
                      ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') <> ''                   
       AND ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') not in                   
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID                   
                      from UserEnquiry UETemp (nolock) inner join Client_UnSubscribeDetails C_UDTemp  (nolock)                
                      on (UETemp.EmailID1 =C_UDTemp.Email)                  
        inner join #TableData2 t2 on ul.EnquiryID = t2.ID   
                                      
                      --where ul.EnquiryID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs )  
       )                                   
                       UNION ALL                                  
                                                         
                       SELECT CASE                                   
                                   WHEN @EmailId2 = 1 THEN ul.EmailID2                                  
                                   ELSE ''                                  
                              END AS EmailID,                                  
                              --dbo.fn_getLeadsMailMessage(ul.ParentID, @Message, ul.EmailID2)                        
                              dbo.fn_getEnquiryMessageMail_new(ul.ParentID, @Message, ul.EmailID2,ul.EnquiryID)                        
                              AS                                   
                              MailContent   , 
							  dbo.fn_getEnquiryMessageMail_new(ul.ParentID, @Email_Subject, ul.EmailID2,ul.EnquiryID)  AS                                   
                              MailSubject 
							 ,
         ul.EnquiryID             
                       FROM   UserEnquiry AS ul  (nolock)                                
        inner join #TableData2 t2 on ul.EnquiryID = t2.ID   
                      WHERE   
       --ul.EnquiryID IN (SELECT [value] FROM   dbo.fn_Split(@IDS, '#') AS fs)  AND                
                                         
                         ----Added By Siddharth ----                  
                                         
                       ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') <> ''                   
                      AND ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') not in                   
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID                   
                      from UserEnquiry UETemp (nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)                 
                      on (UETemp.EmailID2 =C_UDTemp.Email)                  
        inner join #TableData2 t2 on ul.EnquiryID = t2.ID   
                                      
                      --where ul.EnquiryID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs )  
       )                   
                       
                                                       
                   )                  A                                  
            WHERE  ISNULL(A.EmailID, '') <> ''                                  
        ) A                                  
               set @getmessageend=GETDATE();                     
  Drop table #TableData2  
  
Declare @Status Bigint=0,@CountLimit bigint = 0                            
select @Status = status,@CountLimit = Plimit from ProcessMailLimit                          
                                  
  if(@Status=1)                            
  Begin                            
Begin                            
  if(@MailCount > @CountLimit )                            
  Begin                            
   set @IsMonitor = 0                             
  End                            
 End                            
   End                            
                              
                               
                                       
                                       
 DECLARE @BatchID BIGINT          
 begin tran                                    
 INSERT INTO GetBatchRecord                                
       (                                
         [User_id],                                
         RandNum                                
       )                   
     VALUES                                
       (                                
         @Account,                                
         @Account                                
       )                                      
select @BatchID=SCOPE_IDENTITY()                                     
DELETE                              
     FROM GetBatchRecord                                
     WHERE batchid=@BatchID          
 commit                                    
                                     
           
     DECLARE @Mail_FromEmail VARCHAR(500) = ''                                  
          
  if(@FromMailID = '')        
  Begin        
select @Mail_FromEmail=coalesce((select top 1 mail_id from defaultmailid(nolock) where user_id=@account order by datecreated desc),          
    (SELECT ud.EMail FROM   User_Detail AS ud  (nolock) WHERE  ud.[User_ID] = @Account),'contactus@email19.in')           
  End        
  else        
  Begin        
    set  @Mail_FromEmail = @FromMailID        
  End        
         set @insertmessagestart=GETDATE();
		  set @count= (Select COUNT(*) from #tempTable)
		--select @count


		INSERT INTO BatchEmail_Infos                                  
        (                                  
         -- ID -- this column value is auto-generated                                  
         BatchID,                                  
         UserID,                                  
         SenderName,                                  
         [Message],                                  
         TotalRecords,                                  
         TotalProcessed,                                  
         ProcessTable,                                  
         IsProcess,                                  
         Priority_Level,                                  
         BatchInsertTime,                                  
         BatchProcessTime,                                  
         ScheduledDate,                                  
         ScheduledTime,                                  
         TemplateID,                                  
         [Route],                                  
         PageName,                                  
         IsScheduled,                                  
         Email_Subject,                                  
         ReplyTo,                                  
        Amount,                                  
         Currency                                  
       )                                  
     SELECT @BatchID,                                  
            A.AccountID,                                  
            --A.SenderName,                                  
            @Mail_FromEmail,
			--@Message,                                  
            A.MailContent,
			COUNT(*),                                  
            0,                                  
            0,                                  
            0,                                  
            0,                                 
            GETDATE(),                                  
            NULL,                                  
            @Mail_ScheduleDate,             
            @Mail_ScheduleDate,                                  
            NULL,                                  
            NULL,                                  
            NULL,                                  
            0,                                  
            A.MailSubject,                           
            A.ReplyTo,                                  
            COUNT(*),                                  
            'INR'                                  
     FROM   #tempTable A                                  
     GROUP BY                                  
            A.AccountID,                                  
            --A.SenderName,                                  
            A.MailContent,
			A.MailSubject,                                  
            A.ReplyTo

    INSERT INTO MailCreditDetails                                  
       (                                  
         FromUser_ID,                                  
         M_ID,                                  
         USER_ID,                                  
         Debits,                                  
         Credits,                                  
         Balance ,                              
         Validity                                 
       )                                  
     VALUES                                  
       (                                  
         @Account,                                  
         @m_id,                              
         @Account,                                  
         @MailCount,                                  
         0,                                  
         @Balance,                              
         99999                                
       )
	   		 	  

	if @count <100
  BEGIN
		insert into [10.0.0.135].[MysmsTrans].[dbo].CloneEmailsFilter(Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,          
		Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source,EntityName
            ,EntityID
            ,IsMatched)          
		select @Mail_FromEmail,A.EmailID,A.MailSubject,'',A.MailContent,GETDATE(),@UserId,@parentid,A.ReplyTo,@BatchID,1,@Mail_ScheduleDate,@Mail_ScheduleDate,'',A.MailContent,@ismonitor,0,@mailcount,'Enquiry-MassSend','Enquiry'
		    ,A.EnquiryID
		    ,0           
		from #tempTable A          
 end 
  ELSE 
 BEGIN
	DROP TABLE  IF EXISTS #tableName   
	CREATE TABLE #tableName (TableName nvarchar(max)  )   

	INSERT INTO #tableName (TableName)
	--EXEC usp_CreateCloneEmailTable @UserID=@UserID
	Exec [10.0.0.135].[MysmsTrans].[dbo].usp_CreateCloneEmailTable_WithoutTRG_WithIsMatch @UserID

	set @TemptableName = (Select top 1 TableName from #tableName) 

	set @sqls =	'	insert into [10.0.0.135].[MysmsTrans].[dbo].'+@TemptableName+' (Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,          
		Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source,EntityName,EntityID,IsMatched)          
		select '''+@Mail_FromEmail+''',A.EmailID,A.MailSubject,'''',A.MailContent,GETDATE(),'+cast(@UserId as varchar )+','+cast(@parentid as varchar)+',A.ReplyTo, '+cast(@BatchID as varchar)+',1,'''+@Mail_ScheduleDate+''','''+@Mail_ScheduleDate+''','''',A.MailContent,'+cast(@ismonitor as varchar)+',0,'+cast(@mailcount as varchar)+',''Enquiry-MassSend'',''Enquiry'', A.EnquiryID, 0           
		from #tempTable A'        
		print @sqls
		execute sp_executesql @sqls

 END
       
         set @insertmessageend=GETDATE();
 if(@UserId  > 0 )        
  begin        
   declare  @Username nvarchar(255)      
   declare @leadActivityHistory AS LeadActivitywithid_Tbltype        
      
   select @Username = User_Login from User_Detail(nolock) where User_Id = @UserId      
        
   insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )        
    select         
  EnquiryId,        
  @UserId,         
  @parentid,        
  concat(@Username , '  sent mail with subject ', MailSubject , ' to emailid ', EmailID),        
  'Mail sent to Enquiry',        
  'Batchemail_infos',            
  @BatchID        
    from #tempTable        
       
  exec UspSaveentityActivity_withMultipleValue_withid_bulk @leadActivityHistory         end      
      
      
      
     SELECT 'Success', @getmessagestart getmessagestart,  @getmessageend getmessageend,  @insertmessagestart insertmessagestart,  @insertmessageend insertmessageend, @TemptableName tablename
	 if @massBatchID IS NOT NULL AND @massBatchID <> 0
	BEGIN
		--Update  Tbl_MassOperationSummary set BatchEndTime= GetDate() , Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@massBatchID 
	   UPDATE Tbl_MassOperationSummary
        SET BatchEndTime = GETDATE(),
            ScheduleDateTime = CASE 
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'
                                 THEN @Mail_ScheduleDate
                                 ELSE ScheduleDateTime
                               END,
            Remarks = 'Record Saved',
            IsProcessed = 1
        WHERE BatchID = @massbatchid;

	END
 END                                  
 ELSE                                  
 BEGIN                                  
     SELECT 'Insufficient Balance'                                  
 END                                  
                                   
 DROP TABLE #tempTable                                  
END     


GO

/* ============================================================
   Procedure: [dbo].[usp_SendMassMailFromEnquiry_WithTemplateID_WithFromMailID_new_bulkreplace]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
----------------------------------------------------------------------  
CREATE   PROCEDURE [dbo].[usp_SendMassMailFromEnquiry_WithTemplateID_WithFromMailID_new_bulkreplace]    
 @IDS VARCHAR(MAX),    
 @Account BIGINT,    
 @Email_Subject VARCHAR(1000),    
 @Message_TemplateID Bigint,    
 @SenderName VARCHAR(100),    
 @ReplyTo VARCHAR(1000),    
 @EmailId BIT,    
 @EmailId1 BIT,    
 @EmailId2 BIT,    
 @FromMailID nvarchar(500)  = '',    
 @UserId bigint = 0,    
 @massbatchid bigint=0 ,    
 @Mail_ScheduleDate VARCHAR(50)=''    
AS    
BEGIN    
    select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))    
    
    CREATE TABLE #TableData2 (Sno int identity, ID BIGINT)    
    if @massbatchid IS NOT NULL AND @massbatchid <> 0    
    BEGIN    
        select @IDS= STRING_AGG(cast(Entityid as nvarchar(max)),'#') from Tbl_MassOperationDetails where SummaryId=@massbatchid    
        --Update  Tbl_MassOperationSummary set BatchStartTime= GetDate()  where BatchID=@massbatchid    
  UPDATE Tbl_MassOperationSummary  
        SET BatchStartTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @Mail_ScheduleDate  
                                 ELSE ScheduleDateTime  
                               END  
        WHERE BatchID = @massbatchid;  
    END    
    
	INSERT INTO #TableData2 (ID)    
    select Item from fu_SplitString(@IDS,'#')    
    
    DECLARE @MailCount BIGINT, @IsMonitor Bit = 1, @getmessagestart datetime, @getmessageend datetime, @insertmessagestart datetime, @insertmessageend datetime,    
            @count int=0, @TemptableName nvarchar(50)='', @sqls nvarchar(max)='', @m_id BIGINT, @parentid bigint    
    
    SELECT @m_id= ud.M_ID, @parentid=parentid    
    FROM   User_Detail AS ud (nolock)    
    WHERE  ud.[User_ID] = @Account    
    
    SELECT @MailCount = (select count(1) from #TableData2)    
    DECLARE @CurrentBalance BIGINT = (    
        SELECT TOP 1 mcd.Balance    
        FROM   MailCreditDetails AS mcd   (nolock)    
        WHERE  mcd.[User_ID] = @parentid    
        ORDER BY mcd.Credit_ID DESC    
    )    
    
    DECLARE @Balance BIGINT = @CurrentBalance - @MailCount    
    IF @Balance > 0    
    BEGIN    
        Declare @Message VARCHAR(MAX)    
    
        select @Message = MailContent  From UserMailTemplate(nolock) where ID= @Message_TemplateID    
    

--code to get replaced values
declare @entity nvarchar(20)='Enquiry',@entityplaceholders nvarchar(2000)                                         
  drop table if exists #entitypcvalues
  drop table if exists #entitypcvalues_subject
  
  declare @entities as entities
  create table #entitypcvalues(entityid bigint,content nvarchar(max))
  create table #entitypcvalues_subject(entityid bigint,msubject nvarchar(500))

   insert into @entities(entity,entityid)
   select @entity,ID from #TableData2


  select @entityplaceholders=dbo.ExtractPlaceholders(@entity,@message)

 
   if @entityplaceholders<>''
   begin
   insert into #entitypcvalues(entityid,content)
   exec [usp_replaceentityplaceholders_bulk_singlecontent] @entities,@message
   end
   else
   begin
     insert into #entitypcvalues(entityid,content)
     select entityid,@message from @entities
   end

     select @entityplaceholders=dbo.ExtractPlaceholders(@entity,@Email_Subject)

 if @entityplaceholders<>''
   begin
   insert into #entitypcvalues_subject(entityid,msubject)
   exec [usp_replaceentityplaceholders_bulk_singlecontent] @entities,@Email_Subject
   end
   else
   begin
   insert into #entitypcvalues_subject(entityid,msubject)
     select entityid,@Email_Subject from @entities
   end






        set @getmessagestart=GETDATE();    
        Declare @mincount int = 1, @maxcount int = 100    
        while exists (Select 1 from #TableData2 where Sno between @mincount and @maxcount)    
        BEGIN    
            SELECT A.EmailID,    
                A.AccountID,    
                A.SenderName,    
                A.MailContent,    
                A.MailSubject,    
                A.ReplyTo,    
                A.EnquiryID  INTO #tempTable    
            FROM (    
                SELECT ISNULL(A.EmailID, '') AS EmailID,    
                    @Account        AS AccountID,    
                    @SenderName     AS SenderName,    
                    A.MailContent,    
                    A.MailSubject,    
                    @ReplyTo        AS ReplyTo,    
                    A.EnquiryID    
                FROM (    
                    SELECT CASE    
                        WHEN @EmailId = 1 THEN ul.EmailID    
                        ELSE ''    
                        END AS EmailID,    
                        --dbo.fn_getEnquiryMessageMail_new(ul.ParentID, @Message, ul.EmailID, ul.EnquiryID) AS MailContent,    
                        --dbo.fn_getEnquiryMessageMail_new(ul.ParentID, @Email_Subject, ul.EmailID, ul.EnquiryID) AS MailSubject,  
						content as MailContent,
						msubject as MailSubject,
                        ul.EnquiryID    
                    FROM UserEnquiry AS ul (nolock)    
                    inner join #TableData2 t2 on ul.EnquiryID = t2.ID   
					inner join #entitypcvalues ep on ep.entityid=ul.enquiryid
				    inner join #entitypcvalues_subject es on es.entityid=ul.enquiryid
                    WHERE ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') <> ''    
                        --AND ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') not in (    
                        --    select ISNULL(C_UDTemp.Email,'') as EmailID    
                        --    from UserEnquiry UETemp (nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)    
                        --    on (UETemp.EmailID =C_UDTemp.Email)    
                        --    inner join #TableData2 t2 on ul.EnquiryID = t2.ID    
                        --    where t2.Sno between @mincount and @maxcount    
                        --) 
						AND t2.Sno between @mincount and @maxcount    
                    UNION ALL    
  SELECT CASE    
                        WHEN @EmailId1 = 1 THEN ul.EmailID1    
                        ELSE ''    
                        END AS EmailID,    
                        --dbo.fn_getEnquiryMessageMail_new(ul.ParentID, @Message, ul.EmailID, ul.EnquiryID) AS MailContent,    
                        --dbo.fn_getEnquiryMessageMail_new(ul.ParentID, @Email_Subject, ul.EmailID, ul.EnquiryID) AS MailSubject,  
						content as MailContent,
						msubject as MailSubject,   
                        ul.EnquiryID    
                    FROM UserEnquiry AS ul (nolock)    
                    inner join #TableData2 t2 on ul.EnquiryID = t2.ID    
					inner join #entitypcvalues ep on ep.entityid=ul.enquiryid
				    inner join #entitypcvalues_subject es on es.entityid=ul.enquiryid
                    WHERE ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') <> ''    
                        --AND ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') not in (    
                        --    select ISNULL(C_UDTemp.Email,'') as EmailID    
                        --    from UserEnquiry UETemp (nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)    
                        --    on (UETemp.EmailID1 =C_UDTemp.Email)    
                        --    inner join #TableData2 t2 on ul.EnquiryID = t2.ID    
                        --    where t2.Sno between @mincount and @maxcount    
                        --) 
						AND t2.Sno between @mincount and @maxcount    
                    UNION ALL    
                    SELECT CASE    
                        WHEN @EmailId2 = 1 THEN ul.EmailID2    
                        ELSE ''    
                        END AS EmailID,    
                        --dbo.fn_getEnquiryMessageMail_new(ul.ParentID, @Message, ul.EmailID, ul.EnquiryID) AS MailContent,    
                        --dbo.fn_getEnquiryMessageMail_new(ul.ParentID, @Email_Subject, ul.EmailID, ul.EnquiryID) AS MailSubject,  
						content as MailContent,
						msubject as MailSubject,   
                        ul.EnquiryID    
                    FROM UserEnquiry AS ul (nolock)    
                    inner join #TableData2 t2 on ul.EnquiryID = t2.ID  
					inner join #entitypcvalues ep on ep.entityid=ul.enquiryid
				    inner join #entitypcvalues_subject es on es.entityid=ul.enquiryid
                    WHERE ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') <> ''    
                        --AND ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') not in (    
                        --    select ISNULL(C_UDTemp.Email,'') as EmailID    
                        --    from UserEnquiry UETemp (nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)    
                        --    on (UETemp.EmailID2 =C_UDTemp.Email)    
                        --    inner join #TableData2 t2 on ul.EnquiryID = t2.ID  
							
                        --    where t2.Sno between @mincount and @maxcount    
                        --) 
						
						AND t2.Sno between @mincount and @maxcount    
                ) A    
                WHERE ISNULL(A.EmailID, '') <> ''    
            ) A    
            set @getmessageend=GETDATE();    
    
            Declare @Status Bigint=0, @CountLimit bigint = 0    
            select @Status = status, @CountLimit = Plimit from ProcessMailLimit    
    
            if(@Status=1)    
            BEGIN    
                IF(@MailCount > @CountLimit)    
                BEGIN    
                    set @IsMonitor = 0    
                END    
            END    
    
            DECLARE @BatchID BIGINT    
            BEGIN TRAN    
            INSERT INTO GetBatchRecord ([User_id], RandNum)    
            VALUES (@Account, @Account)    
            SELECT @BatchID=SCOPE_IDENTITY()    
            DELETE FROM GetBatchRecord WHERE batchid=@BatchID    
            COMMIT    
    
            DECLARE @Mail_FromEmail VARCHAR(500) = ''    
    
            if(@FromMailID = '')    
            BEGIN    
                select @Mail_FromEmail=coalesce((select top 1 mail_id from defaultmailid(nolock) where user_id=@account order by datecreated desc),    
                    (SELECT ud.EMail FROM   User_Detail AS ud  (nolock) WHERE  ud.[User_ID] = @Account),'contactus@email19.in')    
            END    
            else    
            BEGIN    
                set  @Mail_FromEmail = @FromMailID    
            END    
            set @insertmessagestart=GETDATE();    
            set @count= (Select COUNT(*) from #tempTable)    
            if @count < 100    
            BEGIN    
                insert into CloneEmailsFilter(Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,    
                Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source)    
                select @Mail_FromEmail,A.EmailID,A.MailSubject,'',A.MailContent,GETDATE(),@UserId,@parentid,A.ReplyTo,@BatchID,1,'','','',A.MailContent,@ismonitor,0,@mailcount,'Enquiry-MassSend'    
                from #tempTable A    
            END    
            ELSE    
            BEGIN    
                DROP TABLE IF EXISTS #tableName    
                CREATE TABLE #tableName (TableName nvarchar(max))    
    
                INSERT INTO #tableName (TableName)    
                EXEC usp_CreateCloneEmailTable @UserID=@UserID    
                set @TemptableName = (Select top 1 TableName from #tableName)    
    
                set @sqls = ' insert into '+@TemptableName+' (Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,    
                Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source)    
                select '''+@Mail_FromEmail+''',A.EmailID,A.MailSubject,'''',A.MailContent,GETDATE(),'+cast(@UserId as varchar )+','+cast(@parentid as varchar)+',A.ReplyTo, '+cast(@BatchID as varchar)+',1,'''','''','''',A.MailContent,'+cast(@ismonitor as varchar)+',0,'+cast(@mailcount as varchar)+',''Enquiry-MassSend''    
                from #tempTable A'    
                print @sqls    
                execute sp_executesql @sqls    
            END    
    
            set @insertmessageend=GETDATE();    
            if(@UserId  > 0 )    
            begin    
                declare  @Username nvarchar(255)    
                declare @leadActivityHistory AS LeadActivitywithid_Tbltype    
    
                select @Username = User_Login from User_Detail(nolock) where User_Id = @UserId    
    
                insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )    
                select EnquiryId, @UserId, @parentid, concat(@Username , '  sent mail with subject ', MailSubject , ' to emailid ', EmailID), 'Mail sent to Enquiry', 'Batchemail_infos', @BatchID    
                from #tempTable    
    
                exec UspSaveentityActivity_withMultipleValue_withid_bulk @leadActivityHistory    
            end    
            delete from @leadActivityHistory    
            set @mincount =@mincount+100    
            set @maxcount = @maxcount +100    
        END    
    
        SELECT 'Success', @getmessagestart getmessagestart,  @getmessageend getmessageend,  @insertmessagestart insertmessagestart,  @insertmessageend insertmessageend, @TemptableName tablename    
    
        IF @massBatchID IS NOT NULL AND @massBatchID <> 0    
        BEGIN    
           -- Update  Tbl_MassOperationSummary set BatchEndTime= GetDate(), ScheduleDateTime=@Mail_ScheduleDate, Remarks = 'Record Saved', IsProcessed=1 where BatchID=@massbatchid    
     UPDATE Tbl_MassOperationSummary  
        SET BatchEndTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @Mail_ScheduleDate  
                                 ELSE ScheduleDateTime  
                               END,  
            Remarks = 'Record Saved',  
            IsProcessed = 1  
        WHERE BatchID = @massbatchid;  
        END    
    END    
    ELSE    
    BEGIN    
        SELECT 'Insufficient Balance'    
    END    
    
    declare @rowJson nvarchar(max)= (Select * from CloneEmailsFilter (nolock) where Mail_BatchID=@batchid for json auto, include_null_values)    
    if(@rowJson is not null)    
    BEGIN    
        EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId, @Activity_type = 'Inst_MassMail_Enq', @ActionType = 'I', @RowJson = @rowJson, @Table_name = 'CloneEmailsFilter'    
    END    
    
    DROP TABLE #TableData2    
    DROP TABLE #tempTable    
END    
  


GO

