--   WHERE Mail_BatchID = @BatchID          
--   FOR JSON AUTO          
--    ,INCLUDE_NULL_VALUES          
--   )          
          
-- EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId          
--  ,@Activity_type = 'Inst_Mail_Lead'          
-- ,@ActionType = 'I'          
--  ,@RowJson = @rowJson          
--  ,@Table_name = 'CloneEmailsFilter'          
--END     
  
BEGIN     
 SET NOCOUNT ON;   
  
  
      BEGIN TRY 
	   -- Check if @IDS is NULL or blank
        IF @IDS IS NULL OR LTRIM(RTRIM(@IDS)) = ''
        BEGIN
            -- Return message if @IDS is null or blank
            SELECT 'ID is null or blank' AS StatusMessage;
            RETURN;
        END
    
       DECLARE @IDsTable TABLE (ID BIGINT);  
        DECLARE @InsertedTable TABLE (EntityID BIGINT);  
        DECLARE @ParentID BIGINT;  
        DECLARE @NewBatchID BIGINT;  
     
  
      
        -- Fetch the ParentID using @UserId  
        SELECT @ParentID = ParentID  
        FROM User_Detail (NOLOCK)  
        WHERE User_ID = @UserId;  
   
      
       INSERT INTO Tbl_MassOperationSummary (  
            MassOperationName,  
            UserID,  
            Parentid,  
            CreatedDate,  
            IsProcessed,  
            Remarks,  
            BatchStartTime,  
            BatchEndTime,  
            EntityType,  
            isvalid,  
            metadata,  
            ErrorDetails,  
            SenderId,  
            UrlTrack,  
     TrackedUrl,  
            SmsPlaceHolder,  
   ScheduleDateTime  
        )  
        VALUES (  
            'Send Mail',  
            @UserId,  
            @ParentID,  
            GETDATE(),  
            0,  
            NULL,  
            null,  
            NULL,  
            @ModuleType,  
            1,  
            @metatdata, -- metadata  
            NULL,  
            NULL,  
            NULL,  
   NULL,  
            NULL,  
   @Mail_ScheduleDate  
        );  
  
        -- Get the BatchID of the last inserted row  
        SELECT @NewBatchID = SCOPE_IDENTITY();  
  
       /* -- Remove braces from @IDS if they exist  
        SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');  
  
        -- Split the IDs and insert into the temporary table  
        DECLARE @Pos INT, @Str VARCHAR(MAX);  
        SET @Pos = 1;  
        WHILE CHARINDEX(',', @IDS, @Pos) > 0  
        BEGIN  
            SET @Str = SUBSTRING(@IDS, @Pos, CHARINDEX(',', @IDS, @Pos) - @Pos);  
            INSERT INTO @IDsTable (ID) VALUES (CAST(@Str AS BIGINT));  
            SET @Pos = CHARINDEX(',', @IDS, @Pos) + 1;  
        END  
        INSERT INTO @IDsTable (ID) VALUES (CAST(SUBSTRING(@IDS, @Pos, LEN(@IDS) - @Pos + 1) AS BIGINT));  
  
        -- Insert records into Tbl_MassOperationDetails using the new BatchID  
        INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)  
        SELECT @NewBatchID, ID FROM @IDsTable;  */
		-- Remove braces from @IDS if they exist  
        SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');  
  
        -- Split the @IDS string and insert into the @IDsTable table using STRING_SPLIT
        INSERT INTO @IDsTable (ID)
        SELECT CAST(value AS BIGINT)
        FROM STRING_SPLIT(@IDS, ',');
  
        -- Insert records into Tbl_MassOperationDetails using the new BatchID  
        INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)  
        SELECT @NewBatchID, ID FROM @IDsTable;  
  
  -- Call Usp_MassOperationLeadEnquiryProcess with the new BatchID  
        EXEC [dbo].[Usp_MassOperationLeadEnquiryProcess] @summary_batchid = @NewBatchID;  
  
        -- Return a status message and count of rows inserted for the given IDs  
        SELECT 'Success' AS StatusMessage, COUNT(*) AS TotalRecords FROM @IDsTable;  
  
    END TRY  
    BEGIN CATCH  
       EXEC usp_InsertErrorInfo;   
    END CATCH;  
  
 END

-----------------------------------------------------------------




GO

/* ============================================================
   Procedure: [dbo].[usp_SendMassMailFromLeads_FromMailID_ViaOtherDB]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_SendMassMailFromLeads_FromMailID_ViaOtherDB]
     @IDS VARCHAR(MAX)=''
	,@Account BIGINT
	,@Email_Subject VARCHAR(1000)
	,@Message VARCHAR(MAX)
	,@SenderName VARCHAR(100)
	,@ReplyTo VARCHAR(1000)
	,@EmailId BIT
	,@EmailId1 BIT
	,@EmailId2 BIT
	,@UserId BIGINT = 0
	,@FromMailID VARCHAR(500)
	,@massbatchid bigint=0
	,@Mail_ScheduleDate VARCHAR(50)=''   
AS
BEGIN
	--select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))                
	DECLARE @MailCount BIGINT
		,@IsMonitor BIT = 1
	DECLARE @m_id BIGINT
		,@parentid BIGINT

	SELECT @m_id = ud.M_ID
		,@parentid = parentid
	FROM User_Detail AS ud(NOLOCK)
	WHERE ud.[User_ID] = @Account

	if @massbatchid IS NOT NULL AND @massbatchid <> 0
	BEGIN
		select @IDS= STRING_AGG(cast(Entityid as nvarchar(max)),'#') from Tbl_MassOperationDetails where SummaryId=@massbatchid 
		--Update  Tbl_MassOperationSummary set BatchStartTime= GetDate()  where BatchID=@massbatchid 

		UPDATE Tbl_MassOperationSummary
        SET BatchStartTime = GETDATE(),
            ScheduleDateTime = CASE 
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'
                                 THEN @Mail_ScheduleDate
                                 ELSE ScheduleDateTime
                               END
        WHERE BatchID = @massbatchid;

	END
	SELECT @MailCount = (
			SELECT count(1)
			FROM dbo.fn_split(@IDS, '#')
			)

	DECLARE @CurrentBalance BIGINT = (
			SELECT TOP 1 mcd.Balance
			FROM MailCreditDetails AS mcd(NOLOCK)
			WHERE mcd.[User_ID] = @parentid
			ORDER BY mcd.Credit_ID DESC
			)
	DECLARE @Balance BIGINT = @CurrentBalance - @MailCount

	IF @Balance > 0
	BEGIN
		SELECT A.EmailID
			,A.AccountID
			,A.SenderName
			,A.MailContent
			,A.MailSubject
			,A.ReplyTo
			,A.leadid
		INTO #tempTable
		FROM (
			SELECT ISNULL(A.EmailID, '') AS EmailID
				,@Account AS AccountID
				,@SenderName AS SenderName
				,A.MailContent
				--,@Email_Subject AS MailSubject
				,A.MailSubject
				,@ReplyTo AS ReplyTo
				,Leadid
			FROM (
				SELECT CASE 
						WHEN @EmailId = 1
							THEN ul.EmailID
						ELSE ''
						END AS EmailID
					,dbo.fn_getLeadsMailMessage_new(ul.ParentID, @Message, ul.EmailID,ul.id) AS MailContent
					,dbo.fn_getLeadsMailMessage_new(ul.ParentID, @Email_Subject, ul.EmailID,ul.id) AS MailSubject
					,ul.ID AS leadid
				FROM UserLeads AS ul(NOLOCK)
				WHERE ul.ID IN (
						SELECT [value]
						FROM dbo.fn_Split(@IDS, '#') AS fs
						)
					AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') <> ''
					AND ISNULL(NULLIF(CAST(ul.EmailID AS VARCHAR), ''), '') NOT IN (
						SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
						FROM UserLeads UETemp(NOLOCK)
						INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID = C_UDTemp.Email)
						WHERE ul.ID IN (
								SELECT fs.value
								FROM dbo.fn_Split(@IDS, '#') AS fs
								)
						)
				
				UNION ALL
				
				SELECT CASE 
						WHEN @EmailId1 = 1
							THEN ul.EmailID1
						ELSE ''
						END AS EmailID
					,dbo.fn_getLeadsMailMessage_new(ul.ParentID, @Message, ul.EmailID1,ul.id) as MailContent
					,dbo.fn_getLeadsMailMessage_new(ul.ParentID, @Email_Subject, ul.EmailID1,ul.id) AS MailSubject
					,ul.ID AS leadid
				FROM UserLeads AS ul(NOLOCK)
				WHERE ul.ID IN (
						SELECT [value]
						FROM dbo.fn_Split(@IDS, '#') AS fs
						)
					AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') <> ''
					AND ISNULL(NULLIF(CAST(ul.EmailID1 AS VARCHAR), ''), '') NOT IN (
						SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
						FROM UserLeads UETemp(NOLOCK)
						INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID1 = C_UDTemp.Email)
						WHERE ul.ID IN (
								SELECT fs.value
								FROM dbo.fn_Split(@IDS, '#') AS fs
								)
						)
					AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') <> ''
					AND ISNULL(NULLIF(CAST(ul.EmailID2 AS VARCHAR), ''), '') NOT IN (
						SELECT ISNULL(C_UDTemp.Email, '') AS EmailID
						FROM UserLeads UETemp(NOLOCK)
						INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (UETemp.EmailID2 = C_UDTemp.Email)
						WHERE ul.ID IN (
								SELECT fs.value
								FROM dbo.fn_Split(@IDS, '#') AS fs
								)
						)
				
				UNION ALL
				
				SELECT CASE 
						WHEN @EmailId2 = 1
							THEN ul.EmailID2
						ELSE ''
						END AS EmailID
					,dbo.fn_getLeadsMailMessage_new(ul.ParentID, @Message, ul.EmailID2,ul.id) as MailContent
					,dbo.fn_getLeadsMailMessage_new(ul.ParentID, @Email_Subject, ul.EmailID2,ul.id) AS MailSubject
					,ul.ID AS leadid
				FROM UserLeads AS ul(NOLOCK)
				WHERE ul.ID IN (
						SELECT [value]
						FROM dbo.fn_Split(@IDS, '#') AS fs
						)
				) A
			WHERE ISNULL(A.EmailID, '') <> ''
			) A

		DECLARE @Status BIGINT = 0
			,@CountLimit BIGINT = 0

		SELECT @Status = STATUS
			,@CountLimit = Plimit
		FROM ProcessMailLimit

		IF (@Status = 1)
		BEGIN
			BEGIN
				IF (@MailCount > @CountLimit)
				BEGIN
					SET @IsMonitor = 0
				END
			END
		END

		DECLARE @BatchID BIGINT

		BEGIN TRAN

		INSERT INTO GetBatchRecord (
			[User_id]
			,RandNum
			)
		VALUES (
			@Account
			,@Account
			)

		SELECT @BatchID = SCOPE_IDENTITY()

		DELETE
		FROM GetBatchRecord
		WHERE batchid = @BatchID

		COMMIT

		DECLARE @Mail_FromEmail VARCHAR(500) = ''

		SELECT @Mail_FromEmail = coalesce((
					SELECT TOP 1 mail_id
					FROM defaultmailid(NOLOCK)
					WHERE user_id = @account
					ORDER BY datecreated DESC
					), (
					SELECT ud.EMail
					FROM User_Detail AS ud(NOLOCK)
					WHERE ud.[User_ID] = @Account
					), 'contactus@email19.in')

		IF (rtrim(ltrim(@FromMailID)) <> '')
		BEGIN
			SET @Mail_FromEmail = @FromMailID
		END
		
       INSERT INTO BatchEmail_Infos                                  
        (                                  
         -- ID -- this column value is auto-generated                                  
         BatchID,                                  
         UserID,                                  
         SenderName,                                  
         [Message],                                  
         TotalRecords,                                  
         TotalProcessed,                                  
         ProcessTable,                                  
         IsProcess,                                  
         Priority_Level,                                  
         BatchInsertTime,                                  
         BatchProcessTime,                                  
         ScheduledDate,                                  
         ScheduledTime,                                  
         TemplateID,                                  
         [Route],                                  
         PageName,                                  
         IsScheduled,                                  
         Email_Subject,                                  
         ReplyTo,                                  
        Amount,                                  
         Currency                                  
       )                                  
     SELECT @BatchID,                                  
            A.AccountID,                                  
            --A.SenderName,                                  
            @Mail_FromEmail,
			--@Message,                                  
            A.MailContent,
			COUNT(*),                                  
            0,                                  
            0,                                  
            0,                                  
            0,                                 
            GETDATE(),                                  
            NULL,                                  
            @Mail_ScheduleDate,             
            @Mail_ScheduleDate,                                  
            NULL,                                  
            NULL,                                  
            NULL,                                  
            0,                                  
            A.MailSubject,                           
            A.ReplyTo,                                  
            COUNT(*),                                  
            'INR'                                  
     FROM   #tempTable A                                  
     GROUP BY                                  
            A.AccountID,                                  
            --A.SenderName, 
			A.MailContent,
            A.MailSubject,                                  
            A.ReplyTo

    INSERT INTO MailCreditDetails                                  
       (                                  
         FromUser_ID,                                  
         M_ID,                                  
         USER_ID,                                  
         Debits,                                  
         Credits,                                  
         Balance ,                              
         Validity                                 
       )                                  
     VALUES                                  
       (                                  
         @Account,                                  
         @m_id,                              
         @Account,                                  
         @MailCount,                                  
         0,                                  
         @Balance  ,                              
         99999                                
       )

		INSERT INTO [10.0.0.135].[MysmsTrans].[dbo].CloneEmailsFilter (
			Mail_FromEmail
			,Mail_ToEmail
			,Mail_Subject
			,Mail_TempleteName
			,Messages
			,Mail_InsertedDate
			,Mail_UserID
			,Mail_ParentID
			,ReplyTo
			,Mail_BatchID
			,Mail_Priority
			,Mail_ScheduleDate
			,Mail_ScheduledTime
			,Mail_Attechement
			,Mail_TempleteBody
			,IsMonitor
			,TemplateID
			,Count
			,Source
			,EntityName
            ,EntityID
            ,IsMatched
			)
		SELECT @Mail_FromEmail
			,A.EmailID
			,A.MailSubject
			,''
			,A.MailContent
			,GETDATE()
			,@UserId
			,@parentid
			,A.ReplyTo
			,@BatchID
			,1
			,@Mail_ScheduleDate      
            ,@Mail_ScheduleDate
			,''
			,A.MailContent
			,@ismonitor
			,0
			,@mailcount
			,'Leads-MassSend'
			,'Lead'
		    ,A.leadid
		    ,0
		FROM #tempTable A

		
		IF (@UserId > 0)
		BEGIN
			DECLARE @leadActivityHistory AS LeadActivitywithid_Tbltype
			DECLARE @Username NVARCHAR(255) = (
					SELECT User_Login
					FROM User_Detail(NOLOCK)
					WHERE User_Id = @UserId
					)

			INSERT INTO @leadActivityHistory (
				LeadID
				,UserID
				,ParentID
				,EventDescription
				,EventName
				,RefTable
				,refid
				)
			SELECT leadid
				,@UserId
				,@parentid
				,CONCAT (
					@Username
					,' sent a mail with subject '
					,MailSubject
					,' to emailid '
					,EmailID
					)
				,'Mail sent to lead'
				,'Batchemail_infos'
				,@BatchID
			FROM #tempTable

			EXEC UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory
		END

		SELECT 'Success'
		if @massBatchID IS NOT NULL AND @massBatchID <> 0
	BEGIN
		--Update  Tbl_MassOperationSummary set BatchEndTime= GetDate() , Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@massBatchID 

		 UPDATE Tbl_MassOperationSummary
        SET BatchEndTime = GETDATE(),
            ScheduleDateTime = CASE 
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'
                                 THEN @Mail_ScheduleDate
                                 ELSE ScheduleDateTime
                               END,
            Remarks = 'Record Saved',
            IsProcessed = 1
        WHERE BatchID = @massBatchID;

	END
		
	END
	ELSE
	BEGIN
		SELECT 'Insufficient Balance'
	END

	DROP TABLE #tempTable

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM CloneEmailsFilter
			WHERE Mail_BatchID = @BatchID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'Inst_Mail_Lead'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'CloneEmailsFilter'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_SendMassMailFromLeads_WithTemplateID_FromMailID_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
    
    
CREATE   PROCEDURE [dbo].[usp_SendMassMailFromLeads_WithTemplateID_FromMailID_new]                     
 @IDS VARCHAR(MAX)='',                        
 @Account BIGINT,                        
 @Email_Subject VARCHAR(1000),                        
 @Message_TemplateID Bigint,                        
 @SenderName VARCHAR(100),                        
 @ReplyTo VARCHAR(1000),                        
 @EmailId BIT,                        
 @EmailId1 BIT,                        
 @EmailId2 BIT,      
 @UserId bigint = 0,
 @FromMailID varchar(500),
 @massbatchid bigint=0
AS                        
BEGIN     
 -- DECLARE @rowJson NVARCHAR(MAX); 
declare @tname nvarchar(200)         
select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))              
DECLARE @MailCount BIGINT,@IsMonitor Bit = 1               
DECLARE @m_id BIGINT,@parentid bigint        
 SELECT @m_id= ud.M_ID,@parentid=parentid                                
                 FROM   User_Detail AS ud (nolock)                               
                 WHERE  ud.[User_ID] = @Account                          
	if @massbatchid IS NOT NULL AND @massbatchid <> 0
	BEGIN
		select @IDS= STRING_AGG(cast(Entityid as nvarchar(max)),'#') from Tbl_MassOperationDetails where SummaryId=@massbatchid 
		Update  Tbl_MassOperationSummary set BatchStartTime= GetDate()  where BatchID=@massbatchid 
	END
 SELECT @MailCount = (select count(1) from dbo.fn_split(@IDS,'#'))                           
  DECLARE @CurrentBalance BIGINT = (                              
             SELECT TOP 1 mcd.Balance                              
             FROM   MailCreditDetails AS mcd   (nolock)                           
             WHERE  mcd.[User_ID] = @parentid                              
             ORDER BY mcd.Credit_ID DESC                              
         )                                          
                           
                               
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount                              
  IF @Balance > 0                                
 BEGIN                                
               
   Declare @Message VARCHAR(MAX)                 
                
  select @Message = MailContent,@tname=Name  From UserMailTemplate(nolock) where ID= @Message_TemplateID                
                  --select @Message
 SELECT A.EmailID,                        
        A.AccountID,                        
        A.SenderName,                        
        A.MailContent,                        
        A.MailSubject,                        
        A.ReplyTo,      
  A.leadid      
  INTO #tempTable                        
 FROM   (                        
            SELECT ISNULL(A.EmailID, '') AS EmailID,                        
                   @Account        AS AccountID,                        
                   @SenderName     AS SenderName,                        
                   A.MailContent,                        
                   --@Email_Subject  AS MailSubject,                        
                   A.MailSubject
				   ,@ReplyTo        AS ReplyTo ,      
       Leadid      
            FROM   (                        
                       SELECT CASE                         
                                   WHEN @EmailId = 1 THEN ul.EmailID                        
                                   ELSE ''                        
                              END AS EmailID,                        
                              dbo.fn_getLeadsMailMessage_new(ul.ParentID, @Message, ul.EmailID,ul.id) AS                         
                              MailContent,
							  dbo.fn_getLeadsMailMessage_new(ul.ParentID, @Email_Subject, ul.EmailID,ul.id) AS                         
							  MailSubject
							  ,ul.ID as leadid                        
                       FROM   UserLeads AS ul  (nolock)                      
                       WHERE  ul.ID IN (SELECT [value]                        
                                        FROM   dbo.fn_Split(@IDS, '#') AS fs)              
                                         AND ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') <> ''               
                      AND ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') not in               
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID               
                      from UserLeads UETemp(nolock) inner join Client_UnSubscribeDetails C_UDTemp  (nolock)            
                      on (UETemp.EmailID =C_UDTemp.Email)              
                                  
                      where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))             
                                  
                                                              
                       UNION ALL                         
                                            
                       SELECT CASE                         
                                   WHEN @EmailId1 = 1 THEN ul.EmailID1                 
                                   ELSE ''                        
                              END AS EmailID,                        
                              dbo.fn_getLeadsMailMessage_new(ul.ParentID, @Message, ul.EmailID1,ul.id) as  MailContent ,      
                              dbo.fn_getLeadsMailMessage_new(ul.ParentID, @Email_Subject, ul.EmailID1,ul.id) AS                         
							  MailSubject,  
		               ul.ID as leadid      
                       FROM   UserLeads AS ul (nolock)                       
                       WHERE  ul.ID IN (SELECT [value]                        
                                        FROM   dbo.fn_Split(@IDS, '#') AS fs)            
                                                    
                                          AND ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') <> ''               
                      AND ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') not in               
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID               
                      from UserLeads UETemp(nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)             
                      on (UETemp.EmailID1 =C_UDTemp.Email)              
                                  
                      where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))                        
                       UNION ALL                        
                                               
                       SELECT CASE                         
                                   WHEN @EmailId2 = 1 THEN ul.EmailID2                        
                                   ELSE ''                        
                              END AS EmailID,                        
                              dbo.fn_getLeadsMailMessage_new(ul.ParentID, @Message, ul.EmailID2,ul.id) as MailContent,
							  dbo.fn_getLeadsMailMessage_new(ul.ParentID, @Email_Subject, ul.EmailID2,ul.id) AS                         
							  MailSubject,
         ul.ID as leadid      
                       FROM   UserLeads AS ul (nolock)                       
                       WHERE  ul.ID IN (SELECT [value]                        
                                        FROM   dbo.fn_Split(@IDS, '#') AS fs)            
                                          AND ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') <> ''               
                      AND ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') not in               
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID               
                      from UserLeads UETemp(nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)             
                      on (UETemp.EmailID2 =C_UDTemp.Email)              
                                  
                      where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs ))             
                                                    
                                                    
                                                                
                   )                  A                        
            WHERE  ISNULL(A.EmailID, '') <> ''                        
        ) A                        
                         
                         
	--select * from #tempTable                   
  Declare @Status Bigint=0,@CountLimit bigint = 0                    
   select @Status = status,@CountLimit = Plimit from ProcessMailLimit                           
      if(@Status = 1)                    
      Begin                    
    Begin                    
      if(@MailCount >  @CountLimit )                    
      Begin                    
       set @IsMonitor = 0                     
      End                    
     End                    
       End                    
                    
         
                                     
 DECLARE @BatchID BIGINT        
 begin tran                                  
 INSERT INTO GetBatchRecord                              
       (                              
         [User_id],                              
         RandNum                              
       )                 
     VALUES                              
       (                              
         @Account,                              
         @Account                              
       )                                    
select @BatchID=SCOPE_IDENTITY()                                   
DELETE                            
     FROM GetBatchRecord                              
     WHERE batchid=@BatchID        
 commit                                  
                                   
         
     DECLARE @Mail_FromEmail VARCHAR(500) = ''                                
        
select @Mail_FromEmail=coalesce((select top 1 mail_id from defaultmailid(nolock) where user_id=@account order by datecreated desc),        
(SELECT ud.EMail FROM   User_Detail AS ud  (nolock) WHERE  ud.[User_ID] = @Account),'contactus@email19.in')         

if(rtrim(ltrim(@FromMailID)) <> '')
   Begin
       set @Mail_FromEmail = @FromMailID
   End
        
insert into CloneEmailsFilter(Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,        
Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source)        

select @Mail_FromEmail,A.EmailID,A.MailSubject,isnull(@tname,''),A.MailContent,GETDATE(),A.AccountID,@parentid,A.ReplyTo,@BatchID,1,'','','',A.MailContent,@ismonitor,0,@mailcount,'Lead-MassSend'        
from #tempTable A  
     
       
 if(@UserId  > 0 )      
 begin      
  declare @leadActivityHistory AS LeadActivitywithid_Tbltype      
  declare  @Username nvarchar(255) = ( select User_Login from User_Detail(nolock) where User_Id = @UserId)       
  insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )      
   select       
    leadid,      
    @UserId,       
    @parentid,      
    concat(@Username , ' sent a mail with subject ',  MailSubject, ' to emailid ', EmailID),      
    'Mail sent to lead',      
    'Batchemail_infos',          
    @BatchID      
   from #tempTable      
      
  exec UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory      
 end      
      
    SELECT 'Success'   
	if @massBatchID IS NOT NULL AND @massBatchID <> 0
	BEGIN
		Update  Tbl_MassOperationSummary set BatchEndTime= GetDate() , Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@massBatchID 
	END
 END                        
 ELSE                        
 BEGIN                        
     SELECT 'Insufficient Balance'                        
 END    

 DROP TABLE #tempTable        
 DECLARE @rowJson NVARCHAR(MAX) = (
				SELECT *
				FROM CloneEmailsFilter
				WHERE Mail_BatchID = @BatchID
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)
  if @rowJson is not null
	begin
	EXEC MySmsAudit_dev.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'Inst_Mail_Lead'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'CloneEmailsFilter'
		END   
	
END         




