/* ============================================================
   Procedure: [dbo].[usp_sendmessagewithTracking]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_sendmessagewithTracking --17626,'kit19.com','7840002738','RJGURU',0,1,'pel.im','kit19.com',null,null,null,null,null,null,null,null, null,null,null,null,null,null,null         
@u_id bigint,          
@message nvarchar(2500),          
@mobile nvarchar(max),          
@sender nvarchar(6),          
@isunicode int=null,          
@priority int=null,       
@shorturl nvarchar(10)=null ,      
@longurl nvarchar(300)=null,      
@page_nm nvarchar(50)=null,      
@IAction nvarchar(50)=null,      
@Cmobile nvarchar(20)=null,      
@email nvarchar(100)=null,      
@subject nvarchar(100)=null,      
@body nvarchar(max)=null,      
@wmobile varchar(20)=null,      
@wtext nvarchar(max)=null,      
@isvoice bit=null,      
@appid int,      
@duration int=null,      
@dnid nvarchar(20)=null,      
@frequency int=null,      
@latency int=null,      
@route nvarchar(20) =null,    
@batchid bigint output        
as          
begin          
set @isunicode=coalesce(@isunicode,0)          
set @priority=coalesce(@priority,0)        
set @shorturl=coalesce(@shorturl,'pel.im')      
set @page_nm=coalesce(@page_nm,'Send SMS Proc')      
set @IAction=coalesce(@IAction,'Original Url')      
      
select distinct value as vmobile,@u_id u_id into #temp from dbo.fn_split(@mobile,',') where value <>''          
declare @m_id bigint=(select m_id from user_detail(nolock) where user_id=@u_id)          
--declare @batchid bigint         
begin tran         
INSERT INTO getbatchrecord                              
   ( [user_id],                              
     randnum                              
   )                              
 SELECT @u_id,@m_id          
select @batchid=SCOPE_IDENTITY()        
delete From GetBatchRecord where batchid=@batchid        
commit        
if @IAction='Original Url'      
begin      
set @longurl=coalesce(@longurl,'')      
set @isvoice=coalesce(@isvoice,0)      
insert into Link_smsUrl_dtl(BatchId,short_url,longurl,insertdate,status,Parentid,Page_nm,lAction,P_url,IsVoice,AppID,Duration,DNID,Frequency,Latency,Route)      
select @batchid,@shorturl,@longurl,GETDATE(),1,@u_id,@page_nm,@IAction,@longurl,isnull(@isvoice,0),@appid,@duration,@dnid,@frequency,@latency,@route      
end      
else if @IAction='Click to Call'      
begin      
set @Cmobile=coalesce(@cmobile,0)      
set @isvoice=coalesce(@isvoice,0)      
insert into Link_smsUrl_dtl(BatchId,short_url,longurl,insertdate,status,Parentid,Page_nm,lAction,      
CMobile,P_url,IsVoice,AppID,Duration,DNID,Frequency,Latency,Route)      
select @batchid,@shorturl,@longurl,GETDATE(),1,@u_id,@page_nm,@IAction,@cmobile,'tel:'+@cmobile,isnull(@isvoice,0),@appid,@duration,@dnid,@frequency,@latency,@route      
end      
else if @IAction='Click to Email'      
begin      
set @email=coalesce(@email,'')      
set @subject=coalesce(@subject,'')      
set @body=coalesce(@body,'')      
set @isvoice=coalesce(@isvoice,0)      
insert into Link_smsUrl_dtl(BatchId,short_url,longurl,insertdate,status,Parentid,Page_nm,lAction,      
Email,subject,Body,P_url,IsVoice,AppID,Duration,DNID,Frequency,Latency,Route)      
select @batchid,@shorturl,@longurl,GETDATE(),1,@u_id,@page_nm,@IAction,@email,@subject,@body,'mailto:'+cast(@email as nvarchar(100))+'?subject='+cast(@subject as nvarchar(200))+'&body='+cast(@body as nvarchar(max)),isnull(@isvoice,0),@appid,@duration,
@dnid,@frequency,@latency,@route      
      
end      
else if @IAction='Click to WhatsApp'      
begin      
set @wmobile=coalesce(@wmobile,'0')      
set @wtext=coalesce(@wtext,'')      
set @isvoice=coalesce(@isvoice,0)      
insert into Link_smsUrl_dtl(BatchId,short_url,longurl,insertdate,status,Parentid,Page_nm,lAction,      
wmobile,wtext,P_url,IsVoice,AppID,Duration,DNID,Frequency,Latency,Route)      
select @batchid,@shorturl,@longurl,GETDATE(),1,@u_id,@page_nm,@IAction,@wmobile,@wtext,'https://api.whatsapp.com/send?phone='+cast(@wmobile as nvarchar(20))+'&text='+cast(@wtext as nvarchar(max)),isnull(@isvoice,0),@appid,@duration,@dnid,@frequency,
@latency,@route      
      
end      
            
      
          
           
 SELECT @batchid batchid,                              
        vmobile mobile,                              
        @message message,                      
        Null messagestatus,                              
        @sender senderid,                              
        getdate() messageinsertdate,                              
        '' as scheduleddate,                              
        '' as scheduledtime,                              
        U.smppid,                              
        @u_id u_id,                              
        @isunicode isunicode,                              
        0 as isdnd,                              
