   Procedure: [dbo].[usp_sendmonitortransactions]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[usp_sendmonitortransactions]
as
begin
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX),@TotalCusSent bigint,@TotalSentbyus bigint
;with cte as(SELECT [UserID],user_login,bi.[BatchID],[TotalRecords],
right(convert(nvarchar,[BatchInsertTime],100),7)Time, mdt.MESSAGE,u.filtermode as OriginalFilterMode,isnull(BI.filterMode,'0')filterMode,BI.userfilter userfilter,ROW_NUMBER()OVER (PARTITION BY BI.BatchID Order By BI.BatchID)AS NUMBER,(bi.FilterMode*totalrecords)/10 as Sent
FROM [MySMS].[dbo].[BatchInfo] BI(nolock)

 --join [MySMStrans].[dbo].messagedeliverystatustemp mdt(nolock)
  join [MySMS].[dbo].messagedeliverystatustemp mdt(nolock)
   on bi.batchid=mdt.batchid 

join [MySMS].[dbo].user_detail u (nolock) on u.user_id=bi.userid where datediff(d,batchinserttime,getdate())=0 and isprocess=1 
and bi.dbtype=7 )
select * into #temp2 from cte where number=1
select @TotalCusSent=SUM(totalrecords),@TotalSentbyus=SUM(sent) from #temp2

SET @xml =CAST(( SELECT [UserID] AS 'td','',[User_Login] AS 'td','',[BatchID] AS 'td','', 
[TotalRecords]  AS 'td','',Time as 'td','',Message AS 'td','',[OriginalFilterMode] AS 'td','',[filterMode] as 'td','',userfilter from #temp2 where NUMBER=1 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))
SET @body ='<html><H1>Transactional Messages Monitor '+cast (getdate() as nvarchar)+ ' Sent by Customer: ' + CAST(@totalcussent as nvarchar) + '||Sent by us: '+CAST(@totalsentbyus as nvarchar) +'</H1><body><table border = 2><tr><th>User ID</th><th>User Login</th><th>Batch ID</th><th>Total</th><th>Time</th><th>Message Text</th><th>Original Filtermode</th><th>FilterMode</th><th>Route</th></tr>' 
SET @body = @body + @xml +'</table></body></html>'
EXEC usp_enqueueemail
@profile_name='Alerts', 
@recipients='csshukla@pelsoftlabs.in',
@blind_copy_recipients='karuna@pelsoftlabs.in',
@subject='Transactional Messages Monitor',
@body = @body,
@body_format ='HTML'
drop table #temp2

/*DECLARE @TotalCampaignsScheduled bigint,@TotalCampaignsFailed bigint
select @TotalCampaignsScheduled= COUNT(1) from usercampaignmaster where iseventbased=0 and cast(NextExecuteDateTime as date)= cast(GETDATE() as date)
select @TotalCampaignsFailed= COUNT(1) from usercampaignmaster ucm left outer join usercampaignhistory uch on ucm.ID=uch.CampaignID where ucm.iseventbased=0 and isnull(Step3,0)=0 and cast(ucm.NextExecuteDateTime as datetime)<= GETDATE()  and cast(ucm.NextExecuteDateTime as date)=cast(getdate() as date)
select @TotalCampaignsFailed

select ucm.id,ucm.Campaignname,ud.User_id,ud.User_login,ucm.NextExecuteDateTime,isnull(ucm.ExecutedDateTime,'') as ExecutedDateTime , case when uch.Step1=0 then 'Step 1' when uch.Step2=0 then 'Step2' when Step3=0 then 'Step 3' else 'ExecutionNotAttempted' end as FailureStep into #temp3  from UserCampaignMaster ucm left outer join usercampaignhistory uch (nolock) on uch.CampaignID=ucm.ID left outer join user_detail ud on ucm.parentid=ud.User_ID  where isnull(ucm.iseventbased,0)=0 and cast(ucm.NextExecuteDateTime as date)= cast(GETDATE() as date) and isnull(Step3,0) =0
SET @xml =CAST(( SELECT [ID] AS 'td','',[Campaignname] AS 'td','',[User_id] AS 'td','', 
[User_login]  AS 'td','',NextExecuteDateTime as 'td','',ExecutedDateTime AS 'td','',[FailureStep] from #temp3 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))
SET @body ='<html><H1>Campaigns Status '+cast (getdate() as nvarchar)+ ' Campaigns Scheduled Today: ' + CAST(@TotalCampaignsScheduled as nvarchar) + '||Campaigns failed: '+CAST(@TotalCampaignsFailed as nvarchar) +'</H1><body><table border = 2><tr><th>ID</th><th>Campaign Name</th><th>User ID</th><th>User Login</th><th>Scheduled For</th><th>Executed at</th><th>Failure Step</th></tr>' 
SET @body = @body + isnull(@xml,' ') +'</table></body></html>'
