/* ============================================================
   Procedure: [dbo].[usp_sendnewfeedbackmail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_sendnewfeedbackmail] --17626  
@feedbackid bigint  
as  
begin  
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX)  
select isnull(f.Enqno,'') Enqno,isnull(p.Name,'') Name,isnull(p.company_name,'') Company,isnull(Mobile_no,'') Mobile,isnull(f.Executive,'') Executive,isnull(cast(f.Datecreated as date),'') FeedbackForDate,
case when AttributeComments = 'green' then 'Good' when AttributeComments = 'Yellow' then 'Average' when AttributeComments = 'Red' then 'Bad' else '' end as AttributeComments,isnull(ActivityFeedback,'') ActivityFeedback,isnull(Comments,'') Comments,isnull(FeedbackDate,'') FeedbackGivenDate 
into #temp 
from crm.crmdb.dbo.FeedbackActivity fa left join crm.crmdb.dbo.Followup_details f with (nolock) on fa.fid =f.FId
left join crm.crmdb.dbo.pre_enquiry p with (nolock) on p.EnqNo=f.EnqNo

 where FeedbackID=@feedbackid  
 declare @urgency int=(select case when  AttributeComments = 'Bad' then 1 else 0 end from #temp)
 declare @executive nvarchar(100)=(select executive from #temp)
  
SET @xml =CAST(( SELECT Enqno AS 'td','',Name AS 'td','',Company AS 'td','',Mobile AS 'td','',   
Executive  AS 'td','',FeedbackForDate as 'td','',AttributeComments as 'td','',ActivityFeedback as 'td','',Comments as 'td','',FeedbackGivenDate from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
SET @body ='<html><H1>Customer Feedback '+'</H1><body><table border = 2><tr><th>Enqno</th><th>Name</th><th>Company</th><th>Mobile</th><th>Executive</th><th>FeedbackForDate</th><th>AttributeComments</th><th>ActivityFeedback</th><th>Comments</th><th>FeedbackGivenDate</th></tr>'   
SET @body = @body + @xml +'</table></body></html>'  
declare @subject nvarchar(500) = case when @urgency=1 then 'Urgent :' else '' end +' New Customer Feedback for ' + @executive
EXEC usp_enqueueemail  
@profile_name='Alerts',   
@recipients='csshukla@pelsoftlabs.in',  
@blind_copy_recipients='karuna@pelsoftlabs.in',  
@subject= @subject,  
@body = @body,  
@body_format ='HTML'  
drop table #temp  
end  
  



GO

