   Procedure: [dbo].[usp_sendnewsignupmail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROC [dbo].[usp_sendnewsignupmail] --38145       
@usercreated bigint        
as        
begin 

DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX)        
select M_ID,User_Login,isnull(FName,'')+' ' +isnull(LName,'') as Name,EMail,isnull(ltrim(rtrim(countrycode)),'+91')+ '-' +str(Mobile,10,0) as Mobile,isnull(CompnayName,'') as Company,      
userfilter as Route,ISNULL(Source,'') as Source,ISNULL(Medium,'') as Medium,ISNULL(Campaign,'') as Campaign into #temp from user_detail with(nolock) where user_id=@usercreated        
      
--Added following code to insert lead in lead list      
declare @Source  nvarchar(200)            
  ,@LeadDetails nvarchar(max)            
  ,@Name nvarchar(200)            
  ,@Mobile nvarchar(50)            
  ,@EmailID nvarchar(500)            
  ,@Company nvarchar(500)            
  ,@Address nvarchar(max)            
  ,@Remarks nvarchar(max)            
  ,@ParentID bigint       
select @Source = 'SignUp' ,@LeadDetails='SignUp from '+ isnull(nullif(source,''),'Web'),@Name=isnull(FName,'')+' ' +isnull(LName,''),@Mobile=str(Mobile,10,0),@EmailID=email,@Company=isnull(CompnayName,'')             
,@Address='',@Remarks= 'Signup Medium: '+ISNULL(Medium,'') + ' .Campaign: '+ ISNULL(Campaign,'') +' .',@ParentID=335 from user_detail with(nolock) where user_id=@usercreated    
    
    
  set  @LeadDetails = ''       
  if(@Name <> '')      
     Begin      
        if(@LeadDetails = '')      
       Begin      
          set @LeadDetails = 'Name'      
    End      
           else       
       Begin      
         set @LeadDetails = @LeadDetails + '|Name'       
    End      
  End      
      
  if(@Mobile <> '')      
     Begin      
        if(@LeadDetails = '')      
       Begin      
          set @LeadDetails = 'Mobile'      
    End      
           else       
       Begin      
         set @LeadDetails = @LeadDetails + '|Mobile'       
    End      
  End      
      
   if(@EmailID <> '')      
      Begin      
         if(@LeadDetails = '')      
        Begin      
           set @LeadDetails = 'EmailID'      
    End      
           else       
       Begin      
         set @LeadDetails = @LeadDetails + '|EmailID'       
    End      
   End      
      
      
    if(@Company <> '')      
      Begin      
         if(@LeadDetails = '')      
        Begin      
           set @LeadDetails = 'Company'      
    End      
           else       
       Begin      
         set @LeadDetails = @LeadDetails + '|Company'       
    End      
   End      
      
      
   if(@Remarks <> '')      
      Begin      
         if(@LeadDetails = '')      
        Begin      
           set @LeadDetails = 'Remarks'      
    End      
           else       
       Begin      
         set @LeadDetails = @LeadDetails + '|Remarks'       
    End      
   End    
       
    
   if(charindex('Mobile',@LeadDetails) <> 0)      
    Begin      
      exec usp_insertintoleadlist @Source,@LeadDetails,@Name,@Mobile,@EmailID,@Company,@Address,@Remarks,@ParentID             
     end    
    
--Code end for lead list        
  begin try 
   
SET @xml =CAST(( SELECT [M_ID] AS 'td','',[User_Login] AS 'td','',[Name] AS 'td','',         
[EMail]  AS 'td','',Mobile as 'td','',Company as 'td','',Route as 'td','',Source as 'td','',Medium as 'td','',Campaign from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))        
SET @body ='<html><H1>New Kit19 User Created on '+cast (getdate() as nvarchar)+'</H1><body><table border = 2><tr><th>M_ID</th><th>User Login</th><th>Name</th><th>Email</th><th>Mobile</th><th>Company</th><th>Route</th><th>Source</th><th>Medium</th><th>Camp
  
    
aign</th></tr>'         
SET @body = @body + @xml +'</table></body></html>' 

EXEC usp_enqueueemail        
@profile_name='Alerts',         
@recipients='csshukla@pelsoftlabs.in',        
@blind_copy_recipients='karuna@pelsoftlabs.in',        
@subject='New Kit19 user signup',        
@body = @body,        
@body_format ='HTML' 
end try
 begin catch
  exec usp_InsertErrorInfo
 end catch
drop table #temp   

end   

------------------------------------------------------------------



GO

