         set @LeadDetails = @LeadDetails + '|EmailID'   
    End  
   End  
  
  
    if(@Company <> '')  
      Begin  
         if(@LeadDetails = '')  
        Begin  
           set @LeadDetails = 'Company'  
    End  
           else   
       Begin  
         set @LeadDetails = @LeadDetails + '|Company'   
    End  
   End  
  
  
   if(@Remarks <> '')  
      Begin  
         if(@LeadDetails = '')  
        Begin  
           set @LeadDetails = 'Remarks'  
    End  
           else   
       Begin  
         set @LeadDetails = @LeadDetails + '|Remarks'   
    End  
   End
   

   if(charindex('Mobile',@LeadDetails) <> 0)  
    Begin  
     -- exec usp_insertintoleadlist @Source,@LeadDetails,@Name,@Mobile,@EmailID,@Company,@Address,@Remarks,@ParentID         
      exec usp_insertintoleadlist_processWithCountryCode @Source,@LeadDetails,@Name,@Mobile,@EmailID,@Company,@Address,@Remarks,@ParentID ,@CountryCode,0      
	 end

--Code end for lead list    
  
SET @xml =CAST(( SELECT [M_ID] AS 'td','',[User_Login] AS 'td','',[Name] AS 'td','',     
[EMail]  AS 'td','',Mobile as 'td','',Company as 'td','',Route as 'td','',Source as 'td','',Medium as 'td','',Campaign from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))    
SET @body ='<html><H1>New Kit19 User Created on '+cast (getdate() as nvarchar)+'</H1><body><table border = 2><tr><th>M_ID</th><th>User Login</th><th>Name</th><th>Email</th><th>Mobile</th><th>Company</th><th>Route</th><th>Source</th><th>Medium</th><th>Campaign</th></tr>'     
SET @body = @body + @xml +'</table></body></html>'    
EXEC usp_enqueueemail    
@profile_name='Alerts',     
@recipients='csshukla@pelsoftlabs.in',    
@blind_copy_recipients='karuna@pelsoftlabs.in',    
@subject='New Kit19 user signup',    
@body = @body,    
@body_format ='HTML'    
drop table #temp    
end    



