/* ============================================================
   Procedure: [dbo].[Usp_SendOTP_WhileCheckinCheckout]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_SendOTP_WhileCheckinCheckout] --34594,7437972,'Lead','CheckIn',15997,'619343', '', 'mail'          
(          
  @UserID bigint,          
  @EntityID bigint,          
  @EntityName nvarchar(200),          
  @Mode nvarchar(50),    --(CheckIn/CheckOut)          
  @AppointmentID bigint,          
  @OTP nvarchar(20),          
  @OTPModeValue nvarchar(200) = '',          
  @OTPMode nvarchar(200) --(SMS/mail/WhatsApp)                
)          
as         

begin
    --DECLARE 
    --    @UserID bigint,          
    --    @EntityID bigint,          
