Declare @rexist int=0,@activityid int =0
Declare @FromMailID nvarchar(max) = ''
Declare @sms bit=1

if object_id('tempdb..#nomobile') is not null
    drop table #nomobile

select ROW_NUMBER() over( order by item) rno,* into #nomobile                    
from dbo.SplitString(@ToEmailID, ',')                
          
              
 select @FromMailID= Mail_ID  from DefaultMailID where User_ID = @parentid

 if rtrim(isnull(@FromMailID,''))=''
 select @FromMailID='contactus@email19.in'    
                                    
                                    
declare @spos int =0                                  
Declare @fld varchar(max)=''                                    
declare @tbl varchar(max)=''
declare @word table (fldval varchar (Max))                                    
Declare @email_cnt as int =1,@balance int =0             
Declare @acnt bigint = 335            

if @type = '1'             
set @acnt = @parentid                    
                        
SELECT TOP 1 @balance=isnull(balance,0) 
FROM MailCreditDetails with(nolock) WHERE  --m_id = @m_id  AND                               
USER_ID = @acnt  ORDER BY credit_id       DESC                                
                    
  if (@balance-@email_cnt) < 0                    
  Begin                    
     select 'Unable to send Mail as Balance is not sufficient'
     set @email_cnt = 0
  End                    
                   
                              
if @email_cnt =1                             
begin                              
                              
DECLARE @Random INT;                                          
  DECLARE @Upper INT;                                          
  DECLARE @Lower INT                                          
                                            
  Declare @BatchID bigint                                          
                                            
  SET @Lower = 1 ---- The lowest random number                                          
  SET @Upper = 10000 ---- The highest random number                                          
  SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)                                         
  --SELECT @Random                                          
                                          
     insert into GetBatchRecord (User_id,RandNum)                                                  
        values(@parentid,@Random)                                                  
   select @BatchID = max(BatchID)  from GetBatchRecord With (Nolock)                                           
   where User_id=@parentid and RandNum=@Random                                                  
        delete from GetBatchRecord  where User_id=@parentid and RandNum=@Random                                       
                 
Declare @tablevar table(col1 varchar(100))
declare @tblname varchar(100)=''
insert into @tablevar(col1) exec usp_CreateCloneEmailTable @parentid
--select * from @tablevar
SELECT @tblname=isnull(col1,'') FROM @tablevar
--select @tblname


declare @Qry varchar(max) = 'insert into ' + @tblname + ' (                                          
    Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,[Messages],Mail_InsertedDate,Mail_UserID,Mail_ParentID                                          
    ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source                                   )                                          
     select ''' + @FromMailID + ''',Item,''' + @Subject + ''','''',''' +@body+ ''',GETDATE(),' + cast(@acnt as varchar) + ',' + cast(@acnt as varchar) + ',''' + @FromMailID + ''',' + cast(@BatchID as varchar) + ',2,''' + @Mail_ScheduleDate + ''',''' + @Mail_ScheduledTime + ''','''',''' + @body + ''',1,0,1,''Emails'' from #nomobile'

	print @Qry

	exec (@Qry)

    select 'Mail sent successfully'
                                                 
 /* Insert into table for Mail */                                              
end                
drop table #nomobile
--drop table #tmpfl                                    
end 



GO

/* ============================================================
   Procedure: [dbo].[usp_sendscheduledmessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_sendscheduledmessage 335,'test msg','9313943059','TXTSMS',0,1,null,367515  
-- exec usp_sendscheduledmessage 335,'test msg','9313943059','SMSSDL',0,1,null,367515  
-- exec usp_sendscheduledmessage 335,'test msg','9313943059','allure',0,1,null,367515  
-- exec usp_sendscheduledmessage 335,'test msg','9313943059','KITAPP',0,1,null,367515  
CREATE   PROCEDURE [dbo].[usp_sendscheduledmessage]  
@u_id bigint,                  
@message nvarchar(2500),                  
@mobile nvarchar(max),                  
@sender nvarchar(6),                  
@isunicode int=null,                  
@priority int=null,              
@scheduleddate datetime=null,        
@LeadId bigint                  
as                  
begin            
            
   Declare @ParentID bigint = 0            
   Select top 1  @ParentID = isnull(ParentID,0) from User_detail with(nolock) where User_ID =   @u_id               
                  
set @scheduleddate=coalesce(@scheduleddate,getdate())              
set @isunicode=coalesce(@isunicode,0)                  
set @priority=coalesce(@priority,0)                  
select value as vmobile,@u_id u_id into #temp from dbo.fn_split(@mobile,',') where value <>''               
declare @c int= (select COUNT(1) from #temp)              
declare @credit int=@c*(select case when @isunicode=0 and LEN(@message)<=160             
then 1 when @isunicode=0 and len(@message)>160 then cast(ceiling(LEN(@message)/CAST(153 as float)) as int)             
 when @isunicode=1 and LEN(@message)<=70 then 1 when @isunicode=1 and len(@message)>70            
  then cast(ceiling(LEN(@message)/CAST(67 as float)) as int) end)              
              
declare @bal bigint=(select top 1 balance from credit_details (nolock) where user_id=@ParentID order by credit_id desc)              
Declare @oldBatchId bigint              
--select @credit              
              
if @bal>=@credit              
begin        
if exists (select '*' from tbl_message_schedule_status (nolock) where LeadId = @LeadId and IsProcessed = 0 and IsDeleted = 0)        
begin        
set @oldBatchId = (select top 1 BatchID from tbl_message_schedule_status (nolock) where LeadId = @LeadId and IsProcessed = 0 and IsDeleted = 0)        
end        
if exists(select '*' from clonemessagedeliverystatus (nolock) where batchid = @oldBatchId)        
begin        
Delete from clonemessagedeliverystatus where batchid = @oldBatchId        
update tbl_message_schedule_status set IsDeleted = 1, IsProcessed = 1 where LeadId = @LeadId and batchid = @oldBatchId        
end        
        
insert into tbl_message_schedule_status(LeadId,Schedule_Date,IsProcessed,IsDeleted,Message_Type)        
values(@LeadId,@scheduleddate,0,0,'SMS')        
                 
declare @m_id bigint=(select m_id from user_detail(nolock) where user_id=@u_id)                  
declare @batchid bigint                 
begin tran                 
INSERT INTO getbatchrecord                                      
   ( [user_id],                                      
     randnum                                      
   )                                      
 SELECT @u_id,@m_id                  
select @batchid=SCOPE_IDENTITY()                
delete From GetBatchRecord where batchid=@batchid                
commit               
         
update tbl_message_schedule_status set batchid = @batchid where LeadId = @LeadId and IsProcessed = 0 and IsDeleted = 0                 
                   
 SELECT @batchid batchid,                                      
        vmobile mobile,                                      
        @message message,                                      
        Null messagestatus,                                      
        @sender senderid,                                      
        getdate() messageinsertdate,                                      
        @scheduleddate as scheduleddate,                                      
        @scheduleddate as scheduledtime,                                      
        U.smppid,                                      
     @u_id u_id,                                      
        @isunicode isunicode,                                      
        0 as isdnd,                                      
        0 as isairtel,                                      
        substring(@mobile,1,4) mobilesubset,                                      
        1 as validno,                                      
        @priority isprority,            
        0 isallowdnd,                                      
        0 dbtype,                    
        0 CampaignID,                    
      1 RCount,                    
        0 as HasVirtualCredits,                    
        0 as HasSufficientVirtualCredits                    
        into #clonemessagedeliverystatus                    
 FROM   user_detail u (nolock) join #temp t on u.user_id=t.u_id                  
                   
                  
 INSERT INTO clonemessagedeliverystatus                                      
   ( batchid,mobile,[message],messagestatus,senderid,messageinsertdate,scheduleddate,scheduledtime,smppid,u_id,isunicode,isdnd            
   ,isairtel,mobilesubset,validno,isprority,isallowdnd,dbtype,campaignid,hasvirtualcredits,HasSufficientVirtualCredits,CMDS_CreatedBy        
)                                  
 SELECT batchid,                                      
        Ucerm.mobile,                                      
        Ucerm.[message],                                      
        Ucerm.messagestatus,                                      
        Ucerm.senderid,                                      
        GETDATE(),                                      
        ScheduledDate,                                      
        ScheduledTime,                                      
        smppid,                          
        Ucerm.u_id,                                      
        Ucerm.isunicode,                                      
        Ucerm.isdnd,                                      
        Ucerm.isairtel,                                      
        Ucerm.mobilesubset,                          
        Ucerm.validno,                                      
        Ucerm.isprority,                                      
        Ucerm.isallowdnd,                                      
        Ucerm.dbtype,                    
        CampaignID,                    
        hasvirtualcredits,                    
        HasSufficientVirtualCredits,
		@u_id                      
 FROM   #clonemessagedeliverystatus Ucerm                   
 --delete FROM #clonemessagedeliverystatus where BatchID=@batchid                    
 Select 'SMS sent.' as status              
 end              
 else              
 begin              
 Select 'Lead Added & Notification Not Sent due to InSufficient Balance.' as status              
 end              
                   
 end  


GO

