)                                    
 SELECT batchid,                                        
        Ucerm.mobile,                                        
        Ucerm.[message],                                        
        Ucerm.messagestatus,                                        
        Ucerm.senderid,                                        
        GETDATE(),                                        
        ScheduledDate,                                        
        ScheduledTime,                                        
        smppid,                            
        Ucerm.u_id,                                        
        Ucerm.isunicode,                                        
        Ucerm.isdnd,                                        
        Ucerm.isairtel,                                        
        Ucerm.mobilesubset,                            
        Ucerm.validno,                                        
        Ucerm.isprority,                                        
        Ucerm.isallowdnd,                                        
        Ucerm.dbtype,                      
        CampaignID,                      
        hasvirtualcredits,                      
        HasSufficientVirtualCredits,
		@u_id                        
 FROM   #clonemessagedeliverystatus Ucerm                     
 --delete FROM #clonemessagedeliverystatus where BatchID=@batchid     
     
   Begin try  
   exec Usp_Save_DLTTemplateID_with_BatchID @batchid,@DLTTemplateID  
   End try  
   begin catch  
     exec usp_InsertErrorInfo  
   End catch  
     
                    
 Select 'SMS sent.' as status                
 end                
 else                
 begin                
 Select 'Lead Added & Notification Not Sent due to InSufficient Balance.' as status                
 end                
                     
 end 


GO

/* ============================================================
   Procedure: [dbo].[usp_SendSelected_recordsSpamTable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
          
/****************************************************************************              
              
SP_Name        : usp_SendSelected_recordsSpamTable                                 
Author         : raghwendra             
Created ON     : 2010-01-14 12:17:52.880                
Version        : 1              
Alter BY       :                      
Alter Date     :               
Location       :                
SP Description : Insert selected Record in MessageQueueAirtel and          
   :MessageSource And MessageQueue          
            :             
                            
                                        
****************************************************************************/            
CREATE   PROC [dbo].[usp_SendSelected_recordsSpamTable]           
@ResselerID BIGINT=1,                                                                              
@userID INT=1,    --change frm bigint to int                                                                          
@MobNos CHAR(20),   
@Message NVARCHAR(2500), --change frm varchar to nvarchar                     
@SenderId nchar(30),  --varchar to char  
@BatchID bigint,        --  
@MessageID bigint,                                                      
@smppID SMALLINT,     --tiny int                           
@Priority SMALLINT,    --tinyint            
@isairtel char(6)   ,          
@Isallowdnd tinyint,      
@IsDnd int              
as          
Declare @airtelNo bigint,@PriorityTmp int          
set @airtelNo=@isairtel          
set @PriorityTmp=@Priority          
Begin           
if @airtelNo=1          
          
INSERT  INTO MessageQueueAirtelPri                                
   (                                
     BatchID,MessageID,[Message],Mobile,Priority ,SenderID,SmppID,U_ID, IsDnd,Operator,Isallowdnd                              
   )                
values(@BatchID,@MessageID,@Message,@MobNos,@Priority ,@SenderId,@smppID,@userID, @IsDnd,@isairtel,@Isallowdnd)          
          
Else          
Begin          
if @PriorityTmp=0          
Begin          
 INSERT  INTO MessageSource                                
   (                                
    MessageBatchID,MessageID,[Message],Mobile,Priority ,SenderID,SmppID,U_ID, IsDnd,Operator,Isallowdnd                              
   )                
values(@BatchID,@MessageID,@Message,@MobNos,@Priority ,@SenderId,@smppID,@userID, @IsDnd,@isairtel,@Isallowdnd)          
          
End          
Else          
Begin          
INSERT  INTO MessageQueue                              
   (                              
      BatchID,MessageID,[Message],Mobile,Priority ,SenderID,SmppID,U_ID, IsDnd,Operator,Isallowdnd                              
   )                
values(@BatchID,@MessageID,@Message,@MobNos,@Priority ,@SenderId,@smppID,@userID, @IsDnd,@isairtel,@Isallowdnd)          
                   
End          
End          
End   
  


GO

