CREATE   PROC [dbo].[usp_SendSenderidAdddedMail] --113563-- 17626  
@newsenderid bigint
as  
begin  
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX)

select u.User_ID,u.user_login,Sender_Name,convert(varchar, s.datecreated, 100) as DateAdded,u1.user_login as ParentReseller into #temp from user_detail u join SenderID_Detail s on u.User_ID=s.User_ID join user_detail u1 on u.ParentSuperResellerId=u1.user_id
where Sender_ID=@newsenderid
  
SET @xml =CAST(( SELECT [User_ID] AS 'td','',[User_Login] AS 'td','',[Sender_Name] AS 'td','',   
[DateAdded]  AS 'td','',ParentReseller from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
SET @body ='<html><H1>New SenderId approval requested on '+cast (getdate() as nvarchar)+'</H1><body><table border = 2><tr><th>User_ID</th><th>User Login</th><th>Sender_Name</th><th>DateAdded</th><th>ParentReseller</th></tr>'   
SET @body = @body + @xml +'</table></body></html>'  
declare @subject nvarchar(100) = 'New sendername ' + (select sender_name from #temp) + ' added'
EXEC usp_enqueueemail  
@profile_name='Alerts',   
@recipients='animesh.shukla@pelsoftlabs.in',  
@blind_copy_recipients='karuna@pelsoftlabs.in',  
@subject=@subject,  
@body = @body,  
@body_format ='HTML'  
drop table #temp  
end  
  



GO

