/* ============================================================
   Procedure: [dbo].[usp_sendsmsDlr]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_sendsmsDlr] --38145           
as            
begin     
    
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX),@email nvarchar(250),@query nvarchar(1000),@id int=0,@parentid bigint=0,@count int
,@additional_mailids nvarchar(4000)
drop table if exists #sms_dlr
select *,CAST(0 as bit) IsProcessed into #sms_dlr from SMS_DLR_Mail(nolock) where isactive=1
select @count=COUNT(1) from #sms_dlr

while @count>0
begin
select @id=MIN(id) from #sms_dlr where id>@id and IsProcessed=0
select @parentid=parentid,@additional_mailids=REPLACE(additional_mailids,';',',') from #sms_dlr where id=@id
select @email=isnull(email+';','')+ isnull(@additional_mailids,'') from user_detail(nolock) where user_id=@parentid    

/*
select @email=email from user_detail(nolock) where user_id=38737    
select @email=@email+';rms@htplonline.com;Accounts.eq@htplonline.com'    
*/
--select @email='karuna@pelsoftlabs.in'    
drop table if exists ##dlr_sms    
--select Mobile,Senderid,MessageInsertDate as SentTime,isnull(nullif(messagestatus,''),'Submitted') MessageStatus,isnull(nullif(statusdescription,''),'Report Awaited') StatusDescription,Message as MessageContent   
--into ##dlr_sms from messagedeliverystatus(nolock) where u_id=38737            
select Mobile,Senderid,MessageInsertDate as SentTime,isnull(nullif(messagestatus,''),'Submitted') MessageStatus,isnull(nullif(statusdescription,''),'Report Awaited') StatusDescription,Message as MessageContent   
into ##dlr_sms from messagedeliverystatus(nolock) where u_id=@parentid            
          
 select @query=' SET NOCOUNT ON; select Mobile,Senderid,SentTime,MessageStatus,StatusDescription,MessageContent                       
from tempdb..##dlr_sms '                                                      
      
    
  begin try     
       
SET @xml =CAST(( SELECT Mobile AS 'td','',SenderID AS 'td','',SentTime AS 'td','',             
MessageStatus  AS 'td','',StatusDescription as 'td','',MessageContent from ##dlr_sms FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))            
SET @body ='<html><H1>SMS Delivery report for '+cast (cast(getdate() as date) as nvarchar)+'</H1><body><table border = 2><tr><th>Mobile</th><th>Senderid</th><th>Sent Time</th><th>Message Status</th>    
<th>Status Description</th><th>MessageContent</th></tr>'             
SET @body = @body + @xml +'</table></body></html>'     
    
EXEC usp_enqueueemail            
@profile_name='Alerts',             
@recipients=@email,            
@subject='SMS Delivery Report',    
@from_address = 'SMSDLR Kit19 <contactus@kit19.com>',    
@body = @body,            
@body_format ='HTML',    
@query=@query,                                                        
@attach_query_result_as_file = 1,                                                        
@query_attachment_filename= 'Report.csv',                                                        
@query_result_separator=',' --enforce csv                                                        
,@query_result_no_padding=1 --trim                                                        
,@query_result_width=32767 --stop wordwrap                                                        
,@query_result_header = 1                                                        
 
 update #sms_dlr set IsProcessed=1 where id=@id
end try    
 begin catch   
  update #sms_dlr set IsProcessed=1,lasterror=ERROR_MESSAGE() where id=@id

  exec usp_InsertErrorInfo   
  
 end catch    
set @count=@count-1
 end
drop table if exists ##dlr_sms    
    
end       



GO

/* ============================================================
   Procedure: [dbo].[usp_SendSMSFromEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

     --170,335,'PANDIT','This is Test',0,1,0,0  
CREATE   PROCEDURE [dbo].[usp_SendSMSFromEnquiry] --391,335,'Pelsft','Hello #PersonName# From #CompanyName# Your Mobile No is #MobileNo#',0,1,0,0  
 @EnqID VARCHAR(500),  
 @Account BIGINT,  
 @SenderID VARCHAR(50),  
 @Message VARCHAR(2000),  
 @IsUnicode BIT,  
 @Mobile BIT,  
 @mobile1 BIT,  
 @Mobile2 BIT  
AS  
BEGIN  
 INSERT INTO GetBatchRecord  
   (  
     [User_id],  
     RandNum  
   )  
 VALUES  
   (  
     @Account,  
     @Account  
   )  
 DECLARE @BatchID BIGINT = (  
             SELECT MAX(gbr.BatchID)  
             FROM   GetBatchRecord AS gbr  
             WHERE  gbr.[User_id] = @Account  
         )  
   
 DELETE   
 FROM   GetBatchRecord  
 WHERE  [User_id] = @Account  
   
 INSERT INTO CloneMessageDeliveryStatus  
   (  
     -- MessageID -- this column value is auto-generated  
     BatchID,  
     Mobile,  
     [Message],  
     MessageStatus,  
     SenderID,  
     MessageInsertDate,  
     ScheduledDate,  
     ScheduledTime,  
     SmppID,  
     U_ID,  
     IsUniCode,  
     IsDnd,  
     IsAirtel,  
     MobileSubSet,  
     ValidNo,  
     IsPrority,  
     IsAllowDND,  
     DBType  
   )  
 SELECT DISTINCT A.BatchID,  
        A.Mobile,  
        A.Messagetext,  
        A.MessageStatus,  
        A.SenderID,  
        A.MessageInsertDate,  
        isnull(A.ScheduledDate,''),  
        isnull(A.ScheduledTime,''),  
        A.SmppID,  
        A.U_ID,  
        A.IsUnicode,  
        A.IsDnd,  
        A.IsAirtel,  
        A.MobileSubSet,  
        A.ValidNo,  
        A.IsPrority,  
        A.IsAllowDND,  
        A.DBType  
 FROM   (  
            SELECT @BatchID     AS BatchID,  
                   CASE   
                        WHEN @Mobile = 1 THEN ue.MobileNo  
                        ELSE ''  
                   END          AS Mobile,  
                   dbo.fn_getEnquiryMessage(ue.ParentID, @Message, ue.MobileNo) AS   
                   Messagetext,  
                   NULL         AS MessageStatus,  
                   @SenderID    AS SenderID,  
                   GETDATE()    AS MessageInsertDate,  
                   NULL         AS ScheduledDate,  
                   NULL         AS ScheduledTime,  
                   (  
                       SELECT TOP 1  
                              ud.SmppID  
                       FROM   User_Detail AS ud  
                       WHERE  ud.[User_ID] = @Account  
                   )            AS SmppID,  
                   @Account     AS U_ID,  
                   @IsUnicode   AS IsUnicode,  
                   0            AS IsDnd,  
                   0            AS IsAirtel,  
                   0            AS MobileSubSet,  
                   1            AS ValidNo,  
                   1            AS IsPrority,  
                   0            AS IsAllowDND,  
                   0            AS DBType  
            FROM   UserEnquiry  AS ue  
            WHERE  ue.EnquiryID IN (SELECT [value]  
                                    FROM   dbo.fn_Split(@EnqID, '#') AS fs)  
                   AND ue.MobileNo <>  
                       ''  
            UNION  
            SELECT @BatchID,  
                   CASE   
                        WHEN @mobile1 = 1 THEN ue.MobileNo1  
                        ELSE       ''  
                   END,  
                   dbo.fn_getEnquiryMessage(ue.ParentID, @Message, ue.MobileNo1),  
                   NULL         AS MessageStatus,  
                   @SenderID,  
                   GETDATE(),  
                   NULL,  
                   NULL,  
                   (  
                       SELECT TOP 1  
                              ud.SmppID  
                       FROM   User_Detail AS ud  
                       WHERE  ud.[User_ID] = @Account  
                   ),  
                   @Account,  
                   @IsUnicode,  
                   0,  
                   0,  
                   0,  
                   1,  
                   1,  
                   0,  
                   0  
            FROM   UserEnquiry  AS ue  
            WHERE  ue.EnquiryID IN (SELECT [value]  
                                    FROM   dbo.fn_Split(@EnqID, '#') AS fs)  
                   AND ue.MobileNo1 < > ''  
            UNION  
            SELECT @BatchID,  
                   CASE   
                        WHEN @Mobile2 = 1 THEN ue.MobileNo2  
                        ELSE       ''  
                   END,  
                   dbo.fn_getEnquiryMessage(ue.ParentID, @Message, ue.MobileNo2),  
                   NULL         AS MessageStatus,  
                   @SenderID,  
                   GETDATE(),  
                   NULL,  
                   NULL,  
                   (  
                       SELECT TOP 1  
                              ud.SmppID  
                       FROM   User_Detail AS ud  
                       WHERE  ud.[User_ID] = @Account  
                   ),  
                   @Account,  
                   @IsUnicode,  
                   0,  
                   0,  
                   0,  
                   1,  
                   1,  
                   0,  
                   0  
            FROM   UserEnquiry  AS ue  
            WHERE  ue.EnquiryID IN (SELECT [value]  
                                    FROM   dbo.fn_Split(@EnqID, '#') AS fs)  
                   AND ue.MobileNo2 < > ''  
        ) A  
 WHERE  A.Mobile <> ''  
   
 SELECT 'Record Saved'  
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_SendSMSFromEnquiry__Link_Track]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_SendSMSFromEnquiry__Link_Track  --66313,17626,RJGURU,'hello 4:49 pm',0,1,1,1               
 @EnqID VARCHAR(500),                  
 @Account BIGINT,                  
 @SenderID VARCHAR(50),                  
 @Message VARCHAR(2000),                  
 @IsUnicode BIT,                  
 @Mobile BIT,                  
 @mobile1 BIT,                  
 @Mobile2 BIT, 
  @tbl SMSUrl_Link READONLY                  
AS                  
BEGIN                  
 INSERT INTO GetBatchRecord                  
   (                  
     -- BatchID -- this column value is auto-generated                      
                       
     [User_id],                  
     RandNum                  
   )                  
 VALUES                  
   (                  
     @Account,                  
     @Account                  
   )                      
                   
 DECLARE @BatchID BIGINT = (                  
             SELECT MAX(gbr.BatchID)                  
             FROM   GetBatchRecord AS gbr                  
             WHERE  gbr.[User_id] = @Account                  
         )                      
                   
                   
                   
 DELETE                   
 FROM   GetBatchRecord                  
 WHERE  [User_id] = @Account                      
                   
                  
 Declare @NoOfSMS  bigint = 0;                  
                   
                   
               
               
 SELECT DISTINCT @NoOfSMS = (Count(*))               
                
 FROM   (                  
            SELECT @BatchID     AS BatchID,                  
                   CASE                   
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT),''),0)                
                        ELSE 0                  
                   END          AS Mobile,                  
                   dbo.fn_getEnquiryMessage_new(ue.ParentID, @Message, ue.MobileNo) AS                   
                   Messagetext,                  
                   NULL         AS MessageStatus,                  
                   @SenderID    AS SenderID,                  
                   GETDATE()    AS MessageInsertDate,                  
                   NULL         AS ScheduledDate,                  
                   NULL         AS ScheduledTime,                  
                   (                  
                       SELECT TOP 1 ud.SmppID                  
                       FROM   User_Detail AS ud                  
                       WHERE  ud.[User_ID] = @Account                  
                   )            AS SmppID,                  
                   @Account     AS U_ID,                  
                   @IsUnicode   AS IsUnicode,                  
                   0            AS IsDnd,                  
                   0            AS IsAirtel,                  
                   0            AS MobileSubSet,                  
                   1            AS ValidNo,                  
                   1            AS IsPrority,                  
                   0            AS IsAllowDND,                  
                   0            AS DBType                  
            FROM   UserEnquiry  AS ue                  
            WHERE  ue.EnquiryID IN (SELECT [value]                  
                                    FROM   dbo.fn_Split(@EnqID, '#') AS fs)                  
                   AND ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), '') <> ''             
                               
                   AND ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), '') not in             
                   (            
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo             
                   from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp            
                   on (UeTemp.MobileNo =C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)            
                
                   where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@EnqID, '#') AS fs ))            
                               
                                     
                                
              
                              
            UNION                  
            SELECT @BatchID,                  
                   CASE                   
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT) ,''),0)                
                        ELSE 0                  
                   END,                  
dbo.fn_getEnquiryMessage_new(ue.ParentID, @Message, ue.MobileNo1),                  
                   NULL         AS MessageStatus,                  
                   @SenderID,                  
     GETDATE(),                  
                   NULL,                  
                   NULL,                  
                   (                  
                       SELECT TOP 1 ud.SmppID                  
FROM   User_Detail AS ud                  
                       WHERE  ud.[User_ID] = @Account                  
                   ),                  
   @Account,                  
                   @IsUnicode,                  
                   0,                  
                   0,                  
                   0,                  
                   1,                  
                   1,                  
                   0,                  
                   0                  
            FROM   UserEnquiry  AS ue                  
            WHERE  ue.EnquiryID IN (SELECT [value]                  
                                    FROM   dbo.fn_Split(@EnqID, '#') AS fs)                  
                   AND ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), '') <> ''                  
                    AND ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT) , ''), '') not in             
                   (            
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo1             
                   from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp            
                   on (UeTemp.MobileNo1 =C_UDTemp.Mobile and UETemp.CountryCode1 = C_UDTemp.CountryCode)            
                
                   where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@EnqID, '#') AS fs ))            
                              
                              
                              
                              
            UNION                  
            SELECT @BatchID,                  
                   CASE                   
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(CAST( ue.MobileNo2   as bigint),''),0)                
                        ELSE 0                  
                   END,                  
                   dbo.fn_getEnquiryMessage_new(ue.ParentID, @Message, ue.MobileNo2),                  
                   NULL         AS MessageStatus,                  
                   @SenderID,                  
                   GETDATE(),                  
                   NULL,                  
                   NULL,                  
                   (                  
                       SELECT TOP 1 ud.SmppID                  
                       FROM   User_Detail AS ud                  
                       WHERE  ud.[User_ID] = @Account                  
                   ),                  
                   @Account,                  
                   @IsUnicode,                  
                   0,                  
                   0,                  
                   0,                  
                   1,                  
                   1,                  
                   0,                  
                   0                  
            FROM   UserEnquiry  AS ue                  
            WHERE  ue.EnquiryID IN (SELECT [value]                  
                                    FROM   dbo.fn_Split(@EnqID, '#') AS fs)                  
                   AND ISNULL(NULLIF(CAST( ue.MobileNo2   as bigint), ''), '') <> ''              
                               
                    AND ISNULL(NULLIF(CAST( ue.MobileNo2   as bigint), ''), '') not in            
                   (            
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo2             
                   from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp            
                   on (UeTemp.MobileNo2 =C_UDTemp.Mobile and UETemp.CountryCode2 = C_UDTemp.CountryCode)            
                
                   where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@EnqID, '#') AS fs ))            
           
        ) A                  
 WHERE  A.Mobile <> 0                  
                   
 --select @NoOfSMS               
                  
      DECLARE @CurrentBalance BIGINT = (                      
             SELECT TOP 1 isnull(cd.Balance,0)                      
             FROM   Credit_Details AS cd                      
             WHERE  cd.[User_ID] = @Account                      
             ORDER BY                      
                    cd.Credit_ID DESC                      
         )                      
                       
 DECLARE @Balance BIGINT = @CurrentBalance - @NoOfSMS                      
    IF @Balance > 0               
      Begin 
      
      declare @rlnk as int =0    
