				   inner join #TableData2 t2 on UE.EnquiryID = t2.ID 
                        
                   --where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@EnqID, '#') AS fs )
				   )                    
                   
        ) A                          
 WHERE  A.Mobile <> 0                          
                           
 --select @NoOfSMS     
     
 select  @NoOfSMS = ( Count(*)) from #tempTable    
                          
      DECLARE @CurrentBalance BIGINT = (                              
             SELECT TOP 1 isnull(cd.Balance,0)                              
             FROM   Credit_Details AS cd                              
             WHERE  cd.[User_ID] = @Account                              
             ORDER BY                              
                    cd.Credit_ID DESC                              
         )                              
                               
 DECLARE @Balance BIGINT = @CurrentBalance - @NoOfSMS                              
    IF @Balance > 0                       
      Begin                      
           INSERT INTO CloneMessageDeliveryStatus                          
   (               -- MessageID -- this column value is auto-generated                              
                               
     BatchID,                          
     Mobile,                          
     [Message],                          
     MessageStatus,                          
     SenderID,                          
     MessageInsertDate,                          
     ScheduledDate,                          
     ScheduledTime,                          
     SmppID,                          
     U_ID,                          
     IsUniCode,                          
IsDnd,                          
     IsAirtel,                          
     MobileSubSet,                          
     ValidNo,                          
     IsPrority,                          
     IsAllowDND,                          
     DBType                          
   )                          
                       
 SELECT     
   A.BatchID,                          
