     U_ID,                        
     IsUniCode,                        
     IsDnd,                        
     IsAirtel,                        
     MobileSubSet,                        
     ValidNo,                        
     IsPrority,                        
     IsAllowDND,                        
     DBType                        
   )                        
 SELECT DISTINCT                      
