CREATE   PROCEDURE [dbo].[usp_SendSMSFromLeads_Link_Track_new_WithDLTTemplateID]                               
 @ID VARCHAR(Max),                                
 @Account BIGINT,                                
 @SenderID VARCHAR(50),                                
 @Message NVARCHAR(2000),                                
 @IsUnicode BIT,                                
 @Mobile BIT,                                
 @mobile1 BIT,                                
 @Mobile2 BIT,   @tbl SMSUrl_Link_new READONLY,      
 @DLTTemplateID nvarchar(200),    
 @UserId bigint    
AS                                
BEGIN                                
 -- BatchID -- this column value is auto-generated        
 declare @parentid bigint = (select Parentid from user_detail where USER_ID=@Account)                                
 INSERT INTO GetBatchRecord                                
   (                                
     [User_id],                                
     RandNum                                
   )                                
 VALUES                                
   (                                
     @Account,                                
     @Account                                
   )                                      
                                 
 DECLARE @BatchID BIGINT = scope_identity()                     
                          
 DELETE                                 
 FROM   GetBatchRecord                                
 WHERE  BatchID = @BatchID                                      
                   
                                 
 Declare @NoOfSMS bigint = 0                                
                                 
     
 drop table if exists #tempTable      
    
select * into #tempTable     
 from (                  
  select case when @IsUnicode=0 and LEN(A.Messagetext) <=160 then 1 when @IsUnicode=0 and LEN(A.Messagetext) >160 then ceiling(LEN(A.Messagetext)/cast(153 as float)) when @IsUnicode=1 and LEN(A.Messagetext) >70 then ceiling(LEN(A.Messagetext)/cast(67 as float)) else 1 end as countm, *  
 FROM   (                                
            SELECT @BatchID    AS BatchID,                                
                   CASE                                 
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), 0)                                
                        ELSE 0                                
                   END         AS Mobile,                                
