    IF @Balance > 0                             
      Begin                
                    
        declare @rlnk as int =0                    
      select @rlnk= COUNT(*) from @tbl                    
      if @rlnk >0                  
      begin                  
  exec Usp_Insert_SMSUrl_Link_new 0,@BatchID,'Enquiry SMS',@tbl                  
     end                                     
   INSERT INTO CloneMessageDeliveryStatus                                
    (                                
     -- MessageID -- this column value is auto-generated                                      
                                     
     BatchID,                                
     Mobile,                                
     [Message],                                
     MessageStatus,                                
     SenderID,                                
     MessageInsertDate,                                
     ScheduledDate,                                
     ScheduledTime,                                
     SmppID,                                
     U_ID,                                
     IsUniCode,                                
     IsDnd,                                
     IsAirtel,      
     MobileSubSet,                                
     ValidNo,                                
     IsPrority,                                
     IsAllowDND,            
     DBType                                
   )                                
 SELECT DISTINCT                              
        A.BatchID,                                
        A.Mobile,                                
        A.Messagetext,                                
        A.MessageStatus,                                
        A.SenderID,                                
        A.MessageInsertDate,                                
        isnull(A.ScheduledDate,'') as ScheduledDate,                           
        isnull(A.ScheduledTime,'') as ScheduledTime,                                
        A.SmppID,                                
        A.U_ID,                                
