                   AND ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), '') <>                                 
                  ''           
                        AND not exists(select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo=C_UDTemp.Mobile and UE.CountryCode = C_UDTemp.CountryCode))                        
                                            
                                            
                                            
                                            
                                            
                          
                                            
