CREATE   PROCEDURE usp_SendSMSFromLeads_New_Shaired           
 @ID VARCHAR(500),            
 @Account BIGINT,            
 @SenderID VARCHAR(50),            
 @Message VARCHAR(2000),            
 @IsUnicode BIT,            
 @Mobile BIT,            
 @mobile1 BIT,            
 @Mobile2 BIT            
AS            
BEGIN            
 -- BatchID -- this column value is auto-generated                  
             
 INSERT INTO GetBatchRecord            
   (            
     [User_id],            
     RandNum            
   )            
 VALUES            
   (            
     @Account,            
     @Account            
   )                  
             
 DECLARE @BatchID BIGINT = (            
             SELECT MAX(gbr.BatchID)            
             FROM   GetBatchRecord AS gbr            
             WHERE  gbr.[User_id] = @Account            
         )                
             
             
             
 DELETE             
 FROM   GetBatchRecord            
 WHERE  [User_id] = @Account                  
             
 Declare @NoOfSMS bigint = 0            
             
 SELECT DISTINCT @NoOfSMS = (Count(*))         
 FROM   (            
            SELECT @BatchID    AS BatchID,            
                   CASE             
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), 0)            
                        ELSE 0            
                   END         AS Mobile,            
                   dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo) AS             
                   Messagetext,            
                   NULL        AS MessageStatus,            
                   @SenderID   AS SenderID,            
                   GETDATE()   AS MessageInsertDate,            
                   NULL        AS ScheduledDate,            
                   NULL        AS ScheduledTime,            
                   (            
                       SELECT TOP 1 ud.SmppID            
                       FROM   User_Detail AS ud            
                       WHERE  ud.[User_ID] = @Account            
                   )           AS SmppID,            
                   @Account    AS U_ID,            
                   @IsUnicode  AS IsUnicode,            
                   0           AS IsDnd,            
                   0           AS IsAirtel,            
                   0           AS MobileSubSet,            
                   1           AS ValidNo,            
                   1           AS IsPrority,            
                   0           AS IsAllowDND,            
                   0           AS DBType            
            FROM   UserLeads   AS ue            
            WHERE  ue.ID IN (SELECT [value]            
                             FROM   dbo.fn_Split(@ID, '#') AS fs)            
                   AND ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), '') <>             
                       ''             
                    AND ISNULL(NULLIF(CAST(ue.MobileNo as bigint), ''), '') not in       
                   (      
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo       
                   from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp      
                   on (UeTemp.MobileNo =C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)      
                   where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs ))      
                  -- where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs ))      
                        
                        
                        
                        
                        
                        
            UNION              
                        
            SELECT @BatchID,            
                   CASE             
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), 0)            
                        ELSE 0            
                   END,            
dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo1),            
                   NULL       AS MessageStatus,            
                   @SenderID,            
       GETDATE(),            
                   NULL,            
                   NULL,            
                   (            
                       SELECT TOP 1 ud.SmppID            
     FROM   User_Detail AS ud            
              WHERE  ud.[User_ID] = @Account            
                   ),            
                   @Account,            
                   @IsUnicode,            
                   0,            
                   0,            
                   0,            
                   1,            
                   1,            
           0,            
                   0            
            FROM   UserLeads  AS ue            
            WHERE  ue.ID IN (SELECT [value]            
                             FROM   dbo.fn_Split(@ID, '#') AS fs)            
                   AND ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), '') <            
                       > ''        
                        AND ISNULL(NULLIF(CAST(ue.MobileNo1 as bigint), ''), '') not in       
                   (      
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo1       
                   from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp      
                   on (UeTemp.MobileNo1 =C_UDTemp.Mobile and UETemp.CountryCode1 = C_UDTemp.CountryCode)      
          
                   where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs ))           
                        
                        
                        
                        
               
                        
                        
                        
                        
                        
                        
            UNION              
                        
            SELECT @BatchID,            
                   CASE             
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), 0)            
                        ELSE 0            
                   END,            
                   dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo2),            
                   NULL       AS MessageStatus,            
                   @SenderID,            
                   GETDATE(),            
                   NULL,            
                   NULL,            
                   (            
                       SELECT TOP 1 ud.SmppID            
                       FROM   User_Detail AS ud            
                       WHERE  ud.[User_ID] = @Account            
                   ),            
                   @Account,            
                   @IsUnicode,            
                   0,            
                   0,            
                   0,            
                   1,            
                   1,            
                   0,            
                   0            
            FROM   UserLeads  AS ue            
            WHERE  ue.ID IN (SELECT [value]            
                             FROM   dbo.fn_Split(@ID, '#') AS fs)            
                   AND ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), '') <            
                       > ''       
                       AND ISNULL(NULLIF(CAST(ue.MobileNo2 as bigint), ''), '') not in      
                   (      
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo2       
                   from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp      
                   on (UeTemp.MobileNo2 =C_UDTemp.Mobile and UETemp.CountryCode2 = C_UDTemp.CountryCode)      
          
                   where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs ))      
                             
                                  
        ) A            
 WHERE  A.Mobile <> 0              
            
  DECLARE @CurrentBalance BIGINT = (                
             SELECT TOP 1 isnull(cd.Balance,0)                
             FROM   Credit_Details AS cd                
             WHERE  cd.[User_ID] = @Account                
             ORDER BY                
                    cd.Credit_ID DESC                
         )                
                 
 DECLARE @Balance BIGINT = @CurrentBalance - @NoOfSMS                
    IF @Balance > 0         
      Begin        
   INSERT INTO CloneMessageDeliveryStatus            
    (            
     -- MessageID -- this column value is auto-generated                  
                 
     BatchID,            
     Mobile,            
     [Message],            
     MessageStatus,            
     SenderID,            
     MessageInsertDate,            
     ScheduledDate,            
     ScheduledTime,            
     SmppID,            
     U_ID,            
     IsUniCode,            
     IsDnd,            
     IsAirtel,            
     MobileSubSet,            
     ValidNo,            
     IsPrority,            
     IsAllowDND,            
     DBType            
   )            
 SELECT DISTINCT          
        A.BatchID,            
        A.Mobile,            
        A.Messagetext,            
        A.MessageStatus,            
        A.SenderID,            
        A.MessageInsertDate,            
        isnull(A.ScheduledDate,''),      
        isnull(A.ScheduledTime,''), 
        A.SmppID,            
        A.U_ID,            
        A.IsUnicode,            
        A.IsDnd,            
        A.IsAirtel,            
        A.MobileSubSet,            
        A.ValidNo,            
        A.IsPrority,            
        A.IsAllowDND,            
        A.DBType            
 FROM   (            
            SELECT @BatchID    AS BatchID,            
                   CASE             
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), 0)            
                        ELSE 0            
                   END         AS Mobile,            
                   dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo) AS             
                   Messagetext,            
                   NULL        AS MessageStatus,            
                   @SenderID   AS SenderID,            
                   GETDATE()   AS MessageInsertDate,            
                   NULL        AS ScheduledDate,            
                   NULL        AS ScheduledTime,            
                   (            
                       SELECT TOP 1 ud.SmppID            
                       FROM   User_Detail AS ud            
                       WHERE  ud.[User_ID] = @Account            
                   )           AS SmppID,            
                   @Account    AS U_ID,            
                   @IsUnicode  AS IsUnicode,            
                   0           AS IsDnd,            
                   0           AS IsAirtel,            
     0           AS MobileSubSet,            
                   1           AS ValidNo,            
                   1           AS IsPrority,            
                   0           AS IsAllowDND,            
                   0           AS DBType            
            FROM   UserLeads   AS ue            
            WHERE  ue.ID IN (SELECT [value]            
                             FROM   dbo.fn_Split(@ID, '#') AS fs)            
                   AND ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), '') <>             
                       ''       
                        AND ISNULL(NULLIF(CAST(ue.MobileNo as bigint), ''), '') not in       
                   (      
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo       
                   from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp      
                   on (UeTemp.MobileNo =C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)      
          
                   where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs ))     
                        
                        
                        
                        
                        
                        
                        
            UNION              
                        
            SELECT @BatchID,            
                   CASE             
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), 0)            
                        ELSE 0            
                   END,            
                   dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo1),            
                   NULL       AS MessageStatus,            
                   @SenderID,            
                   GETDATE(),            
                   NULL,            
                   NULL,            
                   (            
                       SELECT TOP 1 ud.SmppID            
                       FROM   User_Detail AS ud            
              WHERE  ud.[User_ID] = @Account            
                   ),            
                   @Account,            
                   @IsUnicode,            
                   0,            
           0,            
                   0,            
                   1,            
                   1,            
           0,            
                   0            
            FROM   UserLeads  AS ue            
            WHERE  ue.ID IN (SELECT [value]            
                             FROM   dbo.fn_Split(@ID, '#') AS fs)            
                   AND ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), '') <            
                       > ''        
                             
                       AND ISNULL(NULLIF(CAST(ue.MobileNo1 as bigint), ''), '') not in      
                   (      
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo1       
                   from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp      
                   on (UeTemp.MobileNo1 =C_UDTemp.Mobile and UETemp.CountryCode1 = C_UDTemp.CountryCode)      
          
                   where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs ))            
                        
                        
                        
                        
                        
                        
                        
                        
                        
                        
                        
            UNION              
                        
            SELECT @BatchID,            
                   CASE             
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), 0)            
                        ELSE 0            
                   END,            
                   dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo2),            
                   NULL       AS MessageStatus,            
                   @SenderID,            
                   GETDATE(),            
                   NULL,            
                   NULL,            
                   (            
                       SELECT TOP 1 ud.SmppID            
                       FROM   User_Detail AS ud            
                       WHERE  ud.[User_ID] = @Account            
                   ),            
                   @Account,            
                   @IsUnicode,            
                   0,            
                   0,            
                   0,            
                   1,            
                   1,            
                   0,            
                   0            
            FROM   UserLeads  AS ue            
            WHERE  ue.ID IN (SELECT [value]            
                             FROM   dbo.fn_Split(@ID, '#') AS fs)            
                   AND ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), '') <            
                       > ''       
                             
                        AND ISNULL(NULLIF(CAST(ue.MobileNo2 as bigint), ''), '') not in       
                   (      
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo2       
                   from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp      
                   on (UeTemp.MobileNo2 =C_UDTemp.Mobile and UETemp.CountryCode2 = C_UDTemp.CountryCode)      
          
                   where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs ))             
        ) A            
 WHERE  A.Mobile <> 0              
               
      SELECT 'Record Saved'        
      End        
    Else        
