/* ============================================================
   Procedure: [dbo].[usp_SendSMSFromLeads_New_WithDLTTemplateID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
              
CREATE   PROCEDURE [dbo].[usp_SendSMSFromLeads_New_WithDLTTemplateID]                           
 @ID VARCHAR(Max),                            
 @Account BIGINT,                            
 @SenderID VARCHAR(50),                            
 @Message NVARCHAR(2000),                            
 @IsUnicode BIT,                            
 @Mobile BIT,                            
 @mobile1 BIT,                            
 @Mobile2 BIT,        
 @DLTTemplateID nvarchar(200),      
 @UserId bigint      
AS                            
BEGIN                            
 -- BatchID -- this column value is auto-generated      
       
 declare @parentid bigint = (select Parentid from user_detail where USER_ID=@Account)                            
 INSERT INTO GetBatchRecord                            
   (                            
     [User_id],                            
     RandNum                            
   )                            
 VALUES                            
   (                            
     @Account,                            
     @Account                            
   )                                  
                             
 DECLARE @BatchID BIGINT = scope_identity()                       
                                               
                             
 DELETE                             
 FROM   GetBatchRecord                            
 WHERE  BatchID = @BatchID                                  
               
                             
 Declare @NoOfSMS bigint = 0                            
                             
      
drop table if exists #tempTable        
      
select * into #tempTable from (              
   select case when @IsUnicode=0 and LEN(A.Messagetext) <=160 then 1 when @IsUnicode=0 and LEN(A.Messagetext) >160 then ceiling(LEN(A.Messagetext)/cast(153 as float))        
    when @IsUnicode=1 and LEN(A.Messagetext) >70 then ceiling(LEN(A.Messagetext)/cast(67 as float)) else 1 end as countm ,    
 *    
  FROM   (                            
            SELECT @BatchID    AS BatchID,                            
                   CASE                             
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), 0)                            
                        ELSE 0                            
                   END         AS Mobile,                            
                   dbo.fn_getLeadsMessage_New(ue.ParentID, @Message, ue.MobileNo) AS                             
                   Messagetext,                            
                   NULL        AS MessageStatus,                            
                   @SenderID   AS SenderID,                            
                   GETDATE()   AS MessageInsertDate,                            
                   ''        AS ScheduledDate,                            
                   ''        AS ScheduledTime,                            
                   (                            
                       SELECT TOP 1 ud.SmppID                            
                       FROM   User_Detail AS ud                            
                       WHERE  ud.[User_ID] = @Account                            
                   )           AS SmppID,                            
                   @Account    AS U_ID,                            
                   @IsUnicode  AS IsUnicode,                            
                   0           AS IsDnd,                            
                   0           AS IsAirtel,                            
                   0           AS MobileSubSet,                            
                   1           AS ValidNo,                            
                   1           AS IsPrority,                            
                   0           AS IsAllowDND,                            
                   0           AS DBType,      
       ue.ID as [LeadId]      
            FROM   UserLeads   AS ue                                        WHERE  ue.ID IN (SELECT [value]                            
                             FROM   dbo.fn_Split(@ID, '#') AS fs)              
                   AND ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), '') <>                             
                       ''                             
                    AND not exists                       
                   (select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo=C_UDTemp.Mobile and UE.CountryCode = C_UDTemp.CountryCode))                      
                  -- where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs ))                      
                                        
                                        
                
                                        
                                        
                                        
            UNION                              
                                        
            SELECT @BatchID,                            
                   CASE                             
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), 0)                            
                        ELSE 0                            
                   END,                            
dbo.fn_getLeadsMessage_New(ue.ParentID, @Message, ue.MobileNo1),                            
                   NULL       AS MessageStatus,                            
                   @SenderID,                            
       GETDATE(),                            
                   '',                            
                   '',                            
                   (                            
                       SELECT TOP 1 ud.SmppID                            
     FROM   User_Detail AS ud                            
              WHERE  ud.[User_ID] = @Account                            
                   ),                            
                   @Account,                            
                   @IsUnicode,                            
                   0,                            
                   0,                            
                   0,                            
                   1,                            
                   1,                            
       0,                            
                   0,      
       ue.ID as [LeadId]      
            FROM   UserLeads  AS ue                            
            WHERE  ue.ID IN (SELECT [value]                            
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                            
                   AND ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), '') <                            
                       > ''                        
                        AND not exists(select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo1=C_UDTemp.Mobile and UE.CountryCode1 = C_UDTemp.CountryCode))                           
                                      
            UNION                              
                                        
            SELECT @BatchID,                            
                   CASE                             
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), 0)                            
                        ELSE 0                            
                   END,                            
                   dbo.fn_getLeadsMessage_New(ue.ParentID, @Message, ue.MobileNo2),                            
                   NULL       AS MessageStatus,                            
                   @SenderID,                            
                   GETDATE(),                            
                   '',                            
                   '',                            
                   (                            
                       SELECT TOP 1 ud.SmppID                            
                       FROM   User_Detail AS ud                            
                       WHERE  ud.[User_ID] = @Account                            
                   ),                            
   @Account,              
                   @IsUnicode,                            
                   0,                            
                   0,                            
                   0,                            
                   1,                            
                   1,                            
                   0,                            
       0,      
       ue.ID as [LeadId]                            
            FROM   UserLeads  AS ue                            
            WHERE  ue.ID IN (SELECT [value]                            
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                            
                   AND ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), '') <                  
                       > ''                       
                       AND not exists(select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo2=C_UDTemp.Mobile and UE.CountryCode2 = C_UDTemp.CountryCode))                      
                                             
                         
        ) A                            
 WHERE  A.Mobile <> 0) B      
       
       
      
 SELECT @NoOfSMS = sum(countm) from #tempTable      
      
                            
  DECLARE @CurrentBalance BIGINT = (                                
             SELECT TOP 1 isnull(cd.Balance,0)                                
             FROM   Credit_Details AS cd                                
             WHERE  cd.[User_ID] = @Account                                
             ORDER BY                                
                    cd.Credit_ID DESC                                
         )                                
                                 
 DECLARE @Balance BIGINT = @CurrentBalance - @NoOfSMS                                
    IF @Balance > 0                         
      Begin                        
   INSERT INTO CloneMessageDeliveryStatus                            
    (                            
     -- MessageID -- this column value is auto-generated                                  
                                 
     BatchID,                            
     Mobile,                            
     [Message],                            
     MessageStatus,                            
     SenderID,                            
     MessageInsertDate,                            
     ScheduledDate,                            
     ScheduledTime,                            
     SmppID,                            
     U_ID,                            
     IsUniCode,                            
     IsDnd,                            
     IsAirtel,                            
     MobileSubSet,                            
     ValidNo,                            
     IsPrority,                            
     IsAllowDND,                            
     DBType                            
   )                            
 SELECT DISTINCT                          
        A.BatchID,                            
        A.Mobile,                            
        A.Messagetext,                            
        A.MessageStatus,                            
        A.SenderID,                            
        A.MessageInsertDate,                            
        isnull(A.ScheduledDate,'') as ScheduledDate,                            
        isnull(A.ScheduledTime,'') as ScheduledTime,                            
        A.SmppID,                            
        A.U_ID,                            
        A.IsUnicode,                            
        A.IsDnd,                            
        A.IsAirtel,                            
        A.MobileSubSet,                            
        A.ValidNo,                       
        A.IsPrority,                            
        A.IsAllowDND,                            
        A.DBType                            
 FROM   (                            
            SELECT @BatchID    AS BatchID,                            
                   CASE                             
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), 0)                            
                        ELSE 0                            
                   END         AS Mobile,                            
                   dbo.fn_getLeadsMessage_New(ue.ParentID, @Message, ue.MobileNo) AS                             
                   Messagetext,                            
                   NULL        AS MessageStatus,                   
                   @SenderID   AS SenderID,             
                   GETDATE()   AS MessageInsertDate,                            
                   NULL        AS ScheduledDate,                            
                   NULL        AS ScheduledTime,                            
                   (                            
                       SELECT TOP 1 ud.SmppID                            
                       FROM   User_Detail AS ud                            
                       WHERE  ud.[User_ID] = @Account                            
                   )           AS SmppID,                            
                   @Account    AS U_ID,                            
                   @IsUnicode  AS IsUnicode,                            
                   0           AS IsDnd,                            
                   0           AS IsAirtel,                            
     0           AS MobileSubSet,                            
                   1           AS ValidNo,                            
  1           AS IsPrority,                            
                   0           AS IsAllowDND,                            
                   0           AS DBType                            
            FROM   UserLeads   AS ue                            
            WHERE  ue.ID IN (SELECT [value]                            
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                            
                   AND ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), '') <>                             
                  ''                  
                        AND not exists(select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo=C_UDTemp.Mobile and UE.CountryCode = C_UDTemp.CountryCode))                    
                                        
            UNION                              
                                        
            SELECT @BatchID,                            
                   CASE                             
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), 0)                            
                        ELSE 0                            
                   END,                            
                   dbo.fn_getLeadsMessage_New(ue.ParentID, @Message, ue.MobileNo1),                            
                   NULL       AS MessageStatus,                            
                   @SenderID,                            
                   GETDATE(),                            
                   NULL,                            
                   NULL,                            
                   (                            
                       SELECT TOP 1 ud.SmppID                            
                       FROM   User_Detail AS ud                            
              WHERE  ud.[User_ID] = @Account                            
                   ),                            
                   @Account,                            
                   @IsUnicode,                            
                   0,                            
           0,                            
                   0,                            
                   1,                            
                   1,                            
           0,                            
                   0                            
            FROM   UserLeads  AS ue                            
            WHERE  ue.ID IN (SELECT [value]                            
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                            
                   AND ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), '') <                            
                       > ''                        
                                             
                       AND not exists(select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo1=C_UDTemp.Mobile and UE.CountryCode1 = C_UDTemp.CountryCode))                          
                             
            UNION                              
                                        
            SELECT @BatchID,                            
                   CASE                          
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), 0)                            
         ELSE 0                            
                   END,                            
                   dbo.fn_getLeadsMessage_New(ue.ParentID, @Message, ue.MobileNo2),                            
                   NULL       AS MessageStatus,                            
                   @SenderID,                            
                   GETDATE(),                            
                   NULL,                            
                   NULL,                            
                   (                            
                       SELECT TOP 1 ud.SmppID                            
                       FROM   User_Detail AS ud                            
                 WHERE  ud.[User_ID] = @Account                            
                   ),                            
                   @Account,                            
          @IsUnicode,                            
                   0,                            
                   0,                            
                   0,                            
                   1,                            
                   1,                            
                   0,                            
                   0                            
            FROM   UserLeads  AS ue                            
            WHERE  ue.ID IN (SELECT [value]                            
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                            
                   AND ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), '') <                            
                       > ''                       
                                             
                        AND not exists(select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo2=C_UDTemp.Mobile and UE.CountryCode2 = C_UDTemp.CountryCode))                             
        ) A                            
 WHERE  A.Mobile <> 0          
         
    Begin try        
       exec Usp_Save_DLTTemplateID_with_BatchID @batchid,@DLTTemplateID        
    End try        
    begin catch        
      exec usp_InsertErrorInfo        
    End catch         
              
if(@UserId  > 0 )    
     
    
  begin           
      
 
    
  declare @Username nvarchar(255)          
  declare @leadActivityHistory AS LeadActivitywithid_Tbltype            
  select @Username = User_Login, @ParentId = ParentID from User_Detail(nolock) where User_Id = @UserId          
            
  insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )            
  select             
  LeadId,            
  @UserId,             
  @parentid,              concat(@Username , ' sent an sms with content ', Messagetext , ' on mobile ', Mobile),            
  'SMS sent to lead',        
'Batchinfo',               
  @BatchID            
  from #tempTable           
  exec UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory          
      
     
end       
                               
      SELECT 'Record Saved'                        
      End                        
    Else                        
      Begin                        
        SELECT 'Insufficient Balance'                            
      End                            
                              
END   
  


GO

/* ============================================================
   Procedure: [dbo].[usp_SendSMSFromLeads_New1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_SendSMSFromLeads_New1               
 @ID VARCHAR(500),                
 @Account BIGINT,                
 @SenderID VARCHAR(50),                
 @Message VARCHAR(2000),                
 @IsUnicode BIT,                
 @Mobile BIT,                
 @mobile1 BIT,                
 @Mobile2 BIT                
AS                
BEGIN                
 -- BatchID -- this column value is auto-generated                      
 declare @parentid bigint = (select Parentid from user_detail where USER_ID=@Account)                
 INSERT INTO GetBatchRecord                
   (                
     [User_id],                
     RandNum                
   )                
 VALUES                
   (                
     @Account,                
     @Account                
   )                      
                 
 DECLARE @BatchID BIGINT = (                
             SELECT MAX(gbr.BatchID)                
             FROM   GetBatchRecord AS gbr                
             WHERE  gbr.[User_id] = @Account                
         )                    
                 
                 
                 
 DELETE                 
 FROM   GetBatchRecord                
 WHERE  BatchID = @BatchID                      
   
                 
 Declare @NoOfSMS bigint = 0                
                 
 SELECT @NoOfSMS = sum(B.countm) from (  
  select case when @IsUnicode=0 and LEN(A.Messagetext) <=160 then 1 when @IsUnicode=0 and LEN(A.Messagetext) >160 then ceiling(LEN(A.Messagetext)/cast(153 as float)) when @IsUnicode=1 and LEN(A.Messagetext) >70 then ceiling(LEN(A.Messagetext)/cast(67 as float)) else 1 end as countm           
 FROM   (                
            SELECT @BatchID    AS BatchID,                
                   CASE                 
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), 0)                
                        ELSE 0                
                   END         AS Mobile,                
                   dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo) AS                 
                   Messagetext,                
                   NULL        AS MessageStatus,                
                   @SenderID   AS SenderID,                
                   GETDATE()   AS MessageInsertDate,                
                   NULL        AS ScheduledDate,                
                   NULL        AS ScheduledTime,                
                   (                
                       SELECT TOP 1 ud.SmppID                
                       FROM   User_Detail AS ud                
                       WHERE  ud.[User_ID] = @Account                
                   )           AS SmppID,                
                   @Account    AS U_ID,                
                   @IsUnicode  AS IsUnicode,                
                   0           AS IsDnd,                
                   0           AS IsAirtel,                
                   0           AS MobileSubSet,                
                   1           AS ValidNo,                
                   1           AS IsPrority,                
                   0           AS IsAllowDND,                
                   0           AS DBType                
            FROM   UserLeads   AS ue                
            WHERE  ue.ID IN (SELECT [value]                
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                
                   AND ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), '') <>                 
                       ''                 
                    AND not exists           
                   (select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo=C_UDTemp.Mobile and UE.CountryCode = C_UDTemp.CountryCode))          
                  -- where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs ))          
                            
                            
                            
                           
                            
                            
            UNION                  
                            
            SELECT @BatchID,                
                   CASE                 
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), 0)                
                        ELSE 0                
                   END,                
dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo1),                
                   NULL       AS MessageStatus,                
                   @SenderID,                
       GETDATE(),                
                   NULL,                
                   NULL,                
                   (                
                       SELECT TOP 1 ud.SmppID                
     FROM   User_Detail AS ud                
              WHERE  ud.[User_ID] = @Account                
                   ),                
                   @Account,                
                   @IsUnicode,                
                   0,                
                   0,                
                   0,                
                   1,                
                   1,                
           0,                
                   0                
            FROM   UserLeads  AS ue                
            WHERE  ue.ID IN (SELECT [value]                
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                
                   AND ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), '') <                
                       > ''            
                        AND not exists(select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo1=C_UDTemp.Mobile and UE.CountryCode1 = C_UDTemp.CountryCode))               
                            
                            
                            
                            
                   
                            
                            
                            
                            
                            
                            
            UNION                  
                            
            SELECT @BatchID,                
                   CASE                 
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), 0)                
                        ELSE 0                
                   END,                
                   dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo2),                
                   NULL       AS MessageStatus,                
                   @SenderID,                
                   GETDATE(),                
                   NULL,                
                   NULL,                
                   (                
                       SELECT TOP 1 ud.SmppID                
                       FROM   User_Detail AS ud                
                       WHERE  ud.[User_ID] = @Account                
                   ),                
                   @Account,                
                   @IsUnicode,                
                   0,                
                   0,                
                   0,                
                   1,                
                   1,                
                   0,                
                   0                
            FROM   UserLeads  AS ue                
            WHERE  ue.ID IN (SELECT [value]                
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                
                   AND ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), '') <                
                       > ''           
                       AND not exists(select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo2=C_UDTemp.Mobile and UE.CountryCode2 = C_UDTemp.CountryCode))          
                                 
                
        ) A                
 WHERE  A.Mobile <> 0) B                 
                
  DECLARE @CurrentBalance BIGINT = (                    
             SELECT TOP 1 isnull(cd.Balance,0)                    
             FROM   Credit_Details AS cd                    
             WHERE  cd.[User_ID] = @Account                    
             ORDER BY                    
                    cd.Credit_ID DESC                    
         )                    
                     
 DECLARE @Balance BIGINT = @CurrentBalance - @NoOfSMS                    
    IF @Balance > 0             
      Begin            
   INSERT INTO CloneMessageDeliveryStatus                
    (                
     -- MessageID -- this column value is auto-generated                      
                     
     BatchID,                
     Mobile,                
     [Message],                
     MessageStatus,                
     SenderID,                
     MessageInsertDate,                
     ScheduledDate,                
     ScheduledTime,                
     SmppID,                
     U_ID,                
     IsUniCode,                
     IsDnd,                
     IsAirtel,                
     MobileSubSet,                
     ValidNo,                
     IsPrority,                
     IsAllowDND,                
     DBType                
   )                
 SELECT DISTINCT              
        A.BatchID,                
        A.Mobile,                
        A.Messagetext,                
        A.MessageStatus,                
        A.SenderID,                
        A.MessageInsertDate,                
        isnull(A.ScheduledDate,''),      
        isnull(A.ScheduledTime,''), 
        A.SmppID,                
        A.U_ID,                
        A.IsUnicode,                
        A.IsDnd,                
        A.IsAirtel,                
        A.MobileSubSet,                
        A.ValidNo,                
        A.IsPrority,                
        A.IsAllowDND,                
        A.DBType                
 FROM   (                
            SELECT @BatchID    AS BatchID,                
                   CASE                 
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), 0)                
                        ELSE 0                
                   END         AS Mobile,                
                   dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo) AS                 
                   Messagetext,                
                   NULL        AS MessageStatus,                
                   @SenderID   AS SenderID,                
                   GETDATE()   AS MessageInsertDate,                
                   NULL        AS ScheduledDate,                
                   NULL        AS ScheduledTime,                
                   (                
                       SELECT TOP 1 ud.SmppID                
                       FROM   User_Detail AS ud                
                       WHERE  ud.[User_ID] = @Account                
                   )           AS SmppID,                
                   @Account    AS U_ID,                
                   @IsUnicode  AS IsUnicode,                
                   0           AS IsDnd,                
                   0           AS IsAirtel,                
     0           AS MobileSubSet,                
                   1           AS ValidNo,                
                   1           AS IsPrority,                
                   0           AS IsAllowDND,                
                   0           AS DBType                
            FROM   UserLeads   AS ue                
            WHERE  ue.ID IN (SELECT [value]                
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                
                   AND ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), '') <>                 
                       ''      
                        AND not exists(select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo=C_UDTemp.Mobile and UE.CountryCode = C_UDTemp.CountryCode))        
                            
                            
                            
                            
                            
                            
                            
            UNION                  
                            
            SELECT @BatchID,                
                   CASE                 
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), 0)                
                        ELSE 0                
                   END,                
                   dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo1),                
                   NULL       AS MessageStatus,                
                   @SenderID,                
                   GETDATE(),                
                   NULL,                
                   NULL,                
                   (                
                       SELECT TOP 1 ud.SmppID                
                       FROM   User_Detail AS ud                
              WHERE  ud.[User_ID] = @Account                
                   ),                
                   @Account,                
                   @IsUnicode,                
                   0,                
           0,                
                   0,                
                   1,                
                   1,                
           0,                
                   0                
            FROM   UserLeads  AS ue                
            WHERE  ue.ID IN (SELECT [value]                
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                
                   AND ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), '') <                
                       > ''            
                                 
                       AND not exists(select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo1=C_UDTemp.Mobile and UE.CountryCode1 = C_UDTemp.CountryCode))              
                            
                            
                            
                            
                            
                            
                            
                            
                            
                            
                            
            UNION                  
                            
            SELECT @BatchID,                
                   CASE                 
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), 0)                
                        ELSE 0                
                   END,                
                   dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo2),                
                   NULL       AS MessageStatus,                
                   @SenderID,                
                   GETDATE(),                
                   NULL,                
                   NULL,                
                   (                
                       SELECT TOP 1 ud.SmppID                
                       FROM   User_Detail AS ud                
                       WHERE  ud.[User_ID] = @Account                
                   ),                
                   @Account,                
          @IsUnicode,                
                   0,                
                   0,                
                   0,                
                   1,                
                   1,                
                   0,                
                   0                
            FROM   UserLeads  AS ue                
            WHERE  ue.ID IN (SELECT [value]                
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                
                   AND ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), '') <                
                       > ''           
                                 
                        AND not exists(select 1 from  Client_UnSubscribeDetails C_UDTemp where parentid=@parentid and (Ue.MobileNo2=C_UDTemp.Mobile and UE.CountryCode2 = C_UDTemp.CountryCode))                 
        ) A                
 WHERE  A.Mobile <> 0                  
                   
      SELECT 'Record Saved'            
      End            
    Else            
      Begin            
        SELECT 'Insufficient Balance'                
      End                
                  
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_SendSMSWithTemplate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_SendSMSWithTemplate  
(  
 @EntityID VARCHAR(500),  
 @Account BIGINT,  
 @SenderID VARCHAR(50),  
 @Template VARCHAR(2000),  
 @IsUnicode BIT,  
 @Mobile BIT,  
 @mobile1 BIT,  
 @Mobile2 BIT,  
 @EntityType varchar(10)='Enquiry'  
)  
AS  
BEGIN  
 Declare @MailContent nvarchar(max)='', @MailBody nvarchar(max)=''  
   
 If(@EntityType = 'Enquiry')  
 Begin  
  Select  @MailContent=MailContent From UserMailTemplate Where ID=@Template and IsSMS=1
   and
     (
       (IsEnquiry=1) or
	   (
	    ISNULL(IsLeads,0) = 0  and ISNULL(IsEnquiry,0) = 0  and  ISNULL(IsConversion,0) = 0 and  ISNULL(IsList,0) = 0 
	    and  ISNULL(isGroup,0) = 0 and  ISNULL(IsPersonalized,0) = 0 
	   )
	 )  
  
  
  Select @MailBody=replace(replace(replace(replace(replace(replace(replace(@MailContent,'#Companyname#',CompanyName),'#personName#',PersonName),'#Mobile#',MobileNo),'#Email#',EmailID),'#City#',City),'#State#',State),'#Country#',Country)  
  From UserEnquiry  
  Where EnquiryID=@EntityID  
  
  If(isnull(@MailBody,'') != '')  
  Begin  
   Exec usp_IntindSMSFromEnquiry @EntityID, @Account, @SenderID, @MailBody, @IsUnicode, @Mobile, @mobile1, @Mobile2  
  End  
  
 End  
  
 If(@EntityType = 'Lead')  
 Begin  
  Select  @MailContent=MailContent From UserMailTemplate Where ID=@Template and IsSMS=1 
  and
     (
       (IsLeads=1) or
	   (
	    ISNULL(IsLeads,0) = 0  and ISNULL(IsEnquiry,0) = 0  and  ISNULL(IsConversion,0) = 0 and  ISNULL(IsList,0) = 0 
	    and  ISNULL(isGroup,0) = 0 and  ISNULL(IsPersonalized,0) = 0 
	   )
	 )  
  
  Select @MailBody=replace(replace(replace(replace(replace(replace(replace(@MailContent,'#Companyname#',CompanyName),'#personName#',PersonName),'#Mobile#',MobileNo),'#Email#',EmailID),'#City#',City),'#State#',State),'#Country#',Country)  
  From UserLeads  
  Where ID=@EntityID  
  
  If(isnull(@MailBody,'') != '')  
  Begin  
   Exec usp_IntindSMSFromLeads_New1 @EntityID, @Account, @SenderID, @MailBody, @IsUnicode, @Mobile, @mobile1, @Mobile2  
  End  
  
 End  
  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_SendSMSWithTemplate_LongURL]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_SendSMSWithTemplate_LongURL]      
(      
 @EntityID VARCHAR(500),      
 @Account BIGINT,      
 @SenderID VARCHAR(50),      
 @Template VARCHAR(50),      
 @IsUnicode BIT,      
 @Mobile BIT,      
 @mobile1 BIT,      
 @Mobile2 BIT,   
 @Message nvarchar(4000),  
 @EntityType varchar(10)='Enquiry',   
 @LongURL nvarchar(2000) = '',  
 @InvModuleEntity nvarchar(500) = '',  
 @InvModuleEntityId bigint = 0,  
 @UserId bigint  
)      
AS      
BEGIN      
  
--select * from UserMailTemplate where IDENT_CURRENT =   
  
  
-- declare   
--@EntityID VARCHAR(500) = '503819',      
--@Account BIGINT = 34594,      
--@SenderID VARCHAR(50) = 'KITAPP',      
--@Template VARCHAR(2000) = '1707160822091194683',      
--@IsUnicode BIT = 0,      
--@Mobile BIT = 1,      
--@mobile1 BIT = 0,      
--@Mobile2 BIT = 0,   
--@Message = ''  
--@EntityType varchar(10)='Lead',   
--@LongURL nvarchar(2000) = 'http://localhost:55786/UserCRMCampaign/invoice/PDF/Quotation/GeneratorOption.aspx?QuotationId=cTNNbTlqV2pWRlE9',  
--@InvModuleEntity nvarchar(500) = 'quotation',  
--@InvModuleEntityId bigint = 66,  
--@UserId bigint = 34594  
  
 declare @MailContent nvarchar(max)= @Message, @MailBody nvarchar(max)=''      
  
 declare @ParentId bigint = 0, @Username nvarchar(255), @QuotationNumber nvarchar(1000), @QuotationAmount float, @PersonName nvarchar(255)    
 select @Username = User_Login, @ParentId = ParentID from User_Detail(nolock) where User_Id = @UserId   
 declare @retBatchid bigint = 0, @retAppid int, @retSender nvarchar(10)  
  
 print @Template  
  
   Select @IsUnicode  =  IsUnicode From UserMailTemplate Where ID=@Template and IsSMS=1     
  and    
     (    
       (IsLeads=1) or    
    (    
     ISNULL(IsLeads,0) = 0  and ISNULL(IsEnquiry,0) = 0  and  ISNULL(IsConversion,0) = 0 and  ISNULL(IsList,0) = 0     
     and  ISNULL(isGroup,0) = 0 and  ISNULL(IsPersonalized,0) = 0     
    )    
  )      
      
 print @MailContent  
  
 Select @MailBody=replace( replace( replace(  
      replace( replace( replace( replace(  
      @MailContent, '#Companyname#', CompanyName), '#personName#', PersonName),  
      '#Mobile#', MobileNo ),  
      '#Email#', EmailID ),'#City#', City),  
      '#State#', State ),'#Country#', Country)      
      From UserLeads(nolock) Where ID = @EntityID      
     
   print @MailBody  
  
   declare @noofmobile int= (select cast(@Mobile as int)+cast(@Mobile1 as int)+cast(@Mobile2 as int))  
   declare @credits int=@noofmobile*(select case when @isunicode=0 and len(@mailbody)<=160 then 1  
   when @isunicode=1 and len(@mailbody)<=70 then 1  
   when @isunicode=0 and len(@mailbody)>160 then cast(ceiling(len(@mailbody)/cast(157 as float)) as int)  
   when @isunicode=1 and len(@mailbody)>70 then cast(ceiling(len(@mailbody)/cast(63 as float)) as int)  
   end)  
   if @credits<=(select dbo.fn_GetSMSBalance(@UserId))  
   begin  
   If(isnull(@MailBody,'') != '')   
   begin      
   -- exce usp_IntindSMSFromLeads_New1 @EntityID, @Account, @SenderID, @MailBody, @IsUnicode, @Mobile, @mobile1, @Mobile2      
     
     declare  @chkMobileNo nvarchar(50), @chkMobileNo1 nvarchar(50), @chkMobileNo2 nvarchar(50)  
  
     select @PersonName = PersonName, @ParentId = ParentID, @chkMobileNo = MobileNo, @chkMobileNo1 = MobileNo1, @chkMobileNo2 = MobileNo2 from UserLeads(nolock) where Id = @EntityID  
  
     declare @MobileNos nvarchar(255) = '';  
  
     if(@Mobile = 1)  
     begin  
    set @MobileNos = concat(@MobileNos, ', ', @chkMobileNo)  
     end  
  
     if(@mobile1 = 1)  
     begin  
    set @MobileNos = concat(@MobileNos, ', ', @chkMobileNo1)  
     end  
  
     if(@mobile2 = 1)  
     begin  
    set @MobileNos += concat(@chkMobileNo2, ',')  
     end  
  
     exec usp_sendmessagewithTracking_withdlt  
     @u_id  = @UserId,      
     @message  = @MailBody,      
     @mobile  = @MobileNos,      
     @sender  = @SenderID,      
     @isunicode =@IsUnicode,      
     @priority =2,      
     @shorturl ='pel.im',      
     @longurl =@LongUrl,      
     @page_nm =null,      
     @IAction =null,      
     @Cmobile =null,      
     @email =null,      
     @subject =null,      
     @body =null,      
     @wmobile =null,      
     @wtext  =null,      
     @isvoice =null,      
     @appid = null,      
     @duration =null,      
     @dnid = null,      
     @frequency = null,              
     @latency = null,              
     @route = null,        
     @event = null,        
     @dltid = null,            
     @batchid = @retBatchid output   
  
   print @retBatchid  
  
   if(@retBatchid > 0)      
   begin    
    declare @leadActivityHistory as LeadActivitywithid_Tbltype, @RevenueNumber nvarchar(255), @InvoiceNumber nvarchar(255)     
     
    If(@InvModuleEntity = 'quotation')      
    begin   
     select @QuotationNumber = quote_number, @QuotationAmount = amount from MySMSInvoicing.dbo.quotes where id = @InvModuleEntityId  
     declare @quotationMessage nvarchar(max) = 'Quotation Message goes here.' 
     insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )            
      select @EntityID, @UserId, @parentid, concat(@Username, ' sent an sms with content "',  @quotationMessage, '" on mobile ', @MobileNos), 'SMS sent to Lead', 'Batchinfo', @retBatchid  
     exec UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory    
    end  
  
    If(@InvModuleEntity = 'invoice')      
    begin    
     select  @InvoiceNumber = cast(receipt_no as nvarchar),  @QuotationAmount = amount from MySMSInvoicing.dbo.transactions where id = @InvModuleEntityId    
     declare @invoiceMessage nvarchar(max) = 'Invoice Message goes here.' 
  
     declare @invoiceHistoryId bigint = SCOPE_IDENTITY()    
       
     insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )            
      select @EntityID, @UserId, @parentid, concat(@Username, ' sent an sms with content "',  @invoiceMessage, '" on mobile ', @MobileNos), 'SMS sent to Lead', 'Batchinfo', @retBatchid   
     exec UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory    
    end  
  
    if(@InvModuleEntity = 'revenue')  
    begin  
  
     select  @RevenueNumber = cast(receipt_no as nvarchar),  @QuotationAmount = amount from MySMSInvoicing.dbo.transactions where id = @InvModuleEntityId    
  
     declare @revenueMessage nvarchar(max) = 'Revenue Message goes here.'  
     declare @transactionHistoryId bigint = SCOPE_IDENTITY()      
         
     insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )              
     select @EntityID, @UserId, @parentid, concat(@Username, ' sent an sms with content "',  @revenueMessage, '" on mobile ', @MobileNos), 'SMS sent to Lead', 'Batchinfo', @retBatchid      
     
     exec UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory      
    end  
  
    select 'Sms Sent Successfully'  
   end   
  end  
  else  
  begin  
   select 'Message body required'  
  end  
  end  
  else  
  begin  
   select 'Insuffcient Balance'  
  end  
  
  
end   
  


GO

