CREATE   PROC [dbo].[usp_SendSMSWithTemplate_WithCreatedBy]    
(    
 @EntityID VARCHAR(500),    
 @Account BIGINT,    
 @SenderID VARCHAR(50),    
 @Template VARCHAR(2000),    
 @IsUnicode BIT,    
 @Mobile BIT,    
 @mobile1 BIT,    
 @Mobile2 BIT,    
 @EntityType varchar(10)='',
 @CreatedBy bigint    
)    
AS    
BEGIN    
 Declare @MailContent nvarchar(max)='', @MailBody nvarchar(max)=''    
     
     Declare @ParentAccount bigint = ( select top 1 ParentID from User_Detail with(nolock) where User_ID = @Account )     

 If(@EntityType = 'Enquiry')    
 Begin    
  Select  @MailContent=MailContent From UserMailTemplate (nolock) Where ID=@Template and IsSMS=1  
   and  
     (  
       (IsEnquiry=1) or  
    (  
     ISNULL(IsLeads,0) = 0  and ISNULL(IsEnquiry,0) = 0  and  ISNULL(IsConversion,0) = 0 and  ISNULL(IsList,0) = 0   
     and  ISNULL(isGroup,0) = 0 and  ISNULL(IsPersonalized,0) = 0   
    )  
  )    
    
    
  Select @MailBody=replace(replace(replace(replace(replace(replace(replace(@MailContent,'#Companyname#',CompanyName),'#personName#',PersonName),'#Mobile#',MobileNo),'#Email#',EmailID),'#City#',City),'#State#',State),'#Country#',Country)    
  From UserEnquiry (nolock)   
  Where EnquiryID=@EntityID    
    
  If(isnull(@MailBody,'') != '')    
  Begin    
   --Exec usp_IntindSMSFromEnquiry @EntityID, @Account, @SenderID, @MailBody, @IsUnicode, @Mobile, @mobile1, @Mobile2   
     --Exec usp_IntindSMSFromEnquiry_WithCreatedBy @EntityID, @Account, @SenderID, @MailBody, @IsUnicode, @Mobile, @mobile1, @Mobile2,@CreatedBy 
	Exec usp_IntindSMSFromEnquiry_WithDLTTemplateID @EntityID, @Account, @SenderID, @MailBody, @IsUnicode, @Mobile, @mobile1, @Mobile2,@CreatedBy
  End    
    
 End    
    
 If(@EntityType = 'Lead')    
 Begin    
  Select  @MailContent=MailContent From UserMailTemplate (nolock) Where ID=@Template and IsSMS=1   
  and  
     (  
       (IsLeads=1) or  
    (  
     ISNULL(IsLeads,0) = 0  and ISNULL(IsEnquiry,0) = 0  and  ISNULL(IsConversion,0) = 0 and  ISNULL(IsList,0) = 0   
     and  ISNULL(isGroup,0) = 0 and  ISNULL(IsPersonalized,0) = 0   
    )  
  )    
    
  Select @MailBody=replace(replace(replace(replace(replace(replace(replace(@MailContent,'#Companyname#',CompanyName),'#personName#',PersonName),'#Mobile#',MobileNo),'#Email#',EmailID),'#City#',City),'#State#',State),'#Country#',Country)    
  From UserLeads (nolock)   
  Where ID=@EntityID    
    
  If(isnull(@MailBody,'') != '')    
  Begin    
   --Exec usp_IntindSMSFromLeads_New1 @EntityID, @Account, @SenderID, @MailBody, @IsUnicode, @Mobile, @mobile1, @Mobile2    

   Exec usp_IntindSMSFromLeads_New1_WithDLTTemplateID_new12 @EntityID, @Account, @SenderID, @MailBody, @IsUnicode, @Mobile, @mobile1, @Mobile2, @CreatedBy
  End    
    
 End    
    
END    




