/* ============================================================
   Procedure: [dbo].[usp_sendtrackleadnotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

              
/****** Script for SelectTopNRows command from SSMS  ******/                  
CREATE  PROCEDURE [dbo].[usp_sendtrackleadnotification] --796822--460695--460691--1--128028 --27                  
@trackid bigint                  
as                  
begin                  
select * into #t from Link_smsTrack where trackid=@trackid                
declare @a int=0                
declare @longurl nvarchar(500),@mobile nvarchar(20),@parentid bigint,@bbatchid bigint                
select @longurl=long_url,@mobile=Mobile,@parentid=Parentid from #t               
select @bbatchid=b.batchid from #t l join Link_smsMobile ls               
on l.link_id=ls.mobile_url_id join Link_smsUrl_dtl b on b.BatchId=ls.batchid               
where trackid=@trackid order by trackid desc          
/*        
Code to be made live after account set up compltion        
*/        
if @longurl like '%kit19.com/accountsetup.aspx%' or @longurl like '%kit19.com/setupprogress.aspx%' or @longurl like '%kit19.com/signup.aspx?uniqueid=%'        
begin        
declare @event nvarchar(500)=(select setupstage from usersetupstages u where BatchID=@bbatchid)        
,@uniqueid nvarchar(100)=(select case when charindex('uniqueid=',@longurl,1)>0 then right(@longurl,len(@longurl)-charindex('uniqueid=',@longurl,1)-9) end)         
if @uniqueid is null        
begin        
insert into usersetupstages(Enqno,kit19user_id,StageType,SetUpStage,StageDate,CreatedOn,StageStatus)        
select Enqno,kit19user_id,'UserResponse',SetUpStage,GETDATE(),GETDATE(),'Completed' from usersetupstages where batchid=@bbatchid        
end        
else        
begin        
insert into TrackSignUp(Userid,enqno,activity,mobile,uniqueid)        
select top 1 userid,enqno,'User clicked on Sign Up Link',mobile,uniqueid from TrackSignUp where uniqueid=@uniqueid         
and mobile=@mobile and activity='Sign Up Link sent'        
order by id desc        
end        
CREATE TABLE #TempLinked                        
 (                        
  Result VARCHAR(50)                        
 )       
 /* Code commented since crm is offline during lockdown        
 INSERT INTO #TempLinked                        
 EXEC GetStatusofLinkedServer 'CRM'          
 if not exists(select 1 from #templinked)        
 begin        
 if @uniqueid is null        
begin        
 insert into CRM.CRMDB.dbo.usersetupstages(Enqno,kit19user_id,StageType,SetUpStage,StageDate,CreatedOn,StageStatus)        
 select Enqno,kit19user_id,'UserResponse',SetUpStage,GETDATE(),GETDATE(),'Completed' from usersetupstages where batchid=@bbatchid        
 end        
 else        
begin        
insert into CRM.CRMDB.dbo.TrackSignUp(Userid,enqno,activity,mobile,uniqueid)        
select top 1 userid,enqno,'User clicked on Sign Up Link',mobile,uniqueid from CRM.CRMDB.dbo.TrackSignUp where uniqueid=@uniqueid         
and mobile=@mobile and activity='Sign Up Link sent'        
order by id desc        
end        
end        
*/      
end       
--*/            
declare @sentdate datetime,@bmessage nvarchar(2000)            
select @sentdate=isnull(nullif(scheduleddate,''),BatchInsertTime) ,@bmessage=bmessage from             
batchinfo(nolock) where batchid=@bbatchid            
if exists (select 1 from Link_smsUrl_dtl where BatchId=@bbatchid and isvoice=1)              
begin              
declare @appid bigint,@route nvarchar(20),@dnid nvarchar(20),@duration int,@latency datetime,@frequency int              
select top 1 @appid=appid,@route=isnull(route,'trans'),@dnid=dnid,@duration=duration,@latency=DATEADD(mi,latency,getdate()),@frequency=frequency from Link_smsUrl_dtl where BatchId=@bbatchid              
if @frequency=0            
begin            
if (select min(trackid) from Link_smsTrack l join Link_smsMobile ls               
on l.link_id=ls.mobile_url_id join Link_smsUrl_dtl b on b.BatchId=ls.batchid               
where l.Mobile=@mobile and long_url=@longurl and b.BatchId=@bbatchid)=@trackid            
begin            
--select 1
print 'Entered Voice call'
exec usp_insertnewcallForBroadcast_withoutid @parentid,@route,@mobile,@appid,@dnid,@duration,@latency              
end            
end            
else            
begin      
print 'Entered Voice call'
exec usp_insertnewcallForBroadcast_withoutid @parentid,@route,@mobile,@appid,@dnid,@duration,@latency              
end            
end                
/*if @longurl like '%kit19.com/ivr%' and (select min(trackid) from Link_smsTrack where Mobile=@mobile and long_url like '%kit19.com/ivr%')=@trackid                
begin                
exec usp_insertnewcallForBroadcast @parentid,'trans',@mobile,697,'1204862882',120,null                
end                
if @longurl like '%kit19.com/erosnew%' and (select min(trackid) from Link_smsTrack where Mobile=@mobile and long_url like '%kit19.com/erosnew%')=@trackid                
begin                
exec usp_insertnewcallForBroadcast @parentid,'trans',@mobile,699,'1204862870',120,null                
end                
*/                
WAITFOR DELAY '00:00:00.10' -- Wait for 10 ms                
begin tran     
select top 1 @a=1 from #t t join Link_smsTrack(nolock)l on t.mobile=l.mobile and t.link_id=l.link_id and t.long_url=l.long_url and t.parentid=l.parentid and t.ipAddress=l.ipAddress and datediff(mi,l.visitdate,t.visitdate)<5 and l.trackid<>t.trackid       
        
commit                
if isnull(@a,0)=0   
begin                
declare @pid bigint=(select parentid from Link_smsTrack(nolock) where trackid=@trackid) ,@company nvarchar(100),@email nvarchar(250)                
select @email=email,@company =CompnayName from user_detail(nolock) where user_id=@pid                  
declare @sender nvarchar(250)=isnull((select top 1 mail_id from DefaultMailID where user_id=335 order by ID desc),'updates@kit19.com'),@email2 nvarchar(250)='shruti.m1989@gmail.com'                  
                  
declare @batchid bigint                  
declare @message nvarchar(max),@subject nvarchar(100)                  
select top 1 @subject= 'You have got a new Lead ' + case when @company is not null then 'for ' + @company + ''  else ''  end +                 
' from Mobile '+ Mobile,@message='Hi there ! Just wanted to let you know that a   
user just visited your link ' + Long_Url + ' on ' +                 
