select @bbatchid=b.batchid from #t l join Link_smsMobile ls             
on l.link_id=ls.mobile_url_id join Link_smsUrl_dtl b on b.BatchId=ls.batchid             
where trackid=@trackid order by trackid desc        
/*      
Code to be made live after account set up compltion      
*/      
if @longurl like '%kit19.com/accountsetup.aspx%' or @longurl like '%kit19.com/setupprogress.aspx%' or @longurl like '%kit19.com/signup.aspx?uniqueid=%'      
begin      
declare @event nvarchar(500)=(select setupstage from usersetupstages u where BatchID=@bbatchid)      
,@uniqueid nvarchar(100)=(select case when charindex('uniqueid=',@longurl,1)>0 then right(@longurl,len(@longurl)-charindex('uniqueid=',@longurl,1)-9) end)       
if @uniqueid is null      
begin      
insert into usersetupstages(Enqno,kit19user_id,StageType,SetUpStage,StageDate,CreatedOn,StageStatus)      
select Enqno,kit19user_id,'UserResponse',SetUpStage,GETDATE(),GETDATE(),'Completed' from usersetupstages where batchid=@bbatchid      
end      
else      
begin      
