/* ============================================================
   Procedure: [dbo].[usp_sendtransactionalmessagereport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_sendtransactionalmessagereport] 
as 
begin 
--select * into #t from [MySMStrans].[dbo].messagedeliverystatustemp mdt with (nolock) 
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX),@TotalCusSent bigint,@TotalSentbyus bigint 
;with cte as(SELECT [UserID],user_login,bi.[BatchID],[TotalRecords],right(convert(nvarchar,[BatchInsertTime],100),7)Time, 
MDT.MESSAGE,u.filtermode as OriginalFilterMode,isnull(BI.filterMode,'0')filterMode,BI.userfilter userfilter, 
ROW_NUMBER()OVER (PARTITION BY BI.BatchID Order By BI.BatchID)AS NUMBER,(bi.FilterMode*totalrecords)/10 as Sent 
FROM [MySMS].[dbo].[BatchInfo] BI(nolock) 
--join [MySMStrans].[dbo].messagedeliverystatustemp mdt with (nolock) on bi.batchid=mdt.batchid 
join [MySMS].[dbo].messagedeliverystatustemp mdt with (nolock) on bi.batchid=mdt.batchid 
join [MySMS].[dbo].user_detail u (nolock) on u.user_id=bi.userid 
where datediff(d,batchinserttime,getdate())=0 and isprocess=1 
and bi.dbtype=7) 
select * into #temp2 from cte where number=1 
select @TotalCusSent=SUM(totalrecords),@TotalSentbyus=SUM(sent) from #temp2 
 
SET @xml =CAST(( SELECT [UserID] AS 'td','',[User_Login] AS 'td','',[BatchID] AS 'td','', 
[TotalRecords] AS 'td','',Time as 'td','',Message AS 'td','',[OriginalFilterMode] AS 'td','',[filterMode] as 'td','',userfilter from #temp2 where NUMBER=1 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX)) 
SET @body ='<html><H1>Transactional Messages Monitor '+cast (getdate() as nvarchar)+ ' Sent by Customer: ' + CAST(@totalcussent as nvarchar) + '||Sent by us: '+CAST(@totalsentbyus as nvarchar) +'</H1><body><table border = 2><tr><th>User ID</th><th>User Lo
gin</th><th>Batch ID</th><th>Total</th><th>Time</th><th>Message Text</th><th>Original Filtermode</th><th>FilterMode</th><th>Route</th></tr>' 
SET @body = @body + @xml +'</table></body></html>' 
EXEC usp_enqueueemail 
@profile_name='Alerts', 
@recipients='csshukla@pelsoftlabs.in', 
@blind_copy_recipients='karuna@pelsoftlabs.in', 
@subject='Transactional Messages Monitor', 
@body = @body, 
@body_format ='HTML' 
drop table #temp2 
--drop table #t 
end




GO

/* ============================================================
   Procedure: [dbo].[USP_SendUnicodeSMS]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC USP_SendUnicodeSMS   -- 'MessageQueue'    
@tablename varchar(100)     
as    
declare @temptable Table    
(    
MessageQueueID bigint,    
MessageID bigint,    
Mobile char(20),    
Message nvarchar(2500),    
SenderID nchar(20),    
SmppID tinyint,    
MessageInsertDate datetime,    
Priority tinyint,    
U_ID int,    
BatchID bigint,    
Operator char(6)    
);    
Declare @query varchar(max)    
Declare @query2 varchar(max)    
    
set @query='select top(50) MessageQueueID,MessageID,Mobile, Message, SenderID,SmppID, MessageInsertDate,Priority,U_ID, BatchID, Operator from '+@tablename+' where isunicode=1'    
insert into @temptable    
exec (@query)    
if @tablename='MessageQueueAirtel'    
    
BEGIN    
delete T1 from   MessageQueueAirtel  T1 join @temptable T2 on T1.MessageQueueID=T2.MessageQueueID    
END    
else IF  @tablename='MessageQueueAirtelDirect'    
BEGIN    
delete T1 from   MessageQueueAirtelDirect  T1 join @temptable T2 on T1.MessageQueueID=T2.MessageQueueID    
END    
else IF  @tablename='MessageQueueAirtelPri'    
BEGIN    
delete T1 from   MessageQueueAirtelPri  T1 join @temptable T2 on T1.MessageQueueID=T2.MessageQueueID    
END    
else IF  @tablename='MessageQueueAirtelTwo'    
BEGIN    
delete T1 from   MessageQueueAirtelTwo  T1 join @temptable T2 on T1.MessageQueueID=T2.MessageQueueID    
END    
else IF  @tablename='MessageQueueFour'    
BEGIN    
delete T1 from   MessageQueueFour  T1 join @temptable T2 on T1.MessageQueueID=T2.MessageQueueID    
END    
else IF  @tablename='MessageQueueThree'    
BEGIN    
delete T1 from   MessageQueueThree  T1 join @temptable T2 on T1.MessageQueueID=T2.MessageQueueID    
END    
else IF  @tablename='MessageQueueVoda'    
BEGIN    
delete T1 from   MessageQueueVoda  T1 join @temptable T2 on T1.MessageQueueID=T2.MessageQueueID    
END    
else IF  @tablename='MessageQueue'    
BEGIN    
delete T1 from   MessageQueue  T1 join @temptable T2 on T1.MessageQueueID=T2.MessageQueueID    
END    
    
    
    
set @query2=''    
print @query2    
execute (@query2)    
select * from @temptable    
    
    
    
    
    
    
    
    
    


GO

