/* ============================================================
   Procedure: [dbo].[usp_sendusagereportalert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_sendusagereportalert]          
as          
begin          
select distinct p.UserID           
into #users           
from Price_UserSubscriptionDetails (nolock) p    
join user_detail ud on p.[UserID]=ud.user_id              
join userreport r on p.[UserID]=r.user_id              
where ud.User_ID=ud.ParentID  and str(mobile)<>'0'              
and IsNewPlan=1 and PlanEndDate>=cast(getdate() as date) --and userid=17626          
--select * from #users          
declare @users nvarchar(max)          
select @users=coalesce(cast(@users as nvarchar(max))+',','')+cast(userid as nvarchar(max)) from #users          
          
DECLARE @BatchID BIGINT                      
begin tran                      
 INSERT INTO GetBatchRecord                        
   (                        
     [User_id],                        
     RandNum                        
   )                        
 VALUES                        
   (                        
     335,                        
     335                        
   )                        
  select @BatchID=SCOPE_IDENTITY()                        
 DELETE                         
 FROM   GetBatchRecord                        
 WHERE  BatchID=@BatchID                      
 commit                      
          
exec usp_getshorturl @users,@batchid          
  
insert into DLT_Template_MSG(BatchID,DLT_TemplateID)  
select @BatchID,'1707161806613841759'  
          
          
INSERT INTO CloneMessageDeliveryStatus                        
   (                        
     -- MessageID -- this column value is auto-generated                        
     BatchID,                        
     Mobile,                
     [Message],                        
     MessageStatus,                        
     SenderID,                        
     MessageInsertDate,                        
     ScheduledDate,                        
     ScheduledTime,                        
 SmppID,                        
     U_ID,                        
     IsUniCode,                        
     IsDnd,                        
     IsAirtel,                        
     MobileSubSet,                        
     ValidNo,                        
     IsPrority,                        
     IsAllowDND,                        
     DBType                        
   )                        
             
 SELECT A.BatchID,                        
        A.Mobile,                        
        A.Messagetext,                        
        A.MessageStatus,                        
        A.SenderID,                        
        A.MessageInsertDate,                        
        isnull(A.ScheduledDate,''),                        
        isnull(A.ScheduledTime,''),                        
        A.SmppID,                        
        A.U_ID,                        
        A.IsUnicode,                        
        A.IsDnd,                        
        A.IsAirtel,                        
        A.MobileSubSet,                        
        A.ValidNo,                        
        A.IsPrority,                        
        A.IsAllowDND,                        
        A.DBType                        
 FROM   ( SELECT @batchid AS BatchID,                        
 str(Mobile) Mobile,     
'Dear User, You can view your account usage till date at kit19.com here : '+'kit19.com/UserCRMCampaign/Report/UsageReport.aspx?id='+cast(a.UserID as nvarchar(100))           
+'&authid='+cast(u.id as nvarchar(100))+' & user work report here: '+          
'kit19.com/UserCRMCampaign/Report/UserActivityReport.aspx?id='+cast(r.id as nvarchar(100))+'&authid='+cast(r.authid as nvarchar(100))          
 +' - Team Kit19. Need Help? Reach us at +917840049991'                      
 AS Messagetext,                        
NULL         AS MessageStatus,                        
'KITAPP'    AS SenderID,                        
GETDATE()    AS MessageInsertDate,                        
 NULL         AS ScheduledDate,                        
NULL         AS ScheduledTime,                  
u.SmppID ,                        
335     AS U_ID,                        
0   AS IsUnicode,                        
0            AS IsDnd,                        
0            AS IsAirtel,                        
0            AS MobileSubSet,                   
1            AS ValidNo,                        
1            AS IsPrority,                        
0            AS IsAllowDND,                        
0            AS DBType                        
FROM #users a                      
  join user_detail u on a.UserID=u.user_id          
  join userreport r on r.user_id=u.User_ID
  where u.m_id=10043
  ) A           
 WHERE cast(A.Mobile as nvarchar) <> '' and cast(A.Mobile as nvarchar) not in ('8368509853')              
 and A.messagetext is not null                   
          
 drop table #users          
end


