/* ============================================================
   Procedure: [dbo].[usp_serv_parentuser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_serv_parentuser] --17626,'www.kit19.com'    
(    
@user_id bigint,      
@url nvarchar(500)    
--@webpage nvarchar(500)      
--@Ticketsubject nvarchar(500),      
--@Ticketdescription nvarchar(max)    
)      
as      
begin      
    
declare @parentid bigint = 0    
if exists(select 1 from reseller_detail r where domain=@url and r.user_id=@user_id and user_id in (select USER_ID from user_detail where TYPE=1 ) )      
begin      
Declare @Immediatereseller bigint=(select r.user_id from reseller_detail r join user_detail      
u on r.Reseller_ID=u.M_ID where u.USER_ID=@user_id and u.Type=1)      
set @parentid =(select parentid from user_detail where USER_ID=@Immediatereseller)      
end    
else    
begin    
set @parentid  =(select top 1 r.USER_ID from reseller_detail r where Domain=@url and user_id in (select USER_ID from user_detail where TYPE=1)  order by Reseller_ID desc)     
end    
 select @parentid asParentid    
end




