/* ============================================================
   Procedure: [dbo].[Usp_SessionStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SessionStatus @User_id BIGINT
	,@mac_address VARCHAR(100) = ''
	,@ip_adress VARCHAR(100) = ''
	,@device_id VARCHAR(500) = ''
	,@mode VARCHAR(20) = ''
	,@token VARCHAR(max) = ''
AS
BEGIN
	DECLARE @old_ip_address VARCHAR(100) = ''
		,@spid INT = 0

	IF @mode = 'SYNC'
	BEGIN
		SELECT @old_ip_address = ip_adress
			,@spid = sp_id
		FROM tbl_loginlookup
		WHERE User_id = @user_id
			AND mac_address = @mac_address
			AND token = @token
			AND device_id = @device_id

		IF @spid <> @@SPID
		BEGIN
			UPDATE tbl_loginlookup
			SET sp_id = @@SPID
				,Modified_Date = GETDATE()
			WHERE User_id = @user_id
				AND mac_address = @mac_address
				AND token = @token

			SELECT @@spid
		END

		IF @old_ip_address <> @ip_adress
		BEGIN
			UPDATE tbl_loginlookup
			SET ip_adress = @ip_adress
				,Modified_Date = GETDATE()
			WHERE User_id = @user_id
				AND mac_address = @mac_address
				AND token = @token
		END
	END
END



GO

