CREATE   PROC [dbo].[Usp_SetAllPriority]                      
@UserID int ,-- frm varchtr 19-08-2010                                              
@SenderID varchar(20),                                 
@Mobile varchar(12),                                              
@FromDate varchar(20),                          
@ToDate varchar(30),                                            
@table varchar(100),                                
@priority int,                                        
@FromTime varchar(20),                              
@ToTime varchar(20),                    
@Setpriority int                              
as                                        
Begin                                      
Begin Try                                                
Declare @MessageQueue varchar(8000)  
