    Else                                                                                                                      
    Begin              
     Set @whereClause = @whereClause + ' Priority = '+ cast(@priority As varchar(3)) + ' and '                             
    End                                                            
      
    If @UserID=''                      
    Begin                                                                      
    Set @whereClause =@whereClause+' 1=1 and '                                                                                                                      
    End                                                                                                                      
    Else                         
    Begin                                                                        
    Set @whereClause = @whereClause+ ' U_ID = '''+@UserID+'''  and '                                                                                                                      
    End                                                                                 
                                                                
    If @SenderID = ''                                                                   
    Begin                                                                      
    Set @whereClause =@whereClause+' 1=1 and '                                                         
    End                                                                                                                      
    Else                                                                                                 
    Begin                                                 
    Set @whereClause = @whereClause+ ' SenderID = '''+@SenderID+''' and '                                                    
    End                                                  
                                                
    If @Mobile = ''                                          
    Begin                                                                      
    Set @whereClause =@whereClause+' 1=1 And '                                                 
    End                                                                                                                 
    Else                                                                                                                      
 Begin                                                      
    Set @whereClause = @whereClause+ ' Mobile like ''%'+@Mobile+'%'' and '                                                    
    End                                                  
                                                
                                              
    If (@FromDate !='')                                                                                  
    Begin                                                                                   
