   End                                                                                  
     Else          
     Begin                                                                                  
     Set @whereClause =@whereClause +  ' 1=1 '                                                
  End                       
                    
                    
   --print (@whereClause)                                         
--begin try                    
                     
--[Usp_SetAllPriority]  '','','','','','MessageQueue','-1','','','1'                                                             
--select * from MessageQueue                    
