 exec(@MessageQueueAirtel)              
exec(@MoveAirtel)        
              
End             
                                 
if((@table='MessageQueueAirtelTwo')  or (@table='A2'))                                 
begin                                  
 exec(@AirtelTwo)                    
exec(@MoveAirtelTwo)        
        
End             
 if((@table='MessageQueueAirtelThree') or (@table='A3'))                                  
begin                                  
 exec(@AirtelThree)                    
exec(@MoveAirtelThree)        
        
        
End             
if((@table='MessageQueueAirtelPri') or (@table='AP'))                                  
begin                                  
 exec(@AirtelPri)           
EXEC USP_PRIORITY_TO_NORMAL      
               
End                                  
 if((@table='MessageSource') or (@table='MS'))                                     
begin                                  
 exec(@MessageSource)                                      
End                                  
                                  
 if((@table='MessageStopped') or (@table='MSD'))                                  
begin                                  
exec(@MessageStopped)                                      
End                        
END Try                                      
Begin Catch                                      
if @@trancount>0                                      
Rollback                                      
End Catch                                        
END 




GO

/* ============================================================
   Procedure: [dbo].[usp_SetDashboardAsDefault]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_SetDashboardAsDefault 32222, 9
CREATE   PROC dbo.usp_SetDashboardAsDefault (
	@UserId BIGINT
	,@DashboardId BIGINT
	)
AS
BEGIN
	DECLARE @ParentId BIGINT = 0

	SELECT @ParentId = ParentID
	FROM User_Detail(NOLOCK)
	WHERE USER_ID = @UserId

	IF (@ParentId = @UserId)
	BEGIN
		UPDATE tbl_Dashboard
		SET IsDefault = (
				CASE 
					WHEN DashboardId = @DashboardId
						THEN 1
					ELSE 0
					END
				)
		WHERE ParentId = @ParentId
	END
	ELSE
	BEGIN
		UPDATE tbl_DashboardUserMapping
		SET IsDefault = (
				CASE 
					WHEN DashboardId = @DashboardId
						THEN 1
					ELSE 0
					END
				)
		WHERE UserId = @UserId
	END

	SELECT @@ROWCOUNT

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM tbl_Dashboard
			WHERE DashboardId = @DashboardId
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'Updt_Dsbrd_sts'
		,@ActionType = 'U'
		,@RowJson = @rowJson
		,@Table_name = 'tbl_Dashboard'
END



GO

