/* ============================================================
   Procedure: [dbo].[usp_setobdprice]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--select top 10 * from tbl_obd_Base_Price
CREATE   PROCEDURE usp_setobdprice
@parentid bigint,@price numeric(18,4),@pulse int=null
as
begin
set @pulse=coalesce(@pulse,(select top 1 pulse_sec from tbl_obd_Base_Price(nolock) where parentid=0 order by id ),30)
declare @oldprice numeric(18,4)
if exists(select 1 from tbl_obd_Base_Price(nolock) where parentid=@parentid)
begin
select top 1 @oldprice=price from tbl_obd_Base_Price(nolock) where parentid=@parentid order by lastmodified desc
update tbl_obd_Base_Price set price=@price ,lastmodified=getdate(),pulse_sec=@pulse where parentid=@parentid
select 'Price updated from '+cast(@oldprice as nvarchar)+ ' to '+cast(@price as nvarchar)+ ' successfully.'
end
else
begin
insert into tbl_obd_Base_Price(dnid,pulse_sec,price,createdon,parentid,lastmodified)
select top 1 dnid,@pulse,@price,getdate(),@parentid,getdate() from tbl_obd_Base_Price(nolock) where parentid=0 order by id
select 'Price set as '+cast(@price as nvarchar)+ ' successfully.'

end
end


GO

