   Procedure: [dbo].[Usp_SetOldNoOfDaysData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SetOldNoOfDaysData  
(  
   @IsGetOLdData bit,  
   @OldNoOfDays int,    
   @IndiaMartID nvarchar(200),  
   @ParentID bigint  
)  
as  
Begin  
      if(@IsGetOLdData = 1)  
      Begin  
      update IndiamartMapping set LastDateFetched = GETDATE() - @OldNoOfDays, GetOLDData = @IsGetOLdData  
          ,OldNoOfDays = @OldNoOfDays  where IndiamartId = @IndiaMartID  
       -- and Kit19ParentId = @ParentID    
      select 'Setting Saved And Applied'   
   End  
        else  
   Begin  
        update IndiamartMapping set  GetOLDData = @IsGetOLdData  
          ,OldNoOfDays = @OldNoOfDays  where IndiamartId = @IndiaMartID   
       --and Kit19ParentId = @ParentID    
      select 'Setting Saved But Not Applied'  
   end  
       
End


GO

