/* ============================================================
   Procedure: [dbo].[Usp_SetStatus_AdRequest]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SetStatus_AdRequest  
(  
  @Status nvarchar(500),  
  @RequestID bigint,  
  @Url nvarchar(max),  
  @Remarks nvarchar(max),  
  @UserID bigint  
   
)  
as  
Begin  
         
  if(@Status = 'Completed' )  
   Begin  
     
     Declare @TypeID bigint = 0  
     Declare @ParentID_Page bigint = 0     
     Declare @PageRequestID bigint = 0  
     Declare @ParentID bigint = 0
	 
	 select  @ParentID = isnull(ParentID,0) from User_Detail where User_ID = @UserID  
      

  
  select @PageRequestID = isnull(PageID,0)  from AdRequests where id = @RequestID   
     
    select @TypeID = isnull(TypeID,0), @ParentID_Page = isnull(ParentID,0) from PageRequests where ID = @PageRequestID   
     
	 if(not exists(select 1 from DigitalMarketingEntities where PageRequestID = @PageRequestID))
	   Begin
	        if(rtrim(ltrim(@Url)) <> '')
			   Begin
			    insert into DigitalMarketingEntities
				  (PageRequestID,TypeID,URL,CreatedOn,ParentID,CreatedBy)
				 values
				  (@PageRequestID,@TypeID,@Url,GETDATE(),@ParentID,@UserID)   
			   end
	   End
     else 
	   Begin
	     if(rtrim(ltrim(@Url)) <> '')
		   Begin
		    update DigitalMarketingEntities set URL = @Url where PageRequestID = @PageRequestID 
		   End 
	   End    

    -- update DigitalMarketingEntities set url = @url   
    --  where TypeID =  @TypeID and parentID = @ParentID_Page  
  
        
   insert into AdRequestHistory  
   (  
     RequestID,  
     URL,  
     AssignedTo,  
     Status,  
     ScheduledDays,  
     StartDate,  
     EndDate,  
     CreatedOn,  
     CreatedBy  
   )  
  
  select top 1  
    
   @RequestID,   
   @URL,  
   AssignedTo,  
   @Status,  
   ScheduledDays,  
   StartDate,  
   EndDate,  
   getdate(),  
   @UserID  
     
   from AdRequestHistory where RequestID = @RequestID order by id desc   
     
  
   End  
 else  
   Begin  
       insert into AdRequestHistory  
   (  
     RequestID,  
     URL,  
     AssignedTo,  
     Status,  
     ScheduledDays,  
     StartDate,  
     EndDate,  
     CreatedOn,  
     CreatedBy  
   )  
  
  select top 1  
   @RequestID,   
   URL,  
   AssignedTo,  
   @Status,  
   ScheduledDays,  
   StartDate,  
   EndDate,  
   getdate(),  
   @UserID  
   from AdRequestHistory where RequestID = @RequestID order by id desc   
  
   End  
  
    --RequestType = @status  
  
   update AdRequests set Remarks = @Remarks where id = @RequestID  
  
  
   select 'Record saved'  
  
End


GO

