     else   
    Begin  
      if(rtrim(ltrim(@Url)) <> '')  
     Begin  
      update DigitalMarketingEntities set URL = @Url where PageRequestID = @RequestID   
     End   
    End      
      
          
    insert into PageRequestHistory    
    (    
     RequestID,    
     AssignedTo,    
     Status,    
     CreatedOn,    
     CreatedBy,
	 AgentName    
    )    
  select top 1    
   @RequestID,     
   AssignedTo,    
   @Status,    
   getdate(),    
   @UserID,
   @AgentName    
   from PageRequestHistory where RequestID = @RequestID order by id desc     
     End    
  else    
   Begin    
    insert into PageRequestHistory    
    (    
     RequestID,    
     AssignedTo,    
     Status,    
     CreatedOn,    
     CreatedBy,
	 AgentName    
    )    
  select top 1    
   @RequestID,     
   AssignedTo,    
   @Status,    
   getdate(),    
   @UserID,
   @AgentName    
   from PageRequestHistory where RequestID = @RequestID order by id desc     
       
   End    
    
   update PageRequests set Status = @Status,Remarks = @Remarks where ID = @RequestID    
    
    
    
   select 'Record saved'    
    
End


