CREATE   PROCEDURE dbo.usp_SetStatusFromMailID (
	@mid BIGINT
	,@uid INT
	,@MailID NVARCHAR(200)
	,@status INT
	)
AS
BEGIN
	
	UPDATE FromMailIDDetails
	SET STATUS = @status
	WHERE Mail_ID = @MailID
		AND M_ID = @mid
		AND USER_ID = @uid

	SELECT 'Record Updated'

	IF @status=3
	BEGIN
	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM FromMailIDDetails WITH(NOLOCK)
			WHERE Mail_ID = @MailID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)
	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @uid
		,@Activity_type = 'Update_Mailid_sntaprl'
		,@ActionType = 'U'
		,@RowJson = @rowJson
		,@Table_name = 'FromMailIDDetails'
	END
END



