/* ============================================================
   Procedure: [dbo].[usp_sftp_cloudplayfileupload]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- =============================================
-- Stored Procedure: usp_sftp_cloudplayfileupload
-- Description: Handles all database operations for cloud playfile upload process
-- =============================================
CREATE   PROCEDURE [dbo].[usp_sftp_cloudplayfileupload]
    @Mode VARCHAR(50),
    @Id INT = NULL,
    @ClientId VARCHAR(100) = NULL,
    @ErrorMessage VARCHAR(MAX) = NULL,
    @FileUrl VARCHAR(MAX) = NULL,
    @MohUploaded VARCHAR(1) = NULL
AS
BEGIN
    SET NOCOUNT ON;
   
    -- Mode 1: GET_NEXT_FILE - Get next file to upload
    IF @Mode = 'GET_NEXT_FILE'
    BEGIN
        SELECT TOP 1
            id,
            clientid,
            name,
            r_url,
            rectype,
            vtext,
            ismoh,
            mohfileuploaded,
            fileuploaded
        FROM cloud_playfile WITH (NOLOCK)
        WHERE 
        status in ('P','U')
            AND (ISNULL(fileuploaded, 'N') = 'N' OR (ismoh='1' AND ISNULL(mohfileuploaded, 'N') = 'N'))
            AND (rectype = 'UTS' OR (rectype = 'TTS' AND ISNULL(filerecorded, 'N') = 'Y'))
            AND error IS NULL
        ORDER BY ISNULL(Priority, 0) DESC, ISNULL(lastaccesstime, GETDATE()) DESC;
    END
   
    -- Mode 2: UPDATE_ACCESS_TIME - Update last access time
    ELSE IF @Mode = 'UPDATE_ACCESS_TIME'
    BEGIN
        UPDATE cloud_playfile
        SET lastaccesstime = GETDATE()
        WHERE id = @Id;
    END
   
    -- Mode 3: UPDATE_ERROR - Update error message
    ELSE IF @Mode = 'UPDATE_ERROR'
    BEGIN
        UPDATE cloud_playfile
        SET lastaccesstime = GETDATE(),
            error = @ErrorMessage
        WHERE id = @Id;
    END
   
    -- Mode 4: UPDATE_UPLOAD_SUCCESS - Mark file as uploaded successfully
    ELSE IF @Mode = 'UPDATE_UPLOAD_SUCCESS'
    BEGIN
        UPDATE cloud_playfile
        SET status = 'S',
            fileuploaded = 'Y',
            mohfileuploaded = @MohUploaded
        WHERE id = @Id;
       
        -- Update Cloud_audio_master table
        UPDATE Cloud_audio_master
        SET active = 1
        WHERE user_id = @ClientId
            AND path = @FileUrl;
    END
   
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_ShowDndDescription]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/**********************      
Alter by Abhishek      
**********************/      
CREATE   PROC Usp_ShowDndDescription  --'','','','',1,0                       
@userid nvarchar(100),                        
@senderid varchar(20),                        
@date varchar(20)  ,                      
@todate varchar(20),                      
@option int,              
@allowNotAllow  char(2)                     
as                        
begin                        
declare @whereclause varchar (1000)                        
DECLARE @Sql VARCHAR(8000)                        
if @option='1'                      
BEGIN                      
set @whereclause=' where '                        
                        
if(@userid='')                        
Begin                        
set @whereclause=@whereclause+' 1=1 and '                      
End                      
else                      
begin                      
set @whereclause=@whereclause+' userid='''+convert(nvarchar,@userid)+''' and '                        
end                      
if(@senderid='')                      
Begin                      
set @whereclause=@whereclause+' 1=1  and '                      
End                        
else                        
begin                        
set @whereclause=@whereclause+' senderid='''+@senderid+''' and  '                        
end              
                        
if ((@date='')and (@todate='')         )              
Begin                        
set @whereclause=@whereclause+'convert(varchar,convert(datetime,dateinsert,104),112) between convert(varchar,convert(datetime,getdate(),104),112) and convert(varchar,convert(datetime,getdate(),104),112)'                        
End                        
else                        
begin                        
set @whereclause=@whereclause+'convert(varchar,convert(datetime,dateinsert,104),112) between convert(varchar,convert(datetime,'''+@date+''',104),112) and convert(varchar,convert(datetime,'''+@todate+''',104),112)'                        
end                        
              
IF @allowNotAllow=''              
BEGIN              
SET @whereclause=@whereclause+' and 1=1 '              
END              
ELSE                    
BEGIN              
SET @whereclause=@whereclause+' and dnd='+@allowNotAllow +''              
END              
                
              
SET @Sql='select message,userid,senderid, dateinsert  as date,case dnd when 0 then ''Not Allow'' when 1 then ''Priority Allow'' when 2 then ''Spam'' when 3 then ''Normal Allow'' else ''Blank''end as dnd   from DNDAllowNotAllow '+@whereClause+' order by ID
 desc '              
 print (@Sql)                           
 EXEC (@Sql)                        
END                      
ELSE                      
BEGIN                      
select distinct userid from DNDAllowNotAllow  order by userid asc --where datediff(d,dateinsert,getdate())=0                     
select distinct senderid from DNDAllowNotAllow order by senderid asc  --where datediff(d,dateinsert,getdate())=0                             
END                      
                      
end 


