/* ============================================================
   Procedure: [dbo].[Usp_ShowScheduledMail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_ShowScheduledMail --39344        
	(@UserID INT)
AS
BEGIN
	DECLARE @ParentID INT = 0
	DECLARE @IsAdmin BIT = 0;
	DECLARE @RoleType VARCHAR(10);
	DECLARE @TeamCode VARCHAR(20)

	SELECT @ParentID = ISNULL(ParentID, 0)
		,@IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserID

	IF object_id('tempdb..#tblUserIds') IS NOT NULL
	BEGIN
		DROP TABLE #tblUserIds
	END

	CREATE TABLE #tblUserIds (UserId BIGINT NOT NULL)

	SELECT @TeamCode = tum.TeamCode
	FROM TBL_UA_TeamUserMappingMaster(NOLOCK) tum
	INNER JOIN TBL_UA_TeamMaster(NOLOCK) tm ON tm.TeamCode = tum.TeamCode
	WHERE tum.UserId = @UserId

	IF (
			(@TeamCode IS NULL)
			AND (
				@ParentId = @UserId
				OR @IsAdmin = 1
				)
			)
	BEGIN
		--set @RoleType = 'Global'  
		INSERT INTO #tblUserIds (UserId)
		SELECT User_Id UserId
		FROM User_Detail(NOLOCK)
		WHERE ParentId = @ParentId
	END
	ELSE IF (@TeamCode != NULL)
	BEGIN
		---set @RoleType = 'Team'  
		INSERT INTO #tblUserIds (UserId)
		SELECT UserId
		FROM TBL_UA_TeamUserMappingMaster(NOLOCK)
		WHERE TeamCode = @TeamCode
	END
	ELSE
	BEGIN
		--set @RoleType = 'User'  
		INSERT INTO #tblUserIds (UserId)
		SELECT @UserId
	END

	IF (
			EXISTS (
				SELECT 'x'
				FROM User_Detail
				WHERE ParentID = @UserID
				)
			)
	BEGIN
		SELECT [ID]
			,[BatchID]
			,(
				SELECT User_Login
				FROM user_detail
				WHERE USER_ID = @UserID
				) AS UserName
			,[SenderName]
			,[Message]
			,[TotalRecords]
			,[TotalProcessed]
			,[ProcessTable]
			,[IsProcess]
			,[Priority_Level]
			--,[BatchInsertTime]   
			,dbo.[fn_getusertimefromindiantime](UserID, BatchInsertTime) AS BatchInsertTime
			--,[BatchProcessTime]        
			,dbo.[fn_getusertimefromindiantime](UserID, BatchProcessTime) AS BatchProcessTime
			--,[ScheduledDate]        
			,dbo.[fn_getusertimefromindiantime](UserID, ScheduledDate) AS ScheduledDate
			-- ,[ScheduledTime]        
			,dbo.[fn_getusertimefromindiantime](UserID, ScheduledTime) AS ScheduledTime
			,[TemplateID]
			,[Route]
			,[PageName]
			,[IsScheduled]
			,[Email_Subject]
			,[ReplyTo]
			,[Amount]
			,[Currency]
		FROM [BatchEmail_Infos]
		WHERE isbatchdeleted = 0
			AND UserID IN (
				SELECT USER_ID
				FROM User_Detail
				WHERE ParentID = @UserID
				)
			AND isnull(ScheduledDate, '') <> ''
			AND ScheduledDate > GETDATE()
		ORDER BY BatchInsertTime DESC
	END
	ELSE
	BEGIN
		SELECT [ID]
			,[BatchID]
			,(
				SELECT User_Login
				FROM user_detail
				WHERE USER_ID = BEI.UserId
				) AS UserName
			,[SenderName]
			,[Message]
			,[TotalRecords]
			,[TotalProcessed]
			,[ProcessTable]
			,[IsProcess]
			,[Priority_Level]
			--,[BatchInsertTime]   
			,dbo.[fn_getusertimefromindiantime](@ParentID, BatchInsertTime) AS BatchInsertTime
			--,[BatchProcessTime]        
			,dbo.[fn_getusertimefromindiantime](@ParentID, BatchProcessTime) AS BatchProcessTime
			--,[ScheduledDate]        
			,dbo.[fn_getusertimefromindiantime](@ParentID, ScheduledDate) AS ScheduledDate
			-- ,[ScheduledTime]        
			,dbo.[fn_getusertimefromindiantime](@ParentID, ScheduledTime) AS ScheduledTime
			,[TemplateID]
			,[Route]
			,[PageName]
			,[IsScheduled]
			,[Email_Subject]
			,[ReplyTo]
			,[Amount]
			,[Currency]
		FROM [BatchEmail_Infos] BEI
		WHERE isbatchdeleted = 0
			AND UserID IN (
				SELECT UserId
				FROM #tblUserIds
				)
			AND isnull(ScheduledDate, '') <> ''
			AND ScheduledDate > GETDATE()
		ORDER BY BatchInsertTime DESC
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'View_SchMail_rpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'BatchEmail_Infos'
END



GO

