 @ToNumber nvarchar(255),  
 @AppName nvarchar(255),  
 @CallerId nvarchar(255),  
 @Duration int,  
 @ScheduleTime datetime = null,  
 @CallbackUrl nvarchar(max)  
)  
as  
begin  
   
 declare @UserId bigint, @ParentId bigint, @Route nvarchar(50), @AppId bigint  
 select @UserId = User_ID, @ParentId = ParentID from User_Detail(nolock) where User_Login = @Username  
  
 if(not exists( select * from Cloud_app_master(nolock) cm   
   where cm.User_id = @UserId and cm.AppId in (   
    select AppId from Cloud_flow_api(nolock) where Parentid = @ParentId ) and cm.Active = 1 and cm.AppName = @AppName )  
  )  
 begin  
  select  0 as cuid, 'App Name not valid' as [message]  
  return  
 end  
  
 if(not exists( select 1 from Cloud_User_Phone(nolock)  
   where Parentid= @ParentId and  Active = 1    
   and PhoneNo not in (select didno from dbo.Cloud_DIDDuty) and PhoneNo  = @CallerId))  
 begin  
  select 0 as cuid, 'Caller Id not valid'  as [message]  
  return  
 end  
  
 if(lower(@RouteName) not in ('promo', 'trans'))  
 begin  
  select 0 as cuid, 'Caller Id not valid'  as [message]  
  return  
 end  
  
  
 SET @ScheduleTime = COALESCE(@ScheduleTime, GETDATE());  
        DECLARE @batchid BIGINT;  
        BEGIN TRAN;  
   INSERT INTO Getbatchrecord  
   ([User_id], RandNum)  
   SELECT @UserId, @UserId;  
   SELECT @batchid = SCOPE_IDENTITY();  
   DELETE FROM GetBatchRecord  
   WHERE BatchID = @batchid;  
        COMMIT;  
  
        SELECT value INTO #mobile FROM fn_split(@ToNumber, ',');  
  
        DECLARE @mcount INT=(SELECT COUNT(1) FROM #mobile);  
  
        SELECT * INTO #temp  FROM dbo.fn_GetVoiceCreditCalculation(@route, @UserId, @Duration, @mcount);  
  
        DECLARE @credits NUMERIC(18, 4)=(SELECT balance  FROM #temp );  
          
  IF EXISTS(SELECT 1 FROM #temp WHERE msg = 'ok')  
        BEGIN  
   INSERT INTO Clone_VoiceDeliveryStatus --clonemessagedeliverystatus                                              
   (BatchID, didno, Mobile, voiceDuration, AppId, IsDnd, IsPrority, IsAllowDND, price, user_id, VoiceInsertDate, ScheduledDate, voice_type, route)  
   SELECT   
   @batchid, @callerid, m.value, @duration, @appid, 0, 2, 0, @credits, @UserId, GETDATE(), @ScheduleTime, 1, @route  
   FROM #mobile m;  
  
  
   select @batchid as cuid, 'Data submited successfully'  as [message]  

    DECLARE @rowJson VARCHAR(MAX) = (  
   SELECT *  
   FROM Clone_VoiceDeliveryStatus(NOLOCK)  
   WHERE BatchID = @batchid  
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
  ,@Activity_type = 'Api_Inst_NewCallBroadcast'  
  ,@ActionType = 'I'  
  ,@RowJson = @rowJson  
  ,@Table_name = 'Clone_VoiceDeliveryStatus'  
        END;  
        ELSE  
        BEGIN      
            --send notification proc to be placed here      
            DECLARE @mail NVARCHAR(200)=(SELECT email FROM user_detail(NOLOCK) WHERE user_id = @UserId);  
  
   select 0 as cuid, 'Unable to process your request please contact admin or support team.'  as [message]  
        END;  
  
end  
  
  


GO

