/* ============================================================
   Procedure: [dbo].[USP_SM_AchievmentSummary]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*  

Achievement summary table   

EXEC  USP_SM_AchievmentSummary  '',32222, 1 , '2024/07/01' , '2024/12/31' ,1 ,''  
EXEC  USP_SM_AchievmentSummary  '',32222, 1 , '2024/07/01' , '2024/12/31' ,1 ,'[{"Field":"UserName","Operator":"=","value":"Abhi01","Conjunction":" AND "}]'  
EXEC  USP_SM_AchievmentSummary  '',32222, 1 , '2024/01/01' , '2024/12/31' ,2,''  
EXEC  USP_SM_AchievmentSummary  '',32222, 1 , '2024/01/01' , '2024/12/31' ,2, '[{"Field":"UserName","Operator":"=","value":"Abhi01","Conjunction":" AND "}]'  
EXEC  USP_SM_AchievmentSummary  '',32222, 1 , '2024/07/01' , '2024/07/31' ,3, ''  
EXEC  USP_SM_AchievmentSummary  '',32222, 1 , '2024/08/01' , '2024/08/01' ,3,'[{"Field":"UserName","Operator":"=","value":"Abhi01","Conjunction":"AND"}]'  
EXEC  USP_SM_AchievmentSummary  '',32222, 1 , '2024/01/01' , '2024/12/31' ,4, ''  
EXEC  USP_SM_AchievmentSummary  '',32222, 1 , '2024/01/01' , '2024/12/31' ,4, '[{"Field":"UserName","Operator":"=","value":"Abhi01","Conjunction":"AND"}]'  
EXEC  USP_SM_AchievmentSummary  '',32222, 1 , '2024/01/01' , '2024/12/31' ,5 ,'' 
EXEC  USP_SM_AchievmentSummary  '',32222, 1 , '2024/01/01' , '2024/12/31' ,5 ,'[{"Field":"UserName","Operator":"=","value":"Abhi01","Conjunction":"AND"}]'  
  
exec USP_SM_AchievmentSummary @P_searchtext=N'',@P_userId=34594,@P_isactive=1,@P_from_date='2024-07-21 00:00:00',@P_to_date='2024-07-27 00:00:00',@P_option=5,@P_Filter_json=N''  
  
tbl_SM_Employee_Points_History  where userid  =  34594      order by 1 desc   
tbl_SM_Employee_Points_History     order by 1 desc   
  
user_detail  where user_id =32222  
  
tbl_sm_scoringraw order by 1 desc  
  
--UPDATE tbl_sm_scoringraw SET PROCESSSTARTTIME = NULL , PROCESSENDTIME = NULL  , ISPROCEESED = 0 WHERE USERID  =  34594  
  
*/  
  
CREATE   PROC USP_SM_AchievmentSummary  
(  
 @P_searchtext varchar(300),  
 @P_userId bigint,  
 @P_isactive int,  
 @P_from_date datetime ,  
 @P_to_date datetime ,  
 @P_option int =1,  
 @P_Filter_json varchar(max) 
)  
as  
begin  

 --tbl_SM_Employee_Incentive_History  
 --tbl_SM_Employee_Points_History order by 1 desc  
 --tbl_SM_Employee_MileStone_History  
  
  DECLARE @PARENTID BIGINT = 0    
 SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_userId      
  
 DECLARE @UserDetails  tbl_type_sm_UserDetails;  
  
 INSERT INTO @UserDetails  
 EXEC Use_GetUserDetails @PARENTID;  
  
  
  
  
 Declare @sql_query nvarchar(max) = '' , @wh_condition varchar(max);  
 Declare @conjunction varchar(10);  
  
 set @P_from_date  = CONCAT( convert( varchar , @P_from_date, 23) , ' 00:00:00' );  
 set @P_to_date  = CONCAT( convert( varchar, @P_to_date, 23) , ' 23:59:59' );  
  
  
 IF OBJECT_ID('tempdb..#temp_Filter_values') IS NOT NULL BEGIN DROP TABLE #temp_Filter_values END;  
  
  
 Create table #temp_Filter_values  
 (  
  Id int identity(1,1),  
  Field varchar(150),  
  Operator varchar(20),  
  Cond_value varchar(150),  
  Conjunction varchar(10)  
 )  
  
  
 if (@P_Filter_json <> '') begin  
  INSERT INTO #temp_Filter_values  
  SELECT   
  JSON_VALUE(VALUE, '$.Field'),  
  JSON_VALUE(VALUE, '$.Operator'),  
  JSON_VALUE(VALUE, '$.value'),  
  JSON_VALUE(VALUE,'$.Conjunction')  
  FROM OPENJSON(@P_Filter_json)  
 END  
    
   
   
 if (@P_option = 1)  
 begin  
  
  IF OBJECT_ID('tempdb..#tempTargetProcUsers') IS NOT NULL   
  BEGIN   
   DROP TABLE #tempTargetProcUsers;  
  END;  
  
  IF OBJECT_ID('tempdb..#TEMP_FINAL_DATA') IS NOT NULL   
  BEGIN   
   DROP TABLE #TEMP_FINAL_DATA;  
  END;  
  
    
  Create table #tempTargetProcUsers  
  (  
   id int identity (1,1),  
   SalesTargetId bigint,  
   UserId bigint,  
   targetPoint decimal(16,2),  
   ISactive bit,  
   Target_date datetime null,  
   UserName varchar(200) null ,  
   TargetName varchaR(100) null,  
   target_period varchar(100) null,  
   targeteType varchar(500) null,  
   targetFor varchar(50) null,  
   target_assigned decimal(16,2) null,  
   target_achieved decimal(16,2) null  
  );  
  
  insert into #tempTargetProcUsers  
  exec usp_sm_GetuserTargetStatus @P_from_date , @P_to_date ,0  
  
  
  SELECT * INTO #TEMP_FINAL_DATA  FROM(  
  SELECT userid as ID , User_Login AS UserName ,  sum( incentive) as Incentive ,sum( target_achieved ) as Target_acheived , 
		sum( milestone_achieved ) as Milestone_achieved ,    sum( Points_earned) as Points_Achieved , Profilepicturepath FROM   
  (SELECT USERID, U.User_Login ,  (CASE WHEN COALESCE(U.IMAGE,'') = '' then 'https://docs.kit19.com/default/person.png' 
		ELSE concat('https://docs.kit19.com/',U.Image) end) AS Profilepicturepath , sum(Incentive_Amount) as incentive ,0 as target_achieved ,0 as milestone_achieved, 0 as Points_earned   FROM tbl_SM_Employee_Incentive_History(NOLOCK) IH   
  INNER JOIN User_Detail(NOLOCK) U ON U.User_ID = IH.UserId   where ih.TranDate between @P_from_date and @P_to_date   
  group by IH.UserId ,U.User_Login  , u.Image
  UNION   
  SELECT USERID, U.User_Login  , (CASE WHEN COALESCE(U.IMAGE,'') = '' then 'https://docs.kit19.com/default/person.png' 
		ELSE concat('https://docs.kit19.com/',U.Image) end) AS Profilepicturepath, 0 as incentive ,0 as target_achieved , COUNT(MilestoneID) as milestone_achieved, 0 as Points_earned 
  FROM tbl_SM_Employee_MileStone_History(NOLOCK) MH INNER JOIN User_Detail(NOLOCK) U ON U.User_ID = MH.UserId   where MH.TranDate between @P_from_date and @P_to_date   
  group by MH.UserId ,U.User_Login , u.Image 
  UNION  
  SELECT ph.UserId , U.User_Login ,(CASE WHEN COALESCE(U.IMAGE,'') = '' then 'https://docs.kit19.com/default/person.png' 
		ELSE concat('https://docs.kit19.com/',U.Image) end) AS Profilepicturepath, 0 as incentive ,0  as target_achieved  , 0 as milestone_achieved, SUM(ph.points)  as Points_earned  
        FROM tbl_SM_Employee_Points_History ph     INNER JOIN User_Detail(NOLOCK) U ON U.User_ID = ph.UserId   
        WHERE ph.TranDate BETWEEN  CONCAT(CONVERT(VARCHAR,  @P_from_date, 23), ' 00:00:00') AND CONCAT(CONVERT(VARCHAR, @P_to_date , 23), ' 23:59:59')     
        GROUP BY ph.UserId ,U.User_Login, u.Image
  --union  
  --SELECT tu.UserId , U.User_Login , 0 as incentive ,0  as target_achieved  , 0 as milestone_achieved, coalesce( sum(tu.target_achieved),0) as Points_earned   
  --FROM #tempTargetProcUsers tu inner join User_Detail U  on  U.User_ID = TU.UserId  
  --where tu.UserId in (select UserId from @UserDetails )  
  --group by tu.UserId ,tu.SalesTargetId ,  U.User_Login, tu.target_achieved  
  UNION  
  SELECT tu.UserId ,  COALESCE(U.User_Login,'') ,(CASE WHEN COALESCE(U.IMAGE,'') = '' then 'https://docs.kit19.com/default/person.png' 
		ELSE concat('https://docs.kit19.com/',U.Image) end) AS Profilepicturepath, 0 as incentive , (case when (SUM (COALESCE (target_achieved,0)) / tu.targetPoint) >= 1 then 1 else 0 end) as target_achieved  , 0 as milestone_achieved,    
  0 as Points_earned   
  FROM #tempTargetProcUsers tu inner join User_Detail U  on  U.User_ID = TU.UserId  
  where tu.UserId in (select UserId from @UserDetails )  
  group by tu.UserId ,tu.SalesTargetId ,  U.User_Login,tu.targetPoint  ,u.Image, Profilepicturepath
  ) AS TBLMAIN  where  User_Login <> ''  group by  userid , User_Login, Profilepicturepath) AS TABLE_MAIN  
    
    
  IF EXISTS(SELECT 1 FROM #temp_Filter_values)  
  BEGIN  
  
   select @conjunction = Conjunction from #temp_Filter_values  
   SELECT @wh_condition = STRING_AGG(FIELD  +' '+ Operator  +' '''+ Cond_value + ''' ' ,  @conjunction  )  FROM #temp_Filter_values;   
  
   
		set @sql_query = 'SELECT  ID, UserName , Incentive , Target_acheived , Milestone_achieved , Points_Achieved , Profilepicturepath   FROM #TEMP_FINAL_DATA   
						   WHERE  '+  @wh_condition +' AND ID IN  (select UserId from @UserDetails ) ' ;  


   print @sql_query;  
   EXEC sp_executesql @sql_query, N'@UserDetails  tbl_type_sm_UserDetails READONLY', @UserDetails;  
    
  END  
  else BEGIN    
		SELECT  * FROM #TEMP_FINAL_DATA  where ID IN  (select UserId from @UserDetails );  
  END  
  
 end  
  
 /*=======================================Incentive details===========================================*/  
  
 if (@P_option = 2)  
 begin  
    
  IF OBJECT_ID('tempdb..#TEMP_FINAL_INCENTIVE') IS NOT NULL   
  BEGIN   
   DROP TABLE #TEMP_FINAL_INCENTIVE;  
  END;  
  
    
  SELECT IH.Tran_ID ,  FORMAT(TranDate, 'dd-MMM-yyyy HH:mm:ss')   as incentive_date , U.User_ID , COALESCE(U.User_Login,'') as userName , (CASE WHEN COALESCE(U.IMAGE,'') = '' 
  then 'https://docs.kit19.com/default/person.png' 	ELSE concat('https://docs.kit19.com/',U.Image) end) AS Profilepicturepath, coalesce( TI.Incentive_name,'') as Incentivename  ,
  coalesce((CASE WHEN IH.IncentiveType = 'CASH' THEN coalesce( Incentive_Amount,0) END),0)  as cash ,  
  coalesce( (CASE WHEN IH.IncentiveType = 'Kind' THEN coalesce( Voucher_details,'') END),'')  as kind , (case when coalesce( IH.IsPaid,0 ) = 1 then 'Paid' else 'Unpaid' end) as Pay_Status, Ih.ispaid   INTO #TEMP_FINAL_INCENTIVE from tbl_SM_Employee_Incentive_History IH   
  left join User_Detail U ON IH.UserId =  U.User_ID  LEFT JOIN tbl_SM_Employee_Incentive  TI  ON TI.ID = IH.IncentiveId  
  WHERE IH.TRANDATE BETWEEN  @P_from_date and @P_to_date   
  and ( (case when @P_searchtext = '' then '1' else    TI.Incentive_name  end ) like '%'+ (case when @P_searchtext = '' then '1' else    @P_searchtext  end ) + '%'   
  or (case when @P_searchtext = '' then '1' else     U.User_Login   end ) like '%'+ (case when @P_searchtext = '' then '1' else    @P_searchtext  end ) + '%' ) ;  
  
  
  IF EXISTS(SELECT 1 FROM #temp_Filter_values)  
  BEGIN  
  
   select @conjunction = Conjunction from #temp_Filter_values  
   SELECT @wh_condition = STRING_AGG(FIELD  +' '+ Operator  +' '''+ Cond_value + ''' ' ,  @conjunction  )  FROM #temp_Filter_values;   
     
		set @sql_query = 'SELECT  Tran_ID , incentive_date , userName , Incentivename  , cash ,   kind , Pay_Status, Profilepicturepath 
				FROM #TEMP_FINAL_INCENTIVE    WHERE  '+  @wh_condition +' AND User_ID IN  (select UserId from @UserDetails ) ' ;  
  
   print @sql_query;  
   EXEC sp_executesql @sql_query, N'@UserDetails  tbl_type_sm_UserDetails READONLY', @UserDetails;  
    
  END  
  ELSE BEGIN   
		SELECT  * FROM #TEMP_FINAL_INCENTIVE where User_ID IN  (select UserId from @UserDetails );
  END  
 END  
  
 /*=======================================Target achieved ===========================================*/  
  
 IF (@P_option = 3)  
 BEGIN  
  
  if OBJECT_ID('tempdb..#tempTargetAchieved') is not null begin drop table #tempTargetAchieved end;  
  
  Create table #tempTargetAchieved  
  (  
   id int identity (1,1),  
   SalesTargetId bigint,  
   UserId bigint,  
   targetPoint decimal(16,2),  
   ISactive bit,  
   Target_date datetime null,  
   UserName varchar(200) null ,  
   TargetName varchaR(100) null,  
   target_period varchar(100) null,  
   targetType varchar(500) null,  
   targetFor varchar(50) null,  
   target_assigned decimal(16,2) null,  
   target_achieved decimal(16,2) null  
  )  
  
  insert into #tempTargetAchieved  
  exec usp_sm_GetuserTargetStatus @P_from_date , @P_to_date ,0 ;  
  
  IF OBJECT_ID('tempdb..#TEMP_FINAL_TARGETS') is not null begin drop table #TEMP_FINAL_TARGETS end;  
  
  select FORMAT(Target_date, 'dd-MMM-yyyy')  as Target_date , UserId , COALESCE(U.User_Login,'') AS UserName ,(CASE WHEN COALESCE(U.IMAGE,'') = '' 
  then 'https://docs.kit19.com/default/person.png' 	ELSE concat('https://docs.kit19.com/',U.Image) end) AS Profilepicturepath, coalesce( Targetname,'') as Targetname, 
  target_period , coalesce(targetType ,'') as targetType , coalesce(targetFor,'') as targetFor , coalesce( targetPoint,0 ) as target_assigned , 
  coalesce(target_achieved ,0) as target_achieved  INTO #TEMP_FINAL_TARGETS from #tempTargetAchieved   
   INNER JOIN User_Detail U ON U.User_ID = #tempTargetAchieved.UserId  
   where targetType = 'Points' and (case when @P_searchtext = '' then '1' else UserName  end ) 
   like '%'+ (case when @P_searchtext = '' then '1' else    @P_searchtext  end ) + '%' ;  
  
  
  IF EXISTS(SELECT 1 FROM #temp_Filter_values)  
  BEGIN  
  
   select @conjunction = Conjunction from #temp_Filter_values  
   SELECT @wh_condition = STRING_AGG(FIELD  +' '+ Operator  +' '''+ Cond_value + ''' ' ,  @conjunction  )  FROM #temp_Filter_values;   
  
		set @sql_query = 'SELECT  Target_date , UserName , Targetname , target_period , targetType , targetFor  , target_assigned , target_achieved ,Profilepicturepath   FROM #TEMP_FINAL_TARGETS   
		   WHERE  '+  @wh_condition +'  AND UserId IN  (select UserId from @UserDetails )' ;  
  
  
   print @sql_query;  
   EXEC sp_executesql @sql_query, N'@UserDetails  tbl_type_sm_UserDetails READONLY', @UserDetails;  
    
  END  
  else BEGIN   
		SELECT  * FROM #TEMP_FINAL_TARGETS  WHERE  UserId IN  (select UserId from @UserDetails );  
  END  
  
 END  
  
 /*=======================================Milestone achieved ===========================================*/  
  
 if (@P_option = 4)  
 begin  
  
  if OBJECT_ID('tempdb..#TEMP_FINAL_MILESTONES') is not null begin drop table #TEMP_FINAL_MILESTONES  end;  
  
  SELECT  FORMAT(MH.TranDate, 'dd-MMM-yyyy HH:mm:ss') as Milstonedate , MH.UserId ,COALESCE( u.User_Login,'') as UserName, (CASE WHEN COALESCE(U.IMAGE,'') = '' 
  then 'https://docs.kit19.com/default/person.png' 	ELSE concat('https://docs.kit19.com/',U.Image) end) AS Profilepicturepath, coalesce( MS.Milestone_Name,'') as Milestonename ,   
     (MH.AchievedTargetAmount * 100 / MH.Sale_target_Amount)  as achieved_percent,   
 coalesce( MS.Event_name,'') as TargetName INTO #TEMP_FINAL_MILESTONES  
  FROM tbl_SM_Employee_MileStone_History(NOLOCK) MH  
  INNER JOIN User_Detail U ON U.User_ID = MH.UserId    
  left join tbl_SM_MileStones(NOLOCK) MS on MH.MilestoneID = MS.Id  
  WHERE   MH.TRANDATE BETWEEN   @P_from_date and @P_to_date   
  and ( (case when @P_searchtext = '' then '1' else    u.User_Login  end ) like '%'+ (case when @P_searchtext = '' then '1' else    @P_searchtext  end ) + '%'   
  or (case when @P_searchtext = '' then '1' else    MS.Milestone_Name   end ) like '%'+ (case when @P_searchtext = '' then '1' else    @P_searchtext  end ) + '%' ) ;  
  
    
    
  IF EXISTS(SELECT 1 FROM #temp_Filter_values)  
  BEGIN  
  
   select @conjunction = Conjunction from #temp_Filter_values  
   SELECT @wh_condition = STRING_AGG(FIELD  +' '+ Operator  +' '''+ Cond_value + ''' ' ,  @conjunction  )  FROM #temp_Filter_values;   
	
	set @sql_query = 'SELECT  Milstonedate , UserName , Milestonename , achieved_percent , TargetName, Profilepicturepath   FROM  #TEMP_FINAL_MILESTONES   
	WHERE  '+  @wh_condition +' AND   UserId IN  (select UserId from @UserDetails )' ;  
	
   print @sql_query;  
   EXEC sp_executesql @sql_query, N'@UserDetails  tbl_type_sm_UserDetails READONLY', @UserDetails;  
    
  
  END  
  else BEGIN  
	
	 SELECT  * FROM #TEMP_FINAL_MILESTONES   WHERE  UserId IN  (select UserId from @UserDetails );  
	
  END  
  
  
  
 end  
  
 /*=======================================Points earned ===========================================*/  
  
 if (@P_option = 5)  
 begin  
  
  if OBJECT_ID('tempdb..#TEMP_FINAL_POINTS') is not null begin drop table #TEMP_FINAL_POINTS  end;  
  
  SELECT FORMAT(PH.TranDate, 'dd-MMM-yyyy HH:mm:ss') as Pointsdate , PH.UserId , COALESCE(U.User_Login,'') as UserName ,coalesce( PH.points,0) as Points, 
  COALESCE(AM.EventName,'') as Activity,  
  [dbo].[ufunc_sm_getUserTranpoints](PH.TranDate, PH.UserId) as Balance , (CASE WHEN COALESCE(U.IMAGE,'') = '' 
  then 'https://docs.kit19.com/default/person.png' 	ELSE concat('https://docs.kit19.com/',U.Image) end) AS Profilepicturepath
   INTO #TEMP_FINAL_POINTS  
  FROM tbl_SM_Employee_Points_History(NOLOCK) PH  
  INNER JOIN User_Detail U ON U.User_ID = PH.UserId    
  left join Activitymaster  (NOLOCK) AM on AM.ID = PH.Activity_id  
  WHERE   PH.TRANDATE BETWEEN   @P_from_date and @P_to_date   
  and ( (case when @P_searchtext = '' then '1' else    u.User_Login  end ) like '%'+ (case when @P_searchtext = '' then '1' else    @P_searchtext  end ) + '%'   
  or (case when @P_searchtext = '' then '1' else  AM.EventName   end ) like '%'+ (case when @P_searchtext = '' then '1' else    @P_searchtext  end ) + '%' )  
  order by convert(datetime, PH.TranDate) desc   
    
  
  IF EXISTS(SELECT 1 FROM #temp_Filter_values)  
  BEGIN  
  
   select @conjunction = Conjunction from #temp_Filter_values  
   SELECT @wh_condition = STRING_AGG(FIELD  +' '+ Operator  +' '''+ Cond_value + ''' ' ,  @conjunction  )  FROM #temp_Filter_values;   
  
	set @sql_query = 'SELECT   Pointsdate , UserName , Points , Activity , Balance, Profilepicturepath FROM  #TEMP_FINAL_POINTS  
		   WHERE  '+  @wh_condition +'   AND  UserId IN  (select UserId from @UserDetails )   order by convert(datetime , Pointsdate) desc ' ;  
	
   print @sql_query;  
   EXEC sp_executesql @sql_query, N'@UserDetails  tbl_type_sm_UserDetails READONLY', @UserDetails;  
    
  END  
  else BEGIN   
		SELECT  * FROM #TEMP_FINAL_POINTS WHERE  UserId IN  (select UserId from @UserDetails )   order by convert(datetime , Pointsdate) desc;  
  END  
  
  
 end  
  
   
end


GO

/* ============================================================
   Procedure: [dbo].[USP_SM_ADD_UPDATE_SCORES]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


 /*

 	--tbl_LeadEventHistory order by 1 desc   ---   all history goes into this table 
	--activitymaster WHERE  ID=7
	--TBL_SM_SCORINGRULE WHERE ACTIVITY_ID = 10
	--tbl_SM_Employee_Points_History
	---   tbl_LeadEventHistory WHERE EVENTID =10 ORDER BY 1 DESC
	---  LeadInteractionHistory  WHERE ID  = 2305930
	--tbl_SM_ScoringRule
	-- EVENTPLACEHOLDERS WHERE EVENTID=10  AND ID IN ( 1007 , 27)   order by exposedname EVENTID= 10 
	--- UPDATE  EVENTPLACEHOLDERS  SET EXPOSEDNAME = 'AmountPaid'  WHERE EVENTID=10  AND ID IN ( 1007 , 27)  	
	--  INSERT INTO EVENTPLACEHOLDERS SELECT 10, 'Amount' , 'Amount', 'Tbl_ST_SalesActivityMaster','amount','lead',1,'int'
	SELECT [AmountPaid] FROM LeadInteractionHistory WHERE ID = 2305918
	tbl_LeadEventHistory WHERE  HISTORYID =  966487 
	tbl_SM_Employee_Points_History  where userid  =  34594      order by 1 desc 
	tbl_SM_Employee_Points_History  order by 1 desc 

	user_detail  where user_id =32222


	tbl_LeadEventHistory where historyid= 967101


	tbl_sm_scoringraw  WHERE USERID = 34594 order by 1 desc

	UPDATE tbl_sm_scoringraw SET ISPROCEESED = 0   WHERE USERID = 34594  --order by 1 desc


	USP_SM_ADD_UPDATE_SCORES  32222, 'New Interaction added' ,'tbl_LeadEventHistory' ,'966891'


    USP_SM_ADD_UPDATE_SCORES  34594, 'User signs in' ,'tbl_userEventHistory' ,'241262'

	USP_SM_ADD_UPDATE_SCORES  34594, 'Notes added' ,'tbl_LeadEventHistory' ,'967114'

	tbl_sm_scoringraw order by 1 desc

	TBL_SM_SCORINGRULE WHERE ACTIVITY_ID = 31   AND ParentId =  34594



 */

CREATE  PROC  [dbo].[USP_SM_ADD_UPDATE_SCORES]
(                    
	 @P_UserID             BIGINT,                                         
	 @P_EventName          NVARCHAR(500),
	 @P_history_tableName  VARCHAR(200),
	 @P_History_row_id  INT
)
AS BEGIN


	 DECLARE @W_EventID BIGINT= 0 ;                              
	 SELECT @W_EventID = ISNULL([ID], 0) FROM   ActivityMaster(NOLOCK) WHERE  [EventName] = @P_EventName;  
	

	PRINT CONCAT( 'EVENTID', CONVERT( VARCHAR, @W_EventID) ) ;

	declare   @W_PARENTID int = 0 ,  @scoring_eventid int , @points int , @roles_json varchar(1000) , @Users_or_roles varchar(2000) = '' , @applicable_type varchar(50) ,
	@W_Points_type varchar(30) = ''  , @W_RANGE_JSON VARCHAR(MAX) = '' , @W_PERCENTAGE INT  = 0;

	select @W_PARENTID =  parentID from User_Detail(nolock)  where [user_id]  = @P_UserID

	PRINT CONCAT('PARENTID ' ,CONVERT( VARCHAR, @W_PARENTID) ) ;

	IF ( EXISTS( SELECT 1 FROM TBL_SM_SCORINGRULE(nolock) WHERE ACTIVITY_ID = @W_EventID   AND ParentId = @W_PARENTID ) )
	BEGIN

		
		Declare  @Min_id bigint = 0 , @max_id  bigint =  0 ; 

		SELECT @Min_id = MIN(ID) FROM tbl_SM_ScoringRule(nolock)   WHERE activity_id = @W_EventID   AND ParentId = @W_PARENTID
		SELECT @max_id = MAX(ID) FROM tbl_SM_ScoringRule(nolock)   WHERE activity_id = @W_EventID   AND ParentId = @W_PARENTID


		WHILE (@max_id >= @Min_id ) 
		BEGIN
			
			
				SELECT @scoring_eventid = eventid from tbl_SM_ScoringRule(nolock) where activity_id = @W_EventID   AND ParentId = @W_PARENTID AND ID =@Min_id
				PRINT CONCAT('SCORING EVENTID  >  ' ,CONVERT( VARCHAR, @scoring_eventid) ) ;

				SELECT @points = Points , @roles_json = Role_name , @W_Points_type = Points_type , @W_RANGE_JSON = COALESCE(RANGE_JSON,'') , @W_PERCENTAGE = Percentage 
				from tbl_SM_ScoringRule(nolock) where activity_id = @W_EventID   AND ParentId = @W_PARENTID AND ID  = @Min_id

			    --drop table if exists #temp_users_100

					if OBJECT_ID('tempdb..#temp_users_100') is not null begin drop table #temp_Users_100  end;

				CREATE TABLE #temp_users_100 (
					id int identity(1,1),
					[values] NVARCHAR(50)
				);
		
		        if OBJECT_ID('tempdb..#temp_CHECK_CONDITION') is not null begin drop table #temp_CHECK_CONDITION  end;  

				CREATE TABLE #temp_CHECK_CONDITION (
					id int identity(1,1),
					[CONDITION] NVARCHAR(50)
				);


				DECLARE @UserDetails  tbl_type_sm_UserDetails;

				INSERT INTO @UserDetails
				EXEC Use_GetUserDetails @W_PARENTID;


				INSERT INTO  #temp_users_100
				EXEC USP_SM_getUsersbyrole  @W_PARENTID ,  @roles_json ,@UserDetails ;

				PRINT CONVERT( VARCHAR ,@W_PARENTID);

				SELECT  STRING_AGG( [values] , ' , ') FROM #temp_users_100 

				if (exists( select 1 from   #temp_users_100 where [values] = @P_UserID))
				begin
			
					--- check condition 
					Declare @w_query  NVARCHAR(MAX)  = '', @W_RULE_ID INT = 0, @W_REFTABLENAME VARCHAR(100) = '' , @W_REF_ID BIGINT  =  0 ;

					SELECT @W_RULE_ID = Id  FROM  tbl_SM_ScoringRule(nolock) WHERE Activity_id =  @W_EventID  AND ParentId = @W_PARENTID  AND ID =@Min_id

					PRINT CONVERT( VARCHAR ,@W_RULE_ID);

					IF (EXISTS (SELECT 1 FROM tbl_SM_ScoringCondition(nolock) WHERE Rule_id = @W_RULE_ID  ))
					BEGIN

					---Tbl_ST_SalesActivityMaster  order by 1 desc
					--  LeadInteractionHistory where id = 2305948
					--  SELECT 1 FROM LeadInteractionHistory WHERE  ID = 2305948 AND   AmountPaid >= '10'  AND  Products LIKE 'LEAD%'  

					IF (@P_history_tableName = 'Tbl_ST_SalesActivityMaster')
					BEGIN
						SET @W_QUERY = ' SELECT  @W_REFTABLENAME = tblRefname , @W_REF_ID = tblRefId  FROM ' + @P_history_tableName + '  WHERE ID = '+  CONVERT(VARCHAR, @P_History_row_id) ;

					END
					ELSE
					BEGIN
						SET @W_QUERY = ' SELECT  @W_REFTABLENAME = REFTABLES , @W_REF_ID = REFIDS  FROM ' + @P_history_tableName + '  WHERE HistoryID = '+  CONVERT(VARCHAR, @P_History_row_id) ;
					end

					if exists(select 1 FROM tbl_SM_ScoringCondition(nolock) WHERE Rule_id = @W_RULE_ID)
						begin

							EXEC sp_executesql     @W_QUERY, N'@W_REFTABLENAME NVARCHAR(MAX) OUTPUT, @W_REF_ID NVARCHAR(MAX) OUTPUT',  @W_REFTABLENAME OUTPUT,   @W_REF_ID OUTPUT;
							print   concat(  'reftablename : '+ @W_REFTABLENAME ,' ref id : ' , convert( varchar,  @W_REF_ID)  )
							SET @w_query = ' SELECT 1 FROM '+ @W_REFTABLENAME + '(nolock) WHERE  ID = '+  CONVERT(VARCHAR, @W_REF_ID) +' AND  ';
							SELECT @w_query += ' ' + FIELD +' ' +    CASE WHEN Operatore LIKE '%REP%' THEN  REPLACE( Operatore,'REP',f_value) ELSE Operatore + ' ''' + f_value + '''' END  +
												' ' + Conjunction  FROM tbl_SM_ScoringCondition(nolock) WHERE Rule_id = @W_RULE_ID  ; 
				
							SET @w_query = SUBSTRING(@w_query , 0, LEN(@W_QUERY) -2);
							PRINT @w_query; 

							-- SELECT * FROM LeadInteractionHistory WHERE  ID = 2305918 AND   AmountPaid = '10'  
	
							INSERT INTO #temp_CHECK_CONDITION
							EXEC (@W_QUERY) 

							--SELECT 'TEST' , * FROM #temp_CHECK_CONDITION;
				 
							IF NOT EXISTS( SELECT 1 FROM  #temp_CHECK_CONDITION ) BEGIN
								select 'Condition not match';
								RETURN;
							END

						end
					END

					------ as per mayank  sir..
					if (@P_history_tableName = 'tbl_LeadEventHistory') begin 
						select  @P_UserID = UserID from tbl_LeadEventHistory(nolock) where HistoryID = @P_History_row_id
					end

			
					IF ( @W_Points_type ='Specific Points' )
					BEGIN
				
						IF NOT EXISTS( SELECT 1 FROM tbl_SM_Employee_Points_History(nolock) WHERE Activity_id = @W_EventID AND UserId =@P_UserID  AND  ref_tran_id =  @P_History_row_id ) BEGIN
							insert into tbl_SM_Employee_Points_History (Activity_id,UserId,points,TranDate,ref_tran_id,Remarks,ExpiryDate,IsExpirable,Isactive,Createdby,createdate)
							select  @W_EventID, @P_UserID , Points , GETDATE() , @P_History_row_id, @P_EventName ,null,null,1,@P_UserID , GETDATE() FROM TBL_SM_SCORINGRULE(nolock) WHERE ACTIVITY_ID = @W_EventID 
							AND ParentId = @W_PARENTID  AND ID =@Min_id
						END

					END

					ELSE IF ( @W_Points_type ='Relative Points' )
					BEGIN

						----- EVENTPLACEHOLDER_ID 
						DECLARE    @W_POINTS INT =0  , @W_AMOUNT BIGINT;


						EXEC USP_SM_GETEVENTAMOUNT  @W_RANGE_JSON , @W_EventID , @P_history_tableName ,@P_History_row_id , @W_PERCENTAGE , @W_AMOUNT output

						

						IF (@W_RANGE_JSON <>'') BEGIN

						if OBJECT_ID('tempdb..#TempRangeTable') is not null begin drop table #TempRangeTable  end; 
							CREATE TABLE #TempRangeTable (
								Field NVARCHAR(100),
								eventid INT,
								[From] INT,
								[To] INT,
								Points INT
							);

							DECLARE @json NVARCHAR(MAX) = N'['+@W_RANGE_JSON+']';

								set @json = REPLACE(@json,'undefined','0')


							INSERT INTO #TempRangeTable (Field, eventid, [From], [To], Points)
							SELECT Field, eventid, [From], [To], Points
							FROM OPENJSON(@json)
							WITH (
								Field NVARCHAR(100) '$.Field',
								eventid INT '$.eventid',
								[From] INT '$.From',
								[To] INT '$.To',
								Points INT '$.Points'
							);

							-- Verify that the data was inserted
							---SELECT * FROM #TempRangeTable;
					
							SET @W_POINTS = 0;

							---SELECT  POINTS FROM #TempRangeTable  WHERE @w_amount BETWEEN  [FROM]   AND [TO]

							SELECT   @W_POINTS = POINTS FROM #TempRangeTable  WHERE @w_amount BETWEEN  [FROM]   AND [TO]

							PRINT CONCAT ('POINTS: ', CONVERT( VARCHAR, @W_POINTS));

							--- EVENTPLACEHOLDER_ID 
							IF NOT EXISTS( SELECT 1 FROM tbl_SM_Employee_Points_History(nolock) WHERE Activity_id = @W_EventID AND UserId =@P_UserID  AND  ref_tran_id =  @P_History_row_id ) BEGIN
								INSERT INTO tbl_SM_Employee_Points_History (Activity_id,UserId,points,TranDate,ref_tran_id,Remarks,ExpiryDate,IsExpirable,Isactive,Createdby,createdate)
								SELECT  @W_EventID, @P_UserID , @W_POINTS , GETDATE() , @P_History_row_id, @P_EventName,null,null,1,@P_UserID , GETDATE() FROM TBL_SM_SCORINGRULE(nolock) WHERE ACTIVITY_ID = @W_EventID 
								AND ParentId = @W_PARENTID  AND ID =@Min_id
							end

							-- Clean up the temporary table
							--DROP TABLE #TempRangeTable;
							if OBJECT_ID('tempdb..#TempRangeTable') is not null begin drop table #TempRangeTable  end; 


						END
						ELSE IF (@W_PERCENTAGE <> 0 )
						BEGIN
					
							IF (@w_amount > 0) BEGIN						
								select  @W_POINTS = ( @w_amount * Percentage) /100  FROM TBL_SM_SCORINGRULE(nolock) WHERE ACTIVITY_ID = @W_EventID AND ID =@Min_id
								IF NOT EXISTS( SELECT 1 FROM tbl_SM_Employee_Points_History WHERE Activity_id = @W_EventID AND UserId =@P_UserID  AND  ref_tran_id =  @P_History_row_id ) BEGIN
									insert into tbl_SM_Employee_Points_History (Activity_id,UserId,points,TranDate,ref_tran_id,Remarks,ExpiryDate,IsExpirable,Isactive,Createdby,createdate)
									select  @W_EventID, @P_UserID , @W_POINTS , GETDATE() , @P_History_row_id, @P_EventName ,null,null,1,@P_UserID , GETDATE() FROM TBL_SM_SCORINGRULE (nolock) WHERE ACTIVITY_ID = @W_EventID 
									AND ParentId = @W_PARENTID AND ID =@Min_id
								END
							END
						END
					END
				END

				--- 
				IF EXISTS(SELECT 1 FROM  tbl_SM_ScoringRule(nolock) WHERE  activity_id = @W_EventID   AND ParentId = @W_PARENTID  AND Id > @Min_id) BEGIN
					SELECT TOP 1  @Min_id = ID  FROM  tbl_SM_ScoringRule(nolock) WHERE  activity_id = @W_EventID   AND ParentId = @W_PARENTID  AND Id > @Min_id ORDER BY Id ASC
				END
				ELSE BEGIN  SET @Min_id =  @max_id  +1 ; END

		END


	

	END

	if OBJECT_ID('tempdb..#temp_users_100') is not null begin drop table #temp_Users_100  end;
	if OBJECT_ID('tempdb..#temp_CHECK_CONDITION') is not null begin drop table #temp_CHECK_CONDITION  end; 
	if OBJECT_ID('tempdb..#TempRangeTable') is not null begin drop table #TempRangeTable  end; 
END


GO

/* ============================================================
   Procedure: [dbo].[usp_sm_ApplySLA]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_sm_ApplySLA 335, '28-Nov-2022'  
CREATE   PROCEDURE usp_sm_ApplySLA  
(  
 @PID bigint=0,  
 @CutOffDate datetime='01-Jul-2022'  
)  
AS  
BEGIN  
  
-- declare @PID bigint=36950,@CutOffDate datetime='28-Nov-2022'  
  
if object_id('tempdb..#tbl_ParentId') is not null begin drop table #tbl_ParentId end  
if object_id('tempdb..#tbl_SLASetting') is not null begin drop table #tbl_SLASetting end  
if object_id('tempdb..#tbl_TicketList') is not null begin drop table #tbl_TicketList end  
  
create table #tbl_ParentId  
(  
 Id int identity(1,1),  
 ParentId bigint  
)  
  
create table #tbl_SLASetting  
(  
 RowId    int identity(1,1),  
 --SLAResp_ID   bigint,  
 SLA_ID    bigint,  
 --Priority_ID   int,  
 Respond_Sec   bigint,  
 Resolve_Sec   bigint,  
 Respond_Esc_Freq nvarchar(100),  
 Respond_Esc_Sec  bigint,  
 Respond_Esc_AgentId bigint,  
 Respond_Rem_Freq nvarchar(100),  
 Respond_Rem_Sec  bigint,  
 Respond_Rem_AgentId bigint,  
 Resolve_Rem_Freq nvarchar(100),  
 Resolve_Rem_Sec  bigint,  
 Resolve_Rem_AgentId bigint  
)  
  
create table #tbl_TicketList  
(  
 RowId      int identity(1,1),  
 TicketID     bigint,  
 User_id      bigint,  
 ParentID     bigint,  
 TicketNo     nvarchar(32),  
 Requester     nvarchar(200),  
 Subject      nvarchar(500),  
 Description     nvarchar(max),  
 Status      tinyint,  
 Remarks      nvarchar(max),  
 Note      nvarchar(max),  
 Date_Created    datetime,  
 Priority     tinyint,  
 AssignTo     bigint,  
 Assign_Group    bigint,  
 Active      tinyint,  
 Ticket_type     int,  
 Source      nvarchar(400),  
 Product      nvarchar(400),  
 Company      nvarchar(400),  
 SLAID      bigint default(0),  
 IsResponseRem    bit,  
 ResponseRemAgentId   bigint,  
 ResponseRemDate    datetime,  
 IsResponseEsc    bit,  
 ResponseEscAgentId   bigint,  
 ResponseEscDate    datetime,  
 IsResolutionRem    bit,  
 ResolutionRemAgentId  bigint,  
 ResolutionRemDate   datetime,  
 IsResolutionEsc1   bit,  
 ResolutionEsc1AgentId  bigint,  
 ResolutionEsc1Date   datetime,  
 IsResolutionEsc2   bit,  
 ResolutionEsc2AgentId  bigint,  
 ResolutionEsc2Date   datetime,  
 IsResolutionEsc3   bit,  
 ResolutionEsc3AgentId  bigint,  
 ResolutionEsc3Date   datetime,  
 IsResolutionEsc4   bit,  
 ResolutionEsc4AgentId  bigint,  
 ResolutionEsc4Date   datetime  
)  
  
declare @iPId bigint=1, @iSLASettingId int=1, @iTL int=1, @PIdCnt bigint=0, @ser_user_id bigint=0, @ParentId bigint=0,  
  @SLASettingCnt int=0, @TLCnt int=0  
declare @SLAResp_ID bigint, @SLA_ID bigint, @TicketId bigint, @Priority_ID int, @Respond_Sec bigint, @Resolve_Sec bigint,   
  @Respond_Esc_Freq nvarchar(100), @Respond_Esc_AgentId bigint, @Respond_Esc_Sec bigint, @Respond_Rem_Freq nvarchar(100),  
  @Respond_Rem_AgentId bigint, @Respond_Rem_Sec bigint, @Resolve_Rem_Freq nvarchar(100), @Resolve_Rem_AgentId bigint,  
  @Resolve_Rem_Sec bigint  
declare @ResolutionEsc1Sec bigint=0, @ResolutionEsc1AgentId bigint=0, @ResolutionEsc2Sec bigint=0,   
  @ResolutionEsc2AgentId bigint=0, @ResolutionEsc3Sec bigint=0, @ResolutionEsc3AgentId bigint=0,   
  @ResolutionEsc4Sec bigint=0, @ResolutionEsc4AgentId bigint=0  
declare @Apply_GroupId bigint, @Apply_TicketTypeId bigint, @Apply_Source nvarchar(400), @Apply_Product nvarchar(400),   
  @Apply_Company nvarchar(400)  
declare @IsResponseRem bit, @ResponseRemAgentId bigint, @IsResponseEsc bit, @ResponseEscAgentId bigint, @IsResolutionRem bit,  
  @ResolutionRemAgentId bigint, @IsResolutionEsc1 bit, @IsResolutionEsc2 bit, @IsResolutionEsc3 bit, @IsResolutionEsc4 bit  
  
insert into #tbl_ParentId  
select distinct parentid from Serv_SLA_Setting(nolock) Where Active=1 and ParentID=case when @PID=0 then ParentID else @PID end  
  
select @PIdCnt=Count(*) from #tbl_ParentId  
print '@PIdCnt: ' + cast(@PIdCnt as varchar)  
  
While @iPId <= @PIdCnt  
Begin  
 Select @ParentId=ParentId From #tbl_ParentId Where Id=@iPId  
 print '@ParentId: ' + cast(@ParentId as varchar)  
  
 insert into #tbl_TicketList  
   (TicketID, User_Id, ParentID, TicketNo, Requester, Subject, Description, Status, Remarks, Note,  
   Date_Created, Priority, AssignTo, Assign_Group, Active, Ticket_Type, Source, Product, Company)  
 Select TicketID, User_Id, ParentID, TicketNo, Requester, Subject, Description, Status, Remarks, Note,   
   Date_Created, Priority, AssignTo, Assign_Group, Active, Ticket_Type, Source, Product, Company  
 From Serv_TicketMaster(nolock) Where ParentID=@ParentId and Status not in (2,4) and Date_Created >= @CutOffDate  
   --and TicketID in (66652)  
 --Select * From Serv_TicketMaster(nolock) Where ParentID=36950 and Status not in (2,4)  
 select @TLCnt=Count(*) from #tbl_TicketList  
 print '@TLCnt: ' + cast(@TLCnt as varchar)  
  
 insert into #tbl_SLASetting  
 SELECT  SLAID=max(SLAR.SLAID), Respond_Sec=max(SLAR.Respond_Sec), Resolve_Sec=Max(SLAR.Resolve_Sec),   
    Respond_Esc_Freq=max(SLAR.resp_Freq), Respond_Esc_Sec=max(FREQ1.val_sec),   
    Respond_Esc_AgentId=Max(SLAR.Assign_Agent), Respond_Rem_Freq=Max(SLAR.resp_remind_freq),   
    Respond_Rem_Sec=Max(isnull(FREQ2.val_sec,0)), Respond_Rem_AgentId=max(SLAR.resp_assignd),   
    Resolve_Rem_Freq=max(SLAR.resolution_remind_freq), Resolve_Rem_Sec=max(isnull(FREQ3.val_sec,0)),   
    Resolve_Rem_AgentId=Max(SLAR.resolution_assignd)  
 FROM        Serv_SLA_Setting AS SLA WITH (nolock) INNER JOIN Serv_SLA_Response AS SLAR WITH (nolock)   
 ON   SLA.SLAId = SLAR.SLAID AND SLA.Active = 1 LEFT JOIN Serv_SLA_Freq as FREQ1 WITH (nolock)  
 ON   SLAR.resp_Freq=FREQ1.Freq_Desc LEFT JOIN Serv_SLA_Freq as FREQ2 WITH (nolock)  
 ON   SLAR.resp_remind_freq=FREQ2.Freq_Desc LEFT JOIN Serv_SLA_Freq as FREQ3 WITH (nolock)  
 ON   SLAR.resolution_remind_freq=FREQ3.Freq_Desc   
 WHERE  SLA.ParentID = @ParentId  
 GROUP BY SLA.ord_no  
  
 Set @SLASettingCnt=@@ROWCOUNT  
 print '@SLASettingCnt: ' + cast(@SLASettingCnt as varchar)  
  
 While @iSLASettingId <= @SLASettingCnt  
 Begin  
  Select /*@SLAResp_ID=SLAResp_ID,*/ @SLA_ID=SLA_ID, /*@Priority_ID=Priority_ID,*/ @Respond_Sec=Respond_Sec,  
    @Resolve_Sec=Resolve_Sec, @Respond_Esc_Freq=Respond_Esc_Freq, @Respond_Esc_Sec=Respond_Esc_Sec,  
    @Respond_Esc_AgentId=Respond_Esc_AgentId, @Respond_Rem_Freq=Respond_Rem_Freq, @Respond_Rem_Sec=Respond_Rem_Sec,  
    @Respond_Rem_AgentId=Respond_Rem_AgentId, @Resolve_Rem_Freq=Resolve_Rem_Freq, @Resolve_Rem_Sec=Resolve_Rem_Sec,  
    @Resolve_Rem_AgentId=Resolve_Rem_AgentId  
  From #tbl_SLASetting   
  Where RowId=@iSLASettingId  
  
  print   '@SLA_ID: ' + cast(@SLA_ID as varchar)  
  
  select @ResolutionEsc1Sec=Interval_Sec, @ResolutionEsc1AgentId=Assigned_to   
  from Serv_SLA_escalation_rule(nolock) where parentid=@ParentId and SLAID=@SLA_ID and Responselevel=1  
  
  select @ResolutionEsc2Sec=Interval_Sec, @ResolutionEsc2AgentId=Assigned_to   
  from Serv_SLA_escalation_rule(nolock) where parentid=@ParentId and SLAID=@SLA_ID and Responselevel=2  
  
  select @ResolutionEsc3Sec=Interval_Sec, @ResolutionEsc3AgentId=Assigned_to   
  from Serv_SLA_escalation_rule(nolock) where parentid=@ParentId and SLAID=@SLA_ID and Responselevel=3  
  
  select @ResolutionEsc4Sec=Interval_Sec, @ResolutionEsc4AgentId=Assigned_to   
  from Serv_SLA_escalation_rule(nolock) where parentid=@ParentId and SLAID=@SLA_ID and Responselevel=4  
  
  print '@ResolutionEsc1Sec: ' + cast(@ResolutionEsc1Sec as varchar) + ', @ResolutionEsc1AgentId: ' + cast(@ResolutionEsc1AgentId as varchar) + ', @ResolutionEsc2Sec: ' + cast(@ResolutionEsc2Sec as varchar) + ', @ResolutionEsc2AgentId: ' + cast(@ResolutionEsc2AgentId as varchar) + ', @ResolutionEsc3Sec: ' + cast(@ResolutionEsc3Sec as varchar) + ', @ResolutionEsc3AgentId: ' + cast(@ResolutionEsc3AgentId as varchar) + ', @ResolutionEsc4Sec: ' + cast(@ResolutionEsc4Sec as varchar) + ', @ResolutionEsc4AgentId: ' + cast(@ResolutionEsc4AgentId as varchar)  
  
  select @Apply_GroupId=case when @Apply_GroupId is null then (case when Apply_to='Group' then isnull((select top 1     GroupId from Serv_Group_Mast(nolock) where group_name=Apply_val),0) else null end) else @Apply_GroupId end,  
    @Apply_TicketTypeId=case when @Apply_TicketTypeId is null then (case when Apply_to='Type' then isnull((select top 1 Type_ID from Serv_TicketType_Mast(nolock) where Type_Desc=Apply_val),0) else null end) else  @Apply_TicketTypeId end,  
    @Apply_Source=case when @Apply_Source is null then (case when Apply_to='Source' then Apply_val else null end) else @Apply_Source end,   
    @Apply_Product=case when @Apply_Product is null then (case when Apply_to='Product' then Apply_val else null end) else @Apply_Product end,   
    @Apply_Company=case when @Apply_Company is null then (case when Apply_to='Company' then Apply_val else null end) else @Apply_Company end  
  from Serv_SLA_ApplyRule(nolock)  
  where parent_id=@ParentId and SLAID=@SLA_ID  
  
  print '@Apply_Company: ' + isnull(@Apply_Company, 'null') + ' , @Apply_Source: ' + isnull(@Apply_Source, 'null') + ' , @Apply_Product: ' + isnull(@Apply_Product, 'null') + ' , @Apply_GroupId: ' + isnull(cast(@Apply_GroupId as varchar),'null') + ' , @Apply_TicketTypeId: ' + isnull(cast(@Apply_TicketTypeId as varchar),'null')  
  
  Update TL   
  Set  TL.SLAID = @SLA_ID,  
    TL.IsResolutionRem=Case When ERH.IsResolutionRem is null or ERH.ResolutionRemDate is null Then (case when DATEADD(ss,@Resolve_Sec+@Resolve_Rem_Sec,Date_Created) < GETDATE() then 1 else 0 end) Else null End,  
    TL.ResolutionRemAgentId=Case When ERH.ResolutionRemAgentId is null or ERH.ResolutionRemDate is null Then (case when DATEADD(ss,@Resolve_Sec+@Resolve_Rem_Sec,Date_Created) < GETDATE() then @Resolve_Rem_AgentId else 0 end) Else null End,  
    TL.IsResponseEsc=Case When ERH.IsResponseEsc is null or ERH.ResponseEscDate is null Then (case when DATEADD(ss,@Respond_Sec+@Respond_Esc_Sec,Date_Created) < GETDATE() then 1 else 0 end) Else null End,  
    TL.ResponseEscAgentId=Case When ERH.ResponseEscAgentId is null or ERH.ResponseEscDate is null Then (case when DATEADD(ss,@Respond_Sec+@Respond_Esc_Sec,Date_Created) < GETDATE() then @Respond_Esc_AgentId else 0 end) Else null End,  
    TL.IsResponseRem=Case When ERH.IsResponseRem is null or ERH.ResponseRemDate is null Then (case when DATEADD(ss,@Respond_Sec+@Respond_Rem_Sec,Date_Created) < GETDATE() then 1 else 0 end) Else null End,  
    TL.ResponseRemAgentId=Case When ERH.ResponseRemAgentId is null or ERH.ResponseRemDate is null Then (case when DATEADD(ss,@Respond_Sec+@Respond_Rem_Sec,Date_Created) < GETDATE() then @Respond_Rem_AgentId else 0 end) Else null End,  
    TL.IsResolutionEsc1=Case When ERH.IsResolutionEsc1 is null or ERH.ResolutionEsc1Date is null Then (case when DATEADD(ss,@Resolve_Sec+@ResolutionEsc1Sec,Date_Created) < GETDATE() then 1 else 0 end) Else null End,  
    TL.ResolutionEsc1AgentId=Case When ERH.ResolutionEsc1AgentId is null or ERH.ResolutionEsc1Date is null Then (case when DATEADD(ss,@Resolve_Sec+@ResolutionEsc1Sec,Date_Created) < GETDATE() then @ResolutionEsc1AgentId else 0 end) Else null End,  
    TL.IsResolutionEsc2=Case When ERH.IsResolutionEsc2 is null or ERH.ResolutionEsc2Date is null Then (case when DATEADD(ss,@Resolve_Sec+@ResolutionEsc2Sec,Date_Created) < GETDATE() then 1 else 0 end) Else null End,  
    TL.ResolutionEsc2AgentId=Case When ERH.ResolutionEsc2AgentId is null or ERH.ResolutionEsc2Date is null Then (case when DATEADD(ss,@Resolve_Sec+@ResolutionEsc2Sec,Date_Created) < GETDATE() then @ResolutionEsc2AgentId else 0 end) Else null End,  
    TL.IsResolutionEsc3=Case When ERH.IsResolutionEsc3 is null or ERH.ResolutionEsc3Date is null Then (case when DATEADD(ss,@Resolve_Sec+@ResolutionEsc3Sec,Date_Created) < GETDATE() then 1 else 0 end) Else null End,  
    TL.ResolutionEsc3AgentId=Case When ERH.ResolutionEsc3AgentId is null or ERH.ResolutionEsc3Date is null Then (case when DATEADD(ss,@Resolve_Sec+@ResolutionEsc3Sec,Date_Created) < GETDATE() then @ResolutionEsc3AgentId else 0 end) Else null End,  
    TL.IsResolutionEsc4=Case When ERH.IsResolutionEsc4 is null or ERH.ResolutionEsc4Date is null Then (case when DATEADD(ss,@Resolve_Sec+@ResolutionEsc4Sec,Date_Created) < GETDATE() then 1 else 0 end) Else null End,  
    TL.ResolutionEsc4AgentId=Case When ERH.ResolutionEsc4AgentId is null or ERH.ResolutionEsc4Date is null Then (case when DATEADD(ss,@Resolve_Sec+@ResolutionEsc4Sec,Date_Created) < GETDATE() then @ResolutionEsc4AgentId else 0 end) Else null End  
  -- declare @SLA_ID bigint=710, @Apply_GroupId bigint, @Apply_TicketTypeId bigint, @Apply_Source nvarchar(400), @Apply_Product nvarchar(400), @Apply_Company nvarchar(400) select *  
  From #tbl_TicketList TL left join tbl_sm_SLA_ESC_REM_History(nolock) ERH  
  On  TL.TicketID = ERH.TicketId and ERH.SLAID=@SLA_ID  
  Where TL.SLAID = 0 and   
    isnull(TL.Company,'') = case when @Apply_Company is null then isnull(TL.Company,'') else @Apply_Company end and  
    isnull(TL.Source,'') = case when @Apply_Source is null then isnull(TL.Source,'') else @Apply_Source end and  
    isnull(TL.Product,'') = case when @Apply_Product is null then isnull(TL.Product,'') else @Apply_Product end and  
    isnull(TL.Assign_Group,0) = case when @Apply_GroupId is null then isnull(TL.Assign_Group,0) else @Apply_GroupId end and  
    isnull(TL.Ticket_type,0) = case when @Apply_TicketTypeId is null then isnull(TL.Ticket_type,0) else @Apply_TicketTypeId end  
   
  Select @ResolutionEsc1Sec=0, @ResolutionEsc1AgentId=0, @ResolutionEsc2Sec=0, @ResolutionEsc2AgentId=0,  
    @ResolutionEsc3Sec=0, @ResolutionEsc3AgentId=0, @ResolutionEsc4Sec=0, @ResolutionEsc4AgentId=0,  
    @Apply_Company=null, @Apply_Source=null, @Apply_Product=null, @Apply_GroupId=null, @Apply_TicketTypeId=null  
  
  Set @iSLASettingId=@iSLASettingId+1  
 End  
  
 While(@iTL <= @TLCnt)  
 Begin  
  Select @IsResponseRem=IsResponseRem, @ResponseRemAgentId=ResponseRemAgentId, @TicketId=TicketId,  
    @IsResponseEsc=IsResponseEsc, @ResponseEscAgentId=ResponseEscAgentId, @ser_user_id=User_id,  
    @IsResolutionRem=IsResolutionRem, @ResolutionRemAgentId=ResolutionRemAgentId,   
    @IsResolutionEsc1=IsResolutionEsc1, @ResolutionEsc1AgentId=ResolutionEsc1AgentId,  
    @IsResolutionEsc2=IsResolutionEsc2, @ResolutionEsc2AgentId=ResolutionEsc2AgentId,  
    @IsResolutionEsc3=IsResolutionEsc3, @ResolutionEsc3AgentId=ResolutionEsc3AgentId,  
    @IsResolutionEsc4=IsResolutionEsc4, @ResolutionEsc4AgentId=ResolutionEsc4AgentId  
  From #tbl_TicketList  
  Where RowId = @iTL  
  
  print '@IsResponseRem: ' + isnull(cast(@IsResponseRem as varchar),'null') + ' ,@ResponseRemAgentId: ' + isnull(cast(@ResponseRemAgentId as varchar),'null') + ' ,@IsResponseEsc: ' + isnull(cast(@IsResponseEsc as varchar),'null') + ' ,@ResponseEscAgentId:
 ' + isnull(cast(@ResponseEscAgentId as varchar),'null') + ' ,@IsResolutionRem: ' + isnull(cast(@IsResolutionRem as varchar),'null') + ' ,@ResolutionRemAgentId:' + isnull(cast(@ResolutionRemAgentId as varchar),'null') + ' ,@IsResolutionEsc1: ' + isnull(cast(@IsResolutionEsc1 as varchar),'null') + ' ,@ResolutionEsc1AgentId: ' + isnull(cast(@ResolutionEsc1AgentId as varchar),'null') + ' ,@IsResolutionEsc2: ' + isnull(cast(@IsResolutionEsc2 as varchar),'null') + ' ,@ResolutionEsc2AgentId: ' + isnull(cast(@ResolutionEsc2AgentId as varchar),'null') + ' ,@IsResolutionEsc3: ' + isnull(cast(@IsResolutionEsc3 as varchar),'null') + ' ,@ResolutionEsc3AgentId: ' + isnull(cast(@ResolutionEsc3AgentId as varchar),'null') + ' ,@IsResolutionEsc4: ' + isnull(cast(@IsResolutionEsc4 as varchar),'null') + ' ,@ResolutionEsc4AgentId: ' + isnull(cast(@ResolutionEsc4AgentId as varchar),'null') + ' ,@TicketId: ' + isnull(cast(@TicketId as varchar),'null') + ' ,@ser_user_id: ' + isnull(cast(@ser_user_id as varchar),'null')  
  
  If(@IsResponseRem=1)  
  Begin  
   exec serv_Raise_emailNotification_support1 @TicketId, @ParentId, 0, @ser_user_id, @ResponseRemAgentId, 'First Response SLA Reminder','Agent'  
   Update #tbl_TicketList Set ResponseRemDate=getdate() Where RowId = @iTL  
  End  
  
  If(@IsResponseEsc=1)  
  Begin  
   exec serv_Raise_emailNotification_support1 @TicketId, @ParentId, 0, @ser_user_id, @ResponseEscAgentId, 'First Response SLA Violation','Agent'  
   Update #tbl_TicketList Set ResponseEscDate=getdate() Where RowId = @iTL  
  End  
  
  If(@IsResolutionRem=1)  
  Begin  
   exec serv_Raise_emailNotification_support1 @TicketId, @ParentId, 0, @ser_user_id, @ResolutionRemAgentId, 'Resolution Time SLA Reminder','Agent'  
   Update #tbl_TicketList Set ResolutionRemDate=getdate() Where RowId = @iTL  
  End  
  
  If(@IsResolutionEsc1=1)  
  Begin  
   exec serv_Raise_emailNotification_support1 @TicketId, @ParentId, 0, @ser_user_id, @ResolutionEsc1AgentId, 'Resolution Time SLA Violation','Agent'  
   Update #tbl_TicketList Set ResolutionEsc1Date=getdate() Where RowId = @iTL  
  End  
  
  If(@IsResolutionEsc2=1)  
  Begin  
   exec serv_Raise_emailNotification_support1 @TicketId, @ParentId, 0, @ser_user_id, @ResolutionEsc2AgentId, 'Resolution Time SLA Violation','Agent'  
   Update #tbl_TicketList Set ResolutionEsc2Date=getdate() Where RowId = @iTL  
  End  
  
  If(@IsResolutionEsc3=1)  
  Begin  
   exec serv_Raise_emailNotification_support1 @TicketId, @ParentId, 0, @ser_user_id, @ResolutionEsc3AgentId, 'Resolution Time SLA Violation','Agent'  
   Update #tbl_TicketList Set ResolutionEsc3Date=getdate() Where RowId = @iTL  
  End  
  
  If(@IsResolutionEsc4=1)  
  Begin  
   exec serv_Raise_emailNotification_support1 @TicketId, @ParentId, 0, @ser_user_id, @ResolutionEsc4AgentId, 'Resolution Time SLA Violation','Agent'  
   Update #tbl_TicketList Set ResolutionEsc4Date=getdate() Where RowId = @iTL  
  End  
  
  Set @iTL = @iTL + 1  
  
  Select @IsResponseRem=0, @ResponseRemAgentId=0, @TicketId=0,  
    @IsResponseEsc=0, @ResponseEscAgentId=0, @ser_user_id=0,  
    @IsResolutionRem=0, @ResolutionRemAgentId=0,   
    @IsResolutionEsc1=0, @ResolutionEsc1AgentId=0,  
    @IsResolutionEsc2=0, @ResolutionEsc2AgentId=0,  
    @IsResolutionEsc3=0, @ResolutionEsc3AgentId=0,  
    @IsResolutionEsc4=0, @ResolutionEsc4AgentId=0  
  
 End  
  
 Update  ERH  
 Set  ERH.IsResponseRem=case when TL.IsResponseRem is null then ERH.IsResponseRem else TL.IsResponseRem end,   
   ERH.ResponseRemAgentId=case when TL.ResponseRemAgentId is null then ERH.ResponseRemAgentId else TL.ResponseRemAgentId end,  
   ERH.ResponseRemDate=case when TL.ResponseRemDate is null then ERH.ResponseRemDate else TL.ResponseRemDate end,   
   ERH.IsResponseEsc=case when TL.IsResponseEsc is null then ERH.IsResponseEsc else TL.IsResponseEsc end,  
   ERH.ResponseEscAgentId=case when TL.ResponseEscAgentId is null then ERH.ResponseEscAgentId else TL.ResponseEscAgentId end,   
   ERH.ResponseEscDate=case when TL.ResponseEscDate is null then ERH.ResponseEscDate else TL.ResponseEscDate end,  
   ERH.IsResolutionRem=case when TL.IsResolutionRem is null then ERH.IsResolutionRem else TL.IsResolutionRem end,   
   ERH.ResolutionRemAgentId=case when TL.ResolutionRemAgentId is null then ERH.ResolutionRemAgentId else TL.ResolutionRemAgentId end,  
   ERH.ResolutionRemDate=case when TL.ResolutionRemDate is null then ERH.ResolutionRemDate else TL.ResolutionRemDate end,   
   ERH.IsResolutionEsc1=case when TL.IsResolutionEsc1 is null then ERH.IsResolutionEsc1 else TL.IsResolutionEsc1 end,  
   ERH.ResolutionEsc1AgentId=case when TL.ResolutionEsc1AgentId is null then ERH.ResolutionEsc1AgentId else TL.ResolutionEsc1AgentId end,   
   ERH.ResolutionEsc1Date=case when TL.ResolutionEsc1Date is null then ERH.ResolutionEsc1Date else TL.ResolutionEsc1Date end,  
   ERH.IsResolutionEsc2=case when TL.IsResolutionEsc2 is null then ERH.IsResolutionEsc2 else TL.IsResolutionEsc2 end,   
   ERH.ResolutionEsc2AgentId=case when TL.ResolutionEsc2AgentId is null then ERH.ResolutionEsc2AgentId else TL.ResolutionEsc2AgentId end,  
   ERH.ResolutionEsc2Date=case when TL.ResolutionEsc2Date is null then ERH.ResolutionEsc2Date else TL.ResolutionEsc2Date end,   
   ERH.IsResolutionEsc3=case when TL.IsResolutionEsc3 is null then ERH.IsResolutionEsc3 else TL.IsResolutionEsc3 end,  
   ERH.ResolutionEsc3AgentId=case when TL.ResolutionEsc3AgentId is null then ERH.ResolutionEsc3AgentId else TL.ResolutionEsc3AgentId end,   
   ERH.ResolutionEsc3Date=case when TL.ResolutionEsc3Date is null then ERH.ResolutionEsc3Date else TL.ResolutionEsc3Date end,  
   ERH.IsResolutionEsc4=case when TL.IsResolutionEsc4 is null then ERH.IsResolutionEsc4 else TL.IsResolutionEsc4 end,   
   ERH.ResolutionEsc4AgentId=case when TL.ResolutionEsc4AgentId is null then ERH.ResolutionEsc4AgentId else TL.ResolutionEsc4AgentId end,  
   ERH.ResolutionEsc4Date=case when TL.ResolutionEsc4Date is null then ERH.ResolutionEsc4Date else TL.ResolutionEsc4Date end  
 From #tbl_TicketList TL inner join tbl_sm_SLA_ESC_REM_History ERH  
 On  TL.TicketID = ERH.TicketID  
  
 insert into tbl_sm_SLA_ESC_REM_History  
 Select  TL.TicketId, TL.SLAID, TL.ParentID, TL.IsResponseRem, TL.ResponseRemAgentId, TL.ResponseRemDate, TL.IsResponseEsc,  
   TL.ResponseEscAgentId, TL.ResponseEscDate, TL.IsResolutionRem, TL.ResolutionRemAgentId, TL.ResolutionRemDate,  
   TL.IsResolutionEsc1, TL.ResolutionEsc1AgentId, TL.ResolutionEsc1Date, TL.IsResolutionEsc2,  
   TL.ResolutionEsc2AgentId, TL.ResolutionEsc2Date, TL.IsResolutionEsc3, TL.ResolutionEsc3AgentId,   
   TL.ResolutionEsc3Date, TL.IsResolutionEsc4, TL.ResolutionEsc4AgentId, TL.ResolutionEsc4Date, GETDATE()  
 From #tbl_TicketList TL Left join tbl_sm_SLA_ESC_REM_History(nolock) ERH  
 On  TL.TicketID = ERH.TicketID  
 Where ERH.TicketID is null and TL.SLAID > 0  
  
 Set @iPId=@iPId+1  
 Set @iSLASettingId=1  
 Set @iTL=1  
  
 truncate table #tbl_TicketList  
 truncate table #tbl_SLASetting  
End  
  
  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_SM_CloneDeleteIncentive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*


*/

CREATE   PROC  usp_SM_CloneDeleteIncentive
(
	@P_IncentiveID int,
    @P_OPTION int,
    @P_USERID bigint
)
as begin
	
	DECLARE @PARENTID BIGINT = 0  , @W_Incentive_ID INT =0 , @K_MAX_ID BIGINT =0;
	SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_USERID   ;


	IF (@P_OPTION = 1)
	BEGIN

	SELECT @K_MAX_ID = COALESCE(MAX(ID),0) +1 FROM tbl_SM_Employee_Incentive(nolock);
		
	INSERT INTO tbl_SM_Employee_Incentive ( Incentive_name,
		incentive_type,
		Reward_type,
		Performance_json,
		Milestone_json,
		Consistency_json,
		Special_reco_json,
		Roles_json,
		Is_expirable,
		Exp_date,
		created_by,
		created_date,
		IsActive)
	SELECT  concat( Incentive_name, convert(varchar,@K_MAX_ID)) as incentive_name,
		incentive_type,
		Reward_type,
		Performance_json,
		Milestone_json,
		Consistency_json,
		Special_reco_json,
		Roles_json,
		Is_expirable,
		Exp_date,
		@P_USERID,
		GETDATE(),
		IsActive
		FROM tbl_SM_Employee_Incentive(nolock)
		WHERE ID = @P_IncentiveID  ;
		
		SET @W_Incentive_ID = SCOPE_IDENTITY();

		print '@W_Incentive_ID-> '+ CONVERT(VARCHAR, @W_Incentive_ID)  ;

		SELECT 'Record Cloned.' as Message

	END
	ELSE IF (@P_OPTION = 2)
	BEGIN
		
		DELETE FROM tbl_SM_Employee_Incentive WHERE ID = @P_IncentiveID;   
		 
		SELECT 'Record Deleted.' as Message

	END
end


GO

/* ============================================================
   Procedure: [dbo].[USP_SM_CloneDeleteMiles]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
 
exec   USP_SM_CloneDeleteMiles 6, 1, 32222
 
 */

CREATE   PROC USP_SM_CloneDeleteMiles
(
	@P_MILE_ID INT,
	@P_ISACTIVE INT,
	@P_USERID INT,
	@P_OPTION INT =1   ----  (1) clone   , (2) -- delete
)
AS
BEGIN
	

	DECLARE @PARENTID BIGINT = 0  , @W_MILE_ID INT =0
	SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_USERID   


	IF (@P_OPTION = 1)
	BEGIN
		INSERT INTO tbl_SM_MileStones ( Milestone_Name,
										Event_name,
										Cond_json,
										Alert_json,
										IsActive,
										ParentId,
										Create_by,
										created_date )
										SELECT   Milestone_Name, 
										Event_name,
										Cond_json,
										Alert_json,
										IsActive ,
										@PARENTID , 
										@P_USERID,
										GETDATE() 
										FROM tbl_SM_MileStones(NOLOCK)  WHERE ID = @P_MILE_ID  AND ParentId =@PARENTID
		
		SET @W_MILE_ID = SCOPE_IDENTITY();

		INSERT INTO TBL_SM_MILESTONEALERTMSGMASTER ( MODE_SRNO,
													MODE_NAME,
													MODE_JSON,
													MSG_TIME_JSON,
													PARENTID,
													MILE_ID,
													CREATED_BY,
													CREATED_DATE )
										SELECT		MODE_SRNO,
													MODE_NAME,
													MODE_JSON,
													MSG_TIME_JSON,
													PARENTID,
													@W_MILE_ID,
													@P_USERID,
													GETDATE() FROM TBL_SM_MILESTONEALERTMSGMASTER(NOLOCK) 
													where MILE_ID =@P_MILE_ID 

		
		SELECT 'Record Cloned.'

	END
	ELSE IF (@P_OPTION = 2)
	BEGIN
		
		DELETE FROM tbl_SM_MileStones WHERE ID = @P_MILE_ID  AND ParentId =@PARENTID
		DELETE FROM TBL_SM_MILESTONEALERTMSGMASTER WHERE MILE_ID= @P_MILE_ID

		SELECT 'Record Deleted.'
	END

	


END





GO

