   Procedure: [dbo].[USP_SM_CloneDeleteScoring]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*

USP_SM_CloneDeleteScoring  1,1,32222,1

select * from tbl_SM_ScoringRule

*/



CREATE   PROC USP_SM_CloneDeleteScoring
(
	@P_RULE_ID int,
    @P_ISACTIVE int,
    @P_USERID bigint,
    @P_OPTION int
)
AS 
BEGIN

	--DECLARE @PARENTID BIGINT = 0  , 
	--SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_USERID   

	declare @maxRuleid int =  0 , @W_RULE_ID INT =0;

	select  @maxRuleid = (coalesce( max(Id),0) +1) from tbl_SM_ScoringRule ;

	IF (@P_OPTION = 1)
	BEGIN
	
	INSERT INTO tbl_SM_ScoringRule (Rule_name,
		Activity_id,
		ApplicableTo,
		Role_name,
		Points_type,
		eventid,
		Points,
		Percentage,
		range_from,
		range_to,
		range_json,
		rule_desc,
		Created_by,
		IsActive,
		Created_date,
		modify_date,
		modified_by)
		
	SELECT (Rule_name ) ,  --- CONVERT( varchar, @maxRuleid ) 
		Activity_id,
		ApplicableTo,
		Role_name,
		Points_type,
		eventid,
		Points,
		Percentage,
		range_from,
		range_to,
		range_json,
		rule_desc,
		@P_USERID,
		IsActive,
		GETDATE(),
		NULL,
		NULL
		FROM tbl_SM_ScoringRule(NOLOCK) 
		WHERE ID = @P_RULE_ID   
		
		SET @W_RULE_ID = SCOPE_IDENTITY();

		print '@W_RULE_ID-> '+ CONVERT(VARCHAR, @W_RULE_ID) ;

		INSERT INTO tbl_SM_ScoringCondition ( Rule_id,
											Seq_no,
											Field,
											Operatore,
											f_value,
											Conjunction,
											Active_status )
											SELECT	@W_RULE_ID,
											Seq_no,
											Field,
											Operatore,
											f_value,
											Conjunction,
											Active_status 
											FROM tbl_SM_ScoringCondition(NOLOCK) 
											where Rule_id =@P_RULE_ID 

		
		SELECT 'Record Cloned.'

	END
	ELSE IF (@P_OPTION = 2)
	BEGIN
		
		DELETE FROM tbl_SM_ScoringRule WHERE ID = @P_RULE_ID  
		DELETE FROM tbl_SM_ScoringCondition WHERE Rule_id= @P_RULE_ID

		SELECT 'Record Deleted.'
	END


END


