-- exec usp_sm_ConvertMailToTicket @ImportData=N'[{"Ser_User_ID":2360,"parentid":335,"FromMail":"asd@Support.appmails.in.net","MailDate":"2021-01-07T03:38:28","MailSubject":"New Ticket created  #ticket No:335_0011793#","MailContent":"Hi,  A new support ticket has been created by    at      Jan  6 2021  5:11AM .  The ticket is available at  http://kit19.com/Support/signin.aspx?tktn=335_0011793    Regards,                                                      http://kit19.com/Support/signin.aspx <br/><br/>To stop receiving email please click on <a alt='''' href=http://kitever.in.net/subscription.aspx?Emails=asd@Support.appmails.in.net&ReplyTo=asd@Support.appmails.in.net&TemplateID=&UserID=335>unsubscribe</a> <br/> Having Second Thoughts? Wish to receive such mails? <a alt='''' href=http://kitever.in.net/subscription.aspx?Emails=asd@Support.appmails.in.net&TemplateID=&UserID=335>Optin</a>\r\n","DateCreated":"2021-01-07T15:38:33.5480186","ToEmail":"asd@Support.appmails.in.net","ticketNo":"","requester":"","msgid":"<01010176dc51ab81-1bde3555-c1b8-48e6-8b6f-222774a2cfc2-000000@us-west-2.amazonses.com>"}]'
CREATE   PROCEDURE [dbo].[usp_sm_ConvertMailToTicket]
(
	@ImportData nvarchar(max)
)
as
Begin
-- declare @ImportData  nvarchar(max)=N'[{"Ser_User_ID":2360,"parentid":335,"FromMail":"asd@Support.appmails.in.net","MailDate":"2021-01-07T03:38:28","MailSubject":"New Ticket created  #ticket No:335_0011793#","MailContent":"Hi,  A new support ticket has been created by    at      Jan  6 2021  5:11AM .  The ticket is available at  http://kit19.com/Support/signin.aspx?tktn=335_0011793    Regards,                                                      http://kit19.com/Support/signin.aspx <br/><br/>To stop receiving email please click on <a alt='''' href=http://kitever.in.net/subscription.aspx?Emails=asd@Support.appmails.in.net&ReplyTo=asd@Support.appmails.in.net&TemplateID=&UserID=335>unsubscribe</a> <br/> Having Second Thoughts? Wish to receive such mails? <a alt='''' href=http://kitever.in.net/subscription.aspx?Emails=asd@Support.appmails.in.net&TemplateID=&UserID=335>Optin</a>\r\n","DateCreated":"2021-01-07T15:38:33.5480186","ToEmail":"asd@Support.appmails.in.net","ticketNo":"","requester":"","msgid":"<01010176dc51ab81-1bde3555-c1b8-48e6-8b6f-222774a2cfc2-000000@us-west-2.amazonses.com>"}]'

	if object_id('tempdb..#tblAllTicketMailFields') is not null begin drop table #tblAllTicketMailFields end
	if object_id('tempdb..#tmpTicketMailSrc') is not null begin drop table #tmpTicketMailSrc end

	declare @RowData nvarchar(max), @FieldNames nvarchar(max)='', @SQLString nvarchar(max)='', @ParmDefinition nvarchar(500),
	@fieldName varchar(50)='', @iter int=1, @RowCnt int=0, @MailId bigint=0, @Mode varchar(5)='Add', @Pos int=0, 
	@TicketSource Varchar(20)='Mail';

	declare @Status as int, @TicketResponse as int, @SerUserId as bigint, @ParentId as bigint,
	@FromMail as nvarchar(250), @MailDate as datetime, @MailSubject  nvarchar(max) , @MailContent nvarchar(max),
	@Requester nvarchar(max), @TicketNo varchar(20), @TicketId as bigint=0, @TicketHistoryId bigint, @MsgId nvarchar(200);

	declare	@Prefix nvarchar(15), @CurNo int, @Priority int=3, @Remarks nvarchar(max)='', @TicketType int = 1, 
	@RaisedBy nvarchar(100)='', @AssignTo bigint=0, @AssignGroup bigint=0, @AssignBy bigint=0

	create table #tblAllTicketMailFields      
	(      
		RowId int identity(1,1),
		fieldName varchar(50),
		FieldType varchar(20)
	)      

	insert into #tblAllTicketMailFields
	values('Ser_User_ID','bigint'),('parentid','bigint'),('FromMail','varchar(1000)'),('MailDate','datetime'),('MailSubject','varchar(max)'),('MailContent','varchar(max)'),('DateCreated','datetime'),('ToEmail','varchar(1000)'),('ticketNo','varchar(1000)'),('requester','varchar(1000)'),('msgid','varchar(1000)')
	--select column_name,Data_Type from information_schema.columns 
	--where table_name='Serv_TicketMails' and column_name not in ('ID','ticketid','tickethistoryid','isautoassignprocessed')

	print '@ImportData: ' + @ImportData
    select top 1 @RowData=value from openjson(@ImportData)
    print '@RowData: ' + @RowData
    select @FieldNames=@FieldNames+'['+[Key]+'] varchar(1000),' from openjson(@RowData)
    print '@FieldNames1: ' + @FieldNames
    set @FieldNames= SUBSTRING(@FieldNames,1,len(@FieldNames)-1)
    print '@FieldNames2: ' + @FieldNames

	if exists(select [Key] from openjson(@RowData) where [Key] COLLATE SQL_Latin1_General_CP1_CI_AS not in (Select FieldName From #tblAllTicketMailFields))
	Begin
		print 'Invalid Field found in Import Data'
		return
	End
	Else
	Begin
		If exists(Select FieldName From #tblAllTicketMailFields Where FieldName COLLATE SQL_Latin1_General_CP1_CI_AS not in (select [Key] from openjson(@RowData)))
		Begin
			print 'Required Field Missing in Import Data'
		End
	End

	create table #tmpTicketMailSrc (id int identity);
	print 'alter table #tmpTicketMailSrc add ' + @FieldNames
	exec('alter table #tmpTicketMailSrc add ' + @FieldNames)
        
	Set @SQLString = N'insert into #tmpTicketMailSrc select * from openjson(@ImptData) with (' + @FieldNames + ')'         
        
    --SET @ParmDefinition = N'@ImptData nvarchar(max), @FldNames nvarchar(max)';          
    SET @ParmDefinition = N'@ImptData nvarchar(max)';          
          
    print @SQLString        
        
   --EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData, @FldNames=@FieldNames          
    EXECUTE sp_executesql @SQLString, @ParmDefinition, @ImptData = @ImportData          

	--select * from #tmpTicketMailSrc
	select @RowCnt=COUNT(*) from #tmpTicketMailSrc

	While(@iter <= @RowCnt)
	Begin
		select @SerUserId=[Ser_User_ID], @ParentId=parentid, @FromMail=FromMail, @MsgId=msgid, @MailDate=MailDate,
		@MailSubject=MailSubject, @MailContent =MailContent, @TicketNo=ticketNo, @Requester=requester 
		from #tmpTicketMailSrc 
		where id=@iter

		Set @RaisedBy = cast(@SerUserId as nvarchar)
		
		If(@TicketNo != '')
		Begin
			Set @Mode='Edit'
		End
		Else
		Begin
			set @Pos=CHARINDEX('#ticket No:',@MailSubject)+11
			If(@Pos > 0)
			Begin
				Set @TicketNo = trim(SUBSTRING(@MailSubject,@Pos,CHARINDEX('#',@MailSubject,@Pos)-@Pos))
				Set @Mode='Edit'
			End
			Else
			Begin
				Set @Mode='Add'
			End
		End

		print '@Mode=' + @Mode
		print '@TicketNo=' + @TicketNo

		If(@Mode='Add')
		Begin
			set @TicketResponse = 0

			If not exists(select * from Serv_ticket_AutoNo where ParentId = @ParentId and prefix not like 'T%')
			Begin
				insert into Serv_ticket_AutoNo (ParentId, user_id, prefix, curr_no)
				values (@ParentId,@ParentId,Convert(varchar(8),@ParentId)+'_',0 )
			End

			select @Prefix = prefix, @CurNo= curr_no
			from Serv_ticket_AutoNo WITH (UPDLOCK) where ParentId = @ParentId and prefix not like 'T%'

			update Serv_ticket_AutoNo set curr_no=curr_no+1
			where ParentId=@ParentId

			select @TicketNo = @Prefix+REPLACE(STR(@CurNo+1, 7), SPACE(1), '0')

			insert into Serv_TicketMaster
			(User_id, ParentID, TicketNo, Subject, Description, Priority, Requester, Ticket_type, AssignTo,
			Assign_Group, Assignedby, AssignedDateTime, Source)
			values 
			(@SerUserId, @ParentId, @TicketNo, @MailSubject, @MailContent, @Priority, @Requester, @TicketType, @AssignTo,
			@AssignGroup, @AssignBy, GETDATE(), @TicketSource)

			select @TicketId = SCOPE_IDENTITY()

			insert into dbo.Serv_TicketHistory 
			(TicketID, ParentID, User_id, SubmittedDate, Status, HistoryDate, Remarks, Priority, raisedby, TransferredTo,
			Assign_Group, Ticket_type) 
			values
			(@TicketId, @ParentId, @SerUserId, GETDATE(), 0, GETDATE(), @MailContent, @Priority, @RaisedBy, @AssignTo,
			@AssignGroup, @TicketType)

			select @TicketHistoryId=SCOPE_IDENTITY()

			exec Serv_Process_Ticket_Dispatch_support_withnoselection @ParentId,@TicketId 

		End
		Else
		Begin--Edit
			set @TicketResponse = 2

			Update Serv_TicketMaster 
			set Remarks=@MailContent, Status=case when [Status]=2 then 1 else [Status] end, @TicketId=TicketID,
				Update_By=@SerUserId, Update_date=GETDATE()
			where TicketNo = @TicketNo and ParentID = @ParentId

			insert into dbo.Serv_TicketHistory 
			(TicketID, ParentID, User_id, SubmittedDate, Status, HistoryDate, Remarks, Priority, Ticket_Response,
			 raisedby,Ticket_type )
			select TicketID, ParentID, User_id, GETDATE(), Status, GETDATE(), Remarks, Priority, @TicketResponse,
			 @RaisedBy, Ticket_type 
			from Serv_TicketMaster 
			where TicketID = @TicketId

			select @TicketHistoryId=SCOPE_IDENTITY()

		End

		print 'Ticketid=' + cast(@TicketId as varchar) + ',tickethistoryid=' + cast(@TicketHistoryId as varchar)

		INSERT INTO [dbo].[Serv_TicketMails]
				   ([UserID],[parentid],[FromMail],[MailDate],[MailSubject],[MailContent],
				    [DateCreated],[ToEmail],[requester],[ticketNo],[msgid],[ticketid],
					[tickethistoryid],[isautoassignprocessed])
		select		[Ser_User_ID], [parentid], [FromMail], Cast(left([MailDate],19) as datetime), [MailSubject], [MailContent],
					cast(left([DateCreated],19) as datetime), [ToEmail], [requester], @TicketNo, [msgid], @TicketId,
					@TicketHistoryId, 1
		from		#tmpTicketMailSrc
		where		id=@iter

		update spt_tkt_attach set Ticketid=@TicketId,tickethistoryid=@TicketHistoryId where msgid=@MsgId

		print '@iter=' + cast(@iter as varchar)

		Set @iter=@iter+1
		
	End

End



