CREATE   PROCEDURE [dbo].[usp_sm_CreateTicketFromMail]
(
	@ImportData TicketMails_Tbltype readonly
)
as
Begin
	-- declare @ImportData dbo.TicketMails_Tbltype insert into @ImportData values(2581,32222,N'ajittest195@gmail.com','2021-01-11 02:23:03',N'Test 123',N'Test 11th january','2021-01-11 02:26:38',N'abhshek.kumar@support.appmails.in.net',N'ajit test',N'',N'<CAG2T4Q7Ty2trnpqvy97FhCzXRG=+zYPBv05v09e4X98nHP_CiA@mail.gmail.com>')

	if object_id('tempdb..#tmpTicketMailSrc') is not null begin drop table #tmpTicketMailSrc end

	declare @iter int=1, @RowCnt int=0, @MailId bigint=0, @Mode varchar(5)='Add', @Pos int=0, 
	@TicketSource Varchar(20)='Mail';

	declare @Status as int, @TicketResponse as int, @SerUserId as bigint, @ParentId as bigint,
	@FromMail as nvarchar(250), @MailDate as datetime, @MailSubject  nvarchar(max) , @MailContent nvarchar(max),
	@Requester nvarchar(max), @TicketNo varchar(20), @TicketId as bigint=0, @TicketHistoryId bigint, @MsgId nvarchar(200);

	declare	@Prefix nvarchar(15), @CurNo int, @Priority int=3, @Remarks nvarchar(max)='', @TicketType int = 1, 
	@RaisedBy nvarchar(100)='', @AssignTo bigint=0, @AssignGroup bigint=0, @AssignBy bigint=0


	create table #tmpTicketMailSrc (
	id int identity,
	Ser_User_Id	bigint,
	parentid	bigint,
	FromMail	nvarchar(500),
	MailDate	datetime,
	MailSubject	nvarchar(max),
	MailContent	nvarchar(max),
	DateCreated	datetime,
	ToEmail	nvarchar(max),
	requester	nvarchar(500),
	ticketNo	nvarchar(50),
	msgid	nvarchar(2000)
	);
        
	insert into #tmpTicketMailSrc select * from @ImportData         
        
	select * from #tmpTicketMailSrc
	select @RowCnt=COUNT(*) from #tmpTicketMailSrc

	While(@iter <= @RowCnt)
	Begin
		select @SerUserId=[Ser_User_ID], @ParentId=parentid, @FromMail=FromMail, @MsgId=msgid, @MailDate=MailDate,
		@MailSubject=MailSubject, @MailContent =MailContent, @TicketNo=ticketNo, @Requester=requester 
		from #tmpTicketMailSrc 
		where id=@iter

		Set @RaisedBy = cast(@SerUserId as nvarchar)
		
		If(@TicketNo != '')
		Begin
			Set @Mode='Edit'
		End
		Else
		Begin
			--print @MailSubject
			set @Pos=CHARINDEX('#ticket No:',@MailSubject)+11
			If(@Pos > 11)
			Begin
				Set @TicketNo = trim(SUBSTRING(@MailSubject,@Pos,CHARINDEX('#',@MailSubject,@Pos)-@Pos))
				Set @Mode='Edit'
			End
			Else
			Begin
				Set @Mode='Add'
			End
		End

		print '@Mode=' + @Mode
		print '@TicketNo=' + @TicketNo

		If(@Mode='Add')
		Begin
			set @TicketResponse = 0

			If not exists(select * from Serv_ticket_AutoNo where ParentId = @ParentId and prefix not like 'T%')
			Begin
				insert into Serv_ticket_AutoNo (ParentId, user_id, prefix, curr_no)
				values (@ParentId,@ParentId,Convert(varchar(8),@ParentId)+'_',0 )
			End

			select @Prefix = prefix, @CurNo= curr_no
			from Serv_ticket_AutoNo WITH (UPDLOCK) where ParentId = @ParentId and prefix not like 'T%'

			update Serv_ticket_AutoNo set curr_no=curr_no+1
			where ParentId=@ParentId

			select @TicketNo = @Prefix+REPLACE(STR(@CurNo+1, 7), SPACE(1), '0')

			insert into Serv_TicketMaster
			(User_id, ParentID, TicketNo, Subject, Description, Priority, Requester, Ticket_type, AssignTo,
			Assign_Group, Assignedby, AssignedDateTime, Source)
			values 
			(@SerUserId, @ParentId, @TicketNo, @MailSubject, @MailContent, @Priority, @FromMail, @TicketType, @AssignTo,
			@AssignGroup, @AssignBy, GETDATE(), @TicketSource)

			select @TicketId = SCOPE_IDENTITY()

			insert into dbo.Serv_TicketHistory 
			(TicketID, ParentID, User_id, SubmittedDate, Status, HistoryDate, Remarks, Priority, raisedby, TransferredTo,
			Assign_Group, Ticket_type) 
			values
			(@TicketId, @ParentId, @SerUserId, GETDATE(), 0, GETDATE(), @MailContent, @Priority, @RaisedBy, @AssignTo,
			@AssignGroup, @TicketType)

			select @TicketHistoryId=SCOPE_IDENTITY()
			print '@ParentId:' + cast(isnull(@ParentId,0) as varchar)+ ', @TicketId: ' + cast(isnull(@TicketId,0) as varchar)
			
			exec serv_Raise_emailNotification_support1 @TicketId, @ParentId, @AssignGroup, @SerUserId, @AssignTo, 'New Ticket Created','Requester'   
			exec Serv_Process_Ticket_Dispatch_support_withnoselection @ParentId,@TicketId 

		End
		Else
		Begin--Edit
			set @TicketResponse = 2

			Update Serv_TicketMaster 
			set Remarks=@MailContent, Status=case when [Status] in (2,4) then 1 else [Status] end, @TicketId=TicketID,
				Update_By=@SerUserId, Update_date=GETDATE()
			where TicketNo = @TicketNo and ParentID = @ParentId

			insert into dbo.Serv_TicketHistory 
			(TicketID, ParentID, User_id, SubmittedDate, Status, HistoryDate, Remarks, Priority, Ticket_Response,
			 raisedby,Ticket_type, TransferredTo, Assign_Group)
			select TicketID, ParentID, User_id, GETDATE(), Status, GETDATE(), Remarks, Priority, @TicketResponse,
			 @RaisedBy, Ticket_type, AssignTo, Assign_Group 
			from Serv_TicketMaster 
			where TicketID = @TicketId

			select @TicketHistoryId=SCOPE_IDENTITY()

		End

		print 'Ticketid=' + cast(@TicketId as varchar) + ',tickethistoryid=' + cast(@TicketHistoryId as varchar)

		INSERT INTO [dbo].[Serv_TicketMails]
				   ([UserID],[parentid],[FromMail],[MailDate],[MailSubject],[MailContent],
				    [DateCreated],[ToEmail],[requester],[ticketNo],[msgid],[ticketid],
					[tickethistoryid],[isautoassignprocessed])
		select		[Ser_User_ID], [parentid], [FromMail], Cast(left([MailDate],19) as datetime), [MailSubject], [MailContent],
					cast(left([DateCreated],19) as datetime), [ToEmail], [requester], @TicketNo, [msgid], @TicketId,
					@TicketHistoryId, 1
		from		#tmpTicketMailSrc
		where		id=@iter

		update spt_tkt_attach set Ticketid=@TicketId,tickethistoryid=@TicketHistoryId where msgid=@MsgId

		print '@iter=' + cast(@iter as varchar)

		Set @iter=@iter+1
		
	End

End



