/* ============================================================
   Procedure: [dbo].[usp_SM_Employee_Incentive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_SM_Employee_Incentive
(
    @P_ID INT = 0,
    @P_Incentive_name VARCHAR(250),
    @P_incentive_type VARCHAR(250),
    @P_Reward_type VARCHAR(100),
    @P_Performance_json VARCHAR(MAX),
    @P_Milestone_json VARCHAR(MAX),
    @P_Consistency_json VARCHAR(MAX),
    @P_Special_reco_json VARCHAR(MAX),
	@P_reward_json VARCHAR(MAX),
    @P_Roles_json VARCHAR(MAX),
    @P_Expiry_date SMALLDATETIME,
    @P_USERID BIGINT ,
	@P_IsActive int
)
AS
BEGIN

	DECLARE @PARENTID BIGINT = 0  ,@W_MILE_ID INT , @W_MODE_COUNT INT, @W_LOOP_COUNT  INT= 1 , @W_MODE_NAME varchar(30);
	SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_USERID   
	
	IF (@P_INCENTIVE_NAME ='') BEGIN
		select 'Incentive name is blank' as Message
		return;
	END

    -- Check if incentive name already exists
    IF EXISTS (SELECT 1 FROM tbl_SM_Employee_Incentive(nolock) WHERE Incentive_name = @P_Incentive_name and id <> @P_ID AND ParentID =   @PARENTID  )
    BEGIN
        SELECT 'Incentive name already exists.' AS Message;
        RETURN;
    END

    -- Insert new record if ID is 0
    IF (@P_ID = 0)
    BEGIN
        INSERT INTO tbl_SM_Employee_Incentive
        (
            Incentive_name,
            incentive_type,
            Reward_type,
            Performance_json,
            Milestone_json,
            Consistency_json,
            Special_reco_json,
			Reward_json,
            Roles_json,
			Is_expirable,
            Exp_date,
            created_by,
            created_date,
			IsActive,
			ParentID
        )
        VALUES
        (
            @P_Incentive_name,
            @P_incentive_type,
            @P_Reward_type,
            @P_Performance_json,
            @P_Milestone_json,
            @P_Consistency_json,
            @P_Special_reco_json,
			@P_reward_json,
            @P_Roles_json,
			case when coalesce( @P_Expiry_date,'') <> '' then 1 else 0 end,
            @P_Expiry_date,
            @P_USERID,
            GETDATE(),
			@P_IsActive,
			@PARENTID
        );

        SELECT 'Record inserted' AS Message;
    END
    -- Update existing record if ID is not 0
    ELSE
    BEGIN
        UPDATE tbl_SM_Employee_Incentive 
        SET 
            Incentive_name = @P_Incentive_name,
            incentive_type = @P_incentive_type,
            Reward_type = @P_Reward_type,
            Performance_json = @P_Performance_json,
            Milestone_json = @P_Milestone_json,
            Consistency_json = @P_Consistency_json,
            Special_reco_json = @P_Special_reco_json,
			Reward_json = @P_reward_json,
            Roles_json = @P_Roles_json,
			Is_expirable = case when coalesce( @P_Expiry_date,'') <> '' then 1 else 0 end,
            Exp_date = @P_Expiry_date,
            Moified_by = @P_USERID,
            Modified_date = GETDATE(),
			IsActive = @P_IsActive,
			ParentID = @PARENTID
        WHERE ID = @P_ID;

        SELECT 'Record updated' AS Message;
    END
END



GO

