   Procedure: [dbo].[usp_sm_FilterLeadByNameEmailMobile]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec usp_sm_FilterLeadByNameEmailMobile @P_ID=32222, @SearchText='abhi', @FilterPattern='Name', @SearchPattern='Begin'
-- exec usp_sm_FilterLeadByNameEmailMobile @P_ID=32222, @SearchText='abhi', @FilterPattern='Name', @SearchPattern='Contain'
-- exec usp_sm_FilterLeadByNameEmailMobile @P_ID=32222, @SearchText='hek', @FilterPattern='Name', @SearchPattern='End'
-- exec usp_sm_FilterLeadByNameEmailMobile @P_ID=32222, @SearchText='abhi', @FilterPattern='Email', @SearchPattern='Begin'
-- exec usp_sm_FilterLeadByNameEmailMobile @P_ID=32222, @SearchText='abhi', @FilterPattern='Email', @SearchPattern='Contain'
-- exec usp_sm_FilterLeadByNameEmailMobile @P_ID=32222, @SearchText='gmail.com', @FilterPattern='Email', @SearchPattern='End'
-- exec usp_sm_FilterLeadByNameEmailMobile @P_ID=32222, @SearchText='989', @FilterPattern='Mobile', @SearchPattern='Begin'
-- exec usp_sm_FilterLeadByNameEmailMobile @P_ID=32222, @SearchText='989', @FilterPattern='Mobile', @SearchPattern='Contain'
-- exec usp_sm_FilterLeadByNameEmailMobile @P_ID=32222, @SearchText='989', @FilterPattern='Mobile', @SearchPattern='End'
CREATE   PROCEDURE [dbo].[usp_sm_FilterLeadByNameEmailMobile]
(
	@P_ID bigint,
	@SearchText varchar(100),
	@FilterPattern varchar(10)='Email',	--'Name','Mobile'
	@SearchPattern varchar(10)='Begin'  --'End','Contain'
)
AS
BEGIN

-- declare @P_ID bigint=32222,	@SearchText varchar(100)='989', @FilterPattern varchar(10)='Mobile',@SearchPattern varchar(10)='Contain'

If(@FilterPattern='Name')
Begin
	SELECT	Id as LeadId, PersonName=isnull(PersonName,''), 
			EmailID=isnull(EmailID,''), EmailID1=isnull(EmailID1,''), EmailID2=isnull(EmailID2,''), 
			MobileNo=isnull(MobileNo,''), MobileNo1=ISNULL(MobileNo1,''), MobileNo2=isnull(MobileNo2,''), 
			strLead=isnull(PersonName,'') + ' | ' + isnull(EmailID,'') + ', ' + isnull(EmailID1,'') + ', ' + isnull(EmailID2,'') + ' | ' + isnull(MobileNo,'') + ', ' + ISNULL(MobileNo1,'') + ', ' + isnull(MobileNo2,'')
	FROM	UserLeads
	WHERE	ParentID = @P_ID and 
			isnull(PersonName,'') like + Case @SearchPattern When 'Begin' Then @SearchText + '%' When 'Contain' Then '%' + @SearchText + '%' When 'End' Then '%' + @SearchText Else '' End
End

If(@FilterPattern='Email')
Begin
	SELECT	Id as LeadId, PersonName=isnull(PersonName,''), 
			EmailID=isnull(EmailID,''), EmailID1=isnull(EmailID1,''), EmailID2=isnull(EmailID2,''), 
			MobileNo=isnull(MobileNo,''), MobileNo1=ISNULL(MobileNo1,''), MobileNo2=isnull(MobileNo2,''), 
			strLead=isnull(PersonName,'') + ' | ' + isnull(EmailID,'') + ', ' + isnull(EmailID1,'') + ', ' + isnull(EmailID2,'') + ' | ' + isnull(MobileNo,'') + ', ' + ISNULL(MobileNo1,'') + ', ' + isnull(MobileNo2,'')
	FROM	UserLeads
	WHERE	ParentID = @P_ID and (
			isnull(EmailID,'') like + Case @SearchPattern When 'Begin' Then @SearchText + '%' When 'Contain' Then '%' + @SearchText + '%' When 'End' Then '%' + @SearchText Else '' End
			or
			isnull(EmailID1,'') like + Case @SearchPattern When 'Begin' Then @SearchText + '%' When 'Contain' Then '%' + @SearchText + '%' When 'End' Then '%' + @SearchText Else '' End
			or
			isnull(EmailID2,'') like + Case @SearchPattern When 'Begin' Then @SearchText + '%' When 'Contain' Then '%' + @SearchText + '%' When 'End' Then '%' + @SearchText Else '' End
			)
End

If(@FilterPattern='Mobile')
Begin
	SELECT	Id as LeadId, PersonName=isnull(PersonName,''), 
			EmailID=isnull(EmailID,''), EmailID1=isnull(EmailID1,''), EmailID2=isnull(EmailID2,''), 
			MobileNo=isnull(MobileNo,''), MobileNo1=ISNULL(MobileNo1,''), MobileNo2=isnull(MobileNo2,''), 
			strLead=isnull(PersonName,'') + ' | ' + isnull(EmailID,'') + ', ' + isnull(EmailID1,'') + ', ' + isnull(EmailID2,'') + ' | ' + isnull(MobileNo,'') + ', ' + ISNULL(MobileNo1,'') + ', ' + isnull(MobileNo2,'')
	FROM	UserLeads
	WHERE	ParentID = @P_ID and (
			isnull(MobileNo,'') like + Case @SearchPattern When 'Begin' Then @SearchText + '%' When 'Contain' Then '%' + @SearchText + '%' When 'End' Then '%' + @SearchText Else '' End
			or
			isnull(MobileNo1,'') like + Case @SearchPattern When 'Begin' Then @SearchText + '%' When 'Contain' Then '%' + @SearchText + '%' When 'End' Then '%' + @SearchText Else '' End
			or
			isnull(MobileNo2,'') like + Case @SearchPattern When 'Begin' Then @SearchText + '%' When 'Contain' Then '%' + @SearchText + '%' When 'End' Then '%' + @SearchText Else '' End
			)
End

END



