/* ============================================================
   Procedure: [dbo].[USP_SM_GET_EVENTPLACEHOLDERS]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
if object_id('USP_SM_GET_EVENTPLACEHOLDERS') is not null
begin
 drop procedure USP_SM_GET_EVENTPLACEHOLDERS
end

EXEC USP_SM_GET_EVENTPLACEHOLDERS  7

*/

CREATE   PROC USP_SM_GET_EVENTPLACEHOLDERS
(
	@P_EVENT_ID INT,
	@P_OPTION INT = 1
)
AS
BEGIN

	IF (@P_OPTION  = 1)
	BEGIN
			 SELECT EV.id [ID], (EV.EXPOSEDNAME) [NAME] FROM EVENTPLACEHOLDERS(NOLOCK)  EV
			 INNER JOIN ACTIVITYMASTER(NOLOCK)  AM ON EV.EVENTID = AM.ID
			 WHERE ISEXPOSED =1 AND ( DATATYPE like 'INT%' or DATATYPE like 'decimal%' or DATATYPE like 'numeric%') AND
			 ( (CASE WHEN  @P_EVENT_ID  = 0 THEN  '1' ELSE EV.eventid END )=   ( CASE WHEN   @P_EVENT_ID = 0 THEN '1' ELSE @P_EVENT_ID END ) )
	END
	ELSE IF (@P_OPTION  = 2) BEGIN
			 SELECT EV.id [ID], (EV.EXPOSEDNAME) [NAME] FROM EVENTPLACEHOLDERS(NOLOCK)  EV
			 INNER JOIN ACTIVITYMASTER(NOLOCK)  AM ON EV.EVENTID = AM.ID
			 WHERE ISEXPOSED =1 AND  ( (CASE WHEN  @P_EVENT_ID  = 0 THEN  '1' ELSE EV.eventid END) =   ( CASE WHEN   @P_EVENT_ID = 0 THEN '1' ELSE @P_EVENT_ID END ) )
			
	END
END








