/* ============================================================
   Procedure: [dbo].[USP_SM_GETALL_MILES]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
exec USP_SM_GETALL_MILES  '', 1, 34594

*/

CREATE   PROC USP_SM_GETALL_MILES
(
	@P_SEARCH_TEXT VARCHAR(200),
	@P_ISACTIVE INT,
	@P_USERID INT
)
AS
BEGIN
	
	DECLARE @PARENTID BIGINT = 0  
	SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_USERID   
	
	DECLARE @UserDetails  tbl_type_sm_UserDetails;

	INSERT INTO @UserDetails
	EXEC Use_GetUserDetails @PARENTID;


	SELECT 	
		MS.ID,
		Milestone_Name,
		Event_name,
		Cond_json,
		Alert_json,
		(SELECT TOP 1 MSG_TIME_JSON FROM TBL_SM_MILESTONEALERTMSGMASTER(NOLOCK)  WHERE MILE_ID = MS.ID  ) as MSG_TIME_JSON ,--MAL.MSG_TIME_JSON,
		(SELECT  MODE_NAME  FROM TBL_SM_MILESTONEALERTMSGMASTER (nolock) WHERE MILE_ID = MS.ID  and MODE_JSON <> '' FOR JSON PATH ) AS MODES  ,
		IsActive  
		from tbl_SM_MileStones(NOLOCK)  MS  
		--LEFT JOIN TBL_SM_MILESTONEALERTMSGMASTER  MAL ON MAL.MILE_ID = MS.ID
		WHERE MS.ParentId =@PARENTID AND Create_by in (select userid from @UserDetails) and
		(CASE WHEN @P_ISACTIVE >1 THEN '1' ELSE MS.ISACTIVE END) =(CASE WHEN @P_ISACTIVE >1 THEN '1' ELSE @P_ISACTIVE END)
		AND
		( 
			(CASE WHEN @P_SEARCH_TEXT = '' THEN '1' ELSE MS.MILESTONE_NAME END) like '%'+ (CASE WHEN @P_SEARCH_TEXT ='' THEN '1' ELSE @P_SEARCH_TEXT END) + '%'
			OR 	
			(CASE WHEN @P_SEARCH_TEXT = '' THEN '1' ELSE MS.EVENT_NAME END) like '%'+ (CASE WHEN @P_SEARCH_TEXT ='' THEN '1' ELSE @P_SEARCH_TEXT END) +'%'
		)


END


