/* ============================================================
   Procedure: [dbo].[usp_sm_getEventAmount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*
	declare	@W_AMOUNT BIGINT =0  ;
	exec usp_sm_getEventAmount  '{"Field":"AmountPaid","eventid":"27","From":"1","To":"1000","Points":"90"} ,{"Field":"AmountPaid","eventid":"27","From":"1001","To":"4000","Points":"150"}' ,
	10, 'tbl_LeadEventHistory' , 966487 , 0 , @W_AMOUNT output

	select @W_AMOUNT

*/

CREATE  PROC  [dbo].[usp_sm_getEventAmount]
(
	@P_RANGE_JSON  varchar(max),
	@P_ActivityID  INT ,
	@P_history_tableName VARCHAR(100),
	@P_History_row_id  BIGINT,
	@P_PERCENTAGE  INT,
	@W_AMOUNT BIGINT  OUTPUT
)
AS
BEGIN
	
		DECLARE @W_EVENT_TABLE VARCHAR(100) , @W_EXPOSED_NAME VARCHAR(100) , @W_REFID NVARCHAR(100)  , 
		@W_SQL_QUERY NVARCHAR(MAX) = '' , @W_POINTS INT =0 ;

		IF (@P_RANGE_JSON <>'')BEGIN
				
				CREATE TABLE #TempRangeTable (
						Field NVARCHAR(100),
						eventid INT,
						[From] INT,
						[To] INT,
						Points INT
					);

				DECLARE @json NVARCHAR(MAX) = N'['+@P_RANGE_JSON+']';

				print(@json)

		 		set @json = REPLACE(@json,'undefined','0')
				
				print(@json)

				INSERT INTO #TempRangeTable (Field, eventid, [From], [To], Points)
				SELECT  Field, eventid, [From] ,  [To] , Points
				FROM OPENJSON(@json)
				WITH (
					Field NVARCHAR(100) '$.Field',
					eventid INT '$.eventid',
					[From] INT '$.From',
					[To] INT '$.To',
					Points INT '$.Points'
				);

				-- Verify that the data was inserted
				---SELECT * FROM #TempRangeTable;
					
				SELECT  @W_EXPOSED_NAME = EXPOSEDNAME FROM eventplaceholders WHERE id = ( SELECT TOP 1 eventid  FROM #TempRangeTable );


		END
		ELSE IF (@P_PERCENTAGE <> 0 )BEGIN
			SELECT  @W_EXPOSED_NAME  =  EXPOSEDNAME FROM eventplaceholders WHERE id = ( SELECT eventid  FROM TBL_SM_SCORINGRULE WHERE ACTIVITY_ID = @P_ActivityID );
		END

		SET @W_SQL_QUERY = 'SELECT @W_EVENT_TABLE = reftables, @W_REFID = refids  	FROM '+ @P_history_tableName  +' (NOLOCK) 	WHERE historyID = '+ CONVERT( VARCHAR(100), @P_History_row_id) +'';
					
		PRINT @W_SQL_QUERY ;

		begin try

		EXEC sp_executesql @W_SQL_QUERY, N'@W_EVENT_TABLE NVARCHAR(MAX) OUTPUT, @W_REFID NVARCHAR(MAX) OUTPUT ',
							@W_EVENT_TABLE OUTPUT, @W_REFID OUTPUT;

             

		PRINT CONCAT('EXPOSED NAME ', @W_EXPOSED_NAME,'@W_EVENT_TABLE',@W_EVENT_TABLE,'@W_REFID',@W_REFID )
		-- Construct the dynamic SQL query

		SET @W_SQL_QUERY = N'SELECT [' + @W_EXPOSED_NAME + N'] FROM ' + @W_EVENT_TABLE + N' WHERE ID = ' + @W_REFID ;
		PRINT  @W_SQL_QUERY

		DECLARE @TempTable TABLE (AmountResult bigint);

		-- Execute the dynamic SQL query and store the result into the temporary table
		INSERT INTO @TempTable (AmountResult)
		EXEC (@W_SQL_QUERY )
		
		SELECT @w_amount = AMOUNTRESULT  FROM @TEMPTABLE 
		PRINT CONCAT('AMOUNT : ', CONVERT(VARCHAR , @W_AMOUNT));
		
		end try
		begin catch
		  exec usp_InsertErrorInfo
		end catch
		
end


GO

