/* ============================================================
   Procedure: [dbo].[usp_sm_GetSearchTicketDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_sm_GetSearchTicketDetails1 @TicketID=0,@ParentID=32222,@ser_user_id=0,@access_level='All Group'  
-- exec usp_sm_GetSearchTicketDetails1 @TicketID=0,@ParentID=335,@ser_user_id=111,@access_level=N'All Group',@RowFilter=N'',@OrderBy=N'AssignedDateTime ASC'  
-- exec usp_sm_GetSearchTicketDetails1 @TicketID=0,@ParentID=335,@ser_user_id=111,@access_level=N'All Group',@RowFilter=N' Requester  like  ''%hari%'' ',@OrderBy=N'Stat_Desc DESC'  
-- exec usp_sm_GetSearchTicketDetails @TicketID=0,@ParentID=32222,@ser_user_id=560,@access_level=N'All Group',@RowFilter=N'',@OrderBy=N'tm.Date_Created DESC'
CREATE   PROCEDURE [dbo].[usp_sm_GetSearchTicketDetails]  
(  
 @TicketID     BIGINT,  
 @ParentID     BIGINT,  
 @ser_user_id  BIGINT,  
 @access_level NVARCHAR(40),  
 @RowFilter nvarchar(max)='',  
 @OrderBy nvarchar(100)=''  
)  
AS  
BEGIN  
 -- declare @TicketID BIGINT=0,@ParentID BIGINT=32222,@ser_user_id BIGINT=0,@access_level NVARCHAR(40)='All Group', @RowFilter nvarchar(max)='', @OrderBy nvarchar(100)=''  
 -- declare @TicketID BIGINT=0,@ParentID BIGINT=32222,@ser_user_id BIGINT=0,@access_level NVARCHAR(40)='All Group', @RowFilter nvarchar(max)=' TicketNo=''32222_09'' ', @OrderBy nvarchar(100)=''  
 -- declare @TicketID BIGINT=0,@ParentID BIGINT=27828,@ser_user_id BIGINT=56,@access_level NVARCHAR(40)='Within Group', @RowFilter nvarchar(max)='', @OrderBy nvarchar(100)=''  
 -- declare @TicketID BIGINT=0,@ParentID BIGINT=35966,@ser_user_id BIGINT=1352,@access_level NVARCHAR(40)='self', @RowFilter nvarchar(max)='', @OrderBy nvarchar(100)=''  
 -- declare @TicketID BIGINT=0,@ParentID BIGINT=36967,@ser_user_id BIGINT=1924,@access_level NVARCHAR(40)='All Group', @RowFilter nvarchar(max)='', @OrderBy nvarchar(100)='tm.Date_Created DESC'  
 -- declare @TicketID BIGINT=0,@ParentID BIGINT=335,@ser_user_id BIGINT=2680,@access_level NVARCHAR(40)='Self', @RowFilter nvarchar(max)='', @OrderBy nvarchar(100)='tm.Date_Created DESC'  
 -- declare @TicketID BIGINT=0,@ParentID BIGINT=32222,@ser_user_id BIGINT=560,@access_level NVARCHAR(40)='All Group', @RowFilter nvarchar(max)='', @OrderBy nvarchar(100)='tm.Date_Created DESC'  
 declare @Query nvarchar(max)='', @ParmDefinition nvarchar(500)  
  
 IF @TicketID > 0  
 BEGIN  
  SELECT  [dbo].[fn_getusertimefromindiantime](@ParentID, [tm].[AssignedDateTime]) AS [AssignedDateTime],  
    [dbo].[fn_getusertimefromindiantime](@ParentID, [tm].[resolved_dt]) AS [resolved_dt],  
    [tm].TicketID,[tm].User_id,[tm].ParentID,[tm].TicketNo,[tm].Requester,[tm].Subject,[tm].Description,[tm].Status,[tm].Remarks,[tm].Note,[tm].Date_Created,[tm].Priority,[tm].AssignTo,[tm].Assign_Group,[tm].UserResponse,[tm].Active,[tm].Ticket_type,[tm].agrp_unassigned,[tm].Source,[tm].Product,[tm].Company,[tm].EmailId,[tm].domain,[tm].spam,[tm].deleted,[tm].skip_nticketmail,[tm].tkt_tag,[tm].Assignedby, ISNULL([stm].[Stat_Desc], 'New') AS [Stat_Desc],  
    CONVERT(DATE, [dbo].[fn_getusertimefromindiantime](@ParentID, [tm].[Date_Created])) AS [Date_Creat],  
    [GM].[Group_Name], [ud].[Login_id], SUBSTRING([tm].[Description], 0, 100) AS [shrtdesc],  
    [ud].[Name] AS [req_name], [ud].[Login_id],  
    ( CASE WHEN ISNULL([ag].[Login_id], '') != ''  
     THEN 'Agent : ' + [ag].[Login_id] + '(' + [ag]  
     .[Email] + ')'  
    ELSE( CASE  
       WHEN ISNULL([gm].[Group_Name], '') != ''  
        THEN 'Group : ' + [gm].[Group_Name]  
       ELSE 'Not Assigned'  
       END )  
    END ) AS [Agent_name],  
    (SELECT TOP 1 [dbo].[fn_getusertimefromindiantime](@ParentID, [SubmittedDate]) AS [SubmittedDate]  
     FROM          [Serv_TicketHistory]  
     WHERE        [TicketID] = [tm].[TicketID]  
     ORDER BY [SubmittedDate] DESC) AS [ldate],  
    ISNULL((SELECT TOP 1 [filename]  
       FROM         [spt_tkt_attach]  
       WHERE        [ticketid] = [tm].[TicketID]  
       ORDER BY [id] DESC), '') AS [attachfile],  
    ISNULL((SELECT TOP 1 [path]  
       FROM         [spt_tkt_attach]  
       WHERE        [ticketid] = [tm].[TicketID]  
       ORDER BY [id] DESC), '') AS [filepath],  
    ISNULL((SELECT TOP 1 [a].[Rating]  
       FROM         [serv_ticket_feedback_tbl] AS [a], [Serv_TicketHistory] AS [b]  
       WHERE        [a].[TicketHistoryID] = [b].[TicketHistoryID]  
           AND [b].[TicketID] = [tm].[TicketID]  
       ORDER BY [id] DESC), '') AS [Rating],  
    ISNULL((SELECT TOP 1 [a].[Comments]  
       FROM         [serv_ticket_feedback_tbl] AS [a], [Serv_TicketHistory] AS [b]  
       WHERE        [a].[TicketHistoryID] = [b].[TicketHistoryID]  
           AND [b].[TicketID] = [tm].[TicketID]  
       ORDER BY [id] DESC), '') AS [Cust_Comments], VST.Remarks as LastResponse,isnull(TP.Priority_Desc,'') as Priority_Desc,
	ISNULL((select top 1 tcm.TicketCategoryName from dbo.Serv_TicketCategory_Mast(nolock) AS tcm  
   where tcm.TicketCategoryId = tm.TicketCategoryId), '') TicketCategoryName
  FROM Serv_TicketMaster(nolock) AS tm LEFT OUTER JOIN Serv_Ticket_Stat_Mast(nolock) AS stm  
  ON stm.Stat_ID = tm.STATUS LEFT JOIN Serv_Group_Mast(nolock) AS GM  
  ON GM.Groupid = tm.Assign_Group LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ud  
  ON ud.ser_user_id = tm.User_id LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ag  
  ON ag.ser_user_id = tm.AssignTo left join V_sm_Serv_TicketHistory(nolock) VST  
  ON tm.TicketId=VST.TicketId left join Serv_Priority_Mast(nolock) TP
  ON tm.Priority=TP.Priority_ID
  WHERE tm.[TicketID] = @TicketID  
 END  
 ELSE  
 BEGIN  
  IF @access_level = ''  
  BEGIN 
   Set @Query = N'SELECT top 200 [dbo].[fn_getusertimefromindiantime](@PID,[tm].[AssignedDateTime]) AS [AssignedDateTime],  
     [dbo].[fn_getusertimefromindiantime](@PID,[tm].[resolved_dt]) AS [resolved_dt], [tm].TicketID,[tm].User_id,[tm].ParentID,[tm].TicketNo,[tm].Requester,[tm].Subject,[tm].Description,[tm].Status,[tm].Remarks,[tm].Note,[tm].Date_Created,[tm].Priority,[tm].AssignTo,[tm].Assign_Group,[tm].UserResponse,[tm].Active,[tm].Ticket_type,[tm].agrp_unassigned,[tm].Source,[tm].Product,[tm].Company,[tm].EmailId,[tm].domain,[tm].spam,[tm].deleted,[tm].skip_nticketmail,[tm].tkt_tag,[tm].Assignedby,  
     ISNULL([stm].[Stat_Desc], ''New'') AS [Stat_Desc],  
     CONVERT(DATE, [dbo].[fn_getusertimefromindiantime](@PID, [tm].[Date_Created])) AS [Date_Creat],  
     [GM].[Group_Name], [ud].[Login_id], SUBSTRING([tm].[Description], 0, 100) AS [shrtdesc],  
     [ud].[Name] AS [req_name], [ud].[Login_id],  
     ( CASE WHEN ISNULL([ag].[Login_id], '''') != ''''  
      THEN ''Agent : '' + [ag].[Login_id] + ''('' +  
      [ag].[Email] + '')''  
     ELSE( CASE WHEN ISNULL([gm].[Group_Name], '''') != ''''  
         THEN ''Group : '' + [gm].[Group_Name]  
        ELSE ''Not Assigned''  
        END )  
     END ) AS [Agent_name],  
     (SELECT TOP 1 [dbo].[fn_getusertimefromindiantime](@PID,[SubmittedDate]) AS [SubmittedDate]  
      FROM  [Serv_TicketHistory](nolock)  
      WHERE [TicketID] = [tm].[TicketID]  
      ORDER BY [SubmittedDate] DESC) AS [ldate],  
     ISNULL((SELECT TOP 1 [filename]  
        FROM [spt_tkt_attach](nolock)  
        WHERE [ticketid] = [tm].[TicketID]  
        ORDER BY [id] DESC), '''') AS [attachfile],  
     ISNULL((SELECT TOP 1 [path]  
        FROM  [spt_tkt_attach](nolock) 
        WHERE  [ticketid] = [tm].[TicketID] 
        ORDER BY [id] DESC), '''') AS [filepath], 
     ISNULL((SELECT TOP 1 [a].[Rating] 
        FROM  [serv_ticket_feedback_tbl](nolock) AS [a], [Serv_TicketHistory](nolock) AS [b] 
        WHERE [a].[TicketHistoryID] = [b].[TicketHistoryID] AND [b].[TicketID] = [tm].[TicketID] 
        ORDER BY [id] DESC), '''') AS [Rating], 
     ISNULL((SELECT TOP 1 [a].[Comments] 
        FROM [serv_ticket_feedback_tbl](nolock) AS [a], [Serv_TicketHistory](nolock) AS [b] 
        WHERE [a].[TicketHistoryID] = [b].[TicketHistoryID] AND [b].[TicketID] = [tm].[TicketID] 
        ORDER BY [id] DESC), '''') AS [Cust_Comments], (case when [tm].[Status] = 2 then ''close''
	 when [tm].[Status] = 4 then ''resolved'' 
	 Else 
	(Case 
	when (isnull(DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)), 0) = 0) then ''today''
	when (isnull((select top 1  (slr.resolve_Sec - (DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)))) from Serv_SLA_Response(nolock) slr where slr.Parentid = ' + cast(@ParentId as varchar(10)) + ' and slr.Priority_ID = [tm].Priority), 0) > 0) then ''overdue''
	when (isnull((select top 1  (slr.resolve_Sec - (DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)))) from Serv_SLA_Response(nolock) slr where slr.Parentid = ' + cast(@ParentId as varchar(10)) + ' and slr.Priority_ID = [tm].Priority), 0) < 0) then ''upcomming''
	else ''NoStatus'' End
	)End) ColorCo, VST.Remarks as LastResponse,isnull(TP.Priority_Desc,'''') as Priority_Desc,
	ISNULL((select top 1 TicketCategoryName from Serv_TicketCategory_Mast(nolock) AS tcm  
   where tcm.TicketCategoryId = tm.TicketCategoryId), '''') TicketCategoryName
   FROM Serv_TicketMaster(nolock) AS tm LEFT OUTER JOIN Serv_Ticket_Stat_Mast(nolock) AS stm  
   ON stm.Stat_ID = tm.STATUS LEFT JOIN Serv_Group_Mast(nolock) AS GM  
   ON GM.Groupid = tm.Assign_Group LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ud  
   ON ud.ser_user_id = tm.User_id LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ag  
   ON ag.ser_user_id = tm.AssignTo left join V_sm_Serv_TicketHistory(nolock) VST  
   ON tm.TicketId=VST.TicketId left join Serv_Priority_Mast(nolock) TP
  ON tm.Priority=TP.Priority_ID 
  WHERE [tm].User_id = @suid  
   ' + Case when @RowFilter != '' then ' and ' + @RowFilter else '' end + ' 
   ORDER BY ' + case when @OrderBy = '' then ' stm.Stat_Desc desc, VST.TicketHistoryID DESC ' else @OrderBy end  
   
      SET @ParmDefinition = N'@suid bigint, @PID bigint';            
   EXECUTE sp_executesql @Query, @ParmDefinition, @suid=@ser_user_id, @PID = @ParentID  
  END;  
  IF @access_level = 'self'  
  BEGIN  
   Set @Query = N'SELECT  top 200 [dbo].[fn_getusertimefromindiantime](@PID,[tm].[AssignedDateTime]) AS [AssignedDateTime], [dbo].[fn_getusertimefromindiantime](@PID,[tm].[resolved_dt]) AS [resolved_dt],  
       [tm].TicketID,[tm].User_id,[tm].ParentID,[tm].TicketNo,[tm].Requester,[tm].Subject,[tm].Description,[tm].Status,[tm].Remarks,[tm].Note,[tm].Date_Created,[tm].Priority,[tm].AssignTo,[tm].Assign_Group,[tm].UserResponse,[tm].Active,[tm].Ticket_type,[tm].agrp_unassigned,[tm].Source,[tm].Product,[tm].Company,[tm].EmailId,[tm].domain,[tm].spam,[tm].deleted,[tm].skip_nticketmail,[tm].tkt_tag,[tm].Assignedby,ISNULL([stm].[Stat_Desc], ''New'') AS [Stat_Desc],
       CONVERT(DATE, [dbo].[fn_getusertimefromindiantime](@PID, [tm].[Date_Created])) AS [Date_Creat],
       [GM].[Group_Name], [ud].[Login_id], SUBSTRING([tm].[Description], 0, 100) AS [shrtdesc],  
       [ud].[Name] AS [req_name], [ud].[Login_id],
       ( CASE WHEN ISNULL([ag].[Login_id], '''') != ''''
		THEN ''Agent : '' + [ag].[Login_id] + ''('' + [ag].[Email] + '')''
		ELSE( CASE WHEN ISNULL([gm].[Group_Name], '''') != ''''
		THEN ''Group : '' + [gm].[Group_Name]
		ELSE ''Not Assigned''
		END )
		END ) AS [Agent_name],
		(SELECT TOP 1 [dbo].[fn_getusertimefromindiantime](@PID,[SubmittedDate]) AS [SubmittedDate]
		FROM [Serv_TicketHistory](nolock)
		WHERE [TicketID] = [tm].[TicketID]
		ORDER BY [SubmittedDate] DESC) AS [ldate],
		ISNULL((SELECT TOP 1 [filename]
		FROM [spt_tkt_attach](nolock)
		WHERE [ticketid] = [tm].[TicketID]
		ORDER BY [id] DESC), '''') AS [attachfile],
	ISNULL((SELECT TOP 1 [path]
	FROM [spt_tkt_attach](nolock)
	WHERE [ticketid] = [tm].[TicketID]
	ORDER BY [id] DESC), '''') AS [filepath],
	ISNULL((SELECT TOP 1 [a].[Rating]
	FROM [serv_ticket_feedback_tbl](nolock) AS [a], [Serv_TicketHistory](nolock) AS [b]
	WHERE [a].[TicketHistoryID] = [b].[TicketHistoryID]
	AND [b].[TicketID] = [tm].[TicketID]
	ORDER BY [id] DESC), '''') AS [Rating],
	ISNULL((SELECT TOP 1 [a].[Comments]
	FROM [serv_ticket_feedback_tbl](nolock) AS [a], [Serv_TicketHistory](nolock) AS [b]
	WHERE [a].[TicketHistoryID] = [b].[TicketHistoryID]
	AND [b].[TicketID] = [tm].[TicketID]
	ORDER BY [id] DESC), '''') AS [Cust_Comments],
	(case when [tm].[Status] = 2 then ''close''
	when [tm].[Status] = 4 then ''resolved''
	Else
	(
	Case
	when (isnull(DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)), 0) = 0) then ''today''
	when (isnull((select top 1 (slr.resolve_Sec - (DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)))) from Serv_SLA_Response(nolock) slr where slr.Parentid = ' + cast(@ParentId as varchar(10)) + ' and slr.Priority_ID = [tm].Priority), 0) > 0) then ''overdue''
	when (isnull((select top 1 (slr.resolve_Sec - (DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)))) from Serv_SLA_Response(nolock) slr where slr.Parentid = ' + cast(@ParentId as varchar(10)) + ' and slr.Priority_ID = [tm].Priority), 0) < 0) then ''upcomming''
	else ''NoStatus''
	End
	)End) ColorCo, VST.Remarks as LastResponse,isnull(TP.Priority_Desc,'''') as Priority_Desc,
	ISNULL((select top 1 TicketCategoryName from dbo.Serv_TicketCategory_Mast(nolock) AS tcm
	where tcm.TicketCategoryId = tm.TicketCategoryId), '''') TicketCategoryName
	FROM Serv_TicketMaster(nolock) AS tm LEFT OUTER JOIN Serv_Ticket_Stat_Mast(nolock) AS stm
	ON stm.Stat_ID = tm.STATUS LEFT JOIN Serv_Group_Mast(nolock) AS GM
	ON GM.Groupid = tm.Assign_Group LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ud
	ON ud.ser_user_id = tm.User_id LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ag
	ON ag.ser_user_id = tm.AssignTo left join V_sm_Serv_TicketHistory(nolock) VST
	ON tm.TicketId=VST.TicketId left join Serv_Priority_Mast(nolock) TP
    ON tm.Priority=TP.Priority_ID
	WHERE( [tm].[AssignTo] = @suid OR [tm].User_id = @suid )
	' + Case when @RowFilter != '' then ' and ' + @RowFilter else '' end + '
	ORDER BY ' + case when @OrderBy = '' then ' stm.Stat_Desc desc, VST.TicketHistoryID DESC ' else @OrderBy end
     
      SET @ParmDefinition = N'@suid bigint, @PID bigint';            
   EXECUTE sp_executesql @Query, @ParmDefinition, @suid=@ser_user_id, @PID = @ParentID     
  END;  
  IF @access_level = 'Within Group'  
  BEGIN  
   Set @Query = N'SELECT  top 200 [sm1].[Group_id], [Userid]  
   INTO [#tmp]  
   FROM   Serv_Agent_Mast AS sm1  
   WHERE  [sm1].[Userid] = @suid;  
  
   SELECT [dbo].[fn_getusertimefromindiantime](@PID, [tm].[AssignedDateTime]) AS [AssignedDateTime],  
     [dbo].[fn_getusertimefromindiantime](@PID, [tm].[resolved_dt]) AS [resolved_dt],  
     [tm].TicketID,[tm].User_id,[tm].ParentID,[tm].TicketNo,[tm].Requester,[tm].Subject,[tm].Description,[tm].Status,[tm].Remarks,[tm].Note,[tm].Date_Created,[tm].Priority,[tm].AssignTo,[tm].Assign_Group,[tm].UserResponse,[tm].Active,[tm].Ticket_type,[tm].agrp_unassigned,[tm].Source,[tm].Product,[tm].Company,[tm].EmailId,[tm].domain,[tm].spam,[tm].deleted,[tm].skip_nticketmail,[tm].tkt_tag,[tm].Assignedby, ISNULL([stm].[Stat_Desc], ''New'') AS [Stat_Desc],  
     CONVERT(DATE, [dbo].[fn_getusertimefromindiantime](@PID,[tm].[Date_Created])) AS [Date_Creat],  
     [GM].[Group_Name], [ud].[Login_id], SUBSTRING([tm].[Description], 0, 100) AS [shrtdesc],  
     [ud].[Name] AS [req_name], [ud].[Login_id],  
     ( CASE WHEN ISNULL([ag].[Login_id], '''') != ''''  
      THEN ''Agent : '' + [ag].[Login_id] +  
      ''('' + [ag].[Email] + '')''  
     ELSE( CASE  
       WHEN ISNULL([gm].[Group_Name], '''') != ''''  
        THEN ''Group : '' + [gm].[Group_Name]  
       ELSE ''Not Assigned''  
       END )  
     END ) AS [Agent_name],  
     (SELECT TOP 1 [dbo].[fn_getusertimefromindiantime](@PID,[SubmittedDate]) AS [SubmittedDate]  
     FROM           [Serv_TicketHistory](nolock)  
     WHERE        [TicketID] = [tm].[TicketID]  
     ORDER BY [SubmittedDate] DESC) AS [ldate],  
     ISNULL((SELECT TOP 1 [filename]  
       FROM         [spt_tkt_attach](nolock)  
       WHERE        [ticketid] = [tm].[TicketID]  
       ORDER BY [id] DESC), '''') AS [attachfile],  
     ISNULL((SELECT TOP 1 [path]  
       FROM         [spt_tkt_attach](nolock)  
       WHERE        [ticketid] = [tm].[TicketID]  
       ORDER BY [id] DESC), '''') AS [filepath],  
     ISNULL((SELECT TOP 1 [a].[Rating]  
       FROM [serv_ticket_feedback_tbl](nolock) AS [a], [Serv_TicketHistory](nolock) AS [b]  
       WHERE [a].[TicketHistoryID] = [b].[TicketHistoryID] AND [b].[TicketID] = [tm].[TicketID]  
       ORDER BY [id] DESC), '''') AS [Rating],  
     ISNULL((SELECT TOP 1 [a].[Comments]  
       FROM [serv_ticket_feedback_tbl](nolock) AS [a], [Serv_TicketHistory](nolock) AS [b]  
       WHERE [a].[TicketHistoryID] = [b].[TicketHistoryID] AND [b].[TicketID] = [tm].[TicketID]  
       ORDER BY [id] DESC), '''') AS [Cust_Comments],  
       VST.TicketHistoryID,VST.SubmittedDate, 
	   (case when [tm].[Status] = 2 then ''close''
	 when [tm].[Status] = 4 then ''resolved''
	 Else 
	(
	Case 
	when (isnull(DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)), 0) = 0) then ''today''
	when (isnull((select top 1  (slr.resolve_Sec - (DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)))) from Serv_SLA_Response(nolock) slr where slr.Parentid = cast(' + @ParentId + ' as varchar(10)) and slr.Priority_ID = [tm].Priority), 0) > 0) then ''overdue''
	when (isnull((select top 1  (slr.resolve_Sec - (DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)))) from Serv_SLA_Response(nolock) slr where slr.Parentid = cast(' + @ParentId + ' as varchar(10)) and slr.Priority_ID = [tm].Priority), 0) < 0) then ''upcomming''
	else ''NoStatus''
	End
	)End) ColorCo, VST.Remarks as LastResponse,isnull(TP.Priority_Desc,'''') as Priority_Desc,
	ISNULL((select top 1 TicketCategoryName from dbo.Serv_TicketCategory_Mast(nolock) AS tcm  
   where tcm.TicketCategoryId = tm.TicketCategoryId), '''') TicketCategoryName  
   FROM Serv_TicketMaster(nolock) AS tm LEFT OUTER JOIN Serv_Ticket_Stat_Mast(nolock) AS stm  
   ON stm.Stat_ID = tm.STATUS LEFT JOIN Serv_Group_Mast(nolock) AS GM  
   ON GM.Groupid = tm.Assign_Group LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ud  
   ON ud.ser_user_id = tm.User_id LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ag  
   ON ag.ser_user_id = tm.AssignTo left join V_sm_Serv_TicketHistory(nolock) VST  
   ON tm.TicketId=VST.TicketId left join Serv_Priority_Mast(nolock) TP
   ON tm.Priority=TP.Priority_ID
   WHERE [tm].[AssignTo] IN(SELECT [Userid] FROM [#tmp])  
   ' + Case when @RowFilter != '' then ' and ' + @RowFilter else '' end + '  
   UNION 
   SELECT [dbo].[fn_getusertimefromindiantime](@PID,[tm].[AssignedDateTime]) AS [AssignedDateTime],  
       [dbo].[fn_getusertimefromindiantime](@PID,[tm].[resolved_dt]) AS [resolved_dt],  
       [tm].TicketID,[tm].User_id,[tm].ParentID,[tm].TicketNo,[tm].Requester,[tm].Subject,[tm].Description,[tm].Status,[tm].Remarks,[tm].Note,[tm].Date_Created,[tm].Priority,[tm].AssignTo,[tm].Assign_Group,[tm].UserResponse,[tm].Active,[tm].Ticket_type,[tm].agrp_unassigned,[tm].Source,[tm].Product,[tm].Company,[tm].EmailId,[tm].domain,[tm].spam,[tm].deleted,[tm].skip_nticketmail,[tm].tkt_tag,[tm].Assignedby,  
       ISNULL([stm].[Stat_Desc], ''New'') AS [Stat_Desc],   
       CONVERT(DATE, [dbo].[fn_getusertimefromindiantime](@PID, [tm].[Date_Created])) AS [Date_Creat],  
       [GM].[Group_Name], [ud].[Login_id],  
       SUBSTRING([tm].[Description], 0, 100) AS [shrtdesc], [ud].[Name] AS [req_name], [ud].[Login_id],  
        ( CASE WHEN ISNULL([ag].[Login_id], '''') != ''''  
        THEN ''Agent : '' + [ag].[Login_id] + ''('' + [ag].[Email] + '')''  
       ELSE( CASE WHEN ISNULL([gm].[Group_Name], '''') != ''''  
           THEN ''Group : '' + [gm].[Group_Name]  
          ELSE ''Not Assigned''  
          END )  
       END ) AS [Agent_name],  
        (SELECT TOP 1 [dbo].[fn_getusertimefromindiantime](@PID,[SubmittedDate]) AS [SubmittedDate]  
         FROM          [Serv_TicketHistory](nolock)  
         WHERE        [TicketID] = [tm].[TicketID]  
         ORDER BY [SubmittedDate] DESC) AS [ldate],  
        ISNULL((SELECT TOP 1 [filename]  
          FROM         [spt_tkt_attach](nolock)  
          WHERE        [ticketid] = [tm].[TicketID]  
          ORDER BY [id] DESC), '''') AS [attachfile],  
        ISNULL((SELECT TOP 1 [path]  
          FROM         [spt_tkt_attach](nolock)  
          WHERE        [ticketid] = [tm].[TicketID]  
          ORDER BY [id] DESC), '''') AS [filepath],  
        ISNULL((SELECT TOP 1 [a].[Rating]  
          FROM         [serv_ticket_feedback_tbl](nolock) AS [a], [Serv_TicketHistory](nolock) AS [b] 
          WHERE        [a].[TicketHistoryID] = [b].[TicketHistoryID] AND [b].[TicketID] = [tm].[TicketID]  
          ORDER BY [id] DESC), '''') AS [Rating],  
        ISNULL((SELECT TOP 1 [a].[Comments]  
          FROM         [serv_ticket_feedback_tbl](nolock) AS [a], [Serv_TicketHistory](nolock) AS [b] 
          WHERE        [a].[TicketHistoryID] = [b].[TicketHistoryID] AND [b].[TicketID] = [tm].[TicketID]  
          ORDER BY [id] DESC), '''') AS [Cust_Comments],  
       VST.TicketHistoryID,VST.SubmittedDate,
			(case when [tm].[Status] = 2 then ''close''
	 when [tm].[Status] = 4 then ''resolved''
	 Else 
	(
	Case 
	when (isnull(DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)), 0) = 0) then ''today''
	when (isnull((select top 1  (slr.resolve_Sec - (DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)))) from Serv_SLA_Response(nolock) slr where slr.Parentid = ' + cast(@ParentId as varchar(10)) + ' and slr.Priority_ID = [tm].Priority), 0) > 0) then ''overdue''
	when (isnull((select top 1  (slr.resolve_Sec - (DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)))) from Serv_SLA_Response(nolock) slr where slr.Parentid = ' + cast(@ParentId as varchar(10)) + ' and slr.Priority_ID = [tm].Priority), 0) < 0) then ''upcomming''
	else ''NoStatus''
	End
	)End) ColorCo, VST.Remarks as LastResponse,isnull(TP.Priority_Desc,'''') as Priority_Desc,
	ISNULL((select top 1 TicketCategoryName from dbo.Serv_TicketCategory_Mast(nolock) AS tcm  
   where tcm.TicketCategoryId = tm.TicketCategoryId), '''') TicketCategoryName
   FROM Serv_TicketMaster(nolock) AS tm LEFT OUTER JOIN Serv_Ticket_Stat_Mast(nolock) AS stm  
   ON stm.Stat_ID = tm.STATUS LEFT JOIN Serv_Group_Mast(nolock) AS GM  
   ON GM.Groupid = tm.Assign_Group LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ud  
   ON ud.ser_user_id = tm.User_id LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ag  
   ON ag.ser_user_id = tm.AssignTo left join V_sm_Serv_TicketHistory(nolock) VST  
   ON tm.TicketId=VST.TicketId left join Serv_Priority_Mast(nolock) TP
  ON tm.Priority=TP.Priority_ID
   WHERE [tm].[Assign_Group] IN(SELECT [Group_id] FROM  [#tmp]) AND [tm].[AssignTo] = 0 
   ' + Case when @RowFilter != '' then ' and ' + @RowFilter else '' end + '  
   ORDER BY ' + case when @OrderBy = '' then ' Stat_Desc desc, VST.TicketHistoryID DESC ' else @OrderBy end +   
   '; DROP TABLE if Exists #tmp;'  
     
      SET @ParmDefinition = N'@suid bigint, @PID bigint';            
   EXECUTE sp_executesql @Query, @ParmDefinition, @suid=@ser_user_id, @PID = @ParentID     
  END;  
  IF @access_level = 'All Group'  
  BEGIN  
   Set @Query = N'SELECT  top 200 [dbo].[fn_getusertimefromindiantime](@PID, [tm].[AssignedDateTime]) AS [AssignedDateTime], [dbo].[fn_getusertimefromindiantime](@PID, [tm].[resolved_dt]) AS [resolved_dt], [tm].TicketID,[tm].User_id,[tm].ParentID,[tm].TicketNo,[tm].Requester,[tm].Subject,[tm].Description,[tm].Status,[tm].Remarks,[tm].Note,[tm].Date_Created,[tm].Priority,[tm].AssignTo,[tm].Assign_Group,[tm].UserResponse,[tm].Active,[tm].Ticket_type,[tm].agrp_unassigned,[tm].Source,[tm].Product,[tm].Company,[tm].EmailId,[tm].domain,[tm].spam,[tm].deleted,[tm].skip_nticketmail,[tm].tkt_tag,[tm].Assignedby, ISNULL([stm].[Stat_Desc], ''New'') AS [Stat_Desc], CONVERT(DATE, [dbo].[fn_getusertimefromindiantime](@PID, [tm].[Date_Created])) AS [Date_Creat], [GM].[Group_Name], [ud].[Login_id], SUBSTRING([tm].[Description], 0, 100) AS [shrtdesc], [ud].[Name] AS [req_name], [ud].[Login_id],  
        ( CASE WHEN ISNULL([ag].[Login_id], '''') != '''' THEN ''Agent : '' + [ag].[Login_id] + ''('' + [ag].[Email] + '')'' 
       ELSE( CASE WHEN ISNULL([gm].[Group_Name], '''') != '''' 
            THEN ''Group : '' + [gm].[Group_Name] 
          ELSE ''Not Assigned'' 
          END) 
       END) AS [Agent_name], 
        (SELECT TOP 1 [dbo].[fn_getusertimefromindiantime](@PID, [SubmittedDate]) AS [SubmittedDate]  
         FROM [Serv_TicketHistory](nolock) 
         WHERE [TicketID] = [tm].[TicketID] 
         ORDER BY [SubmittedDate] DESC) AS [ldate], 
        ISNULL((SELECT TOP 1 [filename] 
          FROM [spt_tkt_attach](nolock) 
          WHERE [ticketid] = [tm].[TicketID] 
          ORDER BY [id] DESC), '''') AS [attachfile], 
        ISNULL((SELECT TOP 1 [path] 
          FROM [spt_tkt_attach](nolock) 
          WHERE [ticketid] = [tm].[TicketID] 
          ORDER BY [id] DESC), '''') AS [filepath], 
        ISNULL((SELECT TOP 1 [a].[Rating] 
          FROM [serv_ticket_feedback_tbl](nolock) AS [a], [Serv_TicketHistory](nolock) AS [b] 
          WHERE [a].[TicketHistoryID] = [b].[TicketHistoryID] AND [b].[TicketID] = [tm].[TicketID]  
          ORDER BY [id] DESC), '''') AS [Rating], 
        ISNULL((SELECT TOP 1 [a].[Comments] 
          FROM [serv_ticket_feedback_tbl](nolock) AS [a], [Serv_TicketHistory](nolock) AS [b] 
          WHERE [a].[TicketHistoryID] = [b].[TicketHistoryID] AND [b].[TicketID] = [tm].[TicketID]  
          ORDER BY [id] DESC), '''') AS [Cust_Comments],
			(case when [tm].[Status] = 2 then ''close'' when [tm].[Status] = 4 then ''resolved''
	 Else 
	(
	Case 
	when (isnull(DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)), 0) = 0) then ''today''
	when (isnull((select top 1 (slr.resolve_Sec - (DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)))) from Serv_SLA_Response(nolock) slr where slr.Parentid = ' + cast(@ParentId as varchar(10)) + ' and slr.Priority_ID = [tm].Priority), 0) > 0) then ''overdue''
	when (isnull((select top 1 (slr.resolve_Sec - (DATEDIFF(minute, cast([tm].Date_Created as Date), cast(GETDATE() as Date)))) from Serv_SLA_Response(nolock) slr where slr.Parentid = ' + cast(@ParentId as varchar(10)) + ' and slr.Priority_ID = [tm].Priority), 0) < 0) then ''upcomming''
	else ''NoStatus''
	End
	)End) ColorCo, VST.Remarks as LastResponse,isnull(TP.Priority_Desc,'''') as Priority_Desc,
	ISNULL((select top 1 TicketCategoryName from [Serv_TicketCategory_Mast](nolock) AS tcm 
   where tcm.TicketCategoryId = tm.TicketCategoryId), '''') TicketCategoryName 
   FROM Serv_TicketMaster(nolock) AS tm LEFT OUTER JOIN Serv_Ticket_Stat_Mast(nolock) AS stm 
   ON stm.Stat_ID = tm.STATUS LEFT JOIN Serv_Group_Mast(nolock) AS GM 
   ON GM.Groupid = tm.Assign_Group LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ud 
   ON ud.ser_user_id = tm.User_id LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ag 
   ON ag.ser_user_id = tm.AssignTo left join V_sm_Serv_TicketHistory(nolock) VST 
   ON tm.TicketId=VST.TicketId left join Serv_Priority_Mast(nolock) TP
   ON tm.Priority=TP.Priority_ID
   WHERE [tm].[ParentID] = @PID
    ' + Case when @RowFilter != '' then ' and ' + @RowFilter else '' end + ' ORDER BY ' + case when @OrderBy = '' then ' stm.Stat_Desc desc, VST.TicketHistoryID DESC ' else @OrderBy end  
   
      SET @ParmDefinition = N'@PID bigint ';            
   EXECUTE sp_executesql @Query, @ParmDefinition, @PID = @ParentID
  END;  
  print @Query
 END;  
END;  



