   Procedure: [dbo].[usp_sm_GetSupportUserDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec usp_sm_GetSupportUserDetails @ParentId=32222, @UserId=0, @LoginId='', @Pwd='', @Mobile='', @Email='', @Mode='GetByParentId'
-- exec usp_sm_GetSupportUserDetails @ParentId=0, @UserId=32494, @LoginId='', @Pwd='', @Mobile='', @Email='', @Mode='GetByKit19UserId'
-- exec usp_sm_GetSupportUserDetails @ParentId=0, @UserId=591, @LoginId='', @Pwd='', @Mobile='', @Email='', @Mode='GetByServiceUserId'
-- exec usp_sm_GetSupportUserDetails @ParentId=0, @UserId=0, @LoginId='Demo2', @Pwd='kitapp', @Mobile='', @Email='', @Mode='GetByAuthentication'
-- exec usp_sm_GetSupportUserDetails @ParentId=27828, @UserId=0, @LoginId='Demo2', @Pwd='kitapp', @Mobile='', @Email='', @Mode='GetByAuthentication'
-- exec usp_sm_GetSupportUserDetails @ParentId=0, @UserId=0, @LoginId='', @Pwd='', @Mobile='7840049991', @Email='', @Mode='GetByMobileNo'
-- exec usp_sm_GetSupportUserDetails @ParentId=26405, @UserId=0, @LoginId='', @Pwd='', @Mobile='7840049991', @Email='', @Mode='GetByMobileNo'
-- exec usp_sm_GetSupportUserDetails @ParentId=0, @UserId=0, @LoginId='', @Pwd='', @Mobile='', @Email='animesh.shukla@pelsoftlabs.in', @Mode='GetByEmailId'
-- exec usp_sm_GetSupportUserDetails @ParentId=27828, @UserId=0, @LoginId='', @Pwd='', @Mobile='', @Email='animesh.shukla@pelsoftlabs.in', @Mode='GetByEmailId'
CREATE   PROCEDURE [dbo].[usp_sm_GetSupportUserDetails]
(
	@ParentId		BIGINT=0,
	@UserId			BIGINT=0,
	@LoginId		NVARCHAR(200) = '',
	@Pwd			NVARCHAR(200) = '',
	@Mobile			NVARCHAR(40) = '',
	@Email			NVARCHAR(200) = '',
	@Mode			VARCHAR(50) = 'GetByParentId'
)
AS
BEGIN

	IF(@Mode = 'GetByParentId')
	BEGIN
		select	SUD.*, isnull(SAM.Access_level,'') as Access_level
		from	Serv_User_Detail(nolock) SUD left join Serv_Agent_Mast(nolock) SAM
		on		SUD.User_Id=SAM.Userid
		where	SUD.ParentId=@ParentId
	END

	IF(@Mode = 'GetByKit19UserId')
	BEGIN
		select	SUD.*, isnull(SAM.Access_level,'') as Access_level
		from	Serv_User_Detail(nolock) SUD left join Serv_Agent_Mast(nolock) SAM
		on		SUD.User_Id=SAM.Userid
		where	SUD.user_id_old=@UserId
	END

	IF(@Mode = 'GetByServiceUserId')
	BEGIN
		select	SUD.*, isnull(SAM.Access_level,'') as Access_level
		from	Serv_User_Detail(nolock) SUD left join Serv_Agent_Mast(nolock) SAM
		on		SUD.User_Id=SAM.Userid
		where	SUD.User_id=@UserId
	END

	IF(@Mode = 'GetByAuthentication')
	BEGIN
		select	SUD.*, isnull(SAM.Access_level,'') as Access_level
		from	Serv_User_Detail(nolock) SUD left join Serv_Agent_Mast(nolock) SAM
		on		SUD.User_Id=SAM.Userid
		where	SUD.Login_id=@LoginId and SUD.pwd=@Pwd and SUD.ParentId=case when @ParentId=0 then SUD.ParentId else @ParentId end
	END

	IF(@Mode = 'GetByMobileNo')
	BEGIN
		select	SUD.*, isnull(SAM.Access_level,'') as Access_level
		from	Serv_User_Detail(nolock) SUD left join Serv_Agent_Mast(nolock) SAM
		on		SUD.User_Id=SAM.Userid
		where	SUD.Mobile=@Mobile and SUD.ParentId=case when @ParentId=0 then SUD.ParentId else @ParentId end
	END

	IF(@Mode = 'GetByEmailId')
	BEGIN
		select	SUD.*, isnull(SAM.Access_level,'') as Access_level
		from	Serv_User_Detail(nolock) SUD left join Serv_Agent_Mast(nolock) SAM
		on		SUD.User_Id=SAM.Userid
		where	SUD.Email=@Email and SUD.ParentId=case when @ParentId=0 then SUD.ParentId else @ParentId end
	END

END



GO

/* ============================================================
   Procedure: [dbo].[usp_sm_GetTicketDdlType]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec usp_sm_GetTicketDdlType @ID=32222, @DdlType='All'
-- exec usp_sm_GetTicketDdlType @ID=0, @DdlType='TicketType'
-- exec usp_sm_GetTicketDdlType @ID=32222, @DdlType='Group'
CREATE   PROCEDURE [dbo].[usp_sm_GetTicketDdlType]
(
	@ID bigint,
	@DdlType varchar(20)
)
AS
BEGIN

-- declare @ID bigint=32222,@DdlType varchar(20)='All'
-- declare @ID bigint=0,@DdlType varchar(20)='TicketType'

declare @tblDdltype table
(
	DdlTypeId bigint,
	DdlTypeName nvarchar(500),
	DdlType varchar(20)
)

If(@DdlType='TicketType' or @DdlType='All')
Begin
	insert into @tblDdltype
	select DdlTypeId=Type_ID,DdlTypeName=Type_Desc,'TicketType' as DdlType
	from Serv_TicketType_Mast(nolock)
	Where Active=1
End
If(@DdlType='TicketCategory' or @DdlType='All')
Begin
	insert into @tblDdltype
	select DdlTypeId=TicketCategoryId,DdlTypeName=TicketCategoryName,'TicketCategory' as DdlType
	from Serv_TicketCategory_Mast(nolock)
	Where IsActive=1 and (ParentId=@ID or ParentId is null)
End

If(@DdlType='Group' or @DdlType='All')
Begin
	insert into @tblDdltype
	select DdlTypeId=GroupId, DdlTypeName=Group_Name, 'Group' as DdlType
	from Serv_Group_Mast(nolock) 
	Where Active=1 and ParentId=@ID
End

If(@DdlType='Priority' or @DdlType='All')
Begin
	insert into @tblDdltype
	select DdlTypeId=Priority_Id, DdlTypeName=Priority_Desc, 'Priority' as DdlType
	from Serv_Priority_Mast(nolock) 
	Where Active=1
End

If(@DdlType='TicketStatus' or @DdlType='All')
Begin
	insert into @tblDdltype
	select DdlTypeId=Stat_Id, DdlTypeName=Stat_Desc, 'TicketStatus' as DdlType
	from Serv_Ticket_Stat_Mast(nolock) 
End

If(@DdlType='UserTicketStatus' or @DdlType='All')
Begin
	insert into @tblDdltype
	select DdlTypeId=Stat_Id, DdlTypeName=Stat_Desc, 'UserTicketStatus' as DdlType
	from Serv_Ticket_Stat_Mast(nolock) 
	where Stat_Id in (1,2,3,4)
End

If(@DdlType='Role' or @DdlType='All')
Begin
	insert into @tblDdltype
	select DdlTypeId=RoleId, DdlTypeName=RoleDesc, 'Role' as DdlType
	from Serv_Role_mast(nolock) 
	Where Active=1 and ParentId=@ID
End

If(@DdlType='AgentByParentId' or @DdlType='All')
Begin
	insert into @tblDdltype
	select DdlTypeId=SAM.UserId, DdlTypeName=SUD.Login_id+'('+SUD.Email+')', 'AgentByParentId' as DdlType
	from Serv_Agent_Mast(nolock) SAM inner join Serv_User_Detail(nolock) SUD
    on SAM.Userid=SUD.ser_user_id and SUD.ParentId = SAM.ParentId
	Where SAM.Active=1 and SAM.ParentId=@ID
End

If(@DdlType='AgentByGroupId' or @DdlType='All')
Begin
	insert into @tblDdltype
	select DdlTypeId=SAM.UserId, DdlTypeName=SUD.Login_id+'('+SUD.Email+')', 'AgentByGroupId' as DdlType
	from Serv_Agent_Mast(nolock) SAM inner join Serv_User_Detail(nolock) SUD
    on SAM.Userid=SUD.ser_user_id and SUD.ParentId = SAM.ParentId
	Where SAM.Active=1 and SAM.Group_id=@ID
End

If(@DdlType='AgentByRoleId' or @DdlType='All')
Begin
	insert into @tblDdltype
	select DdlTypeId=SAM.UserId, DdlTypeName=SUD.Login_id+'('+SUD.Email+')', 'AgentByRoleId' as DdlType
	from Serv_Agent_Mast(nolock) SAM inner join Serv_User_Detail(nolock) SUD
    on SAM.Userid=SUD.ser_user_id and SUD.ParentId = SAM.ParentId
	Where SAM.Active=1 and SAM.RoleId=@ID
End

Select * From @tblDdltype

END




GO

