   Procedure: [dbo].[USP_SM_GETUSER_ROLES]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
if object_id('USP_SM_GETUSER_ROLES') is not null
begin
 drop procedure USP_SM_GETUSER_ROLES
end

EXEC USP_SM_GETUSER_ROLES 42502


tbl_lead_event_history


truncate table tbl_sm_scoringraw

tbl_sm_scoringraw order by 1 desc



