CREATE   PROC USP_SM_GETUSER_ROLES
(
	@P_USER_ID INT
)
AS
BEGIN

	 DECLARE @PARENTID BIGINT = 0  
	 SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_USER_ID    


	IF OBJECT_ID('tempdb..#TEMP_USERS_ROLEWISE') is not null begin drop table  #TEMP_USERS_ROLEWISE end 

	DECLARE @UserDetails  tbl_type_sm_UserDetails;

	INSERT INTO @UserDetails
	EXEC Use_GetUserDetails @PARENTID;



	SELECT *  INTO  #TEMP_USERS_ROLEWISE FROM (
	SELECT   RoleCode, UserId , ParentId  FROM TBL_UA_USERROLEMAPPINGMASTER  where ParentId = @PARENTID and RoleCode
	in  ( SELECT RoleCode FROM TBL_UA_ROLEMASTER  where  parentid = @PARENTID  )
	UNION 
	SELECT  RoleCode,  USERID ,   PARENTID FROM TBL_UA_USERROLEMAPPINGMASTER WHERE USERID IN (SELECT USERID FROM @UserDetails) AND Active =1
	) AS TAB


	SELECT DISTINCT  V.RoleId AS [ID] ,   V.ROLENAME   AS [NAME] FROM #TEMP_USERS_ROLEWISE  T LEFT JOIN VW_SYSTEMROLE_ROLEMASTER V ON  V.ROLECODE = T.ROLECODE
	where  coalesce( v.RoleId,0)  <> 0 or   coalesce( v.ROLENAME,'' )  <>  ''

	 --SELECT ROLEID [ID], ROLENAME[NAME] FROM TBL_UA_ROLEMASTER(NOLOCK)   WHERE PARENTID = @PARENTID AND ACTIVE=1

	--- get users by role
	---select * from tbl_UA_UserRoleMappingMaster where parentid = 34594



END


