/* ============================================================
   Procedure: [dbo].[USP_SM_getUsersbyrole]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*

DECLARE @P_role_name varchar(1000) =  '{"type":"roles" , "values": "Manager"},{"type":"roles" , "values": "Assistent"}'

EXEC USP_SM_getUsersbyrole  34594 , '{"type":"roles" , "values": "Admin"},{"type":"roles" , "values": "Guest"},{"type":"roles" , "values": "Ajit user"}'



*/
 

CREATE   PROC  USP_SM_getUsersbyrole
(
	@P_parentid bigint,
	@P_role_JSON varchar(1000) ,
	@P_usertable  tbl_type_sm_UserDetails readonly
)
as 
begin


		DECLARE @APPLICABLE_TYPE VARCHAR(50);

		IF OBJECT_ID('tempdb..#TEMP_USERS_ROLEWISE_SP_getUsersbyrole') IS NOT NULL  DROP TABLE #TEMP_USERS_ROLEWISE_SP_getUsersbyrole;

		IF OBJECT_ID('tempdb..#temp_Roles_SP_getUsersbyrole') IS NOT NULL   DROP TABLE #temp_Roles_SP_getUsersbyrole; 
 

		CREATE TABLE #temp_Roles_SP_getUsersbyrole (
			[type] NVARCHAR(50),
			[values] NVARCHAR(50)
		);

		DECLARE @json_data NVARCHAR(MAX) = '[' + @P_role_JSON + ']';
		INSERT INTO #temp_Roles_SP_getUsersbyrole ([type], [values])
		SELECT [type], [values]
		FROM OPENJSON(@json_data)
		WITH (
			[type] NVARCHAR(50),
			[values] NVARCHAR(50)
		);

	

		SELECT TOP 1 @APPLICABLE_TYPE = [type] FROM #temp_Roles_SP_getUsersbyrole;

	

	 

		-- Create the temporary table for user roles
		SELECT * INTO #TEMP_USERS_ROLEWISE_SP_getUsersbyrole FROM (
			SELECT RoleCode, UserId, ParentId
			FROM TBL_UA_USERROLEMAPPINGMASTER
			WHERE ParentId = @P_parentid AND RoleCode IN (
				SELECT RoleCode
				FROM TBL_UA_ROLEMASTER
				WHERE Parentid = @P_parentid
			)
			UNION
			SELECT RoleCode, USERID, PARENTID
			FROM TBL_UA_USERROLEMAPPINGMASTER
			WHERE USERID IN (SELECT USERID FROM @P_usertable) AND Active = 1
		) AS TAB;

		IF (@APPLICABLE_TYPE = 'ROLES')
		BEGIN
			SELECT T.USERID
			FROM #TEMP_USERS_ROLEWISE_SP_getUsersbyrole T
			LEFT JOIN VW_SYSTEMROLE_ROLEMASTER V ON V.ROLECODE = T.ROLECODE
			WHERE V.ROLENAME IN (SELECT [values] FROM #temp_Roles_SP_getUsersbyrole);
		END
		ELSE IF (@APPLICABLE_TYPE = 'USERS')
		BEGIN
			SELECT [user_id]
			FROM User_Detail
			WHERE User_Login IN (SELECT [values] FROM #temp_Roles_SP_getUsersbyrole);
		END


END




