/* ============================================================
   Procedure: [dbo].[usp_sm_GetuserTargetStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*

usp_sm_GetuserTargetStatus '01-jul-2024' , '20-jul-2024' , 32222

*/

CREATE   PROC usp_sm_GetuserTargetStatus
(
	@P_from_date datetime,
	@P_to_date datetime,
	@P_userID bigint = 0
)
as 
begin

		if OBJECT_ID('tempdb..#tempTargetUsers') is not null begin drop table #tempTargetUsers end;

		Create table #tempTargetUsers
		(
			id int identity (1,1),
			SalesTargetId bigint,
			UserId bigint,
			targetPoint decimal(16,2),
			ISactive bit,
			Target_date datetime null,
			UserName varchar(200) null ,
			TargetName varchaR(100) null,
			target_period varchar(100) null,
			targeteType varchar(500) null,
			targetFor varchar(50) null,
			target_assigned decimal(16,2) null,
			target_achieved decimal(16,2) null
		)

		
		Declare  @SalesTargetId int = 0,  @TargetPoints as bigint = 0 , @usersplitdetail varchar(max) , @K_MIN INT = 0 ,  @K_MAX  INT = 0 , @last_sales_targetId int = 0;
		Declare @TargetFor varchar(50);

		select  @K_MIN = MIN(SalesTargetId) , @K_MAX = MAX(SalesTargetId)   from   TBL_ST_SalesTargetSettingMaster 
		where (TargetFromDate between @P_from_date and @P_to_date) and (TargetToDate between @P_from_date and @P_to_date)  ;


		While (@K_MIN <= @K_MAX)
		begin
			
			if  object_id('tempdb..#temp_tbl_usertarget') is not null begin drop table #temp_tbl_usertarget end;
			if  object_id('tempdb..#temp_tbl_master_target') is not null begin drop table #temp_tbl_master_target end;
			 
			select * into #temp_tbl_usertarget from TBL_ST_SALESTARGETSETTINGUSERTARGET where SalesTargetId = @K_MIN ;
			select * into #temp_tbl_master_target from TBL_ST_SalesTargetSettingMaster where SalesTargetId = @K_MIN ;
			 
			SELECT top 1  @SalesTargetId = SalesTargetId , @usersplitdetail = UserSplitDetail FROM #temp_tbl_usertarget WHERE SalesTargetId = @K_MIN
			select @TargetFor = TargetFor from   #temp_tbl_master_target

			if (@last_sales_targetId <> @SalesTargetId) begin
				

				if (@TargetFor ='team') begin
					insert into #tempTargetUsers (SalesTargetId , UserId , targetPoint ,ISactive)
					select @K_MIN , 
					JSON_VALUE(value, '$.UserId') , 
					JSON_VALUE(value, '$.Target') ,
					JSON_VALUE(value, '$.IsActive') 
					from openjson(@usersplitdetail);
				end
				else begin
					insert into #tempTargetUsers (SalesTargetId , UserId , targetPoint ,ISactive)
					select distinct @K_MIN , userid  , TargetNumber , IsActive  from  #temp_tbl_usertarget;

				end


				UPDATE #tempTargetUsers
					SET 
						UserName = u.user_login + '(' + u.FName + ' ' + u.LName + ')',  
						Target_date = tm.TargetFromDate,
						TargetName = '',
						target_period = FORMAT(tm.TargetFromDate, 'dd-MMM-yyyy') + ' - ' + FORMAT(tm.TargetToDate, 'dd-MMM-yyyy'),
						targeteType = CASE 
										WHEN tm.TargetType = 1 THEN 'Revenue'  
										WHEN tm.TargetType = 2 THEN 'Conversion'  
										WHEN tm.TargetType = 3 THEN 'Points' 
										END,
						targetFor = tm.targetfor,
						target_assigned = tm.TotalTarget, 
						target_achieved = (
											SELECT SUM(ph.points) 
											FROM tbl_SM_Employee_Points_History ph  
											WHERE ph.TranDate BETWEEN  CONCAT(CONVERT(VARCHAR,  tm.TargetFromDate, 23), ' 00:00:00') AND CONCAT(CONVERT(VARCHAR,  tm.TargetToDate , 23), ' 23:59:59') 
												AND ph.UserId = tu.UserId
											)
					FROM 
						#tempTargetUsers tu
					LEFT JOIN 
						#temp_tbl_master_target tm ON tm.SalesTargetId = tu.SalesTargetId  
					LEFT JOIN
						user_detail u ON u.User_ID = tu.UserId
					where  tu.SalesTargetId =   @SalesTargetId;

			end
			set @last_sales_targetId = @SalesTargetId ;
			set @K_MIN = @K_MIN + 1;
		end


		if (@P_userID = 0)
		begin
			select SalesTargetId, UserId, targetPoint, ISactive, Target_date, UserName, TargetName, target_period, targeteType, targetFor, target_assigned, target_achieved from #tempTargetUsers  
		end
		else begin
			select SalesTargetId, UserId, targetPoint, ISactive, Target_date, UserName, TargetName, target_period, targeteType, targetFor, target_assigned, target_achieved from #tempTargetUsers
			where UserId in ( @P_userID );
		end
end


GO

/* ============================================================
   Procedure: [dbo].[usp_SM_Incentive_Earned]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
if object_id('usp_SM_MileStone_Earned') is not null
	begin  drop proc usp_SM_MileStone_Earned
end

tbl_LeadEventHistory order by 1 desc   ---   all history goes into this table 

