CREATE   PROC usp_SM_Incentive_Earned
(
	 @P_UserID   BIGINT,
	 @P_EventName varchar(300)
)
AS
BEGIN
	
		---tbl_SM_Employee_Incentive_History
		--- tbl_SM_Employee_MileStone_History
		--- tbl_SM_Employee_Points_History
		---  delete from tbl_SM_Employee_MileStone_History

		Declare @Point_Start_date datetime  =  '01-Jul-2024';

		Declare @Start_date datetime , @End_date datetime, @Cur_date  datetime = getdate() ;


		Declare @K_POINTS INT , @MileStoneAchieved int , @targetAchieved int , @badgeEarned int, @IncentiveAmount bigint  ; 
		Declare @Reward_type  varchar(100) , @Incentive_json varchar(max) , @roles_json varchar(max) , @reward_json varchar(max) , @IsExpirable bit , @Exp_date datetime ;

	
		--select @Reward_type =  Reward_type ,@Incentive_json = Performance_json ,@roles_json = Roles_json ,@reward_json = Reward_json , @IsExpirable = Is_expirable ,
		--@Exp_date = Exp_date  
		--from tbl_SM_Employee_Incentive(nolock) where incentive_type like '%'+ @P_EventName + '%' 

		Print Concat('Reward json  > ' , @reward_json);

		IF OBJECT_ID('tempdb..#temp_incentive') is not null begin drop table #temp_incentive end;
		
		select * into #temp_incentive from tbl_SM_Employee_Incentive(nolock) where
		 ( INCENTIVE_TYPE like '%'+ @P_EventName + '%' OR incentive_type = @P_EventName ) and IsActive =1
		AND ParentID = (SELECT ParentID FROM User_Detail(nolock) WHERE USER_ID = @P_UserID) ;

		DECLARE @COUNT INT , @LOOP_COUNT INT = 0 , @MAX_ID INT , @MIN_ID INT;

		select @MAX_ID = MAX(ID) from #temp_incentive(nolock) ;
		select @MIN_ID = MIN(ID) from #temp_incentive(nolock) ;

	
		WHILE (@MAX_ID >= @MIN_ID)
		BEGIN

			select @Reward_type =  Reward_type ,@Incentive_json = Performance_json ,  @roles_json = Roles_json ,@reward_json = Reward_json ,
			@IsExpirable = Is_expirable , @Exp_date = Exp_date  from #temp_incentive(nolock) where ID = @MIN_ID;
			
			Declare @PeriodType varchar(100) = '', @Min_score int =0;

			IF EXISTS(SELECT 1 FROM #TEMP_INCENTIVE(nolock) where  coalesce( @Reward_type,'') <>'' )
			BEGIN

				IF (@P_EVENTNAME = 'PERFORMANCE BASED') BEGIN
					--******performance *********************
					if OBJECT_ID('tempdb..#temp_performance') is not null begin drop table #temp_performance end;
					-- {"Type":"Performance","Period":"Monthly","min_score":"2000"}
					Create table #temp_performance
					(
						Id int identity(1,1),
						[Type] varchar(100),
						[Period] varchar(100),
						[min_score] varchar(10) 
					)
					SET @INCENTIVE_JSON = '['+@INCENTIVE_JSON+']';
				
					insert into #temp_performance
					select 
					JSON_VALUE(value, '$.Type'),
					JSON_VALUE(value, '$.Period'),
					JSON_VALUE(value, '$.min_score')
					from openjson(@Incentive_json)

					select @PeriodType = [Period] ,  @Min_score = [min_score]  from #temp_performance(nolock);

				END

				IF (@P_EVENTNAME = 'MILESTONE BASED') BEGIN
					
					select  @Incentive_json = Milestone_json from #temp_incentive(nolock) where ID = @MIN_ID;

					if OBJECT_ID('tempdb..#temp_Milestones') is not null begin drop table #temp_Milestones end;
					-- {"type":"Fastest Achievers","Applicableto":"MILE6","unit":"Percentage","value":"90"}

					Create table #temp_Milestones
					(
						Id int identity(1,1),
						[Type] varchar(100),
						[ApplicableTo] varchar(100),
						[Unit] varchar(10),
						[value] int
					)

					SET @INCENTIVE_JSON = '['+@INCENTIVE_JSON+']';
					
					PRINT CONCAT(' INCENTIVE_JSON  > ' , @INCENTIVE_JSON);

					insert into #temp_Milestones
					select 
					JSON_VALUE(value, '$.type'),
					JSON_VALUE(value, '$.Applicableto'),
					JSON_VALUE(value, '$.unit'),
					JSON_VALUE(value, '$.value')
					from openjson(@Incentive_json)

					Declare @MilestoneType varchar(100) = '', @m_appplicableto  varchar(100) , @m_unit varchar(20), @m_value int =0;			
					select @MilestoneType = [Type] , @m_appplicableto = Applicableto , @m_unit = unit , @m_value = [value]   from #temp_Milestones(nolock);

					PRINT CONCAT(' MILESTONE_name =  @m_appplicableto > ' , @m_appplicableto , ', MILESTONE TYPE > ' ,@MilestoneType , ' VALUE > ' , @m_value );

				END

				set @Start_date = @Point_Start_date;
				PRINT CONCAT(' PERIOD TYPE > ' , @PERIODTYPE , 'Start date' ,@Start_date  );
				IF ( COALESCE (@PERIODTYPE, '') ='') BEGIN SET @PERIODTYPE = 'MONTHLY' END ;
				PRINT CONCAT(' PERIOD TYPE > ' , @PERIODTYPE , 'Start date' ,@Start_date  );
				IF @PERIODTYPE ='MONTHLY'
				BEGIN
					set @End_date = DATEADD(MONTH, 1, @Start_date);
				END

				IF @PERIODTYPE ='Quarterly'
					set @End_date = DATEADD(MONTH, 3, @Start_date);
				END

				BEGIN
				IF @PERIODTYPE ='Half Yearly'
				BEGIN
					set @End_date = DATEADD(MONTH, 6, @Start_date);
				END

				IF @PERIODTYPE ='Yearly'
				BEGIN
					set @End_date = DATEADD(MONTH, 12, @Start_date);
				END

				SET @End_date = DATEADD(DAY, -1, @End_date);
				PRINT CONCAT('Start date' ,@Start_date, ', end date > ', @End_date , ' cur date >', @Cur_date );
				PRINT CONCAT('Start date' ,@Start_date, ', end date calculte > ', convert (varchar, DATEADD(DAY, -1, @Cur_date), 23) , ' cur date >', @Cur_date );
				
				Declare @F_date as datetime  = DATEADD(DAY, -1, @Cur_date);

				PRINT concat(' fdate > ' , @F_date);

				if  @F_date = @End_date or  @End_date < @Cur_date begin
					
					SET @Start_date =  DATEADD(DAY, 1,  @End_date); ;

					IF @PERIODTYPE ='MONTHLY'
					BEGIN
						set @End_date = DATEADD(MONTH, 1, @Start_date);
					END

					IF @PERIODTYPE ='Quarterly'
						set @End_date = DATEADD(MONTH, 3, @Start_date);
					END

					BEGIN
					IF @PERIODTYPE ='Half Yearly'
					BEGIN
						set @End_date = DATEADD(MONTH, 6, @Start_date);
					END

					IF @PERIODTYPE ='Yearly'
					BEGIN
						set @End_date = DATEADD(MONTH, 12, @Start_date);
					END
				end

				SET @Start_date =  CONVERT(VARCHAR , @Start_date , 23);
				SET @End_date =  CONVERT(VARCHAR , @End_date , 23);
				SET @End_date = DATEADD(DAY, -1, @End_date);

				PRINT CONCAT('FINAL = Start date' ,@Start_date, ', end date > ', @End_date   );

				if (@P_EventName = 'Consistency Based')begin
					
					IF OBJECT_ID('TEMPDB..#tempTargetIncentiveUsers') IS NOT NULL BEGIN DROP TABLE #tempTargetIncentiveUsers END ;

					Create table #tempTargetIncentiveUsers
					(
						id int identity (1,1),
						SalesTargetId bigint,
						UserId bigint,
						targetPoint decimal(16,2),
						ISactive bit,
						Target_date datetime null,
						UserName varchar(200) null ,
						TargetName varchaR(100) null,
						target_period varchar(100) null,
						targeteType varchar(500) null,
						targetFor varchar(50) null,
						target_assigned decimal(16,2) null,
						target_achieved decimal(16,2) null
					);

					Declare @Cons_target_period varchar(100) , @Cons_target_unit int;

					select  @Incentive_json = Consistency_json  from #temp_incentive(nolock) where ID = @MIN_ID;
			
					IF OBJECT_ID('TEMPDB..#temp_consistency_Reward') IS NOT NULL BEGIN DROP TABLE #temp_consistency_Reward END ;

					Create table #temp_consistency_Reward
					(
						Id int identity(1,1),
						Target_period varchar(100),
						Target_unit int
					)
					
					SET @Incentive_json  = '['+ @Incentive_json +']';

					insert into #temp_consistency_Reward
					select 
					JSON_VALUE(VALUE, '$.Target_period'),
					JSON_VALUE(VALUE, '$.Target_unit')
					FROM OPENJSON(@Incentive_json)

					select @PERIODTYPE = Target_period , @Cons_target_unit =  Target_unit from #temp_consistency_Reward(nolock);
					insert into #tempTargetIncentiveUsers
					exec usp_sm_GetuserTargetStatus @Start_date , @End_date ,0

				end

				/*******Roles *********************/

				if OBJECT_ID('tempdb..#temp_roles') is not null begin drop table #temp_roles end;
				-- [{"type":"include","roles":"Manager"}]
				Create table #temp_roles
				(
					Id int identity(1,1),
					[Type] varchar(100),
					[Roles] varchar(100)
				)

				set @roles_json = '['+@roles_json+']';

				insert into #temp_roles
				select 
				JSON_VALUE(value, '$.type'),
				JSON_VALUE(value, '$.roles')
				from openjson(@roles_json)

				Declare @RoleType varchar(100) = '', @Roles varchar(100) = '' ;
				select @RoleType = [Type] ,  @Roles = [Roles]  from #temp_roles(nolock);
				
				DECLARE @P_RoleExist bit =0;

				EXEC USP_GETUSER_BYROLE @P_USERID , @Roles , @P_RoleExist output;
				
				IF  @P_RoleExist = 0 and @RoleType ='include'
				BEGIN
					PRINT 'Role not matched';
					GOTO NEXTLOOP;
				END
				IF  @P_RoleExist = 1 and @RoleType ='exclude'
				BEGIN
					PRINT 'Role not matched';
					GOTO NEXTLOOP;
				END

				/******************Rewards**********************/
				---{"reward_type":"Cash","cashType":"Fixed","fixed":{"Amount":"20000"},"slab":{"slab_score_from":"","slab_score_to":"","amount":""},"Proportionate":{"Point":"","Amount":""}}
		
				if OBJECT_ID('tempdb..#temp_rewards') is not null begin drop table #temp_rewards end;
				-- {"Type":"Performance","Period":"Monthly","min_score":"2000"}
				Create table #temp_rewards
				(
					Id int identity(1,1),
					[reward_type] varchar(100),
					[cashType] varchar(100),
					[fixed_amount] varchar(100),
					[slab_score_from] varchar(100),
					[slab_score_to] varchar(100),
					[slab_amount] varchar(100),
					[Proportionate_point] varchar(100),
					[Proportionate_amount] varchar(100)
				)

				set @reward_json = '['+@reward_json+']';

				print concat ('Reward_json > ',@reward_json);

				insert into #temp_rewards
				select 
				JSON_VALUE(value, '$.reward_type'),
				JSON_VALUE(value, '$.cashType'),
				JSON_VALUE(value, '$.fixed.Amount'),
				JSON_VALUE(value, '$.slab.slab_score_from'),
				JSON_VALUE(value, '$.slab.slab_score_to'),
				JSON_VALUE(value, '$.slab.amount'),
				JSON_VALUE(value, '$.Proportionate.Point'),
				JSON_VALUE(value, '$.Proportionate.Amount')
				from openjson(@reward_json)

				Declare  @r_type varchar(50), @cashType varchar(50), @fixed_amount varchar(20), @voucher_details varchar(500), @slab_score_from int , @slab_score_to int , @slab_amount int, @Prop_Point int, @Prop_amount int;
				Declare @TotalPoints int  = 0,   @calc_amount int ;
			
				Declare @reward_max_id int,  @Reward_min_id int = 0;
				select @reward_max_id = MAX(id) from #temp_rewards(nolock);
				select @Reward_min_id = MIN(id) from #temp_rewards(nolock);

				PRINT concat('Reward loop start - max id reward > ', convert(varchar, @reward_max_id))

				IF (@IsExpirable =1) BEGIN
					IF (@Cur_date > @Exp_date ) BEGIN
						GOTO NEXTLOOP;
					END
				END

				while (@Reward_min_id <= @reward_max_id )
				BEGIN

					PRINT concat('-----Under loop of Reward  - min id reward > ', convert(varchar, @Reward_min_id),'---------')

					select top  1  @r_type = coalesce( reward_type,'') , @cashType= coalesce( cashType ,''), 
					@fixed_amount  =   convert (varchar, fixed_amount) ,
					@voucher_details = case when  coalesce( reward_type,'') ='kind' then convert(varchar, fixed_amount) end, 
					@slab_score_from = Coalesce (slab_score_from, '') , 
					@slab_score_to = Coalesce (slab_score_to, ''), @slab_amount =  Coalesce(slab_amount ,'') , @Prop_Point = Coalesce (Proportionate_point,''),
					@Prop_amount =  Coalesce ( Proportionate_amount,'')  from #temp_rewards(nolock) WHERE ID = @Reward_min_id;

					/* Get points from history table */
					IF (@P_EVENTNAME = 'PERFORMANCE BASED') BEGIN

						select @TotalPoints = sum(points) from tbl_SM_Employee_Points_History(nolock) where  userid = @P_UserID  and (TranDate between @Start_date and  @End_date) and Isactive = 1 ;
				
						if (@Min_score <= @TotalPoints)
							begin
								IF ( @cashType = 'Fixed')
								BEGIN

									print concat(' r_type > ' , @r_type , ' , cashType > ' ,@cashType ,' start date > ',@Start_date , ' END DATE > ' ,@End_date );

									IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId = @P_UserID  and Points_earned = @TotalPoints and  Isactive = 1 
													AND IncentiveId = @MIN_ID AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
										INSERT INTO  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	Points_earned,	Incentive_Amount, Voucher_details,
										TranDate,	ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
										SELECT @P_UserID ,@MIN_ID , @Reward_type , @TotalPoints , @fixed_amount,  
										case when  coalesce( @Reward_type,'') ='kind' then convert(varchar, @voucher_details) end ,
										getdate() , 0 , '', 'Performance incentive fixed', 1,  0 , 	GETDATE();

									END

								END
								ELSE IF ( @cashType = 'Slab')
								BEGIN
									IF ( @TotalPoints between  @slab_score_from and @slab_score_to )
									BEGIN
										IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID  and Points_earned = @TotalPoints and  Isactive = 1 
										AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
											insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	Points_earned,	Incentive_Amount, Voucher_details,
												 TranDate, ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
										 select @P_UserID ,@MIN_ID , @Reward_type , @TotalPoints , @slab_amount, 
										 case when  coalesce( @Reward_type,'') ='kind' then convert(varchar, @voucher_details) end , getdate() , 0 , '',
										 'Performance incentive slab', 1,  0 , GETDATE();
										END
									END

								END
								ELSE IF (@r_type <> 'Kind' AND @cashType = 'Proportionate')
								BEGIN
							
									set @calc_amount  = @TotalPoints * @Prop_amount / @Prop_Point ;
							
									IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID  and Points_earned = @TotalPoints and  Isactive = 1 
												AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
										INSERT INTO  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	Points_earned,	Incentive_Amount, Voucher_details, TranDate, ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
										SELECT @P_UserID ,@MIN_ID , @Reward_type , @TotalPoints , @calc_amount,
										case when  coalesce( @Reward_type,'') ='kind' then convert(varchar, @voucher_details) end ,
										getdate() , 0 , '', 'Performance incentive proportionate', 1,  0 , GETDATE();

									END
								END

							END
				
					end
					IF (@P_EVENTNAME = 'MILESTONE BASED') BEGIN
						Declare  @IsExist bit =0, @Milestone_Count int =0;

						select TOP 1  @IsExist = (case when count(1) > 0 then 1 else  0 end) , @Milestone_Count = count(1) from tbl_SM_Employee_MileStone_History(nolock)  where UserId =  @P_UserID  and (TranDate between @Start_date and  @End_date) and Isactive = 1 and MilestoneID = ( select id from tbl_SM_MileStones where Milestone_Name =   @m_appplicableto )

						----{"type":"Fastest Achievers","Applicableto":"MILE6","unit":"Percentage","value":"90"}
						---select 'test exist', @IsExist , @Start_date , @End_date , @cashType ,@MilestoneType;

						--select * from tbl_SM_MileStones where Milestone_Name = 'MILE(10%)'

						--select *  from tbl_SM_Employee_MileStone_History  where UserId =  34594  and (TranDate between '2024-08-01' and '2024-08-30') and Isactive = 1 and MilestoneID = ( select id from tbl_SM_MileStones where Milestone_Name = 'MILE(10%)'  )


						PRINT concat ('MILESTONE BASED = ' ,'Milestone name -> ',@m_appplicableto , ' @MilestoneType > ', @MilestoneType, ', Isexist > ', convert(varchar, @IsExist) );
						
						IF (@MilestoneType = 'All Achievers') BEGIN
							PRINT('MILESTONE BASED > All achievers');

							if (@IsExist =1) begin
								IF (@CASHTYPE = 'FIXED')
								BEGIN
									PRINT('MILESTONE BASED > All achievers > cash type - Fixed');	
									print concat('SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY where UserId =', convert(varchar, @P_UserID ),' and MileStoneAchieved =', 
									convert(varchar,@Milestone_Count) ,	'and  Isactive = 1 AND IncentiveId = ', convert(varchar, @MIN_ID),'  AND createdate >', convert(varchar, @Start_date));
									IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID  and MileStoneAchieved = @Milestone_Count 
											and  Isactive = 1 	AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
										insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	MileStoneAchieved,	Incentive_Amount,Voucher_details, TranDate,	ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)	
										select @P_UserID ,@MIN_ID , @Reward_type , @Milestone_Count , @fixed_amount , 
										case when  coalesce( @Reward_type,'') ='kind' then convert(varchar, @voucher_details) end,
										getdate() , 0 , '', 'Milestone incentive Fixed', 1,  0 , GETDATE();
									END
								END
								ELSE IF ( @cashType = 'Slab')
								BEGIN
									
									PRINT('MILESTONE BASED > All achievers > cash type - Slab');

									IF ( @TotalPoints between  @slab_score_from and @slab_score_to )
									BEGIN
								
										print concat('SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =', convert(varchar, @P_UserID ),' and MileStoneAchieved =', 
											convert(varchar,@Milestone_Count) ,	'and  Isactive = 1 AND IncentiveId = ', convert(varchar, @MIN_ID),'  AND createdate >', convert(varchar, @Start_date));

										IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID  and MileStoneAchieved = @Milestone_Count 
										and  Isactive = 1 AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
										
											insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	MileStoneAchieved, Incentive_Amount, Voucher_details, TranDate,	ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
											select @P_UserID ,@MIN_ID , @Reward_type , @Milestone_Count , @slab_amount, 
											case when  coalesce( @Reward_type,'') ='kind' then convert(varchar, @voucher_details) end, 
											getdate() , 0 , '', 'Milestone incentive slab', 1,  0 , GETDATE();

										END

									END
								END
								ELSE IF ( @R_TYPE <> 'Kind'  AND @cashType = 'Proportionate')
								BEGIN
									
									PRINT('MILESTONE BASED > All achievers > cash type - Proportionate');
									
									set @calc_amount  = @TotalPoints * @Prop_amount / @Prop_Point ;
							
									IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID  and MileStoneAchieved = @Milestone_Count 
									and  Isactive = 1 AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
										insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	MileStoneAchieved, Incentive_Amount, Voucher_details,
										TranDate, ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
										select @P_UserID ,@MIN_ID , @Reward_type , @Milestone_Count , @calc_amount ,
										case when  coalesce( @Reward_type,'') ='kind' then convert(varchar, @voucher_details) end, 
										getdate() , 0 , '', 'Milestone incentive proportionate', 1,  0 , GETDATE();
									END

								END

							END
						END

						IF (@MilestoneType = 'Top Achievers') 
						BEGIN

							PRINT('MILESTONE BASED > Top achievers ');
									
							if (@m_unit = 'Number') begin
								select  top(@m_value)  @IsExist = (case when count(1) > 0 then 1 else  0 end)   from  tbl_SM_Employee_MileStone_History(nolock)  where userid  = @P_UserID and  (TranDate between @Start_date and  @End_date) and Isactive = 1 
								and MilestoneID = ( select id from tbl_SM_MileStones(nolock) where Milestone_Name =   @m_appplicableto )   --- applicable milestone
							
							end

							Declare @TotalAchievers int = 0 ; 

							if (@m_unit = 'Percent') begin
							
								select  @TotalAchievers =  count(1)    from tbl_SM_Employee_MileStone_History(nolock)  where  (TranDate between @Start_date and  @End_date) and Isactive = 1 
									and MilestoneID = ( select id from tbl_SM_MileStones(nolock) where Milestone_Name =   @m_appplicableto )  
							
								set @m_value = @TotalAchievers * @m_value/ 100;

								select  top (@m_value)  @IsExist = (case when count(1) > 0 then 1 else  0 end)  from tbl_SM_Employee_MileStone_History(nolock)  where userid  = @P_UserID and  (TranDate between @Start_date and  @End_date) and Isactive = 1 
								and MilestoneID = ( select id from tbl_SM_MileStones(nolock) where Milestone_Name =   @m_appplicableto )   --- applicable milestone
					 

							end

							if (@IsExist =1) begin

								IF ( @CASHTYPE = 'FIXED')
								BEGIN
									PRINT('MILESTONE BASED > Top achievers  > Fixed');

									IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID  and MileStoneAchieved = @Milestone_Count and  Isactive = 1 	AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date) BEGIN
									
										insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	MileStoneAchieved,	Incentive_Amount, Voucher_details , TranDate,	ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
										select @P_UserID ,@MIN_ID , @Reward_type , @Milestone_Count , @fixed_amount ,
										case when  coalesce( @Reward_type,'') ='kind' then convert(varchar, @voucher_details) end, 
										getdate() , 0 , '', 'Milestone incentive Fixed', 1,  0 , GETDATE();

									END
								END
								ELSE IF ( @cashType = 'Slab')
								BEGIN
									PRINT('MILESTONE BASED > Top achievers > cash type - Slab');
									IF ( @TotalPoints between  @slab_score_from and @slab_score_to )
									BEGIN
								

										IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID  and MileStoneAchieved = @Milestone_Count and  Isactive = 1 AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
											insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	MileStoneAchieved, Incentive_Amount, Voucher_details, TranDate,	ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
											select @P_UserID ,@MIN_ID , @Reward_type , @Milestone_Count , @slab_amount, 
											case when  coalesce( @Reward_type,'') ='kind' then convert(varchar, @voucher_details) end, 
											getdate() , 0 , '', 'Milestone incentive slab', 1,  0 , GETDATE();

										END

									END
								END
								ELSE IF ( @R_TYPE <> 'Kind'  AND @cashType = 'Proportionate')
								BEGIN
									PRINT('MILESTONE BASED > Top achievers > cash type - Proportionate');
									set @calc_amount  = @TotalPoints * @Prop_amount / @Prop_Point ;
									IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID  and MileStoneAchieved = @Milestone_Count 
									and  Isactive = 1 AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
										insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	MileStoneAchieved, Incentive_Amount, 
										TranDate, ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
										select @P_UserID ,@MIN_ID , @Reward_type , @Milestone_Count , @calc_amount , getdate() , 0 , '', 
										'Milestone incentive proportionate', 1,  0 , GETDATE();
									END

								END

							 END

						END

						IF (@MilestoneType = 'Fastest Achievers') BEGIN
							if (@IsExist =1) begin

							PRINT('MILESTONE BASED > fastest achievers ');

								IF (  @CASHTYPE = 'Fixed')
								BEGIN

									PRINT('MILESTONE BASED > fastest achievers  > Fixed');

									IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID  and MileStoneAchieved = @Milestone_Count 
									and  Isactive = 1 	AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date  ) BEGIN
										insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	MileStoneAchieved,	Incentive_Amount, Voucher_details , TranDate,	ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
										select @P_UserID ,@MIN_ID , @Reward_type , @Milestone_Count , @fixed_amount ,
										case when  coalesce( @Reward_type,'') ='kind' then convert(varchar, @voucher_details) end, 
										getdate() , 0 , '', 'Milestone incentive Fixed', 1,  0 , GETDATE();

									END

								END
								IF ( @CASHTYPE = 'Slab')
								BEGIN
									PRINT('MILESTONE BASED > fastest achievers  > Slab');
									IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID  and MileStoneAchieved = @Milestone_Count 
									and  Isactive = 1 AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
										insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	MileStoneAchieved,	Incentive_Amount, Voucher_details, TranDate, ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
										select @P_UserID ,@MIN_ID , @Reward_type , @Milestone_Count , @slab_amount,
										case when  coalesce( @Reward_type,'') ='kind' then convert(varchar, @voucher_details) end , 
										getdate() , 0 , '', 'Milestone incentive Fixed', 1,  0 ,  GETDATE();

									END

								END
								IF ((@R_TYPE <> 'Kind' ) AND @CASHTYPE = 'Proportionate')
								BEGIN

									PRINT('MILESTONE BASED > fastest achievers  > Proportionate');

									set @calc_amount  = @TotalPoints * @Prop_amount / @Prop_Point ;
									IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID  and MileStoneAchieved = @Milestone_Count and  Isactive = 1 	AND IncentiveId =  @MIN_ID AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
										insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	MileStoneAchieved,	Incentive_Amount, TranDate,	
											ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
										select @P_UserID ,@MIN_ID , @Reward_type , @Milestone_Count , @calc_amount , getdate() , 0 , '', 'Milestone incentive Proportionate', 1,  0 , GETDATE();

									END
								END
							END
						END
					END
					IF (@P_EVENTNAME = 'Consistency Based') BEGIN
					 
						PRINT('Consistency Based');

						SET @IsExist = 0;

						SELECT   @targetAchieved  =  sum(1) 
							FROM #tempTargetIncentiveUsers(nolock) tu   WHERE tu.userid =@P_UserID 
							group by  tu.targetPoint , tu.SalesTargetId
							having  (case when (SUM (COALESCE (target_achieved,0)) / tu.targetPoint) = 1 then 1 else 0 end)   > 0 

						if @Cons_target_unit < @targetAchieved 
						begin
							SET @IsExist = 1;
						end

						PRINT CONCAT('Reward type > ', @Reward_type);

						IF (@IsExist =1 ) BEGIN
							if (  @cashType = 'Fixed') begin
								PRINT('Consistency Based > fixed');
								IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID   and  Isactive = 1 
												AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
											insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	Target_achieved, Voucher_details,	Incentive_Amount, TranDate,	ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
											select @P_UserID ,@MIN_ID , @Reward_type , @targetAchieved , @fixed_amount,
											case when  coalesce( @Reward_type,'') ='kind' then convert(varchar, @voucher_details) end,  
											getdate() , 0 , '', 'Consistency incentive fixed', 1,  0 , GETDATE();
								END
							END

							if ( @cashType = 'Slab') begin
								PRINT('Consistency Based > Slab');
								IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID   and  Isactive = 1 
												AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
											insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	Target_achieved,	Incentive_Amount,
											Voucher_details, TranDate,	ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
											select @P_UserID ,@MIN_ID , @Reward_type , @targetAchieved , @slab_amount,
											case when  coalesce( @Reward_type,'') ='kind' then convert(varchar, @voucher_details) end, 
											GETDATE() , 0 , '', 'Consistency incentive slab ', 1,  0 , GETDATE();
								END
							END

							if (@Reward_type <> 'Kind' AND @cashType = 'Proportionate') begin
								PRINT('Consistency Based > Proportionate');
								set @calc_amount  = @TotalPoints * @Prop_amount / @Prop_Point ;
								IF NOT EXISTS (SELECT 1 FROM  TBL_SM_EMPLOYEE_INCENTIVE_HISTORY(nolock) where UserId =@P_UserID   and  Isactive = 1 
												AND IncentiveId =  @MIN_ID  AND createdate > @Start_date AND createdate <= @End_date ) BEGIN
											insert into  tbl_SM_Employee_Incentive_History(UserId,	IncentiveId,	IncentiveType,	Target_achieved,	Incentive_Amount, TranDate,	
												ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
											select @P_UserID ,@MIN_ID , @Reward_type , @targetAchieved , @calc_amount, getdate() , 0 , '', 'Consistency incentive proportionate ', 1,  0 , GETDATE();
								END
							END
						END					 
					END
					SET @Reward_min_id =  @Reward_min_id +1;
				END
			END
NEXTLOOP:
			SET @MIN_ID = @MIN_ID +1;
		END



END





