/* ============================================================
   Procedure: [dbo].[usp_sm_InsertscoringRecord]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*

EXEC usp_sm_InsertscoringRecord 'new record', '2024/01/05' , 32222 , 'tblleadhistory' , 1253;

*/


CREATE   PROC usp_sm_InsertscoringRecord
(
	@P_activityname nvarchar(2000),
	@P_Activity_time datetime,
	@P_UserId bigint,
	@P_history_tableName varchar(200),
	@P_History_row_id bigint
)
as
begin


	Declare @ParentId  bigint = dbo.ufn_getuserparentid(@P_UserId);
	Declare @Eventid int = (select id from ActivityMaster(nolock) where EventName = @P_activityname )
	
	IF ( EXISTS( SELECT 1 FROM TBL_SM_SCORINGRULE(nolock) WHERE ACTIVITY_ID = @Eventid   AND ParentId = @Parentid  ) )
	begin
		begin try	
		insert into tbl_sm_ScoringRaw(Activity_name ,Activity_datetime , userid, HistorytableName , History_row_id , Createdtime , ProcessStartTime , ProcessEndTime , ErrorResponse , Isproceesed  )
		select @P_activityname , @P_Activity_time , @P_UserId , @P_history_tableName , @P_History_row_id , GETDATE() ,  null , null , null, 0
		end try
		begin catch
			print  concat(@@error, CAST(ERROR_NUMBER() AS VARCHAR) ,CAST(ERROR_message() AS VARCHAR) );

		end catch
	end

end




