/* ============================================================
   Procedure: [dbo].[USP_SM_LOADEMPSCORINGRULE]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
IF OBJECT_ID('USP_SM_LOADEMPSCORINGRULE') IS NOT NULL
BEGIN
DROP PROCEDURE USP_SM_LOADEMPSCORINGRULE
END

 USP_SM_LOADEMPSCORINGRULE  1, '', 34594
 

*/

CREATE   PROC USP_SM_LOADEMPSCORINGRULE
(
	@P_ACTIVE INT = 0,
	@P_SEARCH_TEXT VARCHAR(150)='',
	@P_USERID BIGINT =0
)
AS 
BEGIN
	 
	DECLARE @PARENTID BIGINT = 0  , @CondCount int =0;
	SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_USERID  
	
	
	DECLARE @UserDetails  tbl_type_sm_UserDetails;

	INSERT INTO @UserDetails
	EXEC Use_GetUserDetails @PARENTID;
	

	SELECT  TB_SM.ID [Rule_Id],  RULE_NAME[Rule_name], AM.EventName [Activity_Name], (Points_type + ':'+  convert(varchar(10),POINTS) ) as [Points] , 
	APPLICABLETO,  TB_SM.IsActive , '' as Action , (select coalesce( count(Rule_id),0) from tbl_SM_ScoringCondition where Rule_id = TB_SM.ID ) as cond_count , TB_SM.Activity_id FROM 
	TBL_SM_SCORINGRULE(NOLOCK)  TB_SM
	LEFT JOIN ACTIVITYMASTER(NOLOCK)  AM ON  AM.ID = TB_SM.Activity_id
	WHERE (case when @P_ACTIVE > 1 then 1 else TB_SM.ISACTIVE end )  = (case when @P_ACTIVE > 1 then 1 else @P_ACTIVE  end )  
	AND 
	(( CASE WHEN @P_SEARCH_TEXT='' THEN '1' ELSE RULE_NAME END) LIKE '%'+ ( CASE WHEN @P_SEARCH_TEXT='' THEN '1' ELSE @P_SEARCH_TEXT END)+'%'
	OR
	(CASE WHEN @P_SEARCH_TEXT='' THEN '1' ELSE AM.EventName END) LIKE '%'+( CASE WHEN @P_SEARCH_TEXT='' THEN '1' ELSE @P_SEARCH_TEXT END)+'%' )
	AND 
	TB_SM.Created_by in (select UserId from @UserDetails)

END


