CREATE   PROC USP_SM_LoadForEditRule
(
	@P_RULE_ID INT = 0,
	@P_USERID BIGINT =0
)
AS 
BEGIN
	 

	
	DECLARE @PARENTID BIGINT = 0  
	SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_USERID    

	DECLARE @UserDetails  tbl_type_sm_UserDetails;

	INSERT INTO @UserDetails
	EXEC Use_GetUserDetails @PARENTID;
	

	 
	SELECT  Rule_name,
			Activity_ID,
