usp_SM_LoadIncentives 1,'',34594
*/

CREATE   PROC usp_SM_LoadIncentives
(
	@P_ACTIVE INT ,
	@P_SEARCH_TEXT VARCHAR(150),
	@P_USERID BIGINT
)
AS
BEGIN

	DECLARE @PARENTID BIGINT = 0  
	SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_USERID    

	DECLARE @UserDetails  tbl_type_sm_UserDetails;

	INSERT INTO @UserDetails
	EXEC Use_GetUserDetails @PARENTID;
	

	SELECT ID [Incentive_id], Incentive_name, incentive_type, Reward_type , Roles_json, Is_expirable, Exp_date , IsActive 
	FROM  tbl_SM_Employee_Incentive(nolock) WHERE
	(CASE WHEN @P_ACTIVE = 2 THEN '1' ELSE  ISACTIVE END = CASE WHEN @P_ACTIVE =2  THEN '1' ELSE @P_ACTIVE END )AND
	(CASE WHEN COALESCE( @P_SEARCH_TEXT,'') ='' THEN '1' ELSE  Incentive_name END  = CASE WHEN COALESCE( @P_SEARCH_TEXT,'') ='' THEN '1' ELSE  @P_SEARCH_TEXT END )
	and created_by in  (select UserId from @UserDetails )


END


