/* ============================================================
   Procedure: [dbo].[usp_SM_MileStone_Earned]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*

if object_id('usp_SM_MileStone_Earned') is not null
	begin  drop proc usp_SM_MileStone_Earned
end


update tbl_st_salesactivitymaster set salesTargetID = 10113 ,  amount = 2500    where id =54


usp_SM_MileStone_Earned  34594, 'PointsActivity'

usp_SM_MileStone_Earned  32222, 'PointsActivity'



*/
CREATE  PROC usp_SM_MileStone_Earned
(
	 @P_UserID             BIGINT,                                         
	 @P_EventName          NVARCHAR(500)
)
AS
BEGIN
	

	Declare  @sales_targetId int , @k_sql_query nvarchar(max) ;

	Declare @Start_date datetime ,  @end_date datetime , @target_percentage int ,  @Point_target int ,  @Point_achieved  int ;

	if (@P_EventName = 'PointsActivity')
	begin
			DECLARE  @user_target_json nvarchar(max) ='' ,  @k_from_date datetime , @k_to_date datetime , @hierarchy_users varchar(1000) ='' ;

			DECLARE @PARENTID BIGINT = 0  
			SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_USERID    

			DECLARE @UserDetails  tbl_type_sm_UserDetails;

			INSERT INTO @UserDetails
			EXEC Use_GetUserDetails @PARENTID;

		--- get hierarchy users for the userid  concat users  

		select   @hierarchy_users  += convert( varchar(10),  coalesce( UserId,'') ) +','  from @UserDetails ;

		IF @hierarchy_users <> '' BEGIN
			set @hierarchy_users   =  SUBSTRING(@hierarchy_users , 1, len(@hierarchy_users) -1 );
		END

		print concat('Hierarchy users', @hierarchy_users);

		Declare @tbl_salestarget as table
		(
			id int identity(1,1),
			SaletargetId bigint,
			Startdate datetime,
			End_date datetime
		)

		insert into @tbl_salestarget 
		select SalesTargetId , TargetFromDate, TargetToDate   from TBL_ST_SalesTargetSettingMaster  where TargetFromDate <= convert( varchar, GETDATE(), 23 ) 
		and TargetToDate >= convert( varchar, GETDATE(), 23 ) 	and  convert( varchar,  @P_UserID) in (REPLACE(UserIds ,'#',',')) and TargetType = 3 ;
		

		Declare @max_salesTgt_Id bigint =0, @min_salesTgt_Id bigint =0;

		SELECT @max_salesTgt_Id = MAX(id) FROM @tbl_salestarget;
		SELECT @min_salesTgt_Id = MIN(id) FROM @tbl_salestarget;


		While ( @min_salesTgt_Id <= @max_salesTgt_Id )
		begin

			select  @sales_targetId = SaletargetId ,  @Start_date = Startdate   ,  @end_date = End_date  from @tbl_salestarget WHERE id = @min_salesTgt_Id

			print concat ('sales target id  > ' ,@sales_targetId , ', Start date > ', @Start_date ,', end date > ', @end_date );

			if OBJECT_ID('tempdb..#tempTargetAchieved') is not null begin drop table #tempTargetAchieved end;

			Create table #tempTargetAchieved
			(
				id int identity (1,1),
				SalesTargetId bigint,
				UserId bigint,
				targetPoint decimal(16,2),
				ISactive bit,
				Target_date datetime null,
				UserName varchar(200) null ,
				TargetName varchaR(100) null,
				target_period varchar(100) null,
				targeteType varchar(500) null,
				targetFor varchar(50) null,
				target_assigned decimal(16,2) null,
				target_achieved decimal(16,2) null
			)

			insert into #tempTargetAchieved
			exec usp_sm_GetuserTargetStatus @Start_date , @end_date ,@P_USERID ;

			select @target_percentage = coalesce( target_achieved, 0) * 100 / targetPoint ,  @Point_target  = targetPoint , @Point_achieved =  target_achieved   
			from #tempTargetAchieved  where targeteType = 'Points' 

			declare @setting_json nvarchar(max) ='' , @milestones varchar(500) ='' ;

			select  @setting_json = SettingJSON  from TBL_ST_SalesTargetSettingMaster where SalesTargetId = @sales_targetId;
		
			set @setting_json = '['+@setting_json+']';
		
			print concat('setting json' ,@setting_json  );

			if OBJECT_ID('tempdb..#temp_mile_stone') is not null begin drop table #temp_mile_stone end ;

			create table #temp_mile_stone
			(
				id int identity(1,1),
				UserId bigint,
				Milestones varchar(500)
			)

			if ( coalesce( @setting_json,'') <>'') begin
				
						--- sales target json milestone 
						print concat('setting json not empty > ', @setting_json  )

						insert into #temp_mile_stone(UserId , Milestones)
						select @P_UserID,  JSON_VALUE( VALUE, '$.Milestone') FROM OPENJSON(@setting_json)

						SET @user_target_json  =  case when  @user_target_json = ''  then '['+ @user_target_json +']'  else @user_target_json  end ;
					 
						SELECT top  1  @Milestones = Milestones FROM #temp_mile_stone  ;

						print concat('Milestones > ',@Milestones );

						truncate table #temp_mile_stone;
	
						INSERT INTO #temp_mile_stone(UserId , Milestones )
						SELECT distinct @P_UserID, VALUE FROM STRING_SPLIT(@Milestones, ',') WHERE COALESCE( VALUE,'')  <> '' ;

						---select * from #temp_mile_stone

						DECLARE @Condition_json nvarchar(max) , @Eventname varchar(1000), @Milestone_id int , @Milestone_name varchar(300), @count int , @loop_count int =1;
						DECLARE @Operatore varchar(10) , @c_value1 int , @c_value2 int , @output_var bit  ;

						select @count = count (id) from #temp_mile_stone;

						print concat('mile stone count', @count);

						while (@count >= @loop_count )
						begin
					
						print concat('mile stone loop id  no. > ', @loop_count);

				 			select @Condition_json = cond_json , @Eventname = Event_name , @Milestone_name = Milestone_Name , @Milestone_id  =  id from tbl_SM_MileStones where ID IN 
												(SELECT Milestones  FROM #temp_mile_stone where id =  @loop_count );
						
							set @Condition_json  = '[' + @Condition_json + ']';

							print concat('condition json ' , @Condition_json);

						 
								if OBJECT_ID('tempdb..#temp_milestone_conditions') is not null begin  drop table #temp_milestone_conditions end;

								create table #temp_milestone_conditions
								(
									ID int identity (1,1),
									[Type ] varchar(500),
									[Operatore] varchar(30),
									Value1 int ,
									Value2 int,
									Applicable varchar(100)
								)							

								insert into #temp_milestone_conditions
								select JSON_VALUE( value , '$.type') ,
								JSON_VALUE( value , '$.operator'),
								JSON_VALUE( value , '$.value1'),
								JSON_VALUE( value , '$.value2'),
								JSON_VALUE( value , '$.Applicable')
								from openjson(@Condition_json) ;
								
								print concat('Milestone condition  > ', @Condition_json);

								select  @Operatore = Operatore , @c_value1 = Value1 , @c_value2 = Value2   from  #temp_milestone_conditions ;

							
								if (@Operatore = 'Between') begin
									
									SET @OUTPUT_VAR = 0;

									set @k_sql_query = N' select  @output_var =  1  from #temp_milestone_conditions where '+ CONVERT( varchar(10), @target_percentage ) + ' '+ @Operatore +' ' +  CONVERT( varchar(10), @c_value1) + ' and ' +  CONVERT( varchar(10), @c_value2) ;

									PRINT @k_sql_query;

									exec sp_executesql @k_sql_query , N'@output_var bit OUTPUT' , @output_var output ;

									PRINT  ' OUTPUT  : ' + CONVERT( VARCHAR, @output_var);

									if ( @output_var  = 1 )
									begin
										
										print 'condition meet'
										IF NOT EXISTS ( SELECT 1 FROM    tbl_SM_Employee_MileStone_History WHERE SaleTarget_id =@sales_targetId AND UserId= @P_UserID  
													AND MilestoneID  = @Milestone_id   )
										BEGIN
										insert into tbl_SM_Employee_MileStone_History(  SaleTarget_id,	UserId,	MilestoneID,	Sale_target_Amount,	AchievedTargetAmount,	TranDate,	
											ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
										select  @sales_targetId, @P_UserID , @Milestone_id , @Point_target , @Point_achieved , GETDATE(),
											'' , '' , @Milestone_name + ' Acheived by the user' as remarks , 1, @P_UserID , GETDATE();
										 
										END 

										print concat('Milestone matched  > ', @Condition_json);


									END 
									ELSE BEGIN
										PRINT 'CONDITION NOT MACTH';
									END

								END
								ELSE   BEGIN
									set @output_var = 0;
									set @k_sql_query = N' select  @output_var =  1  from #temp_milestone_conditions where '+ CONVERT( varchar(10), @target_percentage ) + ' '+
														@Operatore +' ' +  CONVERT( varchar(10), @c_value1) ;

							
									PRINT @k_sql_query;
									exec sp_executesql @k_sql_query , N'@output_var bit OUTPUT' , @output_var output ;
									PRINT  ' OUTPUT  : ' + CONVERT( VARCHAR, @output_var);

									IF ( @OUTPUT_VAR  = 1 )
									BEGIN
											print 'condition meet'

											IF NOT EXISTS ( SELECT 1 FROM    tbl_SM_Employee_MileStone_History WHERE SaleTarget_id =@sales_targetId AND UserId= @P_UserID  
													AND MilestoneID  = @Milestone_id   )
										BEGIN
											insert into tbl_SM_Employee_MileStone_History(  SaleTarget_id,	UserId,	MilestoneID,	Sale_target_Amount,	AchievedTargetAmount,	TranDate,	
											ref_tran_id,	ref_tablename,	Remarks,	Isactive,	Createdby,	createdate)
											select  @sales_targetId, @P_UserID , @Milestone_id , COALESCE( @Point_target,0) , COALESCE( @Point_achieved,0) , GETDATE(),
											'' , '' , @Milestone_name + ' Acheived by the user' as remarks , 1, @P_UserID , GETDATE();
										END
									END
									ELSE BEGIN
										PRINT 'CONDITION NOT MACTH';
									END

								END
						 

					 
							set @loop_count =  @loop_count +1 ;

						END

				end


			SET @min_salesTgt_Id = @min_salesTgt_Id + 1;

		end

	end
	



END


