CREATE   PROCEDURE usp_SM_Points_Allowance
(
	@P_Allowance_ID INT =0,
	@P_ActivityId INT,
	@P_Role_id INT,
	@P_Userid INT,
	@P_AllownacePoints INT,
	@P_Balance_points INT,
	@P_expired_points INT,
	@P_max_cf_points INT,
	@P_Allowance_start_date datetime,
	@P_Allowance_end_date datetime,
	@P_Isexpirable bit,
	@P_Expiry_days INT,
	@P_Isactive BIT,
    @P_USER_ID BIGINT
)
AS
BEGIN
		IF (@P_Allowance_ID = 0)
		BEGIN
				INSERT INTO tbl_SM_Employee_Points_Allowance
				(
					ActivityId,
					Role_id,
					userid,
					AllownacePoints,
					Balance_points,
					expired_points,
					max_cf_points,
					Allowance_start_date,
					Allowance_end_date,
					Isexpirable,
					Expiry_days,
					created_by,
					created_date,
					Isactive
				)
				VALUES
				(
					@P_ActivityId,
					@P_Role_id,
					@P_userid,
					@P_AllownacePoints,
					@P_Balance_points,
					@P_expired_points,
					@P_max_cf_points,
					@P_Allowance_start_date,
					@P_Allowance_end_date,
					@P_Isexpirable,
					@P_Expiry_days,
					@P_USERID,
					GETDATE(),
					@P_Isactive 
				);

			   SELECT 'Record saved.' AS Message;
		END
		ELSE
		BEGIN
			UPDATE tbl_SM_Employee_Points_Allowance
			SET 
					ActivityId =ActivityId,
					Role_id= Role_id,
					userid =userid,
					AllownacePoints=AllownacePoints,
					Balance_points=Balance_points,
					expired_points=expired_points,
					max_cf_points = max_cf_points ,
					Allowance_start_date = Allowance_start_date,
					Allowance_end_date = Allowance_end_date,
					Isexpirable = Isexpirable,
					Expiry_days = Expiry_days,
					created_by = @P_USER_ID,
					created_date= GETDATE(),
					Isactive = @P_Isactive
				WHERE Allowance_ID = @P_Allowance_ID;

			SELECT 'Record updated.' AS Message;
		END;

END;



