/* ============================================================
   Procedure: [dbo].[USP_SM_PROCESS_SCORING]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*

update TBL_SM_SCORINGRAW set   ISPROCEESED = 0

tbl_SM_Employee_Points_History ORDER BY 1 DESC 

TBL_SM_SCORINGRAW  order by 1 desc

exec USP_SM_PROCESS_SCORING  2103

exec  usp_SM_Incentive_Earned 34594 , 'Milestone based';


*/

CREATE   PROC USP_SM_PROCESS_SCORING
(
	@P_Tran_ID bigint
)
AS BEGIN
	
	DECLARE @W_PROCESS_STARTIME  DATETIME  = GETDATE(),
	@W_ACTIVITY_NAME varchar(500) , @W_ACTIVITY_DATE_TIME  datetime , @W_USERID bigint , @W_HISTORY_TABLE varchar(200) , @W_HISTORY_ROW_ID bigint , 
	@W_CREATED_TIME  datetime  ;

	
	SELECT  @W_ACTIVITY_NAME = ACTIVITY_NAME ,  @W_ACTIVITY_DATE_TIME = Activity_datetime , @W_USERID =  UserId  ,
	@W_HISTORY_TABLE =  HistorytableName ,  @W_HISTORY_ROW_ID =  History_row_id ,   @W_CREATED_TIME = Createdtime FROM TBL_SM_SCORINGRAW(nolock) WHERE  ISPROCEESED = 0 AND ID  = @P_Tran_ID 


	EXEC  USP_SM_ADD_UPDATE_SCORES @W_USERID, @W_ACTIVITY_NAME , @W_HISTORY_TABLE , @W_HISTORY_ROW_ID ;
		
	UPDATE TBL_SM_SCORINGRAW SET ISPROCEESED =1 , ProcessStartTime =  @W_PROCESS_STARTIME , ProcessEndTime = GETDATE()  WHERE  ISPROCEESED = 0 AND ID  = @P_Tran_ID ;
		

	  -- milestone

	 exec usp_SM_MileStone_Earned  @W_USERID, 'PointsActivity' ;


	 --- incentive 
	 exec  usp_SM_Incentive_Earned @W_USERID , 'Performance Based';
	 exec  usp_SM_Incentive_Earned @W_USERID , 'Milestone based';
	 exec  usp_SM_Incentive_Earned @W_USERID , 'Consistency based';



END





