/* ============================================================
   Procedure: [dbo].[USP_SM_SAVE_MileStones]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
EXEC USP_SM_SAVE_MileStones 12, 'MILE1', 'FIRST ACHIEVEMENT IN TARGET PERIOD', '{"type":"Percentage achievement" , "operator":"<=" , "value1":"80" , "value2":"0" , "Applicable":"Manager" }',
'{"type":"Next Day of","mode":"SMS"},{"type":"Next Day of","mode":"EMAIL"},{"type":"Next Day of","mode":"APP"}' ,
'{"type":"Next Day of" ,"time":"00:40"}', 1,32222



--1,'DESKTOP','<Username> <target type> <target name> <target period achieved> <achieved short target> <short target> <achieved till> <(date)>',

EXEC  USP_SM_MilestoneMsgSave  1, 1 , 'DESKTOP', '<Username> <target type> <target name> <target period achieved> <achieved short target> <short target> <achieved till> <(date)>', 32222


SELECT * FROM TBL_SM_MILESTONEALERTMSGMASTER ORDER BY ID

--delete from TBL_SM_MILESTONEALERTMSGMASTER  where id = 4


SELECT * FROM tbl_SM_MileStones

--delete from tbl_SM_MileStones  where id =4
*/
CREATE   PROC USP_SM_SAVE_MileStones
(
	@P_MILE_ID INT,
	@P_MILENAME VARCHAR(500),
	@P_EVENTNAME VARCHAR(500),
	@P_COND_JSON VARCHAR(MAX),
	@P_ALERT_JSON VARCHAR(MAX),
	@P_MSG_TIME_JSON VARCHAR(MAX),
	@P_IS_ACTIVE BIT,
	@P_USERID BIGINT
)
AS BEGIN

	DECLARE @PARENTID BIGINT = 0  ,@W_MILE_ID INT , @W_MODE_COUNT INT, @W_LOOP_COUNT  INT= 1 , @W_MODE_NAME varchar(30);
	SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_USERID   
	

	BEGIN TRY

	IF(@P_MILE_ID = 0)
	BEGIN

		IF (NOT EXISTS(SELECT 1 FROM tbl_SM_MileStones(NOLOCK)  WHERE Milestone_Name = @P_MILENAME  AND ParentId = @PARENTID  ))
		BEGIN
			INSERT INTO tbl_SM_MileStones
			(
				Milestone_Name,
				Event_name,
				Cond_json,
				Alert_json,
				ISactive,
				ParentId,
				Create_by,
				created_date
			)
			VALUES
			(
				@P_MILENAME,
				@P_EVENTNAME,
				@P_COND_JSON,
				@P_ALERT_JSON,
				@P_IS_ACTIVE,
				@PARENTID,
				@P_USERID,
				GETDATE()
			)
			SET @W_MILE_ID = SCOPE_IDENTITY();
		END
		ELSE
		BEGIN
			SELECT 'Milestone name already exists';
			RETURN;
		END


	END
	ELSE IF (@P_MILE_ID > 0) BEGIN
		IF (NOT EXISTS(SELECT 1 FROM tbl_SM_MileStones(NOLOCK)  WHERE Milestone_Name = @P_MILENAME AND ID <> @P_MILE_ID  AND ParentId = @PARENTID ))
		BEGIN
			UPDATE tbl_SM_MileStones SET Milestone_Name =@P_MILENAME,
			Event_name= @P_EVENTNAME, 
			Cond_json = @P_COND_JSON,
			Alert_json = @P_ALERT_JSON,
			ISactive=  @P_IS_ACTIVE ,
			ParentId = @PARENTID,
			Modified_by= @P_USERID ,
			Modified_date =GETDATE()
			WHERE ID= @P_MILE_ID
			SET @W_MILE_ID = @P_MILE_ID;
		END
		ELSE
		BEGIN
			SELECT 'Milestone name already exists';
			RETURN;
		END

	END

		--- ADD OR UPDATE MILESTONEMESSAGE
		SET @W_MILE_ID = COALESCE(@W_MILE_ID,0);


		--- GET DATA FROM JSON 
			IF  OBJECT_ID('TEMPDB..#TEMP_ALERT_DATA') IS NOT NULL BEGIN DROP TABLE  #TEMP_ALERT_DATA    END

			SET @P_ALERT_JSON = '['+@P_ALERT_JSON+']';

			DECLARE @ROWDATA  NVARCHAR(MAX)='', @FIELDNAMES NVARCHAR(MAX)='', @SQLString NVARCHAR(MAX), @ROW_VALUES NVARCHAR(MAX) = '' ;
	
			SELECT  @ROWDATA= VALUE FROM OPENJSON(@P_ALERT_JSON)  
			PRINT @ROWDATA

			SELECT @FIELDNAMES=@FIELDNAMES+'['+[KEY]+'] NVARCHAR(2000),' FROM OPENJSON(@ROWDATA)                
			PRINT '@FIELDNAMES1: ' + @FIELDNAMES  

			SET @FIELDNAMES =SUBSTRING( @FIELDNAMES,1 ,LEN( @FIELDNAMES)  -1 )

			 CREATE TABLE #TEMP_ALERT_DATA
			 (
				ID int identity(1,1)
			 )

			 SET @SQLString  = ' ALTER TABLE #TEMP_ALERT_DATA  ADD '+@FIELDNAMES+' '

			 PRINT @SQLSTRING
			 EXEC(@SQLSTRING)

			SET @SQLString  =' 	INSERT INTO #TEMP_ALERT_DATA
					SELECT *  FROM OPENJSON('''+@P_ALERT_JSON +''') WITH ('+@FIELDNAMES+')'

			PRINT @SQLString
			EXECUTE SP_EXECUTESQL @SQLString 

			SELECT  @W_MODE_COUNT = count(id) FROM #TEMP_ALERT_DATA

			WHILE (@W_MODE_COUNT >= @W_LOOP_COUNT)
			BEGIN
				select @W_MODE_NAME = COALESCE(mode,'') from #TEMP_ALERT_DATA where ID  =  @W_LOOP_COUNT;
				EXEC  USP_SM_MilestoneMsgSave  @W_LOOP_COUNT, @W_MILE_ID , @W_MODE_NAME,'', @P_MSG_TIME_JSON, @P_USERID ;
				SET @W_LOOP_COUNT = @W_LOOP_COUNT +1;
			END


		Select 'Save Successful';

	END TRY
	BEGIN CATCH

		PRINT 'error occured';

		-- Optionally, handle errors and log them
		DECLARE @ErrorMessage NVARCHAR(4000);
		DECLARE @ErrorSeverity INT;
		DECLARE @ErrorState INT;

		SELECT
			@ErrorMessage = ERROR_MESSAGE(),
			@ErrorSeverity = ERROR_SEVERITY(),
			@ErrorState = ERROR_STATE();

	END CATCH

END


GO

