	--PRINT '@P_modeid >' +CONVERT(VARCHAR, @P_MODE_SNO) +';@P_modename > '+ CONVERT(VARCHAR, @P_modename) +';@PARENTID > ' + CONVERT(VARCHAR, @PARENTID)+
