SET QUOTED_IDENTIFIER ON

/*
	
	  

	exec usp_SM_SaveAwardbadge  0, 'badge 1' , 'c:/image/imag1.jpg' , 'Outstanding achiever' , 10 , 'Achievement' , '{"roles":"users","roles":"managers"}' ,
	20 , 'yes', 0 , '05-01-2024', '05-01-2025' , 1 , 32222


*/

CREATE   PROCEDURE usp_SM_SaveAwardbadge
(
	@P_BADGE_ID INT = 0 ,
    @P_Badge_Name varchar(200)  ,
	@P_Image_url varchar(max) ,
	@P_Badge_Description varchar(max)  ,
	@P_recv_badge_limit int   ,
	@P_Badge_Type varchar(150) ,
	@P_Roles_json varchar(1000),
	@P_Sender_limit int ,
	@P_Reason_requires varchar(10) ,
	@P_Points int ,
	@P_Period_from smalldatetime,
	@P_Period_to smalldatetime,
    @P_Active_status INT,
    @P_USERID BIGINT
)
AS
BEGIN

	IF (EXISTS(SELECT 1 FROM tbl_SM_AwardBadge(nolock) WHERE Badge_Name = @P_Badge_Name))
	BEGIN
		SELECT 'Badge name already exists.' AS Message;
		return;
	END

    IF (@P_BADGE_ID = 0)
    BEGIN
            INSERT INTO tbl_SM_AwardBadge
            (
                Badge_Name,
                Image_url,
                Badge_Description,
                recv_badge_limit,
                Badge_Type,
                Roles_json,
                Sender_limit,
                Reson_requires,
                Points,
				Period_from,
				Period_to,
                Active_status,
                created_by,
                created_date
            )
            VALUES
            (
                @P_Badge_Name,
                @P_Image_url,
                @P_Badge_Description,
                @P_recv_badge_limit,
                @P_Badge_Type,
                @P_Roles_json,
                @P_Sender_limit,
                @P_Reason_requires,
                @P_Points,
				@P_Period_from,
				@P_Period_to,
                @P_Active_status,
                @P_USERID,
                GETDATE()
            );

           SELECT 'Record saved.' AS Message;
    END
         
    ELSE
    BEGIN
        UPDATE tbl_SM_AwardBadge
        SET 
            Badge_Name = @P_Badge_Name,
            Image_url = @P_Image_url,
            Badge_Description = @P_Badge_Description,
            recv_badge_limit = @P_recv_badge_limit,
            Badge_Type = @P_Badge_Type,
            Roles_json = @P_Roles_json,
            Sender_limit = @P_Sender_limit,
            Reson_requires = @P_Reason_requires,
            Points = @P_Points,
			Period_from = @P_Period_from,
			period_to =	@P_Period_to,
            Active_status = @P_Active_status,
            modified_by = @P_USERID,
            modified_date = GETDATE()
        WHERE ID = @P_BADGE_ID;

        SELECT 'Record updated.' AS Message;
    END
END;



