   ,@rangeto bigint
   ,@range_json varchar(max)
   ,@IsActive bit  
   ,@UserID bigint    
)  
as  
Begin  
      declare @ParentID bigint = 0  
	  select top 1 @ParentID = ISNULL(ParentID,User_ID) from User_Detail(nolock) where User_ID = @UserID       
      declare @InsertedCriteriaID bigint = 0  
  
  IF(@rule_id = 0)  
    BEGIN  

	IF (@RULENAME = '') 
	BEGIN
		SELECT 'Rule Name is blank.'
		RETURN;
	END

	IF (@ActivityId = 0) 
	BEGIN
		SELECT 'Activity Name is blank.'
		RETURN;
	END


	if(@PointsType like '%Specific%'  and @Points = 0)
	begin
		SELECT 'Fill points.'
		return;
	end

	if (exists(select 1 from tbl_SM_ScoringRule(nolock) where Activity_id = @ActivityId  and parentid =  @ParentID   and    id <>  @rule_id AND @rule_id = 0  AND ApplicableTo = @ApplyTo  ))
	begin
		select 'Activity already exist.';
		return;
	end

 
	--- select 1 from tbl_SM_ScoringRule(nolock) where Activity_id = 3  and parentid =  34594   and    id <>   47 AND   47 >0 AND ApplicableTo = 'role' 

     if(not exists(select 1 from tbl_SM_ScoringRule(nolock) where (Rule_name = @RuleName or ID = @rule_id) and parentid =  @ParentID ))   
        BEGIN  
			 insert into tbl_SM_ScoringRule  
			(  
				Rule_name,
				Activity_ID,
				ApplicableTo,
				Role_name,
				Points_type,
				eventid,
				Points,
				Percentage,
				range_from,
				range_to,
				range_json,
				Created_by,
				IsActive,
				Created_date,
				ParentId
			)  
			values(  
				@RuleName ,
				@ActivityId ,
				@ApplyTo,
				@RoleName,
				@PointsType,
				@eventid,
				@Points,
				COALESCE( @percentage,0),
				COALESCE( @rangefrom,0),
				COALESCE( @rangeto,0),
				coalesce( @range_json,''),
				@UserID,
				@IsActive,
				GETDATE(),
				@ParentID
				)  
              set @InsertedCriteriaID = SCOPE_IDENTITY();  
			  select 'Record Saved'     
        END  
	 ELSE  
     BEGIN  
         SELECT 'Rule Name Already Exists.'  
     END  

   END  
  ELSE IF(@rule_id > 0)  
     BEGIN  


	if (exists(select 1 from tbl_SM_ScoringRule(nolock) where Activity_id = @ActivityId  and parentid =  @ParentID   and    id <>  @rule_id AND @rule_id > 0  AND ApplicableTo = @ApplyTo  ))
	begin
		select 'You can add new rule for same activity with different appplicabilty. e.g. User or Rolewise. ';
		return;
	end

	if (exists(select 1 from tbl_SM_ScoringRule(nolock) where Activity_id = @ActivityId  and parentid =  @ParentID   and    id <>  @rule_id AND @rule_id > 0  AND Rule_name = @RuleName  ))
	begin
		select 'Please change the rule name. This rule name  already exist.';
		return;
	end

   IF( exists(select 1 from tbl_SM_ScoringRule(nolock) where  ID = @rule_id))  
       BEGIN  
         update tbl_SM_ScoringRule  
			set Rule_name =@RuleName,  
			Activity_ID = @ActivityId,  
			ApplicableTo = @ApplyTo,  
			Role_name= @RoleName,
			Points_type =@PointsType,
			eventid = @eventid,
			Points =@Points,
			[Percentage] = COALESCE( @percentage,0),
			range_from = COALESCE( @rangefrom,0),
			range_to =	COALESCE( @rangeto,0),
			range_json = COALESCE(@range_json,''),
			IsActive = @IsActive,  
			modify_date = getdate(),  
			modified_by = @UserID  ,
			ParentId = @ParentID
			where ID = @rule_id  
       
            select 'Record Saved'   
              
		End   
      ELSE   
      BEGIN  
			SELECT 'Scoring Rule Name Already Exists'   
	  END      
  
  End     
  
  
End  


GO

/* ============================================================
   Procedure: [dbo].[usp_SM_ScoringCondition]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
select * from tbl_SM_ScoringCondition

exec usp_SM_ScoringCondition   1,1,'[]',''

exec usp_SM_ScoringCondition   2,1,'[{"Field":"Probability","Operator":"<>","OperatoreText":"not equal to","P_Value":"LOW"} ]' , 'and'


*/

CREATE   PROC usp_SM_ScoringCondition
(
@Rule_id int,
@Active_status bit,
@cond_json nvarchar(max),
@Conjunction varchar(10)
)
AS
BEGIN
	
	Create table #temp_data
	(
		ID int ,
		Field varchar(100),
		Operator varchar(100),
		OperatoreText varchar(300),
		Cond_Value  varchar(100)
	)
	
	IF (@cond_json <> '[]')BEGIN
		DECLARE @ROWDATA  NVARCHAR(MAX)='', @FIELDNAMES NVARCHAR(MAX)='', @SQLString NVARCHAR(MAX), @ROW_VALUES NVARCHAR(MAX) = '' ;
	
		SELECT  @ROWDATA= VALUE FROM OPENJSON(@COND_JSON)  
		PRINT @ROWDATA

		SELECT @FIELDNAMES=@FIELDNAMES+'['+[KEY]+'] NVARCHAR(2000),' FROM OPENJSON(@ROWDATA)                
		PRINT '@FIELDNAMES1: ' + @FIELDNAMES  

		SET @FIELDNAMES =SUBSTRING( @FIELDNAMES,1 ,LEN( @FIELDNAMES)  -1 )

		 CREATE TABLE #TEMP_IMPORT_COND_DATA
		 (
			ID int identity(1,1)
		 )

		 SET @SQLString  = ' ALTER TABLE #TEMP_IMPORT_COND_DATA  ADD '+@FIELDNAMES+' '

		 PRINT @SQLSTRING
		 EXEC(@SQLSTRING)

		SET @SQLString  =' 	INSERT INTO #TEMP_IMPORT_COND_DATA
				SELECT *  FROM OPENJSON('''+@cond_json +''') WITH ('+@FIELDNAMES+')'

		PRINT @SQLString
		EXECUTE SP_EXECUTESQL @SQLString 



		INSERT INTO #temp_data
		SELECT * FROM #TEMP_IMPORT_COND_DATA

		DELETE FROM tbl_SM_ScoringCondition WHERE Rule_id  = @Rule_id 
		
		if exists(select 1 from #temp_data)begin
			INSERT INTO tbl_SM_ScoringCondition( Seq_no, Rule_id, Field, Operatore,OperatoreText, f_value, Conjunction, Active_status)
			SELECT  ID , @Rule_id, Field , Operator , OperatoreText, Cond_Value , @Conjunction ,@Active_status FROM #temp_data
			---UPDATE TBL_SM_SCORINGRULE SET RULE_DESC = @COND_JSON WHERE ID = @RULE_ID;
			SELECT 'Record saved.';
		end
	END	 
	else begin
		DELETE FROM tbl_SM_ScoringCondition WHERE Rule_id  = @Rule_id 
		SELECT 'Conditions removed.';
	end
	

END


GO

/* ============================================================
   Procedure: [dbo].[usp_sm_SendEmail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_sm_SendEmail 1, 'Test Email Subject', 'Test Email body', 'Mayank.nigam@pelsoftlabs.in'  
-- Exec usp_sm_SendEmail 2724, 'Test Email Subject', 'Test Email body', 'Mayank.nigam@pelsoftlabs.in'  
CREATE  PROCEDURE [dbo].[usp_sm_SendEmail]  
(      
 @SerUserId bigint,  
 @Subject varchar(max),  
 @Body varchar(max),  
 @To varchar(max)  
)      
as      
Begin      
  
-- declare @SerUserId bigint=2724,@Subject varchar(max)='Test Email Subject',@Body varchar(max)='Test Email body',@To varchar(max)='Mayank.nigam@pelsoftlabs.in'  
  
 Declare @AdminEmailID nvarchar(max) = '', @FromMailID nvarchar(max) = ''      
 declare @link_Account as bigint, @balance as bigint=0, @ParentId bigint      
 Declare @email_cnt as int =0      
 Declare @BatchID bigint      
      
 drop table if exists #tmp_lst_EmailId  
      
 If LEN(@Subject) > 0      
 Begin      
  If LEN(@Body) > 0      
  Begin      
   Select @ParentId=ParentId From Serv_User_Detail(nolock) Where ser_user_id=@SerUserId      
      
   select ROW_NUMBER() over( order by item) rno,*       
   into #tmp_lst_EmailId      
   from dbo.SplitString(@To, ',')      
      
   select @email_cnt = COUNT(*) from #tmp_lst_EmailId      
         
   select @FromMailID=virtual_mail,@link_Account=link_Account from dbo.serv_user_domain(nolock) where ParentID = @ParentId      
    
   if exists(select 1 from supportreplymail(nolock) where parentid=@parentid and virtualmail=@FromMailID and isactive=1)    
   begin    
   select top 1 @FromMailID=usermail from supportreplymail(nolock) where parentid=@parentid and virtualmail=@FromMailID and isactive=1 order by id desc    
   end    
    
   SELECT TOP 1 @balance=isnull(balance,0) FROM MailCreditDetails(nolock) WHERE USER_ID = @link_Account ORDER BY credit_id DESC    
  
   print '@link_Account: ' + cast(@link_Account as varchar)  
   print '@balance: ' + cast(@balance as varchar)                                                              
   print '(@balance-@email_cnt): ' + cast((@balance-@email_cnt) as varchar)                                                              
      
   --begin tran      
   insert into GetBatchRecord (User_id,RandNum)      
   select @ParentId, round(rand()*100000,0)      
      
   select @BatchID = SCOPE_IDENTITY()      
      
   delete from GetBatchRecord where BatchID=@BatchID      
   --commit      
      
   if (@balance-@email_cnt) > 0      
   begin      
      
    insert into CloneEmailsFilter(      
    Mail_FromEmail, Mail_ToEmail, Mail_Subject, Mail_TempleteName, Messages, Mail_InsertedDate, Mail_UserID, Mail_ParentID,      
    ReplyTo, Mail_BatchID, Mail_Priority, Mail_ScheduleDate, Mail_ScheduledTime, Mail_Attechement, Mail_TempleteBody,      
    IsMonitor,TemplateID,Count,Source      
    )      
    select @FromMailID, item, left(@Subject,180), '', @Body, GETDATE(), @link_Account, @ParentId,      
    @FromMailID, @BatchID, 1, '', '', '', @Body,      
    1, 0, @email_cnt, 'Ticket Management'       
    from #tmp_lst_EmailId      
      
    print 'Msg: Email Queued Successfully, BatchID: ' +  cast(@BatchID as varchar) + ', MailId: ' + cast(SCOPE_IDENTITY() as varchar)      
   end      
   --else      
   --begin      
      
   -- set @Subject = 'Insufficient Balance'      
      
   -- set @Body = 'Due to insufficient balance, You are unable to generate ticket related updates on email. Please Recharge!!!'      
      
   -- select @AdminEmailID=virtual_mail from dbo.serv_user_domain(nolock) where ParentID = 335      
      
   -- insert into CloneEmailsFilter(      
   -- Mail_FromEmail, Mail_ToEmail, Mail_Subject, Mail_TempleteName, Messages, Mail_InsertedDate, Mail_UserID, Mail_ParentID,      
   -- ReplyTo, Mail_BatchID, Mail_Priority, Mail_ScheduleDate, Mail_ScheduledTime, Mail_Attechement, Mail_TempleteBody,      
   -- IsMonitor, TemplateID, Count, Source      
   -- )      
   -- select @AdminEmailID, @FromMailID, @Subject, '', @Body, GETDATE(), 335, 335,      
   -- @AdminEmailID, @BatchID, 1, '', '', '', @Body,      
   -- 1, 0, 1, 'Ticket Management'      
         -- print 'Msg: Insufficient Email Balance '      
   --end      
  End      
  Else      
  Begin      
   print 'Msg: Invalid Email Body '      
  End      
 End      
 Else      
 Begin      
  print 'Msg: Invalid Email Subject '      
 End      
      
End   



GO

/* ============================================================
   Procedure: [dbo].[USP_SM_TopAchieversSummary]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*  
  
Achievement summary table   
  
EXEC  USP_SM_TopAchieversSummary  34594, '2024/07/01' , '2024/12/31' 

exec USP_SM_AchievmentSummary @P_searchtext=N'',@P_userId=34594,@P_isactive=1,@P_from_date='2024-07-21 00:00:00',@P_to_date='2024-07-27 00:00:00',@P_option=5,@P_Filter_json=N''  
  
tbl_SM_Employee_Points_History  where userid  =  34594      order by 1 desc   
tbl_SM_Employee_Points_History     order by 1 desc   
  
user_detail  where user_id =32222  
  
tbl_sm_scoringraw order by 1 desc  
  
--UPDATE tbl_sm_scoringraw SET PROCESSSTARTTIME = NULL , PROCESSENDTIME = NULL  , ISPROCEESED = 0 WHERE USERID  =  34594  
  
*/  
  
CREATE   PROC USP_SM_TopAchieversSummary
(   
 @P_userId bigint,  
 @P_from_date datetime ,  
 @P_to_date datetime ,  
 @P_option int =1
)  
as  
begin  

 --tbl_SM_Employee_Incentive_History  
 --tbl_SM_Employee_Points_History order by 1 desc  
 --tbl_SM_Employee_MileStone_History  
  
  DECLARE @PARENTID BIGINT = 0    
 SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_userId      
  
 DECLARE @UserDetails  tbl_type_sm_UserDetails;  
  
 INSERT INTO @UserDetails  
 EXEC Use_GetUserDetails @PARENTID;  
  
  
 set @P_from_date  = CONCAT( convert( varchar , @P_from_date, 23) , ' 00:00:00' );  
 set @P_to_date  = CONCAT( convert( varchar, @P_to_date, 23) , ' 23:59:59' );  
  

   IF OBJECT_ID('tempdb..#tempTargetProcUsers') IS NOT NULL   
  BEGIN   
   DROP TABLE #tempTargetProcUsers;  
  END;  
  
  IF OBJECT_ID('tempdb..#TEMP_FINAL_DATA') IS NOT NULL   
  BEGIN   
   DROP TABLE #TEMP_FINAL_DATA;  
  END;  
  
    
  Create table #tempTargetProcUsers  
  (  
   id int identity (1,1),  
   SalesTargetId bigint,  
   UserId bigint,  
   targetPoint decimal(16,2),  
   ISactive bit,  
   Target_date datetime null,  
   UserName varchar(200) null ,  
   TargetName varchaR(100) null,  
   target_period varchar(100) null,  
   targeteType varchar(500) null,  
   targetFor varchar(50) null,  
   target_assigned decimal(16,2) null,  
   target_achieved decimal(16,2) null  
  );  
  
  insert into #tempTargetProcUsers  
  exec usp_sm_GetuserTargetStatus @P_from_date , @P_to_date ,0  
  
   
 --if (@P_option = 0)  
 --begin  
  
  
 -- SELECT * INTO #TEMP_FINAL_DATA  FROM(  
 -- SELECT userid as ID , User_Login AS UserName , sum( incentive) as Incentive ,sum( target_achieved ) as Target_acheived , sum( milestone_achieved ) as Milestone_achieved ,  
 -- sum( Points_earned) as Points_Achieved  FROM   
 -- (SELECT USERID, U.User_Login , sum(Incentive_Amount) as incentive ,0 as target_achieved ,0 as milestone_achieved, 0 as Points_earned   FROM tbl_SM_Employee_Incentive_History(NOLOCK) IH   
 -- INNER JOIN User_Detail(NOLOCK) U ON U.User_ID = IH.UserId   where ih.TranDate between @P_from_date and @P_to_date   
 -- group by IH.UserId ,U.User_Login  
 -- UNION   
 -- SELECT USERID, U.User_Login , 0 as incentive ,0 as target_achieved , COUNT(MilestoneID) as milestone_achieved, 0 as Points_earned     
 -- FROM tbl_SM_Employee_MileStone_History(NOLOCK) MH INNER JOIN User_Detail(NOLOCK) U ON U.User_ID = MH.UserId   where MH.TranDate between @P_from_date and @P_to_date   
 -- group by MH.UserId ,U.User_Login  
 -- UNION  
 -- SELECT ph.UserId , U.User_Login , 0 as incentive ,0  as target_achieved  , 0 as milestone_achieved, SUM(ph.points)  as Points_earned     
 --       FROM tbl_SM_Employee_Points_History ph     INNER JOIN User_Detail(NOLOCK) U ON U.User_ID = ph.UserId   
 --       WHERE ph.TranDate BETWEEN  CONCAT(CONVERT(VARCHAR,  @P_from_date, 23), ' 00:00:00') AND CONCAT(CONVERT(VARCHAR, @P_to_date , 23), ' 23:59:59')     
 --       GROUP BY ph.UserId ,U.User_Login  
 -- --union  
 -- --SELECT tu.UserId , U.User_Login , 0 as incentive ,0  as target_achieved  , 0 as milestone_achieved, coalesce( sum(tu.target_achieved),0) as Points_earned   
 -- --FROM #tempTargetProcUsers tu inner join User_Detail U  on  U.User_ID = TU.UserId  
 -- --where tu.UserId in (select UserId from @UserDetails )  
 -- --group by tu.UserId ,tu.SalesTargetId ,  U.User_Login, tu.target_achieved  
 -- UNION  
 -- SELECT tu.UserId , U.User_Login , 0 as incentive , (case when (SUM (COALESCE (target_achieved,0)) / tu.targetPoint) >= 1 then 1 else 0 end) as target_achieved  , 0 as milestone_achieved,  0 as Points_earned 
 -- FROM #tempTargetProcUsers tu inner join User_Detail U  on  U.User_ID = TU.UserId  
 -- where tu.UserId in (select UserId from @UserDetails )  
 -- group by tu.UserId ,tu.SalesTargetId ,  U.User_Login,tu.targetPoint  
 -- ) AS TBLMAIN  where  User_Login <> ''  group by  userid , User_Login) AS TABLE_MAIN  
    
   
 --   SELECT top 3 * FROM #TEMP_FINAL_DATA  where ID IN  (select UserId from @UserDetails );

 --END  
  
 /*=======================================Incentive details===========================================*/  
  
 
    
  IF OBJECT_ID('tempdb..#TEMP_FINAL_INCENTIVE') IS NOT NULL   
  BEGIN   
   DROP TABLE #TEMP_FINAL_INCENTIVE;  
  END;  
  
	--select IH.Tran_ID ,  FORMAT(TranDate, 'dd-MMM-yyyy HH:mm:ss')   as incentive_date , U.User_ID ,  U.User_Login as userName , TI.Incentive_name as Incentivename  , ( CASE WHEN IH.IncentiveType = 'CASH' THEN Incentive_Amount END)   as cash ,  
	--( CASE WHEN IH.IncentiveType = 'Kind' THEN Incentive_Amount END)  as kind , (case when coalesce( IH.IsPaid,0 ) = 1 then 'Paid' else 'Unpaid' end) as Pay_Status, Ih.ispaid   INTO #TEMP_FINAL_INCENTIVE from tbl_SM_Employee_Incentive_History IH   
	--left join User_Detail U ON IH.UserId =  U.User_ID  LEFT JOIN tbl_SM_Employee_Incentive  TI  ON TI.ID = IH.IncentiveId  
	--WHERE IH.TRANDATE BETWEEN  @P_from_date and @P_to_date   
  
	  SELECT USERID, U.User_Login , (CASE WHEN COALESCE(U.IMAGE,'') = '' then 'https://docs.kit19.com/default/person.png' 
		ELSE concat('https://docs.kit19.com/',U.Image) end) AS Profilepicturepath , sum(Incentive_Amount) as incentive  into #TEMP_FINAL_INCENTIVE
	  FROM tbl_SM_Employee_Incentive_History(NOLOCK) IH   
	  INNER JOIN User_Detail(NOLOCK) U ON U.User_ID = IH.UserId   where ih.TranDate between @P_from_date and @P_to_date   
	  group by IH.UserId ,U.User_Login ,U.Image 


	  SELECT top 3  UserId , User_Login , Profilepicturepath ,  sum(incentive) as Incentive FROM #TEMP_FINAL_INCENTIVE 
	  where USERID IN  (select UserId from @UserDetails )   group by  userid , User_Login, profilepicturepath   order by Incentive desc;  
  
  

   
 /*=======================================Milestone achieved ===========================================*/  
  
  
  if OBJECT_ID('tempdb..#TEMP_FINAL_MILESTONES') is not null begin drop table #TEMP_FINAL_MILESTONES  end;  
  
	  --SELECT  FORMAT(MH.TranDate, 'dd-MMM-yyyy HH:mm:ss') as Milstonedate , MH.UserId , u.User_Login as UserName , MS.Milestone_Name as Milestonename ,   
	  --   (MH.AchievedTargetAmount * 100 / MH.Sale_target_Amount)  as achieved_percent,   
	  --MS.Event_name as TargetName INTO #TEMP_FINAL_MILESTONES  
	  --FROM tbl_SM_Employee_MileStone_History(NOLOCK) MH  
	  --INNER JOIN User_Detail U ON U.User_ID = MH.UserId    
	  --left join tbl_SM_MileStones(NOLOCK) MS on MH.MilestoneID = MS.Id  
	  --WHERE   MH.TRANDATE BETWEEN   @P_from_date and @P_to_date   

	  SELECT  MH.UserId ,U.User_Login , (CASE WHEN COALESCE(U.IMAGE,'') = '' then 'https://docs.kit19.com/default/person.png' 
		ELSE concat('https://docs.kit19.com/',U.Image) end) AS Profilepicturepath , COUNT(MilestoneID) as milestone_achieved  
	   into  #TEMP_FINAL_MILESTONES 
	  FROM tbl_SM_Employee_MileStone_History(NOLOCK) MH INNER JOIN User_Detail(NOLOCK) U ON U.User_ID = MH.UserId   where MH.TranDate between @P_from_date and @P_to_date   
	  group by MH.UserId ,U.User_Login  ,U.Image 


	  SELECT  TOP 3  UserId, User_Login , Profilepicturepath , sum( milestone_achieved) as milestone_achieved   FROM #TEMP_FINAL_MILESTONES   WHERE  UserId IN  (select UserId from @UserDetails ) 
	  group by UserId, User_Login , profilepicturepath 
	  order by User_Login, milestone_achieved desc
  
   /*=======================================Target achieved ===========================================*/  
  
  
  
  if OBJECT_ID('tempdb..#tempTargetAchieved') is not null begin drop table #tempTargetAchieved end;  
  
  Create table #tempTargetAchieved  
  (  
   id int identity (1,1),  
   SalesTargetId bigint,  
   UserId bigint,  
   targetPoint decimal(16,2),  
   ISactive bit,  
   Target_date datetime null,  
   UserName varchar(200) null ,  
   TargetName varchaR(100) null,  
   target_period varchar(100) null,  
   targetType varchar(500) null,  
   targetFor varchar(50) null,  
   target_assigned decimal(16,2) null,  
   target_achieved decimal(16,2) null  
  )  
  
  INSERT INTO #tempTargetAchieved  
  exec usp_sm_GetuserTargetStatus @P_from_date , @P_to_date ,0 ;  
  
  if OBJECT_ID('tempdb..#TEMP_FINAL_TARGETS') is not null begin drop table #TEMP_FINAL_TARGETS end;  
  
  --select FORMAT(Target_date, 'dd-MMM-yyyy')  as Target_date , UserId , U.User_Login AS UserName , Targetname , target_period , targetType , targetFor , targetPoint as target_assigned , target_achieved      
  -- INTO #TEMP_FINAL_TARGETS from #tempTargetAchieved   
  -- INNER JOIN User_Detail U ON U.User_ID = #tempTargetAchieved.UserId  
  -- where targetType = 'Points' 
  

	SELECT tu.UserId , U.User_Login , (CASE WHEN COALESCE(U.IMAGE,'') = '' then 'https://docs.kit19.com/default/person.png' 
		ELSE concat('https://docs.kit19.com/',U.Image) end) AS Profilepicturepath   , (case when (SUM (COALESCE (target_achieved,0)) / tu.targetPoint) >= 1 then 1 else 0 end) as target_achieved   
	into #TEMP_FINAL_TARGETS
	FROM #tempTargetProcUsers tu inner join User_Detail U  on  U.User_ID = TU.UserId  
	where tu.UserId in (select UserId from @UserDetails )  
	group by tu.UserId ,tu.SalesTargetId ,  U.User_Login,tu.targetPoint, U.Image 
  
	SELECT  distinct   TOP 3   UserId, User_Login , Profilepicturepath  , sum(target_achieved) as target_achieved FROM #TEMP_FINAL_TARGETS  WHERE  UserId IN  (select UserId from @UserDetails )
	group by  userid , User_Login , profilepicturepath   order by target_achieved desc;
	
 /*=======================================Points earned ===========================================*/  
  

  
  if OBJECT_ID('tempdb..#TEMP_FINAL_POINTS') is not null begin drop table #TEMP_FINAL_POINTS  end;  
  
  --SELECT FORMAT(PH.TranDate, 'dd-MMM-yyyy HH:mm:ss') as Pointsdate , PH.UserId , u.User_Login as UserName , PH.points as Points ,   
  --   AM.EventName as Activity,  
  --[dbo].[ufunc_sm_getUserTranpoints](PH.TranDate, PH.UserId) as Balance   
  -- INTO #TEMP_FINAL_POINTS  
  --FROM tbl_SM_Employee_Points_History(NOLOCK) PH  
  --INNER JOIN User_Detail U ON U.User_ID = PH.UserId    
  --left join Activitymaster  (NOLOCK) AM on AM.ID = PH.Activity_id  
  --WHERE   PH.TRANDATE BETWEEN   @P_from_date and @P_to_date   
  --order by convert(datetime, PH.TranDate) desc   


    SELECT ph.UserId , U.User_Login, (CASE WHEN COALESCE(U.IMAGE,'') = '' then 'https://docs.kit19.com/default/person.png' 
		ELSE concat('https://docs.kit19.com/',U.Image) end) AS Profilepicturepath  , SUM(ph.points)  as Points_earned 
	INTO #TEMP_FINAL_POINTS 
    FROM tbl_SM_Employee_Points_History ph  INNER JOIN User_Detail(NOLOCK) U ON U.User_ID = ph.UserId   
    WHERE ph.TranDate BETWEEN  CONCAT(CONVERT(VARCHAR,  @P_from_date, 23), ' 00:00:00') AND CONCAT(CONVERT(VARCHAR, @P_to_date , 23), ' 23:59:59')     
    GROUP BY ph.UserId ,U.User_Login, U.Image 
 
	SELECT  TOP 3  UserId , User_Login , Profilepicturepath , sum(Points_earned) as Points_earned FROM #TEMP_FINAL_POINTS WHERE  UserId IN  (select UserId from @UserDetails )
	GROUP BY UserId , User_Login  , profilepicturepath  
	ORDER BY Points_earned desc
  
 
end


