/* ============================================================
   Procedure: [dbo].[usp_SMS_EmailReportToday]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_SMS_EmailReportToday]  
as      
begin      
 drop table if exists #temp1  
 drop table if exists #temp2      
 drop table if exists #temp3  
  
         
   select  mail_batchid,  mail_delivereddate, Mail_ToEmail,Status into #temp3 from   
     (  
        select BatchID as mail_batchid, SentDateTime as mail_delivereddate, Email_Id as Mail_ToEmail,Status from ClientEmails with (nolock)  
       where month(SentDateTime)=month(getdate()) and year(SentDateTime)=year(getdate())   
         and [Status] = 'Delivered'      
          union     
           select BatchID as mail_batchid, SentDateTime as mail_delivereddate, Email_Id as Mail_ToEmail,Status  from ThirtyDaysClientEmails with (nolock)   
     where  month(SentDateTime)=month(getdate()) and year(SentDateTime)=year(getdate())   
         and [Status] = 'Delivered'      
     ) as tbl   
  
   
select 'Mail'as Service,* into #temp1    
 from  
 (  
 select smtpserver,sum(case when cast(mail_delivereddate as date)=cast(getdate() as date) then 1 else 0 end) as EmailsSentToday,  
 sum(case when cast(mail_delivereddate as date)=cast(getdate() as date) and id is not null then 1 else 0 end) as DeliveryReportToday,  
 sum(case when month(mail_delivereddate)=month(getdate()) and year(mail_delivereddate)=year(getdate()) then 1 else 0 end)   
 as EmailsSentThisMonth,  
 sum(case when month(mail_delivereddate)=month(getdate()) and year(mail_delivereddate)=year(getdate()) and id is not null  then 1 else 0 end)   
 DeliveryReportThismonth  
 --(select count(1) from emaildeliverystatus(nolock) where cast(accept_time as date)=cast(getdate() as date)) as KarixDeliveryReport ,  
 --(select count(1) from maildeliveries(nolock) where cast(maildate as date)=cast(getdate() as date) and batchid is not null)  
 --+ (select count(1) from mailbounces(nolock) where cast(maildate as date)=cast(getdate() as date)  and batchid is not null) as awsdeliveryReport,  
 --into #tempConvparentId    
 from  
 (select 'Karix' smtpserver,mail_delivereddate,e.event_status,e.id from #temp3(nolock) c left join emaildeliverystatus(nolock) e  
 on c.mail_batchid=e.batchid and c.Mail_ToEmail=e.message_tag3   
 where  
      --c.Mail_Delivered = 1   
   c.Status = 'Delivered'    
  -- and smtpserver='Karix' 
   and month(mail_delivereddate)=month(getdate()) and year(mail_delivereddate)=year(getdate()))  
    a 
	group by smtpserver  
 union  
 select 'Karix' smtpserver,sum(case when cast(mail_delivereddate as date)=cast(getdate() as date) then 1 else 0 end) as EmailsSentToday,  
 sum(case when cast(mail_delivereddate as date)=cast(getdate() as date) and (m_id is not null or d_id is not null) then 1 else 0 end) as DeliveryReportToday,  
 sum(case when month(mail_delivereddate)=month(getdate()) and year(mail_delivereddate)=year(getdate()) then 1 else 0 end)   
 as EmailsSentThisMonth,  
 sum(case when month(mail_delivereddate)=month(getdate()) and year(mail_delivereddate)=year(getdate())  and (m_id is not null or d_id is not null)  then 1 else 0 end)   
 DeliveryReportThismonth  
 --(select count(1) from emaildeliverystatus(nolock) where cast(accept_time as date)=cast(getdate() as date)) as KarixDeliveryReport ,  
 --(select count(1) from maildeliveries(nolock) where cast(maildate as date)=cast(getdate() as date) and batchid is not null)  
 --+ (select count(1) from mailbounces(nolock) where cast(maildate as date)=cast(getdate() as date)  and batchid is not null) as awsdeliveryReport,  
 --into #tempConvparentId    
 from  
 (select 'aws' smtpserver,mail_delivereddate,e.id as D_id,m.id as m_id from #temp3(nolock) c left join maildeliveries(nolock) e  
 on c.mail_batchid=e.batchid and c.Mail_ToEmail=e.ToMail left join mailbounces(nolock) m  on c.mail_batchid=m.batchid and c.Mail_ToEmail=m.ToMail  
 where  
 --c.Mail_Delivered = 1  
   c.Status = 'Delivered'    
   --and smtpserver='aws' 
   and month(mail_delivereddate)=month(getdate()) and year(mail_delivereddate)=year(getdate()))  
    a group by smtpserver  
 ) a  
   
   
   
 select 'SMS' as Service,MessagesentToday,MessageDeliveryReportToday,messagesentThisMonth,MessageDeliveryReportThisMonth   
 into #temp2  
 from  
 (  
 select * from (select count(1) as MessageDeliveryReportToday from messagedeliverystatus(nolock) where isnull(messagestatus,'')  
 not in ('','6')) a  
 right join  
 (  
   --select count(1) as MessagesentToday from mysmstrans.dbo.Messagedeliverystatustemp(nolock)  
   select count(1) as MessagesentToday from mysms.dbo.Messagedeliverystatustemp(nolock)   
 ) b  
 on 1=1) a  
 join  
 (  
 select * from  
 (select count(1) as MessageDeliveryReportThisMonth  from thirtydayshistory(nolock) where isnull(messagestatus,'')  
 not in ('','6') ) c  
 right join  
 (select count(1) as messagesentThisMonth from MySMSReport.dbo.msgtemphistory1(nolock) where   
 month(messageinsertdate)=month(getdate()) and year(messageinsertdate)=year(getdate())  
 ) d on 1=1) b on 1=1   
  
  
   
DECLARE @xml NVARCHAR(MAX),@xml1 NVARCHAR(MAX) DECLARE @body NVARCHAR(MAX),@body1 NVARCHAR(MAX)                        
    
SET @xml =CAST(( SELECT Service AS 'td','',smtpserver      
   AS 'td','',EmailsSentToday AS 'td','',DeliveryReportToday  AS 'td','',EmailsSentThisMonth as 'td','',DeliveryReportThismonth as 'td'  
   ,''       
 from #temp1 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))                
 SET @xml1 =CAST(( SELECT Service AS 'td','',MessagesentToday AS 'td','',MessageDeliveryReportToday AS 'td','',                 
MessagesentThisMonth  AS 'td','',MessageDeliveryReportThisMonth as 'td',''  
 from #temp2 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))                
        
SET @body ='<html><H1>Mail Sent as on date: '+cast (cast(getdate() as date) as nvarchar)        
+'</H1><body><table border = 2><tr>        
<th>Service</th><th>Server</th><th>Sent Today</th><th>Delivery Report Today</th>        
<th>Sent This Month</th><th>Delivery Report This Month</th>      
</tr>'                 
SET @body = @body + @xml +'</table></body></html>'        
        
SET @body1 ='<html><H1>SMS Sent as on date: '+cast (cast(getdate() as date) as nvarchar)        
+'</H1><body><table border = 2><tr>        
<th>Service</th><th>Sent Today</th><th>Delivery Report Today</th>        
<th>Sent This Month</th><th>Delivery Report This Month</th>  
</tr>'                 
SET @body1 = @body1 + @xml1 +'</table></body></html>'                
        
set @body= @body+@body1        
        
--select @body        
EXEC usp_enqueueemail                
@profile_name='Alerts',                 
@recipients='csshukla@pelsoftlabs.in',                
@blind_copy_recipients='karuna@pelsoftlabs.in',                
@subject='Mail and SMS Sent',                
@body = @body,                
@body_format ='HTML',      
@from_address='Mail and SMS sent <noreply@kit19.com>';      
  
drop table if exists #temp1                
drop table if exists #temp2                
drop table if exists #temp3    
    
end   
  



GO

