CREATE   PROC USP_SMS_GetSenderName    
@prefixText Varchar(30)    
AS    
BEGIN    
  Select ltrim(Sender_Name) As Sender_Name  From SenderID_Detail   
  Where Sender_Name LIKE @prefixText +'%' And Status = 1     
  Group by Sender_Name    
END


