/* ============================================================
   Procedure: [dbo].[usp_SMS_LinkTrackReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.usp_SMS_LinkTrackReport --335,'2019-02-16','2019-02-18','','',''    
	(
	@user_id BIGINT
	,@fmdate VARCHAR(10)
	,@toDate VARCHAR(10)
	,@domain VARCHAR(100)
	,@mobile VARCHAR(20)
	,@longurl VARCHAR(200)
	)
AS
BEGIN
	DECLARE @fltr AS VARCHAR(max) = ''

	IF @fmdate != ''
		AND @toDate != ''
		SET @fltr = ' and convert(date,VisitDate)             
  between ''' + @fmdate + ''' and ''' + @toDate + ''''

	IF @mobile != ''
	BEGIN
		IF @fltr != ''
			SET @fltr = @fltr + ' and lk.Mobile like ''%' + @mobile + '%'''
		ELSE
			SET @fltr = ' and lk.Mobile like ''%' + @mobile + '%'''
	END

	IF @domain != ''
	BEGIN
		IF @fltr != ''
			SET @fltr = @fltr + ' and lk.shorturl like ''%' + @domain + '%'''
		ELSE
			SET @fltr = ' and lk.shorturl like ''%' + @domain + '%'''
	END

	IF @longurl != ''
	BEGIN
		IF @fltr != ''
			SET @fltr = @fltr + ' and lk.longurl like ''%' + @longurl + '%'''
		ELSE
			SET @fltr = ' and lk.longurl like ''%' + @longurl + '%'''
	END

	DECLARE @sqltot VARCHAR(max)
	DECLARE @sqlstr VARCHAR(max)

	SET @sqlstr = 'select trackid, tk.VisitDate, tk.Mobile, lk.Parentid,            
 tk.link_id, tk.Long_Url, tk.ipAddress, isnull(ll.location,'''') location,          
  isnull(source_from,'''') source_from, isnull(zipcode,'''') zipcode,            
  lk.batchid,lk.shorturl,isnull(ul.PersonName,'''') lname,isnull(ul.PersonName,''nolead'') leadok    
  from dbo.Link_smsTrack tk inner join dbo.Link_smsMobile  lk     
  on lk.mobile_url_id =link_id            
  left outer join dbo.SMS_Link_Location ll    
  (nolock)   on ll.IPAddress = tk.IPAddress     
  left outer join UserLeads ul   (nolock)      
  on tk.Mobile in (ul.MobileNo1,ul.MobileNo,ul.MobileNo2) and ul.parentid=lk.Parentid             
  where            
    lk.Parentid=' + cast(@user_id AS VARCHAR) + ' and ll.ipId=(select max(ipId) from SMS_Link_Location where ipaddress=ll.ipaddress) ' + @fltr
	SET @sqltot = 'select Count(*) from Link_smsTrack  tk inner join dbo.Link_smsMobile  lk            
  on lk.mobile_url_id =link_id            
  left outer join dbo.SMS_Link_Location ll          
  on ll.IPAddress = tk.IPAddress   where lk.Parentid=' + cast(@user_id AS VARCHAR) + @fltr

	EXEC (@sqlstr)

	EXEC (@sqltot)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @user_id
		,@Activity_type = 'View_SmsTrk_Rpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'Link_smsTrack'
END



GO

