   Procedure: [dbo].[usp_SMSConsumption]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE   PROCEDURE [dbo].[usp_SMSConsumption] --'01/03/2017','28/03/2017','Days',7
@FromDate varchar(20)=null,
@Todate varchar(20)=null,
@Range nvarchar(50)=null,
@RangeValue int=7
	-- Add the parameters for the stored procedure here
AS
BEGIN
create table #UsersConsumption(FromTo nvarchar(100),UsersCount int,SMSConsumption bigint,Type nvarchar(20))
--create table #UsersConsumptionAll(Fromto varchar(100),UsersCount bigint,SMSConsumption bigint,Type nvarchar(20),Rangevalue nvarchar(50))
declare @RangeValue1 int
	set @RangeValue1=coalesce(@rangevalue,7)
	StartBuildingTable:
	set @FromDate=coalesce(@FromDate,convert(varchar,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0),103))
	set @ToDate=coalesce(@ToDate,convert(varchar,GETDATE(),103))
	set @Range=coalesce(@range,'Days')
	set @RangeValue=coalesce(@rangevalue,7)

If @Fromdate ='' and @Todate=''
set @Fromdate='01/01/2000'
set @Todate=convert(varchar,getdate(),103)
declare @datecreated1 varchar(20)
set @datecreated1=@FromDate
	
while CONVERT(varchar, CONVERT(datetime, @datecreated1, 103), 112)<=CONVERT(varchar, CONVERT(datetime, @todate, 103), 112)
begin
if @Range='Days'
begin
	if datediff(dd,CONVERT(datetime,@fromdate,103),convert(datetime,@todate,103))>20*@RangeValue
	begin
	set @RangeValue=ceiling((datediff(dd,CONVERT(datetime,@fromdate,103),convert(datetime,@todate,103)))/20) +1
	end
insert into #UsersConsumption(FromTo,UsersCount,SMSConsumption,Type)
select @datecreated1 + ' - ' + cast(convert(varchar,dateadd(dd,@RAngevalue-1,convert(datetime,@datecreated1,103)),103) as nvarchar),count(distinct c.user_id),sum(debits),u.userfilter from credit_details(nolock) c join user_detail (nolock) u on u.user_id=c.user_id where
convert(varchar,c.datecreated,112) between convert(varchar,convert(datetime,@datecreated1,103),112) and convert(varchar,dateadd(dd,@Rangevalue-1,convert(datetime,@datecreated1,103)),112) group by u.userfilter 
set @datecreated1=convert(varchar,dateadd(dd,@Rangevalue,CONVERT(varchar, CONVERT(datetime, @datecreated1, 103), 112)),103)
end
else if @Range = 'Months'
begin
if datediff(mm,CONVERT(datetime,@fromdate,103),convert(datetime,@todate,103))>20*@RangeValue
begin
set @RangeValue=ceiling((datediff(mm,CONVERT(datetime,@fromdate,103),convert(datetime,@todate,103)))/20) +1
end
	declare @monthend varchar(20)
	set @monthend= Convert(varchar,DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, CONVERT(datetime, @datecreated1, 103)) + @Rangevalue, 0)),103)
	insert into #UsersConsumption(FromTo,UsersCount,SMSConsumption,Type)
	select @datecreated1 + ' - ' + cast(convert(varchar,dateadd(dd,@RAngevalue-1,convert(datetime,@datecreated1,103)),103) as nvarchar),count(distinct c.user_id),sum(debits),u.userfilter from credit_details(nolock) c join user_detail (nolock) u on u.user_id=c.user_id where
convert(varchar,c.datecreated,112) between convert(varchar,convert(datetime,@datecreated1,103),112) and convert(varchar,dateadd(dd,@Rangevalue-1,convert(datetime,@datecreated1,103)),112) group by u.userfilter 
	set @datecreated1=convert(varchar,dateadd(dd,1,convert(datetime,@monthend,103)),103)						
end
end	
--insert into #UsersConsumptionAll(Fromto,UsersCount,SMSConsumption,Type)
--				select u.FromTo,u.COUNT,s.COUNT from #UserStats u join #UserStats s on u.FromTo=s.fromto where u.type='Individual' and s.Type='Company' group by u.fromto,u.COUNT,s.COUNT
select * from #UsersConsumption 
drop table #UsersConsumption
	
	
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	
END





