/* ============================================================
   Procedure: [dbo].[usp_SmsDeliveryReportUpdateByJob]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_SmsDeliveryReportUpdateByJob    
as    
Begin    
    drop table if exists #Temp_tbl    
 begin try    
    
      select row_number() over(order by id asc) as RowNum ,ID, txid,[to],[from],[description] ,deliverystatus, deliverydt,dlr_updated    
            into #Temp_tbl  from tbl_SMS_QueryString with(nolock) where isnull(dlr_updated,0) =  0 and id > 402 and dlr_updateattempted =0 order by id asc    
          
   declare @Count int = isnull((select count(1) from #Temp_tbl),0)          
   declare @RowNum int = 1    
    
 declare  @txnid bigint,        
   @mobile nvarchar(50),        
   @senderid nvarchar(50),        
   @err_description nvarchar(500),        
   @deliverystatus nvarchar(100),        
   @deliverydt nvarchar(50),        
   @tbl_qs_id bigint    
    
   while(@Count > 0)    
    begin    
        select  @txnid = txid ,        
   @mobile = [to],        
   @senderid = [from],        
   @err_description = [description],        
   @deliverystatus = deliverystatus,        
   @deliverydt = deliverydt ,        
   @tbl_qs_id  = ID    
   from #Temp_tbl where RowNum = @RowNum    
    
   begin try    
    exec usp_updatesmsdelivery_xml @txnid , @mobile ,@senderid ,@err_description ,@deliverystatus ,@deliverydt ,@tbl_qs_id      
   -- update tbl_SMS_QueryString set dlr_updated = 1 where ID = @tbl_qs_id    
    
            end try    
   begin catch    
           exec usp_InsertErrorInfo    
         end catch    
    
   set @RowNum = @RowNum + 1    
   set @Count = @Count - 1    
    end    
 end try    
    begin catch    
   exec usp_InsertErrorInfo    
 end catch    
 drop table if exists #Temp_tbl    
end


GO

