/* ============================================================
   Procedure: [dbo].[usp_smsreportsdetailed]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
 
 --[usp_emailreportssummary] 335,null,null,'2021-07-01','2021-07-11' 
CREATE   PROCEDURE [dbo].[usp_smsreportsdetailed] --335,null,null,'20210701','20210806','bulk sms'-- 33819,null,null,'2021-05-01','2021-07-11',null,null,'clicked' 
( 
@parentid bigint, 
@campaigntype nvarchar(20)=null, 
@campaignname nvarchar(100)=null, 
@fromdate date=null, 
@todate date=null, 
@sms_source nvarchar(200)=null, 
@batchid bigint=null, 
@reporttype nvarchar(50)=null 
) 
as 
begin 
--declare @parentid bigint=335, 
--@campaigntype nvarchar(20)=null, 
--@campaignname nvarchar(100)=null, 
--@fromdate date='2021-07-01', 
--@todate date='2021-07-10' 
 
 if(@campaigntype = '') 
 Begin 
 set @campaigntype = null 
 End 
 
 if(@campaignname = '') 
 Begin 
 set @campaignname = null 
 End 
 
 if(@fromdate = '') 
 Begin 
 set @fromdate = null 
 End 
 
 if(@todate = '') 
 Begin 
 set @todate = null 
 End 
 
 if(@sms_source = '') 
 Begin 
 set @sms_source = null 
 End 
 
 
 
if @fromdate=null 
begin 
set @fromdate=cast(DATEADD(m, DATEDIFF(m, 0, GETDATE()), 0) as date) 
set @todate=cast(getdate() as date) 
end 
 
create table #batchids(batchid bigint) 
if @sms_source is not null 
begin 
insert into #batchids (batchid) 
select batchid from mysms.dbo.BatchInfo b with (nolock) join 
user_detail u with (nolock) on u.User_ID=b.UserID 
where 
u.parentid=@parentid and 
sms_source=@sms_source and isnull(cast(nullif(scheduleddate,'') as datetime),batchinserttime) between @fromdate and @todate 
end 
if @batchid is not null 
begin 
insert into #batchids (batchid) 
select @batchid 
end 
 
 
 
drop table if exists #batch 
drop table if exists #sent 
drop table if exists #smsreport 
drop table if exists #kopened 
drop table if exists #kclicked 
drop table if exists #awsreport 
drop table if exists #unsubscribed 
 
select b.batchid,sms_source ,cast(isnull(nullif(scheduleddate,''),batchinserttime) as date) batchinserttime, 
coalesce(t.cname,c.campaignname,case when sms_source ='api' then 
cast(cast(isnull(nullif(scheduleddate,''),batchinserttime) as date) as nvarchar(50)) when isnull(sms_source,'Bulk SMS') ='Bulk SMS' then 
cast(isnull(nullif(scheduleddate,''),batchinserttime) as nvarchar(50))+'_'+cast(b.batchid as nvarchar) 
else 'CRM_'+sms_source end) 
 as campaignname, 
 case when t.id is not null then 'Triggered Campaign' 
 when c.id is not null and isnull(c.IsScheduled,0)=1 then 'Scheduled Campaign' 
 when c.id is not null and isnull(c.IsScheduled,0)=0 then 'Event Based Campaign' 
 when sms_source ='api' then 
cast(cast(isnull(nullif(scheduleddate,''),batchinserttime) as date) as nvarchar(50)) 
 when isnull(sms_source,'Bulk SMS') ='Bulk SMS' then 'Bulk SMS Campaign' 
 else 'CRM Mails' end 
 as campaigntype,cast(isnull(nullif(scheduleddate,''),batchinserttime) as date) CampaignDate,TotalRecords, 
 bsender_id,bmessage--,Delivered,Bounced,TotalSent 
into #batch 
from 
BatchInfo b with (nolock) 
join user_detail u with (nolock) on u.User_ID=b.UserID 
join #batchids bd on b.batchid=bd.batchid 
left join usercampaignmaster c with (nolock) on c.ParentID=u.parentid and b.sms_source like 'campaign%' 
and cast(c.ID as nvarchar)=replace(b.sms_source, 
'Campaign :','') 
left join triggeredcampaigns t with (nolock) on c.eventid=t.eventid and t.smscampaignid=c.id 
where u.ParentID=@parentid 
and cast(isnull(nullif(scheduleddate,''),batchinserttime) as date) between @fromdate and @todate 
 
if @reporttype='clicked' 
begin 
select m.batchid,e.mobile,e.Long_Url, m.MessageID , 
VisitDate ClickedTime,campaignname ,BatchInsertTime 
into #kclicked_link 
from 
mysms.dbo.[Link_smsTrack] e with (nolock) 
join mysms.dbo.Link_smsMobile m with (nolock) 
on e.link_id=m.mobile_url_id 
join #batch b on m.BatchID=b.BatchID 
where (campaigntype is null or (campaigntype=case when @campaigntype is null then campaigntype 
else @campaigntype end 
and campaignname=case when @campaignname is null then campaignname 
else @campaignname end )) 
 
select k.batchid,long_url Link,Mobile,k.campaignname,k.BatchInsertTime as Senttime,ClickedTime 
from #kclicked_link k 
order by ClickedTime desc 
end 
else 
begin 
--to be discussed (delivery reports) 
select batchid,mobile,senderid,messagetext,messagestatus 
into #sent 
from 
( 
select b.batchid,coalesce(m.mobile,t.mobile) as Mobile,coalesce(bsender_id,m.senderid,t.senderid) as senderid,coalesce(m.message,t.message) as messagetext, 
coalesce(m.messagestatus,t.messagestatus) messagestatus 
from #batch b 
left join 
messagedeliverystatus m with (nolock) on m.BatchID=b.batchid 
left join 
ThirtyDaysHistory t with (nolock) on t.batchid=b.BatchID 
) a 
 
 
/* 
select e.BatchID,e.cust_ref_id,event_status,event_desc,Reason as Description,cast(event_time as datetime) as Delivereddate 
into #smsreport 
from mysms.dbo.EmailDeliveryStatus e with (nolock) 
join #batch b on e.BatchID=b.BatchID 
 
create table #awsreport(batchid bigint,apiheader nvarchar(100),mailstatus nvarchar(50),description nvarchar(200), eventdate datetime) 
 
insert into #awsreport(batchid,apiheader,mailstatus,description,eventdate) 
select e.batchid,APIHeader,'Delivered' as mailstatus,'' as description,Delivereddate 
from mysms.dbo.Maildeliveries e with (nolock) 
join #batch b on e.BatchID=b.BatchID 
union 
select e.batchid,apiheader,'Bounced' as mailstatus,cast(bouncetype as nvarchar(20))+'- '+BounceSubType as Description,createdon 
from mysms.dbo.Mailbounces e with (nolock) 
join #batch b on e.BatchID=b.BatchID 
 
select e.mail_batchid batchid,e.Mail_ToEmail, 
case when smtpserver='aws' then a.mailstatus 
when smtpserver='karix' then k.event_desc 
else 'Sent' end as MailStatus, 
case when smtpserver='aws' then a.description 
when smtpserver='karix' then k.description 
 end as Description, 
case when smtpserver='aws' then a.eventdate 
when smtpserver='karix' then k.Delivereddate 
 end as delivereddate, 
 smtpserver 
into #sent 
from mysmstrans.dbo.emailsreportsent e with (nolock) 
join #batch b on e.Mail_BatchID=b.BatchID 
left join #karixreport k on k.BatchID=e.Mail_BatchID and k.cust_ref_id=e.Mail_GUID 
left join #awsreport a on a.BatchID=e.Mail_BatchID and a.apiheader=e.Mail_GUID 
 */ 
 
 
select m.batchid,e.mobile, 
max(visitdate) LastClickedTime 
into #kclicked 
from 
mysms.dbo.[link_smstrack] e with (nolock) 
join mysms.dbo.Link_smsMobile m with (nolock) 
on e.link_id=m.mobile_url_id 
join #batch b on m.BatchID=b.BatchID 
group by m.batchid,e.Mobile 
--order by cast((event_date + ' '+event_time) as datetime) desc 
 
 
select CampaignDate,sms_source ,campaigntype,campaignname,batchid,SentTime,mobile, 
--mailstatus,delivereddate,Description, 
LastClickedTime,senderid,messagetext 
from 
( 
select CampaignDate,sms_source ,campaigntype,campaignname,b.batchid,batchinserttime as SentTime, 
s.mobile,bsender_id as senderid,bmessage as messagetext, 
--isnull(s.MailStatus,i.mailstatus) Mailstatus,delivereddate, 
kc.LastClickedTime 
from 
#batch b 
left join #sent s on b.BatchID=s.batchid 
left join #kclicked kc on kc.BatchID=b.BatchID and s.mobile=kc.mobile 
--union 
--select CampaignDate,sms_source ,campaigntype,campaignname,b.batchid,isnull(scheduleddate,batchinserttime) as SentTime, 
--s.Mail_ToEmail,s.MailStatus,null as OpenedTimes,null as LastOpened 
--from 
--#batch b 
--left join #invalidmails s on s.batchid=b.BatchID 
) a 
where campaigntype=case when @campaigntype is null then campaigntype 
else @campaigntype end 
and campaignname=case when @campaignname is null then campaignname 
else @campaignname end 
--group by CampaignDate,campaigntype,campaignname,sms_source 
order by CampaignDate desc 
 
 
end 
 
drop table if exists #batch 
drop table if exists #sent 
drop table if exists #karixreport 
drop table if exists #kclicked 
 
 
 
 
 
 
 
 
/* 
if @fromdate=null 
begin 
set @fromdate=cast(DATEADD(m, DATEDIFF(m, 0, GETDATE()), 0) as date) 
set @todate=cast(getdate() as date) 
end 
select CampaignDate,campaigntype,campaignname,sum(TotalRecords) as Recipients 
from 
( 
select 
coalesce(t.cname,c.campaignname,case when sms_source in ('emails','csv') then 
cast(isnull(scheduleddate,batchinserttime) as nvarchar(50))+'_'+cast(b.batchid as nvarchar) 
else 'CRM' end) 
 as campaignname, 
 case when t.id is not null then 'Triggered Campaign' 
 when c.id is not null and isnull(c.IsScheduled,0)=1 then 'Scheduled Campaign' 
 when c.id is not null and isnull(c.IsScheduled,0)=0 then 'Event Based Campaign' 
 when sms_source in ('emails','csv') then 'Bulk Mail Campaign' 
 else 'CRM Mails' end 
 as campaigntype,cast(isnull(scheduleddate,batchinserttime) as date) CampaignDate,TotalRecords 
from 
BatchEmail_Infos b with (nolock) 
join user_detail u with (nolock) on u.User_ID=b.UserID 
left join usercampaignmaster c with (nolock) on c.ParentID=u.parentid and b.sms_source like 'campaign%' 
and cast(c.ID as nvarchar)=replace(b.sms_source, 
'Campaign :','') 
left join triggeredcampaigns t with (nolock) on c.eventid=t.eventid and t.mailcampaignid=c.id 
where u.ParentID=@parentid 
and cast(isnull(scheduleddate,batchinserttime) as date) between @fromdate and @todate 
) a 
where campaigntype=case when @campaigntype is null then campaigntype 
else @campaigntype end 
and campaignname=case when @campaignname is null then campaignname 
else @campaignname end 
group by CampaignDate,campaigntype,campaignname 
order by CampaignDate desc 
*/ 
