/* ============================================================
   Procedure: [dbo].[usp_smsreportssummary]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_smsreportssummary]-- 335,null,null,'2021-07-01','2021-07-09' 
( 
@parentid bigint, 
@campaigntype nvarchar(20)=null, 
@campaignname nvarchar(100)=null, 
@fromdate date=null, 
@todate date=null 
) 
as 
begin 
--declare @parentid bigint=335, 
--@campaigntype nvarchar(20)=null, 
--@campaignname nvarchar(100)=null, 
--@fromdate date='2021-07-01', 
--@todate date='2021-07-09' 
 
if @fromdate=null 
begin 
set @fromdate=cast(DATEADD(m, DATEDIFF(m, 0, GETDATE()), 0) as date) 
set @todate=cast(getdate() as date) 
end 
 
drop table if exists #batch 
drop table if exists #sent 
drop table if exists #status 
drop table if exists #datestatus 
drop table if exists #clicked 
drop table if exists #datesent 
drop table if exists #dateclicked 
 
--select * from batchinfo with (nolock) where userid=@parentid and cast(isnull(scheduleddate,batchinserttime) as date) 
--between @fromdate and @todate 
 
 
--select top 100 * from batchinfo with (nolock) where userid=335 order by batchinfoid desc 
----and cast(isnull(scheduleddate,batchinserttime) as date) between @fromdate and @todate 
 
select b.batchid,sms_source ,cast(isnull(nullif(scheduleddate,''),batchinserttime) as date) batchinserttime, 
coalesce(t.cname,c.campaignname,case when sms_source ='api' then 
cast(cast(isnull(nullif(scheduleddate,''),batchinserttime) as date) as nvarchar(50)) when isnull(sms_source,'Bulk SMS') ='Bulk SMS' then 
cast(isnull(nullif(scheduleddate,''),batchinserttime) as nvarchar(50))+'_'+cast(b.batchid as nvarchar) 
else 'CRM_'+sms_source end) 
 as campaignname, 
 case when t.id is not null then 'Triggered Campaign' 
 when c.id is not null and isnull(c.IsScheduled,0)=1 then 'Scheduled Campaign' 
 when c.id is not null and isnull(c.IsScheduled,0)=0 then 'Event Based Campaign' 
 when sms_source ='api' then 
cast(cast(isnull(nullif(scheduleddate,''),batchinserttime) as date) as nvarchar(50)) 
 when isnull(sms_source,'Bulk SMS') ='Bulk SMS' then 'Bulk SMS Campaign' 
 else 'CRM Mails' end 
 as campaigntype,cast(isnull(nullif(scheduleddate,''),batchinserttime) as date) CampaignDate,TotalRecords--,Delivered,Bounced,TotalSent 
into #batch 
from 
BatchInfo b with (nolock) 
join user_detail u with (nolock) on u.User_ID=b.UserID 
left join usercampaignmaster c with (nolock) on c.ParentID=u.parentid and b.sms_source like 'campaign%' 
and cast(c.ID as nvarchar)=replace(b.sms_source, 
'Campaign :','') 
left join triggeredcampaigns t with (nolock) on c.eventid=t.eventid and t.smscampaignid=c.id 
where u.ParentID=@parentid 
and cast(isnull(nullif(scheduleddate,''),batchinserttime) as date) between @fromdate and @todate 
 
--select * from #batch 
 
select e.BatchID,sum(sent) Sent,SentDate 
into #datesent 
from 
(select b.batchid,cast(batchinserttime as date) as SentDate,count(1) Sent 
from messageDeliveryStatus e with (nolock) 
join #batch b on e.BatchID=b.BatchID 
group by b.batchid,cast(batchinserttime as date) 
union 
select b.batchid,cast(batchinserttime as date) as SentDate,count(1) Sent 
from thirtydayshistory e 
join #batch b on e.BatchID=b.BatchID 
group by b.batchid,cast(batchinserttime as date) 
) e 
group by batchid,sentdate 
 
--select * from #datesent 
 
select e.batchid,sum(Sent) Sent 
into #sent 
from 
#datesent e with (nolock) 
group by e.batchid 
 
--select * from #sent 
 
select e.BatchID,status,sum(total) Total,SentDate 
into #datestatus 
from 
(select b.batchid,cast(batchinserttime as date) as SentDate,MessageStatus as status,count(1) Total 
from messageDeliveryStatus e with (nolock) 
join #batch b on e.BatchID=b.BatchID 
group by b.batchid,cast(batchinserttime as date),MessageStatus 
union select b.batchid,cast(batchinserttime as date) as SentDate,MessageStatus as status,count(1) Total 
from thirtydayshistory e 
join #batch b on e.BatchID=b.BatchID 
group by b.batchid,cast(batchinserttime as date),MessageStatus 
) 
e 
group by batchid,sentdate,status 
 
--select * from #datestatus 
 
select e.batchid,Status,sum(total) Total 
into #status 
from 
#datestatus e with (nolock) 
group by e.batchid,status 
 
--select * from #status 
 
select count(distinct link_id) clicked,m.batchid,cast(b.batchinserttime as date) SentDate 
into #dateclicked 
from link_smstrack l join link_smsmobile m on l.link_id=m.mobile_url_id 
join #batch b on b.batchid=m.batchid 
group by m.batchid,cast(b.batchinserttime as date) 
 
--select * from #dateclicked 
 
select e.batchid,sum(clicked) Clicked 
into #clicked 
from 
#dateclicked e with (nolock) 
group by e.batchid 
 
--select * from #clicked 
 
--/////////**********Queries for display///////////////////// 
 
select cast(b.batchinserttime as date) as sentdate,sum(isnull(clicked,0)) clicked from #dateclicked k right 
join #batch b on b.BatchID=k.BatchID 
where campaigntype=case when @campaigntype is null then campaigntype 
else @campaigntype end 
and campaignname=case when @campaignname is null then campaignname 
else @campaignname end 
group by cast(b.batchinserttime as date) 
 
select cast(batchinserttime as date) as sentdate,isnull(status,'') status,count(Total) as Total from #datestatus k 
right join #batch b on b.BatchID=k.BatchID 
where campaigntype=case when @campaigntype is null then campaigntype 
else @campaigntype end 
and campaignname=case when @campaignname is null then campaignname 
else @campaignname end 
group by cast(b.batchinserttime as date),isnull(status,'') 
 
select top 20 b.campaignname,clicked 
from #clicked c join #batch b on b.batchid=c.batchid 
order by clicked desc 
 
select 
sum(totalrecords) TotalRecords, 
sum(isnull(Sent,0)) Sent, 
sum(case when status='' then 1 else 0 end) Delivered, 
sum(clicked) Clicked 
from 
#batch b 
left join #sent s on b.BatchID=s.BatchID 
left join #status a on a.batchid=b.batchid 
left join #clicked c on c.batchid=b.BatchID 
where campaigntype=case when @campaigntype is null then campaigntype 
else @campaigntype end 
and campaignname=case when @campaignname is null then campaignname 
else @campaignname end 
 
select batchid,CampaignDate,sms_source ,campaigntype,campaignname,sum(TotalRecords) as Recipients,sum(case when status='' then 1 else 0 end) as Delivered, 
sum(isnull(clicked,0)) Clicked,sum(isnull(sent,0)) Sent 
from 
( 
select b.batchid,CampaignDate,sms_source ,campaigntype,campaignname,TotalRecords,Sent,Status,Clicked 
from 
#batch b 
left join #sent s on b.BatchID=s.batchid 
left join #status ab on ab.batchid=b.BatchID 
left join #clicked kc on kc.BatchID=b.BatchID 
) a 
where campaigntype=case when @campaigntype is null then campaigntype 
else @campaigntype end 
and campaignname=case when @campaignname is null then campaignname 
else @campaignname end 
group by CampaignDate,campaigntype,campaignname,sms_source,BatchID 
order by CampaignDate desc 
 
--select sum(TotalRecords) as Recipients,sum(case when status='' then 1 else 0 end) as Delivered, 
--sum(isnull(clicked,0)) Clicked,sum(isnull(sent,0)) Sent 
--from 
--( 
--select CampaignDate,sms_source ,campaigntype,campaignname,TotalRecords,Sent,Status,Clicked 
--from 
--#batch b 
--left join #sent s on b.BatchID=s.batchid 
--left join #status ab on ab.batchid=b.BatchID 
--left join #clicked kc on kc.BatchID=b.BatchID 
--) a 
--where campaigntype=case when @campaigntype is null then campaigntype 
--else @campaigntype end 
--and campaignname=case when @campaignname is null then campaignname 
--else @campaignname end 
 
 
 
drop table if exists #batch 
drop table if exists #sent 
drop table if exists #status 
drop table if exists #datestatus 
drop table if exists #clicked 
drop table if exists #datesent 
drop table if exists #dateclicked 
 
 
end 
 
 
--select * from mysmstrans.dbo.EmailsReportSent with (nolock) where mail_batchid=68138618 
--select * from mysmstrans.dbo.invalid_mail_emailsreport with (nolock) where mail_batchid=68138618 
 
--select --cast(e.event_time as date) event_time, 
--top 30* 
--into #datekbounced 
--from EmailDeliveryStatus e with (nolock) order by e.id desc 



