/* ============================================================
   Procedure: [dbo].[Usp_SMSToLeadEvent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SMSToLeadEvent    
(    
  @LeadID bigint,      
  @UserID bigint,      
  @ParentID bigint,      
  @Message nvarchar(max)        
  
)    
as    
Begin    
     
   Declare @EventID bigint = 0     
   Declare @EventName nvarchar(500) = 'SMS sent to lead'      
   Declare @EventTemplate nvarchar(max) = ''    
   Declare @UserName nvarchar(200) = ''  
   Declare @MobileNo nvarchar(50) = ''  
       
  select @UserName = isnull(user_login,'') from user_detail  where USER_ID = @UserID         
  select @MobileNo = isnull(MobileNo,'') from UserLeads where ID = @LeadID  
    
 select @EventID = isnull(ID,0) ,@EventTemplate = isnull(EventTemplate,'')  from ActivityMaster where EventName = @EventName     
   if(@EventID > 0)    
    Begin  
     
	 if(rtrim(ltrim(@MobileNo)) <> '')
	 Begin
      select @EventTemplate = replace(replace(replace(@EventTemplate,'#username#',@UserName),'#Messagecontent#',@Message),'#mobileno#',@MobileNo)  
   
      exec UspSaveLeadActivity @LeadID,@UserID,@ParentID,@EventTemplate,@EventID  
    End

    End    
    
End


GO

/* ============================================================
   Procedure: [dbo].[usp_smstrack_salessignal]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROCEDURE [dbo].[usp_smstrack_salessignal]      
@id bigint,@trackid bigint      
as      
begin      
declare @parentid bigint,@mobile nvarchar(20),@batchid bigint,@LongURL_LD nvarchar(200)      
select @parentid=parentid,@mobile=mobile,@batchid=batchid,@LongURL_LD=longurl from Link_smsMobile(nolock) where mobile_url_id=@id      
/* If sms sender has a valid subscription, check if the user who has clicked on the link exists in his lead or enquiry and send him a sales signal accordingly*/      
      
if exists(select 1 from Price_UserSubscriptionDetails(nolock) where userid=@parentid and IsNewPlan=1 and PlanEndDate>getdate())      
begin      
declare @user_login nvarchar(50),@user_id bigint,@message nvarchar(2000),@assignedto nvarchar(100)                
declare @recipients nvarchar(max),@salesmessage nvarchar(2500),@leadid bigint,@leadno int,@leadname nvarchar(100)      
select @message=bmessage from batchinfo(nolock) where batchid=@batchid                
Declare @Message_LDActivity nvarchar(max) = ''          
Declare @MessageSentDate_LDActivity nvarchar(50)      
select @Message_LDActivity= isnull(bmessage,''),@MessageSentDate_LDActivity = cast(isnull(nullif(scheduleddate,''),BatchInsertTime) as nvarchar(20))  from batchinfo(nolock) where batchid=@BatchID            
if @Message_LDActivity is null      
select @Message_LDActivity='Message text unavailable',@MessageSentDate_LDActivity='More than 30 days back'      
      
if exists(select 1 from UserLeads(nolock) where parentid=@parentid and @mobile in (MobileNo,MobileNo1,MobileNo2))      
begin                
select top 1 @Leadid=id,@leadno=leadno,@leadname=isnull(personname,''),@user_id=assignedto from userleads(nolock) where parentid=@parentid and @mobile in (MobileNo,MobileNo1,MobileNo2) order by id desc      
select @user_login=user_login from user_detail(nolock) where user_id=@user_id      
select @recipients= coalesce(@recipients+',','')+cast(str(mobile) as nvarchar(max)) from user_Detail(nolock) where user_id in (@user_id,@parentid)      
 Begin try          
Declare @UserID_LDActivity bigint = @user_id          
Declare @LeadID_LDActivity   bigint = 0           
Declare @ParentID_LDActivity  bigint = @ParentID         
      
select @salesmessage= 'Lead number: '+ cast(@leadno as nvarchar)+ ', Name: '+@leadname+ ', Assigned to : '+@user_login +   
' and with mobile number '+@mobile+' just clicked on a link on a SMS sent by you. The message read as "' +     
substring(@Message_LDActivity,1,50)      
  + '" was sent on '+ @MessageSentDate_LDActivity + '. Pl take apt action Kit19'    
  
    
if not exists(select 1 from Salesignals(nolock) where parentid=@parentid and mapping='Mobile' and Mappingvalue=@mobile and datediff(mi,createdon,getdate())<=5 and RelatedEntity='Lead' and relatedentityid=@leadid)      
begin      
 exec usp_sendmessage 335,@salesmessage,@recipients,'KITAPP',0,1      
end      
select top 1 @LeadID_LDActivity = isnull(ID,0) from UserLeads(nolock) where @mobile in (MobileNo,MobileNo1,MobileNo2)  
and parentid=@parentid    order by id desc      
          
  create table #tblEventDescrb          
  (          
    EVNT_Description nvarchar(max)           
  )          
          
  if(isnull(@LeadID_LDActivity,0) > 0)          
    Begin          
                 
    insert into #tblEventDescrb          
       exec  Usp_EventTemplate_DynamicVarReplacement 'Lead clicked on link in sms',@UserID_LDActivity,@Message_LDActivity,          
    @Mobile,@LeadID_LDActivity,@LongURL_LD,@MessageSentDate_LDActivity,0,0,null,null,0,null,0,null,          
    null,null,null,null,0,null,null,null,null,null,null,null,null,null,null,null,0,0,0,null,null,null,0,null,null,          
    null,null,null,null          
           
    declare @evntMessage nvarchar(max) = ''           
          
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb          
             
   exec UspSaveLeadActivity_withid @LeadID_LDActivity,@UserID_LDActivity,@ParentID_LDActivity,@evntMessage,'Lead clicked on link in sms' ,'Link_smstrack',@trackid         
 End          
          
 End try          
          
 Begin Catch          
          
   exec usp_InsertErrorInfo           
          
 End Catch          
          
  IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence            
   Begin                DROP TABLE #tblEventDescrb            
   End           
 end                
 else if exists(select 1 from userenquiry(nolock) where ParentID =@parentid and @mobile in (MobileNo,MobileNo1,MobileNo2))      
 begin      
select top 1 @Leadid=enquiryid,@leadname=isnull(personname,''),@user_id=CreatedBy from userenquiry(nolock) where parentid=@parentid and @mobile in (MobileNo,MobileNo1,MobileNo2) order by EnquiryID desc      
select @user_login=user_login from user_detail(nolock) where user_id=@user_id      
select @recipients= coalesce(@recipients+',','')+cast(str(mobile) as nvarchar(max)) from user_Detail(nolock) where user_id in (@user_id,@parentid)      
select @salesmessage= 'Enquiry with ID: '+ cast(@leadid as nvarchar)+ ', Name: '+@leadname+ ', created by: '+@user_login + ' and with mobile number '    
+@mobile+' just clicked on a link on a SMS sent by you. The message read as "'     
+ substring(@Message_LDActivity,1,50)      
  + '" was sent on '+ @MessageSentDate_LDActivity + '. Pl take apt action Kit19'      
  if not exists(select 1 from Salesignals(nolock) where parentid=@parentid and mapping='Mobile' and Mappingvalue=@mobile and datediff(mi,createdon,getdate())<=5 and RelatedEntity='Enquiry' and relatedentityid=@leadid)      
begin      
 exec usp_sendmessage 335,@salesmessage,@recipients,'KITAPP',0,1      
 end      
end      
if not exists(select 1 from Salesignals(nolock) where parentid=@parentid and mapping='Mobile' and Mappingvalue=@mobile and datediff(mi,createdon,getdate())<=5 and       
RelatedEntity=case when @leadno is not null then 'Lead' when @leadid is not null then 'Enquiry' end and relatedentityid=@leadid)      
begin      
insert into Salesignals(parentid ,Event,Description,Reftable,Refid,RelatedEntity,RelatedEntityid,Mapping,Mappingvalue)      
select @parentid,'SMS link tracking',@salesmessage,'Link_smstrack',@trackid,case when @leadno is not null then 'Lead' when @leadid is not null then 'Enquiry' end,@leadid,'Mobile',@mobile      
end      
end      
end      
      
--select top 100* from Salesignals(nolock) order by id desc      
--select email from user_detail(nolock) where user_id=335      
      


GO

/* ============================================================
   Procedure: [dbo].[usp_Soc_GetLongAccessTokenBypage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Soc_GetLongAccessTokenBypage] --------------------------------------kit19social
    @Page nvarchar(100),
    @PlateformId INT
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        DECLARE @LoggedinUserId BIGINT;
        DECLARE @FbUserId BIGINT;
        DECLARE @PageId BIGINT;

        -- Step 2: Get FbUserId from FacebookUsers table using PageId
        SELECT TOP 1 
               @FbUserId = fu.FbUserId
        FROM Mysms.dbo.tbl_fb_FacebookUsers fu
        WHERE  fu.PlatformId = @PlateformId
          AND fu.isActive = 1
          AND fu.Pages = @Page
        ORDER BY fu.UpdatedOn DESC;

        -- Step 3: Return LongAccessToken + PageAccessToken
        SELECT TOP 1 
               CAST(fu.LongAccessToken AS VARCHAR(MAX)) AS LongAccessToken,
               CAST(fp.FbPageLongToken AS VARCHAR(MAX)) AS PageAccessToken
        FROM Mysms.dbo.tbl_fb_FacebookUsers fu
        INNER JOIN Mysms.dbo.tbl_fb_FacebookPages fp 
            ON fu.FbUserId = fp.FbUserId
        WHERE  fp.FbUserId = @FbUserId
        ORDER BY fu.UpdatedOn DESC;

    END TRY
    BEGIN CATCH
        EXEC Mysms.dbo.usp_InsertErrorInfo;
    END CATCH
END



GO

