        @Pages           NVARCHAR(MAX) = '[{"Id":"524733957399412","Name":"My test page","AccessToken":null}]',
		@IsValid        bit =1,
    @LoggedUserId BIGINT=32222
  */

  /*DECLARE   
  @Result INT = 0,  
        @PersonName      VARCHAR(255) = 'Dhananjay Giri',   
        @LongAccessToken VARCHAR(MAX) = 'AQXXPvsh6I8m2wEVXyZHFj5ZAKHczwPARLjKlDPjjauhW8QtW92TEsmDjAvszWLWNoR86fnUoCqCtojOoqMfxjTmbXinZfGoGAEt1bUXNfueNbdQlV4LenjFuy46YbNXe71v5GPjGBPP-t84-oECTAf56M6RQsF5ahbzXjQ_ZDfx_Dbg07zaQotGesHi6JQNNjXuSMUsRI21xBI-9u5yjK
NY52AH9R4XCzlgBKUU2BRdZEG-A-BQO1SNFqTQwQPMoJljoAZzSGzKbV013k0tu-khqovM3h2nwD3P337S7ZuCbm1eGJfKD0GNdh9DxJKZRNSXnoHe7MYR9fWcdP9V0Z26NWKlMg',   
        @ExpiryTimestamp BIGINT = 5183999,   
        @FbUserId        VARCHAR(255) = 'ki9YZgZf_z',   
        @ParentId        BIGINT = 34594,   
  @PlateformId int=5,  
        @CreatedOn       DATETIME = '2025-06-11',  
        @Email           VARCHAR(255) = 'djay9973@gmail.com',            
        @Pages           NVARCHAR(MAX) = null;*/  
  
  
  
  
  BEGIN TRY  
  IF EXISTS (  
    SELECT 1   
    FROM MYSMS.dbo.tbl_fb_FacebookUsers WITH (NOLOCK)   
    WHERE FbUserId = @FbUserId AND PlatformId = @PlateformId and ParentId=@ParentId and LoggedUserId=@LoggedUserId  
)  
BEGIN  
    UPDATE MYSMS.dbo.tbl_fb_FacebookUsers   
    SET   
        PersonName = IIF(ISNULL(@PersonName, '') = '', PersonName, @PersonName),  
        LongAccessToken = IIF(ISNULL(@LongAccessToken , '') = '', LongAccessToken, @LongAccessToken),  
        ExpiryTimestamp = IIF(@ExpiryTimestamp = 0, ExpiryTimestamp, @ExpiryTimestamp),  
        ParentId = IIF(@ParentId = 0 , ParentId, @ParentId),  
  LoggedUserId = IIF(@LoggedUserId = 0 , LoggedUserId, @LoggedUserId),  
        PlatformId = IIF(@PlateformId = 0, PlatformId, @PlateformId),  
        Email = IIF(ISNULL(@Email, '') = '', Email, @Email),              
  
       Pages =   
    CASE   
        WHEN @PlateformId = 2 THEN   
            IIF(ISNULL(@PersonName, '') = '', Pages, @PersonName)  
        WHEN @PlateformId = 5 THEN   
            NULL  
        ELSE   
            ISNULL((  
                SELECT TOP 1 NULLIF(JSON_VALUE(value, '$.Name'), '')  
                FROM OPENJSON(@Pages)  
            ), Pages)  
    END,  
  
  
        UpdatedOn = GETDATE()  
    WHERE FbUserId = @FbUserId AND PlatformId = @PlateformId;  
END  
ELSE  
BEGIN  
    INSERT INTO MYSMS.dbo.tbl_fb_FacebookUsers   
    (  
        PersonName, LongAccessToken, ExpiryTimestamp, FbUserId,   
        ParentId, PlatformId, CreatedOn, UpdatedOn, Email,LoggedUserId, Pages  
    )   
    VALUES   
    (  
        @PersonName,   
        @LongAccessToken,   
        @ExpiryTimestamp,   
        @FbUserId,   
        @ParentId,   
        @PlateformId,   
        @CreatedOn,   
        GETDATE(),   
        @Email,   
  @LoggedUserId,  
        CASE   
    WHEN @PlateformId = 2 THEN @PersonName  
    WHEN @PlateformId = 5 THEN NULL  
    ELSE (  
        SELECT TOP 1 NULLIF(JSON_VALUE(value, '$.Name'), '')  
 FROM OPENJSON(@Pages)  
    )  
  
        END  
    );  
END  
  
       /* IF EXISTS (SELECT 1 FROM tbl_fb_FacebookUsers WITH (NOLOCK) WHERE FbUserId = @FbUserId and PlatformId=@PlateformId)  
        BEGIN  
            UPDATE tbl_fb_FacebookUsers   
            SET   
                PersonName = IIF(ISNULL(@PersonName, '') = '', PersonName, @PersonName),  
                LongAccessToken = IIF(ISNULL(@LongAccessToken , '') = '', LongAccessToken, @LongAccessToken),  
                ExpiryTimestamp = IIF(@ExpiryTimestamp = 0, ExpiryTimestamp, @ExpiryTimestamp),  
                ParentId = IIF(@ParentId = 0 , ParentId, @ParentId),  
    PlatformId = IIF(@PlateformId = 0, PlatformId, @PlateformId),  
                Email = IIF(ISNULL(@Email, '') = '', Email, @Email),              
                Pages =   
            CASE   
                WHEN @PlateformId = 2 THEN   
                    IIF(ISNULL(@PersonName, '') = '', Pages, @PersonName)  
                ELSE   
                    ISNULL((  
                        SELECT TOP 1 NULLIF(JSON_VALUE(value, '$.Name'), '')  
                        FROM OPENJSON(@Pages)  
                    ), Pages)  
            END,      
                UpdatedOn = GETDATE()  
            WHERE FbUserId = @FbUserId;  
        END  
        ELSE  
        BEGIN  
            INSERT INTO tbl_fb_FacebookUsers   
            (PersonName, LongAccessToken, ExpiryTimestamp, FbUserId, ParentId,PlatformId, CreatedOn, UpdatedOn, Email, Pages)   
            VALUES   
            (@PersonName, @LongAccessToken, @ExpiryTimestamp, @FbUserId, @ParentId,@PlateformId, @CreatedOn, GETDATE(), @Email, @Pages);   
        END*/  
  
        IF ISJSON(@Pages) = 1    
    BEGIN    
        DECLARE @MaxId INT = ISNULL((SELECT MAX(Id) FROM MYSMS.dbo.tbl_fb_FacebookPages), 0);    
  
        ;WITH PagesCTE AS (    
            SELECT    
                ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS RowNum,    
                NULLIF(JSON_VALUE(value, '$.Id'), '') AS FbPageId,    
                COALESCE(NULLIF(JSON_VALUE(value, '$.Name'), ''), 'Unknown Page') AS FbPageName,    
                NULLIF(JSON_VALUE(value, '$.AccessToken'), '') AS FbPageLongToken    
    --,IsValidToken  
            FROM OPENJSON(@Pages)    
            WHERE NULLIF(JSON_VALUE(value, '$.Id'), '') IS NOT NULL    
        )    
        MERGE MYSMS.dbo.tbl_fb_FacebookPages AS target    
        USING PagesCTE AS source    
        ON target.FbPageId = source.FbPageId AND target.FbUserId = @FbUserId    
        WHEN MATCHED THEN    
            UPDATE SET    
                FbPageName = source.FbPageName,    
                FbPageLongToken = source.FbPageLongToken,    
                UpdatedOn = GETDATE(),   
    ParentId = @ParentId,   
    LoggedUserId = @LoggedUserId,   
                TokenLastSynced = GETDATE()    
        WHEN NOT MATCHED THEN    
            INSERT (    
                --Id,
				FbPageId, FbPageName, FbPageLongToken, FbUserId, ParentId,LoggedUserId,    
                CreatedOn, UpdatedOn, isActive, IsAuthorized, LastAuthorizedStatus, TokenLastSynced,IsValidToken    
            )    
            VALUES (    
                --@MaxId + source.RowNum
				--,    
                source.FbPageId, source.FbPageName, @PageAccessToken,--source.FbPageLongToken,    
                @FbUserId, @ParentId,@LoggedUserId, GETDATE(), GETDATE(),    
                1, 1, 1, GETDATE(),1    
            );    
    END    
  
     ELSE  
        BEGIN  
            -- Handle invalid JSON by inserting a dummy/fallback page entry  
            MERGE MYSMS.dbo.tbl_fb_FacebookPages AS target    
            USING (SELECT 1 AS DummySource) AS source    
            ON 1 = 0  -- Always insert  
            WHEN NOT MATCHED THEN    
                INSERT  (    
                    --Id,
					FbPageId, FbPageName, FbPageLongToken, FbUserId, ParentId,LoggedUserId,    
                    CreatedOn, UpdatedOn, isActive, IsAuthorized, LastAuthorizedStatus, TokenLastSynced ,IsValidToken    
                )    
 VALUES (    
                    --@MaxId + 1,    
                    CAST(NEWID() AS VARCHAR(255)),    
                    @PersonName,    
                    @PageAccessToken,    
                    @FbUserId, @ParentId,@LoggedUserId, GETDATE(), GETDATE(),    
                    1, 1, 0, GETDATE() , 1   
                );  
        END  
     print '1'
        SET @Result = 1;  
    END TRY  
    BEGIN CATCH  
	  SET @Result = -1;  
	 print '2'
	 --select ERROR_MESSAGE();
        EXEC MYSMS.dbo.usp_InsertErrorInfo;  
       
    END CATCH  
  
    SELECT @Result AS Result;  

    SET NOCOUNT Off;  
END  


GO

