/* ============================================================
   Procedure: [dbo].[usp_soc_SaveWebhooks]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_soc_SaveWebhooks]  -------------------in mysms
    @RequestJson NVARCHAR(MAX)  
AS

BEGIN 
    BEGIN TRY
	
        PRINT @RequestJson;

        -- Skip saving if JSON contains "leadgen"
        IF @RequestJson NOT LIKE '%leadgen%'
        BEGIN
            -- Save original json
            INSERT INTO tbl_soc_webhook(RequestJson)  
            VALUES(@RequestJson);  

            DECLARE @WebhookJsonId BIGINT = SCOPE_IDENTITY();

            -- Declare variables for FbFeedUpdateJson mapping
            DECLARE 
                @FbPageId NVARCHAR(100),
                @FbPage NVARCHAR(255),
                @Item NVARCHAR(50),
                @Verb NVARCHAR(50),
                @PostId NVARCHAR(100),
                @CommentId NVARCHAR(100),
                @ParentId NVARCHAR(100),
                @CreatedTime BIGINT,
                @UserId NVARCHAR(100),
                @UserName NVARCHAR(255),
                @Message NVARCHAR(MAX),
                @ReactionType NVARCHAR(50),
                @UserProfileImage NVARCHAR(MAX),
                @PhotoId NVARCHAR(100),
                @VideoId NVARCHAR(100),
				
				@InstaUserName NVARCHAR(255),
				@SelfIGScopedId NVARCHAR(100),
				@MediaId NVARCHAR(100),
				@MediaProductType NVARCHAR(50),
				@PlatformId INT;

				 -- Determine Platform
            IF JSON_VALUE(@RequestJson, '$.object') = 'instagram'
                SET @PlatformId = 2;
            ELSE 
                SET @PlatformId = 1;

            -- Extract common top-level entry id (page id or ig id)
            SELECT @FbPageId = JSON_VALUE(@RequestJson, '$.entry[0].id');

           /* -- Extract from changes.value
            SELECT 
                @FbPage        = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.from.name'),
                @UserId        = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.from.id'),
                @UserName      = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.from.name'),
                @Message       = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.message'),
                @PostId        = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.post_id'),
                @CreatedTime   = TRY_CAST(JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.created_time') AS BIGINT),
                @Item          = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.item'),
                @Verb          = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.verb'),
                @PhotoId       = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.photo_id'),
                @VideoId       = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.video_id'),
                @ReactionType  = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.reaction_type'),
				@ParentId  = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.parent_id'),
				@InstaUserName=JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.username'),
                @UserProfileImage = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.user_profile_image'); -- if exists

            -- Convert unix timestamp to datetime
            DECLARE @CreatedTimeDT DATETIME = 
                DATEADD(SECOND, @CreatedTime, '1970-01-01');

            -- Call your insert proc with parsed values
            EXEC usp_InsertFbFeedUpdateJson 
                @WebhookJsonId    = @WebhookJsonId,
                @JsonData         = @RequestJson,
                @FbPageId         = @FbPageId,
                @FbPage           = @FbPage,
                @Item             = @Item,
                @Verb             = @Verb,
                @PostId           = @PostId,
                @CommentId        = @CommentId,
                @ParentId         = @ParentId,
                @CreatedTime      = @CreatedTimeDT,
                @UserId           = @UserId,
                @UserName         = @UserName,
                @Message          = @Message,
                @ReactionType     = @ReactionType,
                --@UserProfileImage = @UserProfileImage,
                @IsProcessed      = 0,
                @FailedReason     = NULL,
                @PhotoId          = @PhotoId,
                @VideoId          = @VideoId;*/

 -- Facebook Mapping
            IF @PlatformId = 1
            BEGIN
                SELECT 
                    @FbPage        = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.from.name'),
                    @UserId        = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.from.id'),
                    @UserName      = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.from.name'),
                    @Message       = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.message'),
                    @PostId        = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.post_id'),
                    @CreatedTime   = TRY_CAST(JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.created_time') AS BIGINT),
                    @Item          = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.item'),
                    @Verb          = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.verb'),
					 @CommentId      = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.comment_id'),
                    @PhotoId       = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.photo_id'),
                    @VideoId       = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.video_id'),
                    @ReactionType  = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.reaction_type'),
					@ParentId      = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.parent_id'),
                    @UserProfileImage = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.user_profile_image');
            END
			DECLARE @Field NVARCHAR(50);
			SET @Field = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].field');
            -- Instagram Mapping
           IF @PlatformId = 2
           BEGIN
               -- Map Instagram events
               IF @Field = 'comments'
                   SET @ReactionType = 'comment';
               ELSE IF @Field = 'likes'
                   SET @ReactionType = 'like';
               ELSE IF @Field = 'mentions'
                   SET @ReactionType = 'mention';
               ELSE 
                   SET @ReactionType = @Field; -- fallback for other types
           
               SELECT
                   @UserId         = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.from.id'),
                   @InstaUserName  = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.from.username'),
                   @SelfIGScopedId = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.from.self_ig_scoped_id'),
                   @MediaId        = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.media.id'),
				   @PostId        = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.media.id'),
                   @MediaProductType = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.media.media_product_type'),
                   @CommentId      = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.id'),
                   @ParentId       = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.parent_id'),
                   @Message        = JSON_VALUE(@RequestJson, '$.entry[0].changes[0].value.text'),
                   @CreatedTime    = TRY_CAST(JSON_VALUE(@RequestJson, '$.entry[0].time') AS BIGINT);
           END

            -- Convert unix timestamp to datetime
            DECLARE @CreatedTimeDT DATETIME = NULL;
            IF @CreatedTime IS NOT NULL
                SET @CreatedTimeDT = DATEADD(SECOND, @CreatedTime, '1970-01-01');

           IF (@UserName IS NULL OR LTRIM(RTRIM(@UserName)) = '')
               SET @UserName = @InstaUserName;

            -- Call your insert proc with parsed values
            EXEC usp_InsertFbFeedUpdateJson 
                @WebhookJsonId    = @WebhookJsonId,--
                @JsonData         = @RequestJson,--
                @FbPageId         = @FbPageId,--
                @FbPage           = @FbPage,--in fb
                @Item             = @Item,--in fb
                @Verb             = @Verb,--in fb
                @PostId           = @PostId,--in 
                @CommentId        = @CommentId,--
                @ParentId         = @ParentId,--
                @CreatedTime      = @CreatedTimeDT,--
                @UserId           = @UserId,--
                @UserName         = @UserName,--
                @Message          = @Message,--
                @ReactionType     = @ReactionType,--
                @IsProcessed      = 0,--
                @FailedReason     = NULL,--
                @PhotoId          = @PhotoId,--in fb
                @VideoId          = @VideoId,--in fb

				@PlatformId       = @PlatformId,--
				@SelfIGScopedId   = @SelfIGScopedId,--in ins
				@MediaId          = @MediaId,--in ins
				@MediaProductType = @MediaProductType;--in ins
        END
        ELSE
        BEGIN
            PRINT 'Skipped leadgen webhook';
        END
    END TRY
    BEGIN CATCH 
        SELECT 'Error occurred: ' + ERROR_MESSAGE() AS Message;
        EXEC usp_inserterrorInfo;
    END CATCH
END


