/* ============================================================
   Procedure: [dbo].[usp_soc_UpdateFeedProcessingStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].usp_soc_UpdateFeedProcessingStatus------in mysms
    @WebhookJsonId BIGINT,
    @IsProcessed BIT,
    @FailedReason NVARCHAR(500) = NULL
AS
BEGIN
--declare 
-- @WebhookJsonId BIGINT=10029,
--    @IsProcessed BIT=1,
--    @FailedReason NVARCHAR(500) = NULL
    SET NOCOUNT ON;
    
  BEGIN TRY
        DECLARE @FeedUpdateId BIGINT;

        ------------------------------------------------------------------
        -- 1️⃣ Find the FeedUpdate record that corresponds to this webhook
        ------------------------------------------------------------------
        SELECT @FeedUpdateId = WebhookJsonId
        FROM Kit19Social.dbo.tbl_soc_FbFeedUpdateJson
        WHERE Id = @WebhookJsonId;

        ------------------------------------------------------------------
        -- 2️⃣ Update webhook main table
        ------------------------------------------------------------------
        UPDATE dbo.tbl_soc_webhook
        SET 
            IsProcessed = @IsProcessed,
            ProcessedDate = CASE WHEN @IsProcessed = 1 THEN GETDATE() ELSE ProcessedDate END
        WHERE Id = @FeedUpdateId;

        ------------------------------------------------------------------
        -- 3️⃣ Update related feed record (if exists)
        ------------------------------------------------------------------
        IF @FeedUpdateId IS NOT NULL
        BEGIN
            UPDATE Kit19Social.dbo.tbl_soc_FbFeedUpdateJson
            SET 
                IsProcessed = @IsProcessed,
                FailedReason = @FailedReason,
                ProcessedOn = CASE WHEN @IsProcessed = 1 THEN GETDATE() ELSE ProcessedOn END
            WHERE Id = @WebhookJsonId;
        END

        ------------------------------------------------------------------
        -- 4️⃣ Return affected info for debugging
        ------------------------------------------------------------------

        
        -- Return the number of affected rows for debugging
        SELECT @@ROWCOUNT AS AffectedRows, @WebhookJsonId AS WebhookJsonId;
        
    END TRY
    BEGIN CATCH
        -- Log the error and re-throw
        EXEC usp_insertErrorInfo;
        THROW;
    END CATCH
END


