   Procedure: [dbo].[Usp_SourceDeletion]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.Usp_SourceDeletion (
	@SourceID BIGINT
	,@IsActive BIT
	)
AS
BEGIN
	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserSourceSettings(NOLOCK)
			WHERE SourceID = @SourceID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)
	DECLARE @userid BIGINT = (
			SELECT UserID
			FROM UserSourceSettings(NOLOCK)
			WHERE SourceID = @SourceID
			)

	UPDATE UserSourceSettings
	SET IsActive = @IsActive
	WHERE SourceID = @SourceID

	SELECT 'Record Deactivated'

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid
		,@Activity_type = 'Delt_Srce_Sttng'
		,@ActionType = 'D'
		,@RowJson = @rowJson
		,@Table_name = 'UserSourceSettings'
END



