   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC USP_SpamMessage  --'MessageMonitor','xyx'  
@tableName varchar(200),  
@senderid varchar(100)  
as  
BEGIN  
if(@tableName='MessageMonitor')  
BEGIN  
insert into MessageFailed(MessageID,MessageBatchID,Mobile,[Message],SenderID,U_ID,FailureClause)  
select MessageID,BatchID,Mobile,[Message],SenderID,U_ID,'MessageMonitor' from dbo.MessageMonitor where ltrim(senderid)=@senderid  
  
delete From MessageMonitor where ltrim(senderid)=@senderid  
  
END  
  
IF @tableName='MessageSpam'  
BEGIN  
insert into MessageFailed(MessageID,MessageBatchID,Mobile,[Message],SenderID,U_ID,FailureClause)  
select MessageID,BatchID,Mobile,[Message],SenderID,U_ID,'MessageSpam' from dbo.MessageSpam where ltrim(senderid)=@senderid  
  
delete From MessageSpam where ltrim(senderid)=@senderid  
  
END  
END  


