/* ============================================================
   Procedure: [dbo].[usp_sso_GetCountryCodeForGivenDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sso_GetCountryCodeForGivenDetails] --'sms19','www.kit19.com'          
(                                             
    @UserNameOrEmailID nvarchar(200),
    @url nvarchar(200)
)                        
as
begin  

    --declare 
    --    @UserNameOrEmailID nvarchar(200),
    --    @url nvarchar(200)

    -- select @UserNameOrEmailID=N'Abhi01',@url=N'partner.newpartner.co.in'
     --select  @UserNameOrEmailID=N'Abhi01',@url=N'partner.newpartner.co.in'
     --select  @UserNameOrEmailID=N'32222-training',@url=N'localhost'

    if(@url like '%localhost%' or @url like '%.kit19.com' or @url like '' )
    begin
        set @url = 'www.kit19.com'
    end
    else
    begin
        set @url = dbo.fn_ExtractDomainWithWWW(@url)
    end

    print @url

    drop table if exists #allowDomain  
        create table #allowDomain(  
        resellerId bigint,  
        doaminName nvarchar(255)  
    )

    declare @UserId bigint = 0, @MId bigint = 0,@resellerId bigint = 0, @ParentId bigint = 0

    select @UserId = User_Id, @MId = M_ID, @resellerId = Reseller_ID from reseller_detail with (nolock) where domain = @url
    print concat('@UserId =>', @UserId)

    if(isnull(@UserId, 0) > 0)
    begin

        select @UserId = User_ID, @ParentId = ParentID, @MId = M_ID 
            from User_Detail with (nolock) where trim(@UserNameOrEmailID) in (User_Login, EMail)

        insert into #allowDomain (resellerId, doaminName)  
        select Reseller_ID, replace(replace(replace(Domain, 'https://', ''), 'www.', ''), 'http://', '')   
        from Reseller_Detail(nolock) where  User_ID = @ParentId or Reseller_ID  = @MId  
    
        if(dbo.fn_userdomain(@ParentId) in ('', 'https://', 'http://' ))  
        begin  
            insert into #allowDomain (resellerId, doaminName)  
            select dbo.fn_getusermid(dbo.fn_userimmediatepartner(@ParentId)),   
            replace(replace(replace(dbo.fn_userdomain(dbo.fn_userimmediatepartner(@ParentId)),  
            'https://', ''), 'www.', ''), 'http://', '')   
        end  

    

        select CountryCode, User_ID, EMail from User_Detail with (nolock) 
        where trim(@UserNameOrEmailID) in (User_Login, EMail)
            and replace(replace(replace(@url, 'https://', ''), 'www.', ''), 'http://', '') 
            in ( select doaminName from #allowDomain)

    end

end



