/* ============================================================
   Procedure: [dbo].[usp_sso_GetUserDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sso_GetUserDetails]  
(
    @UserId   BIGINT,  
    @TpUserId BIGINT  
)  
AS  
BEGIN  
     
     -- Example test values  
     --DECLARE @UserId BIGINT = 19035;  
     --DECLARE @TpUserId BIGINT = 0; -- 534, 446  

    DECLARE @tableName TABLE (propertyName NVARCHAR(255));  

    INSERT INTO @tableName (propertyName)  
    VALUES ('userDetail'), ('ticketPortal'), ('mediaLibrary'), ('teamChat'), ('userSubscription')  

    SELECT * FROM @tableName;  

    DECLARE @mId BIGINT = 0, @ParentId BIGINT = 0, @IsAdmin BIT = 0;  

    SELECT @mId = M_ID, @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail (NOLOCK)   WHERE User_ID = @UserId;  

    IF (ISNULL(@TpUserId, 0) = 0)  
    BEGIN  
        SELECT @TpUserId = TpUser_Id  
        FROM tbl_tp_UserLogin (NOLOCK)  
        WHERE IsActive = 1  
          AND User_Id = ISNULL(@UserId, 0);  
    END;  

    -- userDetail  
    PRINT 'Inter/Parent User';  

    SELECT   
        --ud.Type,
        ud.Type as [type],
        ud.ParentID AS [parentId],  
        --ud.IsAdmin,  
        ud.IsAdmin as [isAdmin],
        ud.User_Login AS [userLogin],  
        ud.EMail AS [email],  
        ud.User_ID AS [userId],  
        ud.[Priority] AS [priority],  
        ud.CompnayName AS [companyName],  
        ud.M_ID AS [mId],  
        ud.Timezone AS [timezone],  
        ud.CountryCode AS [countryCode],  
        ud.Mobile AS [mobile],  
        ud.FName AS [fName],  
        ud.LName AS [lName],  
        LOWER(CASE WHEN (ud.Type = 3 OR ud.Type = 4) THEN 'Partner' ELSE 'User' END) AS [defaultMasterPage],  
        ISNULL(rd.Partner_Type, '') AS [partnerType],  
        CONCAT(ud.User_Login, ' (', TRIM(ud.FName), ' ', TRIM(ud.LName), ')') AS [displayName],  
        c.Shortname AS [CountryShortName],  
        ud.smppid AS [smpPid]  
    FROM User_Detail ud (NOLOCK)  
        LEFT JOIN Reseller_Detail (NOLOCK) rd ON ud.ParentID = rd.User_ID  
        LEFT JOIN User_Filter uf (NOLOCK) ON ud.UserFilter = uf.Code  
        LEFT JOIN m_country1 (NOLOCK) c ON TRIM(ud.CountryCode) = TRIM(c.CountryCode)  
    WHERE ud.Status = 1  
      AND ud.User_ID = ISNULL(@UserId, 0);  

    -- ticketPortal  
    SELECT 
        [TpUser_Id] AS [tpUserId],  
        ISNULL(GroupId, 0) AS [groupId],  
        ISNULL(UL.User_Id, 0) AS [userId],  
        UL.ParentId AS [parentId],  
        CASE  
            WHEN UL.User_Id IS NOT NULL THEN UD.User_Login  
            ELSE UL.LoginName  
        END AS [loginName],  
        [Name] AS [name],  
        UL.Email AS [email],  
        IsActive AS [status],  
        1 AS [isLoginSuccess],  
        'User Login Successfull' AS [message],  
        dbo.fn_ConvertDateTime(GETDATE(), 'India Standard Time', 0) AS [timeZoneDateTime],  
        ISNULL(UL.Timezone, 'India Standard Time') AS [timeZone]  
    FROM tbl_tp_UserLogin UL (NOLOCK)  
        LEFT JOIN User_Detail UD (NOLOCK) ON UD.User_ID = UL.User_Id  
    WHERE IsActive = 1  
      AND TpUser_Id = ISNULL(@TpUserId, 0);  

    -- mediaLibrary  
    SELECT 
        'Valid' AS [Status],  
        mlt.EntityID AS [EntityId],  
        mlt.Token,  
        ue.ParentID AS [ParentId],  
        ue.User_Login AS [UserLogin]  
    FROM Tbl_ML_MediaLibraryToken mlt (NOLOCK)  
        JOIN User_Detail ue (NOLOCK) ON mlt.EntityID = ue.User_Id  
    WHERE mlt.EntityID = ISNULL(@UserId, 0)  
      AND mlt.ExpiryDate > GETDATE();  

    -- teamChat  
    EXEC usp_mk_GetLoginDetails_1 @User_Id = @UserId, @Mode = 'GETDATA';  

    SELECT top 1 UserID, PlanId, PlanStartDate, PlanEndDate, Cost, IsTrailPlan, 
        IsNewPlan , IsKYCRequired,
        case when PlanEndDate < cast(GETDATE() as date) then 1 else 0 end as IsExpired
    FROM Price_UserSubscriptionDetails WITH (NOLOCK) WHERE UserId = @ParentId
        and IsNewPlan  = 1 
        order by id desc


END;  



GO

