	select @Country  = Country_Name from m_country1 with (nolock) where Country_ID = @CountryId

	--select @uid as [@S_Userid], @UserName as [@Login_User], @FirstName as [@Fname],  @LastName as [@Lname], @Email as [@Email], @Mobile as [@Mobile]

	--select @mid as [@mid], @uid as [@uid] 

	exec usp_create_sms_user_microsite080318_New2
		@S_Userid = @uid,
		@Login_User = @UserName,      
		@Fname = @FirstName,
		@Lname = @LastName,
		@Email = @Email,
		@Mobile = @Mobile,
		@City = N'',
		@State = N'',
		@Country = @Country,
		@Type  = 0,
		@Status  = 1,
		@Banner_Id = 0,
		@Ac_Type  = N'',
		@Urltype = 0,
		@Compnayname = @CompanyName,
		@Defaulthtml = N'',
		@Newmicrosite  = N'',
		@Newoficename  = N'',
		@Accounttype = N'',
		@Userfilter  = N'MTIX_TR',
		@Countrycode = @CountryCode,
		@Referrerid  = @uid,
		@Source  = N'',
		@Medium  = N'',
		@Campaign = N'',
		@Timezone  = @TimezoneId,
		@Uniqueid = N''


end



