/****** Object:  StoredProcedure [dbo].[usp_st_InsertUpdateSalesTargetSettings]  */


CREATE   PROCEDURE [dbo].[usp_st_InsertUpdateSalesTargetSettings]
(
	@UserId bigint,
	@SalesTargetSettings nvarchar(max)
)
as
begin
	  
	declare 
		@StatusCode int = 0,
		@StatusMessage nvarchar(255) = '',
		@StatusDescription nvarchar(2000) = '',
		@ParentId bigint = 0

	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId

	declare 
		@TargetId bigint = 0,
		@TargetType int,
		@IsConversion bit,
		@TargetProducts nvarchar(max),
		@IsPipelineDeal bit,
		@PipelineDeals nvarchar(max),
		@IsInvoice bit,
		@InvoiceType nvarchar(25),
		@InvoiceCurrency nvarchar(25),
		@PersonType nvarchar(25),
		@PersonUsers nvarchar(max),
		@PersonTeamCode nvarchar(25),
		@PersonTeamName nvarchar(25),
		@TeamMembers nvarchar(max),
		@TotalTarget float,
		@CalculateBy nvarchar(25) ,
		@Unit int, 
		@FromDate datetime,
		@ToDate datetime,
		@EditChoice nvarchar(25) = 'insert',
		@pSalesTargetId bigint = 0,
		@UserTargetSettingId bigint = 0


	select @TargetType = TargetType, @IsConversion = IsConversion, @TargetProducts = TargetProducts, @IsPipelineDeal = IsPipelineDeal,
		@PipelineDeals = PipelineDeals, @IsInvoice = IsInvoice, @InvoiceType = InvoiceType, @InvoiceCurrency = InvoiceCurrency, 
		@PersonType = PersonType, @PersonUsers = PersonUsers, @PersonTeamCode = PersonTeamCode, @PersonTeamName = PersonTeamName,
		@TeamMembers = TeamMembers, @TotalTarget = TotalTarget, @CalculateBy = CalculateBy, @Unit = Unit, @FromDate = FromDate, @ToDate = ToDate, @EditChoice = EditChoice, @pSalesTargetId = SalesTargetId, @UserTargetSettingId = UserTargetSettingId

 from openjson(@SalesTargetSettings) with  (
		TargetId bigint '$.TargetId',
		TargetType int '$.TargetType',
		IsConversion bit '$.TargetSetting.IsConversion',
		TargetProducts nvarchar(max) '$.TargetSetting.TargetProducts' as json,
		IsPipelineDeal bit '$.TargetSetting.IsPipelineDeal',
		PipelineDeals nvarchar(max) '$.TargetSetting.PipelineDeals' as json,
		IsInvoice bit '$.TargetSetting.IsInvoice',
		InvoiceType nvarchar(25) '$.InvoiceSetting.InvoiceType',
		InvoiceCurrency nvarchar(25) '$.InvoiceSetting.Currency',
		PersonType nvarchar(25) '$.Person.Type',
		PersonUsers nvarchar(max) '$.Person.Users' as json,		
		PersonTeamCode nvarchar(25) '$.Person.Team.Code',
		PersonTeamName nvarchar(25) '$.Person.Team.Name',		
		TeamMembers nvarchar(max) '$.Person.Team.TeamMembers' as json,
		TotalTarget float '$.TotalTarget',
		CalculateBy nvarchar(25) '$.CalculateBy',
		Unit int '$.Period.Unit',
		FromDate datetime '$.Period.FromDate',
		ToDate datetime '$.Period.ToDate',
		EditChoice nvarchar(25) '$.EditChoice',
		SalesTargetId bigint '$.SalesTargetId',
		UserTargetSettingId bigint '$.UserTargetSettingId'
	)

	--select @TargetType as TargetType, @IsConversion as IsConversion, @TargetProducts as TargetProducts, @IsPipelineDeal as IsPipelineDeal,
	--	@PipelineDeals as PipelineDeals, @IsInvoice as IsInvoice, @InvoiceType as InvoiceType, @InvoiceCurrency as InvoiceCurrency, 
	--	@PersonType as PersonType, @PersonUsers as PersonUsers, @PersonTeamCode as PersonTeamCode, @PersonTeamName as PersonTeamName,
	--	@TotalTarget as TotalTarget, @CalculateBy as CalculateBy, @Unit as Unit, @FromDate as FromDate, @ToDate as ToDate

	if(isnull(@EditChoice, '') = '') begin set @EditChoice = 'insert'  end 


	drop table if exists #stUsers
	create table #stUsers (UserId bigint, [Target] float, TargetNumber float, TargetPercent float)
	drop table if exists #stTargetSetting
	create table #stTargetSetting (UserId bigint, [Target] float, TargetNumber float, TargetPercent float)

	print concat('Person type > ' ,@PersonType);

	if(@PersonType = 'user')
	begin
		
		insert into #stUsers(UserId, [Target], TargetNumber, TargetPercent )
		select Id, @TotalTarget, @TotalTarget, 100 from openjson(@PersonUsers) with (Id bigint '$.Id')

		insert into #stTargetSetting(UserId, [Target], TargetNumber, TargetPercent)
		select Id, @TotalTarget, @TotalTarget, 100 from openjson(@PersonUsers) with (Id bigint '$.Id')
	end
	else
	begin

		print concat('@TeamMembers => ', @TeamMembers)
		insert into #stTargetSetting(UserId, [Target], TargetNumber, TargetPercent)
		select null, @TotalTarget, @TotalTarget, 100 

		insert into #stUsers(UserId, [Target], TargetNumber, TargetPercent)
		select UserId, @TotalTarget, @TotalTarget, 100 from openjson(@TeamMembers) with (
			UserId bigint '$.UserId',
			[Target] float '$.Target',
			TargetPercent float '$.Percentage',
			TargetNumber float '$.Number',
			IsActive bit '$.IsActive'
		) where IsActive = 1
	end


	drop table if exists #tempCalendar 
	create table #tempCalendar(
		FromDate datetime,
		ToDate datetime
	)
	
	-- @Unit => 1 = 'Daily' | 2 = 'Weekly' | 3 = 'Monthly' | 4 = 'Quarterly' | 5 = 'Yearly' | 6 = 'Custom'
	if(@Unit = 1)
	begin
		print 'Daily'
		;WITH DateRange AS (
			SELECT @FromDate AS FromDate, @FromDate AS ToDate
			UNION ALL
			SELECT DATEADD(DAY, 1, FromDate),
					DATEADD(DAY, 1, ToDate)
			FROM DateRange
			WHERE ToDate <  @ToDate
		)
		insert into #tempCalendar( FromDate, ToDate )
		SELECT FromDate, ToDate FROM  DateRange
	end

	if(@Unit = 2)
	begin
		print 'Weekly'
		;WITH DateRange AS (
			SELECT @FromDate AS FromDate, DATEADD(DAY, 6, @FromDate) AS ToDate
			UNION ALL
			SELECT DATEADD(DAY, 7, FromDate), 
					DATEADD(DAY, 7, ToDate)
			FROM DateRange
			WHERE ToDate <  @ToDate
		)
		insert into #tempCalendar( FromDate, ToDate )
		SELECT FromDate, ToDate FROM  DateRange

	end

	if(@Unit = 3)
	begin
		print 'Monthly'
		declare @instances int
		select @instances=DATEDIFF(m,@fromdate,@todate)
		;WITH DateRange AS (
			SELECT @FromDate AS FromDate, DATEADD(DAY, -1, DATEADD(MONTH, 1, @FromDate)) AS ToDate
			UNION ALL
			SELECT DATEADD(MONTH, 1, FromDate), 
					DATEADD(MONTH, 1, ToDate)
			FROM DateRange
			WHERE ToDate <  @ToDate
		)
		insert into #tempCalendar( FromDate, ToDate )
		SELECT FromDate, ToDate FROM  DateRange

	end

	if(@Unit = 4)
	begin
		print 'Quarterly'
		;WITH DateRange AS (
			SELECT @FromDate AS FromDate, DATEADD(DAY, -1, DATEADD(MONTH, 3, @FromDate)) AS ToDate
			UNION ALL
			SELECT DATEADD(MONTH, 3, FromDate), 
					DATEADD(MONTH, 3, ToDate)
			FROM DateRange
			WHERE ToDate <  @ToDate
		)
		insert into #tempCalendar( FromDate, ToDate )
		SELECT FromDate, ToDate FROM  DateRange
	end

	if(@Unit = 5)
	begin
		print 'Yearly'
		;WITH DateRange AS (
			SELECT @FromDate AS FromDate, DATEADD(DAY, -1, DATEADD(YEAR, 1, @FromDate)) AS ToDate
			UNION ALL
			SELECT DATEADD(YEAR, 1, FromDate), 
					DATEADD(YEAR, 1, ToDate)
			FROM DateRange
			WHERE ToDate <  @ToDate
		)
		insert into #tempCalendar( FromDate, ToDate )
		SELECT FromDate, ToDate FROM  DateRange
	end

	if(@Unit = 6)
	begin
		print 'Custom'
		insert into #tempCalendar( FromDate, ToDate )
		SELECT @FromDate, @ToDate
	end

	begin try

		print concat('@TargetId => ', @TargetId)
		print concat('@TargetType => ', @TargetType)

		declare @TotalRangeCount int = 0, @TotalRangeFilterCount int = 0
		select @TotalRangeCount = count(1) from  #tempCalendar;
		select @TotalRangeFilterCount = count(1) from  #tempCalendar t 
			where ( t.FromDate between @FromDate and @ToDate and t.ToDate between @FromDate and @ToDate )

		if( not( @TotalRangeCount = @TotalRangeFilterCount))
		begin
			
			select @StatusCode  = 409, @StatusMessage = 'Invalid date range',
				@StatusDescription = concat( 'FromDate and ToDate not valid for ', ( case @Unit when 1 then 'Daily' when 2 then 'Weekly' 
				when 3 then 'Monthly' when 4 then 'Quarterly' when 5 then 'Yearly' when 6 then 'Custom' end ), ' Unit Type ')

			GOTO RESULTSECTION;
		end

		begin transaction		
		if(@EditChoice not in ('current', 'upcoming'))
		begin

			print concat('target type > ' , convert(varchar,@TargetType) );
			if(exists( select 1 from #stUsers u inner join TBL_ST_SalesTargetSettingUserTarget(nolock) t
					on t.ParentId = @ParentId and 1 = ( case 
							when @PersonType = 'user' and u.UserId = t.UserId then 1
							when @PersonType = 'team' and t.TeamCode = @PersonTeamCode then 1
						else 0 end)
					and t.TargetType = @TargetType
					where (
							@FromDate between t.FromDate and  t.ToDate 
							or @ToDate between t.FromDate and  t.ToDate
						)) and @TargetId = 0 )
			begin
				print 'colapese'
				declare @stId bigint = 0;
				select top 1 @stId = t.SalesTargetId from #stUsers u inner join TBL_ST_SalesTargetSettingUserTarget(nolock) t
					on t.ParentId = @ParentId and 1 = ( case 
							when @PersonType = 'user' and u.UserId = t.UserId then 1
							when @PersonType = 'team' and t.TeamCode = @PersonTeamCode then 1
						else 0 end) and t.TargetType = @TargetType
					where ( (t.FromDate between @FromDate and @ToDate ) or (t.ToDate between @FromDate and @ToDate )) 

				select @StatusCode  = 409, @StatusMessage = 'Exists',
					@StatusDescription = 'Sales Target already exists '

				GOTO RESULTSECTION;
			end

			-- BY PASS
			--GOTO RESULTSECTION;

				--- MOD.14.07.2024 BY SATYA

				IF (OBJECT_ID('TEMPDB..#TEMP_USERIDS09072024')) IS NOT NULL BEGIN DROP TABLE  #TEMP_USERIDS09072024 END;

				CREATE  TABLE  #TEMP_USERIDS
				(
					USERID  varchar(10)
				);

				DECLARE @tableusers varchar(max);
		
				SELECT @tableusers += (userids +'#') FROM TBL_ST_SalesTargetSettingMaster(nolock) where TargetType = @TargetType  and TargetPeriodId = @Unit 
				and TargetFromDate > @FromDate and  TargetToDate >= @ToDate 

				INSERT INTO #TEMP_USERIDS
				SELECT distinct VALUE FROM STRING_SPLIT(@TABLEUSERS, '#') WHERE COALESCE( VALUE,'')  <> '' ;

				IF EXISTS( SELECT  1 FROM #stUsers where UserId  in ( select USERID  from  #TEMP_USERIDS) ) 
				BEGIN
					set @tableusers = '' ;
					select @tableusers += (U.USER_LOGIN + ', ')FROM  #TEMP_USERIDS  TEMP LEFT JOIN USER_DETAIL U ON U.USER_ID = TEMP.USERID;

					select @StatusCode  = 204, @StatusMessage = 'Rejected', @StatusDescription = 'User ('+ @tableusers +') target Combination already exist for current target period.'
					GOTO RESULTSECTION;
				END
		
		--- MOD.14.07.2024 BY SATYA  END


			if(@TargetId > 0)
			begin
				delete from TBL_ST_SalesTargetSettingMaster where SalesTargetId = @TargetId
				delete from TBL_ST_SalesTargetSettingChild where SalesTargetId = @TargetId
				delete from TBL_ST_SalesTargetSettingUserTarget where SalesTargetId = @TargetId
			end
			
			print  concat(' totaltarget id >  ', convert(varchar,  @TotalTarget ));
			
			print concat('Target id > ' ,  convert(varchar, @TargetId ));


			insert into TBL_ST_SalesTargetSettingMaster( TargetFor, Conversions, Pipelines, Invoices, iInvoiceRaised, iInvoicePaid, TargetType, TeamCodes, TargetPeriodId, TargetFromDate, TargetToDate, TargetProductIds, TargetPipelineIds, TotalTarget, TargetUnit, Currency, UserId, ParentId, Status, IsActive, CreatedBy, CreatedDate,  UserIds, SalesTargetName )
			 select @PersonType, @IsConversion, @IsPipelineDeal, @IsInvoice, (case when @InvoiceType = 'invoiceRaised' then  1 else 0 end),
				(case when @InvoiceType = 'invoicePaid' then  1 else 0 end), @TargetType, @PersonTeamCode, @Unit, @FromDate, @ToDate,
				(case when @IsConversion = 1 then (select STRING_AGG(Id, '#') from openjson(@TargetProducts) with (Id bigint '$.Id')) else '' end),
				(case when @IsPipelineDeal = 1 then (select STRING_AGG(Id, '#') from openjson(@PipelineDeals) with (Id bigint '$.Id')) else '' end),
				@TotalTarget, @CalculateBy, @InvoiceCurrency, @UserId, @ParentId, 1, 1, @UserId, GETDATE(),
				(select STRING_AGG(UserId, '#') from #stUsers),
				concat('ST_', format(@FromDate, 'yyyyMMdd'), '_', format(@FromDate, 'yyyyMMdd'), (case when @PersonType = 'team' then '_t' else '_U' end))
	 
		
			declare @SalesTargetId bigint = 0;
			set @SalesTargetId = scope_identity()

			print  concat(' sales target  id > ', convert(varchar,  @SalesTargetId ));

			if(@SalesTargetId > 0)
			begin
			
				update TBL_ST_SalesTargetSettingMaster set TargetFor= @PersonType,
					UserIds = (select STRING_AGG(UserId, '#') from #stUsers),
					SettingJSON = JSON_MODIFY(@SalesTargetSettings, '$.TargetId', @SalesTargetId)  
						where SalesTargetId = @SalesTargetId

				insert into TBL_ST_SalesTargetSettingChild(SalesTargetId, TeamCode, UserId, [Target], IsActive)
					select @SalesTargetId, @PersonTeamCode,	UserId, [Target],	1 from #stTargetSetting

				insert into TBL_ST_SalesTargetSettingUserTarget( SalesTargetId, TeamCode, UserId, [Target], TargetNumber, TargetPercentage, 
						FromDate, ToDate, ParentId, IsActive, CreatedOn, TargetType, UserSplitDetail)			
				select @SalesTargetId, @PersonTeamCode, s.UserId, s.[Target], s.TargetNumber, s.TargetPercent,
					  t.FromDate, t.ToDate, @ParentId, 1, GETDATE(), @TargetType, @TeamMembers
					from #tempCalendar t cross join #stTargetSetting s 
					order by t.FromDate

			end
		
			select @StatusCode  = 200, @StatusMessage = 'Accepted', @StatusDescription = 'Sales Target saved successfully.'

		end
		else
		begin
			if(@EditChoice = 'current')
			begin
				print concat('current => @EditChoice => ', @EditChoice)
				print  concat(' sales target  id >  ', convert(varchar,  @SalesTargetId ), ' ,  totaltarget > ', convert(varchar,  @TotalTarget ), ' psaletargetid> ',convert(varchar,  @pSalesTargetId ));

				update TBL_ST_SalesTargetSettingMaster set 	TargetFor= @PersonType,
					UserIds = (select STRING_AGG(UserId, '#') from #stUsers),
					SettingJSON = JSON_MODIFY(@SalesTargetSettings, '$.TargetId', @pSalesTargetId)   , TotalTarget = @TotalTarget,
					ModifiedBy =@UserId , ModifiedDate = GETDATE()
						where SalesTargetId = @pSalesTargetId 
				
				delete from TBL_ST_SalesTargetSettingUserTarget
					where id = @UserTargetSettingId and SalesTargetId = @pSalesTargetId
				
				insert into TBL_ST_SalesTargetSettingUserTarget( SalesTargetId, TeamCode, UserId, [Target], TargetNumber, TargetPercentage, 
						FromDate, ToDate, ParentId, IsActive, CreatedOn, TargetType, UserSplitDetail)			
				select @pSalesTargetId, @PersonTeamCode, s.UserId, s.[Target], s.TargetNumber, s.TargetPercent,
					  t.FromDate, t.ToDate, @ParentId, 1, GETDATE(), @TargetType, @TeamMembers
					from #tempCalendar t cross join #stTargetSetting s 
					order by t.FromDate

				select @StatusCode  = 200, @StatusMessage = 'Accepted', @StatusDescription = 'Sales Target saved successfully.'

			end
			else
			if(@EditChoice = 'upcoming')
			begin
				print concat('upcoming => @EditChoice => ', @EditChoice)

				print  concat(' salestarget id >  ', convert(varchar,  @pSalesTargetId ));

				delete from TBL_ST_SalesTargetSettingUserTarget
				where id >= @UserTargetSettingId and SalesTargetId = @pSalesTargetId

				insert into TBL_ST_SalesTargetSettingUserTarget( SalesTargetId, TeamCode, UserId, [Target], TargetNumber, TargetPercentage, 
						FromDate, ToDate, ParentId, IsActive, CreatedOn, TargetType, UserSplitDetail)			
				select @pSalesTargetId, @PersonTeamCode, s.UserId, s.[Target], s.TargetNumber, s.TargetPercent,
					  t.FromDate, t.ToDate, @ParentId, 1, GETDATE(), @TargetType, @TeamMembers
					from #tempCalendar t cross join #stTargetSetting s 
					order by t.FromDate

				select @StatusCode  = 200, @StatusMessage = 'Accepted', @StatusDescription = 'Sales Target saved successfully.'
			end

			
		end
		commit transaction
	end try
	begin catch
		rollback transaction
		select @StatusCode  = 500, @StatusMessage = 'Error', @StatusDescription = 'Internal Error.'	

		GOTO RESULTSECTION;
	end catch

	RESULTSECTION:
	select @StatusCode as [StatusCode],
		@StatusMessage as [StatusMessage],
		@StatusDescription as [StatusDescription]

end



GO

/* ============================================================
   Procedure: [dbo].[usp_st_SaleActivityMasterManage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_st_SaleActivityMasterManage  
(  
 @Historyid bigint  
)  
as  
begin  

	--declare @Historyid bigint = 74811158 
 
	declare @refTable nvarchar(255) = '', @refTableId bigint = 0, @leadId bigint = 0 
	select @leadId = LeadID, @refTable = reftables, @refTableId = refids from tbl_LeadEventHistory(nolock) where Historyid = @Historyid 
	

	declare @TblRefId bigint = NULL, @TblRefName nvarchar(200) =  NULL, @Amount numeric(18,2) = NULL,   
	@RecordDate datetime = null, @InvoiceNo nvarchar(200) = NULL, @ProductIds nvarchar(1000) = NULL,   
	@PipelineId bigint = 0, @UserId bigint = NULL, @ParentId bigint =NULL, @LeadNo bigint = NULL, @FollowUpStatus int = 0  
   
	select @LeadNo = LeadNo, @ParentId = ParentID from UserLeads(nolock) where ID = @leadId

	if(isnull(@refTable, '') = 'Leadinteractionhistory' and isnull(@refTableId, 0) > 0)  
	begin   
		begin try  
			select @TblRefName = 'Leadinteractionhistory', @TblRefId = ID, @Amount = AmountPaid, @RecordDate = CreatedOn,  
			@InvoiceNo = '', @ProductIds = isnull(Products, ''), @PipelineId = 0, @UserId = CreatedBy 
			from Leadinteractionhistory(nolock) where ID = @refTableId  

  
			declare @nextProcess bit = 0  
			if(@FollowUpStatus = 5)    
			begin    
				set @Nextprocess = 1    
			end    
			else if exists( select 1 from FollowUp_Status fs(nolock)    
				where fs.IsConvert = 1 AND fs.ID = @FollowUpStatus  AND fs.ParentId = @ParentId)    
			begin    
				set @Nextprocess = 1  
			end    
		end try
		begin catch  
			exec usp_InsertErrorInfo  
		end catch
	end

	if(isnull(@refTable, '') = 'LeadPipelineMapping')
	begin
		print 'selecting LeadPipelineMapping'
		select @TblRefName = 'LeadPipelineMapping', @TblRefId = ID, @Amount = Amount, @RecordDate = CreatedDate,  
			@InvoiceNo = '', @ProductIds = '', @PipelineId = PipelineID, @UserId = DealOwner
			from LeadPipelineMapping(nolock) where ID = @refTableId  
	end

	if(isnull(@refTable, '') = 'mysmsinvoicing.dbo.invoice_histories')
	begin
		print 'selecting invoices'

		select * from mysmsinvoicing.dbo.invoice_histories 
		declare @invoiceId bigint = 0
		select @invoiceId = invoice_id from mysmsinvoicing.dbo.invoice_histories(nolock) where id = @refTableId
		select @TblRefName = 'invoices', @TblRefId = @invoiceId, @Amount = amount, @RecordDate = created_at,  
			@InvoiceNo = invoice_number, @ProductIds = '', @PipelineId = 0, @UserId = isnull(SalesOwner, createdby)
			from MySMSInvoicing.dbo.invoices (nolock) where id = @invoiceId
	end


	if(@Nextprocess = 1 or @refTable in ('LeadPipelineMapping', 'invoices'))    
	begin
		
		select @TblRefId as [@TblRefId], @TblRefName as [@TblRefName], @Amount as [@Amount], @RecordDate as [@RecordDate],   
			@InvoiceNo as [@InvoiceNo], @ProductIds as [@ProductIds], @PipelineId as [@PipelineId], @UserId as [@UserId],   
			@ParentId as [@ParentId], @LeadNo as [@LeadNo]  
  
		exec Usp_Insert_Tbl_ST_SalesActivityMasterNew  @TblRefId, @TblRefName, @Amount,   
		 @RecordDate, @InvoiceNo, @ProductIds, @PipelineId, @UserId, @ParentId, @LeadNo   
	end  
end



GO

/* ============================================================
   Procedure: [dbo].[usp_st_SalesTargetActionByMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_st_SalesTargetActionByMode](    
 @SalesTargetId bigint,    
 @Mode nvarchar(255) = 'setting',    
 @UserId bigint = 0    
)    
as    
begin    
   
 --declare  
 --@SalesTargetId bigint = 65,    
 --@Mode nvarchar(255) = 'setting',    
 --@UserId bigint = 34594   
   
 declare     
  @StatusCode int = 500,    
  @StatusMessage nvarchar(255) = 'failed',    
  @StatusDescription nvarchar(2000) = 'Unable to process your request please contact your administrator or support team'    
    
 if(@Mode = 'setting')    
 begin    
  select @StatusCode = 200, @StatusMessage = 'success', @StatusDescription = SettingJSON    
   from TBL_ST_SalesTargetSettingMaster(nolock) m  where SalesTargetId = @SalesTargetId    
 end    
     
 declare @oldSaleTargetId bigint
 select @oldSaleTargetId = SalesTargetId from TBL_ST_SalesTargetSettingUserTarget(nolock) 
	where id = @SalesTargetId 

 if(@Mode = 'remove')    
 begin
  delete from TBL_ST_SalesTargetSettingUserTarget where id = @SalesTargetId    
  select @StatusCode = 200, @StatusMessage = 'success', @StatusDescription = 'Removed successfully'

 end    
     
 if(@Mode = 'remove_upcoming')    
 begin    
  --delete from TBL_ST_SalesTargetSettingMaster where SalesTargetId = @SalesTargetId 
  --delete from TBL_ST_SalesTargetSettingChild where SalesTargetId = @SalesTargetId

	declare @slId bigint = 0;
	select @slId = SalesTargetId from TBL_ST_SalesTargetSettingUserTarget(nolock) where id = @SalesTargetId
	delete from TBL_ST_SalesTargetSettingUserTarget where id >= @SalesTargetId    and SalesTargetId = @slId
    
  select @StatusCode = 200, @StatusMessage = 'success', @StatusDescription = 'Sales target setting removed successfully'    
 end    
  
  if(@Mode in('remove_upcoming', 'remove'))
  begin
	  if(not exists(select * from TBL_ST_SalesTargetSettingUserTarget(nolock) where SalesTargetId = @oldSaleTargetId))
	  begin
		delete TBL_ST_SalesTargetSettingMaster where SalesTargetId = @oldSaleTargetId     
	  end
	  else
	  begin
		update TBL_ST_SalesTargetSettingMaster set
			TargetFromDate = (select top 1 FromDate from TBL_ST_SalesTargetSettingUserTarget(nolock) 
					where SalesTargetId = @oldSaleTargetId order by cast(FromDate as date) asc ),
			TargetToDate = (select top 1 ToDate from TBL_ST_SalesTargetSettingUserTarget(nolock) 
					where SalesTargetId = @oldSaleTargetId order by cast(ToDate as date) desc )

		where SalesTargetId = @oldSaleTargetId
	  end
  end
  

 select     
  @StatusCode as [StatusCode],     
  @StatusMessage as [StatusMessage],    
  @StatusDescription as [StatusDescription]    
end    



GO

/* ============================================================
   Procedure: [dbo].[Usp_StatusUpdationByAdmin]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_StatusUpdationByAdmin  
(  
 @Status nvarchar(200),  
 @Remarks nvarchar(max),  
 @RequestID bigint,  
 @ByAdmin bigint
)  
as  
Begin  
           
 Declare @ParentID bigint = 0  
 Declare @Mobile nvarchar(50) = ''  
 Declare @LandLine nvarchar(50) = ''  
  

   select top 1 @ParentID = ISNULL(ParentID,0),@Mobile = ISNULL(Mobile,''),@LandLine = isnull(LandLine,'')  from Cloud_MobileForwardingRequest where RequestID = @RequestID  
  
  if(rtrim(ltrim(@Status)) <> 'CompletedMappingRemoval' )
    Begin
  
      Update Cloud_User_Phone set Status = @Status ,LandLine = @LandLine  where PhoneNo = @Mobile and Parentid = @ParentID    
  
    end 
  else
   Begin
      Update Cloud_User_Phone set Status = '',landline = '' where PhoneNo = @Mobile and Parentid = @ParentID     
   End


   insert into Cloud_MobileForwardingRequestHistory    
     (    
        [RequestID]    
       ,[LandLine]    
       ,[Action]    
       ,[ActionDate]    
       ,[Remarks]    
       ,[CreatedBy]    
     )    
    values    
     (    
		  @RequestID,    
		  @LandLine,    
		  @Status,    
		  GETDATE(),    
		  @Remarks,    
		  @ByAdmin    
     )    
      
    select 'Record Updated'  
  
End  


GO

/* ============================================================
   Procedure: [dbo].[usp_stop_marketingsequence_batch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_stop_marketingsequence_batch
@batchid bigint,@userid bigint,@ids varchar(max)=null
as
begin
update t set t.isstopped=1,stoppedby=@userid,stoppedon=getdate() from [tbl_mass_mktgsequence] t where t.batchid=@batchid
and 1= case when @ids is null then 1 when entityid in (select item from SplitString(@ids,',')) then 1 else 0 end
and scheduledfor>getdate()
end




GO

/* ============================================================
   Procedure: [dbo].[usp_stopemails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_stopemails
(@batchid nvarchar(max))
as
begin
select value as batchid into #batchid from dbo.fn_split(@batchid,',') 
declare @count int=(select count(1) from #batchid),@minbatchid bigint=0,@bcount int,@id bigint
update e set isstopped=1 from BatchEmail_Infos e join #batchid b on e.batchid=b.batchid
while @count>0
begin
select @minbatchid=min(batchid) from #batchid where batchid>@minbatchid
select @bcount=count(1),@id=min(mail_id) from emailsfilter(nolock) where mail_batchid=@minbatchid
while @bcount>0
begin
insert into emailsstopped(Mail_GUID,Mail_ID,Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,
Mail_Attechement,Mail_TempleteBody,IsMonitor)
select top 1000 Mail_GUID,Mail_ID,Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,
Mail_Attechement,Mail_TempleteBody,IsMonitor from emailsfilter(nolock) where Mail_BatchID=@minbatchid and mail_id <=(@id+1000)
delete from emailsfilter where Mail_BatchID=@minbatchid and mail_id <=(@id+1000)
set @bcount=@bcount-1000
set @id=@id+1000
end
delete from #batchid where batchid=@minbatchid
set @count=@count-1
end
drop table if exists #batchid
end


GO

/* ============================================================
   Procedure: [dbo].[usp_stt_GetRecordingUrl]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_stt_GetRecordingUrl
(
	@RequestId bigint,
	@EntityName nvarchar(255),
	@EntityId bigint,
	@UserId bigint
)
as
begin

	declare @Status int = 1, @RequestMessage nvarchar(255) = null, @RecordingUrl nvarchar(1000) = null
	
	if(isnull(@EntityName, '') = '' or @EntityId = 0)
	begin
		select @RequestMessage = 'Invalid EntityName or EntityId'
	end

	declare @ParentId bigint = dbo.ufn_GetUserParentId(@UserId) -- hardcoded as of now, can be passed as parameter if needed

	if(isnull(@EntityName, '') = 'calllog')
	begin
		select @RecordingUrl = recordurl  from calllog with (nolock) where id = @EntityId
		select @Status = case when @RecordingUrl is not null then 1 else 0 end
		select @RequestMessage = case when @RecordingUrl is not null then 'Recording URL fetched successfully.' else 'No recording URL found for the given EntityId.' end
	end

	select @Status as Status, @RecordingUrl as RecordingUrl, @RequestMessage as Message

end



GO

/* ============================================================
   Procedure: [dbo].[usp_stt_RequestsGetStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_stt_RequestsGetStatus]
(
	@UserId bigint,
	@EntityName nvarchar(255),
	@EntityId bigint
)
as

--declare 
--	@UserId bigint = 34594,
--	@EntityName nvarchar(255) = 'calllog',
--	@EntityId bigint = 8218902

begin
	 declare @ParentId bigint = 0
	 select @ParentId= parentid from User_Detail where [User_ID] = @UserId  


	 declare @Status int = 1, @RequestId bigint = 0, @RequestMessage nvarchar(255) = null  

	 select @RequestId  = Id from tbl_stt_Requests with (nolock)
		where ParentId = @ParentId and EntityName = @EntityName and EntityId = @EntityId

	if(@RequestId > 0)
	begin
		select 
			(case isnull(ProcessState, '') 
				when 'Processing' then 1
				when 'Converted' then 2
				when 'Generated' then 3
				when 'Translated' then 4
				when 'Completed' then 5
				when 'Failed' then -1
			else 0 end) as  [Status],

			Id as [RequestId], ProcessState,
				FileSize, DurationInSec, CostApplied, AudioDetectionLang, TransScript, MetaData
		from tbl_stt_Requests  with (nolock)  where Id = @RequestId

		select id, char_count, detail_json from tbl_translation_deduction  with (nolock)
			where refTableName = @EntityName and refTableId = @EntityId order by id desc
	end
	else
	begin
		select 
			(case isnull(ProcessState, '') 
				when 'Processing' then 1
				when 'Converted' then 2
				when 'Generated' then 3
				when 'Translated' then 4
				when 'Completed' then 5
				when 'Failed' then -1
			else 0 end) as  [Status],

			Id as [RequestId], ProcessState,
				FileSize, DurationInSec, CostApplied, AudioDetectionLang, TransScript, MetaData
		from tbl_stt_Requests  with (nolock)  where Id = 0

		select id, char_count, detail_json from tbl_translation_deduction  with (nolock)
			where refTableName = @EntityName and refTableId = @EntityId order by id desc
	end
end



GO

/* ============================================================
   Procedure: [dbo].[usp_stt_RequestsInsert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_stt_RequestsInsert]
(
	@UserId bigint,
	@EntityName nvarchar(255),
	@EntityId bigint
)
as
begin

	--declare 
	--	@UserId bigint = 34594 ,
	--	@EntityName nvarchar(255) = 'CallLog',
	--	@EntityId bigint = 8218902
	
	declare @ParentId bigint = dbo.ufn_GetUserParentId(@UserID)


	declare @Status int = 1, @RequestId bigint = 0, @RequestMessage nvarchar(255) = null

	if(exists(select 1 from tbl_stt_Requests with (nolock) where parentid = @ParentId 
		and EntityName = @EntityName and  EntityId = @EntityId))
	begin 
		set @RequestMessage = 'STT Request already exists for this entity.'
		select @Status = (case isnull(ProcessState, '') 
				when 'Processing' then 1
				when 'Converted' then 2
				when 'Generated' then 3
				when 'Translated' then 4
				when 'Completed' then 5
				when 'Failed' then -1
			else 0 end), @RequestId = id from tbl_stt_Requests with (nolock) where parentid = @ParentId 
			and EntityName = @EntityName and  EntityId = @EntityId
	end
	else 
	begin
		insert into tbl_stt_Requests (ParentId, EntityName, EntityId, IsProcessed, CreatedOn)
			values (@ParentId, @EntityName, @EntityId, 0, getutcdate())
		set @RequestId = scope_identity()
		set @Status = 1
		set @RequestMessage = 'STT Request created successfully.'
	end

	select @Status as Status, @RequestId as RequestId, @RequestMessage as Message
end



GO

/* ============================================================
   Procedure: [dbo].[usp_stt_UpdateRequestStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_stt_UpdateRequestStatus]  
(  
	@RequestId bigint,  
	@IsProcessed bit = null,  
	@ProcessState nvarchar(255) = null,  
	@FileSize bigint = null,  
	@DurationInSec int = null,  
	@ProcesseStartAt datetime = null,  
	@ProcessEndAt datetime = null,  
	@AudioDetectionLang nvarchar(50) = null,  
	@TransScript nvarchar(max) = null,  
	@ErrorDescription nvarchar(1000) = null,
	@MetaData nvarchar(max) = null 
)  
as  
begin  
   
	begin try  
		update tbl_stt_Requests set  
			IsProcessed = isnull(@IsProcessed, IsProcessed),  
			ProcessState = isnull(@ProcessState, ProcessState),  
			FileSize = isnull(@FileSize, FileSize),  
			DurationInSec = isnull(@DurationInSec, DurationInSec),  
			ProcessStartAt = isnull(@ProcesseStartAt, ProcessStartAt),  
			ProcessEndedAt = isnull(@ProcessEndAt, ProcessEndedAt),  
			AudioDetectionLang = isnull(@AudioDetectionLang, AudioDetectionLang),
			TransScript = isnull(@TransScript, TransScript),
			ErrorDescription = isnull(@ErrorDescription, ErrorDescription),  
			MetaData = isnull(@MetaData, MetaData)
		where Id = @RequestId  
	end try  
	begin catch  
		execute usp_InsertErrorInfo  
	end catch  
  
end  



GO

