/* ============================================================
   Procedure: [dbo].[usp_Subscription_Handling]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Subscription_Handling]    
as    
Begin    
     Declare @ParentID bigint = 0    
  Declare @ChannelTokenID bigint = 0    
     DECLARE @sqlquery NVARCHAR(MAX)    
 --select ROW_NUMBER() over( order by id asc) as RowID ,ID,parentid,channelprofileid  into #TempChannelToken  from mysmsConversations.dbo.channeltokens with(nolock)  where isactive = 1  order by id asc    
    
	drop table if exists #TempChannelToken
	create table #TempChannelToken(RowID bigint,ID bigint,parentid bigint,channelprofileid nvarchar(1000))
	DECLARE @query NVARCHAR(MAX);

SET @query = '
SELECT 
    ROW_NUMBER() OVER (ORDER BY id ASC) AS RowID,
    ID,
    parentid,
    channelprofileid  
FROM channeltokens WITH (NOLOCK)  
WHERE isactive = 1  
ORDER BY id ASC;
';

-- Execute via CLR stored procedure
insert into #TempChannelToken(RowID,ID,parentid,channelprofileid)
EXEC usp_clr_FillRemoteData @query;

  Declare @Count int = 0;    
  Declare @RowIndex int = 1     
  Declare @MonthlyRental numeric(18,2) = 0    
  Declare @FromDate date , @ToDate date    
  declare @DailyRental numeric(18,2) = 0  
    
  select @Count = count(1) from #TempChannelToken    
    
  declare  @SubscriptionTBL as table(FromDate datetime,ToDate datetime, Amount numeric(18,2))  
                  
  while(@Count > 0)    
    Begin    
    select @ChannelTokenID = isnull(ID,0), @ParentID = isnull(ParentID,0) from #TempChannelToken where RowID = @RowIndex    
    select @MonthlyRental = isnull(MonthlyRental,0) from tbl_Wa_MonthlyRental with(nolock) where ChannelTokenID = @ChannelTokenID     
    select top 1 @FromDate =  CAST(FromDate as date), @ToDate = Cast(ToDate as date) from tbl_Wa_Subscription with(nolock) where ChannelTokenID = @ChannelTokenID and isactive = 1 order by id desc    
    
      --declare @CurrentDateTime datetime =  DATEADD(DAY ,3,dateadd(MONTH,2,GETDATE()));         
   declare @CurrentDateTime datetime = GETDATE();   
  
     --if(Month(cast(@CurrentDateTime as date)) = Month(@FromDate))  
	  if((Month(cast(@CurrentDateTime as date)) = Month(@ToDate) ) and ((year(cast(@CurrentDateTime as date)))  = year(cast(@ToDate as date)))) 
       Begin  
            if( ((day(Eomonth(cast(@CurrentDateTime as date))) - day(cast(@CurrentDateTime as date)))  <= 3) and (((day(Eomonth(cast(@CurrentDateTime as date))) - day(cast(@CurrentDateTime as date)))  >= 0 )) )   
     Begin  
          if(Eomonth(@ToDate) <> @ToDate)  
         Begin  
           Declare @FromDateTemp date = dateadd(DAY,1,@ToDate)  
        Declare @ToDateTemp date = Eomonth(@ToDate)  
        set @DailyRental = @MonthlyRental / day(Eomonth(@ToDate))  
        declare @DaysTemp int = day(@ToDateTemp) - day(@FromDateTemp) + 1   
        if(@DaysTemp > 0)  
          Begin  
             declare @AmountTemp numeric(18,2) = @DaysTemp * @DailyRental  
               insert into @SubscriptionTBL  
                (FromDate,ToDate,Amount)  
                select Cast(@FromDateTemp as datetime), Cast(@ToDateTemp as datetime),@AmountTemp             
          End          
      End   
        
      Declare @FromDateExactMonth date = DATEADD(dd,1,EOMONTH(cast(@CurrentDateTime as date)))   
      Declare @ToDateExactMonth date = EOMONTH(@FromDateExactMonth)   
           
       insert into @SubscriptionTBL  
            (FromDate,ToDate,Amount)  
         select Cast(@FromDateExactMonth as datetime), Cast(@ToDateExactMonth as datetime),@MonthlyRental             
             
                        if(exists(select 1 from @SubscriptionTBL))  
         Begin  
             Declare @TotalAmount numeric(18,2) = (select SUM(isnull(Amount,0)) from @SubscriptionTBL)    
           
                   declare @MID bigint = (Select top 1 M_id from mysms.dbo.User_Detail with(nolock) where User_ID = @ParentID)             
                                   Declare @Balance numeric(18,2)  = 0     
    
        select  @Balance = isnull(( select top 1 isnull(Balance,0) from mysms.dbo.IntCredit_Details with(nolock) where User_ID = @ParentID order by Credit_ID desc ),0)      
      
        DECLARE @avilableBalance decimal(18,4) = dbo.GetAvailableBalanceForService(@ParentID, 5)

        if(@avilableBalance > @TotalAmount)  
          Begin  
            select @Balance = @Balance - @TotalAmount      
                              
			insert into mysms.dbo.IntCredit_Details      
          (  M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,dCurr_Value,Validity,Default_Credit,FromDate,ToDate,DateCreated,DateUpdated,    
          LastModified,typecredit,Remarks      
          )      
          values(@MID,@ParentID,@ParentID,@TotalAmount,0,@Balance,0,99999,0,getdate(),GETDATE(),getdate(),getdate(),getdate(),5,'Amount debit while subscription being added ')      
          Declare @CreditID bigint = scope_identity();       
          exec usp_rf_UpdateReserveFundTransaction @CreditId = @CreditID


           insert into mysms.dbo.tbl_Wa_Subscription      
         (ChannelTokenID,FromDate,ToDate,Amount,CreditID,IsActive,CreatedOn,ReverseCreditID,ReverseRemarks,Remarks)      
         select @channeltokenid,Cast(FromDate as datetime),Cast(ToDate as datetime),Amount,@CreditID,1,getdate(),0,'','Subscription included'  From @SubscriptionTBL order by Cast(FromDate as datetime) asc  
           
        end -- balance if     
         else  
            Begin  
            --update mysmsConversations.dbo.channeltokens set isactive = 0 where id = @ChannelTokenID  
			SET @sqlquery = '
				UPDATE channeltokens 
				SET isactive = 0 
				WHERE id = ' + CAST(@ChannelTokenID AS NVARCHAR)

			EXEC usp_clr_ExecuteRemoteQuery @sqlquery
             select 'Your balance is low for subscription, your account has been deactivated'  
         End  
         End    
           delete from @SubscriptionTBL   
     End              
    End         
    
         delete from @SubscriptionTBL    
         set @RowIndex = @RowIndex + 1      
         set @Count = @Count - 1    
       End  -- end of while loop    
      
 drop table  if exists #TempChannelToken      
End



GO

/* ============================================================
   Procedure: [dbo].[usp_subscriptionalerts]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_subscriptionalerts
as
begin
drop table if exists #subs
select user_login,parentid,m_id,datediff(d,planenddate,cast(getdate() as date)) as DaysElapsed,p.* into #subs 
from Price_UserSubscriptionDetails(nolock) p join user_detail(nolock) u on u.user_id=p.userid
where IsNewPlan=1 and PlanEndDate between dateadd(d,-7,cast(getdate() as date)) and dateadd(d,30,cast(getdate() as date)) 

declare @tbl as LeadActivitywithid_Tbltype
insert into @tbl(EventName,EventDescription,LeadID,UserID,ParentID,refid,RefTable)
select 
case when dayselapsed >0 then 'Subscription expired' else 'Subscription approaching expiry' end,
user_login+'''s subscription '+ case when dayselapsed >0 then 'has expired on ' else 'is expiring on ' end+ cast(planenddate as nvarchar),
userid,userid,parentid,id,'Price_UserSubscriptionDetails'
from #subs s where dayselapsed=-30 or  dayselapsed=-15 or dayselapsed>-8
--select * from @tbl
exec UspSaveentityActivity_withMultipleValue_withid_bulk @tbl
end


GO

/* ============================================================
   Procedure: [dbo].[usp_subscriptionstatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_subscriptionstatus]  
as  
begin  
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX),@expired int,@expiring int  ,@subject nvarchar(200)        
  
drop table if exists #temp  
select distinct u.user_login,u.CompnayName as Company  
,isnull(cast(u.LastLogin1 as nvarchar),'') LastLogin1,isnull(cast(l.RefrenceNo as nvarchar),'') Refrenceno,planEnddate as SubscriptionExpiryOn,  
case when datediff(dd,getdate(),planenddate)<0 then 'Expired' else 'Active' end as CurrentAccountStatus,  
--a.datecreated,a.totalamount,  
datediff(dd,getdate(),planenddate) [DaysToExpire/Expired]--,p.*   
into #temp  
from Price_UserSubscriptionDetails p (nolock)  
 join user_detail u (nolock)  
 on p.UserID=u.user_id  
and p.IsNewPlan=1  
left join LinkedAccount l on l.User_ID=u.User_ID and l.Verified=1  
left join   
(select enqno,totalamount,datecreated from crm.crmdb.dbo.appointment_details a where meetingstatus='enrolled' and   
a.aid=(select max(aid) from crm.crmdb.dbo.appointment_details where enqno=a.enqno)  
) a  
on a.enqno=l.RefrenceNo  
where u.user_id=u.ParentID and datediff(dd,getdate(),planenddate) between -30 and 30  
--and l.RefrenceNo is null   
--and u.user_id=31871  
order by planenddate desc  
  
select @expired=count(1) from #temp where CurrentAccountStatus='Expired'  
select @expiring=count(1) from #temp where CurrentAccountStatus<>'Expired'  
select @subject = 'Subscription status: '+cast(@expired as nvarchar)+ ' expired, '+cast(@expiring as nvarchar)+ ' expiring in next 30 days'  
--alter table Price_UserSubscriptionDetails add created_date datetime default getdate()  
--select * from #temp  
--select * from LinkedAccount where user_login='parallel678633'  
  
SET @xml =CAST(( SELECT SubscriptionExpiryOn  AS 'td','',user_login AS 'td','',Company AS 'td','',LastLogin1 AS 'td','',           
t.RefrenceNo  AS 'td','', t.CurrentAccountStatus as 'td','',t.[DaysToExpire/Expired] from #temp t   
order by SubscriptionExpiryOn desc FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))          
SET @body ='<html><H1>Subscriptions Expired/Expiring in 30 days as on '+cast (getdate() as nvarchar)+  
'</H1><body><table border = 2><tr><th>SubscriptionExpiryOn</th><th>User Login</th><th>Company</th><th>Last Login</th><th>Enq no</th>  
<th>Current Account Status</th><th>DaysToExpire/Expired</th></tr>'           
SET @body = @body + @xml +'</table></body></html>'          
EXEC usp_enqueueemail          
@profile_name='Alerts',           
@recipients='csshukla@pelsoftlabs.in;nitin.lal@pelsoftlabs.in',          
@blind_copy_recipients='karuna@pelsoftlabs.in',          
@subject=@subject,--'Subscription status',          
@body = @body,          
@body_format ='HTML',  
@from_address='Subscriptions Kit19 <contactus@kit19.com>'  
drop table #temp          
end



GO

/* ============================================================
   Procedure: [dbo].[usp_subsriptionMatrix]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

     --170,335,'PANDIT','This is Test',0,1,0,0      
CREATE   PROCEDURE [dbo].[usp_subsriptionMatrix]     
AS      
BEGIN      
     
select clientID Parentid,count(clientID) IncomingCalls,sum(case when cast(dbo.[fn_getusertimefromindiantime](k.clientid,k.call_start_time) as date) =cast(dateadd(dd,-1,cast(getdate() as date)) as date) then 1 else 0 end) IncomingCallsYesterday,max( cast(k.call_start_time   as date)) LastIncomingCall
into #incomingCalls     
from Kit19calls k     
where k.context <>'outbound'         
group by clientID    
    
--select f.clientid,count(puniqueid) CallsReceived,SUM(case when dialstatus in ('NOANSWER','Busy') then 1 else 0 end)    
--CallsMissed,sum(case when cast(dbo.[fn_getusertimefromindiantime](f.clientid,f.call_start_time)as date) =cast(dateadd(dd,-1,cast(getdate() as date)) as date) then 1 else 0 end) CallsReceivedYesterday,max( cast(k.call_start_time   as date)) LastCallM    
--into #CallsMissed    
--from Kit19CallsDialled k     
--join Kit19Calls f on f.uniqueid=k.puniqueid         
--group by f.clientid    
      
select u.parentid,sum(case when cast(dbo.[fn_getusertimefromindiantime](u.parentid,u.CreatedOn) as date) =cast(dateadd(dd,-1,cast(getdate() as date)) as date) then 1 else 0 end) TotalLeadsAddedYesterday,COUNT(u.parentid) TotalLeadsAdded,MAX(cast(u.createdon as DATE)) LastLeadAdded
into #LeadAdded     
from  userleads u (nolock)     
--join LeadInteractionHistory l (nolock) on u.parentid=l.ParentID     
group by u.parentid   

select p.Parentid,COUNT(p.parentid) TotalEnquiriesParsed, SUM(case when cast(Createddate as date) =cast(dateadd(dd,-1,cast(getdate() as date)) as date) then 1 else 0 end) TotalEnquiriesParsedYesterday,MAX(cast(p.createddate as DATE)) LastEnquiryParsed
into #enquiriesparsed
from parsedenquiries(nolock) p group by p.parentid order by  COUNT(p.parentid) desc


  
--select @count  
 --INSERT INTO CloneMessageDeliveryStatus      
 --  (      
 --    -- MessageID -- this column value is auto-generated      
 --    BatchID,      
 --    Mobile,      
 --    [Message],      
 --    MessageStatus,      
 --    SenderID,      
 --    MessageInsertDate,      
 --    ScheduledDate,      
 --    ScheduledTime,      
 --    SmppID,      
 --    U_ID,      
 --    IsUniCode,      
 --    IsDnd,      
 --    IsAirtel,      
 --    MobileSubSet,      
 --    ValidNo,      
 --    IsPrority,      
 --    IsAllowDND,      
 --    DBType      
 --  )      
 SELECT *  
 FROM   ( SELECT u.parentid,
 u.CompnayName,
 u.user_login,
 CAST(isnull(IncomingCalls,0) AS nvarchar) IncomingCalls,
 CAST(isnull(IncomingCallsYesterday,0) AS nvarchar) IncomingCallsYesterday,
 ISNULL(cast(LastIncomingCall as nvarchar),'Never')  LastIncomingCall,
 CAST(isnull(TotalLeadsAdded,0) AS nvarchar) TotalLeadsAdded,
 CAST(isnull(TotalLeadsAddedYesterday,0) AS nvarchar) TotalLeadsAddedYesterday,
 ISNULL(cast(LastLeadAdded as nvarchar),'Never') LastLeadAdded, 
 CAST(isnull(TotalEnquiriesParsed,0) AS nvarchar) TotalEnquiriesParsed,
 CAST(isnull(TotalEnquiriesParsedYesterday,0) AS nvarchar) TotalEnquiriesParsedYesterday,
 ISNULL(cast(LastEnquiryParsed as nvarchar),'Never') LastEnquiryParsed,
 cast(u.LastLogin1 as DATE) LastLogin
 FROM user_detail u 
  left join #incomingCalls ic on ic.Parentid=u.user_ID    
  left join #LeadAdded f on f.ParentID=u.user_ID 
  left join #enquiriesparsed e on e.ParentID=u.user_ID     
  where u.M_ID=10043 --and u.parentid not in (select parentid From user_detail where m_id=10043)   
--   [DaySMSConsumption]>0    
--or [DayMailConsumption]>0     
--or  
and   
(exists(select 1 from userenquiry(nolock) where u.user_ID=parentid)
or exists(select 1 from userleads(nolock) where u.user_ID=parentid)
  )    
        ) A      
 
 
drop table #LeadAdded
drop table #enquiriesparsed
drop table #incomingCalls
       
END 


