/* ============================================================
   Procedure: [dbo].[usp_sy_DeleteForm]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sy_DeleteForm]
    @FormId bigint,
    @UserId bigint
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @FormExists BIT;

    BEGIN TRY
        -- Check if the form exists in tbl_sy_FormMaster
        IF EXISTS (SELECT 1 FROM tbl_sy_FormMaster WHERE Form_Id = @FormId)
        BEGIN
            SET @FormExists = 1;

            DECLARE @rowJson NVARCHAR(MAX) = (    
               SELECT *    
               FROM tbl_sy_FormMaster WITH(NOLOCK)    
               WHERE Form_Id = @FormId and ParentId = @UserId   
               FOR JSON AUTO    
                ,INCLUDE_NULL_VALUES    
              );

            declare @formName as varchar(max);

            select @formName = FormName from tbl_sy_FormMaster where Form_Id = @FormId and ParentId = @UserId  

            --Activity Entry
            DECLARE @EventName NVARCHAR(255) = 'Form deleted';
            DECLARE @EventTemplate NVARCHAR(MAX) = CONCAT('Form: ', @FormName, ' was deleted by ', @UserId);              
              
            exec UspSaveEntityActivity_withid 'user', @FormId, @UserId, @UserId, @EventTemplate, @EventName, 'tbl_sy_FormMaster', @FormId    

            -- Fetch Survey Schema from tbl_sy_FormMaster
            update tbl_sy_FormMaster
            set IsDeleted = 1, IsActive = 0, ModifiedOn = GETDATE(), ModifiedBy = @UserId
            WHERE Form_Id = @FormId and ParentId = @UserId;

            EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid    
              ,@Activity_type = 'Del_sy_Form'    
              ,@ActionType = 'D'    
              ,@RowJson = @rowJson    
              ,@Table_name = 'tbl_sy_FormMaster';

           Select @FormExists AS FormExists, 'Deleted' as FormSchema;
        END
        ELSE
        BEGIN
            SET @FormExists = 0;
           -- PRINT 'Form does not exist';
        
            -- Return a row with FormExists = 0 and NULL for SurveySchema
            SELECT @FormExists AS FormExists, NULL AS FormSchema;
        END
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo
    END CATCH;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_sy_GetCollection]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sy_GetCollection]
    @CollectionName NVARCHAR(1000)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @RawValues NVARCHAR(MAX);

    -- Get combined values for the given collection
    SELECT @RawValues = CollectionValues
    FROM tbl_sy_APICollectionDetails WITH (NOLOCK)
    WHERE CollectionName = @CollectionName 
      AND IsDeleted = 0;

    IF (@RawValues IS NULL OR LTRIM(RTRIM(@RawValues)) = '')
    BEGIN
        SELECT 'NoDataFound' AS Status;
        RETURN;
    END

    -- Normalize delimiters (convert tab/newline → comma)
    SET @RawValues = REPLACE(@RawValues, CHAR(9), ',');   -- tab → comma
    SET @RawValues = REPLACE(@RawValues, CHAR(10), ',');  -- newline → comma
    SET @RawValues = REPLACE(@RawValues, CHAR(13), ',');  -- carriage return → comma

    -- Split and return each value as a separate row
    SELECT 
        LTRIM(RTRIM(value)) AS CollectionValue
    FROM STRING_SPLIT(@RawValues, ',')
    WHERE LTRIM(RTRIM(value)) <> '';
END




GO

/* ============================================================
   Procedure: [dbo].[usp_sy_GetCustomAPIDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sy_GetCustomAPIDetails]
    @PageNumber INT = 1,
    @PageSize INT = 5,
    @UserId bigint = 0,
    @Search NVARCHAR(100) = ''
AS
BEGIN
    SET NOCOUNT ON;

    SELECT 
        Id,
        CollectionName,
        CollectionValues,
        ROW_NUMBER() OVER (ORDER BY Id DESC) AS RowNum
    FROM tbl_sy_APICollectionDetails with(nolock)
    WHERE (@Search = '' OR CollectionName LIKE '%' + @Search + '%') and CreatedBy = @UserId and IsDeleted = 0
    ORDER BY Id DESC;

    -- Return total count
    SELECT COUNT(*) AS TotalRecords
    FROM tbl_sy_APICollectionDetails with(nolock)
    WHERE (@Search = '' OR CollectionName LIKE '%' + @Search + '%') and CreatedBy = @UserId and IsDeleted = 0;
END




