/* ============================================================
   Procedure: [dbo].[usp_sy_GetForm]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sy_GetForm]
    @FormId BIGINT,
    @FormSharedet_Id BIGINT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @FormExists BIT;
    DECLARE @UserId BIGINT;
    DECLARE @rowJson NVARCHAR(MAX);

    BEGIn TRY

        SELECT @UserId = CreatedBy
        FROM tbl_sy_FormShareDetails
        WHERE FormSharedet_Id = @FormId;

        -- Check if the form exists in tbl_sy_FormShareDetails first
        IF EXISTS (SELECT 1 FROM tbl_sy_FormShareDetails WHERE FormSharedet_Id = @FormSharedet_Id)
        BEGIN
            SET @FormExists = 1;

            SELECT 
                @FormExists AS FormExists, 
                SharedContentJson AS SurveySchema
            FROM tbl_sy_FormShareDetails
            WHERE FormSharedet_Id = @FormSharedet_Id;

            set @rowJson = (    
               SELECT *    
               FROM tbl_sy_FormShareDetails WITH(NOLOCK)    
               WHERE FormSharedet_Id = @FormSharedet_Id --and CreatedBy = @UserId
               FOR JSON AUTO    
                ,INCLUDE_NULL_VALUES    
              );

            EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
              ,@Activity_type = 'Sel_sy_Form'    
              ,@ActionType = 'S'    
              ,@RowJson = @rowJson    
              ,@Table_name = 'tbl_sy_FormShareDetails';
        END
        ELSE IF EXISTS (SELECT 1 FROM tbl_sy_FormMaster WHERE Form_Id = @FormId)
        BEGIN
            SET @FormExists = 1;

            SELECT 
                @FormExists AS FormExists, 
                ContentJson AS SurveySchema
            FROM tbl_sy_FormMaster
            WHERE Form_Id = @FormId;

            set @rowJson = (    
               SELECT *    
               FROM tbl_sy_FormMaster WITH(NOLOCK)    
               WHERE Form_Id = @FormId --and ParentId = @UserId
               FOR JSON AUTO    
                ,INCLUDE_NULL_VALUES    
              );

            EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
              ,@Activity_type = 'Sel_sy_Form'    
              ,@ActionType = 'S'    
              ,@RowJson = @rowJson    
              ,@Table_name = 'tbl_sy_FormMaster';
        END
        ELSE
        BEGIN
            SET @FormExists = 0;

            SELECT 
                @FormExists AS FormExists, 
                NULL AS SurveySchema;
        END
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo
    END CATCH;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_sy_GetFormList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sy_GetFormList]
    @ParentId INT,
    @Page INT,
    @PageSize INT,
    @SearchText NVARCHAR(1000) = ''
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        -- Total count for paging with search
        SELECT COUNT(*) AS TotalCount
        FROM tbl_sy_FormMaster
        WHERE ParentId = @ParentId
          AND IsActive = 1
          AND IsDeleted = 0
          AND (@SearchText = '' OR FormName LIKE '%' + @SearchText + '%');

        -- Paged result set with search
        SELECT Form_Id, FormName, [Description], ParentId, IsActive
        FROM tbl_sy_FormMaster
        WHERE ParentId = @ParentId
          AND IsActive = 1
          AND IsDeleted = 0
          AND (@SearchText = '' OR FormName LIKE '%' + @SearchText + '%')
        ORDER BY CreatedOn desc, FormName
        OFFSET (@Page - 1) * @PageSize ROWS
        FETCH NEXT @PageSize ROWS ONLY;

        DECLARE @rowJson NVARCHAR(MAX) = (    
                SELECT *
                FROM tbl_sy_FormMaster
                WHERE ParentId = @ParentId
                  AND IsActive = 1
                  AND IsDeleted = 0
                  AND (@SearchText = '' OR FormName LIKE '%' + @SearchText + '%')
                ORDER BY FormName
                OFFSET (@Page - 1) * @PageSize ROWS
                FETCH NEXT @PageSize ROWS ONLY
               FOR JSON AUTO    
                ,INCLUDE_NULL_VALUES    
              );

        EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentId    
            ,@Activity_type = 'Sel_sy_Form'    
            ,@ActionType = 'S'    
            ,@RowJson = @rowJson    
            ,@Table_name = 'tbl_sy_FormMaster';
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;
    END CATCH;
END



GO

/* ============================================================
   Procedure: [dbo].[usp_sy_GetFormMoreSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_sy_GetFormMoreSettings]  
    @UserId BIGINT,  
    @FormId BIGINT = 0  
AS  
BEGIN  
--declare  @UserId BIGINT=32222,  
--    @FormId BIGINT = 10238  
    SET NOCOUNT ON;  
  
    BEGIN TRY  
  
        SELECT   
            FM.MoreSettings,  
            FM.ContentJson,  
  
            -------------------------------------------------  
            -- Webhooks as JSON  
            -------------------------------------------------  
            (  
                SELECT  
                    WA.apiid,  
                    WA.formid,  
                    WA.webapi,  
                    WA.method,  
                    WA.dateCreated,  
                    WA.status,  
                    WA.baseapi,  
                    WA.isdynamic  
                FROM webformApi_Tbl WA  
                WHERE WA.formid = FM.Form_Id and isdynamic=1  
                FOR JSON PATH  
            ) AS WebhookJson  
  
        FROM tbl_sy_FormMaster FM  
        WHERE FM.Form_Id = @FormId  
          AND FM.ParentId = @UserId  
          AND FM.IsDeleted = 0;  
  
    END TRY  
    BEGIN CATCH  
        EXEC usp_InsertErrorInfo;  
    END CATCH;  
END;  


