/* ============================================================
   Procedure: [dbo].[usp_sy_GetResponseDetailedList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sy_GetResponseDetailedList]
    @FormId BIGINT,
    @FromDate DATETIME,
    @ToDate DATETIME,
    @IsSharedDetails bit,
    @ParentId bigint
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @rowJson NVARCHAR(MAX);

    if (@IsSharedDetails = 1)
    begin
        SELECT 
            s.FormSharedet_Id,
            s.EntityName AS Name,
            s.EntityType AS [Entity Type]
        FROM tbl_sy_FormMaster AS f
            LEFT JOIN tbl_sy_FormShareDetails AS s WITH (NOLOCK) ON s.Form_Id = f.Form_Id
            LEFT JOIN tbl_sy_FormResponseDetails AS r WITH (NOLOCK) ON r.FormSharedet_Id = s.FormSharedet_Id
        WHERE s.EntityName is not null and
            f.Form_Id = @FormId  
            AND (
                (r.CreatedOn >= @FromDate AND r.CreatedOn <= DATEADD(DAY, 1, @ToDate))
                OR r.CreatedOn IS NULL
            )
            AND f.IsDeleted = 0
            -- AND f.IsActive = 1
        ORDER BY s.EntityName;

        set @rowJson = (    
               SELECT 
                    s.FormSharedet_Id,
                    s.EntityName AS Name,
                    s.EntityType AS [Entity Type]
                FROM tbl_sy_FormMaster AS f
                    LEFT JOIN tbl_sy_FormShareDetails AS s WITH (NOLOCK) ON s.Form_Id = f.Form_Id
                    LEFT JOIN tbl_sy_FormResponseDetails AS r WITH (NOLOCK) ON r.FormSharedet_Id = s.FormSharedet_Id
                WHERE s.EntityName is not null and
                    f.Form_Id = @FormId  
                    AND (
                        (r.CreatedOn >= @FromDate AND r.CreatedOn <= DATEADD(DAY, 1, @ToDate))
                        OR r.CreatedOn IS NULL
                    )
                    AND f.IsDeleted = 0
                    -- AND f.IsActive = 1
                ORDER BY s.EntityName
               FOR JSON AUTO    
                ,INCLUDE_NULL_VALUES    
         );

        EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentId    
            ,@Activity_type = 'Sel_sy_Form'    
            ,@ActionType = 'S'    
            ,@RowJson = @rowJson    
            ,@Table_name = 'tbl_sy_FormShareDetails';
    end 
    else
    begin
        SELECT 
            s.EntityName as Name,
            s.EntityType as [Entity Type],
            r.FormResponseJson as Response,
            s.SharedContentJson as SharedFormJson
        FROM tbl_sy_FormMaster AS f
            LEFT JOIN tbl_sy_FormResponseDetails AS r WITH (NOLOCK) ON r.Form_Id = f.Form_Id
            LEFT JOIN tbl_sy_FormShareDetails AS s WITH (NOLOCK) ON s.FormSharedet_Id = r.FormSharedet_Id
        WHERE 
            f.Form_Id = @FormId
            AND (
                (r.CreatedOn >= @FromDate AND r.CreatedOn <= DATEADD(DAY, 1, @ToDate))
                OR r.CreatedOn IS NULL
            ) AND f.IsDeleted = 0
            --AND f.IsActive = 1
        ORDER BY f.FormName;

         set @rowJson = (    
               SELECT 
                    s.EntityName as Name,
                    s.EntityType as [Entity Type],
                    r.FormResponseJson as Response,
                    s.SharedContentJson as SharedFormJson
                FROM tbl_sy_FormMaster AS f
                    LEFT JOIN tbl_sy_FormResponseDetails AS r WITH (NOLOCK) ON r.Form_Id = f.Form_Id
                    LEFT JOIN tbl_sy_FormShareDetails AS s WITH (NOLOCK) ON s.FormSharedet_Id = r.FormSharedet_Id
                WHERE 
                    f.Form_Id = @FormId
                    AND (
                        (r.CreatedOn >= @FromDate AND r.CreatedOn <= DATEADD(DAY, 1, @ToDate))
                        OR r.CreatedOn IS NULL
                    ) AND f.IsDeleted = 0
                    --AND f.IsActive = 1
                ORDER BY f.FormName
               FOR JSON AUTO    
                ,INCLUDE_NULL_VALUES    
         );

        EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentId    
            ,@Activity_type = 'Sel_sy_Form'    
            ,@ActionType = 'S'    
            ,@RowJson = @rowJson    
            ,@Table_name = 'tbl_sy_FormResponseDetails';
    end
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_sy_GetResponseFormList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sy_GetResponseFormList]
    @ParentId INT,
    @FromDate DATETIME,
    @ToDate DATETIME
AS
BEGIN
    SET NOCOUNT ON;
    BEGIN TRY
        SELECT 
            f.Form_Id,
            f.FormName,
            COUNT(r.Form_Id) AS ResponseCount,
            MAX(r.CreatedOn) AS LastResponseDate,
            (
                SELECT COUNT(*) 
                FROM tbl_sy_FormShareDetails s 
                WHERE s.Form_Id = f.Form_Id
            ) AS SharedCount
        FROM tbl_sy_FormMaster AS f
            LEFT JOIN tbl_sy_FormResponseDetails AS r WITH (NOLOCK) ON r.Form_Id = f.Form_Id
            LEFT JOIN tbl_sy_FormShareDetails AS s WITH (NOLOCK) ON s.FormSharedet_Id = r.FormSharedet_Id
        WHERE 
            f.ParentId = @ParentId
            AND (
                (r.CreatedOn >= @FromDate AND r.CreatedOn <= DATEADD(DAY, 1, @ToDate))
                OR r.CreatedOn IS NULL
            ) 
            AND f.IsDeleted = 0
            --AND f.IsActive = 1
        GROUP BY f.Form_Id, f.FormName
        ORDER BY LastResponseDate DESC,  -- Latest response at the top; NULLs (no response) will be at the bottom
                f.FormName


        DECLARE @rowJson NVARCHAR(MAX) = (    
                        SELECT 
                            f.Form_Id,
                            f.FormName,
                            COUNT(r.Form_Id) AS ResponseCount,
                            MAX(r.CreatedOn) AS LastResponseDate,
                            (
                                SELECT COUNT(*) 
                                FROM tbl_sy_FormShareDetails s 
                                WHERE s.Form_Id = f.Form_Id
                            ) AS SharedCount
                        FROM tbl_sy_FormMaster AS f
                            LEFT JOIN tbl_sy_FormResponseDetails AS r WITH (NOLOCK) ON r.Form_Id = f.Form_Id
                            LEFT JOIN tbl_sy_FormShareDetails AS s WITH (NOLOCK) ON s.FormSharedet_Id = r.FormSharedet_Id
                        WHERE 
                            f.ParentId = @ParentId
                            AND (
                                (r.CreatedOn >= @FromDate AND r.CreatedOn <= DATEADD(DAY, 1, @ToDate))
                                OR r.CreatedOn IS NULL
                            ) 
                            AND f.IsDeleted = 0
                            --AND f.IsActive = 1
                        GROUP BY f.Form_Id, f.FormName
                        ORDER BY LastResponseDate DESC,  -- Latest response at the top; NULLs (no response) will be at the bottom
                                            f.FormName
                       FOR JSON AUTO    
                        ,INCLUDE_NULL_VALUES    
                      );

        EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentId    
            ,@Activity_type = 'Sel_sy_Form'    
            ,@ActionType = 'S'    
            ,@RowJson = @rowJson    
            ,@Table_name = 'tbl_sy_FormMaster';

        SELECT 
            COUNT(*) AS TotalForms
        FROM tbl_sy_FormMaster
        WHERE 
            ParentId = @ParentId
            --AND IsActive = 1
            AND IsDeleted = 0;
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo
    END CATCH;
END;



GO

