/* ============================================================
   Procedure: [dbo].[usp_sy_InsertCustomAPIDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sy_InsertCustomAPIDetail]
    @Id BIGINT = 0,
    @CollectionName NVARCHAR(1000),
    @CollectionValues NVARCHAR(MAX),
    @ParentId BIGINT = 0
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @Exists INT = 0;

    -- Check if a record with the same CollectionName already exists
    SELECT @Exists = COUNT(*)
    FROM tbl_sy_APICollectionDetails with(nolock)
    WHERE CollectionName = @CollectionName
      AND (@Id = 0 OR Id <> @Id);  

    IF (@Exists > 0)
    BEGIN
        SELECT 'AlreadyExists' AS Status;
        RETURN;
    END

    IF (@Id > 0)
    BEGIN
        UPDATE tbl_sy_APICollectionDetails
        SET  
            CollectionName = @CollectionName,
            CollectionValues = @CollectionValues,
            ModifiedBy = @ParentId,
            ModifiedOn = GETDATE()
        WHERE Id = @Id;

        SELECT 'Updated' AS Status;
    END 
    ELSE
    BEGIN
        INSERT INTO tbl_sy_APICollectionDetails
        (
            CollectionName,
            CollectionValues,
            ParentId,
            CreatedBy
        )
        VALUES
        (
            @CollectionName,
            @CollectionValues,
            @ParentId,
            @ParentId
        );

        SELECT 'Inserted' AS Status;
    END 
END





GO

/* ============================================================
   Procedure: [dbo].[usp_sy_InsertForm]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Created by GitHub Copilot in SSMS - review carefully before executing

CREATE   PROCEDURE [dbo].[usp_sy_InsertForm]

    @SurveyJson NVARCHAR(MAX),

    @FormTitle NVARCHAR(200),

    @FormDesc NVARCHAR(1000),

    @UserId BIGINT,

    @FormId BIGINT = 0,

    @CmdName NVARCHAR(100),

    @MoreSettings NVARCHAR(MAX) = NULL

AS

BEGIN

    SET NOCOUNT ON;
 
    DECLARE @Result NVARCHAR(50);

    DECLARE @NewFormId BIGINT;

    DECLARE @EventName NVARCHAR(255);

    DECLARE @EventTemplate NVARCHAR(MAX);

    DECLARE @ExistingMoreSettings NVARCHAR(MAX) = NULL;

    DECLARE @OldFormId BIGINT = NULL;
 
    BEGIN TRY

        PRINT 'Entry Started';
 
        IF EXISTS (

            SELECT 1

            FROM dbo.tbl_sy_FormMaster

            WHERE FormName = @FormTitle

              AND ParentId = @UserId

              AND IsDeleted = 0

              AND IsActive = 1

              AND (

                    (@CmdName = 'Update' AND Form_Id <> @FormId)

                    OR (@CmdName = 'Insert' AND (@FormId = 0 OR Form_Id <> @FormId))

                  )

        )

        BEGIN

            SET @Result = 'Exists';

            SET @NewFormId = 0;

        END

        ELSE

        BEGIN

            IF (@CmdName = 'Update' AND @FormId <> 0)

            BEGIN

                -- Preserve MoreSettings on update when caller did not supply any

                IF @MoreSettings IS NULL

                BEGIN

                    SELECT @MoreSettings = replace(MoreSettings,'\','')

                    FROM dbo.tbl_sy_FormMaster

                    WHERE Form_Id = @FormId;

                END
 
                UPDATE dbo.tbl_sy_FormMaster

                SET

                    FormName = @FormTitle,

                    [Description] = @FormDesc,

                    ContentJson = @SurveyJson,

                    MoreSettings = replace(MoreSettings,'\',''),

                    ModifiedBy = @UserId,

                    ModifiedOn = GETDATE()

                WHERE Form_Id = @FormId;
 
                SET @NewFormId = @FormId;

                SET @Result = 'Success';
 
                SET @EventName = 'Form updated';

                SET @EventTemplate = CONCAT('Form: ', @FormTitle, ' was updated by ', @UserId);

                EXEC UspSaveEntityActivity_withid 'user', @FormId, @UserId, @UserId, @EventTemplate, @EventName, 'tbl_sy_FormMaster', @FormId;

            END

            ELSE IF (@CmdName = 'Insert' AND @FormId <> 0)

            BEGIN

                -- Preserve existing MoreSettings for reinsert

                SELECT @ExistingMoreSettings = replace( MoreSettings, '\', '')

                FROM dbo.tbl_sy_FormMaster

                WHERE Form_Id = @FormId;
 
                SET @OldFormId = @FormId;
 
                UPDATE dbo.tbl_sy_FormMaster

                SET

                    IsActive = 0,

                    Remarks = 'Marked inactive during reinsert',

                    ModifiedBy = @UserId,

                    ModifiedOn = GETDATE()

                WHERE Form_Id = @FormId

                  AND IsActive = 1;
 
                INSERT INTO dbo.tbl_sy_FormMaster

                (

                    FormName,

                    [Description],

                    ContentJson,

                    CreatedBy,

                    ParentId,

                    IsActive,

                    IsDeleted,

                    CreatedOn,

                    MoreSettings

                )

                VALUES

                (

                    @FormTitle,

                    @FormDesc,

                    @SurveyJson,

                    @UserId,

                    @UserId,

                    1,

                    0,

                    GETDATE(),

                    replace(COALESCE(@MoreSettings, @ExistingMoreSettings),'\','')

                );
 
                SET @NewFormId = SCOPE_IDENTITY();

                SET @Result = 'Success';
 
                -- Copy webhook/webform API rows from old form to new form (preserve same content)

                IF EXISTS (

                    SELECT 1 FROM dbo.webformApi_Tbl WHERE formid = @OldFormId and IsDynamic=1

                )

                BEGIN

                    INSERT INTO dbo.webformApi_Tbl

                    (

                        formid,

                        webapi,

                        method,

                        dateCreated,

                        status,

                        baseapi,

                        isdynamic

                    )

                    SELECT

                        @NewFormId,

                        webapi,

                        method,

                        GETDATE(),

                        status,

                        baseapi,

                        isdynamic

                    FROM dbo.webformApi_Tbl

                    WHERE formid = @OldFormId and IsDynamic=1;

                END
 
                SET @EventName = 'Form updated';

                SET @EventTemplate = CONCAT('Form: ', @FormTitle, ' was updated by ', @UserId);

                EXEC UspSaveEntityActivity_withid 'user', @NewFormId, @UserId, @UserId, @EventTemplate, @EventName, 'tbl_sy_FormMaster', @NewFormId;

            END

            ELSE IF (@CmdName = 'Insert' AND @FormId = 0)

            BEGIN

                PRINT 'In INSERT';
 
                INSERT INTO dbo.tbl_sy_FormMaster

                (

                    FormName,

                    [Description],

                    ContentJson,

                    CreatedBy,

                    ParentId,

                    IsActive,

                    IsDeleted,

                    CreatedOn,

                    MoreSettings

                )

                VALUES

                (

                    @FormTitle,

                    @FormDesc,

                    @SurveyJson,

                    @UserId,

                    @UserId,

                    1,

                    0,

                    GETDATE(),

                   replace( @MoreSettings,'\','')

                );
 
                SET @NewFormId = SCOPE_IDENTITY();

                SET @Result = 'Success';
 
                PRINT 'Inserted';
 
                SET @EventName = 'Form created';

                SET @EventTemplate = CONCAT('Form: ', @FormTitle, ' was created by ', @UserId);

                EXEC UspSaveEntityActivity_withid 'user', @NewFormId, @UserId, @UserId, @EventTemplate, @EventName, 'tbl_sy_FormMaster', @NewFormId;
 
                PRINT 'Activity added';

            END

            ELSE

            BEGIN

                SET @Result = 'Invalid Command';

                SET @NewFormId = 0;

            END

        END

    END TRY

    BEGIN CATCH

        EXEC usp_InsertErrorInfo;

        SET @Result = 'Fail: ' + ERROR_MESSAGE();

        SET @NewFormId = 0;

    END CATCH;
 
    SELECT @Result AS Result, @NewFormId AS FormId;

END;
 


GO


